def compute_rebreakout_display_score(raw_score: float, prep_score: float, attempts: int, success_attempts: int, failed_attempts: int) -> float:
    raw_score = safe_float(raw_score, 0)
    prep_score = safe_float(prep_score, raw_score)
    attempts = int(safe_float(attempts, 0))
    success_attempts = int(safe_float(success_attempts, 0))
    failed_attempts = int(safe_float(failed_attempts, 0))
    if attempts <= 0:
        return prep_score
    display = raw_score
    if success_attempts >= 1:
        display += 0.55 + max(success_attempts - 1, 0) * 0.18
        if failed_attempts == 0:
            display = max(display, 0.45 + max(min(prep_score, 1.40), 0) * 0.25)
    if failed_attempts >= 1:
        display -= 0.45 * failed_attempts
        if success_attempts == 0:
            display = min(display, max(prep_score * 0.30, 0.15))
    if success_attempts <= 0 and failed_attempts <= 0:
        display = max(display, prep_score * 0.85)
    return round(display, 2)

def format_rebreakout_stat_text(item_or_row: dict, compact: bool = False) -> str:
    item_or_row = item_or_row if isinstance(item_or_row, dict) else {}
    raw_score = safe_float(item_or_row.get("rebreakout_raw_score", item_or_row.get("rebreakout_score", 0)), 0)
    re_score = safe_float(item_or_row.get("rebreakout_score", raw_score), raw_score)
    prep_score = safe_float(item_or_row.get("rebreakout_prep_score", re_score), re_score)
    attempts = int(safe_float(item_or_row.get("rebreakout_attempts", 0), 0))
    success_attempts = int(safe_float(item_or_row.get("rebreakout_success_attempts", 0), 0))
    failed_attempts = int(safe_float(item_or_row.get("rebreakout_failures", 0), 0))
    success_rate = safe_float(item_or_row.get("rebreakout_success_rate", 0), 0) * 100.0
    if attempts <= 0:
        prep_label = "준비 약함"
        if prep_score >= 1.00:
            prep_label = "곧 재시도 가능"
        elif prep_score >= 0.45:
            prep_label = "재돌파 준비중"
        elif prep_score >= 0.15:
            prep_label = "아직 시도 전"
        return f"고점 다시도전 힘 {prep_score:.2f}({prep_label})"
    if success_attempts <= 0 and failed_attempts <= 0:
        return f"고점 다시도전 힘 {re_score:.2f}(확인중)"
    return f"고점 다시도전 힘 {re_score:.2f}({success_rate:.0f}% / 성공 {success_attempts}회 / 실패 {failed_attempts}회)"


def get_recovery_profile_snapshot(item_or_row: dict) -> dict:
    item_or_row = item_or_row if isinstance(item_or_row, dict) else {}
    score = safe_float(item_or_row.get("recovery_quality_score", 0), 0)
    dwell = int(safe_float(item_or_row.get("low_zone_stay_bars", 0), 0))
    reclaim = int(safe_float(item_or_row.get("low_zone_reclaim_count", 0), 0))
    defense = safe_float(item_or_row.get("low_zone_defense_score", 0), 0)
    persist = safe_float(item_or_row.get("turnover_persistence_score", 0), 0)
    ratio3 = safe_float(item_or_row.get("turnover_sustain_ratio_3v10", 0), 0)
    ratio5 = safe_float(item_or_row.get("turnover_sustain_ratio_5v20", 0), 0)
    snap = ensure_pre_alert_snapshot(item_or_row) if isinstance(item_or_row, dict) else {}
    from_low = safe_float(snap.get("from_30m_low_pct", item_or_row.get("from_30m_low_pct", 0)), 0)
    high_gap_pct = get_effective_high_gap_pct(item_or_row) if isinstance(item_or_row, dict) else safe_float(item_or_row.get("high_gap_pct", 999), 999)
    turnover_5m = safe_float(item_or_row.get("turnover_5m", item_or_row.get("turnover_recent_5m", 0)), 0)
    promising = bool(
        score >= 1.10
        and high_gap_pct >= 1.00
        and (dwell >= 2 or reclaim >= 1)
        and (persist >= 0.70 or ratio3 >= 1.15 or turnover_5m >= 750000)
        and from_low <= 2.20
    )
    strong = bool(
        score >= 1.45
        and high_gap_pct >= 1.15
        and (dwell >= 3 or reclaim >= 1)
        and (persist >= 0.95 or ratio3 >= 1.30)
        and from_low <= 1.90
    )
    return {
        "recovery_quality_score": score,
        "low_zone_stay_bars": dwell,
        "low_zone_reclaim_count": reclaim,
        "low_zone_defense_score": defense,
        "turnover_persistence_score": persist,
        "turnover_sustain_ratio_3v10": ratio3,
        "turnover_sustain_ratio_5v20": ratio5,
        "recovery_profile_promising": promising,
        "recovery_profile_strong": strong,
    }


def is_low_structure_unverified_v245(item_or_row: dict) -> bool:
    """v2.5.245: 저점방어 0점과 정밀차트 미검증을 분리한다."""
    try:
        row = item_or_row if isinstance(item_or_row, dict) else {}
        route = str(row.get("low_structure_route_v244", "") or "").strip()
        if route and route not in {"저점 구조 확인중", ""}:
            return False
        low_keys = [
            "low_defense_v2_score", "low_structure_score_v2", "low_zone_defense_score",
            "recovery_quality_score", "low_rising_score_v2", "low_recent_reclaim_bars_v244",
            "low_zone_stay_bars", "low_zone_reclaim_count", "turnover_persistence_score",
        ]
        for key in low_keys:
            if abs(safe_float(row.get(key, 0), 0)) > 0.0001:
                return False
        chart_keys = ["candle_body_ratio_1", "body_ratio_1", "close_position_ratio_1", "close_pos_1", "upper_wick_pct_1", "lower_wick_pct_1"]
        has_chart_value = any(abs(safe_float(row.get(k, 0), 0)) > 0.0001 for k in chart_keys)
        source = str(row.get("precision_chart_source", row.get("current_candle_source", row.get("source", ""))) or "").lower()
        sample = int(safe_float(row.get("sample_candles_1m", row.get("minute1_candles", row.get("snapshot_rows", 0))), 0))
        if (not has_chart_value) and (sample <= 3 or "snapshot" in source or "realtime_snapshot" in source or "light_snapshot" in source):
            return True
        return False
    except Exception:
        return False


def format_low_structure_status_v245(item_or_row: dict) -> str:
    try:
        row = item_or_row if isinstance(item_or_row, dict) else {}
        if is_low_structure_unverified_v245(row):
            return "저점방어 판단보류(정밀 1분봉 미검증)"
        try:
            row = apply_low_defense_quality_v248(dict(row)) if 'apply_low_defense_quality_v248' in globals() else row
            final_label = str(row.get("low_defense_final_label_v248", "") or "").strip()
            if final_label:
                return final_label
        except Exception:
            pass
        route = get_low_structure_route_label_v244(row) if 'get_low_structure_route_label_v244' in globals() else ""
        if route:
            return route
        return ""
    except Exception:
        return ""


def low_defense_structure_route_is_good_v248(row: dict) -> bool:
    try:
        route = get_low_structure_route_label_v244(row if isinstance(row, dict) else {}) if 'get_low_structure_route_label_v244' in globals() else ""
        return route in {"저점높임 재출발형", "저점방어 재출발형", "저점방어 관찰형"}
    except Exception:
        return False


def assess_low_defense_quality_v248(row: dict) -> dict:
    """v2.5.248: 저점방어 구조와 최종 승격 품질을 분리한다."""
    try:
        row = row if isinstance(row, dict) else {}
        if not bool(globals().get("LOW_DEFENSE_QUALITY_V248_ON", True)):
            return {"enabled": False}
        route = get_low_structure_route_label_v244(row) if 'get_low_structure_route_label_v244' in globals() else ""
        if route not in {"저점높임 재출발형", "저점방어 재출발형", "저점방어 관찰형"}:
            return {"enabled": True, "route": route, "has_structure": False, "promote_ok": False, "label": route or "저점 구조 확인중"}
        reasons = []
        money_code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
        if money_code in {"actual_zero", "tiny", "thin"}:
            reasons.append("돈얇음")
        sustain = classify_money_sustain_for_row(row) if 'classify_money_sustain_for_row' in globals() else {}
        sustain_label = str((sustain or {}).get("label", row.get("money_sustain_label", "")) or "")
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        if "매도우세" in sustain_label or (cnt >= 5 and 0 < buy <= safe_float(globals().get("LOW_DEFENSE_V248_SELL_HEAVY_BUY_RATIO_MAX", 45.0), 45.0)):
            reasons.append("매도우세")
        try:
            weak_candle = is_current_candle_weak_for_label_v244(row) if 'is_current_candle_weak_for_label_v244' in globals() else False
        except Exception:
            weak_candle = False
        candle_label = str(row.get("current_candle_label", row.get("current_candle_code", "")) or "")
        if weak_candle or "밀림" in candle_label or "위꼬리" in candle_label:
            reasons.append("현재봉 밀림")
        high_gap = safe_float(row.get("below_30m_high_pct", row.get("below_high", 999)), 999)
        from_low = safe_float(row.get("from_low", row.get("from_30m_low_pct", 0)), 0)
        if 0 <= high_gap <= safe_float(globals().get("LOW_DEFENSE_V248_NEAR_HIGH_BLOCK_GAP", 0.20), 0.20) and from_low >= 0.80:
            reasons.append("고점 바로 앞")
        dedup = []
        for r in reasons:
            if r and r not in dedup:
                dedup.append(r)
        blocked = bool(dedup)
        if blocked:
            label = f"{route} / 승격금지({', '.join(dedup[:3])})"
            short = "저점방어 구조 있음 / " + "·".join(dedup[:3]) + "으로 매수 후보 아님"
            quality = "structure_only_blocked"
        else:
            label = route
            short = f"{route} / 돈·현재봉 확인 통과"
            quality = "promote_ok"
        return {"enabled": True, "route": route, "has_structure": True, "promote_ok": not blocked, "blocked": blocked, "block_reasons": dedup, "block_reason_text": "·".join(dedup), "quality": quality, "label": label, "short": short}
    except Exception as e:
        return {"enabled": True, "error": str(e)[:80], "promote_ok": False, "label": "저점방어 품질 확인중"}


def apply_low_defense_quality_v248(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        q = assess_low_defense_quality_v248(row)
        if not isinstance(q, dict) or not q.get("enabled", True):
            return row
        if q.get("has_structure", False):
            row["low_defense_quality_v248"] = str(q.get("quality", ""))
            row["low_defense_final_label_v248"] = str(q.get("label", ""))
            row["low_defense_quality_short_v248"] = str(q.get("short", ""))
            row["low_defense_promote_ok_v248"] = bool(q.get("promote_ok", False))
            row["low_defense_block_reasons_v248"] = list(q.get("block_reasons", []) or [])
            row["low_defense_block_reason_text_v248"] = str(q.get("block_reason_text", ""))
        return row
    except Exception:
        return row


def classify_high_rebreakout_hold_v248(row: dict) -> dict:
    """v2.5.248: 고점 바로 앞 후보를 재돌파 유지/추격위험/관찰로 분리."""
    try:
        row = row if isinstance(row, dict) else {}
        if not bool(globals().get("HIGH_REBREAKOUT_V248_ON", True)):
            return {"enabled": False}
        gap = safe_float(row.get("below_30m_high_pct", row.get("below_high", 999)), 999)
        if gap >= 900:
            return {"enabled": True, "label": "고점거리 확인중", "code": "unknown", "score": 0.0}
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        amount = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        live = safe_float(row.get("current_candle_live_score", 0), 0)
        pressure = safe_float(row.get("current_candle_pressure_score", 0), 0)
        follow = safe_float(row.get("current_candle_follow_score", 0), 0)
        current_chg = safe_float(row.get("current_candle_change_pct", row.get("change_1", 0)), 0)
        try:
            weak = is_current_candle_weak_for_label_v244(row) if 'is_current_candle_weak_for_label_v244' in globals() else False
        except Exception:
            weak = False
        near_gap = safe_float(globals().get("HIGH_REBREAKOUT_V248_NEAR_GAP_PCT", 0.35), 0.35)
        hold_gap = safe_float(globals().get("HIGH_REBREAKOUT_V248_HOLD_GAP_PCT", 0.20), 0.20)
        good_buy = safe_float(globals().get("HIGH_REBREAKOUT_V248_GOOD_BUY_RATIO", 60.0), 60.0)
        score = 0.0
        if 0 <= gap <= near_gap: score += 1.0
        if 0 <= gap <= hold_gap: score += 0.6
        if cnt >= 5 and buy >= good_buy: score += 1.0
        if amount >= 1_000_000: score += 0.5
        if live >= 2.0 or follow >= 1.2 or current_chg >= 0.35: score += 0.8
        if weak or pressure >= 1.2 or (cnt >= 5 and 0 < buy <= 45): score -= 1.2
        if gap <= near_gap and score >= 2.2:
            label, code = "고점 재돌파 유지 확인", "rebreak_hold"
        elif gap <= near_gap and score >= 1.0:
            label, code = "고점 재접근 관찰", "near_high_watch"
        elif gap <= near_gap:
            label, code = "고점 앞 밀림/추격금지", "near_high_reject"
        else:
            label, code = "고점 여유 확인", "not_near_high"
        return {"enabled": True, "label": label, "code": code, "score": round(score, 2), "gap": gap, "buy_ratio": buy, "trade_count": cnt}
    except Exception as e:
        return {"enabled": True, "label": "고점 재돌파 확인중", "code": "error", "error": str(e)[:80]}


def apply_high_rebreakout_hold_v248(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        h = classify_high_rebreakout_hold_v248(row)
        if not isinstance(h, dict) or not h.get("enabled", True):
            return row
        row["high_rebreakout_v248_label"] = str(h.get("label", ""))
        row["high_rebreakout_v248_code"] = str(h.get("code", ""))
        row["high_rebreakout_v248_score"] = safe_float(h.get("score", 0), 0)
        row["high_rebreakout_v248_gap"] = safe_float(h.get("gap", 999), 999)
        return row
    except Exception:
        return row

def _dedupe_reason_bits_v251(bits) -> list:
    out = []
    try:
        for b in bits or []:
            b = str(b or "").strip()
            if b and b not in out:
                out.append(b)
    except Exception:
        pass
    return out


def build_final_candidate_display_context_v251(row: dict) -> dict:
    """v2.5.251 판단통합 정리판.

    rank_short / rank_watch / review_watch / trace_detail의 결론이 서로 흔들리지 않게
    돈흐름·현재봉·저점방어·고점재돌파 결과를 하나의 표시용 결론으로 합친다.
    """
    try:
        row = row if isinstance(row, dict) else {}
        reasons = []
        money_code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
        try:
            sustain = classify_money_sustain_for_row(row) if 'classify_money_sustain_for_row' in globals() else {}
        except Exception:
            sustain = {}
        sustain_label = str(row.get("money_sustain_label", "") or (sustain or {}).get("label", "") or "")
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        strongest = _row_strongest_rank_move(row) if '_row_strongest_rank_move' in globals() else max(
            safe_float(row.get("change_1", 0), 0), safe_float(row.get("change_3", 0), 0),
            safe_float(row.get("change_5", 0), 0), safe_float(row.get("change_30", 0), 0)
        )
        high = classify_high_rebreakout_hold_v248(row) if 'classify_high_rebreakout_hold_v248' in globals() else {}
        high_label = str((high or {}).get("label", row.get("high_rebreakout_v248_label", "")) or "")
        high_code = str((high or {}).get("code", row.get("high_rebreakout_v248_code", "")) or "")
        low_route = get_low_structure_route_label_v244(row) if 'get_low_structure_route_label_v244' in globals() else ""
        low_q = assess_low_defense_quality_v248(row) if 'assess_low_defense_quality_v248' in globals() else {}
        low_has = bool((low_q or {}).get("has_structure", False))
        low_blocked = bool((low_q or {}).get("blocked", False))
        low_ok = bool((low_q or {}).get("promote_ok", False)) if low_has else False
        if low_blocked:
            reasons += list((low_q or {}).get("block_reasons", []) or [])
        weak_candle = is_current_candle_weak_for_label_v244(row) if 'is_current_candle_weak_for_label_v244' in globals() else False
        flash_limited = is_money_or_candle_flash_watch_limited_v244(row) if 'is_money_or_candle_flash_watch_limited_v244' in globals() else False
        if money_code in {"actual_zero", "tiny"}:
            reasons.append("실제돈작음")
        elif money_code == "thin":
            reasons.append("돈얇음")
        if "매도우세" in sustain_label or (cnt >= 5 and 0 < buy <= 45):
            reasons.append("매도우세")
        if weak_candle:
            reasons.append("현재봉 밀림")
        if high_code == "near_high_reject":
            reasons.append("고점근처 재돌파 유지 미확인")
        elif high_code == "near_high_watch" and low_has and not low_ok:
            reasons.append("고점근처 확인 필요")
        reasons = _dedupe_reason_bits_v251(reasons)

        if money_code in {"actual_zero", "tiny"} and score < 9.0 and strongest < 1.20:
            main = "돈 약함 확인"; state = "실제돈작음 / 복기 우선"; action = "복기용 기록"; watch_action = "빠른하향"
        elif flash_limited or ("반짝" in sustain_label or "식는" in sustain_label or (cnt >= 5 and 0 < buy <= 45)):
            main = "반짝형 관찰"; state = "반짝형 관찰"; action = "반짝형 관찰"; watch_action = "관찰만"
        elif weak_candle:
            main = "위꼬리/현재봉 밀림"; state = "위꼬리/현재봉 밀림"; action = "반짝형 관찰"; watch_action = "관찰만"
        elif low_has and low_blocked:
            main = "저점방어 구조만 확인"; state = "저점방어 구조 있음/승격금지"; action = "복기용 기록"; watch_action = "승격금지"
        elif low_has and low_ok:
            label = str((low_q or {}).get("label", "") or low_route)
            main = label; state = label; action = "정밀검토 대기" if label != "저점방어 관찰형" else "복기용 기록"; watch_action = "내부감시"
        elif high_code == "rebreak_hold":
            main = "고점 재돌파 유지 확인"; state = "고점 재돌파 유지 확인"; action = "정밀검토 대기"; watch_action = "내부감시"
        elif high_code == "near_high_reject":
            main = "고점 앞 밀림/추격금지"; state = "고점 앞 밀림/추격금지"; action = "복기용 기록"; watch_action = "승격금지"
        else:
            base_state = str(row.get("chart_lifecycle_label", row.get("rank_watch_chart_state", row.get("primary_reason", ""))) or "").strip()
            base_action = str(row.get("rank_watch_action", row.get("primary_reason", "")) or "").strip()
            main = base_state or base_action or "상태 확인중"; state = base_state or main; action = base_action or main; watch_action = "확인중"

        if not reasons and low_has and low_blocked:
            text = str((low_q or {}).get("block_reason_text", "") or "").strip()
            reasons = _dedupe_reason_bits_v251(text.replace(",", "·").split("·")) if text else []
        reason_text = "·".join(reasons)
        one_liner = ""
        if reason_text:
            if watch_action == "승격금지" or "승격금지" in state:
                one_liner = f"구조는 있지만 {reason_text} 때문에 승격 금지"
            elif watch_action == "빠른하향":
                one_liner = f"{reason_text}이라 내부감시 슬롯 오래 먹이지 않음"
            else:
                one_liner = reason_text
        return {
            "main_label": main, "state_label": state, "action_label": action, "watch_action": watch_action,
            "block_reasons": reasons, "block_reason_text": reason_text, "one_liner": one_liner,
            "money_code": money_code, "high_label": high_label, "high_code": high_code,
            "low_route": low_route, "low_has_structure": low_has, "low_promote_ok": low_ok,
        }
    except Exception as e:
        return {"main_label": "상태 확인중", "state_label": "상태 확인중", "action_label": "상태 확인중", "block_reason_text": "", "error": str(e)[:80]}


def apply_final_candidate_display_context_v251(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        ctx = build_final_candidate_display_context_v251(row)
        if not isinstance(ctx, dict):
            return row
        row["final_candidate_main_label_v251"] = str(ctx.get("main_label", "") or "")
        row["final_candidate_state_v251"] = str(ctx.get("state_label", "") or "")
        row["final_candidate_action_v251"] = str(ctx.get("action_label", "") or "")
        row["final_candidate_watch_action_v251"] = str(ctx.get("watch_action", "") or "")
        row["final_candidate_block_reason_text_v251"] = str(ctx.get("block_reason_text", "") or "")
        row["final_candidate_one_liner_v251"] = str(ctx.get("one_liner", "") or "")
        row["final_candidate_high_label_v251"] = str(ctx.get("high_label", "") or "")
        row["final_candidate_low_route_v251"] = str(ctx.get("low_route", "") or "")
        main = row["final_candidate_main_label_v251"]
        state = row["final_candidate_state_v251"]
        action = row["final_candidate_action_v251"]
        if state:
            row["chart_lifecycle_label"] = state
            row["rank_watch_chart_state"] = state
        if action:
            row["rank_watch_action"] = action
            row["primary_reason"] = main or action
            row["label_text"] = main or action
        if row.get("final_candidate_one_liner_v251"):
            row["one_liner"] = row["final_candidate_one_liner_v251"]
        return row
    except Exception:
        return row


def format_final_candidate_reason_v251(row: dict, prefix: str = "사유") -> str:
    try:
        row = row if isinstance(row, dict) else {}
        reason = str(row.get("final_candidate_block_reason_text_v251", row.get("low_defense_block_reason_text_v248", "")) or "").strip()
        high = str(row.get("final_candidate_high_label_v251", row.get("high_rebreakout_v248_label", "")) or "").strip()
        bits = []
        if reason:
            bits.append(reason)
        if high and high not in {"고점거리 확인중", "고점 여유 확인"} and high not in reason:
            bits.append(high)
        bits = _dedupe_reason_bits_v251(bits)
        if not bits:
            return ""
        return f"{prefix}: " + " / ".join(bits[:3])
    except Exception:
        return ""


def format_recovery_profile_text(item_or_row: dict, compact: bool = False) -> str:
    if is_low_structure_unverified_v245(item_or_row):
        return "저점방어 판단보류(정밀 1분봉 미검증) / 저점체류 확인전·재확인 확인전 / 돈이 계속 붙는 힘 확인전"
    prof = get_recovery_profile_snapshot(item_or_row)
    score = safe_float(prof.get("recovery_quality_score", 0), 0)
    dwell = int(prof.get("low_zone_stay_bars", 0))
    reclaim = int(prof.get("low_zone_reclaim_count", 0))
    persist = safe_float(prof.get("turnover_persistence_score", 0), 0)
    low_v2_label = str((item_or_row or {}).get("low_structure_summary_v2", (item_or_row or {}).get("low_defense_v2_label", "")) or "").strip()
    low_v2_score = safe_float((item_or_row or {}).get("low_defense_v2_score", 0), 0)
    if low_v2_label and low_v2_score > 0:
        low_text = f"{low_v2_label} {low_v2_score:.2f}"
    else:
        low_text = f"저점 버틴 힘 {score:.2f}"
    if compact:
        return f"{low_text} / 저점체류 {dwell}봉·재확인 {reclaim}회 / 돈이 계속 붙는 힘 {persist:.2f}"
    return f"{low_text} / 저점체류 {dwell}봉·재확인 {reclaim}회 / 돈이 계속 붙는 힘 {persist:.2f}"


def is_recovery_profile_promising(item: dict) -> bool:
    return bool(get_recovery_profile_snapshot(item).get("recovery_profile_promising", False))


def is_chart_current_candle_uninformative(item: dict) -> bool:
    body1 = safe_float(item.get("candle_body_ratio_1", 0), 0)
    close1 = safe_float(item.get("close_position_ratio_1", 0), 0)
    upper1 = safe_float(item.get("upper_wick_pct_1", 0), 0)
    lower1 = safe_float(item.get("lower_wick_pct_1", 0), 0)
    body3 = safe_float(item.get("candle_body_ratio_3", 0), 0)
    body5 = safe_float(item.get("candle_body_ratio_5", 0), 0)
    close3 = safe_float(item.get("close_position_ratio_3", 0), 0)
    if body1 <= 0.01 and upper1 <= 0.01 and lower1 <= 0.01 and close1 <= 0.01:
        if body3 >= 0.18 or body5 >= 0.18 or close3 >= 0.18:
            return True
    return False


def _format_percent_maybe(value: float, digits: int = 0, allow_pending: bool = False, pending_text: str = "진행중") -> str:
    value = safe_float(value, 0)
    if allow_pending and abs(value) <= 0.0001:
        return pending_text
    if digits <= 0:
        return f"{value:.0f}%"
    return f"{value:.{digits}f}%"


def format_turnover_flash_label(score: float) -> str:
    score = safe_float(score, 0)
    if score <= -6.0:
        return "반짝형 강함"
    if score <= -1.2:
        return "반짝형 약함"
    if score >= 2.5:
        return "지속형 우세"
    if score >= 0.8:
        return "지속형 보통"
    return "반짝/지속 비슷"

def format_prebreakout_simple_label(item: dict) -> str:
    item = item if isinstance(item, dict) else {}
    score = safe_float(item.get("prebreakout_ready_score", 0), 0)
    hold = int(safe_float(item.get("prebreakout_hold_near_high_bars", 0), 0))
    pullback = safe_float(item.get("prebreakout_pullback_depth_pct", 0), 0)
    reaccel = safe_float(item.get("prebreakout_volume_reaccel_score", 0), 0)
    if score >= 2.60 and reaccel >= 0.05:
        return "고점 전 준비 좋음"
    if score >= 1.35 or (hold >= 2 and 0 < pullback <= 1.8 and reaccel > -0.10):
        return "고점 전 준비 보통"
    if score <= -0.4 or pullback >= 3.0 or reaccel <= -0.25:
        return "고점 전 힘 약함"
    return "고점 전 준비 약함"


def format_htf_position_simple_text(item: dict) -> str:
    item = item if isinstance(item, dict) else {}
    bits = []
    htf_pos = str(item.get("htf_box_position_label", "") or "").strip()
    daily_pos = str(item.get("daily_box_position_label", "") or "").strip()
    rebound_day = int(safe_float(item.get("daily_rebound_day", 0), 0))
    htf_higher_low = bool(item.get("htf_higher_low_3", False))
    if htf_pos:
        bits.append(htf_pos)
    if htf_higher_low:
        bits.append("4시간 저점 높임")
    if daily_pos:
        bits.append(daily_pos)
    if rebound_day in {1, 2, 3}:
        bits.append(f"일봉 반등 {rebound_day}일차")
    return " / ".join(bits)


def _format_chart_pct_text(value: float, precision: int = 0) -> str:
    value = safe_float(value, 0)
    abs_v = abs(value)
    if abs_v < 0.05:
        return "0.0%"
    if abs_v < 1.0:
        return f"{value:.1f}%"
    if precision > 0:
        return f"{value:.{precision}f}%"
    return f"{value:.0f}%"


def _is_chart_flat_cluster(body3: float, body5: float, close3: float, close5: float, upper5: float, lower5: float) -> bool:
    return (
        abs(body3) < 0.12
        and abs(body5) < 0.18
        and abs(close3) < 5.0
        and abs(close5) < 5.0
        and abs(upper5) < 0.05
        and abs(lower5) < 0.05
    )


def format_chart_quant_summary_text(item: dict, compact: bool = False) -> str:
    ensure_roadmap_context(item)
    # v2.5.198: reverse_trace 저장 row는 body_ratio_1/close_pos_1 같은 짧은 키도 갖는다.
    body1 = safe_float(item.get("candle_body_ratio_1", item.get("body_ratio_1", 0)), 0) * 100.0
    body3 = safe_float(item.get("candle_body_ratio_3", item.get("body_ratio_3", 0)), 0) * 100.0
    body5 = safe_float(item.get("candle_body_ratio_5", item.get("body_ratio_5", 0)), 0) * 100.0
    upper1 = safe_float(item.get("upper_wick_pct_1", 0), 0)
    upper3 = safe_float(item.get("upper_wick_pct_3", 0), 0)
    upper5 = safe_float(item.get("upper_wick_pct_5", 0), 0)
    lower1 = safe_float(item.get("lower_wick_pct_1", 0), 0)
    lower3 = safe_float(item.get("lower_wick_pct_3", 0), 0)
    lower5 = safe_float(item.get("lower_wick_pct_5", 0), 0)
    close1 = safe_float(item.get("close_position_ratio_1", item.get("close_pos_1", 0)), 0) * 100.0
    close3 = safe_float(item.get("close_position_ratio_3", item.get("close_pos_3", 0)), 0) * 100.0
    close5 = safe_float(item.get("close_position_ratio_5", item.get("close_pos_5", 0)), 0) * 100.0
    bull_streak = int(safe_float(item.get("bullish_streak_5", 0), 0))
