    candle_3_text = "거의 안 움직임" if abs(body3) < 0.05 else _format_chart_pct_text(body3)
    candle_5_text = "거의 안 움직임" if abs(body5) < 0.05 else _format_chart_pct_text(body5)
    close_3_text = "횡보" if abs(close3) < 0.05 else _format_chart_pct_text(close3)
    close_5_text = "횡보" if abs(close5) < 0.05 else _format_chart_pct_text(close5)
    recent_flat_cluster = _is_chart_flat_cluster(body3, body5, close3, close5, upper5, lower5)
    if recent_flat_cluster:
        candle_3_text = "거의 안 움직임"
