# =========================================================
# 파일 I/O
# =========================================================
def load_json_file(path, default):
    lock = get_file_io_lock(path)
    with lock:
        if not os.path.exists(path):
            return default
        try:
            with open(path, "r", encoding="utf-8") as f:
                return json.load(f)
        except json.JSONDecodeError as e:
            broken_path = f"{path}.broken_{int(time.time())}"
            moved = False
            try:
                os.replace(path, broken_path)
                moved = True
            except Exception:
                pass
            log_exception_details("json_load", e, extra={"path": path, "backup_path": broken_path if moved else ""}, prefix="[JSON 로드 오류]")
            return default
        except Exception as e:
            log_exception_details("json_load", e, extra={"path": path}, prefix="[JSON 로드 오류]")
            return default

def make_json_safe_snapshot(data, max_depth: int = 12):
    """저장 중 원본 dict/list가 다른 스레드에서 바뀌어도 json.dump가 터지지 않게 스냅샷을 만든다."""
    def _snap(obj, depth: int):
        if depth >= max_depth:
            return str(obj)
        if isinstance(obj, dict):
            items = None
            for _ in range(3):
                try:
                    items = list(obj.items())
                    break
                except RuntimeError:
                    time.sleep(0.01)
            if items is None:
                try:
                    items = list(dict(obj).items())
                except Exception:
                    return {}
            out = {}
            for k, v in items:
                try:
                    key = str(k)
                except Exception:
                    key = repr(k)
                out[key] = _snap(v, depth + 1)
            return out
        if isinstance(obj, (list, tuple, set)):
            try:
                rows = list(obj)
            except RuntimeError:
                time.sleep(0.01)
                try:
                    rows = list(obj)
                except Exception:
                    return []
            return [_snap(v, depth + 1) for v in rows]
        if isinstance(obj, (str, int, float, bool)) or obj is None:
            return obj
        return str(obj)
    return _snap(data, 0)

def save_json_file(path, data):
    lock = get_file_io_lock(path)
    tmp_path = ""
    with lock:
        try:
            target_dir = os.path.dirname(os.path.abspath(path)) or "."
            snapshot = make_json_safe_snapshot(data)
            fd, tmp_path = tempfile.mkstemp(prefix=os.path.basename(path) + ".", suffix=".tmp", dir=target_dir)
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                json.dump(snapshot, f, ensure_ascii=False, indent=2, default=str)
                f.flush()
                os.fsync(f.fileno())
            os.replace(tmp_path, path)
            tmp_path = ""
        except Exception as e:
            try:
                if tmp_path and os.path.exists(tmp_path):
                    os.remove(tmp_path)
            except Exception:
                pass
            log_exception_details("json_save", e, extra={"path": path}, prefix="[JSON 저장 오류]")
def persist_price_check_state():
    try:
        # v2.5.160: refs/scheduled는 서로 맞물린 상태라 저장 시점도 한 묶음으로 잡는다.
        # 파일별 atomic write는 save_json_file이 담당하고, 여기서는 상태쌍 스냅샷을 고정한다.
        with STATE_PERSIST_LOCK:
            refs_snapshot = make_json_safe_snapshot(PRICE_CHECK_REFS)
            sched_snapshot = make_json_safe_snapshot(PRICE_CHECK_SCHEDULED)
            save_json_file(PRICE_CHECK_REFS_FILE, refs_snapshot)
            save_json_file(PRICE_CHECK_SCHEDULED_FILE, sched_snapshot)
    except Exception as e:
        print(f"[가격 확인 상태 저장 오류] {e}")
def load_price_check_state():
    global PRICE_CHECK_REFS, PRICE_CHECK_SCHEDULED
    refs = load_json_file(PRICE_CHECK_REFS_FILE, {})
    sched = load_json_file(PRICE_CHECK_SCHEDULED_FILE, {})
    PRICE_CHECK_REFS = refs if isinstance(refs, dict) else {}
    PRICE_CHECK_SCHEDULED = sched if isinstance(sched, dict) else {}
    cleanup_price_check_refs(time.time())
