    rows = load_json_file(RECENT_CANDIDATES_FILE, [])
    if isinstance(rows, list) and rows:
        return rows
    # 예전 버전에서 상대경로로 저장된 파일이 있으면 한 번 가져와서 절대경로 파일로 옮겨준다.
    legacy_rows = load_json_file(LEGACY_RECENT_CANDIDATES_FILE, [])
