def persist_missed_review_state():
    try:
        # v2.5.160: missed queue/log/meta도 같이 움직이는 상태라 한 번에 스냅샷을 잡는다.
        with STATE_PERSIST_LOCK:
            queue_snapshot = make_json_safe_snapshot(missed_review_queue)
            logs_snapshot = make_json_safe_snapshot(missed_review_logs)
            meta_snapshot = make_json_safe_snapshot(missed_review_meta if isinstance(missed_review_meta, dict) else {})
            save_json_file(MISSED_REVIEW_QUEUE_FILE, queue_snapshot)
            save_json_file(MISSED_REVIEW_LOG_FILE, logs_snapshot)
            save_json_file(MISSED_REVIEW_META_FILE, meta_snapshot)
    except Exception as e:
        print(f"[놓친 코인 상태 저장 오류] {e}")

def trim_missed_review_logs():
    global missed_review_logs
    rows = missed_review_logs if isinstance(missed_review_logs, list) else []
    now_ts = time.time()
    kept = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        if is_watch_excluded_ticker(str(row.get("ticker", "") or "")):
            continue
        ts = safe_float(row.get("logged_at", row.get("saved_at", 0)), 0)
        if ts > 0 and now_ts - ts > missed_review_retention_sec(row):
            continue
        kept.append(row)
    if len(kept) > MISSED_REVIEW_MAX_LOGS:
        kept.sort(key=lambda r: (get_missed_review_bucket(r) == "진짜놓침", safe_float(r.get("logged_at", r.get("saved_at", 0)), 0)), reverse=True)
        kept = kept[:MISSED_REVIEW_MAX_LOGS]
        kept.sort(key=lambda r: safe_float(r.get("logged_at", r.get("saved_at", 0)), 0))
    missed_review_logs = kept

def cleanup_missed_review_queue(now_ts: float = None):
    global missed_review_queue
    now_ts = safe_float(now_ts, time.time())
    fresh = {}
    if not isinstance(missed_review_queue, dict):
        missed_review_queue = {}
        return
    for ticker, row in missed_review_queue.items():
        if not isinstance(row, dict):
            continue
        saved_at = safe_float(row.get("saved_at", 0), 0)
        review_ts = safe_float(row.get("review_ts", 0), 0)
        if saved_at <= 0:
            continue
        if missed_review_noise_reason(row) and now_ts - saved_at > MISSED_REVIEW_NOISE_KEEP_SEC:
            continue
        keep_limit = MISSED_REVIEW_PENDING_KEEP_SEC if safe_float(row.get("review_ts", 0), 0) > now_ts else max(MISSED_REVIEW_DELAY_SEC * 3, 4 * 3600)
        if now_ts - saved_at > keep_limit:
            continue
        if review_ts <= 0:
            row["review_ts"] = saved_at + MISSED_REVIEW_DELAY_SEC
        fresh[str(ticker).upper().strip()] = row
    if len(fresh) > MISSED_REVIEW_MAX_QUEUE:
        ordered = sorted(fresh.items(), key=lambda kv: safe_float(kv[1].get("saved_at", 0), 0), reverse=True)
        fresh = dict(ordered[:MISSED_REVIEW_MAX_QUEUE])
    missed_review_queue = fresh

def load_missed_review_state():
    global missed_review_queue, missed_review_logs, missed_review_meta
    queue = load_json_file(MISSED_REVIEW_QUEUE_FILE, {})
    logs = load_json_file(MISSED_REVIEW_LOG_FILE, [])
    meta = load_json_file(MISSED_REVIEW_META_FILE, {})
    missed_review_queue = queue if isinstance(queue, dict) else {}
    missed_review_logs = logs if isinstance(logs, list) else []
    missed_review_meta = meta if isinstance(meta, dict) else {}
    cleanup_missed_review_queue(time.time())
    trim_missed_review_logs()


def load_internal_watch_track_state():
    global internal_watch_track_state
    data = load_json_file(INTERNAL_WATCH_TRACK_FILE, {"active": {}, "logs": []})
    if not isinstance(data, dict):
        data = {"active": {}, "logs": []}
    active = data.get("active") if isinstance(data.get("active"), dict) else {}
    logs = data.get("logs") if isinstance(data.get("logs"), list) else []
    internal_watch_track_state = {"active": active, "logs": dedupe_internal_watch_logs(logs)[-INTERNAL_WATCH_TRACK_MAX_LOGS:]}
    cleanup_internal_watch_track_state(time.time(), persist=False)


def persist_internal_watch_track_state():
    try:
        with STATE_PERSIST_LOCK:
            save_json_file(INTERNAL_WATCH_TRACK_FILE, make_json_safe_snapshot(internal_watch_track_state if isinstance(internal_watch_track_state, dict) else {"active": {}, "logs": []}))
    except Exception as e:
        print(f"[내부 감시 추적 저장 오류] {e}")


def _get_internal_watch_state_parts():
    global internal_watch_track_state
    if not isinstance(internal_watch_track_state, dict):
        internal_watch_track_state = {"active": {}, "logs": []}
    active = internal_watch_track_state.get("active")
    logs = internal_watch_track_state.get("logs")
    if not isinstance(active, dict):
        active = {}
        internal_watch_track_state["active"] = active
    if not isinstance(logs, list):
        logs = []
        internal_watch_track_state["logs"] = logs
    return active, logs






def _internal_watch_log_identity(row: dict) -> tuple:
    """v2.5.215: 내부감시 완료 기록 중복 제거용 키."""
    try:
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker", "") or "").upper().strip()
        saved = int(safe_float(row.get("saved_at", 0), 0) // 3)
        base = round(safe_float(row.get("base_price", 0), 0), 8)
        first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else {}
        reason = str(first.get("primary_reason", row.get("register_reason", "")) or "")[:40]
        return (ticker, saved, base, reason)
    except Exception:
        return (str(row.get("ticker", "") if isinstance(row, dict) else ""), 0, 0, "")


def dedupe_internal_watch_logs(logs: list) -> list:
    """완료 로그 중복 제거. 같은 키는 더 최근 closed_at/더 풍부한 결과를 남긴다."""
    if not isinstance(logs, list):
        return []
    kept = {}
    order = []
    for row in logs:
        if not isinstance(row, dict):
            continue
        key = _internal_watch_log_identity(row)
        prev = kept.get(key)
        if not isinstance(prev, dict):
            kept[key] = row
            order.append(key)
            continue
        prev_results = prev.get("results") if isinstance(prev.get("results"), dict) else {}
        row_results = row.get("results") if isinstance(row.get("results"), dict) else {}
        prev_score = len(prev_results) * 10 + safe_float(prev.get("closed_at", 0), 0) / 1e10
        row_score = len(row_results) * 10 + safe_float(row.get("closed_at", 0), 0) / 1e10
        if row_score >= prev_score:
            kept[key] = row
    return [kept[k] for k in order if k in kept]


def append_internal_watch_log(logs: list, row: dict):
    """내부감시 완료 로그를 추가하되, 같은 표본 중복은 병합한다.

    v2.5.243: 이전 버전은 신규 로그 추가 지점에서 자기 자신을 다시 호출하는 재귀 버그가 있었다.
    이 함수가 실패하면 회수/교체 로그가 제대로 남지 않아 내부감시 회전 상태를 추적하기 어려워진다.
    """
    try:
        if not isinstance(logs, list) or not isinstance(row, dict):
            return
        key = _internal_watch_log_identity(row)
        for i, old in enumerate(logs):
            if isinstance(old, dict) and _internal_watch_log_identity(old) == key:
                merged = dict(old)
                merged.update(row)
                logs[i] = merged
                return
        logs.append(row)
    except Exception:
        try:
            if isinstance(logs, list) and isinstance(row, dict):
                logs.append(row)
        except Exception:
            pass


def _internal_watch_row_priority(row: dict) -> float:
    """내부감시 active 슬롯 우선순위.

    v2.5.243: 단순 점수/거래대금만 보지 않고 돈흐름 라벨, 매수/매도 체결,
    초저가 틱노이즈, 실제 추적 결과(max/current)를 반영한다. 목적은 후보를 죽이는 것이 아니라
    active 14~18칸 안에서 더 좋은 후보에게 자리를 빨리 넘기는 것이다.
    """
    try:
        row = row if isinstance(row, dict) else {}
        snap = row.get("last_snapshot") if isinstance(row.get("last_snapshot"), dict) else row.get("first_snapshot", {})
        if not isinstance(snap, dict):
            snap = row
        score = safe_float(snap.get("snapshot_rank_score", snap.get("lite_score", 0)), 0)
        strongest = _row_strongest_rank_move(snap)
        leader = safe_float(snap.get("leader_score", 0), 0)
        turn = safe_float(snap.get("turnover_5m", snap.get("turnover_recent_5m", 0)), 0)
        code = money_status_code_for_row(snap)
        money_bonus = {
            "ok": 2.00,
            "thin": 0.30,
            "checking": -0.15,
            "delayed": -0.35,
            "verify_failed": -0.55,
            "unknown": -0.40,
            "suspect": -0.80,
            "tiny": -1.40,
            "actual_zero": -2.50,
        }.get(code, -0.20)
        try:
            sustain = classify_money_sustain_for_row(snap)
        except Exception:
            sustain = {}
        label = str(snap.get("money_sustain_label", "") or sustain.get("label", "") or "")
        money_prio = str(snap.get("money_watch_priority", "") or sustain.get("watch_priority", "") or "normal")
        flash = bool(snap.get("money_flash_risk", False)) or bool(sustain.get("flash_risk", False)) or ("반짝" in label or "식는" in label)
        flow_bonus = 0.0
        if money_prio == "high" or "돈유지 강함" in label:
            flow_bonus += 1.65
        elif money_prio == "watch" or "돈얇지만 강세" in label:
            flow_bonus += 0.45
        elif money_prio == "low":
            flow_bonus -= 1.20
        if flash:
            flow_bonus -= 2.40
        if is_rank_watch_low_price_tick_noise_v237(snap):
            flow_bonus -= 3.20
        # v2.5.244: 저점방어/저점높임 좋은 재출발형은 active 슬롯에서 조금 더 살리고,
        # 죽은 저점/약한 회복은 빨리 밀리게 한다.
        low_route = get_low_structure_route_label_v244(snap) if 'get_low_structure_route_label_v244' in globals() else ""
        low_score = max(
            safe_float(snap.get("low_defense_v2_score", 0), 0),
            safe_float(snap.get("low_structure_score_v2", 0), 0),
            safe_float(snap.get("low_zone_defense_score", 0), 0),
        )
        rising = safe_float(snap.get("low_rising_score_v2", 0), 0)
        if low_route in {"저점높임 재출발형", "저점방어 재출발형"}:
            flow_bonus += 0.85
        elif low_route == "저점방어 관찰형":
            flow_bonus += 0.25
        if bool(snap.get("low_dead_stay_flag_v2", False)) or bool(snap.get("low_break_weak_reclaim_flag_v2", False)):
            flow_bonus -= 1.10
        elif low_score >= 1.20 and rising >= 0.45:
            flow_bonus += 0.25
        saved_at = safe_float(row.get("saved_at", 0), 0)
        age_min = max(0.0, (time.time() - saved_at) / 60.0) if saved_at > 0 else 0.0
        age_bonus = 0.40 if age_min < 10 else (0.05 if age_min < 30 else -0.45)
        max_up = safe_float(row.get("max_up_pct", 0), 0)
        last_up = safe_float(row.get("last_up_pct", 0), 0)
        result_bonus = 0.0
        if max_up >= 0.70 and last_up >= 0.25:
            result_bonus += 1.00
        elif max_up >= 0.35 and last_up >= 0.10:
            result_bonus += 0.35
        if last_up <= safe_float(globals().get("INTERNAL_WATCH_FAST_EJECT_DROP_PCT", -0.90), -0.90):
            result_bonus -= 3.00
        elif last_up <= -0.50:
            result_bonus -= 1.30
        if max_up <= 0.10 and age_min >= 3:
            result_bonus -= 0.80
        return (score * 0.70) + (strongest * 1.45) + (leader * 0.55) + min(turn / 10_000_000.0, 2.0) + money_bonus + flow_bonus + age_bonus + result_bonus
    except Exception:
        return 0.0

def cleanup_internal_watch_track_state(now_ts: float = None, persist: bool = True):
    now_ts = safe_float(now_ts, time.time())
    active, logs = _get_internal_watch_state_parts()
    changed = False
    for ticker in list(active.keys()):
        row = active.get(ticker)
        if not isinstance(row, dict):
            active.pop(ticker, None)
            changed = True
            continue
        saved_at = safe_float(row.get("saved_at", 0), 0)
        if saved_at <= 0 or now_ts - saved_at > INTERNAL_WATCH_TRACK_TTL_SEC:
            row["closed_reason"] = "TTL 만료"
            row["closed_at"] = now_ts
            append_internal_watch_log(logs, row)
            active.pop(ticker, None)
            changed = True
    # v2.5.237: 식은 후보/돈 확인 지연 후보/틱노이즈 후보가 슬롯을 오래 잡고 있으면
    # 새 강세 후보가 등록 보류로 밀린다. 알림 조건을 조이는 게 아니라 내부감시 자리만 회수한다.
    try:
        for ticker in list(active.keys()):
            row = active.get(ticker)
            if not isinstance(row, dict):
                continue
            saved_at = safe_float(row.get("saved_at", 0), 0)
            age_sec = max(0.0, now_ts - saved_at) if saved_at > 0 else 0.0
            first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else row
            last = row.get("last_snapshot") if isinstance(row.get("last_snapshot"), dict) else first
            max_up = safe_float(row.get("max_up_pct", 0), 0)
            last_up = safe_float(row.get("last_up_pct", 0), 0)
            money_code = money_status_code_for_row(last if isinstance(last, dict) else first)
            try:
                sustain_ctx = classify_money_sustain_for_row(last if isinstance(last, dict) else first)
            except Exception:
                sustain_ctx = {}
            sustain_label = str((last if isinstance(last, dict) else first).get("money_sustain_label", "") or sustain_ctx.get("label", "") or "")
            sustain_prio = str((last if isinstance(last, dict) else first).get("money_watch_priority", "") or sustain_ctx.get("watch_priority", "") or "normal")
            flash_risk = bool((last if isinstance(last, dict) else first).get("money_flash_risk", False)) or bool(sustain_ctx.get("flash_risk", False)) or ("반짝" in sustain_label or "식는" in sustain_label)
            close_reason = ""
            # v2.5.251: 실제돈작음 후보는 복기용 가치만 남기고 active 슬롯을 오래 먹지 않게 빠르게 하향한다.
            if age_sec >= safe_float(globals().get("INTERNAL_WATCH_TINY_FAST_EJECT_SEC", 45), 45) and money_code in {"actual_zero", "tiny"} and max_up <= 0.35 and last_up <= 0.20:
                close_reason = "실제돈작음 후보 빠른 하향(슬롯 회수)"
            elif age_sec >= safe_float(globals().get("INTERNAL_WATCH_THIN_FAST_EJECT_SEC", 90), 90) and money_code == "thin" and max_up <= 0.35 and last_up <= 0.15:
                close_reason = "돈얇음 후보 빠른 하향(슬롯 회수)"
            elif is_rank_watch_low_price_tick_noise_v237(first) or is_rank_watch_low_price_tick_noise_v237(last if isinstance(last, dict) else first):
                close_reason = "초저가 틱노이즈 내부감시 슬롯 회수"
            elif age_sec >= 15 and 'is_money_or_candle_flash_watch_limited_v244' in globals() and is_money_or_candle_flash_watch_limited_v244(last if isinstance(last, dict) else first) and max_up <= 0.35 and last_up <= 0.15:
                close_reason = "반짝형/현재봉 약화 후보 슬롯 빠른 회수"
            elif age_sec >= safe_float(globals().get("INTERNAL_WATCH_FAST_EJECT_AGE_SEC", 20), 20) and last_up <= safe_float(globals().get("INTERNAL_WATCH_FAST_EJECT_DROP_PCT", -0.90), -0.90):
                close_reason = "급격히 식은 후보 슬롯 회수(-0.9% 이하)"
            elif age_sec >= safe_float(globals().get("INTERNAL_WATCH_FLASH_EJECT_AGE_SEC", 45), 45) and flash_risk and max_up <= 0.30 and last_up <= 0.15:
                close_reason = "돈흐름 반짝/식는중 후보 슬롯 회수"
            elif age_sec >= 75 and sustain_prio == "low" and max_up <= 0.20 and last_up <= 0.10:
                close_reason = "돈흐름 우선순위 낮은 후보 슬롯 회수"
            elif age_sec >= 180 and money_code in {"checking", "delayed", "verify_failed", "suspect", "unknown"} and max_up <= 0.15:
                close_reason = "대금확인 지연/미확인 후보 슬롯 회수"
            elif age_sec >= 420 and max_up < 0.20 and last_up <= 0.05:
                close_reason = "반응 없는 내부감시 후보 슬롯 회수"
            elif age_sec >= 600 and money_code in {"tiny", "actual_zero", "thin"} and max_up < 0.45:
                close_reason = "돈 약한 내부감시 장기 점유 정리"
            if close_reason:
                row["closed_reason"] = close_reason
                row["closed_at"] = now_ts
                row["closed_priority"] = round(_internal_watch_row_priority(row), 3)
                append_internal_watch_log(logs, row)
                active.pop(ticker, None)
                changed = True
    except Exception:
        pass

    # v2.5.203: 실거래대금 0만/극소액 후보가 내부감시를 도배하지 않게 먼저 정리한다.
    try:
        weak_limit = int(safe_float(globals().get("INTERNAL_WATCH_WEAK_MONEY_MAX_ACTIVE", 3), 3))
        zero_limit = int(safe_float(globals().get("INTERNAL_WATCH_ZERO_MONEY_MAX_ACTIVE", 0), 0))
        ordered_all = sorted(active.items(), key=lambda kv: safe_float(kv[1].get("saved_at", 0), 0), reverse=True)
        keep_active = {}
        weak_kept = 0
        zero_kept = 0
        for ticker, row in ordered_all:
            if not isinstance(row, dict):
                continue
            first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else row
            code = money_status_code_for_row(first)
            is_zero = code == "actual_zero"
            is_weak = code in {"actual_zero", "tiny", "thin"}
            if is_zero and zero_kept >= max(0, zero_limit):
                row["closed_reason"] = "실거래대금 0만 내부감시 제한 정리"
                row["closed_at"] = now_ts
                append_internal_watch_log(logs, row)
                changed = True
                continue
            if is_weak and weak_kept >= max(1, weak_limit):
                row["closed_reason"] = "돈 약한 내부감시 과다 정리"
                row["closed_at"] = now_ts
                append_internal_watch_log(logs, row)
                changed = True
                continue
            keep_active[ticker] = row
            if is_zero:
                zero_kept += 1
            if is_weak:
                weak_kept += 1
        if len(keep_active) != len(active):
            active.clear()
            active.update(keep_active)
    except Exception:
        pass
    max_active_now = get_internal_watch_dynamic_max_active(active=active) if 'get_internal_watch_dynamic_max_active' in globals() else INTERNAL_WATCH_TRACK_MAX_ACTIVE
    if len(active) > max_active_now:
        # v2.5.215~243: 최신순이 아니라 우선순위 낮은 후보부터 정리한다.
        ordered = sorted(active.items(), key=lambda kv: _internal_watch_row_priority(kv[1]), reverse=True)
        keep = dict(ordered[:max_active_now])
        for ticker, row in ordered[max_active_now:]:
            if isinstance(row, dict):
                row["closed_reason"] = "활성 추적 초과 정리(우선순위 낮음)"
                row["closed_at"] = now_ts
                row["closed_priority"] = round(_internal_watch_row_priority(row), 3)
                logs.append(row)
        internal_watch_track_state["active"] = keep
        changed = True
    if len(logs) > INTERNAL_WATCH_TRACK_MAX_LOGS:
        internal_watch_track_state["logs"] = dedupe_internal_watch_logs(logs)[-INTERNAL_WATCH_TRACK_MAX_LOGS:]
        changed = True
    if changed and persist:
        persist_internal_watch_track_state()


def classify_internal_watch_track_result(max_up_pct: float, end_up_pct: float, min_down_pct: float) -> str:
    max_up_pct = safe_float(max_up_pct, 0)
    end_up_pct = safe_float(end_up_pct, 0)
    min_down_pct = safe_float(min_down_pct, 0)
    if max_up_pct >= 3.0 and end_up_pct >= 1.0:
        return "승격 놓침 가능성"
    if max_up_pct >= 3.0 and end_up_pct < 0.5:
        return "가짜 상승"
    if max_up_pct >= 1.5 and end_up_pct >= 0.5:
        return "감시 판단 좋음"
    if max_up_pct >= 1.2 and end_up_pct < 0.3:
        return "튀고 식음"
    if max_up_pct <= 0.8 and end_up_pct <= 0.3:
        return "보류 정상"
    if min_down_pct <= -1.8 and end_up_pct <= 0.0:
        return "위험 회피"
    return "결과 애매"


