def get_reverse_trace_stage_label(stage: str) -> str:
    stage = str(stage or '').strip()
    return {
        'shortlist': '1차 후보',
        'alert': '미리 볼 후보',
        'user_alert_sent': '실제 알림 보냄',
        'rank_watch': '순위권 포착 기록',
    }.get(stage, stage or '기록')

def get_reverse_trace_bucket_label(bucket: str) -> str:
    bucket = str(bucket or '').strip()
    return {
        'user_alert': '지금 볼 후보',
        'pre_entry': '미리 볼 후보',
        'internal_watch': '내부 감시',
        'rank_watch': '복기용 기록',
        'late': '늦은 후보',
        'skip': '제외',
    }.get(bucket, bucket or '-')


def get_reverse_trace_bucket_display(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        if str(row.get('bucket', '') or '').strip() == 'rank_watch':
            return realtime_rank_watch_action_label(row)
        return get_reverse_trace_bucket_label(row.get('bucket', ''))
    except Exception:
        return get_reverse_trace_bucket_label((row or {}).get('bucket', '') if isinstance(row, dict) else '')

def format_reverse_trace_ts(ts: float) -> str:
    try:
        return datetime.fromtimestamp(float(ts), ZoneInfo(TIMEZONE)).strftime('%m-%d %H:%M:%S')
    except Exception:
        return '--:--:--'

def format_htf_brief_for_row(row: dict) -> str:
    label = str(row.get('htf_setup_label', '') or '확인중').strip()
    trend = str(row.get('htf_trend_label', '') or '').strip()
    gap = safe_float(row.get('htf_gap_pct', 999), 999)
    rise = safe_float(row.get('htf_rise_pct', 0), 0)
    slope7 = safe_float(row.get('htf_ma7_slope_pct', 0), 0)
    slope30 = safe_float(row.get('htf_ma30_slope_pct', 0), 0)
    if '데이터 부족' in label or gap >= 900:
        return label
    suffix = f" / {trend}" if trend else ""
    return f"{label}{suffix} (고점거리 {gap:.2f}% / 저점대비 {rise:.2f}% / MA7기울기 {slope7:+.2f}% / MA30기울기 {slope30:+.2f}%)"

def format_daily_brief_for_row(row: dict) -> str:
    label = str(row.get('daily_setup_label', '') or '확인중').strip()
    gap = safe_float(row.get('daily_gap_pct', 999), 999)
    rise = safe_float(row.get('daily_rise_pct', 0), 0)
    return f"{label} (고점거리 {gap:.2f}% / 저점대비 {rise:.2f}%)"

def format_rank_line_for_reverse_trace(row: dict) -> str:
    parts = []
    for label, key in (("거래대금", "turnover_rank"), ("5분", "change5_rank"), ("주목", "leader_rank")):
        bit = format_rank_item(label, row.get(key, 0))
        if bit:
            parts.append(bit)
    return " / ".join(parts) if parts else "내부 유사 순위 감시 기록"


def format_reverse_trace_block(row: dict, idx: int = 1) -> str:
    if not isinstance(row, dict):
        return ''
    try:
        row = apply_precision_minute1_state_to_row(dict(row)) if 'apply_precision_minute1_state_to_row' in globals() else dict(row)
    except Exception:
        row = dict(row)
    reason = str(row.get('reason', '') or '').strip()
    reasons = row.get('reasons', []) if isinstance(row.get('reasons', []), list) else []
    extra = ', '.join([str(x).strip() for x in reasons if str(x).strip()][:2])
    if reason and extra:
        reason_text = f"{reason} / {extra}"
    else:
        reason_text = reason or extra or '-'
    pattern_text = str(row.get('label_text', '') or '').strip()
    if not pattern_text:
        pattern_text = get_fast_scan_label_text(str(row.get('primary_reason', '') or ''))
    final_bucket_text = get_fast_scan_bucket_text(row.get('bucket', ''))
    if str(row.get('bucket', '') or '') == 'rank_watch':
        final_label = realtime_rank_watch_action_label(row)
    else:
        final_label = pattern_text if final_bucket_text == '내부 감시' else final_bucket_text
    rebreakout_gap_text = ''
    rebreakout_gap = safe_float(row.get('rebreakout_gap_pct', 999), 999)
    if 0 <= rebreakout_gap < 900:
        rebreakout_gap_text = f" / 단기고점거리 {rebreakout_gap:.2f}%"
    ticker = str(row.get('ticker', '?') or '?').upper().strip()
    high_gap_text = format_pct_or_pending(row.get('below_30m_high_pct', row.get('below_high', 999)), pending_text="고점 거리 확인 안 됨", zero_text="고점 바로 근처")
    lines = [
        f"{circled_number(idx)} {ticker_review_icon(row)} {ticker}",
        f"- 시간: {format_reverse_trace_ts(safe_float(row.get('ts', 0), 0))}",
        f"- 단계: {get_reverse_trace_stage_label(row.get('stage', ''))} / 최종분류: {get_reverse_trace_bucket_display(row)} / 등급 {str(row.get('grade', '-') or '-')}",
        f"- 패턴태그: {pattern_text or '-'}",
        f"- 최종판정: {final_label}",
        f"- 기록뜻: {realtime_rank_watch_action_explain(row)}" if str(row.get('bucket', '') or '') == 'rank_watch' else '',
        f"- 흐름: 1분 {safe_float(row.get('change_1', 0), 0):+.2f}% / 3분 {safe_float(row.get('change_3', 0), 0):+.2f}% / 5분 {safe_float(row.get('change_5', 0), 0):+.2f}% / 15분 {safe_float(row.get('change_15', 0), 0):+.2f}% / 30분 {safe_float(row.get('change_30', 0), 0):+.2f}% / 1시간 {safe_float(row.get('change_60', 0), 0):+.2f}%",
        f"- 위치: 저점대비 {safe_float(row.get('from_low', 0), 0):+.2f}% / 최근30분 고점거리 {high_gap_text}",
        format_gap_context_line(row),
        format_chart_lifecycle_line(row),
        format_recent_30m_price_context(row, current_price=safe_float(row.get('current_price', row.get('price', 0)), 0), prefix='- 최근30분 기준값'),
        format_recent_60m_price_context(row, prefix='- 최근60분 기준값'),
        f"- 상위봉: 4시간 {format_htf_brief_for_row(row)} / 일봉 {format_daily_brief_for_row(row)}",
        f"- 힘: 거래량 {safe_float(row.get('vol_ratio', 0), 0):.2f}배 / 시장주목 {safe_float(row.get('leader_score', 0), 0):.2f} / 최근5분 거래대금 {format_money_for_row(row)}",
        format_reverse_trace_chart_line(row, rebreakout_gap_text=rebreakout_gap_text),
        f"- 순위: {format_rank_line_for_reverse_trace(row)}",
        f"- 이유: {reason_text}",
    ]
    lines = [x for x in lines if str(x).strip()]
    return '\n'.join(lines)

def trace_recent_command(update, context: CallbackContext):
    load_reverse_trace_logs()
    limit = 5
    if getattr(context, 'args', None):
        try:
            limit = int(context.args[0])
        except Exception:
            limit = 5
    limit = max(1, min(limit, 10))
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        send("🧭 아직 역추적 기록이 없어\n\n- 알림/후보가 조금 더 쌓이면 여기서 최근 흐름을 바로 볼 수 있어")
        return
    recent = rows[-limit:]
    lines = ['🧭 최근 역추적 기록', '', f'- 최근 {len(recent)}건']
    for idx, row in enumerate(reversed(recent), start=1):
        lines.append('')
        lines.append(format_reverse_trace_block(row, idx=idx))
    send_text_chunks('\n'.join(lines), limit=TG_MESSAGE_SOFT_LIMIT)

def trace_command(update, context: CallbackContext):
    load_reverse_trace_logs()
    args = list(getattr(context, 'args', []) or [])
    if not args:
        trace_recent_command(update, context)
        return
    ticker = str(args[0] or '').upper().strip()
    if not ticker:
        send("🧭 코인명을 같이 적어줘\n\n예) /trace SPURS")
        return
    rows = [x for x in reverse_trace_logs if isinstance(x, dict) and str(x.get('ticker', '') or '').upper().strip() == ticker]
    if not rows:
        send(f"🧭 {ticker} 역추적 기록이 아직 없어\n\n- 아직 후보/알림 기록이 안 쌓였거나\n- 로그 저장 전일 수 있어")
        return
    recent = rows[-8:]
    lines = [f'🧭 {ticker} 역추적 기록', '', f'- 최근 {len(recent)}건']
    for idx, row in enumerate(reversed(recent), start=1):
        lines.append('')
        lines.append(format_reverse_trace_block(row, idx=idx))
    send('\n'.join(lines))

def save_runtime_settings():
    data = {
        "auto_buy": bool(AUTO_BUY),
        "last_seen_version": BOT_VERSION,
    }
    save_json_file(RUNTIME_SETTINGS_FILE, data)
    return True
def load_runtime_settings():
    global AUTO_BUY, STARTUP_PREV_VERSION
    data = load_json_file(RUNTIME_SETTINGS_FILE, {})
    if not isinstance(data, dict):
        AUTO_BUY = False
        STARTUP_PREV_VERSION = ""
        return False
    AUTO_BUY = bool(data.get("auto_buy", AUTO_BUY))
    STARTUP_PREV_VERSION = str(data.get("last_seen_version", "") or "").strip()
    return True

def force_autobuy_off_on_startup():
    global AUTO_BUY
    changed = bool(AUTO_BUY)
    AUTO_BUY = False
    save_runtime_settings()
    return changed
def save_config():
    return save_runtime_settings()
def save_settings():
    return save_runtime_settings()
RECENT_CANDIDATE_ALERTS = load_recent_candidate_alerts()
trade_logs = load_json_file(LOG_FILE, [])
CLOSE_TYPES = {"TP", "TRAIL_TP", "BREAKEVEN", "STOP", "TIME_STOP", "SCENARIO_FAIL", "EARLY_FAIL"}
def save_logs():
    save_json_file(LOG_FILE, trade_logs)
def add_log(item: dict):
    trade_logs.append(item)
    save_logs()
def mark_position_state_dirty():
    global position_state_dirty
    position_state_dirty = True
def flush_position_state(force=False):
    global position_state_dirty, last_position_save_time
    now_ts = time.time()
    if (not force) and (not position_state_dirty):
        return False
    if (not force) and (now_ts - last_position_save_time < POSITION_SAVE_MIN_INTERVAL_SEC):
        return False
    save_json_file(POSITIONS_FILE, active_positions)
    position_state_dirty = False
    last_position_save_time = now_ts
    return True
def save_positions(force=True):
    if force:
        return flush_position_state(force=True)
    mark_position_state_dirty()
    return False
def load_positions():
    global active_positions, position_state_dirty, last_position_save_time
    active_positions = load_json_file(POSITIONS_FILE, {})
    position_state_dirty = False
    last_position_save_time = time.time()
def clear_position_file_if_empty():
    if not active_positions and os.path.exists(POSITIONS_FILE):
        try:
            os.remove(POSITIONS_FILE)
        except Exception:
            pass
def save_pending_sells():
    save_json_file(PENDING_SELLS_FILE, pending_sells)
def load_pending_sells():
    global pending_sells
    pending_sells = load_json_file(PENDING_SELLS_FILE, {})
def save_pending_buys():
    save_json_file(PENDING_BUYS_FILE, pending_buy_candidates)
def load_pending_buys():
    global pending_buy_candidates
    pending_buy_candidates = load_json_file(PENDING_BUYS_FILE, {})
