def merge_missed_review_row(base: dict, extra: dict):
    if not isinstance(base, dict):
        return extra
    if not isinstance(extra, dict):
        return base
    for key in ["seen_market", "seen_shortlist", "seen_signal", "alert_sent", "higher_low_hint", "seen_hot_rank"]:
        base[key] = bool(base.get(key, False) or extra.get(key, False))
    if extra.get("alert_section"):
        base["alert_section"] = extra.get("alert_section")
    if extra.get("display_key"):
        base["display_key"] = extra.get("display_key")
    if extra.get("quality_block_reason") and not base.get("quality_block_reason"):
        base["quality_block_reason"] = extra.get("quality_block_reason")
    for key in [
        "strategy", "strategy_label", "trade_tier", "signal_score", "edge_score", "vol_ratio", "leader_score",
        "change_pct", "turnover", "chg_5m", "chg_30m", "from_30m_low_pct", "below_30m_high_pct",
        "vol_5v20_ratio", "chart_rise_pct", "chart_gap_pct", "chart_zone_ratio", "high_gap_pct",
        "change_1_rank", "change_3_rank", "change_5_rank", "vol_ratio_rank", "turnover_rank_pulse", "leader_rank", "turnover_rank", "surge_rank",
        "body_ratio_1", "body_ratio_3", "body_ratio_5", "upper_wick_pct_1", "upper_wick_pct_3", "upper_wick_pct_5", "lower_wick_pct_1", "lower_wick_pct_3", "lower_wick_pct_5",
        "close_pos_1", "close_pos_3", "close_pos_5", "bullish_streak_5", "bearish_streak_5", "strong_bullish_count_5",
        "pullback_pct_18", "recovery_from_low_pct", "recovery_speed_pct", "recovery_quality_score", "low_zone_stay_bars", "low_zone_reclaim_count", "turnover_persistence_score", "turnover_sustain_ratio_3v10", "turnover_sustain_ratio_5v20", "pullback_duration_bars",
        "compression_score", "rebreakout_score", "rebreakout_attempts", "rebreakout_success_rate", "rebreakout_success_attempts", "rebreakout_failures", "hold_near_high_bars", "hold_near_high_bars_05", "hold_near_high_bars_10", "breakout_hold_score",
        "chart_quant_label", "htf_trend_label", "htf_ma7_slope_pct", "htf_ma30_slope_pct",
    ]:
        if (not base.get(key)) and extra.get(key) not in [None, ""]:
            base[key] = extra.get(key)
    base_saved = safe_float(base.get("saved_at", 0), 0)
    extra_saved = safe_float(extra.get("saved_at", 0), 0)
    if extra_saved > 0 and (base_saved <= 0 or extra_saved < base_saved):
        base["saved_at"] = extra_saved
        base["review_ts"] = extra.get("review_ts", extra_saved + MISSED_REVIEW_DELAY_SEC)
        if safe_float(extra.get("base_price", 0), 0) > 0:
            base["base_price"] = extra.get("base_price")
    return base

def register_missed_review_candidate(item: dict, now_ts: float = None, seen_market: bool = False, seen_shortlist: bool = False, seen_signal: bool = False, alert_sent: bool = False, alert_section: str = "", quality_block_reason: str = "", persist: bool = True):
    global missed_review_queue
    if not MISSED_REVIEW_ON:
        return
    row = build_missed_review_row_from_item(item, now_ts=now_ts)
    if not row:
        return
    ticker = row["ticker"]
    row["seen_market"] = bool(seen_market)
    row["seen_shortlist"] = bool(seen_shortlist)
    row["seen_signal"] = bool(seen_signal)
    row["alert_sent"] = bool(alert_sent)
    row["alert_section"] = str(alert_section or "").strip()
    row["display_key"] = str(alert_section or row.get("display_key", "")).strip() or str(row.get("display_key", "")).strip()
    row["quality_block_reason"] = str(quality_block_reason or "").strip()
    noise_reason = missed_review_noise_reason(row)
    if noise_reason:
        try:
            missed_review_meta.setdefault("noise_dropped", 0)
            missed_review_meta["noise_dropped"] = int(safe_float(missed_review_meta.get("noise_dropped", 0), 0)) + 1
            missed_review_meta["last_noise_drop"] = {"ticker": ticker, "reason": noise_reason, "ts": now_ts}
            if persist:
                persist_missed_review_state()
        except Exception:
            pass
        return
    row["missed_tracking_bucket"] = "대기"
    existing = missed_review_queue.get(ticker)
    changed = False
    if isinstance(existing, dict):
        existing_saved = safe_float(existing.get("saved_at", 0), 0)
        row_saved = safe_float(row.get("saved_at", 0), 0)
        if existing_saved > 0 and row_saved - existing_saved <= MISSED_REVIEW_REGISTER_COOLDOWN_SEC:
            missed_review_queue[ticker] = merge_missed_review_row(existing, row)
            changed = True
        else:
            missed_review_queue[ticker] = row
            changed = True
    else:
        missed_review_queue[ticker] = row
        changed = True
    if changed:
        cleanup_missed_review_queue(now_ts)
        if persist:
            persist_missed_review_state()

def register_missed_review_market_candidates(cache: dict, now_ts: float = None, limit: int = MISSED_REVIEW_MARKET_LIMIT):
    if not MISSED_REVIEW_ON or int(limit) <= 0:
        return 0
    now_ts = safe_float(now_ts, time.time())
    picked = []
    picked.extend(build_missed_review_market_candidates(cache, limit=limit))
    rank_limit = min(int(limit), max(4, MARKET_PULSE_TOP_N // 2))
    picked.extend(build_market_rank_watch_candidates(cache, limit_each=rank_limit))
    seen = set()
    changed = 0
    for item in picked:
        ticker = str(item.get("ticker", "") or "").upper().strip()
        if not ticker or ticker in seen:
            continue
        seen.add(ticker)
        before = dict(missed_review_queue.get(ticker, {})) if isinstance(missed_review_queue.get(ticker), dict) else None
        register_missed_review_candidate(item, now_ts=now_ts, seen_market=True, persist=False)
        after = missed_review_queue.get(ticker)
        if before != after:
            changed += 1
    if changed > 0:
        cleanup_missed_review_queue(now_ts)
        persist_missed_review_state()
    return changed

def initial_spot_good_enough_for_missed_review(row: dict):
    high_gap_pct = safe_float(row.get("high_gap_pct", row.get("below_30m_high_pct", 999)), 999)
    from_low = safe_float(row.get("from_30m_low_pct", 0), 0)
    chart_rise = safe_float(row.get("chart_rise_pct", from_low), from_low)
    chg_5 = safe_float(row.get("chg_5m", 0), 0)
    chg_30 = safe_float(row.get("chg_30m", 0), 0)
    vol_ratio = safe_float(row.get("vol_ratio", 0), 0)
    leader = safe_float(row.get("leader_score", 0), 0)
    if high_gap_pct < MISSED_REVIEW_NEAR_HIGH_BLOCK_PCT:
        return False, "시작 자리 자체가 최근 고점에 너무 가까웠음"
    if from_low > MISSED_REVIEW_MAX_BASE_FROM_LOW_PCT and high_gap_pct < 1.20:
        return False, "시작할 때 이미 저점에서 꽤 올라온 자리였음"
    if chart_rise > MISSED_REVIEW_MAX_BASE_CHART_RISE_PCT and high_gap_pct < 1.80:
        return False, "시작할 때 차트상 이미 위쪽 자리였음"
    if max(chg_5, chg_30, from_low) < 0.10 and vol_ratio < MISSED_REVIEW_MIN_BASE_VOL_RATIO and leader < MISSED_REVIEW_MIN_BASE_LEADER_SCORE:
        return False, "시작할 때는 시장 힘이 아직 거의 없었음"
    return True, ""

def classify_missed_review_result_quality(best_up_pct: float, end_up_pct: float, worst_down_pct: float) -> str:
    best_up_pct = safe_float(best_up_pct, 0)
    end_up_pct = safe_float(end_up_pct, 0)
    worst_down_pct = safe_float(worst_down_pct, 0)
    peak_fade = best_up_pct - end_up_pct
    qualifies_move = (
        best_up_pct >= MISSED_REVIEW_MIN_FAST_UP_PCT
        or (best_up_pct >= MISSED_REVIEW_MIN_BEST_UP_PCT and end_up_pct >= MISSED_REVIEW_MIN_END_UP_PCT)
    )
    if not qualifies_move:
        if best_up_pct >= 1.60 and end_up_pct >= 0.60:
            return "assist"
        if best_up_pct >= 2.20 and end_up_pct >= 0.20 and worst_down_pct > -2.40:
            return "assist"
        return "weak"
    if end_up_pct <= MISSED_REVIEW_MAX_FALSE_SPIKE_END_DOWN_PCT and peak_fade >= MISSED_REVIEW_MAX_FALSE_SPIKE_FADE_PCT:
        return "spike"
    if best_up_pct >= MISSED_REVIEW_MIN_FAST_UP_PCT and end_up_pct < MISSED_REVIEW_MIN_TRUE_END_UP_PCT and peak_fade >= MISSED_REVIEW_MAX_FALSE_SPIKE_FADE_PCT:
        return "spike"
    if end_up_pct >= MISSED_REVIEW_MIN_KEEP_AFTER_SPIKE_END_PCT:
        return "good"
    if best_up_pct >= MISSED_REVIEW_MIN_BEST_UP_PCT and end_up_pct >= MISSED_REVIEW_MIN_END_UP_PCT and worst_down_pct > -1.60:
        return "good"
    if best_up_pct >= 1.60 and end_up_pct >= 0.60:
        return "assist"
    return "weak"

def get_missed_review_window_stats(ticker: str, base_price: float, eval_start_ts: float = 0.0, eval_end_ts: float = 0.0):
    now_ts = time.time()
    start_ts = safe_float(eval_start_ts, 0)
    end_ts = safe_float(eval_end_ts, 0)
    if start_ts <= 0:
        start_ts = now_ts - 1800
    if end_ts <= 0:
        end_ts = start_ts + 1800
    if end_ts < start_ts:
        end_ts = start_ts + 1800
    start_floor_ts = floor_minute_ts(start_ts)
    end_floor_ts = floor_minute_ts(end_ts)
    stats = {
        "best_up_pct": 0.0,
        "end_up_pct": 0.0,
        "worst_down_pct": 0.0,
        "best_price": base_price,
        "end_price": base_price,
        "worst_price": base_price,
        "best_price_ts": 0.0,
        "worst_price_ts": 0.0,
        "end_price_ts": 0.0,
        "eval_start_ts": start_floor_ts if start_floor_ts > 0 else start_ts,
        "eval_end_ts": end_floor_ts if end_floor_ts > 0 else end_ts,
        "pending": now_ts < end_ts,
        "window_candles": 0,
        "source_interval": "minute1",
        "window_source_ok": False,
    }
    if base_price <= 0:
        return stats
    # 평가 종료 전에는 결과를 미리 계산하지 않는다.
    if now_ts < end_ts:
        return stats
    try:
        df = get_ohlcv(ticker, "minute1")
        if df is None or len(df) < 2:
            return stats
        recent = df.copy()
        idx_ts = recent.index.map(lambda x: float(x.timestamp()) if hasattr(x, 'timestamp') else 0.0)
        recent = recent.assign(_ts=idx_ts)
        window = recent[(recent["_ts"] >= start_floor_ts) & (recent["_ts"] <= end_floor_ts)]
        if len(window) < 1:
            return stats
        window = window.sort_values("_ts")
        end_row = window.iloc[-1]
        high_idx = window["high"].astype(float).idxmax()
        low_idx = window["low"].astype(float).idxmin()
        high_row = window.loc[high_idx]
        low_row = window.loc[low_idx]
        high_price = safe_float(high_row.get("high", base_price), base_price)
        low_price = safe_float(low_row.get("low", base_price), base_price)
        end_price = safe_float(end_row.get("close", base_price), base_price)
        stats["best_price"] = high_price
        stats["worst_price"] = low_price
        stats["end_price"] = end_price
        stats["best_price_ts"] = safe_float(high_row.get("_ts", 0), 0)
        stats["worst_price_ts"] = safe_float(low_row.get("_ts", 0), 0)
        stats["end_price_ts"] = safe_float(end_row.get("_ts", 0), 0)
        stats["window_candles"] = int(len(window))
        stats["best_up_pct"] = ((high_price - base_price) / base_price) * 100.0 if base_price > 0 else 0.0
        stats["end_up_pct"] = ((end_price - base_price) / base_price) * 100.0 if base_price > 0 else 0.0
        stats["worst_down_pct"] = ((low_price - base_price) / base_price) * 100.0 if base_price > 0 else 0.0
        stats["pending"] = False
        stats["window_source_ok"] = True
    except Exception:
        return stats
    return stats

def is_missed_review_late_move(row: dict) -> bool:
    from_low = safe_float(row.get("from_30m_low_pct", row.get("from_low", 0)), 0)
    chart_rise = safe_float(row.get("chart_rise_pct", from_low), from_low)
    chg_30 = safe_float(row.get("chg_30m", 0), 0)
    high_gap = min(
        safe_float(row.get("high_gap_pct", 999), 999),
        safe_float(row.get("below_30m_high_pct", 999), 999),
        safe_float(row.get("chart_gap_pct", 999), 999),
    )
    if from_low >= MISSED_REVIEW_LATE_FROM_LOW_PCT:
        return True
    if chart_rise >= MISSED_REVIEW_LATE_CHART_RISE_PCT:
        return True
    if from_low >= 2.60 and chg_30 >= MISSED_REVIEW_LATE_CHANGE30_PCT:
        return True
    if from_low >= 2.80 and 0 <= high_gap <= 1.20:
        return True
    return False

def classify_missed_review_type(row: dict) -> str:
    if bool(row.get("data_fetch_failed", False)):
        return "데이터 실패로 못 봄"
    if bool(row.get("alert_sent", False)) and str(row.get("alert_section", "") or "") in {"late", "watch"}:
        return "판단 빗나감"
    if is_missed_review_late_move(row):
        return "움직였지만 늦음"
    if bool(row.get("seen_signal", False)) or bool(row.get("seen_shortlist", False)):
        return "봤는데 못 올림"
    return "아예 못 잡음"

def build_missed_review_reason_text(row: dict, miss_type: str) -> str:
    alert_section = str(row.get("alert_section", "") or "")
    block_reason = str(row.get("quality_block_reason", "") or "").strip()
    if miss_type == "데이터 실패로 못 봄":
        base = "데이터 조회 실패로 실시간 스캔에서는 건너뜀. 이후 실제 움직임이 커서 missed에만 기록"
    elif miss_type == "판단 빗나감":
        if alert_section == "late":
            base = "움직이긴 했는데 늦은 후보로 너무 아래에 내려버림"
        elif alert_section == "watch":
            base = "움직이긴 했는데 감시만 할 후보로만 둠"
        else:
            base = "움직일 자리였는데 보수적으로 분류함"
    elif miss_type == "움직였지만 늦음":
        base = "움직임은 컸지만 우리가 잡아야 할 초입보단 늦은 쪽이라 무조건 살릴 표본은 아님"
    elif miss_type == "봤는데 못 올림":
        if block_reason:
            base = f"상위 후보까진 봤는데 여기서 못 올림: {block_reason}"
        else:
            base = "상위 후보까진 봤는데 카드 알림으로 못 올림"
    elif bool(row.get("seen_hot_rank", False)):
        base = "급등/거래량 순위엔 올라왔는데 본선 후보 단계까지 못 잡음"
    else:
        base = "시장 흐름은 있었는데 본선 후보 단계까지 못 잡음"
    sample_conf = get_minute1_sample_confidence_text(int(safe_float(row.get("window_candles", 0), 0)))
    if sample_conf:
        base += f" / {sample_conf}"
    return base

def _short_missed_reason(row: dict) -> str:
    """자동 missed 알림은 길게 보내지 않는다. 자세한 내용은 /review_dump에서 본다."""
    miss_type = str(row.get("miss_type", "탐색 놓침") or "탐색 놓침")
    reason_text = str(row.get("reason_text", "") or "").strip()
    data_fail = bool(row.get("data_fetch_failed", False)) or miss_type == "데이터 실패로 못 봄"
    if data_fail:
        return "데이터 조회 실패로 못 봤고, 이후 움직임이 커서 기록함"
    if "늦" in miss_type or "늦" in reason_text:
        return "움직임은 컸지만 초입보다는 늦은 자리였음"
    if "봤는데" in miss_type:
        return "상위 후보까진 봤지만 알림 승격까지는 못 올라옴"
    if "아예" in miss_type:
        return "급등/거래대금 흐름은 있었지만 본선 후보에 못 들어옴"
    return "움직임이 커서 복기용으로 기록함"


def maybe_send_missed_review_alert(row: dict):
    global last_missed_review_alert_ts
    if not MISSED_REVIEW_AUTO_ALERT_ON:
        return
    # 데이터 조회/분석 실패는 사용자가 매번 볼 내용이 아니다.
    # 자세한 원인은 /review_dump에만 남기고 자동 알림은 보내지 않는다.
    if bool(row.get("data_fetch_failed", False)) or str(row.get("miss_type", "") or "") == "데이터 실패로 못 봄":
        return
    best_up_pct = safe_float(row.get("best_up_pct", 0), 0)
    if best_up_pct < MISSED_REVIEW_AUTO_ALERT_MIN_PCT:
        return
    now_ts = time.time()
    if now_ts - last_missed_review_alert_ts < MISSED_REVIEW_AUTO_ALERT_COOLDOWN_SEC:
        return
    ticker = row.get("ticker", "?")
    miss_type = row.get("miss_type", "탐색 놓침")
    end_up = safe_float(row.get("end_up_pct", 0), 0)
    lines = [
        f"📌 복기 필요: {ticker} / {miss_type}",
        f"- 결과: 30분 최고 {best_up_pct:+.2f}% / 끝 {end_up:+.2f}%",
        f"- 이유: {_short_missed_reason(row)}",
        "자세히: /review_dump",
    ]
    send("\n".join(lines))
    last_missed_review_alert_ts = now_ts

def process_missed_review_queue(now_ts: float = None):
    global missed_review_queue
    if not MISSED_REVIEW_ON:
        return
    now_ts = safe_float(now_ts, time.time())
    cleanup_missed_review_queue(now_ts)
    due = []
    for ticker, row in list(missed_review_queue.items()):
        if safe_float(row.get("review_ts", 0), 0) <= now_ts:
            due.append((ticker, row))
    changed = False
    for ticker, row in due:
        noise_reason = missed_review_noise_reason(row)
        if noise_reason:
            try:
                missed_review_meta.setdefault("noise_dropped", 0)
                missed_review_meta["noise_dropped"] = int(safe_float(missed_review_meta.get("noise_dropped", 0), 0)) + 1
                missed_review_meta["last_noise_drop"] = {"ticker": ticker, "reason": noise_reason, "ts": now_ts}
            except Exception:
                pass
            missed_review_queue.pop(ticker, None)
            changed = True
            continue
        base_price = safe_float(row.get("base_price", 0), 0)
        ok_spot, _spot_reason = initial_spot_good_enough_for_missed_review(row)
        stats = get_missed_review_window_stats(ticker, base_price, safe_float(row.get("saved_at", 0), 0), safe_float(row.get("review_ts", 0), 0))
        best_up_pct = safe_float(stats.get("best_up_pct", 0), 0)
        end_up_pct = safe_float(stats.get("end_up_pct", 0), 0)
        row["best_up_pct"] = safe_float(best_up_pct, 0)
        row["end_up_pct"] = safe_float(end_up_pct, 0)
        row["worst_down_pct"] = safe_float(stats.get("worst_down_pct", 0), 0)
        row["best_price"] = safe_float(stats.get("best_price", base_price), base_price)
        row["end_price"] = safe_float(stats.get("end_price", base_price), base_price)
        row["worst_price"] = safe_float(stats.get("worst_price", base_price), base_price)
        row["best_price_ts"] = safe_float(stats.get("best_price_ts", 0), 0)
        row["end_price_ts"] = safe_float(stats.get("end_price_ts", 0), 0)
        row["worst_price_ts"] = safe_float(stats.get("worst_price_ts", 0), 0)
        row["window_candles"] = int(safe_float(stats.get("window_candles", 0), 0))
        row["window_source_ok"] = bool(stats.get("window_source_ok", False))
        row["eval_start_ts"] = safe_float(stats.get("eval_start_ts", now_ts - 1800), now_ts - 1800)
        row["eval_end_ts"] = safe_float(stats.get("eval_end_ts", now_ts), now_ts)
        row["logged_at"] = now_ts
        result_quality = classify_missed_review_result_quality(best_up_pct, end_up_pct, safe_float(row.get("worst_down_pct", 0), 0))
        sample_trust = get_minute1_sample_trust(int(safe_float(stats.get("window_candles", 0), 0)))
        row["sample_trust"] = sample_trust
        if sample_trust == "very_low":
            if result_quality == "good":
                result_quality = "assist"
            elif result_quality == "assist":
                result_quality = "weak"
        elif sample_trust == "low":
            if result_quality == "good" and best_up_pct < 4.5:
                result_quality = "assist"
        row["result_quality"] = result_quality
        was_caught = bool(row.get("alert_sent", False)) and str(row.get("alert_section", "") or "") in {"early", "live", "restart"}
        data_fail_row = bool(row.get("data_fetch_failed", False))
        # 데이터 실패 표본은 당시 차트수치가 부족해도, 이후 실제로 움직였으면 missed에 남긴다.
        # 단, 이후 크게 빠진 후보는 missed가 아니라 잘 버린 후보라 기록하지 않는다.
        clearly_bad_after = best_up_pct < 1.20 and end_up_pct < 0.20 and safe_float(row.get("worst_down_pct", 0), 0) <= -1.20
        if (ok_spot or data_fail_row) and result_quality in {"good", "assist"} and not was_caught and not clearly_bad_after:
            miss_type = classify_missed_review_type(row)
            row["miss_type"] = miss_type
            row["miss_level"] = "핵심" if result_quality == "good" else "보조"
            row["missed_tracking_bucket"] = "진짜놓침" if result_quality == "good" else "애매"
            if sample_trust in {"very_low", "low"}:
                row["miss_level"] = "보조"
            row["reason_text"] = build_missed_review_reason_text(row, miss_type)
            if result_quality == "assist":
                row["reason_text"] = f"움직였지만 애매: {row['reason_text']}"
            if not has_recent_same_missed_review(row):
                save_missed_review_log(dict(row))
                if result_quality == "good":
                    maybe_send_missed_review_alert(row)
        missed_review_queue.pop(ticker, None)
        changed = True
    if changed:
        persist_missed_review_state()

def format_rank_line_for_missed_review(row: dict) -> str:
    parts = []
    for label, key in (("1분급등", "change_1_rank"), ("5분급등", "change_5_rank"), ("거래량", "vol_ratio_rank"), ("거래대금", "turnover_rank"), ("시장주목", "surge_rank")):
        bit = format_rank_item(label, row.get(key, 0))
        if bit:
            parts.append(bit)
    if not any(p.startswith("거래대금") for p in parts):
        bit = format_rank_item("거래대금", row.get("turnover_rank_pulse", 0))
        if bit:
            parts.append(bit)
    return " / ".join(parts) if parts else "내부 유사 순위 감시 기록"


def format_missed_review_high_gap_text(row: dict) -> str:
    for key in ("below_30m_high_pct", "high_gap_pct", "chart_gap_pct"):
        gap = safe_float(row.get(key, 999), 999)
        if 0 <= gap < 900:
            return f"{gap:.2f}%"
    return "기준 없음"

def format_missed_review_price_context(row: dict) -> str:
    high30 = safe_float(row.get("recent_30m_high_price", 0), 0)
    low30 = safe_float(row.get("recent_30m_low_price", 0), 0)
    base_price = safe_float(row.get("base_price", 0), 0)
    if high30 <= 0 and low30 <= 0:
        return ""
    parts = []
    if high30 > 0:
        parts.append(f"고점 {fmt_price_detail(high30)}")
    if low30 > 0:
        parts.append(f"저점 {fmt_price_detail(low30)}")
    if base_price > 0:
        parts.append(f"기준가 {fmt_price_detail(base_price)}")
    return " / ".join(parts)


def format_missed_review_result_prices(row: dict) -> str:
    base_price = safe_float(row.get("base_price", 0), 0)
    best_price = safe_float(row.get("best_price", 0), 0)
    end_price = safe_float(row.get("end_price", 0), 0)
    worst_price = safe_float(row.get("worst_price", 0), 0)
    parts = []
    if base_price > 0:
        parts.append(f"기준가 {fmt_price_detail(base_price)}")
    if best_price > 0:
        parts.append(f"최고가 {fmt_price_detail(best_price)}")
    if end_price > 0:
        parts.append(f"종가 {fmt_price_detail(end_price)}")
    if worst_price > 0:
        parts.append(f"최저가 {fmt_price_detail(worst_price)}")
    return " / ".join(parts)


def format_missed_review_result_timestamps(row: dict) -> str:
    best_ts = safe_float(row.get("best_price_ts", 0), 0)
    end_ts = safe_float(row.get("end_price_ts", 0), 0)
    worst_ts = safe_float(row.get("worst_price_ts", 0), 0)
    candles = int(safe_float(row.get("window_candles", 0), 0))
    parts = []
    if best_ts > 0:
        parts.append(f"최고 {format_ts_mdhm(best_ts)}")
    if end_ts > 0:
        parts.append(f"종가 {format_ts_mdhm(end_ts)}")
    if worst_ts > 0:
        parts.append(f"최저 {format_ts_mdhm(worst_ts)}")
    if candles > 0:
        parts.append(f"사용봉 {candles}개")
    sample_note = get_minute1_sample_note(candles)
    if sample_note:
        parts.append(sample_note)
    return " / ".join(parts)


def format_missed_review_eval_window(row: dict) -> str:
    start_ts = safe_float(row.get("eval_start_ts", 0), 0)
    end_ts = safe_float(row.get("eval_end_ts", 0), 0)
    candles = int(safe_float(row.get("window_candles", 0), 0))
    if start_ts <= 0 or end_ts <= 0:
        return ""
    tail = f" / minute1 {candles}봉" if candles > 0 else ""
    sample_note = get_minute1_sample_note(candles)
    if sample_note:
        tail += f" / {sample_note}"
    if bool(row.get("pending", False)):
        return f"평가 대기중: {format_ts_mdhm(start_ts)} ~ {format_ts_mdhm(end_ts)}{tail}"
    return f"평가구간 {format_ts_mdhm(start_ts)} ~ {format_ts_mdhm(end_ts)}{tail}"

def format_missed_review_log_block(row: dict, idx: int = 0) -> str:
    prefix = f"{idx}. " if idx else "- "
    ticker = row.get("ticker", "?")
    miss_type = row.get("miss_type", "놓침")
    display_type = get_missed_review_display_type(row)
    type_text = display_type if display_type == miss_type or not miss_type else f"{display_type} ({miss_type})"
    result_prices = format_missed_review_result_prices(row)
    eval_window = format_missed_review_eval_window(row)
    sample_conf_text = get_minute1_sample_confidence_text(int(safe_float(row.get("window_candles", 0), 0)))
    return "\n".join([
        f"{prefix}{ticker} / {type_text} / 분류 {get_missed_review_bucket(row)}",
        f"- 순위: {format_rank_line_for_missed_review(row)}",
        f"- 시작흐름: 1분 {safe_float(row.get('chg_1m', 0), 0):+.2f}% / 3분 {safe_float(row.get('chg_3m', 0), 0):+.2f}% / 5분 {safe_float(row.get('chg_5m', 0), 0):+.2f}% / 15분 {safe_float(row.get('chg_15m', 0), 0):+.2f}% / 30분 {safe_float(row.get('chg_30m', 0), 0):+.2f}% / 1시간 {safe_float(row.get('chg_60m', 0), 0):+.2f}% / 저점대비 {safe_float(row.get('from_30m_low_pct', 0), 0):+.2f}% / 최근30분 고점까지 {format_missed_review_high_gap_text(row)}",
        *([f"- 최근30분 기준값: {format_missed_review_price_context(row)}"] if format_missed_review_price_context(row) else []),
        f"- 결과: 30분 안 최고 {safe_float(row.get('best_up_pct', 0), 0):+.2f}% / 끝 {safe_float(row.get('end_up_pct', 0), 0):+.2f}% / 중간최저 {safe_float(row.get('worst_down_pct', 0), 0):+.2f}%",
        *([f"- 결과 원값: {result_prices}"] if result_prices else []),
        *([f"- 결과 시각: {format_missed_review_result_timestamps(row)}"] if format_missed_review_result_timestamps(row) else []),
        *([f"- {eval_window}"] if eval_window else []),
        *([f"- 신뢰도: {sample_conf_text}"] if sample_conf_text else []),
        *([f"- 차트수치: {format_chart_quant_summary_text(row, compact=True)}"] if row.get('chart_quant_label') else []),
        f"- 해석: {row.get('reason_text', '')}",
    ])


def format_missed_review_compact_block(row: dict, idx: int = 0) -> str:
    """review_dump 외부용 놓친 코인 요약. 자세한 차트수치는 /review_dump에서 본다."""
    prefix = f"{idx}. " if idx else ""
    ticker = str((row or {}).get("ticker", "?") or "?").upper()
    type_text = get_missed_review_display_type(row or {})
    reason = str((row or {}).get("reason_text", "") or "").strip()
    base_price = safe_float((row or {}).get("base_price", 0), 0)
    end_price = safe_float((row or {}).get("end_price", 0), 0)
    best_price = safe_float((row or {}).get("best_price", 0), 0)
    best_up = safe_float((row or {}).get("best_up_pct", 0), 0)
    end_up = safe_float((row or {}).get("end_up_pct", 0), 0)
    ranks = format_rank_line_for_missed_review(row or {})
    lines = [f"{prefix}{ticker} / {type_text} / 분류 {get_missed_review_bucket(row or {})}"]
    if reason:
        lines.append(f"- 이유: {reason[:110]}")
    if base_price > 0 or end_price > 0 or best_price > 0:
        lines.append(f"- 가격: 시작 {fmt_price(base_price)} → 끝 {fmt_price(end_price)} / 최고 {fmt_price(best_price)}")
    lines.append(f"- 결과: 최고 {best_up:+.2f}% / 끝 {end_up:+.2f}%")
    if ranks:
        lines.append(f"- 당시순위: {ranks}")
    return "\n".join(lines)

def format_alert_review_compact_block(row: dict, idx: int = 1) -> str:
    """review_dump 외부용 최근 알림 결과 요약."""
    summary = row.get("summary", {}) if isinstance(row, dict) else {}
    ticker = str((row or {}).get("ticker", "?") or "?").upper()
    source = str((row or {}).get("source_label", "") or "").strip()
    note = str((row or {}).get("note", "") or "").strip()
    return "\n".join([
        f"{idx}. {ticker}" + (f" / {source}" if source else ""),
        f"- 결과: 최고 {safe_float(summary.get('max_up_pct', 0), 0):+.2f}% / 끝 {safe_float(summary.get('end_up_pct', 0), 0):+.2f}% / 최저 {safe_float(summary.get('max_down_pct', 0), 0):+.2f}%",
        f"- 해석: {note or '비교 불가'}",
    ])

def append_missed_review_parts(parts: list, limit: int = 2):
    rows = get_all_missed_review_rows(include_supplemental=True, supplemental_limit=80)[-max(1, int(limit)):]
    if not rows:
        return
    rows = list(reversed(rows))
    lines = ["📌 최근 놓친 코인"]
    for idx, row in enumerate(rows, start=1):
        lines.append("")
        lines.append(format_missed_review_log_block(row, idx=idx))
    parts.append("\n".join(lines))

def summarize_missed_review_logs(rows):
    bucket = {"아예 못 잡음": 0, "봤는데 못 올림": 0, "움직였지만 늦음": 0, "판단 빗나감": 0, "데이터 실패로 못 봄": 0, "움직였지만 애매": 0, "진짜놓침": 0, "애매": 0, "가짜튐": 0, "잡음": 0}
    for row in rows:
        if not isinstance(row, dict):
            continue
        if is_watch_excluded_ticker(str(row.get("ticker", "") or "")):
            continue
        b = get_missed_review_bucket(row)
        bucket[b] = bucket.get(b, 0) + 1
        miss_type = str(row.get("miss_type", "") or "")
        trust = get_minute1_sample_trust(int(safe_float(row.get("window_candles", 0), 0)))
        if miss_type == "데이터 실패로 못 봄":
            bucket["데이터 실패로 못 봄"] = bucket.get("데이터 실패로 못 봄", 0) + 1
            continue
        if str(row.get("miss_level", "핵심") or "핵심") == "보조" or trust in {"very_low", "low"}:
            bucket["움직였지만 애매"] = bucket.get("움직였지만 애매", 0) + 1
            continue
        bucket[miss_type] = bucket.get(miss_type, 0) + 1
    bucket["탐색 놓침"] = bucket.get("아예 못 잡음", 0)
    bucket["승격 놓침"] = bucket.get("봤는데 못 올림", 0)
    bucket["늦어서 안 올림"] = bucket.get("움직였지만 늦음", 0)
    bucket["분류 놓침"] = bucket.get("판단 빗나감", 0)
    bucket["데이터 실패"] = bucket.get("데이터 실패로 못 봄", 0)
    return bucket

def get_missed_review_display_type(row: dict) -> str:
    miss_type = str((row or {}).get("miss_type", "") or "")
    base = {
        "아예 못 잡음": "탐색 놓침",
        "봤는데 못 올림": "승격 놓침",
        "움직였지만 늦음": "늦어서 안 올림",
        "판단 빗나감": "분류 놓침",
        "데이터 실패로 못 봄": "데이터 실패(내부기록)",
    }.get(miss_type, miss_type or "놓침")
    trust = get_minute1_sample_trust(int(safe_float((row or {}).get("window_candles", 0), 0)))
    if str((row or {}).get("miss_level", "핵심") or "핵심") == "보조" or trust in {"very_low", "low"}:
        return "움직였지만 애매"
    return base


def build_supplemental_missed_review_rows(limit: int = 12):
    rows = []
    now_ts = time.time()
    try:
        seen_tickers = {
            str(x.get("ticker", "") or "").upper().strip()
            for x in missed_review_logs if isinstance(x, dict)
        }
        src = [x for x in reverse_trace_logs if isinstance(x, dict)]
        src = src[-120:]
        for row in reversed(src):
            ticker = str(row.get("ticker", "") or "").upper().strip()
            if not ticker or ticker in seen_tickers:
                continue
            bucket = str(row.get("bucket", "") or "")
            stage = str(row.get("stage", "") or "")
            if bucket == "user_alert" or stage == "user_alert_sent":
                continue
            turnover_rank = int(safe_float(row.get("turnover_rank", 999), 999))
            leader_rank = int(safe_float(row.get("leader_rank", 999), 999))
            change5_rank = int(safe_float(row.get("change5_rank", 999), 999))
            vol_ratio = safe_float(row.get("vol_ratio", 0), 0)
            leader = safe_float(row.get("leader_score", 0), 0)
            from_low = safe_float(row.get("from_low", 0), 0)
            below_high = safe_float(row.get("below_high", 999), 999)
            chart_quality = max(
                safe_float(row.get("rebreakout_score", 0), 0),
                safe_float(row.get("breakout_hold_score", 0), 0),
                safe_float(row.get("compression_score", 0), 0),
            )
            qualifies = (
                turnover_rank <= 35
                or leader_rank <= 35
                or change5_rank <= 25
                or vol_ratio >= 1.5
                or leader >= 1.8
                or (from_low >= 0.6 and below_high >= 0.6)
                or chart_quality >= 1.8
            )
            if not qualifies:
                continue
            reason_bits = []
            if turnover_rank <= 35:
                reason_bits.append(f"거래대금 {turnover_rank}위")
            if leader_rank <= 35:
                reason_bits.append(f"시장주목 {leader_rank}위")
            if change5_rank <= 25:
                reason_bits.append(f"5분 {change5_rank}위")
            if chart_quality >= 1.8:
                reason_bits.append("차트수치 괜찮음")
            extra = str(row.get("reason", "") or "").strip()
            reason_text = " / ".join(reason_bits[:3]) if reason_bits else extra
            if extra and extra not in reason_text:
                reason_text = f"{reason_text} / {extra}" if reason_text else extra
            row_ts = safe_float(row.get("ts", 0), 0) or now_ts
            review_end_ts = row_ts + MISSED_REVIEW_DELAY_SEC
            if now_ts < review_end_ts:
                continue
            base_price = safe_float(row.get("price", 0), 0)
            stats = get_missed_review_window_stats(ticker, base_price, row_ts, review_end_ts)
            if bool(stats.get("pending", False)):
                continue
            best_up_pct = safe_float(stats.get("best_up_pct", 0), 0)
            end_up_pct = safe_float(stats.get("end_up_pct", 0), 0)
            worst_down_pct = safe_float(stats.get("worst_down_pct", 0), 0)
            best_price = safe_float(stats.get("best_price", base_price), base_price)
            end_price = safe_float(stats.get("end_price", base_price), base_price)
            worst_price = safe_float(stats.get("worst_price", base_price), base_price)
            eval_start_ts = safe_float(stats.get("eval_start_ts", row_ts), row_ts)
            eval_end_ts = safe_float(stats.get("eval_end_ts", review_end_ts), review_end_ts)
            # 참고용 표본이라도 실제로 위로 움직였던 코인만 missed에 남긴다.
            # ENJ처럼 이후 크게 빠진 후보는 missed가 아니라 우리가 잘 버린 위험 회피 표본이다.
            near_high_late = below_high <= 0.20
            moved_enough = (
                (best_up_pct >= 1.20 and end_up_pct >= 0.30)
                or end_up_pct >= 0.80
                or (best_up_pct >= 2.20 and end_up_pct >= 0.00 and worst_down_pct > -3.20)
            )
            late_high_reject = near_high_late and end_up_pct <= 0.10
            if not moved_enough:
                continue
            supplemental_miss_type = "판단 빗나감"
            supplemental_level = "보조"
            if late_high_reject:
                supplemental_miss_type = "움직였지만 늦음"
                supplemental_level = "핵심"
            supp = {
                "ticker": ticker,
                "logged_at": safe_float(row.get("ts", time.time()), time.time()),
                "saved_at": safe_float(row.get("ts", time.time()), time.time()),
                "miss_type": supplemental_miss_type,
                "miss_level": supplemental_level,
                "reason_text": reason_text or "움직임은 있었지만 무조건 살릴 급은 아니라 참고용으로 남김",
                "change_1_rank": 0,
                "change_3_rank": 0,
                "change_5_rank": change5_rank if change5_rank < 999 else 0,
                "vol_ratio_rank": 0,
                "turnover_rank_pulse": 0,
                "leader_rank": leader_rank if leader_rank < 999 else 0,
                "turnover_rank": turnover_rank if turnover_rank < 999 else 0,
                "surge_rank": 0,
                "chg_5m": safe_float(row.get("change_5", 0), 0),
                "chg_30m": safe_float(row.get("change_30", 0), 0),
                "from_30m_low_pct": from_low,
                "below_30m_high_pct": below_high,
                "recent_30m_high_price": safe_float(row.get("recent_30m_high_price", 0), 0),
                "recent_30m_low_price": safe_float(row.get("recent_30m_low_price", 0), 0),
                "base_price": base_price,
                "vol_ratio": vol_ratio,
                "leader_score": leader,
                "turnover": safe_float(row.get("turnover_5m", 0), 0),
                "chart_quant_label": str(row.get("chart_quant_label", "") or ""),
                "body_ratio_1": safe_float(row.get("body_ratio_1", 0), 0),
                "body_ratio_3": safe_float(row.get("body_ratio_3", 0), 0),
                "upper_wick_pct_1": safe_float(row.get("upper_wick_pct_1", 0), 0),
                "upper_wick_pct_3": safe_float(row.get("upper_wick_pct_3", 0), 0),
                "lower_wick_pct_1": safe_float(row.get("lower_wick_pct_1", 0), 0),
                "lower_wick_pct_3": safe_float(row.get("lower_wick_pct_3", 0), 0),
                "close_pos_1": safe_float(row.get("close_pos_1", 0), 0),
                "close_pos_3": safe_float(row.get("close_pos_3", 0), 0),
                "pullback_pct_18": safe_float(row.get("pullback_pct_18", 0), 0),
                "recovery_from_low_pct": safe_float(row.get("recovery_from_low_pct", 0), 0),
                "recovery_speed_pct": safe_float(row.get("recovery_speed_pct", 0), 0),
                "compression_score": safe_float(row.get("compression_score", 0), 0),
                "rebreakout_score": safe_float(row.get("rebreakout_score", 0), 0),
                "rebreakout_success_rate": safe_float(row.get("rebreakout_success_rate", 0), 0),
                "rebreakout_success_attempts": int(safe_float(row.get("rebreakout_success_attempts", 0), 0)),
                "hold_near_high_bars": int(safe_float(row.get("hold_near_high_bars", 0), 0)),
                "breakout_hold_score": safe_float(row.get("breakout_hold_score", 0), 0),
                "best_up_pct": best_up_pct,
                "end_up_pct": end_up_pct,
                "worst_down_pct": worst_down_pct,
                "best_price": best_price,
                "end_price": end_price,
                "worst_price": worst_price,
                "eval_start_ts": eval_start_ts,
                "eval_end_ts": eval_end_ts,
                "pending": False,
                "best_price": safe_float(stats.get("best_price", base_price), base_price),
                "end_price": safe_float(stats.get("end_price", base_price), base_price),
            }
            rows.append(supp)
            seen_tickers.add(ticker)
            if len(rows) >= max(1, int(limit)):
                break
    except Exception:
        return []
    rows.sort(key=lambda x: safe_float(x.get("logged_at", 0), 0))
    return rows


def get_all_missed_review_rows(include_supplemental: bool = False, supplemental_limit: int = 12):
    base_rows = [x for x in missed_review_logs if isinstance(x, dict)]
    if not include_supplemental:
        return base_rows
    extra_rows = build_supplemental_missed_review_rows(limit=supplemental_limit)
    rows = list(base_rows) + list(extra_rows)
    rows.sort(key=lambda x: safe_float(x.get("logged_at", x.get("saved_at", 0)), 0))
    return rows

def send_report_blocks(header_lines, blocks, title_prefix: str = ""):
    header_text = "\n".join([str(x) for x in (header_lines or []) if str(x).strip()]).strip()
    if header_text:
        send_text_chunks(header_text)
    total = len(blocks or [])
    for idx, block in enumerate(blocks or [], start=1):
        block_text = str(block or "").strip()
        if not block_text:
            continue
        prefix = ""
        if title_prefix and total > 1:
            prefix = f"{title_prefix} {idx}/{total}"
        send_text_chunks(block_text, prefix=prefix)


