def get_recent_buy_fill_logs(limit: int = 10):
    rows = [x for x in trade_logs if isinstance(x, dict) and x.get("type") == "BUY"]
    rows.sort(key=lambda x: safe_float(x.get("time", 0), 0), reverse=True)
    return rows[:max(1, int(limit))]

def split_text_chunks(text: str, limit: int = 3500):
    text = str(text or "")
    if len(text) <= limit:
        return [text]
    chunks = []
    current_lines = []
    current_len = 0

    def flush_current():
        nonlocal current_lines, current_len
        if current_lines:
            chunks.append("\n".join(current_lines))
            current_lines = []
            current_len = 0

    def append_line(line: str):
        nonlocal current_lines, current_len
        line = str(line or "")
        if len(line) <= limit:
            extra = len(line) + (1 if current_lines else 0)
            if current_lines and current_len + extra > limit:
                flush_current()
            current_lines.append(line)
            current_len += len(line) + (1 if len(current_lines) > 1 else 0)
            return

        if current_lines:
            flush_current()
        start = 0
        while start < len(line):
            part = line[start:start + limit]
            chunks.append(part)
            start += limit

    for line in text.splitlines():
        append_line(line)
    flush_current()
    return chunks or [text[:limit]]

def collect_internal_failure_summary_for_review_dump(limit: int = 10) -> str:
    """일반 알림에서 숨긴 데이터/분석 실패를 review_dump에서만 요약+최근 원본으로 확인한다."""
    rows = []
    try:
        if os.path.exists(RUNTIME_ERROR_LOG_FILE):
            with open(RUNTIME_ERROR_LOG_FILE, 'r', encoding='utf-8') as f:
                tail = f.readlines()[-120:]
            keywords = ["데이터", "조회", "분석", "생성 오류", "scan_debug", "missed", "review_dump", "ohlcv", "timeout", "error"]
            for line in tail:
                line = str(line or '').strip()
                if not line:
                    continue
                low = line.lower()
                if any(k.lower() in low for k in keywords):
                    rows.append({'tag': 'runtime_error', 'ts': '', 'message': line[:220], 'raw': line[:220]})
        if os.path.exists(RUNTIME_EVENT_LOG_FILE):
            with open(RUNTIME_EVENT_LOG_FILE, 'r', encoding='utf-8') as f:
                tail = f.readlines()[-220:]
            keywords = ["fail", "error", "timeout", "skip", "stuck", "partial", "데이터", "조회", "생성"]
            for line in tail:
                raw = str(line or '').strip()
                if not raw:
                    continue
                low = raw.lower()
                if not any(k.lower() in low for k in keywords):
                    continue
                try:
                    obj = json.loads(raw)
                    tag = str(obj.get('tag', '') or 'event')
                    msg = str(obj.get('message', '') or '')
                    ts = str(obj.get('ts', '') or '')
                    rows.append({'tag': tag, 'ts': ts, 'message': msg[:180], 'raw': f"{ts} / {tag}: {msg}"[:240]})
                except Exception:
                    rows.append({'tag': 'raw_event', 'ts': '', 'message': raw[:180], 'raw': raw[:240]})
    except Exception as e:
        return f"🧯 [내부 실패/데이터 오류 요약]\n- 요약 생성 오류: {e}"
    if not rows:
        return "🧯 [내부 실패/데이터 오류 요약]\n- 최근 표시할 데이터 조회/분석 실패 없음"

    counts = {}
    for row in rows:
        tag = str(row.get('tag') or 'unknown')
        counts[tag] = counts.get(tag, 0) + 1
    top_counts = sorted(counts.items(), key=lambda kv: kv[1], reverse=True)[:8]

    recent = []
    seen = set()
    for row in reversed(rows):
        raw = str(row.get('raw') or '').strip()
        key = raw[-170:]
        if key in seen:
            continue
        seen.add(key)
        recent.append(raw)
        if len(recent) >= max(1, int(limit)):
            break

    lines = [
        "🧯 [내부 실패/데이터 오류 요약]",
        "- 일반 알림에서는 숨김. review_dump에서만 원인 확인용으로 표시",
        "- 같은 오류 수십 줄 반복은 묶어서 보여주고, 아래에 최근 원본만 일부 표시",
        "- 요약: " + " / ".join([f"{tag} {cnt}회" for tag, cnt in top_counts]),
        "",
        f"[최근 원본 {len(recent)}건]",
    ]
    for idx, row in enumerate(recent, start=1):
        lines.append(f"{idx}. {row}")
    return "\n".join(lines)

def build_review_dump_quick_summary(scan_display_at_start=None) -> str:
    """review_dump 맨 위에 사용자가 바로 볼 요약만 따로 모은다."""
    lines = ["📌 빠른 요약"]
    try:
        display = scan_display_at_start if isinstance(scan_display_at_start, dict) else get_latest_scan_display_state(now_ts=time.time(), limit=12)
        user_count = len(display.get('user_items') or [])
        watch_count = len(display.get('internal_items') or [])
        discard_count = len(display.get('discard_items') or [])
        note = format_scan_display_state_line(display)
        lines.append(f"- 후보 상태: 바로 볼 후보 {user_count}개 / 조금 더 볼 후보 {watch_count}개 / 내부에서 넘긴 후보 {discard_count}개")
        if note:
            lines.append(f"- 스캔 상태: {note}")
    except Exception as e:
        lines.append(f"- 후보 상태 요약 실패: {e}")
    try:
        rows = collect_recent_alert_review_rows(limit=20, summary_limit=20)
        summary = summarize_alert_review_rows(rows[:20]) if rows else {}
        lines.append(f"- 최근 알림: 좋은표본 {summary.get('good', 0)} / 보조표본 {summary.get('assist', 0)} / 가짜상승 {summary.get('spike', 0)} / 약함 {summary.get('weak', 0)} / 실패 {summary.get('bad', 0)}")
    except Exception as e:
        lines.append(f"- 최근 알림 요약 실패: {e}")
    try:
        active_watch, watch_logs = _get_internal_watch_state_parts()
        strong_logs = [x for x in watch_logs[-30:] if isinstance(x, dict) and any(isinstance((x.get('results') or {}).get(k), dict) and (x.get('results') or {}).get(k, {}).get('result_type') in {'승격 놓침 가능성', '감시 판단 좋음'} for k in ['10m', '30m'])]
        lines.append(f"- 내부감시 추적: 진행 {len(active_watch)} / 완료 {len(watch_logs)} / 유효표본 {len(strong_logs)}")
    except Exception as e:
        lines.append(f"- 내부감시 추적 요약 실패: {e}")
    try:
        missed_rows = get_all_missed_review_rows(include_supplemental=True, supplemental_limit=80)
        missed_summary = summarize_missed_review_logs(missed_rows[-20:]) if missed_rows else {}
        lines.append(f"- 놓친 움직임: 탐색 {missed_summary.get('탐색 놓침', 0)} / 승격 {missed_summary.get('승격 놓침', 0)} / 늦어서 차단 {missed_summary.get('늦어서 안 올림', 0)} / 데이터 실패 {missed_summary.get('데이터 실패', 0)}")
    except Exception as e:
        lines.append(f"- 놓친 움직임 요약 실패: {e}")
    try:
        if int(safe_float(last_market_refresh_stuck_suppressed, 0)) > 0:
            lines.append(f"- 내부복구: market_refresh 지연 자동복구 {int(safe_float(last_market_refresh_stuck_suppressed, 0))}회는 로그 줄임")
    except Exception:
        pass
    lines.append("- 내부 오류/데이터 실패 세부내용은 아래 🧯 [내부 실패/데이터 오류]에만 표시")
    return "\n".join(lines)


def _rd_pct_ratio(value) -> str:
    return f"{safe_float(value, 0) * 100.0:.1f}%"

def _rd_pct(value) -> str:
    return f"{safe_float(value, 0):.2f}%"

def _rd_score_or_pending(item: dict, key: str, default=0.0) -> str:
    value = safe_float((item or {}).get(key, default), default)
    if abs(value) <= 0.0001:
        return "정밀분석 전"
    if value >= 900:
        return "정밀분석 전"
    return f"{value:.2f}"

def _rd_gap_or_pending(value) -> str:
    value = safe_float(value, 999)
    if value >= 900:
        return "확인 안 됨"
    if abs(value) <= 0.000001:
        return "고점 바로 근처"
    return f"{value:.2f}%"


def _review_dump_meaningful_chart_field_count(item: dict) -> int:
    """review_dump 표시용: 저장된 후보에 정밀 차트 수치가 얼마나 붙었는지 대략 센다."""
    item = item if isinstance(item, dict) else {}
    keys = [
        'candle_body_ratio_1', 'candle_body_ratio_3', 'candle_body_ratio_5',
        'body_ratio_1', 'body_ratio_3', 'body_ratio_5',
        'close_position_ratio_1', 'close_position_ratio_3', 'close_position_ratio_5',
        'close_pos_1', 'close_pos_3', 'close_pos_5',
        'upper_wick_pct_1', 'upper_wick_pct_3', 'upper_wick_pct_5',
        'lower_wick_pct_1', 'lower_wick_pct_3', 'lower_wick_pct_5',
        'pullback_pct_18', 'recovery_from_low_pct', 'recovery_quality_score', 'low_zone_defense_score',
        'low_defense_v2_score', 'low_retest_count_v2', 'low_rising_score_v2', 'low_structure_summary_v2',
        'turnover_persistence_score', 'turnover_sustain_ratio_3v10', 'turnover_sustain_ratio_5v20',
        'turnover_keep_bars_5', 'turnover_keep_bars_10', 'turnover_flash_score',
        'rebreakout_score', 'rebreakout_attempts', 'hold_near_high_bars', 'breakout_hold_score',
        'prebreakout_ready_score', 'prebreakout_hold_near_high_bars', 'prebreakout_volume_reaccel_score',
        'htf_gap_pct', 'daily_gap_pct', 'htf_setup_label', 'daily_setup_label',
    ]
    cnt = 0
    for key in keys:
        v = item.get(key)
        if v is None or v == '':
            continue
        if isinstance(v, (int, float)):
            fv = safe_float(v, 0)
            if key.endswith('_gap_pct') and fv >= 900:
                continue
            if abs(fv) <= 0.0001:
                continue
        cnt += 1
    return cnt


def _review_dump_analysis_stage_text(item: dict) -> str:
    item = item if isinstance(item, dict) else {}
    detail_cnt = _review_dump_meaningful_chart_field_count(item)
    if detail_cnt >= 8:
        return f"정밀분석 완료 / 저장 차트수치 {detail_cnt}개"
    if detail_cnt >= 3:
        return f"부분 정밀분석 / 저장 차트수치 {detail_cnt}개"
    reason = []
    if bool(item.get('is_lite_cache', False)) or str(item.get('data_source', '')).lower().find('lite') >= 0:
        reason.append('3분봉 가벼운 1차 후보')
    if safe_float(item.get('sample_candles_1m', item.get('minute1_candles', 0)), 0) <= 0:
        reason.append('1분봉 정밀 표본 없음')
    if safe_float(item.get('htf_gap_pct', 999), 999) >= 900 or safe_float(item.get('daily_gap_pct', 999), 999) >= 900:
        reason.append('상위봉 미확인')
    if not reason:
        reason.append('time budget 또는 우선순위 때문에 정밀분석 전')
    return '1차 감시만 완료 / 정밀분석 전: ' + ' / '.join(reason[:3])


def _review_dump_target_fit_text(item: dict) -> str:
    """후보별로 우리 목표와 맞는지 바로 읽히게 만든다."""
    item = item if isinstance(item, dict) else {}
    one_liner = str(item.get('one_liner', item.get('judgement_text', '')) or '')
    primary = str(item.get('primary_reason', '') or '')
    label = str(item.get('label_text', item.get('user_label_text', '')) or '')
    bucket = str(item.get('alert_bucket', item.get('bucket', '')) or '')
    grade = str(item.get('alert_grade', item.get('grade', '')) or '')
    chg5 = safe_float(item.get('change_5', 0), 0)
    chg30 = safe_float(item.get('change_30', 0), 0)
    chg60 = safe_float(item.get('change_60', 0), 0)
    from_low = safe_float(item.get('from_low', item.get('from_30m_low_pct', 0)), 0)
    high_gap = safe_float(item.get('below_high', item.get('below_30m_high_pct', item.get('high_gap_pct', 999))), 999)
    turnover = safe_float(item.get('turnover_5m', item.get('turnover_recent_5m', item.get('turnover', 0))), 0)
    vol = safe_float(item.get('vol_ratio', 0), 0)
    low_def = safe_float(item.get('low_zone_defense_score', item.get('recovery_quality_score', 0)), 0)
    low_v2 = safe_float(item.get('low_defense_v2_score', 0), 0)
    low_v2_label = str(item.get('low_defense_v2_label', '') or '')
    low_v2_summary = str(item.get('low_structure_summary_v2', '') or '')
    recovery = safe_float(item.get('recovery_quality_score', 0), 0)
    persist = safe_float(item.get('turnover_persistence_score', 0), 0)
    re_score = safe_float(item.get('rebreakout_score', item.get('rebreakout_prep_score', 0)), 0)
    prep = safe_float(item.get('prebreakout_ready_score', 0), 0)
    rsi = safe_float(item.get('rsi', 0), 0)
    flags = []
    if bool(item.get('flash_low_liquidity_near_high_block', False)):
        flags.append('고점 앞 반짝형')
    if bool(item.get('low_actual_turnover_flag', False)):
        flags.append('실제 돈 작음')
    if bool(item.get('late_high_volatility_block', False)):
        flags.append('이미 늦은 고점권 흔들림')
    if bool(item.get('near_high_rebreakout_watch', False)):
        flags.append('재돌파 대기')
    lifecycle_ctx = item.get('alert_chart_context', {}) if isinstance(item.get('alert_chart_context'), dict) else {}
    lifecycle_code = str(item.get('chart_lifecycle_code', lifecycle_ctx.get('chart_lifecycle_code', '')) or '').strip()
    lifecycle_early = safe_float(item.get('chart_lifecycle_early_score', lifecycle_ctx.get('chart_lifecycle_early_score', 0)), 0)
    lifecycle_restart = safe_float(item.get('chart_lifecycle_restart_score', lifecycle_ctx.get('chart_lifecycle_restart_score', 0)), 0)
    lifecycle_late = safe_float(item.get('chart_lifecycle_late_score', lifecycle_ctx.get('chart_lifecycle_late_score', 0)), 0)

    good = []
    caution = []
    if chg5 >= 1.2 and max(chg30, chg60) >= 2.0:
        good.append('실시간 강세 초입/중간가속 후보')
    elif 0.25 <= chg5 < 1.2 and 0 <= from_low <= 2.2:
        good.append('초반 감시 후보')
    if low_v2 >= 1.1:
        good.append(low_v2_summary or low_v2_label or '저점방어 무난')
    elif low_def >= 1.0 or recovery >= 1.3:
        good.append('저점 방어/회복질 있음')
    if persist >= 1.0 or turnover >= 10_000_000:
        good.append('돈 유지 또는 실제 거래대금 확인')
    if re_score >= 1.4 or prep >= 1.2:
        good.append('재돌파/고점 전 준비도 있음')
    if lifecycle_code == 'EARLY_GOOD' or lifecycle_early >= 2.55:
        good.append('차트 위치상 초입 구조')
    if lifecycle_code == 'RESTART_GOOD' or lifecycle_restart >= 2.65:
        good.append('차트 위치상 재출발 구조')

    if lifecycle_code == 'LATE_CHASE' or lifecycle_late >= CHART_LIFE_LATE_SCORE_BLOCK:
        caution.append('차트 위치상 늦은 추격권')
    if 0 <= high_gap <= 0.35:
        caution.append('고점이 너무 가까움')
    elif 0.35 < high_gap <= 0.85:
        caution.append('고점까지 여유가 좁음')
    if from_low >= 6.0:
        caution.append('저점대비 이미 꽤 진행됨')
    if bool(item.get('low_dead_stay_flag_v2', False)):
        caution.append('저점 근처 죽은 흐름')
    if bool(item.get('low_break_weak_reclaim_flag_v2', False)):
        caution.append('저점 이탈 후 회복 약함')
    if turnover < 5_000_000 and vol >= 2.0:
        caution.append('거래량 배수 대비 실제 돈 작음')
    if rsi >= 82:
        caution.append('RSI 과열')
    if chg5 <= 0 and '폭발' not in primary:
        caution.append('5분 힘 약함')
    if flags:
        caution.extend(flags[:2])

    if bucket in {'user_alert'}:
        base = '사용자 알림 후보. 우리 목표에 어느 정도 맞지만, 실제 진입은 고점거리/돈유지/30분 진행폭을 같이 봐야 함.'
    elif bucket in {'internal_watch', 'pre_entry'} or '초입' in primary or '감시' in label or '미리' in label:
        base = '내부 감시/미리 볼 후보. 바로 매수보다 다음 봉에서 돈이 계속 붙는지 확인할 자리.'
    elif 'discard' in bucket or bucket in {'late', 'skip'} or '버릴' in one_liner:
        base = '버린 후보 쪽. 우리 목표인 초입 선점보다는 약하거나 늦은 자리일 가능성이 큼.'
    else:
        base = '검증 후보. 초입/재출발/실시간 강세 중 어디에 가까운지 아래 수치로 확인 필요.'

    if '반짝' in ' '.join(flags + [label, primary, one_liner]):
        base = '초입 선점보다는 반짝/고점 앞 확인 후보. 사용자 알림 보류가 맞는지 보는 표본.'
    elif '실시간 폭발' in primary or (chg5 >= 1.8 and max(chg30, chg60) >= 4.0):
        base = '실시간 강세 초입 또는 중간가속 후보. 다만 저점대비가 과하면 추격인지 같이 봐야 함.'
    elif '재돌파' in ' '.join(flags + [primary, label]) or re_score >= 2.5:
        base = '재돌파 대기 후보. 고점 가까움 자체보다 돌파 후 유지/돈유지가 핵심.'

    tail = []
    if good:
        tail.append('맞는 포인트: ' + ' / '.join(good[:3]))
    if caution:
        tail.append('주의 포인트: ' + ' / '.join(caution[:3]))
    if grade:
        tail.append(f'등급 {grade}')
    return base + (' ' + ' | '.join(tail) if tail else '')


def _review_dump_detail_score(item: dict) -> int:
    item = item if isinstance(item, dict) else {}
    score = _review_dump_meaningful_chart_field_count(item) * 10
    if safe_float(item.get('turnover_5m', item.get('turnover_recent_5m', 0)), 0) > 0:
        score += 3
    if str(item.get('one_liner', item.get('judgement_text', '')) or '').strip():
        score += 3
    if isinstance(item.get('reasons'), list) and item.get('reasons'):
        score += 2
    if safe_float(item.get('htf_gap_pct', 999), 999) < 900:
        score += 4
    if safe_float(item.get('daily_gap_pct', 999), 999) < 900:
        score += 4
    return score


def _review_dump_merge_latest_with_rich(latest: dict, rich: dict) -> dict:
    latest = dict(latest) if isinstance(latest, dict) else {}
    rich = dict(rich) if isinstance(rich, dict) else {}
    if not rich:
        return latest
    merged = dict(rich)
    prefer_latest_keys = [
        'ticker', 'price', 'current_price', 'change_1', 'change_3', 'change_5', 'change_15', 'change_30', 'change_60',
        'vol_ratio', 'leader_score', 'turnover_5m', 'turnover', 'turnover_recent_1m', 'turnover_recent_3m',
        'from_low', 'from_30m_low_pct', 'below_high', 'below_30m_high_pct', 'primary_reason', 'reasons',
        'alert_bucket', 'alert_grade', 'label_text', 'user_label_text', 'one_liner', 'lite_score',
    ]
    for key in prefer_latest_keys:
        if key in latest:
            v = latest.get(key)
            if v not in (None, '', [], {}):
                if isinstance(v, (int, float)) and key not in {'change_1', 'change_3', 'change_5', 'change_15', 'change_30', 'change_60'}:
                    if abs(safe_float(v, 0)) <= 0.0001 and key not in {'price', 'current_price', 'from_low', 'from_30m_low_pct'}:
                        continue
                merged[key] = v
    merged['_detail_augmented_from'] = rich.get('_detail_source', rich.get('_detail_augmented_from', '최근 정밀 기록'))
    return merged


def build_review_dump_rich_detail_index(scan_display_at_start=None, trace_limit: int = 120) -> dict:
    """review_dump 섹션 간 같은 티커의 정밀 수치를 공유하기 위한 최신 상세 인덱스."""
    candidates = []
    try:
        display = scan_display_at_start if isinstance(scan_display_at_start, dict) else get_latest_scan_display_state(now_ts=time.time(), limit=12)
        for item in list(display.get('results') or []):
            if isinstance(item, dict):
                row = dict(item)
                row['_detail_source'] = '현재 후보 스냅샷'
                candidates.append(row)
    except Exception:
        pass
    try:
        load_reverse_trace_logs()
        for row in [x for x in reverse_trace_logs if isinstance(x, dict)][-max(1, int(trace_limit)):]:
            r = dict(row)
            r['_detail_source'] = '최근 역추적'
            candidates.append(r)
    except Exception:
        pass
    try:
        active, logs = _get_internal_watch_state_parts()
        for row in list(active.values()) + list(logs[-40:]):
            if not isinstance(row, dict):
                continue
            for snap_key, source in [('last_snapshot', '내부감시 최신'), ('first_snapshot', '내부감시 최초')]:
                snap = row.get(snap_key) if isinstance(row.get(snap_key), dict) else {}
                if snap:
                    r = dict(snap)
                    r.setdefault('ticker', row.get('ticker'))
                    r['_detail_source'] = source
                    candidates.append(r)
    except Exception:
        pass
    index = {}
    for item in candidates:
        ticker = str(item.get('ticker', '') or '').upper().strip()
        if not ticker:
            continue
        if ticker not in index or _review_dump_detail_score(item) >= _review_dump_detail_score(index[ticker]):
            index[ticker] = item
    return index



def _review_dump_collect_current_ticker_status(scan_display_at_start=None) -> dict:
    """현재 저장 스냅샷에서 티커별 현재 분류를 모은다. 새 스캔은 돌리지 않는다."""
    status = {}
    try:
        display = scan_display_at_start if isinstance(scan_display_at_start, dict) else get_latest_scan_display_state(now_ts=time.time(), limit=50)
        groups = [
            ('사용자알림후보', display.get('user_items') or []),
            ('내부감시/미리보기', display.get('internal_items') or []),
            ('내부넘김/버림', display.get('discard_items') or []),
            ('shortlist', display.get('results') or []),
        ]
        for label, rows in groups:
            for row in rows:
                if not isinstance(row, dict):
                    continue
                ticker = str(row.get('ticker', '') or '').upper().strip()
                if ticker:
                    status.setdefault(ticker, set()).add(label)
    except Exception:
        pass
    return status


def build_review_dump_bithumb_strength_crosscheck_section(scan_display_at_start=None, detail_index: dict = None, alert_rows=None, missed_rows=None, limit: int = 30) -> str:
    """빗썸 앱 순위/푸시 사진과 대조하기 위한 review_dump 전용 섹션.

    앱 화면을 직접 읽는 기능은 아니고, 봇 내부 캐시 + 현재가 스냅샷 유사순위 기준으로
    현재후보/내부감시/최근알림/놓친기록/정밀기록 중 어디에 잡혔는지 보여준다.
    """
    detail_index = detail_index if isinstance(detail_index, dict) else {}
    alert_rows = alert_rows if isinstance(alert_rows, list) else []
    missed_rows = missed_rows if isinstance(missed_rows, list) else []
    current_status = _review_dump_collect_current_ticker_status(scan_display_at_start)
    alert_tickers = {str(row.get('ticker', '') or '').upper().strip() for row in alert_rows if isinstance(row, dict)}
    missed_tickers = {str(row.get('ticker', '') or '').upper().strip() for row in missed_rows if isinstance(row, dict)}
    watch_tickers = set()
    try:
        active, logs = _get_internal_watch_state_parts()
        for row in list(active.values()) + list(logs):
            if isinstance(row, dict):
                ticker = str(row.get('ticker', '') or '').upper().strip()
                if ticker:
                    watch_tickers.add(ticker)
    except Exception:
        pass

    rows = []
    base_cache = dict(shared_market_cache) if isinstance(shared_market_cache, dict) else {}
    cache_count_before = len(base_cache)
    cache = inject_realtime_snapshot_rows_into_cache(base_cache, limit=REALTIME_RANK_INJECT_LIMIT)
    cache_count = len(cache)
    universe_count = len(market_universe) if isinstance(market_universe, list) else 0
    target_count = max(UNIVERSE_COLD_START_TARGET, CACHE_COLD_START_TARGET, 20)
    coverage_ratio = (cache_count / float(target_count)) if target_count > 0 else 0.0
    coverage_label = '낮음' if cache_count < 12 else ('보통' if cache_count < target_count else '양호')

    for ticker, data in cache.items():
        if not isinstance(data, dict):
            continue
        ticker = str(ticker or data.get('ticker', '') or '').upper().strip()
        if not ticker:
            continue
        chg1 = safe_float(data.get('change_1', 0), 0)
        chg3 = safe_float(data.get('change_3', 0), 0)
        chg5 = safe_float(data.get('change_5', 0), 0)
        chg15 = safe_float(data.get('change_15', 0), 0)
        chg30 = safe_float(data.get('change_30', 0), 0)
        chg60 = safe_float(data.get('change_60', 0), 0)
        turnover = safe_float(data.get('turnover_5m', data.get('turnover_recent_5m', data.get('turnover', 0))), 0)
        vol = safe_float(data.get('vol_ratio', 0), 0)
        leader = safe_float(data.get('leader_score', 0), 0)
        snap_rank_score = safe_float(data.get('snapshot_rank_score', 0), 0)
        strength = max(chg60, chg30, chg15, chg5, chg3)
        if strength < 1.20 and turnover < 10_000_000 and vol < 3.0 and snap_rank_score < 1.0:
            continue
        rows.append({
            'ticker': ticker,
            'chg1': chg1,
            'chg3': chg3,
            'chg5': chg5,
            'chg15': chg15,
            'chg30': chg30,
            'chg60': chg60,
            'turnover': turnover,
            'vol': vol,
            'leader': leader,
            'strength': strength,
            'snapshot_rank_score': snap_rank_score,
            'snapshot_rank': int(safe_float(data.get('snapshot_rank', 999), 999)),
            'injected': bool(data.get('realtime_rank_injected')),
        })
    rows.sort(key=lambda r: (r['strength'], r['snapshot_rank_score'], r['chg30'], r['chg3'], r['turnover']), reverse=True)
    rows = rows[:max(1, int(limit))]

    lines = [
        "📊 [봇 내부 강세 캐시 대조용]",
        "- 목적: 빗썸 푸시/실시간 순위 사진과 봇 기록을 대조하기 위한 섹션",
        "- 중요: 빗썸 앱 실시간 순위를 직접 읽은 값은 아니고, 봇 현재가 스냅샷으로 만든 내부 유사 순위야",
        f"- 커버리지: 내부캐시 {cache_count_before}개 → 순위주입 후 {cache_count}개 / 유니버스 {universe_count}개 / 목표 {target_count}개 / 신뢰 {coverage_label}",
        f"- 현재가 스냅샷 전체스윕: 최근 {int(safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT', 0), 0))}개 기록 / 순위주입 최대 {REALTIME_RANK_INJECT_LIMIT}개",
        "- 사진 속 코인이 없으면 이제 /review_trace_detail 코인명 으로 유니버스/캐시/스냅샷 누락 원인을 확인",
        "- 사진 추천: 초입 검증은 5분 상승률, 중간가속은 30분 상승률, 놓친 급등 복기는 1시간 상승률, 돈 붙음은 거래대금 탭",
        "- 상태표시: 현재후보 / 내부감시추적 / 최근알림 / 놓친기록 / 정밀기록 / 미확인",
    ]
    if not rows:
        lines.append("- 현재 내부 캐시/스냅샷 기준 강세 대조 후보가 없어")
        return "\n".join(lines)
    if coverage_ratio < 0.50:
        lines.append("- 판정주의: 지금은 내부캐시가 적어서 빗썸 순위와 1:1 비교하면 안 됨")
    for idx, row in enumerate(rows, start=1):
        ticker = row['ticker']
        tags = []
        if ticker in current_status:
            tags.extend(sorted(current_status.get(ticker) or []))
        if ticker in watch_tickers:
            tags.append('내부감시추적')
        if ticker in alert_tickers:
            tags.append('최근알림')
        if ticker in missed_tickers:
            tags.append('놓친기록')
        if ticker in detail_index:
            tags.append('정밀기록')
        if row.get('injected'):
            tags.append('스냅샷순위')
        seen = set()
        tags = [x for x in tags if not (x in seen or seen.add(x))]
        status_text = ' / '.join(tags) if tags else '미확인'
        check = '봇 기록 있음' if (ticker in current_status or ticker in detail_index or ticker in alert_tickers or ticker in missed_tickers or ticker in watch_tickers) else '봇 상세기록 미확인: 사진 속 강세라면 탐색풀 누락 의심'
        money_text = format_money_or_unknown(row['turnover'], snapshot_based=bool(row.get('injected')) or safe_float(row.get('turnover', 0), 0) <= 0)
        lines.append(
            f"{idx}. {ticker} / 상태 {status_text} / 3m {row['chg3']:+.2f}% / 5m {row['chg5']:+.2f}% / "
            f"15m {row['chg15']:+.2f}% / 30m {row['chg30']:+.2f}% / 1h {row['chg60']:+.2f}% / 거래대금 {money_text} / "
            f"내부순위점수 {row['snapshot_rank_score']:.2f} / {check}"
        )
    return "\n".join(lines)



def build_review_dump_rank_missing_section(scan_display_at_start=None, detail_index: dict = None, limit: int = None) -> str:
    # v2.5.188: 함수 정의 시점에는 REALTIME_RANK_DISPLAY_LIMIT가 아직 아래에서 선언될 수 있어
    # 기본값을 None으로 두고 실행 시점에 globals()로 읽는다.
    if limit is None:
        limit = int(safe_float(globals().get("REALTIME_RANK_DISPLAY_LIMIT", 18), 18))
    """내부 유사 실시간 순위권인데 상세기록이 없는 코인을 따로 보여준다."""
    detail_index = detail_index if isinstance(detail_index, dict) else {}
    current_status = _review_dump_collect_current_ticker_status(scan_display_at_start)
    rank_rows = get_light_snapshot_rank_rows(limit=max(max(1, int(limit)) * 4, int(safe_float(globals().get("REALTIME_RANK_WATCH_SOURCE_LIMIT", 140), 140))), min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
    lines = [
        "🚨 [순위권 누락 의심]",
        "- 목적: 빗썸 순위 사진에는 있는데 봇 기록이 없는 문제를 바로 확인",
        "- 기준: 앱 순위 직접값이 아니라 봇 현재가 스냅샷으로 만든 내부 유사 순위",
        "- 현재가 최신값만 있고 표본이 없던 코인은 detail 조회/순위 갱신 때 감시 등록됨",
    ]
    if not rank_rows:
        lines.append("- 아직 스냅샷 순위 표본이 없어. 봇 시작 후 몇 분 더 지나야 정확해짐")
        return "\n".join(lines)
    shown = 0
    for row in rank_rows:
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            continue
        tags = []
        if ticker in current_status:
            tags.extend(sorted(current_status.get(ticker) or []))
        if ticker in detail_index:
            tags.append("정밀기록")
        try:
            if ticker in shared_market_cache:
                tags.append("내부캐시")
        except Exception:
            pass
        try:
            if isinstance(market_universe, list) and any(str(x.get("ticker", "") if isinstance(x, dict) else x).upper().strip() == ticker for x in market_universe):
                tags.append("유니버스")
        except Exception:
            pass
        with LIGHT_SNAPSHOT_LOCK:
            has_snapshot = ticker in LIGHT_SNAPSHOT_HISTORY
        if has_snapshot:
            tags.append("현재가스냅샷")
        seen = set()
        tags = [x for x in tags if x and not (x in seen or seen.add(x))]
        has_detail = ticker in detail_index or ticker in current_status or has_recent_realtime_rank_trace(ticker)
        cause = "기록 있음"
        if not has_detail:
            saved = append_realtime_rank_min_trace(row, item=None, now_ts=time.time(), force=True)
            has_detail = bool(saved) or has_recent_realtime_rank_trace(ticker)
        if has_detail:
            if ticker not in detail_index and ticker not in current_status:
                cause = "복기용 기록 있음"
            else:
                cause = "기록 있음"
        else:
            if not tags or tags == ["현재가스냅샷"]:
                cause = "복기 기록 저장 실패 → 탐색풀/순위주입 확인"
            elif "내부캐시" not in tags and "유니버스" not in tags:
                cause = "스냅샷만 있음 → 유니버스/캐시 미포함 의심"
            else:
                cause = "캐시에는 있으나 정밀기록 없음 → fast scan 선별 확인"
        row = apply_verified_turnover_to_row(row)
        if has_detail:
            queue_realtime_rank_turnover_verify(row, reason="rank_missing_section")
        money = format_money_for_row(row)
        lines.append(
            f"{shown + 1}. {ticker} / 태그 {' / '.join(tags) if tags else '기록없음'} / "
            f"3m {safe_float(row.get('change_3', 0), 0):+.2f}% / 5m {safe_float(row.get('change_5', 0), 0):+.2f}% / "
            f"30m {safe_float(row.get('change_30', 0), 0):+.2f}% / 1h {safe_float(row.get('change_60', 0), 0):+.2f}% / "
            f"돈 {money} / 점수 {safe_float(row.get('snapshot_rank_score', 0), 0):.2f} / {cause}"
        )
        shown += 1
        if shown >= max(1, int(limit)):
            break
    return "\n".join(lines)


def format_snapshot_sample_age_text(row: dict) -> str:
    try:
        detected = safe_float(row.get("snapshot_rank_detected_ts", 0), 0)
        if detected <= 0:
            return "표본시간 확인 안 됨"
        age = max(0.0, time.time() - detected)
        return f"스냅샷 {format_elapsed_text(age)} 전 기준"
    except Exception:
        return "표본시간 확인 안 됨"





def freeze_rank_rows_for_command_snapshot(rows: list, limit: int = None) -> list:
    """v2.5.224: 한 캐시 묶음 안에서 rank_short/rank_watch가 같은 원본을 보게 얕은 복사로 고정한다."""
    frozen = []
    try:
        max_n = None if limit is None else max(1, int(limit))
    except Exception:
        max_n = None
    try:
        for row in list(rows or []):
            if not isinstance(row, dict):
                continue
            cloned = dict(row)
            ticker = str(cloned.get("ticker", "") or "").upper().strip()
            if ticker:
                cloned["ticker"] = ticker
            cloned["command_rank_snapshot_frozen"] = True
            frozen.append(cloned)
            if max_n is not None and len(frozen) >= max_n:
                break
    except Exception:
        return []
    return frozen


def _rank_snapshot_meta_line(snapshot_meta: dict) -> str:
    """rank 출력용 고정 스냅샷 안내. 길어지지 않게 한 줄만 붙인다."""
    try:
        meta = snapshot_meta if isinstance(snapshot_meta, dict) else {}
        gen = meta.get("generation", "")
        ts = safe_float(meta.get("created_ts", 0), 0)
        rows = int(safe_float(meta.get("rank_rows", 0), 0))
        if not gen and ts <= 0 and rows <= 0:
            return ""
        parts = []
        if gen not in {"", None}:
            parts.append(f"묶음#{gen}")
        if ts > 0:
            parts.append(f"{format_elapsed_text(time.time() - ts)} 전 고정")
        if rows > 0:
            parts.append(f"원본 {rows}개")
        return "- 고정 스냅샷: " + " / ".join(parts)
    except Exception:
        return ""



def get_market_cache_age_for_display(now_ts: float = None, display: dict = None):
    """v2.5.228: scan_health와 work_check가 시장 데이터 시간을 같은 기준으로 보게 한다."""
    try:
        now_ts = safe_float(now_ts, time.time())
        if isinstance(display, dict):
            age = display.get("cache_age")
            if age is not None:
                return int(max(0, safe_float(age, 0)))
        ts = safe_float(globals().get("shared_market_cache_time", 0), 0)
        if ts > 0:
            return int(max(0, now_ts - ts))
        ts = safe_float(globals().get("last_shared_cache_success_ts", 0), 0)
        if ts > 0:
            return int(max(0, now_ts - ts))
    except Exception:
        return None
    return None


def cache_delay_status_text(age_sec: float, building: bool = False) -> str:
    try:
        age = safe_float(age_sec, 0)
        if age <= 45:
            return f"정상 갱신권 / 완성본 {format_elapsed_text(age)} 전"
        if age <= 90:
            return f"느림, 마지막 완성본 참고 / 완성본 {format_elapsed_text(age)} 전" + (" / 새 캐시 생성 중" if building else "")
        if age <= 120:
            return f"지연 의심 / 완성본 {format_elapsed_text(age)} 전 / 워커·API 병목 확인"
        return f"병목 확인 필요 / 완성본 {format_elapsed_text(age)} 전 / scan_health와 오류로그 확인"
    except Exception:
        return "캐시 지연 상태 확인중"


def is_rank_row_noise_for_display(row: dict) -> bool:
    try:
        row = row if isinstance(row, dict) else {}
        return bool(row.get("rank_tick_noise_block", False) or row.get("ultra_low_tick_noise_block", False) or is_realtime_rank_tick_noise(row))
    except Exception:
        return False


def format_rank_timeframe_summary(rank_rows: list, top_n: int = None) -> str:
    """v2.5.228: 빗썸식 시간대별 랭크판. 저장된 현재가 스냅샷만 사용한다."""
    try:
        rows = [dict(x) for x in list(rank_rows or []) if isinstance(x, dict)]
        top_n = max(1, int(safe_float(top_n if top_n is not None else globals().get("MISSED_REVIEW_RANK_SUMMARY_TOP_N", 3), 3)))
        if not rows:
            return ""
        specs = [("1분", "change_1"), ("3분", "change_3"), ("5분", "change_5"), ("15분", "change_15"), ("30분", "change_30"), ("1시간", "change_60")]
        lines = ["", "⏱ 시간대별 강세 요약", "- 알림 판단용이 아니라, 빗썸식으로 뭐가 움직이는지 보는 대조판"]
        for label, key in specs:
            picked = []
            for row in rows:
                ticker = str(row.get("ticker", "") or "").upper().strip()
                if not ticker or is_rank_row_noise_for_display(row):
                    continue
                val = safe_float(row.get(key, 0), 0)
                min_v = 0.20 if key == "change_1" else 0.10
                if val < min_v:
                    continue
                money = safe_float(row.get("turnover", row.get("snapshot_turnover_hint", row.get("turnover_5m", 0))), 0)
                score = safe_float(row.get("snapshot_rank_score", 0), 0)
                picked.append((val, score, money, ticker, row))
            picked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
            bits = []
            for val, score, money, ticker, row in picked[:top_n]:
                tail = f"{ticker} {val:+.2f}%"
                if money >= 1_000_000:
                    tail += f"·{format_money_compact_amount_krw(money)}"
                bits.append(tail)
            lines.append(f"- {label}: " + (", ".join(bits) if bits else "의미 있는 강세 없음"))
        return "\n".join(lines)
    except Exception:
        return ""


def missed_review_noise_reason(row: dict) -> str:
    """v2.5.228: missed 장부에 오래 둘 가치가 낮은 잡음/틱/극소액 표본을 분리한다."""
    try:
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return "티커 없음"
        if is_watch_excluded_ticker(ticker):
            return "제외종목"
        if bool(row.get("rank_tick_noise_block", False)) or bool(row.get("ultra_low_tick_noise_block", False)) or is_realtime_rank_tick_noise(row):
            return "초저가 틱노이즈"
        price = safe_float(row.get("base_price", row.get("price", row.get("current_price", 0))), 0)
        if price > 0 and price <= safe_float(globals().get("USER_ALERT_ULTRA_LOW_TICK_PRICE_MAX", 0.01), 0.01):
            tick = estimate_bithumb_low_price_tick_unit_v227(price)
            tick_pct = (tick / price) * 100.0 if tick > 0 else 0.0
            if tick_pct >= safe_float(globals().get("USER_ALERT_ULTRA_LOW_TICK_MIN_TICK_PCT", 0.65), 0.65):
                return "초저가 한 틱 착시"
        turnover = safe_float(row.get("turnover", row.get("turnover_5m", 0)), 0)
        strongest = max(
            safe_float(row.get("chg_5m", row.get("change_5", 0)), 0),
            safe_float(row.get("chg_30m", row.get("change_30", 0)), 0),
            safe_float(row.get("from_30m_low_pct", row.get("from_low", 0)), 0),
            safe_float(row.get("best_up_pct", 0), 0),
        )
        seen_signal = bool(row.get("seen_signal", False) or row.get("seen_shortlist", False))
        seen_hot = bool(row.get("seen_hot_rank", False))
        if turnover > 0 and turnover < safe_float(globals().get("MISSED_REVIEW_TINY_MONEY_BLOCK_KRW", 100_000), 100_000) and strongest < 2.0 and not seen_signal and not seen_hot:
            return "실거래대금 극소액"
        if turnover > 0 and turnover < safe_float(globals().get("MISSED_REVIEW_MIN_TRACK_TURNOVER_KRW", 100_000), 100_000) and strongest < 1.2 and not seen_signal:
            return "돈 거의 없음"
        return ""
    except Exception:
        return ""


def get_missed_review_bucket(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        if missed_review_noise_reason(row):
            return "잡음"
        if bool(row.get("pending", False)) or safe_float(row.get("review_ts", 0), 0) > time.time():
            return "대기"
        quality = str(row.get("result_quality", "") or "")
        miss_level = str(row.get("miss_level", "") or "")
        best = safe_float(row.get("best_up_pct", 0), 0)
        end = safe_float(row.get("end_up_pct", 0), 0)
        fade = best - end
        if quality == "good" or miss_level == "핵심":
            return "진짜놓침"
        if quality == "spike" or (best >= 1.5 and end <= 0.25 and fade >= 1.2):
            return "가짜튐"
        if quality == "assist" or miss_level == "보조":
            return "애매"
        return "애매" if best >= 1.0 else "잡음"
    except Exception:
        return "애매"


def missed_review_retention_sec(row: dict) -> int:
    try:
        bucket = get_missed_review_bucket(row)
        if bucket == "진짜놓침":
            return int(safe_float(globals().get("MISSED_REVIEW_TRUE_KEEP_SEC", 7 * 24 * 3600), 7 * 24 * 3600))
        if bucket == "애매":
            return int(safe_float(globals().get("MISSED_REVIEW_ASSIST_KEEP_SEC", 6 * 3600), 6 * 3600))
        if bucket in {"잡음", "가짜튐"}:
            return int(safe_float(globals().get("MISSED_REVIEW_NOISE_KEEP_SEC", 3600), 3600))
        return int(safe_float(globals().get("MISSED_REVIEW_PENDING_KEEP_SEC", 45 * 60), 45 * 60))
    except Exception:
        return 6 * 3600


def get_missed_review_pending_rows(limit: int = 5) -> list:
    try:
        now_ts = time.time()
        rows = []
        for ticker, row in list((missed_review_queue or {}).items()):
            if not isinstance(row, dict):
                continue
            if safe_float(row.get("review_ts", 0), 0) <= now_ts:
                continue
            if missed_review_noise_reason(row):
                continue
            rows.append(row)
        rows.sort(key=lambda r: (
            -safe_float(r.get("signal_score", r.get("edge_score", 0)), 0),
            -max(safe_float(r.get("chg_5m", 0), 0), safe_float(r.get("chg_30m", 0), 0), safe_float(r.get("from_30m_low_pct", 0), 0)),
            safe_float(r.get("review_ts", 0), 0),
        ))
        return rows[:max(1, int(limit))]
    except Exception:
        return []


def format_missed_review_summary_line() -> str:
    try:
        now_ts = time.time()
        pending = 0
        noise = 0
        for _ticker, row in list((missed_review_queue or {}).items()):
            if not isinstance(row, dict):
                continue
            if safe_float(row.get("review_ts", 0), 0) <= now_ts:
                continue
            if missed_review_noise_reason(row):
                noise += 1
            else:
                pending += 1
        recent = [x for x in list(missed_review_logs or []) if isinstance(x, dict)]
        true_rows = [x for x in recent if get_missed_review_bucket(x) == "진짜놓침"]
        assist_rows = [x for x in recent if get_missed_review_bucket(x) == "애매"]
        last_true = ""
        if true_rows:
            r0 = true_rows[-1]
            last_true = f" / 최근 {str(r0.get('ticker','?')).upper()} 최고 {safe_float(r0.get('best_up_pct',0),0):+.2f}%·끝 {safe_float(r0.get('end_up_pct',0),0):+.2f}%"
        return f"- 대기 {pending}개 / 최근 진짜놓침 {len(true_rows[-10:])}개 / 애매 {len(assist_rows[-10:])}개 / 잡음정리 {noise}개{last_true}"
    except Exception:
        return "- 놓침감시 요약 확인중"


def format_missed_review_pending_compact(limit: int = 4) -> str:
    rows = get_missed_review_pending_rows(limit=limit)
    if not rows:
        return "- 대기 중인 놓침 후보 없음"
    lines = []
    now_ts = time.time()
    for idx, row in enumerate(rows, start=1):
        ticker = str(row.get("ticker", "?") or "?").upper()
        left = max(0, safe_float(row.get("review_ts", 0), 0) - now_ts)
        reason = str(row.get("quality_block_reason", "") or row.get("strategy_label", "") or "검증 대기")
        lines.append(
            f"{idx}. {ticker} / 30분결과 {format_elapsed_text(left)} 뒤 / "
            f"5분 {safe_float(row.get('chg_5m',0),0):+.2f}% / 30분 {safe_float(row.get('chg_30m',0),0):+.2f}% / "
            f"저점대비 {safe_float(row.get('from_30m_low_pct',0),0):+.2f}% / 이유 {reason[:42]}"
        )
    return "\n".join(lines)

def format_rank_watch_storage_status(row: dict, action_label: str = None, has_trace=None) -> str:
    """정밀검토/복기/등록 상태를 '저장 확인 대기' 같은 애매한 말 대신 실제 운영상태로 정리한다."""
    try:
        row = row if isinstance(row, dict) else {}
        label = str(action_label if action_label is not None else realtime_rank_watch_action_label_with_tracking(row) or "").strip()
        if has_trace is None:
            ticker = str(row.get("ticker", "") or "").upper().strip()
            has_trace = has_recent_realtime_rank_trace(ticker) if ticker else False
        if label == "내부감시 등록됨" or label.startswith("등록 보류"):
            return label
        if label == "정밀검토 대기":
            return "정밀검토 대기"
        if label == "복기용 기록":
            return "복기 기록됨" if has_trace else "복기 기록 대기"
        return label or "상태 확인중"
    except Exception:
        return str(action_label or "상태 확인중")

def build_rank_watch_text(limit: int = None, rank_rows_override=None, snapshot_meta: dict = None) -> str:
    limit = int(safe_float(limit if limit is not None else globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 20), 20))
    source_limit = max(max(1, limit), int(safe_float(globals().get("REALTIME_RANK_WATCH_SOURCE_LIMIT", 140), 140)))
    if rank_rows_override is not None:
        rank_rows = freeze_rank_rows_for_command_snapshot(rank_rows_override, limit=source_limit)
        source_limit = max(source_limit, len(rank_rows))
    else:
        rank_rows = get_light_snapshot_rank_rows(limit=source_limit, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
    lines = [
        "📊 순위권 대조 / 내부 유사 순위",
        "- 빗썸 앱 순위를 직접 읽은 값은 아니고, 봇 현재가 스냅샷으로 만든 대조용 순위야",
        "- 사진과 시간이 다르면 3분 순위는 크게 달라질 수 있어",
        "- 봇 시작 후 30분/1시간이 덜 지났으면 앱 30분·1시간 상승률과 차이가 날 수 있어",
        f"- 현재가 스냅샷 전체스윕: 최근 {int(safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT', 0), 0))}개 기록 / 후보소스 {source_limit}개까지 확인",
        f"- 강제감시 등록: {len(globals().get('LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS', {}) if isinstance(globals().get('LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS', {}), dict) else {})}개",
        "- 정밀검토 대기 = 순위권 강세라 내부 감시 후보로 한 번 더 볼 자리",
        "- 복기용 기록 = 바로 매수 신호가 아니라 나중에 놓쳤는지 비교하려고 저장한 기록",
        "- 거래대금 확인 전 = 현재가 스냅샷으로 먼저 잡은 상태. 진짜 돈 없음으로 단정하지 않음",
        "- 실거래대금 작음/얇음 = 실제 대금이 확인됐지만 작아서 보수적으로 봄",
        "- 유니버스/캐시에 없어도 현재가 스냅샷 점수가 높으면 우선 목록에 올림",
        "",
    ]
    meta_line = _rank_snapshot_meta_line(snapshot_meta)
    if meta_line:
        lines.insert(len(lines) - 1, meta_line)
    summary = format_rank_timeframe_summary(rank_rows, top_n=MISSED_REVIEW_RANK_SUMMARY_TOP_N)
    if summary:
        lines.append(summary)
        lines.append("")
    try:
        compare_rows = [r for r in rank_rows if bool(r.get("app_compare_candidate", False))]
        compare_rows = sorted(compare_rows, key=lambda x: (safe_float(x.get("app_compare_score", 0), 0), safe_float(x.get("snapshot_rank_score", 0), 0)), reverse=True)
        if compare_rows:
            lines.append("🎯 앱 대조 후보층")
            lines.append("- 앱을 직접 읽은 값은 아니고, 1/3/5/15/30분 중 여러 구간에 반복 등장하는 후보야")
            for _r in compare_rows[:5]:
                lines.append(f"- {str(_r.get('ticker','?')).upper()} / 반복구간 {int(safe_float(_r.get('app_compare_window_count',0),0))}개({str(_r.get('app_compare_hits','') or '-')}) / 점수 {safe_float(_r.get('app_compare_score',0),0):.2f} / 3m {safe_float(_r.get('change_3',0),0):+.2f}% / 15m {safe_float(_r.get('change_15',0),0):+.2f}% / 30m {safe_float(_r.get('change_30',0),0):+.2f}%")
            lines.append("")
    except Exception:
        pass
    if not rank_rows:
        lines.append("- 아직 순위감시 표본이 없어. 봇 시작 후 몇 분 더 지나야 정확해짐")
        return "\n".join(lines)
    for idx, row in enumerate(rank_rows[:max(1, limit)], start=1):
        ticker = str(row.get("ticker", "") or "").upper().strip()
        readonly_cache = bool(globals().get("COMMAND_DISPLAY_READONLY_BUILDING", False))
        # v2.5.232: 읽기전용 명령어 출력 중에는 reverse_trace 파일을 티커마다 다시 읽지 않는다.
        # 이 반복 파일 I/O가 rank_short/rank_watch/work_check 지연의 핵심 원인이었다.
        has_trace = bool(row.get("rank_trace_exists", False) or row.get("realtime_rank_injected", False)) if readonly_cache else has_recent_realtime_rank_trace(ticker)
        if (not readonly_cache) and not has_trace:
            saved = append_realtime_rank_min_trace(row, item=None, now_ts=time.time(), force=True)
            has_trace = bool(saved) or has_recent_realtime_rank_trace(ticker)
        row = apply_watch_display_consistency_v244(row) if 'apply_watch_display_consistency_v244' in globals() else row
        action_label = realtime_rank_watch_action_label_with_tracking(row)
        status = format_rank_watch_storage_status(row, action_label=action_label, has_trace=has_trace)
        if not bool(row.get("command_rank_snapshot_frozen", False)):
            row = apply_verified_turnover_to_row(row)
        if (not bool(globals().get("COMMAND_DISPLAY_READONLY_BUILDING", False))) and (not bool(row.get("command_rank_snapshot_frozen", False))) and is_realtime_rank_precision_candidate(row):
            queue_realtime_rank_turnover_verify(row, reason="rank_watch_command")
        row = apply_money_sustain_context(row)
        money = format_money_for_row(row)
        money_sustain = format_money_sustain_compact(row)
        sample_note = format_snapshot_sample_age_text(row)
        state = classify_rank_watch_chart_state(row).get('label', '상태확인중')
        trade_note = format_ws_trade_signal_for_row(row)
        candle_note = format_current_candle_compact_for_row(row)
        candle_part = f" / 현재봉 {candle_note}" if candle_note else ""
        final_reason = format_final_candidate_reason_v251(row, prefix="판단사유") if 'format_final_candidate_reason_v251' in globals() else ""
        final_part = f" / {final_reason}" if final_reason else ""
        lines.append(
            f"{idx}. {ticker} / {format_rank_change_value(row, 'change_3', 180, '3m')} / "
            f"{format_rank_change_value(row, 'change_5', 300, '5m')} / "
            f"{format_rank_change_value(row, 'change_15', 900, '15m')} / "
            f"{format_rank_change_value(row, 'change_30', 1800, '30m')} / "
            f"{format_rank_change_value(row, 'change_60', 3600, '1h')} / "
            f"점수 {safe_float(row.get('snapshot_rank_score',0),0):.2f} / {money} / 돈흐름 {money_sustain} / 체결 {trade_note}{candle_part}{final_part} / {status} / {state} / {sample_note}"
        )
    lines.append("")
    lines.append("- 특정 코인 복기: /review_trace_detail 코인명 또는 아래 상세 버튼")
    return "\n".join(lines)


def build_detail_buttons_for_tickers(tickers, max_buttons: int = 12, per_row: int = 2):
    """코인 상세를 직접 입력하지 않고 버튼으로 열기 위한 공통 키보드."""
    try:
        max_buttons = max(1, min(int(max_buttons or 12), 24))
        per_row = max(1, min(int(per_row or 2), 3))
        uniq = []
        seen = set()
        for raw in tickers or []:
            tk = str(raw or '').upper().strip()
            if not tk or tk in seen:
                continue
            # 텔레그램 callback_data 64바이트 제한을 피하기 위해 티커만 넣는다.
            if len(tk) > 18:
                continue
            seen.add(tk)
            uniq.append(tk)
            if len(uniq) >= max_buttons:
                break
        if not uniq:
            return None
        rows = []
        cur = []
        for tk in uniq:
            cur.append(InlineKeyboardButton(f"상세 {tk}", callback_data=f"rv:detail:{tk}"))
            if len(cur) >= per_row:
                rows.append(cur)
                cur = []
        if cur:
            rows.append(cur)
        return InlineKeyboardMarkup(rows)
    except Exception:
        return None


def build_rank_watch_detail_keyboard(limit: int = None):
    try:
        limit = int(safe_float(limit if limit is not None else globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 20), 20))
        source_limit = max(max(1, limit), int(safe_float(globals().get("REALTIME_RANK_WATCH_SOURCE_LIMIT", 140), 140)))
        rows = get_light_snapshot_rank_rows(limit=source_limit, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
        return build_detail_buttons_for_tickers([r.get("ticker") for r in rows[:max(1, limit)]], max_buttons=min(20, max(1, limit)), per_row=2)
    except Exception:
        return None


