def rank_short_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    limit = RANK_WATCH_SHORT_LIMIT
    has_args = bool(getattr(context, 'args', None))
    try:
        if has_args:
            limit = int(context.args[0])
    except Exception:
        limit = RANK_WATCH_SHORT_LIMIT
    if (not has_args) or int(limit) == int(RANK_WATCH_SHORT_LIMIT):
        # v2.5.206: 기본 rank_short는 캐시 읽기만 한다.
        send_cached_or_build_command("rank_short", lambda: build_rank_watch_short_text(limit=limit), prefix='', reply_markup=None, cache_keyboard=True, limit=TG_MESSAGE_SOFT_LIMIT)
    else:
        keyboard = build_rank_watch_short_keyboard(limit=limit)
        send_text_chunks(build_rank_watch_short_text(limit=limit), prefix='', limit=TG_MESSAGE_SOFT_LIMIT, reply_markup=keyboard)


def _compact_scan_health_lines_from_text(text: str, max_lines: int = 9) -> list:
    """v2.5.235: 이미 만든 scan_health 텍스트에서 work_check용 핵심 줄만 뽑는다.

    work_check 캐시 조립 중 build_scan_health_text(compact=True)를 다시 호출하면
    runtime_event_log 파일 요약/상태 계산을 중복으로 타면서 build_fast_work_check가
    100초 이상 걸릴 수 있었다. 이미 만든 scan_health_text를 재사용해서
    work_check는 진짜 조립만 하게 만든다.
    """
    try:
        raw = str(text or "").splitlines()
    except Exception:
        raw = []
    keep_keys = ['전체 판단', '시장 데이터', '마지막 후보', '메인 루프', 'OHLCV 실패', '계획 순환', 'timeout', '캐시:', '유니버스:', '강세대조']
    out = []
    for ln in raw:
        s = str(ln).strip()
        if not s:
            continue
        if any(k in s for k in keep_keys) or s.startswith('🩺'):
            out.append(s)
        if len(out) >= max(1, int(max_lines)):
            break
    return out or raw[:max(1, int(max_lines))]


def _compact_scan_health_lines(max_lines: int = 9) -> list:
    try:
        raw_text = str(build_scan_health_text(compact=True))
    except TypeError:
        raw_text = str(build_scan_health_text())
    except Exception as e:
        return [f"- 스캔헬스 생성 실패: {e}"]
    return _compact_scan_health_lines_from_text(raw_text, max_lines=max_lines)


def build_work_check_text() -> str:
    """일하는 중 빠르게 보는 1세트: 상태 + 순위권 짧게 + 내부감시 압축."""
    now_ts = time.time()
    try:
        display = get_latest_scan_display_state(now_ts=now_ts, limit=6)
    except Exception:
        display = {}
    user_items = [x for x in list(display.get('user_items') or []) if not is_fast_scan_tiny_turnover_noise(x)]
    internal_items = [x for x in list(display.get('internal_items') or []) if not is_fast_scan_tiny_turnover_noise(x)]
    discard_items = [x for x in list(display.get('discard_items') or []) if not is_fast_scan_tiny_turnover_noise(x)]
    note = format_scan_display_state_line(display) if display else '스캔 상태 확인중'
    watch_active_count, watch_done_count = get_internal_watch_counts_for_summary()
    lines = [
        "⚡ 일하는 중 압축 /work_check",
        f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S')}",
        "- 긴 review_dump는 평소 제외. 내가 요청할 때만 뽑으면 됨",
        "",
        "1) 상태",
        f"- 자동매수: {'켜짐' if AUTO_BUY else '꺼짐'} / 보유: {len(active_positions)}개" if active_positions else f"- 자동매수: {'켜짐' if AUTO_BUY else '꺼짐'} / 보유: 없음",
        f"- 후보: 바로 {len(user_items)} / 관찰 {len(internal_items)}",
        f"- 내부감시: 진행 {watch_active_count} / 완료 {watch_done_count}",
        f"- 복기기록: {len(discard_items)}개",
        f"- 기준: {note}",
        "",
        "2) 놓침감시",
        format_missed_review_summary_line(),
        "",
        "3) 스캔 핵심",
    ]
    lines += _compact_scan_health_lines(max_lines=9)
    lines += ["", "4) 순위권 짧게"]
    rank_text = build_rank_watch_short_text(limit=WORK_CHECK_RANK_LIMIT).splitlines()
    for ln in rank_text:
        s = str(ln).strip()
        if not s or s.startswith('📊') or s.startswith('- 최근') or s.startswith('- 정밀검토') or s.startswith('🧷') or s.startswith('- 특정') or s.startswith('- 더'):
            continue
        lines.append(s)
    lines += ["", "5) 내부감시"]
    watch_text = build_review_watch_text(active_limit=WORK_CHECK_WATCH_ACTIVE_LIMIT, done_limit=2).splitlines()
    for ln in watch_text:
        s = str(ln).strip()
        if not s or s.startswith('🧪') or s.startswith('- 이건') or s.startswith('🧷') or s.startswith('- 특정') or s.startswith('- 길게'):
            continue
        lines.append(s)
    lines += ["", "🧷 길게 필요할 때만", "- 전체 덤프: /review_dump", "- 여러 코인 상세: /trace_set 코인1 코인2", "- 순위권 길게: /rank_watch"]
    return "\n".join(lines)


def build_work_check_text_from_cached_parts(rank_text_override: str = None, watch_text_override: str = None, scan_health_text_override: str = None) -> str:
    """v2.5.215: 캐시 워커용 work_check.

    rank_short/review_watch를 다시 계산하지 않고, 같은 캐시 생성 회차에서 만든 텍스트를 조합한다.
    이렇게 해야 work_check만 최신이고 rank_short/review_watch는 60초 전으로 밀리는 현상을 막을 수 있다.
    """
    now_ts = time.time()
    try:
        display = get_latest_scan_display_state(now_ts=now_ts, limit=6)
    except Exception:
        display = {}
    user_items = [x for x in list(display.get('user_items') or []) if not is_fast_scan_tiny_turnover_noise(x)] if display else []
    internal_items = [x for x in list(display.get('internal_items') or []) if not is_fast_scan_tiny_turnover_noise(x)] if display else []
    discard_items = [x for x in list(display.get('discard_items') or []) if not is_fast_scan_tiny_turnover_noise(x)] if display else []
    note = format_scan_display_state_line(display) if display else '스캔 상태 확인중'
    watch_active_count, watch_done_count = get_internal_watch_counts_for_summary()
    lines = [
        "⚡ 일하는 중 압축 /work_check",
        f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S')}",
        "- 긴 review_dump는 평소 제외. 내가 요청할 때만 뽑으면 됨",
        "",
        "1) 상태",
        f"- 자동매수: {'켜짐' if AUTO_BUY else '꺼짐'} / 보유: {len(active_positions)}개" if active_positions else f"- 자동매수: {'켜짐' if AUTO_BUY else '꺼짐'} / 보유: 없음",
        f"- 후보: 바로 {len(user_items)} / 관찰 {len(internal_items)}",
        f"- 내부감시: 진행 {watch_active_count} / 완료 {watch_done_count}",
        f"- 복기기록: {len(discard_items)}개",
        f"- 기준: {note}",
        "",
        "2) 놓침감시",
        format_missed_review_summary_line(),
        "",
        "3) 스캔 핵심",
    ]
    if scan_health_text_override:
        lines += _compact_scan_health_lines_from_text(scan_health_text_override, max_lines=9)
    else:
        # 마지막 안전 fallback. 정상 캐시 워커 경로에서는 scan_health_text_override를 반드시 넘긴다.
        lines += _compact_scan_health_lines(max_lines=9)
    rank_text = str(rank_text_override or "")
    watch_text = str(watch_text_override or "")
    if not rank_text:
        rank_row = get_command_display_cache("rank_short", allow_stale=True)
        rank_text = str((rank_row or {}).get("text", "") or "")
    if not watch_text:
        watch_row = get_command_display_cache("review_watch", allow_stale=True)
        watch_text = str((watch_row or {}).get("text", "") or "")
    lines += ["", "4) 순위권 짧게"]
    rank_lines = rank_text.splitlines()
    if rank_lines:
        for ln in rank_lines:
            s = str(ln).strip()
            if not s or s.startswith('📊') or s.startswith('- 최근') or s.startswith('- 정밀검토') or s.startswith('🧷') or s.startswith('- 특정') or s.startswith('- 더') or s.startswith('- 캐시상태'):
                continue
            lines.append(s)
    else:
        lines.append("- 순위권 캐시 준비중")
    lines += ["", "5) 내부감시"]
    watch_lines = watch_text.splitlines()
    if watch_lines:
        for ln in watch_lines:
            s = str(ln).strip()
            if not s or s.startswith('🧪') or s.startswith('- 이건') or s.startswith('🧷') or s.startswith('- 특정') or s.startswith('- 길게') or s.startswith('- 캐시상태'):
                continue
            lines.append(s)
    else:
        lines.append("- 내부감시 캐시 준비중")
    lines += ["", "🧷 길게 필요할 때만", "- 전체 덤프: /review_dump", "- 여러 코인 상세: /trace_set 코인1 코인2", "- 순위권 길게: /rank_watch"]
    return "\n".join(lines)


def set_command_display_cache_bundle(rows: dict):
    """work_check/review_watch/rank_short를 한 번에 교체한다.

    중간에 한 항목만 최신으로 바뀌는 상태를 막기 위한 원자 갱신 함수다.
    """
    global COMMAND_DISPLAY_CACHE_GENERATION, COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION, COMMAND_DISPLAY_CACHE_LAST_COMPLETE_TS
    try:
        created_ts = time.time()
        with COMMAND_DISPLAY_CACHE_LOCK:
            COMMAND_DISPLAY_CACHE_GENERATION += 1
            generation = COMMAND_DISPLAY_CACHE_GENERATION
            for key, row in (rows or {}).items():
                if not isinstance(row, dict):
                    continue
                COMMAND_DISPLAY_CACHE[str(key)] = {
                    "text": str(row.get("text", "") or ""),
                    "created_ts": created_ts,
                    "tickers": list(row.get("tickers") or []),
                    "generation": generation,
                    "bundle_created_ts": created_ts,
                    "snapshot_meta": dict(row.get("snapshot_meta") or {}),
                }
            COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION = generation
            COMMAND_DISPLAY_CACHE_LAST_COMPLETE_TS = created_ts
    except Exception:
        pass


def set_command_display_cache(key: str, text: str, tickers=None):
    try:
        with COMMAND_DISPLAY_CACHE_LOCK:
            COMMAND_DISPLAY_CACHE[str(key)] = {
                "text": str(text or ""),
                "created_ts": time.time(),
                "tickers": list(tickers or []),
                "generation": COMMAND_DISPLAY_CACHE_GENERATION,
                "bundle_created_ts": time.time(),
                "snapshot_meta": {},
            }
    except Exception:
        pass


def get_command_display_cache(key: str, max_age_sec: float = None, allow_stale: bool = False) -> dict:
    try:
        if not bool(globals().get("COMMAND_DISPLAY_CACHE_ON", True)):
            return {}
        max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("COMMAND_DISPLAY_MAX_AGE_SEC", 90), 90)
        snapshot = globals().get("COMMAND_DISPLAY_BATCH_SNAPSHOT", None)
        if isinstance(snapshot, dict) and str(key) in snapshot:
            row = snapshot.get(str(key))
        else:
            with COMMAND_DISPLAY_CACHE_LOCK:
                row = COMMAND_DISPLAY_CACHE.get(str(key))
        if not isinstance(row, dict):
            return {}
        age = time.time() - safe_float(row.get("created_ts", 0), 0)
        out = dict(row)
        out["age_sec"] = int(max(0, age))
        warn_age_sec = safe_float(globals().get("COMMAND_DISPLAY_WARN_AGE_SEC", 45), 45)
        out["is_warn"] = bool(age > warn_age_sec and age <= max_age_sec)
        out["is_stale"] = bool(age > max_age_sec)
        if out["is_stale"] and not allow_stale:
            return {}
        return out
    except Exception:
        return {}


def _cached_command_text(row: dict) -> str:
    text = str((row or {}).get("text", "") or "").strip()
    if not text:
        return ""
    age = int(safe_float((row or {}).get("age_sec", 0), 0))
    stale = bool((row or {}).get("is_stale", False))
    warn = bool((row or {}).get("is_warn", False))
    gen = (row or {}).get("generation", "")
    gen_tail = f" / 묶음#{gen}" if gen not in {"", None} else ""
    building = bool(globals().get("COMMAND_DISPLAY_CACHE_WORKER_BUILDING", False))
    if stale:
        return text + f"\n- 캐시상태: 오래됨 / 마지막 완성본 {age}초 전 / 명령어 직접계산은 막아둠{gen_tail}"
    if warn:
        if building:
            return text + f"\n- 캐시상태: 완성본 사용 / {age}초 전 생성 / 새 캐시 생성 중이라 참고용{gen_tail}"
        return text + f"\n- 캐시상태: 사용됨 / {age}초 전 생성 / 약간 오래됨, 참고용{gen_tail}"
    return text + f"\n- 캐시상태: 사용됨 / {age}초 전 생성 / 명령어는 즉시 출력{gen_tail}"


def _command_cache_title(key: str) -> str:
    title_map = {
        "work_check": "⚡ /work_check",
        "review_watch": "🧪 /review_watch",
        "rank_short": "📊 /rank_short",
        "scan_health": "🩺 /scan_health",
        "rank_watch": "📊 /rank_watch",
        "review_pack": "🧩 /review_pack",
        "review_dump": "🧾 /review_dump",
        "check": "⚡ /check",
    }
    return title_map.get(str(key), "/" + str(key))


def _snapshot_span_label(span_sec: float) -> str:
    span_sec = safe_float(span_sec, 0)
    if span_sec <= 0:
        return "표본 없음"
    if span_sec < 60:
        return f"표본 {int(span_sec)}초"
    return f"표본 {format_elapsed_text(span_sec)}"


def format_rank_change_value(row: dict, key: str, seconds: int, label: str) -> str:
    """스냅샷 변화율 표시용. 기준값이 없는데 0.00%로 확정 표시하지 않는다."""
    row = row if isinstance(row, dict) else {}
    val = safe_float(row.get(key, 0), 0)
    span = safe_float(row.get("snapshot_span_sec", 0), 0)
    ready_key = f"{key}_ready"
    ready = row.get(ready_key, None)
    min_span = max(int(seconds) * 0.80, 30)
    if ready is False:
        if span >= int(seconds) * 0.98:
            return f"{label} 계산대기(기준가 부족/{_snapshot_span_label(span)})"
        return f"{label} 계산중({_snapshot_span_label(span)})"
    if span > 0 and span < min_span:
        return f"{label} 계산중({_snapshot_span_label(span)})"
    return f"{label} {val:+.2f}%"


def _active_internal_watch_tickers() -> set:
    try:
        active, _logs = _get_internal_watch_state_parts()
        return {str(k or "").upper().strip() for k in active.keys() if str(k or "").strip()}
    except Exception:
        return set()




def get_internal_watch_dynamic_max_active(candidate: dict = None, active: dict = None) -> int:
    """v2.5.243: active 내부감시 최대치를 장 상황/신규 후보 강도에 따라 조절한다.

    기본 감각은 14개지만, 강한 신규 후보가 들어올 때는 최대 18개까지 허용한다.
    """
    try:
        base = int(safe_float(globals().get("INTERNAL_WATCH_TRACK_BASE_ACTIVE", 14), 14))
        burst = int(safe_float(globals().get("INTERNAL_WATCH_TRACK_BURST_MAX_ACTIVE", globals().get("INTERNAL_WATCH_TRACK_MAX_ACTIVE", 18)), 18))
        if burst < base:
            burst = base
        cand_score = 0.0
        if isinstance(candidate, dict) and candidate:
            cand_row = {"first_snapshot": candidate, "last_snapshot": candidate, "saved_at": time.time()}
            cand_score = _internal_watch_row_priority(cand_row)
            try:
                sustain = classify_money_sustain_for_row(candidate)
                if str(sustain.get("watch_priority", "")) == "high":
                    cand_score += 0.75
            except Exception:
                pass
        active_len = len(active or {}) if isinstance(active, dict) else 0
        strong_cut = safe_float(globals().get("INTERNAL_WATCH_PRIORITY_STRONG_CANDIDATE", 6.20), 6.20)
        if active_len >= base and cand_score >= strong_cut:
            return burst
        if active_len > base:
            return burst
        return base
    except Exception:
        return int(safe_float(globals().get("INTERNAL_WATCH_TRACK_MAX_ACTIVE", 14), 14))

def is_rank_watch_low_price_tick_noise_v237(row: dict) -> bool:
    """v2.5.237: SHIB류 저가 한두 틱 착시는 내부감시 슬롯까지 먹지 않게 분리한다."""
    try:
        row = row if isinstance(row, dict) else {}
        if bool(row.get("rank_tick_noise_block", False)) or bool(row.get("ultra_low_tick_noise_block", False)) or is_realtime_rank_tick_noise(row):
            return True
        price = safe_float(row.get("price", row.get("current_price", row.get("snapshot_price", 0))), 0)
        if price <= 0 or price > 0.02:
            return False
        tick = estimate_bithumb_low_price_tick_unit_v227(price)
        tick_pct = (tick / price) * 100.0 if price > 0 and tick > 0 else 0.0
        if tick_pct < 0.45:
            return False
        ch1 = safe_float(row.get("change_1", 0), 0)
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        from_low = safe_float(row.get("from_low", row.get("from_30m_low_pct", 0)), 0)
        strongest = max(abs(ch1), abs(ch3), abs(ch5), abs(from_low))
        est_ticks = max(
            estimate_move_ticks_v227(price, ch1),
            estimate_move_ticks_v227(price, ch3),
            estimate_move_ticks_v227(price, ch5),
            estimate_move_ticks_v227(price, from_low),
        )
        # 한두 틱 착시: 3분/15분은 커 보이는데 5분 지속성이 없거나 실제 이동 틱 수가 작다.
        if est_ticks <= 2.5 and strongest <= max(1.35, tick_pct * 1.45) and (abs(ch5) <= 0.15 or abs(ch3 - ch5) >= tick_pct * 0.65 or abs(ch15 - ch5) >= tick_pct * 0.65):
            return True
        # v2.5.243: SHIB처럼 5분까지 같은 한두 틱 상승률이 유지되면 기존 조건을 피할 수 있다.
        # 체결이 얇고 현재봉이 실제로 커지지 않았다면 내부감시 active 슬롯까지 먹지 않게 복기 쪽으로 둔다.
        try:
            cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
            amount60 = safe_float(row.get("ws_trade_amount_60s", 0), 0)
            current_chg = abs(safe_float(row.get("current_candle_change_pct", 0), 0))
            if est_ticks <= 2.5 and strongest <= max(1.55, tick_pct * 1.65) and cnt < 4 and amount60 < 500_000 and current_chg <= 0.05:
                return True
        except Exception:
            pass
        return False
    except Exception:
        return False


def _make_internal_watch_slot_for_candidate(candidate: dict, now_ts: float = None) -> bool:
    """v2.5.237: 내부감시가 꽉 찼을 때 약한 기존 후보를 회수하고 강한 신규 후보에게 자리를 만든다."""
    try:
        now_ts = safe_float(now_ts, time.time())
        candidate = candidate if isinstance(candidate, dict) else {}
        active, logs = _get_internal_watch_state_parts()
        cleanup_internal_watch_track_state(now_ts, persist=False)
        active, logs = _get_internal_watch_state_parts()
        cand_row = {"first_snapshot": candidate, "last_snapshot": candidate, "saved_at": now_ts}
        cand_prio = _internal_watch_row_priority(cand_row)
        max_active = get_internal_watch_dynamic_max_active(candidate, active)
        if len(active) < max_active:
            return True
        ordered = sorted([(ticker, row, _internal_watch_row_priority(row)) for ticker, row in active.items() if isinstance(row, dict)], key=lambda x: x[2])
        if not ordered:
            return True
        weakest_ticker, weakest_row, weakest_prio = ordered[0]
        margin = safe_float(globals().get("INTERNAL_WATCH_SLOT_REPLACE_MIN_MARGIN", 0.35), 0.35)
        if cand_prio >= weakest_prio + margin:
            weakest_row["closed_reason"] = f"강한 신규 후보로 내부감시 슬롯 교체({str(candidate.get('ticker','?'))})"
            weakest_row["closed_at"] = now_ts
            weakest_row["closed_priority"] = round(weakest_prio, 3)
            weakest_row["replace_candidate_priority"] = round(cand_prio, 3)
            append_internal_watch_log(logs, weakest_row)
            active.pop(weakest_ticker, None)
            internal_watch_track_state["active"] = active
            internal_watch_track_state["logs"] = dedupe_internal_watch_logs(logs)[-INTERNAL_WATCH_TRACK_MAX_LOGS:]
            return True
        try:
            candidate["internal_watch_skip_reason"] = f"내부감시 슬롯 부족 / 신규우선순위 {cand_prio:.2f} <= 최저 {weakest_prio:.2f}"
        except Exception:
            pass
        return False
    except Exception:
        return False

def realtime_rank_watch_action_label_with_tracking(row: dict) -> str:
    """순위권 문구를 실제 내부감시 등록 상태와 맞춘다."""
    try:
        row = row if isinstance(row, dict) else {}
        base = realtime_rank_watch_action_label(row)
        if base != "정밀검토 대기":
            return base
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if ticker and ticker in _active_internal_watch_tickers():
            return "내부감시 등록됨"
        allow, reason = should_allow_internal_watch_by_money(row)
        if not allow:
            return f"등록 보류({reason})"
        try:
            active_count = len(_active_internal_watch_tickers())
            active_dict, _logs = _get_internal_watch_state_parts()
            max_active = get_internal_watch_dynamic_max_active(row, active_dict)
            if active_count >= max_active:
                return f"등록 보류(내부감시 {active_count}개 진행 중 / 약한 후보와 교체 대기)"
        except Exception:
            pass
        return "정밀검토 대기"
    except Exception:
        return realtime_rank_watch_action_label(row)


def _maybe_register_rank_precision_rows_from_snapshot(rows: list, now_ts: float = None):
    """명령어 캐시 생산자 쪽에서 순위권 정밀검토 후보를 내부감시에 연결한다.

    v2.5.237: 장이 활발할 때 원본 100개+ 전체를 정밀등록 검사하면 register_rank_precision이
    30초 이상 먹었다. 넓은 순위 기록은 유지하되, 내부감시 등록 시도는 상위/검증 가능 후보로 제한한다.
    """
    if not bool(globals().get("COMMAND_SNAPSHOT_REGISTER_RANK_WATCH_ON", True)):
        return
    now_ts = safe_float(now_ts, time.time())
    try:
        cleanup_internal_watch_track_state(now_ts, persist=False)
        active = _active_internal_watch_tickers()
        active_dict, _logs = _get_internal_watch_state_parts()
        max_active = get_internal_watch_dynamic_max_active(active=active_dict)
        max_n = int(safe_float(globals().get("COMMAND_SNAPSHOT_REGISTER_RANK_WATCH_MAX", 4), 4))
        process_limit = int(safe_float(globals().get("COMMAND_RANK_PRECISION_PROCESS_LIMIT", 28), 28))
        max_unverified = int(safe_float(globals().get("COMMAND_RANK_PRECISION_MAX_UNVERIFIED", 4), 4))
        tried = 0
        unverified_tried = 0
        source = [x for x in list(rows or []) if isinstance(x, dict)]
        source.sort(key=lambda x: (safe_float(x.get("snapshot_rank_score", 0), 0), _row_strongest_rank_move(x)), reverse=True)
        for row in source[:max(1, process_limit)]:
            if tried >= max_n:
                break
            ticker = str(row.get("ticker", "") or "").upper().strip()
            if not ticker or ticker in active:
                continue
            if bool(row.get("rank_tick_noise_block", False)) or bool(row.get("ultra_low_tick_noise_block", False)) or is_rank_watch_low_price_tick_noise_v237(row):
                continue
            if not (bool(row.get("rank_precision_watch", False)) or is_realtime_rank_precision_candidate(row)):
                continue
            money_code = money_status_code_for_row(row)
            # 대금 확인 지연 후보가 수십 개 쌓이면 정밀등록 단계가 병목이 된다.
            # 완전히 버리지는 않고 복기/순위에는 남기되, 내부감시 등록 시도만 제한한다.
            if money_code in {"checking", "delayed", "verify_failed", "unknown", "suspect"}:
                if unverified_tried >= max_unverified:
                    continue
                if safe_float(row.get("snapshot_rank_score", 0), 0) < 5.8 and _row_strongest_rank_move(row) < 1.20:
                    continue
                unverified_tried += 1
            watch = dict(row)
            watch["rank_precision_watch"] = True
            if len(active) >= max_active and not _make_internal_watch_slot_for_candidate(watch, now_ts=now_ts):
                continue
            ok = register_rank_precision_internal_watch(watch, now_ts=now_ts, reason="snapshot_producer_rank_precision")
            tried += 1
            if ok:
                active.add(ticker)
    except Exception as e:
        try:
            append_runtime_event_log("rank_precision_register_worker_error", "순위권 정밀검토 내부감시 연결 오류", extra={"error": str(e)[:160]})
        except Exception:
            pass


def _record_get_price_caller(caller: str, result: str = "call"):
    try:
        caller = str(caller or "unknown")[:80]
        result = str(result or "call")[:40]
        now_ts = time.time()
        with GET_PRICE_CALLER_STATS_LOCK:
            row = GET_PRICE_CALLER_STATS.get(caller)
            if not isinstance(row, dict):
                row = {"count": 0, "timeout": 0, "none": 0, "exception": 0, "last_ts": 0.0}
            row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
            if result in {"timeout", "none", "exception"}:
                row[result] = int(safe_float(row.get(result, 0), 0)) + 1
            row["last_ts"] = now_ts
            GET_PRICE_CALLER_STATS[caller] = row
            if len(GET_PRICE_CALLER_STATS) > GET_PRICE_CALLER_STAT_MAX:
                old = sorted(GET_PRICE_CALLER_STATS.items(), key=lambda kv: safe_float(kv[1].get("last_ts", 0), 0))
                for k, _v in old[:max(1, len(old) - GET_PRICE_CALLER_STAT_MAX)]:
                    GET_PRICE_CALLER_STATS.pop(k, None)
    except Exception:
        pass


def get_price_caller_stats_text(limit: int = 6) -> str:
    try:
        with GET_PRICE_CALLER_STATS_LOCK:
            rows = [(k, dict(v)) for k, v in GET_PRICE_CALLER_STATS.items() if isinstance(v, dict)]
        if not rows:
            return "- 가격조회 호출자: 아직 기록 없음"
        rows.sort(key=lambda kv: (safe_float(kv[1].get("timeout", 0), 0), safe_float(kv[1].get("count", 0), 0)), reverse=True)
        parts = []
        for caller, row in rows[:max(1, int(limit))]:
            parts.append(f"{caller} {int(safe_float(row.get('count',0),0))}회/timeout {int(safe_float(row.get('timeout',0),0))}")
        return "- 가격조회 호출자: " + ", ".join(parts)
    except Exception:
        return "- 가격조회 호출자: 확인 실패"




def ohlcv_reason_label(reason) -> str:
    """OHLCV 실패 원인을 사용자가 바로 읽을 수 있게 짧게 번역한다."""
    r = str(reason or "").lower().strip()
    table = {
        "api_timeout": "API timeout",
        "timeout": "API timeout",
        "exception": "예외/응답오류",
        "empty": "빈 응답",
        "empty_response": "빈 응답",
        "cooldown": "쿨다운",
        "circuit_break": "회로차단",
        "api_busy": "API 바쁨",
    }
    return table.get(r, str(reason or "원인미상"))

def build_scan_health_summary_line(display: dict = None, cache_age=None, api: dict = None, now_ts: float = None) -> str:
    """v2.5.242: /scan_health의 '전체 판단'을 실제 함수로 고정한다.

    이전에는 globals()에 함수가 있으면 쓰는 식이라, 기능이 있는 것처럼 보이지만
    실제 정의가 없으면 항상 '상태 확인중'으로 떨어지는 유령 경로였다.
    새 API/OHLCV 호출 없이 이미 만든 display/cache/api 값만 읽는다.
    """
    try:
        now_ts = time.time() if now_ts is None else safe_float(now_ts, time.time())
        display = display if isinstance(display, dict) else {}
        api = api if isinstance(api, dict) else {}
        candidate_age = display.get("age_sec")
        candidate_age = safe_float(candidate_age, -1) if candidate_age is not None else -1
        cache_age_v = safe_float(cache_age, -1) if cache_age is not None else -1
        loop_age = max(0.0, now_ts - safe_float(last_main_loop_heartbeat_ts, 0)) if safe_float(last_main_loop_heartbeat_ts, 0) > 0 else -1
        worker_age = max(0.0, now_ts - safe_float(COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS, 0)) if safe_float(COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS, 0) > 0 else -1

        if loop_age < 0 and cache_age_v < 0 and candidate_age < 0:
            return "시작 직후 준비중"
        if loop_age >= safe_float(globals().get("SCAN_HEARTBEAT_HARD_RESTART_SEC", 360), 360):
            return f"메인루프 멈춤 의심 / {int(loop_age)}초 전"
        if loop_age >= safe_float(globals().get("SCAN_HEARTBEAT_WARN_SEC", 120), 120):
            return f"메인루프 지연 주의 / {int(loop_age)}초 전"

        api_inflight = int(safe_float(api.get("api_inflight", 0), 0))
        api_timeout = int(safe_float(api.get("api_timeout_count", 0), 0))
        api_busy = int(safe_float(api.get("api_rejected_count", 0), 0))
        if api_inflight >= int(safe_float(globals().get("API_CALL_MAX_CONCURRENT", 4), 4)):
            return "API 동시호출 포화 / 스캔 지연 가능"
        if api_timeout > 0 or api_busy > 0:
            last_slow = str(api.get("api_last_slow_name", "") or api.get("api_last_reject_name", "") or "").strip()
            return "API 병목 흔적 있음" + (f" / 최근 {last_slow}" if last_slow else "")

        cache_warn = safe_float(globals().get("SCAN_CACHE_WARN_SEC", 60), 60)
        command_warn = safe_float(globals().get("COMMAND_DISPLAY_WARN_AGE_SEC", 45.0), 45.0)
        if cache_age_v >= 0 and candidate_age >= 0:
            if cache_age_v > cache_warn and candidate_age <= command_warn:
                return "시장 데이터 갱신 지연 / 출력 후보는 있음"
            if cache_age_v <= cache_warn and candidate_age > command_warn:
                return "출력 후보 스냅샷 지연 / 시장 데이터는 살아있음"
            if cache_age_v > cache_warn and candidate_age > command_warn:
                return "시장 데이터와 후보 출력 둘 다 오래됨"
            return "정상 / 시장 데이터와 출력 후보 모두 최신권"

        if cache_age_v >= 0:
            return "시장 데이터는 있음 / 후보 출력 확인중"
        if candidate_age >= 0:
            return "후보 출력은 있음 / 시장 데이터 나이 확인중"
        if worker_age >= 0 and worker_age > 30:
            return f"명령어 캐시 워커 지연 가능 / {int(worker_age)}초 전"
        return "상태 확인중"
    except Exception as e:
        return f"판단 생성 실패: {str(e)[:60]}"


def build_scan_health_cached_text() -> str:
    """명령어용 스캔진단 스냅샷. 새 API/OHLCV를 직접 호출하지 않는다."""
    try:
        now_ts = time.time()
        display = get_latest_scan_display_state(now_ts=now_ts, limit=3)
        fast = display.get('fast') if isinstance(display.get('fast'), dict) else {}
        api = get_api_bottleneck_snapshot()
        cache_age = get_market_cache_age_for_display(now_ts=now_ts, display=display)
        age_sec = display.get('age_sec')
        lines = [
            "🩺 스캔 상태 진단 /scan_health",
            f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S')}",
            "- 생성방식: 저장된 스냅샷 읽기전용 / 명령어에서 새 API 조회 안 함",
            f"- 전체 판단: {build_scan_health_summary_line(display=display, cache_age=cache_age, api=api, now_ts=now_ts)}",
            f"- 시장 데이터: {int(cache_age)}초 전" if cache_age is not None else "- 시장 데이터: 없음",
            f"- 마지막 후보 완성: {int(age_sec)}초 전" if age_sec is not None else "- 마지막 후보 완성: 없음",
            f"- 메인 루프: {format_elapsed_text(max(0, now_ts - safe_float(last_main_loop_heartbeat_ts, 0)))} 전 / 단계 {last_main_loop_stage}",
            f"- API 동시: {api.get('api_inflight', 0)}/{API_CALL_MAX_CONCURRENT} / timeout 누적 {api.get('api_timeout_count', 0)} / busy누적 {api.get('api_rejected_count', 0)}",
            f"- 마지막 느린 호출: {api.get('api_last_slow_name', '') or '-'}",
            f"- OHLCV 실패 활성/저장: {api.get('ohlcv_fail_state_active_count', 0)} / {api.get('ohlcv_fail_state_count', 0)}",
            "- 본선분리: minute240/day 실패는 표시만 하고 실시간 순위·내부감시는 계속 진행",
            get_price_caller_stats_text(limit=6),
            get_price_source_stats_text(limit=6),
            get_ohlcv_caller_stats_text(limit=5),
        ]
        try:
            cds = api.get("slow_prefetch_interval_cooldowns", {}) if isinstance(api, dict) else {}
            if isinstance(cds, dict) and cds:
                lines.append("- 상위봉 선조회 쿨다운: " + ", ".join([f"{k} {int(v)}초" for k, v in list(cds.items())[:4]]))
        except Exception:
            pass

        caller_top = api.get('api_caller_top') or []
        if caller_top:
            parts = []
            for k, row in caller_top[:5]:
                caller = str(row.get('caller', '') or '').strip()
                func = str(row.get('func', '') or '').strip()
                cnt = int(safe_float(row.get('count', 0), 0))
                tout = int(safe_float(row.get('timeout', 0), 0))
                slow = int(safe_float(row.get('slow', 0), 0))
                parts.append(f"{caller}->{func} {cnt}회/t{tout}/s{slow}")
            if parts:
                lines.append("- API 호출자: " + ", ".join(parts))
        reason_top = api.get('ohlcv_fail_reason_top') or []
        if reason_top:
            lines.append("- OHLCV 실패원인: " + ", ".join([f"{ohlcv_reason_label(k)} {v}건" for k, v in reason_top[:4]]))
        ticker_top = api.get('ohlcv_fail_ticker_top') or []
        if ticker_top:
            lines.append("- 실패 많은 코인: " + ", ".join([f"{k} {v}건" for k, v in ticker_top[:4]]))
        lines += [
            "",
            "[원칙]",
            "- timeout이 보이면 가벼운 모드로 덮지 말고 호출자/경로를 먼저 확인",
            "- 웹소켓 도입 전 REST/스냅샷 백업 구조가 단독으로도 버티게 고친다",
        ]
        return "\n".join(lines)
    except Exception as e:
        return f"🩺 스캔 상태 진단 /scan_health\n- 캐시 생성 오류: {e}"


