def _command_cache_missing_notice(key: str, prefix: str = "") -> str:
    stale = get_command_display_cache(key, allow_stale=True)
    lines = []
    if prefix:
        lines.append(str(prefix).strip())
    title_map = {"work_check": "⚡ /work_check", "review_watch": "🧪 /review_watch", "rank_short": "📊 /rank_short"}
    lines.append(f"{title_map.get(str(key), '/' + str(key))} 캐시 준비 안 됨")
    if stale:
        age = int(safe_float(stale.get("age_sec", 0), 0))
        lines.append(f"- 상태: 캐시가 {age}초 전 값이라 너무 오래됨")
    else:
        lines.append("- 상태: 아직 미리 정리된 캐시가 없음")
    if str(key) in set(globals().get("COMMAND_INSTANT_SNAPSHOT_KEYS", set()) or set()):
        lines += [
            "- 조치: 이 명령어는 원래 실시간 내부 스냅샷을 바로 읽어야 함",
            "- 즉시조회까지 실패한 상태라 /cache_status와 /errorlog 확인 필요",
        ]
    else:
        lines += [
            "- 조치: 직접계산은 막아둬서 명령어가 2~4분 멈추지 않게 했음",
            "- 5~10초 뒤 다시 확인하거나 /cache_status로 캐시 워커 상태를 봐줘",
        ]
    if COMMAND_DISPLAY_CACHE_LAST_ERROR:
        lines.append(f"- 마지막 캐시 오류: {COMMAND_DISPLAY_CACHE_LAST_ERROR}")
    return "\n".join([x for x in lines if str(x).strip()])


def build_cache_status_text() -> str:
    now_ts = time.time()
    names = [("work_check", "/work_check"), ("review_watch", "/review_watch"), ("rank_short", "/rank_short"), ("scan_health", "/scan_health"), ("rank_watch", "/rank_watch"), ("review_pack", "/review_pack"), ("review_dump", "/review_dump"), ("check", "/check")]
    complete_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_COMPLETE_TS', 0), 0) or safe_float(COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS, 0)
    complete_gen = globals().get('COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION', 0) or COMMAND_DISPLAY_CACHE_GENERATION
    fast_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_FAST_TS', 0), 0)
    long_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_LONG_TS', 0), 0)
    fast_text = (format_elapsed_text(now_ts - fast_ts) + " 전") if fast_ts > 0 else "아직 없음"
    long_text = (format_elapsed_text(now_ts - long_ts) + " 전") if long_ts > 0 else "아직 없음"
    fallback_text = "켜짐" if bool(globals().get('COMMAND_DISPLAY_DIRECT_BUILD_FALLBACK_ON', False)) else "꺼짐"
    worker_text = "새 캐시 생성 중" if bool(COMMAND_DISPLAY_CACHE_WORKER_BUILDING) else "대기/휴식"
    mode_text = "읽기전용" if bool(globals().get('COMMAND_DISPLAY_READONLY_BUILDING', False)) else "대기"
    lines = [
        "🧊 명령어 캐시 상태 /cache_status",
        f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S')}",
        f"- 직접계산 fallback: {fallback_text}",
        f"- 마지막 완성 캐시: {format_elapsed_text(now_ts - complete_ts)} 전 / 묶음#{complete_gen}" if complete_ts else "- 마지막 완성 캐시: 아직 없음",
        f"- 워커 heartbeat: {format_elapsed_text(now_ts - COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS)} 전" if COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS else "- 워커 heartbeat: 아직 없음",
        f"- 워커 상태: {worker_text}",
        f"- 현재 빌드 단계: {globals().get('COMMAND_DISPLAY_CACHE_BUILD_STAGE', '대기')}",
        f"- 캐시 생성 모드: {mode_text}",
        f"- 성공/실패: {COMMAND_DISPLAY_CACHE_DONE}회 / {COMMAND_DISPLAY_CACHE_FAIL}회",
        f"- 캐시 분리: 빠른캐시 {fast_text} / 긴캐시 {long_text}",
        f"- 즉시조회: {'켜짐' if bool(globals().get('COMMAND_INSTANT_SNAPSHOT_ON', True)) else '꺼짐'} / 성공 {globals().get('COMMAND_INSTANT_SNAPSHOT_DONE', 0)}회 / 실패 {globals().get('COMMAND_INSTANT_SNAPSHOT_FAIL', 0)}회",
    ]

    try:
        stage_summary = str(globals().get('COMMAND_DISPLAY_CACHE_STAGE_LAST_SUMMARY', '') or '').strip()
        total_stage_sec = safe_float(globals().get('COMMAND_DISPLAY_CACHE_STAGE_LAST_TOTAL_SEC', 0), 0)
        if stage_summary:
            lines.append(f"- 최근 캐시 단계별 소요: 합계 {total_stage_sec:.2f}초 / {stage_summary}")
        current_round = globals().get('COMMAND_DISPLAY_CACHE_STAGE_TIMINGS', {}) or {}
        if bool(COMMAND_DISPLAY_CACHE_WORKER_BUILDING) and isinstance(current_round, dict) and current_round:
            slow_now = sorted(current_round.items(), key=lambda kv: safe_float(kv[1], 0), reverse=True)[:4]
            lines.append("- 이번 생성 누적: " + ", ".join([f"{k} {safe_float(v,0):.2f}초" for k, v in slow_now]))
    except Exception:
        pass

    try:
        inst_ts = safe_float(globals().get('COMMAND_INSTANT_SNAPSHOT_LAST_TS', 0), 0)
        if inst_ts > 0:
            lines.append(f"- 최근 즉시조회: /{globals().get('COMMAND_INSTANT_SNAPSHOT_LAST_KEY', '')} / {format_elapsed_text(now_ts - inst_ts)} 전 / {safe_float(globals().get('COMMAND_INSTANT_SNAPSHOT_LAST_DURATION_SEC', 0), 0):.2f}초")
        inst_err = str(globals().get('COMMAND_INSTANT_SNAPSHOT_LAST_ERROR', '') or '').strip()
        if inst_err:
            lines.append(f"- 최근 즉시조회 오류: {inst_err}")
        bulk_ts = safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS', 0), 0)
        if bulk_ts > 0:
            lines.append(f"- 실시간 순위 스냅샷: {format_elapsed_text(now_ts - bulk_ts)} 전 / 전체스윕 {int(safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT', 0), 0))}개")
        else:
            lines.append("- 실시간 순위 스냅샷: 아직 없음")
        try:
            lines.append(f"- rank 상태표: {globals().get('RANK_STATE_LAST_NOTE', '대기')} / 저장 {len(globals().get('RANK_STATE_BY_TICKER', {}) or {})}개")
            step_note = str(globals().get('RANK_SOURCE_STEP_LAST_NOTE', '') or '').strip()
            if step_note:
                lines.append(f"- rank 단계별 병목: {step_note}")
                lines.append(f"- rank 생성 카운터: 경량생성 {globals().get('RANK_SOURCE_LIGHT_CREATE_COUNT',0)} / 스킵 {globals().get('RANK_SOURCE_SKIPPED_COUNT',0)} / 정밀병합 {globals().get('RANK_SOURCE_PRECISION_MERGE_COUNT',0)} / 미계측 {safe_float(globals().get('RANK_SOURCE_STEP_UNMEASURED_SEC',0),0):.2f}s")
                try:
                    stage_round = globals().get('COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND', {}) if isinstance(globals().get('COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND', {}), dict) else {}
                    stage_rank = safe_float(stage_round.get('build_rank_source', 0), 0)
                    rank_total = safe_float((globals().get('RANK_SOURCE_STEP_LAST_TIMINGS', {}) or {}).get('total', 0), 0) if isinstance(globals().get('RANK_SOURCE_STEP_LAST_TIMINGS', {}), dict) else 0.0
                    gap = max(0.0, stage_rank - rank_total)
                    if stage_rank > 0 and rank_total > 0 and gap >= 1.0:
                        lines.append(f"- rank 계측차이: 캐시단계 {stage_rank:.2f}s / 순위함수 {rank_total:.2f}s / 외부대기·락·전후처리 {gap:.2f}s")
                except Exception:
                    pass
            q_len = len(globals().get('PRECISION_MINUTE1_QUEUE', []) or []) if isinstance(globals().get('PRECISION_MINUTE1_QUEUE', []), list) else 0
            state_len = len(globals().get('PRECISION_MINUTE1_STATE', {}) or {}) if isinstance(globals().get('PRECISION_MINUTE1_STATE', {}), dict) else 0
            circuit_left = int(_precision_minute1_global_cooldown_left()) if '_precision_minute1_global_cooldown_left' in globals() else 0
            circuit_txt = f" / REST쿨다운 {circuit_left}초" if circuit_left > 0 else ""
            lines.append(f"- 정밀 1분봉 큐: 대기 {q_len} / 저장 {state_len} / 성공 {globals().get('PRECISION_MINUTE1_DONE',0)} / 실패 {globals().get('PRECISION_MINUTE1_FAIL',0)} / 최근 {globals().get('PRECISION_MINUTE1_LAST_ITEM','') or '-'} {globals().get('PRECISION_MINUTE1_LAST_RESULT','-')}{circuit_txt}")
            try:
                rej = globals().get('PRECISION_MINUTE1_QUEUE_REJECT_REASONS', {}) if isinstance(globals().get('PRECISION_MINUTE1_QUEUE_REJECT_REASONS', {}), dict) else {}
                rej_text = ', '.join([f"{k} {v}" for k, v in sorted(rej.items(), key=lambda kv: kv[1], reverse=True)[:4]]) or '-'
                lines.append(f"- 정밀 1분봉 자격심사: 등록 {globals().get('PRECISION_MINUTE1_QUEUE_ACCEPT_COUNT',0)} / 거절 {globals().get('PRECISION_MINUTE1_QUEUE_REJECT_COUNT',0)} / 최근 {globals().get('PRECISION_MINUTE1_QUEUE_LAST_DECISION','-')} / 거절이유 {rej_text}")
                samples = globals().get('RANK_STATE_NEGATIVE_AGE_SAMPLES', []) if isinstance(globals().get('RANK_STATE_NEGATIVE_AGE_SAMPLES', []), list) else []
                if samples:
                    s0 = samples[-1] if isinstance(samples[-1], dict) else {}
                    kind = str(s0.get('kind', '') or '')
                    if kind == 'stale_build_clock':
                        lines.append(f"- rank 시간기준 참고: {s0.get('ticker','?')} build_now보다 row가 {abs(safe_float(s0.get('age',0),0)):.1f}초 최신 / source {s0.get('source','-')}")
                    else:
                        lines.append(f"- negative_age 샘플: {s0.get('ticker','?')} age {s0.get('age','?')} / now {s0.get('now_ts','?')} / updated {s0.get('updated_ts','?')} / source {s0.get('source','-')}")
            except Exception:
                pass
            lines.append("- 판단 기준: 출력캐시 오래됨+순위스냅샷 최신=출력 생성 문제 / 출력캐시 최신+순위스냅샷 오래됨=데이터 갱신 문제")
        except Exception:
            pass
    except Exception:
        pass
    if complete_ts:
        complete_age = now_ts - complete_ts
        lines.append(f"- 캐시 지연 판단: {cache_delay_status_text(complete_age, building=bool(COMMAND_DISPLAY_CACHE_WORKER_BUILDING))}")
    if COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS:
        lines.append(f"- rank 원본 스냅샷: {COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_NOTE or '-'} / {format_elapsed_text(now_ts - COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS)} 전")
    if COMMAND_DISPLAY_CACHE_LAST_BUILD_START_TS:
        if COMMAND_DISPLAY_CACHE_WORKER_BUILDING:
            build_age = now_ts - COMMAND_DISPLAY_CACHE_LAST_BUILD_START_TS
            warn_sec = safe_float(globals().get('COMMAND_DISPLAY_CACHE_BUILD_WARN_SEC', 20.0), 20.0)
            lines.append(f"- 현재 생성 경과: {format_elapsed_text(build_age)}" + (" / 참고: 완성 전까지는 마지막 완성 캐시를 보여줌" if build_age >= warn_sec else ""))
        elif COMMAND_DISPLAY_CACHE_LAST_BUILD_FINISH_TS:
            lines.append(f"- 마지막 생성 소요: {format_elapsed_text(COMMAND_DISPLAY_CACHE_LAST_BUILD_FINISH_TS - COMMAND_DISPLAY_CACHE_LAST_BUILD_START_TS)}")
    if COMMAND_DISPLAY_CACHE_LAST_ERROR:
        lines.append(f"- 마지막 오류: {COMMAND_DISPLAY_CACHE_LAST_ERROR}")
    try:
        api = get_api_bottleneck_snapshot()
        lines += [
            "",
            "🌐 API 병목",
            f"- API 동시: {api.get('api_inflight', 0)}/{API_CALL_MAX_CONCURRENT} / timeout 누적 {api.get('api_timeout_count', 0)} / busy누적 {api.get('api_rejected_count', 0)}",
            f"- 마지막 느린 호출: {api.get('api_last_slow_name', '') or '-'}",
            f"- OHLCV 실패 활성/저장: {api.get('ohlcv_fail_state_active_count', 0)} / {api.get('ohlcv_fail_state_count', 0)}",
        ]

        caller_top = api.get('api_caller_top') or []
        if caller_top:
            parts = []
            for k, row in caller_top[:5]:
                caller = str(row.get('caller', '') or '').strip()
                func = str(row.get('func', '') or '').strip()
                cnt = int(safe_float(row.get('count', 0), 0))
                tout = int(safe_float(row.get('timeout', 0), 0))
                slow = int(safe_float(row.get('slow', 0), 0))
                parts.append(f"{caller}->{func} {cnt}회/t{tout}/s{slow}")
            if parts:
                lines.append("- API 호출자: " + ", ".join(parts))
        reason_top = api.get('ohlcv_fail_reason_top') or []
        if reason_top:
            lines.append("- OHLCV 실패원인: " + ", ".join([f"{ohlcv_reason_label(k)} {v}건" for k, v in reason_top[:4]]))
        ticker_top = api.get('ohlcv_fail_ticker_top') or []
        if ticker_top:
            lines.append("- 실패 많은 코인: " + ", ".join([f"{k} {v}건" for k, v in ticker_top[:4]]))
        try:
            lines.append(get_ws_ticker_status_text())
        except Exception:
            pass
        try:
            lines.append(get_ws_trade_status_text())
        except Exception:
            pass
    except Exception:
        pass
    lines += ["", "📌 항목별"]
    max_age = safe_float(globals().get("COMMAND_DISPLAY_MAX_AGE_SEC", 90), 90)
    warn_age = safe_float(globals().get("COMMAND_DISPLAY_WARN_AGE_SEC", 45), 45)
    generations = []
    with COMMAND_DISPLAY_CACHE_LOCK:
        for key, label in names:
            row = COMMAND_DISPLAY_CACHE.get(key)
            if not isinstance(row, dict):
                lines.append(f"- {label}: 없음")
                continue
            created = safe_float(row.get("created_ts", 0), 0)
            age = int(max(0, now_ts - created)) if created > 0 else 0
            if age <= warn_age:
                status = "정상"
            elif age <= max_age:
                status = "완성본 참고" if bool(COMMAND_DISPLAY_CACHE_WORKER_BUILDING) else "주의"
            else:
                status = "오래됨"
            tickers = row.get("tickers") if isinstance(row.get("tickers"), list) else []
            text_len = len(str(row.get("text", "") or ""))
            gen = row.get("generation", "")
            if gen not in {"", None}:
                generations.append(gen)
            gen_text = f" / 묶음#{gen}" if gen not in {"", None} else ""
            lines.append(f"- {label}: {status} / {age}초 전 / 길이 {text_len}자 / 버튼후보 {len(tickers)}개{gen_text}")
    if generations:
        same = len(set(generations)) == 1
        if same:
            lines.append(f"- 묶음 동기화: 정상 / {','.join([str(x) for x in generations])}")
        else:
            lines.append(f"- 묶음 동기화: 빠른/긴 캐시 분리 사용 중 / {','.join([str(x) for x in generations])}")
    lines += [
        "",
        "운영 기준",
        "- work_check/review_watch/rank_short/scan_health/rank_watch/review_pack/review_dump는 캐시 없으면 직접계산하지 않음",
        "- batch도 같은 캐시 스냅샷을 읽기만 함",
        "- 긴 명령어는 새 API/OHLCV/전체 덤프 생성을 직접 하지 않음",
        f"- {BOT_VERSION} 기준 batch 경로도 scan_health/rank_watch/review_pack/review_dump 직접생성 금지",
    ]
    return "\n".join(lines)


def cache_status_command(update, context: CallbackContext):
    try:
        send_text_chunks(build_cache_status_text(), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        send(f"⚠️ cache_status 에러: {e}")


def _set_command_cache_build_stage(stage: str):
    """v2.5.234: 캐시 워커가 지금 어느 항목에서 막혔는지와 직전 단계 소요시간을 같이 남긴다."""
    global COMMAND_DISPLAY_CACHE_BUILD_STAGE, COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS
    global COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS, COMMAND_DISPLAY_CACHE_STAGE_TIMINGS
    global COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND, COMMAND_DISPLAY_CACHE_STAGE_LAST_TOTAL_SEC, COMMAND_DISPLAY_CACHE_STAGE_LAST_SUMMARY
    try:
        now_ts = time.time()
        prev = str(COMMAND_DISPLAY_CACHE_BUILD_STAGE or "대기")
        prev_started = safe_float(COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS, 0)
        if prev and prev != "대기" and prev_started > 0:
            elapsed = max(0.0, now_ts - prev_started)
            COMMAND_DISPLAY_CACHE_STAGE_TIMINGS[prev] = round(elapsed, 3)
        new_stage = str(stage or "대기")[:80]
        if new_stage == "대기":
            try:
                COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND = dict(COMMAND_DISPLAY_CACHE_STAGE_TIMINGS)
                COMMAND_DISPLAY_CACHE_STAGE_LAST_TOTAL_SEC = round(sum(safe_float(v, 0) for v in COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND.values()), 3)
                slow = sorted(COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND.items(), key=lambda kv: safe_float(kv[1], 0), reverse=True)[:5]
                COMMAND_DISPLAY_CACHE_STAGE_LAST_SUMMARY = ", ".join([f"{k} {safe_float(v,0):.2f}s" for k, v in slow])
            except Exception:
                pass
            COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS = 0.0
        else:
            COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS = now_ts
        COMMAND_DISPLAY_CACHE_BUILD_STAGE = new_stage
        COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS = now_ts
    except Exception:
        pass


def _reset_command_cache_stage_timing():
    global COMMAND_DISPLAY_CACHE_STAGE_TIMINGS, COMMAND_DISPLAY_CACHE_STAGE_LAST_SUMMARY
    global COMMAND_DISPLAY_CACHE_BUILD_STAGE, COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS
    try:
        COMMAND_DISPLAY_CACHE_STAGE_TIMINGS = {}
        COMMAND_DISPLAY_CACHE_BUILD_STAGE = "대기"
        COMMAND_DISPLAY_CACHE_BUILD_STAGE_STARTED_TS = 0.0
    except Exception:
        pass


def _mark_command_fast_cache_complete(generation: int = None):
    global COMMAND_DISPLAY_CACHE_LAST_FAST_TS, COMMAND_DISPLAY_CACHE_LAST_FAST_GENERATION
    try:
        COMMAND_DISPLAY_CACHE_LAST_FAST_TS = time.time()
        COMMAND_DISPLAY_CACHE_LAST_FAST_GENERATION = generation if generation is not None else globals().get("COMMAND_DISPLAY_CACHE_GENERATION", 0)
    except Exception:
        pass


def _mark_command_long_cache_complete(generation: int = None):
    global COMMAND_DISPLAY_CACHE_LAST_LONG_TS, COMMAND_DISPLAY_CACHE_LAST_LONG_GENERATION
    try:
        COMMAND_DISPLAY_CACHE_LAST_LONG_TS = time.time()
        COMMAND_DISPLAY_CACHE_LAST_LONG_GENERATION = generation if generation is not None else globals().get("COMMAND_DISPLAY_CACHE_GENERATION", 0)
    except Exception:
        pass


def build_command_display_cache_once():
    global COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS, COMMAND_DISPLAY_CACHE_DONE, COMMAND_DISPLAY_CACHE_FAIL, COMMAND_DISPLAY_CACHE_LAST_ERROR
    global COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS, COMMAND_DISPLAY_CACHE_WORKER_BUILDING, COMMAND_DISPLAY_CACHE_LAST_BUILD_START_TS, COMMAND_DISPLAY_CACHE_LAST_BUILD_FINISH_TS
    global COMMAND_DISPLAY_READONLY_BUILDING, COMMAND_DISPLAY_CACHE_ACTIVE_BUILD_GENERATION
    global COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS, COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_COUNT, COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_NOTE
    global COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS, COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_META
    global COMMAND_DISPLAY_LONG_CACHE_SKIP_COUNT
    now_ts = time.time()
    _reset_command_cache_stage_timing()
    COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS = now_ts
    COMMAND_DISPLAY_CACHE_WORKER_BUILDING = True
    COMMAND_DISPLAY_READONLY_BUILDING = True
    COMMAND_DISPLAY_CACHE_LAST_BUILD_START_TS = now_ts
    COMMAND_DISPLAY_CACHE_ACTIVE_BUILD_GENERATION = COMMAND_DISPLAY_CACHE_GENERATION + 1
    fast_saved = False
    try:
        _set_command_cache_build_stage("build_rank_source")
        rank_rows = []
        try:
            source_limit = max(30, min(int(safe_float(globals().get("REALTIME_RANK_WATCH_SOURCE_LIMIT", 140), 140)), int(safe_float(globals().get("COMMAND_DISPLAY_RANK_SOURCE_LIMIT", 80), 80))))
            rank_rows = get_light_snapshot_rank_rows(limit=source_limit, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
        except Exception as e:
            append_runtime_event_log("command_cache_rank_source_error", "순위 원본 생성 오류", extra={"error": str(e)[:160]})
            rank_rows = []
        try:
            _set_command_cache_build_stage("register_rank_precision")
            _maybe_register_rank_precision_rows_from_snapshot(rank_rows, now_ts=now_ts)
        except Exception as e:
            append_runtime_event_log("command_cache_rank_register_error", "순위권 내부감시 연결 오류", extra={"error": str(e)[:160]})

        _set_command_cache_build_stage("freeze_rank_rows")
        rank_rows = freeze_rank_rows_for_command_snapshot(rank_rows)
        rank_snapshot_meta = {
            "generation": COMMAND_DISPLAY_CACHE_ACTIVE_BUILD_GENERATION,
            "created_ts": now_ts,
            "rank_rows": len(rank_rows),
            "cache_split": "fast_long",
        }
        COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS = now_ts
        COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_COUNT = len(rank_rows)
        COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_NOTE = f"묶음#{COMMAND_DISPLAY_CACHE_ACTIVE_BUILD_GENERATION} / 원본 {len(rank_rows)}개"
        COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS = freeze_rank_rows_for_command_snapshot(rank_rows)
        COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_META = dict(rank_snapshot_meta)
        try:
            rank_tickers = [r.get("ticker") for r in rank_rows[:max(1, RANK_WATCH_SHORT_LIMIT)]]
        except Exception:
            rank_tickers = []

        # 빠른 캐시 먼저 저장: 긴 출력 병목이 있어도 기본 점검 명령은 최신 유지.
        _set_command_cache_build_stage("build_fast_rank_short")
        rank_text = build_rank_watch_short_text(limit=RANK_WATCH_SHORT_LIMIT, rank_rows_override=rank_rows, snapshot_meta=rank_snapshot_meta)
        _set_command_cache_build_stage("build_fast_scan_health")
        scan_health_text = build_scan_health_cached_text()
        _set_command_cache_build_stage("build_fast_review_watch")
        watch_text = build_review_watch_text(active_limit=REVIEW_WATCH_ACTIVE_LIMIT, done_limit=REVIEW_WATCH_DONE_LIMIT)
        try:
            watch_tickers = collect_review_watch_detail_tickers(limit=8)
        except Exception:
            watch_tickers = []
        _set_command_cache_build_stage("build_fast_work_check")
        work_text = build_work_check_text_from_cached_parts(rank_text_override=rank_text, watch_text_override=watch_text, scan_health_text_override=scan_health_text)
        try:
            work_tickers = list(dict.fromkeys((rank_tickers or []) + (watch_tickers or [])))[:10]
        except Exception:
            work_tickers = []

        _set_command_cache_build_stage("save_fast_cache")
        set_command_display_cache_bundle({
            "rank_short": {"text": rank_text, "tickers": rank_tickers[:8], "snapshot_meta": rank_snapshot_meta},
            "review_watch": {"text": watch_text, "tickers": watch_tickers[:10], "snapshot_meta": rank_snapshot_meta},
            "work_check": {"text": work_text, "tickers": work_tickers[:10], "snapshot_meta": rank_snapshot_meta},
            "scan_health": {"text": scan_health_text, "tickers": [], "snapshot_meta": rank_snapshot_meta},
        })
        fast_saved = True
        _mark_command_fast_cache_complete(COMMAND_DISPLAY_CACHE_GENERATION)
        COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS = time.time()
        COMMAND_DISPLAY_CACHE_LAST_ERROR = ""

        # 긴 캐시는 낮은 빈도와 시간 예산 안에서만 갱신. 실패해도 빠른 캐시는 실패 처리하지 않음.
        long_interval = max(10.0, safe_float(globals().get("COMMAND_DISPLAY_LONG_CACHE_INTERVAL_SEC", 30.0), 30.0))
        last_long = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_LONG_TS", 0), 0)
        if last_long > 0 and (time.time() - last_long) < long_interval:
            COMMAND_DISPLAY_LONG_CACHE_SKIP_COUNT += 1
            COMMAND_DISPLAY_CACHE_DONE += 1
            return

        long_started = time.time()
        budget = max(4.0, safe_float(globals().get("COMMAND_DISPLAY_LONG_BUILD_BUDGET_SEC", 10.0), 10.0))
        def _long_budget_left():
            return (time.time() - long_started) <= budget

        long_rows = {}
        try:
            _set_command_cache_build_stage("build_long_rank_watch")
            rank_limit = int(safe_float(globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 12), 12))
            rank_full_text = build_rank_watch_text(limit=rank_limit, rank_rows_override=rank_rows, snapshot_meta=rank_snapshot_meta)
            long_rows["rank_watch"] = {"text": rank_full_text, "tickers": [r.get("ticker") for r in rank_rows[:rank_limit]] if isinstance(rank_rows, list) else [], "snapshot_meta": rank_snapshot_meta}
            if not _long_budget_left():
                raise TimeoutError("long cache budget exceeded after rank_watch")

            _set_command_cache_build_stage("build_long_review_pack")
            review_pack_text = build_review_pack_cached_text(scan_health_text=scan_health_text, rank_text=rank_text, watch_text=watch_text)
            long_rows["review_pack"] = {"text": review_pack_text, "tickers": work_tickers[:10], "snapshot_meta": rank_snapshot_meta}
            long_rows["check"] = {"text": review_pack_text, "tickers": work_tickers[:10], "snapshot_meta": rank_snapshot_meta}
            if not _long_budget_left():
                raise TimeoutError("long cache budget exceeded after review_pack")

            _set_command_cache_build_stage("build_long_review_dump")
            review_dump_text = build_review_dump_cached_text(scan_health_text=scan_health_text, rank_text=rank_full_text, watch_text=watch_text)
            long_rows["review_dump"] = {"text": review_dump_text, "tickers": work_tickers[:10], "snapshot_meta": rank_snapshot_meta}

            _set_command_cache_build_stage("save_long_cache")
            set_command_display_cache_bundle(long_rows)
            _mark_command_long_cache_complete(COMMAND_DISPLAY_CACHE_GENERATION)
        except Exception as e:
            COMMAND_DISPLAY_CACHE_LAST_ERROR = f"long cache: {str(e)[:120]}"
            append_runtime_event_log("command_display_long_cache_error", "긴 명령어 캐시 생성 오류", extra={"stage": globals().get("COMMAND_DISPLAY_CACHE_BUILD_STAGE", ""), "error": str(e)[:160]})

        COMMAND_DISPLAY_CACHE_DONE += 1
    except Exception as e:
        COMMAND_DISPLAY_CACHE_FAIL += 1
        COMMAND_DISPLAY_CACHE_LAST_ERROR = str(e)[:160]
        append_runtime_event_log("command_display_cache_error", "명령어/진단 스냅샷 캐시 생성 오류", extra={"stage": globals().get("COMMAND_DISPLAY_CACHE_BUILD_STAGE", ""), "error": str(e)[:160], "fast_saved": fast_saved})
    finally:
        COMMAND_DISPLAY_CACHE_LAST_BUILD_FINISH_TS = time.time()
        COMMAND_DISPLAY_CACHE_WORKER_BUILDING = False
        COMMAND_DISPLAY_READONLY_BUILDING = False
        _set_command_cache_build_stage("대기")
        COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS = time.time()

def command_display_cache_worker_loop():

    global COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS
    time.sleep(1.2)
    while True:
        try:
            COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS = time.time()
            if bool(globals().get("COMMAND_DISPLAY_CACHE_ON", True)):
                build_command_display_cache_once()
        except Exception as e:
            append_runtime_event_log("command_display_cache_worker_error", "명령어 캐시 워커 오류", extra={"error": str(e)[:160]})
        COMMAND_DISPLAY_CACHE_WORKER_HEARTBEAT_TS = time.time()
        time.sleep(max(2.0, safe_float(globals().get("COMMAND_DISPLAY_REFRESH_SEC", 6.0), 6.0)))



def get_cached_rank_rows_for_instant(limit: int = None, max_age_sec: float = None) -> tuple[list, dict]:
    """v2.5.232: 즉시조회용 저장 rank rows 반환.

    중요: 여기서는 get_light_snapshot_rank_rows()를 호출하지 않는다.
    명령어가 눌릴 때 447개 현재가 스냅샷을 다시 훑으면 즉시조회가 아니라 재계산이 된다.
    """
    try:
        now_ts = time.time()
        max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("COMMAND_INSTANT_RANK_ROWS_MAX_AGE_SEC", 90.0), 90.0)
        ts = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS", 0), 0)
        rows = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
        if ts <= 0 or (now_ts - ts) > max(5.0, max_age_sec) or not isinstance(rows, list):
            return [], {}
        try:
            n = int(safe_float(limit, 0)) if limit is not None else len(rows)
        except Exception:
            n = len(rows)
        if n <= 0:
            n = len(rows)
        frozen = freeze_rank_rows_for_command_snapshot(rows, limit=n)
        meta = dict(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_META", {}) or {})
        if not meta:
            meta = {"created_ts": ts, "rank_rows": len(rows), "generation": globals().get("COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION", "")}
        return frozen, meta
    except Exception:
        return [], {}


def _build_instant_text_from_saved_snapshots(key: str, build_func):
    """v2.5.232: 평소 명령어는 저장된 스냅샷만 조립한다.

    rank_short/rank_watch/work_check가 get_light_snapshot_rank_rows()를 직접 호출하지 않게 하는 핵심 우회로다.
    """
    key = str(key or "")
    if key == "rank_short":
        rows, meta = get_cached_rank_rows_for_instant(limit=max(20, int(safe_float(globals().get("RANK_WATCH_SHORT_LIMIT", 8), 8))))
        if rows:
            return build_rank_watch_short_text(limit=globals().get("RANK_WATCH_SHORT_LIMIT", 8), rank_rows_override=rows, snapshot_meta=meta)
    if key == "rank_watch":
        rows, meta = get_cached_rank_rows_for_instant(limit=max(30, int(safe_float(globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 10), 10))))
        if rows:
            return build_rank_watch_text(limit=globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 10), rank_rows_override=rows, snapshot_meta=meta)
    if key == "work_check":
        rows, meta = get_cached_rank_rows_for_instant(limit=max(20, int(safe_float(globals().get("WORK_CHECK_RANK_LIMIT", 8), 8))))
        if rows:
            rank_text = build_rank_watch_short_text(limit=globals().get("WORK_CHECK_RANK_LIMIT", 8), rank_rows_override=rows, snapshot_meta=meta)
        else:
            rank_row = get_command_display_cache("rank_short", allow_stale=True)
            rank_text = str((rank_row or {}).get("text", "") or "")
        try:
            watch_text = build_review_watch_text(active_limit=globals().get("WORK_CHECK_WATCH_ACTIVE_LIMIT", 5), done_limit=2)
        except Exception:
            watch_row = get_command_display_cache("review_watch", allow_stale=True)
            watch_text = str((watch_row or {}).get("text", "") or "")
        return build_work_check_text_from_cached_parts(rank_text_override=rank_text, watch_text_override=watch_text)
    if key == "scan_health":
        try:
            return build_scan_health_cached_text()
        except Exception:
            return build_scan_health_text(compact=True)
    return build_func()

def _instant_snapshot_source_status_line(duration_sec: float = 0.0) -> str:
    try:
        now_ts = time.time()
        parts = []
        bulk_ts = safe_float(globals().get("LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS", 0), 0)
        if bulk_ts > 0:
            parts.append(f"순위스냅샷 {format_elapsed_text(now_ts - bulk_ts)} 전")
        else:
            parts.append("순위스냅샷 준비중")
        try:
            display = get_latest_scan_display_state(now_ts=now_ts, limit=1)
            age = display.get("age_sec") if isinstance(display, dict) else None
            if age is not None:
                parts.append(f"후보스냅샷 {int(safe_float(age, 0))}초 전")
        except Exception:
            pass
        if duration_sec > 0:
            parts.append(f"조회 {duration_sec:.2f}초")
        return "- 조회상태: 실시간 내부 스냅샷 직접표시 / " + " / ".join(parts)
    except Exception:
        return "- 조회상태: 실시간 내부 스냅샷 직접표시"


def _instant_snapshot_tickers_for_key(key: str, limit: int = 12) -> list:
    try:
        key = str(key or "")
        if key in {"rank_short", "rank_watch", "work_check"}:
            n = int(safe_float(limit, 12))
            rows, _meta = get_cached_rank_rows_for_instant(limit=max(n, 12))
            if not rows:
                row = get_command_display_cache("rank_short", allow_stale=True)
                cached = row.get("tickers") if isinstance(row, dict) and isinstance(row.get("tickers"), list) else []
                return [str(t or "").upper().strip() for t in cached[:n] if str(t or "").strip()]
            return [str(r.get("ticker", "") or "").upper().strip() for r in rows[:n] if str(r.get("ticker", "") or "").strip()]
        if key == "review_watch":
            return collect_review_watch_detail_tickers(limit=10)
    except Exception:
        return []
    return []


def build_instant_snapshot_command_text(key: str, build_func) -> tuple[str, list, float]:
    """v2.5.232: 평소 명령어 즉시조회 경로.

    명령어 출력 캐시가 오래됐거나 캐시 워커가 막혀도, 저장된 내부 스냅샷만 읽어 바로 보여준다.
    이 함수 안에서는 새 API/OHLCV/전체스윕을 만들지 않도록 COMMAND_DISPLAY_READONLY_BUILDING을 켠다.
    """
    global COMMAND_DISPLAY_READONLY_BUILDING, COMMAND_INSTANT_SNAPSHOT_DONE, COMMAND_INSTANT_SNAPSHOT_FAIL
    global COMMAND_INSTANT_SNAPSHOT_LAST_TS, COMMAND_INSTANT_SNAPSHOT_LAST_KEY, COMMAND_INSTANT_SNAPSHOT_LAST_DURATION_SEC, COMMAND_INSTANT_SNAPSHOT_LAST_ERROR
    started = time.time()
    prev_readonly = bool(globals().get("COMMAND_DISPLAY_READONLY_BUILDING", False))
    prev_stage = globals().get("COMMAND_DISPLAY_CACHE_BUILD_STAGE", "대기")
    key = str(key or "")
    try:
        COMMAND_DISPLAY_READONLY_BUILDING = True
        _set_command_cache_build_stage(f"instant_snapshot_{key}")
        text = str(_build_instant_text_from_saved_snapshots(key, build_func) or "").strip()
        duration = max(0.0, time.time() - started)
        if text:
            text += "\n" + _instant_snapshot_source_status_line(duration)
        else:
            text = _command_cache_missing_notice(key) + "\n" + _instant_snapshot_source_status_line(duration)
        tickers = _instant_snapshot_tickers_for_key(key, limit=12)
        COMMAND_INSTANT_SNAPSHOT_DONE += 1
        COMMAND_INSTANT_SNAPSHOT_LAST_TS = time.time()
        COMMAND_INSTANT_SNAPSHOT_LAST_KEY = key
        COMMAND_INSTANT_SNAPSHOT_LAST_DURATION_SEC = duration
        COMMAND_INSTANT_SNAPSHOT_LAST_ERROR = ""
        try:
            set_command_display_cache(key, text, tickers=tickers)
        except Exception:
            pass
        return text, tickers, duration
    except Exception as e:
        duration = max(0.0, time.time() - started)
        COMMAND_INSTANT_SNAPSHOT_FAIL += 1
        COMMAND_INSTANT_SNAPSHOT_LAST_TS = time.time()
        COMMAND_INSTANT_SNAPSHOT_LAST_KEY = key
        COMMAND_INSTANT_SNAPSHOT_LAST_DURATION_SEC = duration
        COMMAND_INSTANT_SNAPSHOT_LAST_ERROR = str(e)[:160]
        append_runtime_event_log("instant_snapshot_command_error", "즉시 스냅샷 명령어 생성 오류", extra={"key": key, "error": str(e)[:160]})
        raise
    finally:
        COMMAND_DISPLAY_READONLY_BUILDING = prev_readonly
        _set_command_cache_build_stage(prev_stage if prev_stage else "대기")


def _cached_command_should_use_snapshot_fallback_v246(key: str, text: str) -> bool:
    """v2.5.246: 시작 직후 긴캐시가 빈 초기 스냅샷이면 최신 rank rows로 대체한다."""
    try:
        key = str(key or "")
        body = str(text or "")
        if key not in {"rank_watch", "review_dump"}:
            return False
        rows = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
        if not isinstance(rows, list) or len(rows) <= 0:
            return False
        if "아직 순위감시 표본이 없어" in body:
            return True
        if key == "review_dump" and "📌 진행 중\n- 없음" in body and len(rows) >= 3:
            return True
        return False
    except Exception:
        return False

def send_cached_or_build_command(key: str, build_func, prefix: str = "", reply_markup=None, cache_keyboard: bool = True, limit: int = TG_MESSAGE_SOFT_LIMIT):
    """명령어 출력 공통 경로.

    v2.5.233 근본 수정:
    - 캐시가 정상/주의권이면 즉시조회보다 캐시 전송을 먼저 한다.
    - v2.5.231~232에서 캐시가 20~30초 전으로 정상인데도 instant_snapshot이 먼저 돌며
      /work_check가 100초 이상 걸린 원인을 차단한다.
    - 즉시조회는 캐시가 없거나 너무 오래됐을 때만 선택적으로 사용한다.
    - 직접 API/OHLCV 계산 fallback은 계속 금지한다.
    """
    key = str(key or "")
    try:
        row = get_command_display_cache(key)
        if row:
            text = _cached_command_text(row)
            if _cached_command_should_use_snapshot_fallback_v246(key, text):
                rows, meta = get_cached_rank_rows_for_instant(limit=max(30, int(safe_float(globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 12), 12))))
                if rows and key == "rank_watch":
                    text = build_rank_watch_text(limit=globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 12), rank_rows_override=rows, snapshot_meta=meta)
                    text += "\n- 참고: 긴캐시가 초기 빈 스냅샷이라 최신 rank rows로 대체 표시"
                    row["tickers"] = [str(r.get("ticker", "") or "").upper().strip() for r in rows[:12] if str(r.get("ticker", "") or "").strip()]
                elif rows and key == "review_dump":
                    rank_full_text = build_rank_watch_text(limit=globals().get("REALTIME_RANK_WATCH_COMMAND_LIMIT", 12), rank_rows_override=rows, snapshot_meta=meta)
                    text = build_review_dump_cached_text(scan_health_text=build_scan_health_cached_text(), rank_text=rank_full_text, watch_text=build_review_watch_text(active_limit=REVIEW_WATCH_ACTIVE_LIMIT, done_limit=REVIEW_WATCH_DONE_LIMIT))
                    text += "\n- 참고: 긴캐시가 초기 빈 스냅샷이라 최신 rank rows로 대체 표시"
                    row["tickers"] = [str(r.get("ticker", "") or "").upper().strip() for r in rows[:10] if str(r.get("ticker", "") or "").strip()]
            if cache_keyboard:
                cached_tickers = row.get("tickers") if isinstance(row.get("tickers"), list) else []
                reply_markup = build_detail_buttons_for_tickers(cached_tickers, max_buttons=12, per_row=2) or reply_markup
            send_text_chunks(text, prefix=prefix, reply_markup=reply_markup, limit=limit)
            return True
    except Exception as e:
        append_runtime_event_log("send_cached_first_error", "캐시 우선 전송 실패", extra={"key": key, "error": str(e)[:160]})

    instant_keys = set(globals().get("COMMAND_INSTANT_SNAPSHOT_KEYS", set()) or set())
    instant_on = bool(globals().get("COMMAND_INSTANT_SNAPSHOT_ON", False))
    stale_row = get_command_display_cache(key, allow_stale=True)
    stale_age = safe_float((stale_row or {}).get("age_sec", 9999), 9999) if stale_row else 9999
    can_try_instant = bool(
        instant_on
        and key in instant_keys
        and (not stale_row or stale_age > safe_float(globals().get("COMMAND_DISPLAY_MAX_AGE_SEC", 90), 90))
    )
    if can_try_instant:
        try:
            text, tickers, _duration = build_instant_snapshot_command_text(key, build_func)
            if cache_keyboard:
                reply_markup = build_detail_buttons_for_tickers(tickers, max_buttons=12, per_row=2) or reply_markup
            send_text_chunks(text, prefix=prefix, reply_markup=reply_markup, limit=limit)
            return True
        except Exception as e:
            try:
                if stale_row:
                    text = _cached_command_text(stale_row) + f"\n- 즉시조회 실패: {str(e)[:80]} / 마지막 캐시로 대체"
                    if cache_keyboard:
                        cached_tickers = stale_row.get("tickers") if isinstance(stale_row.get("tickers"), list) else []
                        reply_markup = build_detail_buttons_for_tickers(cached_tickers, max_buttons=12, per_row=2) or reply_markup
                    send_text_chunks(text, prefix=prefix, reply_markup=reply_markup, limit=limit)
                    return True
            except Exception:
                pass
            send_text_chunks(f"{_command_cache_title(key)} 즉시조회 실패\n- 오류: {str(e)[:120]}\n- 명령어가 새 API/OHLCV를 직접 때리지는 않음", prefix=prefix, limit=limit)
            return False

    if stale_row:
        try:
            text = _cached_command_text(stale_row)
            if cache_keyboard:
                cached_tickers = stale_row.get("tickers") if isinstance(stale_row.get("tickers"), list) else []
                reply_markup = build_detail_buttons_for_tickers(cached_tickers, max_buttons=12, per_row=2) or reply_markup
            send_text_chunks(text, prefix=prefix, reply_markup=reply_markup, limit=limit)
            return True
        except Exception:
            pass

    if bool(globals().get("COMMAND_DISPLAY_DIRECT_BUILD_FALLBACK_ON", False)):
        text = build_func()
        send_text_chunks(text, prefix=prefix, reply_markup=reply_markup, limit=limit)
        return False
    send_text_chunks(_command_cache_missing_notice(key, prefix=prefix), limit=limit)
    return False

def work_check_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    try:
        # v2.5.206: 명령어 handler에서는 버튼 후보 수집도 하지 않는다. 캐시 안에 저장된 버튼 후보만 사용.
        send_cached_or_build_command("work_check", build_work_check_text, prefix='', reply_markup=None, cache_keyboard=True, limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        send(f"⚠️ work_check 에러: {e}")


def build_review_dump_no_scan_check_section() -> str:
    return "\n".join([
        "🧯 [명령어 no-scan 점검]",
        "- 기준: /status, /scan_debug, /review_dump, /recent5는 시장 전체 새 스캔을 직접 돌리지 않고 저장된 최신 스냅샷/기록만 읽는 구조를 유지해야 함",
        "- 현재 점검: get_latest_scan_display_state 기반 소비자 구조 유지. 이 함수는 저장된 fast-scan 상태를 읽고 shortlist만 분류함",
        "- /missed는 저장된 missed/alert 기록을 읽는 복기용. 새 전체 시장 스캔 버튼으로 쓰지 않음",
        "- 예외: 현재가 확인 버튼, 내부감시 10분/30분 추적, 실제 매수/매도는 단건 가격 조회가 필요함",
        "- 운영 기준: 명령어는 조회창, 내부 루프가 생산자. 명령어를 눌러 스캔 병목을 만들지 않는 방향 유지",
    ])

def _review_dump_promotion_timing_text(item: dict) -> str:
    item = item if isinstance(item, dict) else {}
    bucket = str(item.get('alert_bucket', item.get('bucket', '')) or '')
    grade = str(item.get('alert_grade', item.get('user_alert_grade', item.get('grade', '')) ) or '').upper().strip()
    primary = str(item.get('primary_reason', '') or '')
    decay_reason = str(item.get('user_alert_block_reason_detail', '') or '').strip() or get_user_alert_momentum_decay_reason(item, section='live')
    if decay_reason:
        return f"사용자 알림 보류가 맞음 / 이유: {decay_reason}"
    chg15 = safe_float(item.get('change_15', 0), 0)
    chg30 = safe_float(item.get('change_30', 0), 0)
    chg60 = safe_float(item.get('change_60', 0), 0)
    from_low = safe_float(item.get('from_low', 0), 0)
    if chg60 >= 3.0 and (chg15 < 0 or chg30 < 0.10):
        return "1시간 흐름은 있으나 15/30분 지속성 약함. 내부 감시 후 재가속 확인 필요"
    if bucket == 'user_alert' or grade in {'S', 'A'}:
        return "사용자 알림 후보. 알림 직전 15/30분 유지와 고점 재접근 여부 확인 필요"
    if '실시간' in primary or '급등' in primary:
        if from_low >= 5.0:
            return "실시간 강세 후보지만 저점대비 이미 진행됨. 추격 위험 같이 확인"
        return "실시간 강세 감시 후보. 다음 봉에서 돈 유지·고점 재접근 확인"
    if bucket in {'internal_watch', 'pre_entry'}:
        return "내부 감시 유지. 바로 알림보다 다음 봉 지속성 확인"
    if bucket == 'discard':
        return "현재는 버림/기록 쪽. 오른다면 왜 놓쳤는지 복기 표본으로 확인"
    return "검증 필요"

def format_review_dump_saved_chart_detail(item: dict, idx: int = 1, group_label: str = "후보") -> str:
    """review_dump 전용: 새 API 조회 없이 저장된 차트 정교화 수치만 최대한 펼쳐 보여준다."""
    item = dict(item) if isinstance(item, dict) else {}
    if not item:
        return f"{idx}. 데이터 없는 후보"
    ticker = str(item.get("ticker", "?") or "?").upper()
    reasons = item.get("reasons", []) if isinstance(item.get("reasons", []), list) else []
    reason_text = " / ".join([str(x).strip() for x in reasons if str(x).strip()][:8]) or "-"
    snap = item.get("pre_alert_snapshot") if isinstance(item.get("pre_alert_snapshot"), dict) else {}
    flags = []
    for key, label in [
        ("ultra_low_tick_noise_block", "초저가틱잡음"),
        ("flash_low_liquidity_near_high_block", "고점앞반짝"),
        ("low_actual_turnover_flag", "실제돈작음"),
        ("late_high_volatility_block", "늦은고점권흔들림"),
        ("near_high_rebreakout_watch", "재돌파대기"),
    ]:
        if bool(item.get(key, False)):
            flags.append(label)
    near_type = str(item.get("near_high_quality_type", "") or "").strip()
    if near_type:
        flags.append(f"고점근처분류={near_type}")
    ctx = item.get("alert_chart_context") if isinstance(item.get("alert_chart_context"), dict) else {}
    ctx_bits = []
    if ctx:
        if ctx.get("chart_state") or ctx.get("chart_state_code"):
            ctx_bits.append(f"상태 {ctx.get('chart_state','-')}({ctx.get('chart_state_code','-')})")
        if ctx.get("chart_warning"):
            ctx_bits.append(f"주의 {ctx.get('chart_warning')}")
        if safe_float(ctx.get("recent_pullback_pct", 0), 0):
            ctx_bits.append(f"직전고점뒤밀림 {safe_float(ctx.get('recent_pullback_pct',0),0):.2f}%")
        if ctx.get("htf_trend") or ctx.get("htf_trend_code"):
            ctx_bits.append(f"4시간흐름 {ctx.get('htf_trend','-')}({ctx.get('htf_trend_code','-')})")
    lines = [
        f"{circled_number(idx)} {ticker_review_icon(item)} {ticker} / {group_label}",
        f"- 분류: bucket {item.get('alert_bucket', item.get('bucket','-'))} / 등급 {item.get('alert_grade', item.get('grade','-'))} / 표시라벨 {item.get('user_label_text', item.get('label_text','후보'))} / primary {item.get('primary_reason','-')}",
        f"- 경로: 유입 {item.get('candidate_source', item.get('source','fast_scan'))} / 판단 {item.get('decision_path', '-')} / 정밀 {item.get('precision_stage', '-')}",
        f"- 분석단계: {_review_dump_analysis_stage_text(item)}" + (f" / 상세출처 {item.get('_detail_augmented_from')}" if item.get('_detail_augmented_from') else ""),
        f"- 한줄판단: {str(item.get('one_liner', item.get('judgement_text','')) or '-').strip()}",
        f"💰 현재가/점수: 현재 {fmt_price(item.get('price', item.get('current_price', 0)))} / lite {safe_float(item.get('lite_score',0),0):.2f} / section {safe_float(item.get('section_rank',0),0):.2f} / bucket {safe_float(item.get('bucket_rank',0),0):.2f} / rescue {safe_float(item.get('rescue_score',0),0):.2f}",
        f"📈 흐름: 1분 {safe_float(item.get('change_1',0),0):+.2f}% / 3분 {safe_float(item.get('change_3',0),0):+.2f}% / 5분 {safe_float(item.get('change_5',0),0):+.2f}% / 15분 {safe_float(item.get('change_15',0),0):+.2f}% / 30분 {safe_float(item.get('change_30',0),0):+.2f}% / 60분 {safe_float(item.get('change_60',0),0):+.2f}%",
        f"💸 돈/주도: 거래량 {safe_float(item.get('vol_ratio',0),0):.2f}배 / 시장주목 {safe_float(item.get('leader_score',0),0):.2f} / 최근5분거래대금 {format_money_for_row(item)} / 1분 {format_money_or_unknown(item.get('turnover_recent_1m',0), snapshot_based=bool(item.get('turnover_unknown_snapshot', False)))} / 3분 {format_money_or_unknown(item.get('turnover_recent_3m',0), snapshot_based=bool(item.get('turnover_unknown_snapshot', False)))} / 체결 {format_ws_trade_signal_for_row(item)}",
        f"📍 위치: 30분저점대비 {safe_float(item.get('from_low', item.get('from_30m_low_pct',0)),0):+.2f}% / 최근30분고점거리 {_rd_gap_or_pending(item.get('below_high', item.get('below_30m_high_pct',999)))} / 단기고점거리 {_rd_gap_or_pending(item.get('rebreakout_gap_pct', item.get('high_gap_pct',999)))} / RSI {safe_float(item.get('rsi',0),0):.2f}",
    ]
    life_line = format_chart_lifecycle_line(item)
    if life_line:
        lines.append(life_line)
    gap_line = format_gap_context_line(item)
    if gap_line:
        lines.append(gap_line)
    price30 = format_recent_30m_price_context(snap if snap else item, current_price=safe_float(item.get('price', item.get('current_price',0)),0), prefix='- 최근30분 기준값')
    if price30:
        lines.append(price30)
    for line in [format_recent_60m_price_context(item), format_recent_4h_price_context(item), format_daily_price_context(item)]:
        if line:
            lines.append(line)

    detail_cnt = _review_dump_meaningful_chart_field_count(item)
    if detail_cnt < 3:
        lines.append("- 정밀 차트수치: 아직 미계산/미저장. 아래 0값을 억지로 펼치지 않고, 현재 저장된 1차 감시 수치만 표시함")
        strengths = _scan_candidate_strength_texts(item)
        risks = _scan_candidate_risk_texts(item)
        if strengths:
            lines.append(f"✅ 좋은 점 전체: {' / '.join(strengths)}")
        if risks:
            lines.append(f"⚠️ 아쉬운 점 전체: {' / '.join(risks)}")
        if flags:
            lines.append(f"🚧 차단/주의 플래그: {' / '.join(flags)}")
        lines.append(f"🧠 내부 이유: {reason_text}")
        lines.append(f"🎯 우리 목표 체크: {_review_dump_target_fit_text(item)}")
        lines.append(f"🚦 승격/보류 체크: {_review_dump_promotion_timing_text(item)}")
        return "\n".join([x for x in lines if str(x).strip()])

    lines.extend([
        f"🧭 차트정교화 요약: {item.get('chart_quant_label','차트 수치 확인중')}",
        f"🕯 캔들 힘: 몸통 1봉 {_rd_pct_ratio(item.get('candle_body_ratio_1',0))} / 3봉 {_rd_pct_ratio(item.get('candle_body_ratio_3',0))} / 5봉 {_rd_pct_ratio(item.get('candle_body_ratio_5',0))} | 종가강도 1봉 {_rd_pct_ratio(item.get('close_position_ratio_1',0))} / 3봉 {_rd_pct_ratio(item.get('close_position_ratio_3',0))} / 5봉 {_rd_pct_ratio(item.get('close_position_ratio_5',0))}",
        f"🧱 꼬리/양봉: 윗꼬리 1봉 {_rd_pct(item.get('upper_wick_pct_1',0))} / 3봉 {_rd_pct(item.get('upper_wick_pct_3',0))} / 5봉 {_rd_pct(item.get('upper_wick_pct_5',0))} | 아랫꼬리 1봉 {_rd_pct(item.get('lower_wick_pct_1',0))} / 3봉 {_rd_pct(item.get('lower_wick_pct_3',0))} / 5봉 {_rd_pct(item.get('lower_wick_pct_5',0))} | 연속양봉 {int(safe_float(item.get('bullish_streak_5',0),0))} / 연속음봉 {int(safe_float(item.get('bearish_streak_5',0),0))} / 강한양봉 {int(safe_float(item.get('strong_bullish_count_5',0),0))}개",
        f"🔄 눌림/회복/압축: 눌림 {safe_float(item.get('pullback_pct_18',0),0):.2f}% → 회복 {safe_float(item.get('recovery_from_low_pct',0),0):.2f}% / 회복속도 {safe_float(item.get('recovery_speed_pct',0),0):.2f}/봉 / 눌림기간 {int(safe_float(item.get('pullback_duration_bars',0),0))}봉 / 압축 {safe_float(item.get('compression_score',0),0):.2f} / 박스 6봉 {safe_float(item.get('box_range_pct_6',0),0):.2f}%·18봉 {safe_float(item.get('box_range_pct_18',0),0):.2f}%",
        f"🛡 저점방어/돈유지: {item.get('low_structure_summary_v2', item.get('low_defense_v2_label','저점 구조 확인중'))} / 점수 {safe_float(item.get('low_defense_v2_score', item.get('low_zone_defense_score',0)),0):.2f} / 재확인 {int(safe_float(item.get('low_retest_count_v2', item.get('low_zone_reclaim_count',0)),0))}회 / 저점근처 {int(safe_float(item.get('low_near_stay_bars_v2', item.get('low_zone_stay_bars',0)),0))}봉 / 저점높임 {item.get('low_rising_label_v2','확인중')} / 회복질 {safe_float(item.get('recovery_quality_score',0),0):.2f} / 돈유지 {safe_float(item.get('turnover_persistence_score',0),0):.2f} / 3v10 {safe_float(item.get('turnover_sustain_ratio_3v10',0),0):.2f} / 5v20 {safe_float(item.get('turnover_sustain_ratio_5v20',0),0):.2f} / 유지봉 5분 {int(safe_float(item.get('turnover_keep_bars_5',0),0))}·10분 {int(safe_float(item.get('turnover_keep_bars_10',0),0))} / 반짝점수 {safe_float(item.get('turnover_flash_score',0),0):.2f}({format_turnover_flash_label(item.get('turnover_flash_score',0))})",
        f"🎯 고점/재돌파: 상단체류 {int(safe_float(item.get('hold_near_high_bars',0),0))}봉 / 0.5%내 {int(safe_float(item.get('hold_near_high_bars_05',0),0))}봉 / 1.0%내 {int(safe_float(item.get('hold_near_high_bars_10',0),0))}봉 / 유지점수 {safe_float(item.get('breakout_hold_score',0),0):.2f} / 재돌파 {format_rebreakout_stat_text(item)}",
        f"⏳ 고점 전 준비도: 라벨 {str(item.get('prebreakout_label','') or format_prebreakout_simple_label(item))} / 점수 {safe_float(item.get('prebreakout_ready_score',0),0):.2f} / 고점아래체류 {int(safe_float(item.get('prebreakout_hold_near_high_bars',0),0))}봉 / 눌림깊이 {safe_float(item.get('prebreakout_pullback_depth_pct',0),0):.2f}% / 재접근간격 {int(safe_float(item.get('prebreakout_retest_gap_bars',999),999))}봉 / 직전거래량재가속 {safe_float(item.get('prebreakout_volume_reaccel_score',0),0):.2f}",
        f"🕓 상위봉 4시간: {item.get('htf_setup_label','4시간 확인중')} / 위치 {item.get('htf_box_position_label','-')} / 고점거리 {_rd_gap_or_pending(item.get('htf_gap_pct',999))} / 저점대비 {safe_float(item.get('htf_rise_pct',0),0):.2f}% / 저점높임3봉 {bool(item.get('htf_higher_low_3', False))}",
        f"📅 상위봉 일봉: {item.get('daily_setup_label','일봉 확인중')} / 위치 {item.get('daily_box_position_label','-')} / 고점거리 {_rd_gap_or_pending(item.get('daily_gap_pct',999))} / 저점대비 {safe_float(item.get('daily_rise_pct',0),0):.2f}% / 반등일차 {int(safe_float(item.get('daily_rebound_day',0),0))} / 준비점수 {safe_float(item.get('daily_ready_score',0),0):.2f}",
        format_chart_lifecycle_line(item),
        f"🧭 차트상태: {' / '.join(ctx_bits) if ctx_bits else '저장된 alert_chart_context 없음'}",
        f"✅ 좋은 점 전체: {' / '.join(_scan_candidate_strength_texts(item)) if _scan_candidate_strength_texts(item) else '-'}",
        f"⚠️ 아쉬운 점 전체: {' / '.join(_scan_candidate_risk_texts(item)) if _scan_candidate_risk_texts(item) else '-'}",
    ])
    if flags:
        lines.append(f"🚧 차단/주의 플래그: {' / '.join(flags)}")
    lines.append(f"🧠 내부 이유: {reason_text}")
    lines.append(f"🎯 우리 목표 체크: {_review_dump_target_fit_text(item)}")
    lines.append(f"🚦 승격/보류 체크: {_review_dump_promotion_timing_text(item)}")
    return "\n".join([x for x in lines if str(x).strip()])

def build_review_dump_current_candidates_detail(scan_display_at_start=None, limit_each: int = 8, detail_index: dict = None) -> str:
    display = scan_display_at_start if isinstance(scan_display_at_start, dict) else get_latest_scan_display_state(now_ts=time.time(), limit=max(limit_each, 8))
    note = format_scan_display_state_line(display)
    raw_user_items = list(display.get('user_items') or [])
    raw_internal_items = list(display.get('internal_items') or [])
    raw_discard_items = list(display.get('discard_items') or [])
    shortlist = list(display.get('shortlist') or [])
    # v2.5.172: 표시 섹션과 내부 bucket이 엇갈리면 분석이 꼬인다.
    # 최종 섹션은 alert_bucket 기준으로 다시 정리한다.
    seen_tickers = set()
    merged_items = []
    for _it in raw_user_items + raw_internal_items + raw_discard_items:
        if not isinstance(_it, dict):
            continue
        _tk = str(_it.get('ticker', '') or '').upper().strip()
        _key = _tk or str(id(_it))
        if _key in seen_tickers:
            continue
        seen_tickers.add(_key)
        merged_items.append(_it)
    user_items = [x for x in merged_items if str(x.get('alert_bucket', '') or '') == 'user_alert']
    internal_items = [x for x in merged_items if str(x.get('alert_bucket', '') or '') in {'internal_watch', 'pre_entry'}]
    discard_items = [x for x in merged_items if str(x.get('alert_bucket', '') or '') not in {'user_alert', 'internal_watch', 'pre_entry'}]
    detail_index = detail_index if isinstance(detail_index, dict) else build_review_dump_rich_detail_index(scan_display_at_start)
    lines = ["🔎 [현재 후보 상세 / 차트 정교화 전체 표시]"]
    if note:
        lines.append(f"- 기준: {note}")
    lines.append("- 목적: 일반 알림은 짧게, review_dump는 차트 정교화 수치와 차단/승격 이유를 최대한 자세히 남김")
    lines.append(f"- 개수: 바로 볼 후보 {len(user_items)}개 / 조금 더 볼 후보 {len(internal_items)}개 / 내부에서 넘긴 후보 {len(discard_items)}개 / shortlist {len(shortlist)}개")
    if not user_items and not internal_items and not discard_items and not shortlist:
        lines.append("- 현재 저장된 후보 없음")
        return "\n".join(lines)
    def append_group(title: str, rows, group_label: str, max_rows: int):
        if not rows:
            return
        lines.append("")
        lines.append(title)
        for i, item in enumerate(rows[:max_rows], start=1):
            lines.append("")
            ticker = str(item.get('ticker','') or '').upper()
            rich = detail_index.get(ticker) if ticker else None
            if rich and _review_dump_detail_score(rich) > _review_dump_detail_score(item):
                item = _review_dump_merge_latest_with_rich(item, rich)
            lines.append(format_review_dump_saved_chart_detail(item, idx=i, group_label=group_label))
    append_group("🌱 [바로 볼 후보 상세]", user_items, "바로 볼 후보", limit_each)
    append_group("👀 [내부 감시/미리보기 후보 상세]", internal_items, "내부 감시/미리보기 후보", limit_each)
    append_group("🙈 [내부 기록/버림 후보 상세]", discard_items, "내부 기록/버림 후보", limit_each)
    if not user_items and not internal_items and shortlist:
        append_group("📌 [상위 shortlist 상세]", shortlist, "shortlist", limit_each)
    return "\n".join(lines)

def _reverse_trace_reason_bucket(row: dict) -> str:
    """역추적 중복 묶음용 큰 이유 분류.

    v2.5.172: 가격/거리 수치가 조금 달라져도 같은 문제는 한 묶음으로 본다.
    """
    try:
        txt = " / ".join([
            str(row.get('reason', '') or ''),
            str(row.get('primary_reason', '') or ''),
            str(row.get('chart_quant_label', '') or ''),
            str(row.get('quality_block_reason', '') or ''),
        ])
        checks = [
            ("고점", "고점 가까움/추격위험"),
            ("5분", "5분 힘 약함"),
            ("거래대금", "실제돈/거래대금 약함"),
            ("거래량", "거래량 약함"),
            ("정밀분석 전", "정밀분석 전"),
            ("데이터", "데이터 실패/미확인"),
            ("늦", "늦은 자리"),
            ("구경만", "구경만 후보"),
        ]
        for key, label in checks:
            if key in txt:
                return label
        return str(row.get('primary_reason', row.get('label_text', '기타')) or '기타')[:30]
    except Exception:
        return '기타'

def _reverse_trace_group_key(row: dict):
    try:
        ticker = str(row.get('ticker', '') or '').upper().strip()
        bucket = str(row.get('bucket', '') or '')
        primary = str(row.get('primary_reason', row.get('label_text', '')) or '')
        final = str(row.get('final_judgement', row.get('judgement', '')) or '')
        return ticker, bucket, primary, final, _reverse_trace_reason_bucket(row)
    except Exception:
        return ('?', '', '', '', '')

def build_review_dump_trace_grouped_section(trace_limit: int = REVIEW_DUMP_TRACE_DISPLAY_LIMIT, raw_window: int = 160, hide_noise: bool = False) -> str:
    """review_dump용 역추적: 중복 원본을 묶어서 채팅 폭주를 막는다."""
    load_reverse_trace_logs()
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        return "[최근 역추적]\n- 아직 역추적 표본이 없어"
    raw_rows = rows[-max(1, int(raw_window)): ]
    groups = {}
    for row in raw_rows:
        key = _reverse_trace_group_key(row)
        if key not in groups:
            groups[key] = {"rows": [], "latest": row}
        groups[key]["rows"].append(row)
        groups[key]["latest"] = row
    ordered = sorted(groups.values(), key=lambda g: safe_float(g.get('latest', {}).get('ts', 0), 0), reverse=True)
    hidden_noise_groups = [g for g in ordered if hide_noise and is_review_trace_tiny_noise(g.get('latest') or {})]
    display_ordered = [g for g in ordered if not (hide_noise and is_review_trace_tiny_noise(g.get('latest') or {}))]
    shown = display_ordered[:max(1, int(trace_limit))]
    lines = [
        f"🧭 [최근 역추적 중복정리 {len(shown)}/{len(ordered)}묶음]",
        f"- 원본 저장 {len(rows)}건 / 최근 원본 {len(raw_rows)}건을 코인·판정·이유 기준으로 묶음" + (f" / 잡음숨김 {len(hidden_noise_groups)}개" if hidden_noise_groups else ""),
        "- 중간 상세: /review_trace / 원본 페이지: /review_trace_full",
    ]
    for idx, g in enumerate(shown, start=1):
        rs = g.get('rows') or []
        latest = dict(g.get('latest') or {})
        repeat = len(rs)
        if repeat > 1:
            latest['reason'] = str(latest.get('reason', '') or '') + f" / 반복 {repeat}회"
        lines += ["", format_reverse_trace_block(latest, idx=idx)]
        if repeat > 1:
            try:
                first_ts = format_reverse_trace_ts(safe_float(rs[0].get('ts', 0), 0))
                last_ts = format_reverse_trace_ts(safe_float(rs[-1].get('ts', 0), 0))
                lines.append(f"- 반복요약: {repeat}회 반복 / 첫 {first_ts} → 마지막 {last_ts}")
            except Exception:
                pass
    return "\n".join(lines)

def build_review_trace_grouped_text(limit: int = REVIEW_TRACE_GROUPED_DISPLAY_LIMIT, raw_window: int = 220) -> str:
    load_reverse_trace_logs()
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        return "🧭 review_trace\n- 아직 역추적 기록이 없어"
    return "🧭 review_trace\n" + build_review_dump_trace_grouped_section(trace_limit=max(1, int(limit)), raw_window=max(1, int(raw_window)), hide_noise=True)

def review_trace_command(update, context: CallbackContext):
    try:
        limit = REVIEW_TRACE_GROUPED_DISPLAY_LIMIT
        if getattr(context, 'args', None):
            try:
                limit = max(1, min(int(context.args[0]), 50))
            except Exception:
                limit = REVIEW_TRACE_GROUPED_DISPLAY_LIMIT
        send_text_chunks(build_review_trace_grouped_text(limit=limit), prefix="")
    except Exception as e:
        send(f"⚠️ review_trace 에러: {e}")

def _review_trace_total_pages(page_size: int = REVIEW_TRACE_FULL_PAGE_SIZE) -> tuple:
    """review_trace 원본 페이지 수 계산."""
    load_reverse_trace_logs()
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    page_size = max(10, min(int(page_size), REVIEW_TRACE_FULL_PAGE_SIZE))
    total = len(rows)
    total_pages = max(1, (total + page_size - 1) // page_size)
    return total, total_pages, page_size


def build_review_trace_full_keyboard(page: int = 0, total_pages: int = None):
    """원본 역추적 페이지를 눌러서 볼 수 있게 하는 버튼."""
    try:
        if total_pages is None:
            _total, total_pages, _page_size = _review_trace_total_pages()
        total_pages = max(1, int(total_pages))
        page = max(0, int(page or 0))
        rows = []
        if page <= 0:
            first_row = [InlineKeyboardButton("1쪽 보기", callback_data="rv:full:1")]
            if total_pages >= 2:
                first_row.append(InlineKeyboardButton("2쪽", callback_data="rv:full:2"))
            if total_pages >= 3:
                first_row.append(InlineKeyboardButton("3쪽", callback_data="rv:full:3"))
            rows.append(first_row)
        else:
            nav = []
            if page > 1:
                nav.append(InlineKeyboardButton("◀ 이전", callback_data=f"rv:full:{page-1}"))
            nav.append(InlineKeyboardButton(f"{page}/{total_pages}쪽", callback_data=f"rv:full:{page}"))
            if page < total_pages:
                nav.append(InlineKeyboardButton("다음 ▶", callback_data=f"rv:full:{page+1}"))
            rows.append(nav)
        rows.append([InlineKeyboardButton("중복정리 보기", callback_data="rv:trace"), InlineKeyboardButton("압축팩", callback_data="rv:pack")])
        return InlineKeyboardMarkup(rows)
    except Exception:
        return None


def build_review_trace_full_text(page: int = 0, page_size: int = REVIEW_TRACE_FULL_PAGE_SIZE) -> str:
    """원본 역추적 페이지 조회. page=0이면 안내만 한다."""
    load_reverse_trace_logs()
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        return "🧭 review_trace_full\n- 아직 역추적 기록이 없어"
    page_size = max(10, min(int(page_size), REVIEW_TRACE_FULL_PAGE_SIZE))
    total = len(rows)
    total_pages = max(1, (total + page_size - 1) // page_size)
    if page is None or int(page) <= 0:
        lines = [
            "🧭 review_trace_full",
            f"- 원본 역추적 {total}건 저장됨",
            f"- 한 번에 전부 보내지 않고 {page_size}개씩 페이지로 보여줘",
            f"- 전체 페이지: {total_pages}쪽",
            "- 아래 버튼으로 1쪽부터 볼 수 있어",
            "- 버튼이 안 보이면 직접 명령어를 입력하면 됨",
            "",
            "직접 입력 예시:",
            "- /review_pack 또는 /review : 복붙용 핵심 요약",
            "- /review_trace_page 1 : 최신 원본 1쪽",
            "- /review_trace_page 2 : 다음 2쪽",
            "- /review_trace_detail RLC : 특정 코인 상세",
            "- /review_dump : 전체 분석용",
        ]
        return "\n".join(lines)
    page = max(1, min(int(page), total_pages))
    recent_desc = list(reversed(rows))
    start_idx = (page - 1) * page_size
    chunk = recent_desc[start_idx:start_idx + page_size]
    lines = [
        "🧭 review_trace_full",
        f"- 원본 역추적 {total}건 중 {page}/{total_pages}쪽",
        f"- 표시 범위: {start_idx + 1}~{start_idx + len(chunk)}번 / 페이지 크기 {page_size}개",
        "- 아래 버튼으로 이전/다음 쪽 이동 가능",
    ]
    for idx, row in enumerate(chunk, start=start_idx + 1):
        lines += ["", format_reverse_trace_block(row, idx=idx)]
    return "\n".join(lines)


def review_trace_full_command(update, context: CallbackContext):
    try:
        page = 0
        if getattr(context, 'args', None):
            try:
                page = int(context.args[0])
            except Exception:
                page = 0
        total, total_pages, _page_size = _review_trace_total_pages()
        keyboard = build_review_trace_full_keyboard(page=page, total_pages=total_pages) if total > 0 else None
        if page <= 0:
            send_text_chunks(build_reverse_trace_catalog(), prefix="", reply_markup=keyboard)
        else:
            send_text_chunks(build_review_trace_page_text(page=page), prefix="", reply_markup=keyboard)
    except Exception as e:
        send(f"⚠️ review_trace_full 에러: {e}")



def format_reverse_trace_catalog_line(row: dict, repeat: int = 1, idx: int = 1) -> str:
    try:
        ticker = str(row.get('ticker', '?') or '?').upper().strip()
        bucket = get_reverse_trace_bucket_display(row)
        primary = str(row.get('label_text', '') or '').strip() or get_fast_scan_label_text(str(row.get('primary_reason', '') or ''))
        chg5 = safe_float(row.get('change_5', 0), 0)
        chg30 = safe_float(row.get('change_30', 0), 0)
        from_low = safe_float(row.get('from_low', 0), 0)
        high_gap = safe_float(row.get('below_30m_high_pct', row.get('below_high', 999)), 999)
        money = get_fast_item_effective_turnover(row)
        reason = str(row.get('reason', '') or '').strip()
        reason_short = reason.split('/')[0].strip()[:30] if reason else '-'
        rep = f" / {repeat}회" if repeat > 1 else ""
        gap_text = format_pct_or_pending(high_gap, pending_text="확인 안 됨", zero_text="고점 근처")
        return f"{idx}. {ticker_review_icon(row)} {ticker}{rep} / {bucket} / {primary} / 5분 {chg5:+.2f}% / 30분 {chg30:+.2f}% / 저점+{from_low:.2f}% / 고점거리 {gap_text} / 돈 {format_money_for_row(row)} / {reason_short}"
    except Exception:
        return f"{idx}. ? / 요약 실패"

def build_reverse_trace_catalog(limit: int = REVIEW_TRACE_CATALOG_LIMIT, raw_window: int = 220) -> str:
    load_reverse_trace_logs()
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        return "🧭 review_trace_full\n- 아직 역추적 기록이 없어"
    raw_rows = rows[-max(1, int(raw_window)):]
    groups = {}
    for row in raw_rows:
        key = _reverse_trace_group_key(row)
        if key not in groups:
            groups[key] = {"rows": [], "latest": row}
        groups[key]["rows"].append(row)
        groups[key]["latest"] = row
    ordered = sorted(groups.values(), key=lambda g: safe_float(g.get('latest', {}).get('ts', 0), 0), reverse=True)
    hidden_noise_groups = [g for g in ordered if REVIEW_TRACE_HIDE_TINY_NOISE_ON and is_review_trace_tiny_noise(g.get('latest') or {})]
    display_ordered = [g for g in ordered if not (REVIEW_TRACE_HIDE_TINY_NOISE_ON and is_review_trace_tiny_noise(g.get('latest') or {}))]
    shown = display_ordered[:max(1, int(limit))]
    total, total_pages, page_size = _review_trace_total_pages(page_size=REVIEW_TRACE_PAGE_SIZE)
    lines = [
        "🧭 review_trace_full 목차",
        f"- 원본 {len(rows)}건 / 최근 묶음 {len(ordered)}개 / 기본목차 잡음숨김 {len(hidden_noise_groups)}개",
        f"- 원본은 {page_size}개씩 {total_pages}쪽으로 분리",
        "- 복붙 부담 줄이려고 실전성 있는 묶음만 먼저 보여줘",
        "",
        "필요할 때만 직접 입력:",
        "- /review_trace_detail RLC : 특정 코인 상세",
        "- /review_trace_page 1 : 원본 1쪽",
        "- /review_pack 또는 /review : 짧은 요약",
        "- 버튼이 안 보이면 위 명령어를 직접 입력",
        "",
        "[최근 주요 묶음]",
    ]
    if not shown:
        lines.append("- 실전성 있는 최근 묶음 없음")
        if hidden_noise_groups:
            samples = []
            for g in hidden_noise_groups[:REVIEW_TRACE_NOISE_SUMMARY_LIMIT]:
                r = g.get('latest') or {}
                samples.append(str(r.get('ticker', '?') or '?').upper())
            lines.append(f"- 거래대금 잡음 {len(hidden_noise_groups)}개 숨김" + (f" 예: {', '.join(samples)}" if samples else ""))
    for idx, g in enumerate(shown, start=1):
        latest = dict(g.get('latest') or {})
        repeat = len(g.get('rows') or [])
        lines.append(format_reverse_trace_catalog_line(latest, repeat=repeat, idx=idx))
    return "\n".join(lines)

def format_current_internal_watch_detail_for_ticker_v245(ticker: str) -> str:
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker:
            return ""
        active, logs = _get_internal_watch_state_parts()
        row = active.get(ticker) if isinstance(active, dict) else None
        if not isinstance(row, dict):
            return ""
        first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else {}
        last = row.get("last_snapshot") if isinstance(row.get("last_snapshot"), dict) else first
        try:
            first = apply_precision_minute1_state_to_row(dict(first)) if 'apply_precision_minute1_state_to_row' in globals() else dict(first)
            last = apply_precision_minute1_state_to_row(dict(last)) if 'apply_precision_minute1_state_to_row' in globals() else dict(last)
            first = apply_watch_display_consistency_v244(dict(first)) if 'apply_watch_display_consistency_v244' in globals() else dict(first)
            last = apply_watch_display_consistency_v244(dict(last)) if 'apply_watch_display_consistency_v244' in globals() else dict(last)
        except Exception:
            pass
        age = format_elapsed_text(max(0, time.time() - safe_float(row.get("saved_at", 0), 0)))
        results = row.get("results") if isinstance(row.get("results"), dict) else {}
        r10 = results.get("10m", {}).get("result_type", "대기") if isinstance(results.get("10m", {}), dict) else "대기"
        r30 = results.get("30m", {}).get("result_type", "대기") if isinstance(results.get("30m", {}), dict) else "대기"
        low_status = format_low_structure_status_v245(first) if 'format_low_structure_status_v245' in globals() else ""
        money = format_money_compact_for_row(first) if 'format_money_compact_for_row' in globals() else format_money_for_row(first)
        money_sustain = format_money_sustain_compact(first) if 'format_money_sustain_compact' in globals() else "돈흐름 확인중"
        state = str(first.get("chart_lifecycle_label", first.get("rank_watch_chart_state", first.get("primary_reason", "-"))) or "-")
        precision_note = str(first.get("precision_chart_note", "") or "")
        precision_age = safe_float(first.get("precision_chart_age_sec", 0), 0)
        high_hint = str(first.get("high_rebreakout_v248_label", "") or "")
        final_reason = format_final_candidate_reason_v251(first, prefix="사유") if 'format_final_candidate_reason_v251' in globals() else ""
        final_state = str(first.get("final_candidate_state_v251", "") or state)
        extra_lines = [
            "[현재 내부감시 상태]",
            f"- 진행 중 / 경과 {age} / 10분 {r10} / 30분 {r30}",
            f"- 기준 {fmt_price(row.get('base_price',0))} / 현재 {fmt_price(row.get('last_price',0))} / 최고 {safe_float(row.get('max_up_pct',0),0):+.2f}% / 현재 {safe_float(row.get('last_up_pct',0),0):+.2f}%",
            f"- 현재상태: {final_state} / {money} / 돈흐름 {money_sustain}" + (f" / 저점 {low_status}" if low_status else ""),
        ]
        if final_reason:
            extra_lines.append(f"- 최종판단 사유: {final_reason}")
        if precision_note:
            extra_lines.append(f"- 정밀1분봉: {precision_note}" + (f" / {precision_age:.0f}초 전" if precision_age > 0 else ""))
        if high_hint:
            extra_lines.append(f"- 고점재돌파: {high_hint} / 점수 {safe_float(first.get('high_rebreakout_v248_score',0),0):.2f}")
        if str(first.get("low_defense_block_reason_text_v248", "") or ""):
            extra_lines.append(f"- 저점방어 품질: 구조는 있지만 {first.get('low_defense_block_reason_text_v248')} 때문에 승격 금지")
        return "\n".join(extra_lines)
    except Exception:
        return ""

def build_review_trace_detail_text(ticker: str, limit: int = REVIEW_TRACE_DETAIL_RECENT_LIMIT) -> str:
    load_reverse_trace_logs()
    raw_query = str(ticker or '').strip()
    ticker, resolve_note = resolve_user_ticker_query(raw_query)
    ticker = str(ticker or '').upper().strip()
    if not ticker:
        return "🧭 review_trace_detail\n- 코인명을 같이 적어줘\n- 예: /review_trace_detail RLC"
    rows = [x for x in reverse_trace_logs if isinstance(x, dict) and str(x.get('ticker', '') or '').upper().strip() == ticker]
    if not rows:
        try:
            in_all_tickers = ticker in {str(x or '').upper().strip() for x in (market_all_tickers if isinstance(market_all_tickers, list) else [])}
        except Exception:
            in_all_tickers = False
        try:
            in_universe = any(str((x.get('ticker', '') if isinstance(x, dict) else x) or '').upper().strip() == ticker for x in (market_universe if isinstance(market_universe, list) else []))
        except Exception:
            in_universe = False
        try:
            in_cache = ticker in shared_market_cache if isinstance(shared_market_cache, dict) else False
        except Exception:
            in_cache = False
        try:
            with LIGHT_SNAPSHOT_LOCK:
                has_snapshot = ticker in LIGHT_SNAPSHOT_HISTORY
                snap_rows = len(LIGHT_SNAPSHOT_HISTORY.get(ticker, [])) if has_snapshot else 0
        except Exception:
            has_snapshot = False
            snap_rows = 0
        try:
            # 최신 전체현재가 캐시를 먼저 한 번 갱신해서, 티커는 있는데 스냅샷이 없는 코인도 바로 등록할 수 있게 한다.
            try:
                get_bulk_current_price_snapshot(force=False)
            except Exception:
                pass
            bulk_price = safe_float(LIGHT_SNAPSHOT_BULK_PRICE_CACHE.get(ticker, 0), 0) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else 0.0
        except Exception:
            bulk_price = 0.0
        seeded_now = False
        if (not has_snapshot) and bulk_price > 0:
            seeded_now = force_track_light_snapshot_ticker(ticker, price=bulk_price, reason="detail_no_snapshot")
            try:
                with LIGHT_SNAPSHOT_LOCK:
                    has_snapshot = ticker in LIGHT_SNAPSHOT_HISTORY
                    snap_rows = len(LIGHT_SNAPSHOT_HISTORY.get(ticker, [])) if has_snapshot else 0
            except Exception:
                pass
        metrics = compute_light_snapshot_metrics(ticker)
        snap_ready = isinstance(metrics, dict) and bool(metrics.get("snapshot_ready"))
        cause = "탐색풀에 아직 제대로 못 들어온 상태"
        if has_snapshot and not in_cache and not in_universe:
            cause = "현재가는 봤지만 유니버스/캐시에 못 들어옴"
        elif in_cache and not in_universe:
            cause = "캐시에는 있으나 정밀 후보 기록 없음"
        elif in_universe and not in_cache:
            cause = "유니버스에는 있으나 fast scan 캐시/정밀기록 없음"
        elif in_cache and in_universe:
            cause = "탐색에는 있었지만 역추적 저장 전 단계에서 빠짐"
        elif not in_all_tickers and not has_snapshot:
            cause = "티커 목록/현재가 스냅샷에 아직 안 잡힘"
        lines = [
            f"🧭 {ticker} 상세" + (f" ({resolve_note})" if resolve_note else ""),
            "- 역추적 기록이 아직 없어",
            "",
            "[누락 진단]",
            f"- 빗썸 티커목록 기록: {'있음' if in_all_tickers else '없음/미확인'}",
            f"- 유니버스 포함: {'있음' if in_universe else '없음'}",
            f"- 내부캐시 포함: {'있음' if in_cache else '없음'}",
            f"- 현재가 스냅샷: {'있음' if has_snapshot else '없음'} / 표본 {snap_rows}개",
            f"- 전체현재가 최신값: {fmt_price(bulk_price) if bulk_price > 0 else '없음/미확인'}",
        ]
        if resolve_note:
            lines.append(f"- 입력 매핑: {resolve_note}")
        if 'seeded_now' in locals() and seeded_now:
            lines.append("- 스냅샷 등록: 전체현재가 최신값으로 방금 감시 시작. 몇 분 뒤 흐름 계산이 더 정확해짐")
        saved_now = False
        score_now = 0.0
        strongest_now = 0.0
        if snap_ready:
            score_now = _snapshot_rank_score(metrics)
            strongest_now = max(
                safe_float(metrics.get('change_3', 0), 0),
                safe_float(metrics.get('change_5', 0), 0),
                safe_float(metrics.get('change_30', 0), 0),
                safe_float(metrics.get('change_60', 0), 0),
            )
            # v2.5.190: detail 조회에서 현재가 스냅샷 강세가 확인되면 그 자리에서 최소기록을 남긴다.
            if score_now >= safe_float(globals().get("REALTIME_RANK_DETAIL_FORCE_SCORE", 1.20), 1.20) or strongest_now >= safe_float(globals().get("REALTIME_RANK_DETAIL_FORCE_MOVE_PCT", 0.80), 0.80):
                row_for_trace = build_light_snapshot_rank_row_for_ticker(ticker, metrics=metrics)
                saved_now = bool(append_realtime_rank_min_trace(row_for_trace, item=None, now_ts=time.time(), force=True)) if row_for_trace else False
                if saved_now:
                    load_reverse_trace_logs()
                    rows = [x for x in reverse_trace_logs if isinstance(x, dict) and str(x.get('ticker', '') or '').upper().strip() == ticker]
                    if rows:
                        latest = rows[-1]
                        return "\n".join([
                            f"🧭 {ticker} 상세" + (f" ({resolve_note})" if resolve_note else ""),
                            f"- 아직 기록은 없었지만, 지금 순위권 움직임이 보여서 {realtime_rank_watch_action_label(latest)}로 새로 남겼어",
                            "",
                            "[저장된 최신 상세]",
                            format_reverse_trace_block(latest, idx=1),
                        ])
            lines += [
                f"- 스냅샷 흐름: 3분 {safe_float(metrics.get('change_3', 0), 0):+.2f}% / "
                f"5분 {safe_float(metrics.get('change_5', 0), 0):+.2f}% / "
                f"30분 {safe_float(metrics.get('change_30', 0), 0):+.2f}% / "
                f"1시간 {safe_float(metrics.get('change_60', 0), 0):+.2f}%",
                f"- 내부순위점수: {score_now:.2f}",
                f"- detail 자동기록: {'저장 완료' if saved_now else '저장 조건 미충족/최근 중복'}",
            ]
        else:
            lines.append("- 스냅샷 흐름: 표본 부족")
        lines += [
            f"- 추정 원인: {cause}",
            "- 다음 확인: /review_dump 의 🚨 [순위권 누락 의심] 섹션 확인",
        ]
        return "\n".join(lines)
    latest = rows[-1]
    first_ts = format_reverse_trace_ts(safe_float(rows[0].get('ts', 0), 0))
    last_ts = format_reverse_trace_ts(safe_float(rows[-1].get('ts', 0), 0))
    buckets = {}
    for r0 in rows:
        b = get_reverse_trace_bucket_display(r0)
        buckets[b] = buckets.get(b, 0) + 1
    bucket_text = ' / '.join([f"{k} {v}회" for k, v in sorted(buckets.items(), key=lambda kv: kv[1], reverse=True)[:4]])
    current_watch_detail = format_current_internal_watch_detail_for_ticker_v245(ticker) if 'format_current_internal_watch_detail_for_ticker_v245' in globals() else ""
    lines = [
        f"🧭 {ticker} 역추적 상세" + (f" ({resolve_note})" if resolve_note else ""),
        f"- 봇이 본 기록: {len(rows)}번 / 첫 포착 {first_ts} → 최근 {last_ts}",
        f"- 기록 종류: {bucket_text or '-'}",
        "- 정밀검토 대기: 순위권 강세라 내부 감시 후보로 한 번 더 보는 상태야. 바로 매수 신호는 아님",
        "- 복기용 기록: 나중에 놓침/승격 여부를 비교하려고 남긴 기록이야",
    ]
    if current_watch_detail:
        lines += ["", current_watch_detail]
    lines += [
        "",
        "[최신 상세]",
        format_reverse_trace_block(latest, idx=1),
    ]
    recent = list(reversed(rows[-max(1, int(limit)): -1]))
    if recent:
        lines += ["", f"[직전 흐름 {len(recent)}건 요약]"]
        for idx, row in enumerate(recent, start=1):
            lines.append(format_reverse_trace_catalog_line(row, repeat=1, idx=idx))
    return "\n".join(lines)

