def build_review_pack_text() -> str:
    now_ts = time.time()
    display = get_latest_scan_display_state(now_ts=now_ts, limit=8)
    user_items = list(display.get('user_items') or [])
    internal_items = list(display.get('internal_items') or [])
    discard_items = list(display.get('discard_items') or [])
    hidden_now_noise = [x for x in (user_items + internal_items + discard_items) if is_fast_scan_tiny_turnover_noise(x)]
    # 기본 복붙팩에서는 잡음 후보를 숨기고, 필요하면 review_dump/detail에서만 본다.
    user_items = [x for x in user_items if not is_fast_scan_tiny_turnover_noise(x)]
    internal_items = [x for x in internal_items if not is_fast_scan_tiny_turnover_noise(x)]
    discard_items = [x for x in discard_items if not is_fast_scan_tiny_turnover_noise(x)]
    note = format_scan_display_state_line(display)
    load_reverse_trace_logs()
    trace_rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    recent_trace = list(reversed(trace_rows[-80:]))
    seen = set()
    trace_compact = []
    hidden_trace_noise = 0
    for row in recent_trace:
        tk = str(row.get('ticker', '') or '').upper().strip()
        if not tk or tk in seen:
            continue
        if is_review_trace_tiny_noise(row):
            hidden_trace_noise += 1
            seen.add(tk)
            continue
        seen.add(tk)
        trace_compact.append(row)
        if len(trace_compact) >= REVIEW_PACK_TRACE_LIMIT:
            break
    try:
        health = build_scan_health_text(compact=True)
    except TypeError:
        health = build_scan_health_text()
    except Exception as e:
        health = f"스캔진단 생성 실패: {e}"
    lines = [
        "🧩 리뷰팩 — 복붙용 핵심 요약",
        f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S')}",
        f"- 스캔: {note}",
        f"- 후보: 바로 {len(user_items)} / 관찰 {len(internal_items)} / 내부기록 {len(discard_items)}" + (f" / 거래대금 잡음 숨김 {len(hidden_now_noise)}" if hidden_now_noise else ""),
        "- 이 내용만 보내도 기본 분석은 가능. 특정 코인이 궁금하면 아래 상세 명령만 추가로 보내면 됨",
        "",
        "🩺 [스캔 핵심]",
    ]
    for ln in str(health).splitlines()[:16]:
        if ln.strip():
            lines.append(ln)
    rows_now = user_items + internal_items + discard_items
    lines += ["", "📌 [현재 후보 압축]"]
    if not rows_now:
        lines.append("- 없음")
    else:
        for idx, it in enumerate(rows_now[:8], start=1):
            tk = str(it.get('ticker', '?') or '?').upper()
            bucket = get_fast_scan_bucket_text(it.get('alert_bucket', ''))
            grade = str(it.get('alert_grade', it.get('user_alert_grade', '-')) or '-')
            gap_text = format_pct_or_pending(it.get('below_high', it.get('below_30m_high_pct',999)), pending_text="확인 안 됨", zero_text="고점 근처")
            money_text = format_money_for_row(it)
            lines.append(f"{idx}. {ticker_review_icon(it)} {tk} / {bucket} / {grade} / 5분 {safe_float(it.get('change_5',0),0):+.2f}% / 30분 {safe_float(it.get('change_30',0),0):+.2f}% / 저점+{safe_float(it.get('from_low',0),0):.2f}% / 고점거리 {gap_text} / 돈 {money_text}")
    lines += ["", "🧭 [최근 역추적 압축]"]
    if hidden_trace_noise:
        lines.append(f"- 거래대금 잡음 {hidden_trace_noise}개 숨김")
    if not trace_compact:
        lines.append("- 실전성 있는 최근 역추적 없음")
    else:
        for idx, row in enumerate(trace_compact, start=1):
            lines.append(format_reverse_trace_catalog_line(row, repeat=1, idx=idx))
    lines += ["", "🧷 [추가로 필요할 때만]", "- 특정 코인 상세: /review_trace_detail 코인명", "- 원본 1/2/3쪽 버튼: /review_full", "- 전체 덤프: /review_dump"]
    return "\n".join(lines)

def collect_review_pack_detail_tickers(limit: int = 12) -> list:
    """review_pack/check에 붙일 상세 버튼 후보를 가볍게 모은다."""
    out = []
    seen = set()
    def add(tk):
        tk = str(tk or '').upper().strip()
        if tk and tk not in seen:
            seen.add(tk)
            out.append(tk)
    try:
        display = get_latest_scan_display_state(now_ts=time.time(), limit=8)
        rows_now = list(display.get('user_items') or []) + list(display.get('internal_items') or []) + list(display.get('discard_items') or [])
        for it in rows_now:
            if len(out) >= limit:
                break
            if isinstance(it, dict) and not is_fast_scan_tiny_turnover_noise(it):
                add(it.get('ticker'))
    except Exception:
        pass
    try:
        load_reverse_trace_logs()
        for row in reversed([x for x in reverse_trace_logs if isinstance(x, dict)][-120:]):
            if len(out) >= limit:
                break
            if is_review_trace_tiny_noise(row):
                continue
            add(row.get('ticker'))
    except Exception:
        pass
    try:
        rank_rows = get_light_snapshot_rank_rows(limit=10, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
        for row in rank_rows:
            if len(out) >= limit:
                break
            add(row.get('ticker'))
    except Exception:
        pass
    return out[:max(1, int(limit or 12))]


def build_review_pack_detail_keyboard(limit: int = 12):
    return build_detail_buttons_for_tickers(collect_review_pack_detail_tickers(limit=limit), max_buttons=limit, per_row=2)


def build_check_text() -> str:
    """상태 + 스캔헬스 + 리뷰팩을 한 번에 보는 압축 점검."""
    now_ts = time.time()
    try:
        display = get_latest_scan_display_state(now_ts=now_ts, limit=8)
    except Exception:
        display = {}
    user_items = list(display.get('user_items') or [])
    internal_items = list(display.get('internal_items') or [])
    discard_items = list(display.get('discard_items') or [])
    hidden_now_noise = [x for x in (user_items + internal_items + discard_items) if is_fast_scan_tiny_turnover_noise(x)]
    user_items = [x for x in user_items if not is_fast_scan_tiny_turnover_noise(x)]
    internal_items = [x for x in internal_items if not is_fast_scan_tiny_turnover_noise(x)]
    discard_items = [x for x in discard_items if not is_fast_scan_tiny_turnover_noise(x)]
    note = format_scan_display_state_line(display) if display else '스캔 상태 확인중'
    lines = [
        '✅ 빠른 점검 /check',
        f'- 시각: {now_kst().strftime("%m-%d %H:%M:%S")}',
        '',
        '1) 상태',
        f'- 자동매수: {"켜짐" if AUTO_BUY else "꺼짐"}',
        f'- 보유 포지션: {len(active_positions)}개' if active_positions else '- 보유 포지션: 없음',
        f'- 후보: 바로 {len(user_items)} / 관찰 {len(internal_items)} / 내부기록 {len(discard_items)}' + (f' / 잡음숨김 {len(hidden_now_noise)}' if hidden_now_noise else ''),
        f'- 기준: {note}',
        '',
        '2) 스캔헬스 압축',
    ]
    try:
        health_lines = str(build_scan_health_text(compact=True)).splitlines()
        for ln in health_lines[:18]:
            if ln.strip():
                lines.append(ln)
    except Exception as e:
        lines.append(f'- 스캔헬스 생성 실패: {e}')
    rows_now = user_items + internal_items + discard_items
    lines += ['', '3) 리뷰팩 압축', '📌 현재 후보']
    if not rows_now:
        lines.append('- 없음')
    else:
        for idx, it in enumerate(rows_now[:6], start=1):
            tk = str(it.get('ticker', '?') or '?').upper()
            bucket = get_fast_scan_bucket_text(it.get('alert_bucket', ''))
            grade = str(it.get('alert_grade', it.get('user_alert_grade', '-')) or '-')
            money_text = format_money_for_row(it)
            lines.append(f'{idx}. {ticker_review_icon(it)} {tk} / {bucket} / {grade} / 5분 {safe_float(it.get("change_5",0),0):+.2f}% / 30분 {safe_float(it.get("change_30",0),0):+.2f}% / 돈 {money_text}')
    lines += ['', '🧭 최근 역추적']
    try:
        load_reverse_trace_logs()
        trace_rows = list(reversed([x for x in reverse_trace_logs if isinstance(x, dict)][-100:]))
        seen = set()
        shown = 0
        hidden_trace_noise = 0
        for row in trace_rows:
            tk = str(row.get('ticker', '') or '').upper().strip()
            if not tk or tk in seen:
                continue
            seen.add(tk)
            if is_review_trace_tiny_noise(row):
                hidden_trace_noise += 1
                continue
            lines.append(format_reverse_trace_catalog_line(row, repeat=1, idx=shown + 1))
            shown += 1
            if shown >= 5:
                break
        if hidden_trace_noise:
            lines.append(f'- 거래대금 잡음 {hidden_trace_noise}개 숨김')
        if shown <= 0:
            lines.append('- 실전성 있는 최근 역추적 없음')
    except Exception as e:
        lines.append(f'- 역추적 압축 생성 실패: {e}')
    lines += ['', '🧷 더 볼 때: /rank_watch, /review_dump', '- 특정 코인은 아래 상세 버튼 또는 /review_trace_detail 코인명']
    return "\n".join(lines)


