# =========================================================
# v2.5.194 순위권 복기 기록 문구 쉬운 표현 정리
# =========================================================
BATCH_COMMAND_MAX_LINES = 14
BATCH_TRACE_SET_MAX_TICKERS = 10


def _update_text(update) -> str:
    try:
        msg = getattr(update, 'message', None)
        if msg is not None:
            return str(getattr(msg, 'text', '') or '')
    except Exception:
        pass
    return ''


def _normalize_batch_line(raw: str):
    line = str(raw or '').strip()
    if not line or not line.startswith('/'):
        return None
    parts = line.split()
    if not parts:
        return None
    cmd = parts[0][1:].split('@', 1)[0].strip().lower()
    args = parts[1:]
    if not cmd:
        return None
    return cmd, args, line


def _extract_batch_command_lines(text: str, skip_batch_header: bool = False) -> list:
    rows = []
    for raw in str(text or '').splitlines():
        line = str(raw or '').strip()
        if not line or not line.startswith('/'):
            continue
        norm = _normalize_batch_line(line)
        if not norm:
            continue
        cmd, _args, _line = norm
        if skip_batch_header and cmd in {'batch', 'run', 'commands'}:
            continue
        rows.append(line)
    return rows


def _maybe_handle_multiline_command_batch(update, context: CallbackContext) -> bool:
    """/check\n/rank_watch 처럼 한 메시지에 여러 줄을 붙여 보낸 경우 처리한다."""
    text = _update_text(update)
    rows = _extract_batch_command_lines(text, skip_batch_header=False)
    if len(rows) < 2:
        return False
    try:
        run_batch_command_lines(rows, source_label='여러 줄 명령')
    except Exception as e:
        send(f"⚠️ 여러 줄 명령 처리 에러: {e}")
    return True


def _trace_set_tickers_from_args(args) -> list:
    joined = ' '.join([str(x) for x in (args or [])]).strip()
    if not joined:
        return []
    raw_parts = []
    for chunk in joined.replace('\n', ',').split(','):
        chunk = chunk.strip()
        if not chunk:
            continue
        if ' ' in chunk and '/' not in chunk:
            raw_parts.extend([x.strip() for x in chunk.split() if x.strip()])
        else:
            raw_parts.append(chunk)
    out, seen = [], set()
    for raw in raw_parts:
        tk = str(raw or '').strip()
        if not tk:
            continue
        key = tk.upper()
        if key in {'DUMP', 'WITH_DUMP', '덤프'}:
            continue
        if key not in seen:
            seen.add(key)
            out.append(tk)
        if len(out) >= BATCH_TRACE_SET_MAX_TICKERS:
            break
    return out


def _run_trace_set(tickers, prefix: str = 'trace_set'):
    tickers = _trace_set_tickers_from_args(tickers)
    if not tickers:
        send("🧭 trace_set\n- 코인을 같이 적어줘\n- 예: /trace_set D ORCA HEMI ZEROBASE")
        return
    for idx, ticker in enumerate(tickers, start=1):
        send_text_chunks(
            build_review_trace_detail_text(ticker),
            prefix=f"🧭 {prefix} {idx}/{len(tickers)} / {ticker}",
            limit=TG_MESSAGE_SOFT_LIMIT,
        )


