SCAN_WATCHLIST_MAX_SEC = 24
SCAN_WATCHLIST_AUX_MAX_SEC = 6
SCAN_WATCHLIST_HEARTBEAT_EVERY = 1
SCAN_WATCHLIST_PREWATCH_LIMIT = 1
SCAN_WATCHLIST_NEWLOW_LIMIT = 1
PREWATCH_MIN_VOL_RATIO = 2.55
PREWATCH_MIN_LEADER_SCORE = 1.25
PREWATCH_MIN_HIGH_GAP_PCT = 1.05
PREWATCH_MAX_HIGH_GAP_PCT = 2.20
PREWATCH_MIN_FROM_LOW_PCT = 0.78
PREWATCH_MIN_3M_PCT = 0.20
PREWATCH_MIN_5M_PCT = 0.08
PREWATCH_MIN_SCORE = 6.10
MISSED_REVIEW_LATE_FROM_LOW_PCT = 3.20
MISSED_REVIEW_LATE_CHART_RISE_PCT = 4.20
MISSED_REVIEW_LATE_CHANGE30_PCT = 3.20
