recent_prewatch_alerts = {}
recent_newlow_alerts = {}
last_watchlist_market_register_ts = 0.0
def build_prewatch_candidates(cache, regime, exclude_tickers=None):
    preview = []
    exclude_tickers = set(exclude_tickers or [])
    regime_name = (regime or {}).get("name", "NORMAL")
    for ticker, data in cache.items():
        try:
            if ticker in exclude_tickers:
                continue
            df = data.get("df_1m")
            if df is None or len(df) < 20:
                continue
            current_price = safe_float(data.get("price", 0))
            if current_price <= 0:
                continue
            if is_watch_excluded_ticker(ticker):
                continue
            if is_tiny_tick_distortion(df, current_price):
                continue
            change_1 = safe_float(data.get("change_1", 0))
            change_3 = safe_float(data.get("change_3", 0))
            change_5 = safe_float(data.get("change_5", 0))
            change_30 = safe_float(data.get("change_30", get_recent_change_pct(df, 30)), 0)
            vol_ratio = safe_float(data.get("vol_ratio", data.get("vol_ratio_1m", 0))) or get_vol_ratio(df, 3, 15)
            rsi = safe_float(data.get("rsi", data.get("rsi_1m", 50))) or get_rsi(df, 14)
            range_pct = safe_float(data.get("range_pct", data.get("range_pct_1m", 0))) or get_range_pct(df, 10)
            leader_score = safe_float(data.get("leader_score", 0))
            turnover_rank = int(safe_float(data.get("turnover_rank", 999), 999))
            surge_rank = int(safe_float(data.get("surge_rank", 999), 999))
            reference_high = get_recent_high(df, 12, exclude_last=True)
            if reference_high <= 0:
                continue
            high_gap_pct = ((reference_high - current_price) / current_price) * 100.0 if current_price > 0 else 999.0
            recent_low = get_recent_low(df, 12, exclude_last=False)
            rebound_from_low_pct = ((current_price - recent_low) / recent_low) * 100.0 if recent_low > 0 else 0.0
            hl = has_higher_lows(df)
            box = detect_box_top_compression(df)
            half_hold = big_bull_half_hold(df)
            flip_count = direction_flip_count(df, 12)
            momentum_hint = max(change_1, change_3 * 0.90, change_5 * 0.70)
            if change_5 >= 1.8 or change_3 >= 1.2:
                continue
            if change_1 <= -0.35 and change_3 <= 0.00:
                continue
            if max(change_1, change_3, change_5) < 0.10:
                continue
            if momentum_hint <= 0.10:
                continue
            if change_5 < PREWATCH_MIN_5M_PCT and change_3 < PREWATCH_MIN_3M_PCT:
                continue
            if change_3 < PREWATCH_MIN_3M_PCT and change_5 < 0.05:
                continue
            if change_30 <= -1.10 and (change_5 < 0.18 or change_3 < 0.30):
                continue
            if change_30 <= -1.50 and rebound_from_low_pct < 0.90:
                continue
            if change_5 < 0.14 and change_3 < 0.28 and leader_score < 1.55:
                continue
            if vol_ratio < 3.00 and change_5 < 0.16 and change_3 < 0.30:
                continue
            if vol_ratio < 3.30 and leader_score < 1.60 and change_5 < 0.20 and change_30 < -0.80:
                continue
            if rebound_from_low_pct < PREWATCH_MIN_FROM_LOW_PCT:
                continue
            if high_gap_pct < 1.00 and rebound_from_low_pct < 0.80:
                continue
            if not (PREWATCH_MIN_VOL_RATIO <= vol_ratio <= 5.4):
                continue
            if vol_ratio < 2.50 and leader_score < 1.35 and momentum_hint < 0.22:
                continue
            if not (47 <= rsi <= 66):
                continue
            if not (PREWATCH_MIN_HIGH_GAP_PCT <= high_gap_pct <= PREWATCH_MAX_HIGH_GAP_PCT):
                continue
            if range_pct >= 2.6:
                continue
            if regime_name == "WEAK" and vol_ratio < 2.55:
                continue
            if leader_score < PREWATCH_MIN_LEADER_SCORE and turnover_rank > 28 and surge_rank > 28:
                continue
            if leader_score < PREWATCH_MIN_LEADER_SCORE and vol_ratio < (PREWATCH_MIN_VOL_RATIO + 0.20):
                continue
            if is_recent_spike_near_high(df, current_price) or is_box_top_range_chase(df, current_price) or is_retest_after_failed_peak(df) or is_false_start_near_high(df, current_price):
                continue
            if rebound_from_low_pct >= 1.45 and high_gap_pct <= 1.00:
                continue
            if flip_count >= 6 and not box and change_5 < 0.60:
                continue
            if flip_count >= 7 and range_pct >= 1.20:
                continue
            if not (hl or box or half_hold):
                continue
            tags = []
            if hl:
                tags.append("저점높임")
            if box:
                tags.append("상단압축")
            if half_hold:
                tags.append("양봉절반유지")
            score = 4.3 + max(vol_ratio - 1.0, 0) * 0.58 + max(change_3, 0) * 0.32 + max(leader_score, 0) * 0.42 + max(rebound_from_low_pct - 0.20, 0) * 0.16
            if score < PREWATCH_MIN_SCORE:
                continue
            prewatch_rank_score = (
                score
                + max(vol_ratio - 2.20, 0) * 0.40
                + max(leader_score - 1.0, 0) * 0.55
                + max(change_3 - PREWATCH_MIN_3M_PCT, 0) * 0.90
                + max(change_5 - PREWATCH_MIN_5M_PCT, 0) * 0.70
                + max(rebound_from_low_pct - PREWATCH_MIN_FROM_LOW_PCT, 0) * 0.32
                + max(high_gap_pct - PREWATCH_MIN_HIGH_GAP_PCT, 0) * 0.18
            )
            if high_gap_pct <= 1.18:
                prewatch_rank_score -= 0.45
            if vol_ratio < 2.80 and leader_score < 1.45:
                prewatch_rank_score -= 0.35
            if change_5 <= 0.12 and change_3 <= 0.24:
                prewatch_rank_score -= 0.30
            if rebound_from_low_pct >= 1.30 and high_gap_pct <= 1.25:
                prewatch_rank_score -= 0.35
            if turnover_rank > 22 and surge_rank > 22:
                prewatch_rank_score -= 0.20
            if change_5 < 0.18 and change_3 < 0.32:
                prewatch_rank_score -= 0.35
            if vol_ratio < 3.10 and leader_score < 1.55:
                prewatch_rank_score -= 0.30
            if change_30 < -0.85 and change_5 < 0.26:
                prewatch_rank_score -= 0.55
            if change_30 < -1.10 and rebound_from_low_pct < 0.95:
                prewatch_rank_score -= 0.50
            if prewatch_rank_score < 6.90:
                continue
            candidate = make_signal(
                ticker=ticker,
                strategy="PREWATCH",
                strategy_label="예비 후보 감시",
                current_price=current_price,
                vol_ratio=vol_ratio,
                change_pct=max(change_1, change_3, change_5),
                rsi=rsi,
                range_pct=range_pct,
                signal_score=max(4.2, score),
                edge_score=max(4.1, score),
                leader_score=leader_score,
                stop_loss_pct=-1.2,
                take_profit_pct=3.0,
                time_stop_sec=900,
                pattern_tags=tags,
                reference_high=reference_high,
                reference_low=recent_low,
                reason=f"예비 감시 / 막 뜨기 직전처럼 보이지만 힘이 붙는지 먼저 확인 / 고점까지 {high_gap_pct:.2f}% / 저가에서 {rebound_from_low_pct:.2f}% / 거래량 {vol_ratio:.2f}배",
            )
            candidate["prewatch_rank_score"] = round(prewatch_rank_score, 2)
            apply_chart_position_profile(candidate, df, lookback=CHART_POS_LOOKBACK_1M)
            if not has_meaningful_watch_motion(candidate):
                continue
            preview.append(candidate)
        except Exception:
            continue
    preview.sort(
        key=lambda x: (
            safe_float(x.get("prewatch_rank_score", 0))
            + safe_float(x.get("edge_score", 0)) * 0.20
            + safe_float(x.get("leader_score", 0)) * 0.12
        ),
        reverse=True,
    )
    return preview[:4]

def build_newlow_recovery_candidates(cache, regime, exclude_tickers=None):
    recovered = []
    exclude_tickers = set(exclude_tickers or [])
    regime_name = (regime or {}).get("name", "NORMAL")
    for ticker, data in cache.items():
        try:
            if ticker in exclude_tickers:
                continue
            df = data.get("df_1m")
            if df is None or len(df) < 24:
                continue
            current_price = safe_float(data.get("price", 0))
            if current_price <= 0 or current_price <= 1.0:
                continue
            if is_tiny_tick_distortion(df, current_price):
                continue
            recent = df.tail(14)
            recent_low = float(recent["low"].min())
            if recent_low <= 0:
                continue
            recent_high = float(recent["high"].max())
            low_gap_pct = ((current_price - recent_low) / recent_low) * 100.0
            pullback_from_peak_pct = ((recent_high - current_price) / recent_high) * 100.0 if recent_high > 0 else 0.0
            change_1 = safe_float(data.get("change_1", 0))
            change_3 = safe_float(data.get("change_3", 0))
            change_5 = safe_float(data.get("change_5", 0))
            vol_ratio = safe_float(data.get("vol_ratio", data.get("vol_ratio_1m", 0))) or get_vol_ratio(df, 3, 15)
            rsi = safe_float(data.get("rsi", data.get("rsi_1m", 50))) or get_rsi(df, 14)
            range_pct = safe_float(data.get("range_pct", data.get("range_pct_1m", 0))) or get_range_pct(df, 10)
            leader_score = safe_float(data.get("leader_score", 0))
            reference_high = get_recent_high(df, 12, exclude_last=True)
            high_gap_pct = ((reference_high - current_price) / current_price) * 100.0 if reference_high > 0 and current_price > 0 else 999.0
            last = recent.iloc[-1]
            prev = recent.iloc[-2]
            bullish_reclaim = float(last["close"]) >= float(last["open"]) and float(last["close"]) >= float(prev["close"]) * 0.998
            fake_recovery = fake_breakdown_recovery(df)
            lower_low_recent = float(prev["low"]) <= recent_low * 1.004 or float(last["low"]) <= recent_low * 1.004
            flip_count = direction_flip_count(df, 12)
            if regime_name == "WEAK" and vol_ratio < 2.10:
                continue
            if change_5 <= -3.2 or change_5 >= 2.8:
                continue
            if change_1 < 0.03 and change_3 < 0.10:
                continue
            if vol_ratio < 1.95:
                continue
            if leader_score < 0.85 and vol_ratio < 2.60:
                continue
            if not (0.20 <= low_gap_pct <= 1.35):
                continue
            if high_gap_pct <= 0.70:
                continue
            if range_pct >= 2.8:
                continue
            if pullback_from_peak_pct >= 0.75 and change_1 <= 0.12:
                continue
            if flip_count >= 7 and range_pct >= 1.4:
                continue
            if not (fake_recovery or (bullish_reclaim and lower_low_recent and change_1 >= 0.03 and change_3 >= 0.08)):
                continue
            if is_recent_spike_near_high(df, current_price) or is_box_top_range_chase(df, current_price) or is_false_start_near_high(df, current_price):
                continue
            tags = ["저가회복"]
            if fake_recovery:
                tags.append("가짜하락회복")
            if has_higher_lows(df):
                tags.append("저점높임")
            score = 4.4 + max(vol_ratio - 1.0, 0) * 0.50 + max(change_1, 0) * 0.25 + max(leader_score, 0) * 0.25
            if score < 5.00:
                continue
            candidate = make_signal(
                ticker=ticker,
                strategy="NEWLOW_RECOVER",
                strategy_label="신저가 반등 감시",
                current_price=current_price,
                vol_ratio=vol_ratio,
                change_pct=max(change_1, change_3, change_5),
                rsi=rsi,
                range_pct=range_pct,
                signal_score=max(4.2, score),
                edge_score=max(4.1, score),
                leader_score=leader_score,
                stop_loss_pct=-1.0,
                take_profit_pct=3.2,
                time_stop_sec=720,
                pattern_tags=tags,
                reference_high=reference_high,
                reference_low=recent_low,
                reason=f"최근 저가권 회복 / 저가에서 {low_gap_pct:.2f}% 회복 / 되밀림 {pullback_from_peak_pct:.2f}% / 거래량 {vol_ratio:.2f}배",
            )
            apply_chart_position_profile(candidate, df, lookback=CHART_POS_LOOKBACK_1M)
            if not has_meaningful_watch_motion(candidate):
                continue
            recovered.append(candidate)
        except Exception:
            continue
    recovered.sort(key=lambda x: (safe_float(x.get("edge_score", 0)) + safe_float(x.get("vol_ratio", 0)) * 0.2), reverse=True)
    return recovered[:4]
def should_send_simple_aux_alert(kind_dict: dict, ticker: str, now_ts: float, cooldown_sec: int):
    prev = safe_float(kind_dict.get(ticker, 0), 0)
    if now_ts - prev < cooldown_sec:
        return False
    kind_dict[ticker] = now_ts
    return True
def is_good_market_for_user_rescue(regime: dict = None) -> bool:
    regime = regime or get_market_regime()
    name = str((regime or {}).get("name", "NORMAL") or "NORMAL")
    if name == "STRONG_UP":
        return True
    day_change = safe_float((regime or {}).get("day_change_pct", 0), 0)
    mid_change = safe_float((regime or {}).get("mid_change_pct", 0), 0)
    return day_change >= USER_ALERT_RESCUE_GOOD_MARKET_DAY_PCT and mid_change >= USER_ALERT_RESCUE_GOOD_MARKET_MID_PCT


def get_effective_high_gap_pct(item: dict) -> float:
    profile = get_item_chart_profile(item)
    vals = [
        get_primary_high_gap_pct(item),
        safe_float(profile.get("chart_gap_pct", 999), 999),
        get_reference_high_gap_pct(item),
    ]
    usable = [v for v in vals if 0 <= v < 900]
    if not usable:
        return 999.0
    return usable[0]


def compute_market_flow_context(item: dict) -> dict:
    info = get_market_pulse_rank_info(item.get("ticker", ""))
    turnover_rank = int(safe_float(item.get("turnover_rank", item.get("turnover_rank_pulse", info.get("turnover_rank_pulse", 999))), 999))
    if turnover_rank <= 0:
        turnover_rank = int(safe_float(info.get("turnover_rank_pulse", 999), 999))
    change_1_rank = int(safe_float(item.get("change_1_rank", info.get("change_1_rank", 999)), 999))
    change_5_rank = int(safe_float(item.get("change_5_rank", info.get("change_5_rank", 999)), 999))
    vol_ratio_rank = int(safe_float(item.get("vol_ratio_rank", info.get("vol_ratio_rank", 999)), 999))
    leader_rank = int(safe_float(item.get("leader_rank", info.get("leader_rank", 999)), 999))
    flow_score = 0.0
    if 0 < turnover_rank <= 15:
        flow_score += 1.10
    elif 0 < turnover_rank <= 30:
        flow_score += 0.75
    elif 0 < turnover_rank <= 50:
        flow_score += 0.35
    if 0 < change_1_rank <= 12:
        flow_score += 0.70
    elif 0 < change_5_rank <= 15:
        flow_score += 0.45
    if 0 < leader_rank <= 15:
        flow_score += 0.70
    elif 0 < leader_rank <= 30:
        flow_score += 0.40
    if 0 < vol_ratio_rank <= 15:
        flow_score += 0.45
    if (0 < turnover_rank <= 25 and 0 < leader_rank <= 25):
        flow_score += 0.40
    if (0 < change_1_rank <= 10 and 0 < turnover_rank <= 25):
        flow_score += 0.25
    label = "흐름 약함"
    if flow_score >= 2.6:
        label = "시장 돈 흐름 강함"
    elif flow_score >= 1.5:
        label = "시장 돈 흐름 보통 이상"
    elif flow_score >= 0.7:
        label = "시장 돈 흐름 약간 붙음"
    return {
        "market_flow_score": round(flow_score, 2),
        "market_flow_label": label,
    }


def compute_daily_setup_context(ticker: str, current_price: float) -> dict:
    ctx = {
        "daily_gap_pct": 999.0,
        "daily_rise_pct": 0.0,
        "daily_zone_ratio": -1.0,
        "daily_ready_score": 0.0,
        "daily_setup_label": "일봉 확인중",
        "daily_high_price": 0.0,
        "daily_low_price": 0.0,
        "daily_ma5": 0.0,
        "daily_ma20": 0.0,
        "daily_rebound_day": 0,
        "daily_box_position_label": "일봉 위치 확인중",
        "daily_bottom_zone": False,
    }
    try:
        df = get_ohlcv(str(ticker or "").upper().strip(), "day")
        if df is None or len(df) < 20 or current_price <= 0:
            return ctx
        recent = df.tail(min(len(df), 45))
        low_v = safe_float(recent["low"].min(), 0)
        high_v = safe_float(recent["high"].max(), 0)
        if low_v <= 0 or high_v <= low_v:
            return ctx
        gap_pct = ((high_v - current_price) / high_v) * 100.0
        rise_pct = ((current_price - low_v) / low_v) * 100.0
        zone_ratio = (current_price - low_v) / (high_v - low_v) if high_v > low_v else -1.0
        ma5v = ma(df, 5)
        ma20v = ma(df, 20)
        score = 0.0
        if gap_pct >= 5.0:
            score += 1.0
        elif gap_pct >= 2.5:
            score += 0.65
        elif gap_pct <= 0.9:
            score -= 0.75
        if rise_pct <= 6.0:
            score += 0.85
        elif rise_pct <= 12.0:
            score += 0.35
        elif rise_pct >= 18.0:
            score -= 0.75
        if 0 <= zone_ratio <= 0.72:
            score += 0.50
        elif zone_ratio >= 0.90:
            score -= 0.65
        if ma20v > 0 and current_price >= ma20v:
            score += 0.25
        if ma5v > 0 and ma20v > 0 and ma5v >= ma20v * 0.995:
            score += 0.20
        if ma20v > 0 and current_price < ma20v * 0.985:
            score -= 0.45
        label = "일봉 애매"
        if score >= 1.35:
            label = "일봉 준비도 좋음"
        elif score >= 0.55:
            label = "일봉 무난"
        elif score <= -0.55:
            label = "일봉상 위쪽"
        closes = df["close"].astype(float)
        lows = df["low"].astype(float)
        rebound_day = 0
        if len(closes) >= 4:
            c0, c1, c2, c3 = [safe_float(x, 0) for x in closes.tail(4).tolist()]
            l0, l1, l2 = [safe_float(x, 0) for x in lows.tail(3).tolist()]
            if c0 > c1 and l0 >= l1 and c1 <= c2:
                rebound_day = 1
            elif c0 >= c1 >= c2 and l0 >= l1 >= l2:
                rebound_day = 2
            elif c0 >= c1 and c1 < c2:
                rebound_day = 3
        pos_label = "일봉 중단"
        if 0 <= zone_ratio <= 0.28:
            pos_label = "일봉 바닥권"
        elif zone_ratio >= 0.78:
            pos_label = "일봉 상단권"
        ctx.update({
            "daily_gap_pct": round(gap_pct, 2),
            "daily_rise_pct": round(rise_pct, 2),
            "daily_zone_ratio": round(zone_ratio, 4),
            "daily_ready_score": round(score, 2),
            "daily_setup_label": label,
            "daily_high_price": round(high_v, 8),
            "daily_low_price": round(low_v, 8),
            "daily_ma5": round(ma5v, 8) if ma5v > 0 else 0.0,
            "daily_ma20": round(ma20v, 8) if ma20v > 0 else 0.0,
            "daily_rebound_day": int(rebound_day),
            "daily_box_position_label": pos_label,
            "daily_bottom_zone": bool(0 <= zone_ratio <= 0.28),
        })
    except Exception:
        return ctx
    return ctx


def build_pseudo_htf_from_lower_interval(ticker: str, interval: str = "minute60", chunk: int = 4, min_rows: int = 2):
    try:
        df_low = get_ohlcv(str(ticker or "").upper().strip(), interval)
        if df_low is None or len(df_low) < max(chunk * min_rows, chunk + 1):
            return None
        rows = []
        idx = []
        usable = len(df_low) - (len(df_low) % chunk)
        if usable < chunk * min_rows:
            return None
        work = df_low.tail(usable)
        for start in range(0, len(work), chunk):
            part = work.iloc[start:start + chunk]
            if len(part) < chunk:
                continue
            rows.append({
                "open": safe_float(part["open"].iloc[0], 0),
                "high": safe_float(part["high"].max(), 0),
                "low": safe_float(part["low"].min(), 0),
                "close": safe_float(part["close"].iloc[-1], 0),
                "volume": safe_float(part["volume"].sum(), 0),
            })
            idx.append(part.index[-1])
        if len(rows) < min_rows:
            return None
        return pd.DataFrame(rows, index=idx)
    except Exception:
        return None


def build_pseudo_htf_from_minute60(ticker: str, chunk: int = 4):
    return build_pseudo_htf_from_lower_interval(ticker, interval="minute60", chunk=chunk, min_rows=2)


def compute_htf_setup_context(ticker: str, current_price: float) -> dict:
    ctx = {
        "htf_gap_pct": 999.0,
        "htf_rise_pct": 0.0,
        "htf_zone_ratio": -1.0,
        "htf_setup_score": 0.0,
        "htf_setup_label": "4시간봉 데이터 부족",
        "htf_high_price": 0.0,
        "htf_low_price": 0.0,
        "htf_ma7": 0.0,
        "htf_ma30": 0.0,
        "htf_ma7_slope_pct": 0.0,
        "htf_ma30_slope_pct": 0.0,
        "htf_trend_label": "4시간 추세 확인중",
        "htf_above_ma7": False,
        "htf_above_ma30": False,
        "htf_data_source": "minute240",
        "htf_box_position_label": "4시간 위치 확인중",
        "htf_higher_low_3": False,
        "htf_bottom_zone": False,
    }
    try:
        ticker = str(ticker or "").upper().strip()
        used_fallback = False
        fallback_source = "minute240"
        df = get_ohlcv(ticker, ALERT_HTF_INTERVAL)
        if df is None or len(df) < 3:
            fallback_candidates = [
                ("minute60x4", build_pseudo_htf_from_lower_interval(ticker, interval="minute60", chunk=4, min_rows=2)),
                ("minute30x8", build_pseudo_htf_from_lower_interval(ticker, interval="minute30", chunk=8, min_rows=2)),
                ("minute15x16", build_pseudo_htf_from_lower_interval(ticker, interval="minute15", chunk=16, min_rows=2)),
            ]
            for source_name, fallback_df in fallback_candidates:
                if fallback_df is not None and len(fallback_df) >= 2:
                    df = fallback_df
                    used_fallback = True
                    fallback_source = source_name
                    break
        if df is None or len(df) < 2 or current_price <= 0:
            return ctx
        recent = df.tail(min(len(df), 30))
        low_v = safe_float(recent["low"].min(), 0)
        high_v = safe_float(recent["high"].max(), 0)
        if low_v <= 0 or high_v <= low_v:
            return ctx
        gap_pct = ((high_v - current_price) / high_v) * 100.0
        rise_pct = ((current_price - low_v) / low_v) * 100.0
        zone_ratio = (current_price - low_v) / (high_v - low_v) if high_v > low_v else -1.0

        ma7v = ma(df, 7) if len(df) >= 7 else 0.0
        ma30v = ma(df, 30) if len(df) >= 30 else 0.0
        ma7_prev = ma(df.iloc[:-3], 7) if len(df) >= 10 else (ma(df.iloc[:-1], 7) if len(df) >= 8 else 0.0)
        ma30_prev = ma(df.iloc[:-3], 30) if len(df) >= 33 else (ma(df.iloc[:-1], 30) if len(df) >= 31 else 0.0)
        ma7_slope_pct = ((ma7v - ma7_prev) / ma7_prev) * 100.0 if ma7v > 0 and ma7_prev > 0 else 0.0
        ma30_slope_pct = ((ma30v - ma30_prev) / ma30_prev) * 100.0 if ma30v > 0 and ma30_prev > 0 else 0.0
        above_ma7 = bool(ma7v > 0 and current_price >= ma7v)
        above_ma30 = bool(ma30v > 0 and current_price >= ma30v)

        score = 0.0
        if gap_pct >= 3.5:
            score += 0.85
        elif gap_pct >= 1.8:
            score += 0.45
        elif gap_pct <= 0.8:
            score -= 0.70
        if rise_pct <= 4.5:
            score += 0.65
        elif rise_pct <= 9.0:
            score += 0.25
        elif rise_pct >= 14.0:
            score -= 0.55
        if 0 <= zone_ratio <= 0.68:
            score += 0.45
        elif zone_ratio >= 0.88:
            score -= 0.55
        if above_ma7:
            score += 0.20
        if above_ma30:
            score += 0.20
        if ma7v > 0 and ma30v > 0 and ma7v >= ma30v * 0.997:
            score += 0.25
        if ma30v > 0 and current_price < ma30v * 0.985:
            score -= 0.35
        if ma7_slope_pct >= 0.10:
            score += 0.15
        elif ma7_slope_pct <= -0.10:
            score -= 0.15
        if ma30_slope_pct >= 0.05:
            score += 0.10
        elif ma30_slope_pct <= -0.05:
            score -= 0.10

        trend_label = "4시간 추세 보통"
        if above_ma7 and above_ma30 and ma7_slope_pct >= 0.10 and ma30_slope_pct >= 0.03:
            trend_label = "4시간 상방 추세"
        elif (not above_ma30) and ma30_slope_pct <= -0.05:
            trend_label = "4시간 하방 추세"
        elif above_ma7 and ma7_slope_pct >= 0.05:
            trend_label = "4시간 회복 시도"
        elif abs(ma7_slope_pct) < 0.05 and abs(ma30_slope_pct) < 0.03 and (ma7v > 0 or ma30v > 0):
            trend_label = "4시간 횡보"
        elif used_fallback:
            trend_label = "4시간 추정 추세"

        label = "4시간봉 애매"
        if len(df) < 3:
            label = "4시간봉 추정 표본 적음" if used_fallback else "4시간봉 표본 적음"
        elif score >= 1.15:
            label = "4시간봉 준비도 좋음"
        elif score >= 0.45:
            label = "4시간봉 무난"
        elif score <= -0.45:
            label = "4시간봉 위쪽"
        elif used_fallback:
            label = "4시간봉 추정값" if score >= 0 else "4시간봉 추정 애매"

        higher_low_3 = False
        try:
            recent_lows = [safe_float(x, 0) for x in recent["low"].tail(3).tolist()]
            if len(recent_lows) == 3 and recent_lows[0] > 0:
                higher_low_3 = recent_lows[2] >= recent_lows[1] >= recent_lows[0]
        except Exception:
            higher_low_3 = False
        pos_label = "4시간 중단"
        if 0 <= zone_ratio <= 0.28:
            pos_label = "4시간 바닥권"
        elif zone_ratio >= 0.78:
            pos_label = "4시간 상단권"
        ctx.update({
            "htf_gap_pct": round(gap_pct, 2),
            "htf_rise_pct": round(rise_pct, 2),
            "htf_zone_ratio": round(zone_ratio, 4),
            "htf_setup_score": round(score, 2),
            "htf_setup_label": label,
            "htf_high_price": round(high_v, 8),
            "htf_low_price": round(low_v, 8),
            "htf_ma7": round(ma7v, 8) if ma7v > 0 else 0.0,
            "htf_ma30": round(ma30v, 8) if ma30v > 0 else 0.0,
            "htf_ma7_slope_pct": round(ma7_slope_pct, 3),
            "htf_ma30_slope_pct": round(ma30_slope_pct, 3),
            "htf_trend_label": trend_label,
            "htf_above_ma7": above_ma7,
            "htf_above_ma30": above_ma30,
            "htf_data_source": fallback_source if used_fallback else "minute240",
            "htf_box_position_label": pos_label,
            "htf_higher_low_3": bool(higher_low_3),
            "htf_bottom_zone": bool(0 <= zone_ratio <= 0.28),
        })
    except Exception:
        return ctx
    return ctx


def compute_breakout_hold_context(ticker: str, current_price: float, df1=None) -> dict:
    ctx = {
        "breakout_hold_score": 0.0,
        "breakout_hold_ok": False,
        "breakout_ref_gap_pct": 999.0,
        "breakout_hold_label": "유지 확인중",
    }
    try:
        df = df1 if df1 is not None else get_ohlcv(str(ticker or "").upper().strip(), "minute1")
        if df is None or len(df) < 16 or current_price <= 0:
            return ctx
        recent = df.tail(18)
        ref_high = safe_float(recent.iloc[:-3]["high"].max(), 0)
        if ref_high <= 0:
            return ctx
        last3 = recent.tail(3)
        hold_gap_pct = ((ref_high - current_price) / ref_high) * 100.0
        close_mean = safe_float(last3["close"].mean(), current_price)
        low_floor = safe_float(last3["low"].min(), current_price)
        vol_ratio = get_vol_ratio(df, 3, 15)
        score = 0.0
        if hold_gap_pct <= 0.60:
            score += 0.65
        elif hold_gap_pct <= 1.20:
            score += 0.35
        else:
            score -= 0.25
        if close_mean >= ref_high * 0.997:
            score += 0.70
        elif close_mean >= ref_high * 0.993:
            score += 0.35
        if low_floor >= ref_high * 0.992:
            score += 0.45
        elif low_floor < ref_high * 0.985:
            score -= 0.45
        if vol_ratio >= 1.80:
            score += 0.25
        elif vol_ratio < 0.95:
            score -= 0.20
        hold_ok = score >= 1.0
        label = "돌파 후 유지 약함"
        if score >= 1.40:
            label = "돌파 후 유지 괜찮음"
        elif score >= 0.70:
            label = "돌파 후 유지 애매"
        ctx.update({
            "breakout_hold_score": round(score, 2),
            "breakout_hold_ok": bool(hold_ok),
            "breakout_ref_gap_pct": round(hold_gap_pct, 2),
            "breakout_hold_label": label,
        })
    except Exception:
        return ctx
    return ctx


