def _fast_user_alert_drought_sec(now_ts: float = None) -> int:
    now_ts = safe_float(now_ts, time.time())
    latest_ts = 0.0
    try:
        for value in recent_signal_alerts.values():
            latest_ts = max(latest_ts, safe_float(value, 0))
    except Exception:
        pass
    try:
        for value in recent_fast_alert_signatures.values():
            if isinstance(value, dict):
                latest_ts = max(latest_ts, safe_float(value.get("ts", 0), 0))
    except Exception:
        pass
    if latest_ts <= 0:
        return 999999
    return max(0, int(now_ts - latest_ts))

def _fast_abs_turnover_ok(item: dict, level: str = "watch") -> bool:
    level = str(level or "watch").strip().lower()
    turnover_15m = safe_float(item.get("turnover", 0), 0)
    turnover_3m = safe_float(item.get("turnover_3m", 0), 0)
    turnover_5m = safe_float(item.get("turnover_5m", 0), 0)
    turnover_rank = int(safe_float(item.get("turnover_rank", 999), 999))
    if level in {"s", "strong"}:
        return (
            turnover_15m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_15M
            or (turnover_3m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_5M)
            or (0 < turnover_rank <= 18 and turnover_3m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_3M)
        )
    if level in {"a", "user"}:
        return (
            turnover_15m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_15M
            or (turnover_3m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_5M)
            or (0 < turnover_rank <= 25 and turnover_3m >= FAST_SCAN_WATCH_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_WATCH_MIN_TURNOVER_5M)
        )
    if level == "rescue":
        return (
            turnover_5m >= FAST_SCAN_RESCUE_MIN_TURNOVER_5M
            or turnover_15m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_15M * 0.70
            or (0 < turnover_rank <= 25 and turnover_5m >= FAST_SCAN_WATCH_MIN_TURNOVER_5M)
        )
    return fast_scan_turnover_gate(item, level="watch")


def _is_late_high_volatility_item(item: dict) -> bool:
    """ENJ형: 이미 크게 튄 뒤 고점권에서 흔드는 후보.

    거래량이 없어서 문제가 아니라, 이미 위에서 흔들리며 손익비가 나빠진 케이스다.
    이런 후보는 '거래량 약함'보다 '늦은 고점권 변동성'으로 설명해야 한다.
    """
    item = item if isinstance(item, dict) else {}
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    change_30 = safe_float(item.get("change_30", 0), 0)
    change_5 = safe_float(item.get("change_5", 0), 0)
    upper3 = safe_float(item.get("upper_wick_pct_3", 0), 0)
    upper5 = safe_float(item.get("upper_wick_pct_5", 0), 0)
    body3 = safe_float(item.get("candle_body_ratio_3", 0), 0)
    body5 = safe_float(item.get("candle_body_ratio_5", 0), 0)
    return bool(
        from_low >= 2.45
        and below_high <= 1.25
        and change_30 >= 0.90
        and (
            upper3 >= 0.22
            or upper5 >= 0.16
            or (body3 <= 0.10 and body5 <= 0.12 and change_5 <= 1.05)
        )
    )


def _is_near_high_rebreakout_watch(item: dict) -> bool:
    """CVC형: 고점은 가깝지만 구조가 좋아서 버리기엔 아까운 재돌파 대기 후보."""
    item = item if isinstance(item, dict) else {}
    if _is_late_high_volatility_item(item):
        return False
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    change_5 = safe_float(item.get("change_5", 0), 0)
    defense = safe_float(item.get("low_zone_defense_score", item.get("recovery_quality_score", 0)), 0)
    persist = safe_float(item.get("turnover_persistence_score", 0), 0)
    re_score = safe_float(item.get("rebreakout_score", item.get("rebreakout_prep_score", 0)), 0)
    hold05 = int(safe_float(item.get("hold_near_high_bars_05", 0), 0))
    hold10 = int(safe_float(item.get("hold_near_high_bars_10", 0), 0))
    strong_bulls = int(safe_float(item.get("strong_bullish_count_5", 0), 0))
    return bool(
        0.12 <= below_high <= 0.70
        and 0.70 <= from_low <= 2.35
        and change_5 >= 0.05
        and defense >= 1.45
        and persist >= 1.20
        and re_score >= 2.20
        and (hold05 >= 1 or hold10 >= 1 or strong_bulls >= 1)
        and fast_scan_turnover_gate(item, level="watch")
    )


def _dampen_prebreakout_if_thrust_weak(item: dict) -> dict:
    """거래량 재가속만으로 '고점 전 준비 좋음'이 과대평가되는 것을 줄인다."""
    item = item if isinstance(item, dict) else {}
    score = safe_float(item.get("prebreakout_ready_score", 0), 0)
    if score < 2.20:
        return item
    change_5 = safe_float(item.get("change_5", 0), 0)
    body3 = safe_float(item.get("candle_body_ratio_3", 0), 0)
    body5 = safe_float(item.get("candle_body_ratio_5", 0), 0)
    close3 = safe_float(item.get("close_position_ratio_3", 0), 0)
    close5 = safe_float(item.get("close_position_ratio_5", 0), 0)
    strong_bulls = int(safe_float(item.get("strong_bullish_count_5", 0), 0))
    weak_thrust = bool(
        change_5 <= 0.12
        or (body3 <= 0.10 and body5 <= 0.12 and close3 <= 0.35 and close5 <= 0.40)
        or strong_bulls <= 0
    )
    if not weak_thrust:
        return item
    item["prebreakout_ready_score_raw"] = score
    item["prebreakout_ready_score"] = round(min(score, 1.05), 2)
    item["prebreakout_label"] = "하락 후 회복 확인 중"
    item["prebreakout_overheat_dampened"] = True
    return item


def _fast_actual_turnover_tier(item: dict) -> str:
    """실제 5분 거래대금 기준. 확인 전 상태는 tiny로 단정하지 않는다."""
    if money_status_code_for_row(item) in {"checking", "unknown"}:
        return "unknown"
    t5 = safe_float(item.get("turnover_5m", 0), 0)
    t3 = safe_float(item.get("turnover_3m", 0), 0)
    t15 = safe_float(item.get("turnover", 0), 0)
    if t5 >= 80000000 or t15 >= 180000000:
        return "strong"
    if t5 >= 25000000 or t3 >= 16000000 or t15 >= 90000000:
        return "normal"
    if t5 >= 8000000 or t3 >= 5000000 or t15 >= 30000000:
        return "thin"
    return "tiny"


def _is_low_actual_turnover(item: dict) -> bool:
    # 확인 전/미확인인 거래대금은 '실제돈작음'으로 차단하지 않는다.
    return _fast_actual_turnover_tier(item) in {"tiny", "thin"}


def _is_ultra_low_tick_noise_item(item: dict) -> bool:
    """NFT형: 초저가 틱 한 칸 변동으로 퍼센트가 과장되는 잡음형."""
    item = item if isinstance(item, dict) else {}
    price = safe_float(item.get("price", item.get("current_price", 0)), 0)
    change_1 = abs(safe_float(item.get("change_1", 0), 0))
    change_3 = abs(safe_float(item.get("change_3", 0), 0))
    change_5 = abs(safe_float(item.get("change_5", 0), 0))
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    turnover_5m = safe_float(item.get("turnover_5m", 0), 0)
    # Bithumb 초저가 토큰은 0.0004 -> 0.0005 같은 한 틱 이동이 +25%로 잡힌다.
    return bool(
        0 < price <= 0.01
        and max(change_1, change_3, change_5, from_low) >= 8.0
        and below_high <= 0.20
        and turnover_5m < 3000000
    )


def _is_flash_low_liquidity_near_high(item: dict) -> bool:
    """XPLA형: 거래량 배수는 커 보이지만 실제 돈은 작고, 고점 바로 앞에서 반짝인 후보."""
    item = item if isinstance(item, dict) else {}
    if _is_near_high_rebreakout_watch(item):
        return False
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    change_5 = safe_float(item.get("change_5", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    turnover_5m = safe_float(item.get("turnover_5m", 0), 0)
    flash_score = safe_float(item.get("turnover_flash_score", 0), 0)
    candle_weak = bool(is_chart_current_candle_uninformative(item))
    return bool(
        0 <= below_high <= 0.12
        and vol_ratio >= 4.0
        and turnover_5m < 10000000
        and change_5 <= 0.85
        and (flash_score <= -1.2 or candle_weak)
    )


def _classify_near_high_quality(item: dict) -> str:
    """고점 바로 앞 후보 3분류: 추격금지 / 반짝확인 / 재돌파대기."""
    if _is_ultra_low_tick_noise_item(item):
        return "초저가 잡음형"
    if _is_late_high_volatility_item(item):
        return "추격 금지"
    if _is_near_high_rebreakout_watch(item):
        return "재돌파 대기"
    if _is_flash_low_liquidity_near_high(item):
        return "반짝 확인"
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    if 0 <= below_high <= 0.12:
        return "고점 바로 앞 보류"
    return ""


def _apply_fast_candidate_quality_refinements(item: dict) -> dict:
    """v2.5.152 후보 품질 보정.
    - XPLA형 반짝 후보 낮추기
    - NFT형 초저가 잡음 차단
    - 실제 거래대금이 작은데 거래량 배수만 큰 후보 과대평가 방지
    - 고점 바로 앞 후보를 추격금지/반짝확인/재돌파대기로 분리
    """
    if not isinstance(item, dict):
        return item
    reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
    def add_reason(text: str):
        if text and text not in reasons:
            reasons.append(text)

    near_type = _classify_near_high_quality(item)
    if near_type:
        item["near_high_quality_type"] = near_type

    if _is_ultra_low_tick_noise_item(item):
        item["ultra_low_tick_noise_block"] = True
        item["section"] = "weak"
        item["primary_reason"] = "초저가 잡음형"
        add_reason("초저가 틱 변동으로 퍼센트가 과장됨")
        add_reason("실전 후보 제외")

    elif _is_flash_low_liquidity_near_high(item):
        item["flash_low_liquidity_near_high_block"] = True
        item["section"] = "watch"
        item["primary_reason"] = "반짝 확인 후보"
        add_reason("고점 바로 앞 반짝형")
        add_reason("실제 거래대금이 작아 알림 보류")

    if _is_low_actual_turnover(item):
        item["low_actual_turnover_flag"] = True
        # 배수는 크지만 실제 돈이 작으면 좋은 후보로 과대평가하지 않는다.
        if safe_float(item.get("vol_ratio", 0), 0) >= 4.0:
            add_reason("거래량 배수는 높지만 실제 거래대금은 작음")

    if near_type == "고점 바로 앞 보류":
        add_reason("고점 바로 앞이라 추격 금지")
        if str(item.get("section", "")) == "strong":
            item["section"] = "watch"
            item["primary_reason"] = "반짝 확인 후보"

    item["reasons"] = reasons[:6]
    return item

def _fast_chart_bad(item: dict) -> bool:
    # CVC형: 고점은 가깝지만 저점 방어/돈 유지/재돌파 힘이 같이 좋으면
    # 버릴 후보가 아니라 내부 감시로 남긴다.
    try:
        if _is_near_high_rebreakout_watch(item):
            return False
        if _is_ultra_low_tick_noise_item(item):
            return True
        if _is_flash_low_liquidity_near_high(item):
            return True
    except Exception:
        pass
    chart_ctx = item.get("alert_chart_context", {}) if isinstance(item.get("alert_chart_context"), dict) else {}
    state_code = str(chart_ctx.get("chart_state_code", "") or "")
    if state_code in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
        return True
    if bool(item.get("box_stall_flag", False)) and safe_float(item.get("below_high", 999), 999) <= 0.95:
        return True
    if str(item.get("chart_quant_label", "") or "") in {"고점 근처 박스 횡보", "박스 횡보형"}:
        return True
    chart_gap = safe_float(item.get("chart_gap_pct", item.get("below_high", 999)), 999)
    chart_rise = safe_float(item.get("chart_rise_pct", item.get("from_low", 0)), 0)
    zone_ratio = safe_float(item.get("chart_zone_ratio", -1), -1)
    below_high = safe_float(item.get("below_high", 999), 999)
    from_low = safe_float(item.get("from_low", 0), 0)
    if 0 <= chart_gap <= 0.45:
        return True
    if chart_rise >= 4.2 and chart_gap < 1.6:
        return True
    if zone_ratio >= 0.88 and chart_gap < 1.2:
        return True
    if below_high <= 0.55 and from_low >= 1.20:
        return True
    if from_low >= 3.60 and below_high < 1.20:
        return True
    return False

def _fast_rescue_has_weak_reason(item: dict) -> bool:
    reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
    one_liner = str(item.get("one_liner", "") or "")
    text = " / ".join([str(x) for x in reasons[:5] if str(x).strip()] + [one_liner])
    weak_words = [
        "지금은 구경만",
        "지금 사기엔 별로",
        "이미 많이 올라와서 늦음",
        "고점이 너무 가까움",
        "차트 모양이 아직 별로",
        "재출발 힘이 아직 약함",
        "실시간 강세 초입으로 보기엔 아직 애매함",
        "초반 선점형으로 보기엔 아직 너무 약함",
        "막 힘 붙는 자리로 보기엔 아직 애매함",
        "초입 후보지만 아직 애매",
        "회복형인데 아직 힘 부족",
    ]
    if _fast_quality_rescue_ok(item):
        # 저점방어+돈유지가 충분하면 "고점이 너무 가까움" 같은 일반 약점만으로 rescue를 막지 않는다.
        text = text.replace("고점이 너무 가까움", "")
        text = text.replace("막 힘 붙는 자리로 보기엔 아직 애매함", "")
        text = text.replace("초입 후보지만 아직 애매", "")
    return any(word in text for word in weak_words)

def _fast_rescue_score(item: dict) -> float:
    lite_score = safe_float(item.get("lite_score", 0), 0)
    change_5 = safe_float(item.get("change_5", 0), 0)
    change_3 = safe_float(item.get("change_3", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    from_low = safe_float(item.get("from_low", 0), 0)
    quality_score, _quality_reasons = _fast_defense_money_quality(item)
    bonus = max(min(below_high, 3.2), 0) * 0.9
    penalty = max(from_low - 2.4, 0) * 1.4
    return round(
        lite_score
        + max(change_5, 0) * 2.8
        + max(change_3, 0) * 1.6
        + max(vol_ratio - 1.0, 0) * 2.2
        + leader_score * 1.7
        + max(quality_score, -1.5) * 1.15
        + bonus
        - penalty,
        2,
    )


def _fast_defense_money_quality(item: dict) -> tuple[float, list]:
    """저점방어 + 돈유지 2차 점수.
    거래량 배수만 크고 실제 돈이 작은 후보와, 실제 돈이 계속 붙는 초입 후보를 분리한다.
    """
    item = item if isinstance(item, dict) else {}
    score = 0.0
    reasons = []
    low_def = safe_float(item.get("low_zone_defense_score", item.get("recovery_quality_score", 0)), 0)
    recovery = safe_float(item.get("recovery_quality_score", 0), 0)
    stay = int(safe_float(item.get("low_zone_stay_bars", 0), 0))
    reclaim = int(safe_float(item.get("low_zone_reclaim_count", 0), 0))
    money = safe_float(item.get("turnover_persistence_score", 0), 0)
    ratio3 = safe_float(item.get("turnover_sustain_ratio_3v10", 0), 0)
    ratio5 = safe_float(item.get("turnover_sustain_ratio_5v20", 0), 0)
    keep5 = int(safe_float(item.get("turnover_keep_bars_5", 0), 0))
    keep10 = int(safe_float(item.get("turnover_keep_bars_10", 0), 0))
    turn5 = safe_float(item.get("turnover_5m", item.get("turnover_recent_5m", 0)), 0)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    flash = safe_float(item.get("turnover_flash_score", 0), 0)
    if low_def >= 1.10 or recovery >= 1.25:
        score += 1.1
        reasons.append("저점방어 좋음")
    elif low_def >= 0.80 or recovery >= 0.95:
        score += 0.55
        reasons.append("저점방어 보통")
    if stay >= 6 or reclaim >= 1:
        score += 0.75
        reasons.append("저점 안 깨고 버팀")
    elif stay >= 3:
        score += 0.35
    if money >= 1.40 or ratio3 >= 1.80 or ratio5 >= 1.80:
        score += 1.20
        reasons.append("돈유지 강함")
    elif money >= 0.90 or ratio3 >= 1.25 or ratio5 >= 1.25:
        score += 0.60
        reasons.append("돈유지 보통")
    if keep5 >= 3 or keep10 >= 5:
        score += 0.55
        reasons.append("거래대금 유지봉 있음")
    if turn5 >= 18_000_000:
        score += 0.60
        reasons.append("실제 거래대금 보강")
    elif turn5 < 5_000_000:
        score -= 0.75
        reasons.append("실제 돈 작음")
    if 0.20 <= from_low <= 2.25:
        score += 0.35
    elif from_low > 3.20 and below_high < 1.20:
        score -= 1.10
        reasons.append("저점대비 이미 높음")
    if below_high >= 1.00:
        score += 0.35
    elif below_high < 0.35 and not bool(item.get("near_high_rebreakout_watch", False)):
        score -= 1.15
        reasons.append("고점 너무 가까움")
    if flash <= -3.8 and turn5 < 12_000_000:
        score -= 0.90
        reasons.append("반짝형 의심")
    return round(score, 2), reasons[:5]


def _fast_quality_rescue_ok(item: dict) -> bool:
    q, _reasons = _fast_defense_money_quality(item)
    turn5 = safe_float(item.get("turnover_5m", item.get("turnover_recent_5m", 0)), 0)
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    if q >= 2.55 and turn5 >= 8_000_000 and below_high >= 0.90 and from_low <= 2.60 and chg30 >= -0.60 and chg5 >= -0.05:
        return True
    if q >= 3.20 and below_high >= 0.65 and turn5 >= 5_000_000 and from_low <= 2.20:
        return True
    return False


def _is_priority_market_row(row: dict) -> bool:
    """데이터 실패 재시도 우선순위.

    실패 종목을 계속 붙잡지는 않지만, 거래대금/시장주목이 살아 있는 종목은
    일반 실패 종목보다 빠르게 다시 확인한다.
    """
    row = row if isinstance(row, dict) else {}
    turnover_rank = int(safe_float(row.get("turnover_rank", 999), 999))
    surge_rank = int(safe_float(row.get("surge_rank", 999), 999))
    leader_score = safe_float(row.get("leader_score", 0), 0)
    turnover_recent = safe_float(row.get("turnover_recent", row.get("turnover", 0)), 0)
    vol_ratio = safe_float(row.get("vol_ratio", 0), 0)
    return (
        (0 < turnover_rank <= 25)
        or (0 < surge_rank <= 20)
        or leader_score >= 1.25
        or turnover_recent >= 20_000_000
        or vol_ratio >= 2.20
    )


def shorten_ohlcv_cooldown_for_priority(ticker: str, interval: str = "minute1", max_cooldown_sec: int = 8):
    """관심도 있는 실패 종목은 쿨다운을 짧게 줄여 다음 차수에서 빨리 재시도한다."""
    try:
        key = _ohlcv_fail_key(ticker, interval)
        row = API_OHLCV_FAIL_STATE.get(key)
        if not isinstance(row, dict):
            return
        now_ts = time.time()
        current_until = safe_float(row.get("cooldown_until", 0), 0)
        row["cooldown_until"] = min(current_until if current_until > 0 else now_ts + max_cooldown_sec, now_ts + max_cooldown_sec)
        row["priority_retry"] = True
        API_OHLCV_FAIL_STATE[key] = row
    except Exception:
        pass



def _is_snapshot_first_realtime_alert(item: dict) -> bool:
    """OHLCV 정밀분석 전에도 현재가 스냅샷만으로 잡아야 하는 ENSO류 급가속."""
    if not SNAPSHOT_FIRST_ALLOW_USER_ALERT:
        return False
    item = item if isinstance(item, dict) else {}
    if not (bool(item.get("snapshot_scan_only")) or bool(item.get("snapshot_engine_used")) or str(item.get("cache_source", "")).startswith("light_snapshot")):
        return False
    if bool(item.get("ultra_low_tick_noise_block", False)) or bool(item.get("flash_low_liquidity_near_high_block", False)):
        return False
    ch1 = safe_float(item.get("change_1", 0), 0)
    ch3 = safe_float(item.get("change_3", 0), 0)
    ch5 = safe_float(item.get("change_5", 0), 0)
    ch15 = safe_float(item.get("change_15", 0), 0)
    ch30 = safe_float(item.get("change_30", 0), 0)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    t3 = safe_float(item.get("turnover_3m", 0), 0)
    t5 = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0)
    t15 = safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0)
    turnover = max(t3, t5, t15, safe_float(item.get("turnover", 0), 0))
    # 급등 초입: 1/3/5분 중 하나가 확실히 튀거나, 5분+15분이 같이 살아나는 경우.
    fast_spike = (
        ch1 >= SNAPSHOT_FIRST_USER_ALERT_MIN_CHANGE1
        or ch3 >= SNAPSHOT_FIRST_USER_ALERT_MIN_CHANGE3
        or ch5 >= SNAPSHOT_FIRST_USER_ALERT_MIN_CHANGE5
        or (ch5 >= 1.35 and ch15 >= 2.40)
        or (ch3 >= 1.10 and ch5 >= 1.60 and ch30 >= 2.20)
    )
    money_ok = (
        t3 >= SNAPSHOT_FIRST_USER_ALERT_MIN_TURNOVER_3M
        or t5 >= SNAPSHOT_FIRST_USER_ALERT_MIN_TURNOVER_5M
        or t15 >= SNAPSHOT_FIRST_USER_ALERT_MIN_TURNOVER_15M
        or turnover >= SNAPSHOT_FIRST_USER_ALERT_MIN_TURNOVER_15M
    )
    not_too_late = from_low <= SNAPSHOT_FIRST_MAX_FROM_LOW_ALERT and ch30 <= SNAPSHOT_FIRST_MAX_30M_ALERT
    # 고점 바로 0.00%는 돌파 순간일 수도 있어 무조건 차단하지 않는다. 대신 너무 오른 자리만 차단.
    if below_high <= 0.05 and from_low >= 9.0 and ch5 < 2.0:
        not_too_late = False
    return bool(fast_spike and money_ok and not_too_late)

def _promote_lite_item_display_safety(item: dict) -> dict:
    """3분봉 기반 가벼운 후보는 사용자 알림으로 바로 올리지 않는다.

    minute1 정밀 데이터가 붙기 전에는 '미리 보는 후보'까지만 허용한다.
    """
    item = item if isinstance(item, dict) else {}
    if bool(item.get("snapshot_realtime_alert", False)):
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        if "OHLCV 전 스냅샷 급등 감지" not in reasons:
            reasons.insert(0, "OHLCV 전 스냅샷 급등 감지")
        item["reasons"] = reasons[:6]
        return item
    if not item.get("lite_scan_only"):
        return item
    item["fast_scan_source"] = item.get("fast_scan_source") or "df3_lite"
    if not FAST_SCAN_LITE_ALLOW_USER_ALERT and str(item.get("alert_bucket", "")) == "user_alert":
        item["alert_bucket"] = "internal_watch"
        item["alert_grade"] = "B" if str(item.get("alert_grade", "C")) in {"S", "A"} else str(item.get("alert_grade", "C") or "C")
        item["bucket_rank"] = 2
        item["quality_block_reason"] = "3분봉 기반 가벼운 후보라 1분봉 확인 전 알림 보류"
    reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
    if "3분봉 기준 가벼운 1차 후보" not in reasons:
        reasons.append("3분봉 기준 가벼운 1차 후보")
    item["reasons"] = reasons[:6]
    one = str(item.get("one_liner", "") or "")
    if one and "1분봉 확인 전" not in one and "지금 사기엔 별로" not in one:
        item["one_liner"] = one + " / 1분봉 확인 전이라 알림은 보류"
    return item

def _build_fast_scan_item(ticker: str, data: dict):
    if not ticker or not isinstance(data, dict):
        return None
    item = dict(data)
    item.setdefault("ticker", str(ticker).upper().strip())
    price = safe_float(item.get("price", item.get("current_price", 0)), 0)
    try:
        item = apply_light_snapshot_metrics_to_item(item)
        price = safe_float(item.get("price", item.get("current_price", price)), price)
    except Exception:
        pass
    df1 = item.get("df_1m")
    if df1 is None or len(df1) < 12:
        # v2.5.148: fast scan은 네트워크를 직접 두드리지 않는다.
        # 대신 3분봉 유니버스 데이터가 있으면 가벼운 1차 후보로만 처리한다.
        # 이 후보는 사용자 알림으로 바로 올리지 않고, minute1 정밀 캐시가 붙으면 승격된다.
        df3_lite = item.get("df_3m")
        pseudo_df = build_light_snapshot_pseudo_df(ticker, price=price) if LIGHT_SNAPSHOT_ENGINE_ON else None
        if pseudo_df is not None and len(pseudo_df) >= 12:
            df1 = pseudo_df
            item["lite_scan_only"] = True
            item["snapshot_scan_only"] = True
            item["fast_scan_source"] = "light_snapshot"
        elif FAST_SCAN_LITE_FALLBACK_ENABLED and df3_lite is not None and len(df3_lite) >= 12:
            df1 = df3_lite
            item["lite_scan_only"] = True
            item["fast_scan_source"] = "df3_lite"
        elif FAST_SCAN_CACHE_ONLY:
            item["fast_scan_skip_reason"] = "df_1m_cache_missing"
            return None
        else:
            df1 = get_ohlcv(ticker, "minute1")
    if df1 is None or len(df1) < 12:
        return None
    if price <= 0:
        price = safe_float(df1["close"].iloc[-1], 0)
    if price <= 0:
        return None

    snap = compute_pre_alert_snapshot_from_df(df1, current_price=price)
    turnover = compute_fast_scan_turnover_metrics(df1, price=price)
    item.update({
        "ticker": str(ticker).upper().strip(),
        "price": price,
        "current_price": price,
        "change_1": safe_float(item.get("change_1", get_recent_change_pct(df1, 2)), 0),
        "change_3": safe_float(item.get("change_3", get_recent_change_pct(df1, 3)), 0),
        "change_5": safe_float(item.get("change_5", get_recent_change_pct(df1, 5)), 0),
        "change_15": safe_float(item.get("change_15", get_recent_change_pct(df1, 15)), 0),
        "change_30": safe_float(snap.get("chg_30m", item.get("change_30", get_recent_change_pct(df1, 30))), 0),
        "change_60": safe_float(item.get("change_60", get_recent_change_pct(df1, 60)), 0),
        "vol_ratio": safe_float(item.get("vol_ratio", item.get("vol_ratio_1m", get_vol_ratio(df1, 3, 15))), 0),
        "leader_score": safe_float(item.get("leader_score", 0), 0),
        "rsi": safe_float(item.get("rsi", item.get("rsi_1m", get_rsi(df1, 14))), 0),
        "from_low": safe_float(snap.get("from_30m_low_pct", 0), 0),
        "below_high": safe_float(snap.get("below_30m_high_pct", 999), 999),
        "turnover_1m": safe_float(turnover.get("turnover_1m", 0), 0),
        "turnover_3m": safe_float(turnover.get("turnover_3m", 0), 0),
        "turnover_5m": safe_float(turnover.get("turnover_5m", 0), 0),
        "turnover_15m": safe_float(turnover.get("turnover_15m", item.get("turnover", 0)), item.get("turnover", 0)),
        "pre_alert_snapshot": snap,
    })
    try:
        item = apply_light_snapshot_metrics_to_item(item)
    except Exception:
        pass
    section, primary_reason, reasons = classify_fast_scan_alert_section(
        item.get("change_5", 0),
        item.get("change_3", 0),
        item.get("vol_ratio", 0),
        item.get("leader_score", 0),
        item.get("from_low", 0),
        item.get("below_high", 999),
        item.get("rsi", 0),
    )
    item["section"] = section
    item["primary_reason"] = primary_reason
    item["reasons"] = list(reasons or [])
    item = refine_fast_scan_item_with_chart(item, df1)
    item = _apply_fast_candidate_quality_refinements(item)
    hot_ignition_score = _hot_ignition_score(item)
    item["hot_ignition_score"] = hot_ignition_score
    if _is_hot_ignition_watch(item) and not bool(item.get("ultra_low_tick_noise_block", False)) and not bool(item.get("flash_low_liquidity_near_high_block", False)):
        # 24H 인기검색에 뜬 뒤가 아니라 3~30분 가속 초입에서 별도 감시층으로 살린다.
        item["section"] = "strong" if _is_hot_ignition_user_alert(item) else "watch"
        item["primary_reason"] = "실시간 폭발 초입 후보"
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        if "1시간 급등 전 초입 감시" not in reasons:
            reasons.insert(0, "1시간 급등 전 초입 감시")
        item["reasons"] = reasons[:6]

    # v2.5.155: 빗썸 1시간 상승률 상위에 뜨기 전 중간 가속 후보.
    # 기존 실시간 폭발 초입보다 느리지만 15/30/60분 축적이 살아 있는 애를 감시판으로 끌어온다.
    if _is_hourly_momentum_watch(item) and not bool(item.get("ultra_low_tick_noise_block", False)) and not bool(item.get("flash_low_liquidity_near_high_block", False)):
        item["hourly_momentum_score"] = _hourly_momentum_score(item)
        if str(item.get("primary_reason", "")) not in {"실시간 폭발 초입 후보"}:
            item["section"] = "strong" if _is_hourly_momentum_user_alert(item) else "watch"
            item["primary_reason"] = "1시간 급등 초입 후보"
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        if "1시간 급등판 전 중간 가속 감시" not in reasons:
            reasons.insert(0, "1시간 급등판 전 중간 가속 감시")
        item["reasons"] = reasons[:6]

    lite_score = (
        max(safe_float(item.get("change_5", 0), 0), 0) * 5.2
        + max(safe_float(item.get("change_3", 0), 0), 0) * 2.6
        + max(safe_float(item.get("vol_ratio", 0), 0) - 1.0, 0) * 4.0
        + safe_float(item.get("leader_score", 0), 0) * 3.0
        + max(safe_float(item.get("from_low", 0), 0), 0) * 1.5
        + max(min(safe_float(item.get("below_high", 999), 999), 3.0), 0) * 1.1
        + (1.2 if fast_scan_turnover_gate(item, level="watch") else 0.0)
        + (2.0 if str(item.get("section", "") or "") == "strong" else 0.8 if str(item.get("section", "") or "") == "watch" else 0.0)
        + safe_float(item.get("hot_ignition_score", 0), 0) * 0.55
        + safe_float(item.get("hourly_momentum_score", 0), 0) * 0.42
    )
    if _fast_chart_bad(item):
        lite_score -= 3.5
    if bool(item.get("low_actual_turnover_flag", False)) and safe_float(item.get("vol_ratio", 0), 0) >= 4.0:
        lite_score -= 2.0
    if bool(item.get("flash_low_liquidity_near_high_block", False)):
        lite_score -= 4.0
    if bool(item.get("ultra_low_tick_noise_block", False)):
        lite_score -= 12.0
    item["lite_score"] = round(max(lite_score, 0.0), 2)

    grade, bucket = classify_fast_scan_grade_bucket(
        str(item.get("section", "") or ""),
        str(item.get("primary_reason", "") or ""),
        safe_float(item.get("change_5", 0), 0),
        safe_float(item.get("change_3", 0), 0),
        safe_float(item.get("vol_ratio", 0), 0),
        safe_float(item.get("leader_score", 0), 0),
        safe_float(item.get("from_low", 0), 0),
        safe_float(item.get("below_high", 999), 999),
        safe_float(item.get("rsi", 0), 0),
        safe_float(item.get("lite_score", 0), 0),
        item,
    )
    # v2.5.226: grade/bucket 계산 직후에도 한 번 더 보정한다.
    flow_block_reason_v226 = get_fast_scan_user_alert_flow_block_reason_v226(item, section=str(item.get("section", "") or ""), primary_reason=str(item.get("primary_reason", "") or ""))
    if bucket == "user_alert" and flow_block_reason_v226:
        item = demote_fast_scan_user_alert_v226(item, flow_block_reason_v226)
        grade = str(item.get("alert_grade", "B") or "B")
        bucket = "internal_watch"

    if _is_snapshot_first_realtime_alert(item):
        item["snapshot_realtime_alert"] = True
        item["section"] = "strong"
        item["primary_reason"] = "실시간 급등 감지 후보"
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        if "현재가 스냅샷 급가속" not in reasons:
            reasons.insert(0, "현재가 스냅샷 급가속")
        item["reasons"] = reasons[:6]
        grade = "A" if safe_float(item.get("change_5", 0), 0) < 4.5 else "S"
        bucket = "user_alert"

    # v2.5.196: PEAQ/ZBT처럼 순위권 강세를 본 코인은 복기용에서 멈추지 않고 내부 감시 후보로 한 번 더 올린다.
    # 단, 바로 사용자 알림으로 강제승격하지는 않는다. 돈/차트 정밀 확인이 붙은 뒤 알림 여부를 판단한다.
    if bucket != "user_alert" and is_realtime_rank_precision_candidate(item):
        item["rank_precision_watch"] = True
        item["rank_watch_action"] = "정밀검토 대기"
        if str(item.get("section", "") or "") != "strong":
            item["section"] = "watch"
        item["primary_reason"] = "순위권 정밀검토 후보"
        item["precision_stage"] = "순위권 강세 → 내부감시 정밀검토"
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        for _r in ["순위권 강세라 정밀검토 대기", "거래대금/차트 확인 전이라 알림은 보류"]:
            if _r not in reasons:
                reasons.insert(0, _r)
        item["reasons"] = reasons[:6]
        grade = "B" if str(grade or "C") == "C" else grade
        bucket = "internal_watch"
    item["alert_grade"] = grade
    item["alert_bucket"] = bucket
    item["label_text"] = get_fast_scan_label_text(str(item.get("primary_reason", "") or ""))
    item["user_label_text"] = get_fast_scan_user_label_text(str(item.get("primary_reason", "") or ""))
    item["alert_header_text"] = get_fast_scan_alert_header_text(str(item.get("primary_reason", "") or ""))
    item["one_liner"] = build_fast_scan_one_liner(
        str(item.get("primary_reason", "") or ""),
        safe_float(item.get("from_low", 0), 0),
        safe_float(item.get("below_high", 999), 999),
        grade=grade,
        bucket=bucket,
        item=item,
    )
    final_gate_reason_v227 = get_user_alert_final_gate_block_reason_v227(item, section=str(item.get("section", "") or ""), primary_reason=str(item.get("primary_reason", "") or ""))
    if bucket == "user_alert" and final_gate_reason_v227:
        item = apply_user_alert_final_gate_demote_v227(item, final_gate_reason_v227)
        grade = str(item.get("alert_grade", "B") or "B")
        bucket = str(item.get("alert_bucket", "internal_watch") or "internal_watch")
    item["bucket_rank"] = 3 if bucket == "user_alert" else 2 if bucket == "internal_watch" else 1
    item["section_rank"] = 3 if str(item.get("section", "")) == "strong" else 2 if str(item.get("section", "")) == "watch" else 1
    item = _promote_lite_item_display_safety(item)
    item = _mark_candidate_precision_gate(item)
    return item

def _friendly_fast_stage_text(stage: str) -> str:
    key = str(stage or "").strip()
    mapping = {
        "scan_watchlist_fast": "빠른 후보 고르는 중",
        "scan_watchlist_done": "빠른 후보 정리 완료",
        "scan_watchlist_empty": "시장 데이터 기다리는 중",
        "scan_watchlist_empty_done": "시장 데이터 없음 처리 완료",
        "fetch_tickers": "거래 코인 목록 새로 받는 중",
        "build_universe": "시장 유니버스 다시 만드는 중",
        "build_cache": "시장 캐시 다시 만드는 중",
    }
    if key in mapping:
        return mapping[key]
    return key.replace("_", " ")

def build_fast_scan_alert_markup(ticker: str, ref_id: str = ""):
    rows = [[InlineKeyboardButton(f"{str(ticker or '').upper()} 빗썸 열기", url=get_bithumb_chart_url(ticker))]]
    if ref_id:
        rows.append([
            InlineKeyboardButton("지금", callback_data=f"pc:{ref_id}:now"),
            InlineKeyboardButton("15분뒤", callback_data=f"pc:{ref_id}:15"),
            InlineKeyboardButton("30분뒤", callback_data=f"pc:{ref_id}:30"),
        ])
    return InlineKeyboardMarkup(rows)

def schedule_fast_scan_auto_check(ref_id: str, chat_id: str, target_min: int = 30, now_ts: float = None):
    if not ref_id:
        return
    now_ts = safe_float(now_ts, time.time())
    key = f"{ref_id}:{int(target_min)}"
    PRICE_CHECK_SCHEDULED[key] = {
        "ref_id": ref_id,
        "chat_id": chat_id,
        "target_min": int(target_min),
        "target_ts": now_ts + int(target_min) * 60,
    }
    persist_price_check_state()

