# v2.5.201: 순위권 거래대금 실제 검증 보조 함수
def _rank_turnover_state() -> dict:
    state = globals().setdefault("REALTIME_RANK_TURNOVER_VERIFY_STATE", {})
    if not isinstance(state, dict):
        globals()["REALTIME_RANK_TURNOVER_VERIFY_STATE"] = {}
        state = globals()["REALTIME_RANK_TURNOVER_VERIFY_STATE"]
    return state


def _rank_turnover_queue() -> list:
    q = globals().setdefault("REALTIME_RANK_TURNOVER_VERIFY_QUEUE", [])
    if not isinstance(q, list):
        globals()["REALTIME_RANK_TURNOVER_VERIFY_QUEUE"] = []
        q = globals()["REALTIME_RANK_TURNOVER_VERIFY_QUEUE"]
    return q


def _compute_turnover_from_minute_df(df) -> dict:
    out = {"turnover_1m": 0.0, "turnover_3m": 0.0, "turnover_5m": 0.0, "turnover_15m": 0.0, "rows": 0, "price": 0.0, "volume_sum_5m": 0.0, "nonzero_volume_rows_5m": 0}
    try:
        if df is None or len(df) < 1:
            return out
        close = df["close"].astype(float)
        volume = df["volume"].astype(float).fillna(0) if "volume" in df.columns else None
        if volume is None or close.empty:
            return out
        out["rows"] = int(len(df))
        out["price"] = safe_float(close.iloc[-1], 0)
        def _sum_tail(n: int) -> float:
            try:
                sub = df.tail(min(len(df), max(1, int(n))))
                return float((sub["close"].astype(float) * sub["volume"].astype(float).fillna(0)).sum())
            except Exception:
                return 0.0
        out["turnover_1m"] = max(0.0, _sum_tail(1))
        out["turnover_3m"] = max(0.0, _sum_tail(3))
        out["turnover_5m"] = max(0.0, _sum_tail(5))
        out["turnover_15m"] = max(0.0, _sum_tail(15))
        try:
            sub5 = df.tail(min(len(df), 5))
            vols5 = sub5["volume"].astype(float).fillna(0)
            out["volume_sum_5m"] = max(0.0, float(vols5.sum()))
            out["nonzero_volume_rows_5m"] = int((vols5 > 0).sum())
        except Exception:
            pass
    except Exception:
        return out
    return out


def _save_verified_turnover_state(ticker: str, data: dict):
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker:
            return
        data = data if isinstance(data, dict) else {}
        data["ticker"] = ticker
        data["updated_at"] = time.time()
        with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
            _rank_turnover_state()[ticker] = data
    except Exception:
        pass


def get_cached_verified_turnover_for_ticker(ticker: str) -> dict:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return {}
    now_ts = time.time()
    ttl = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC", 600), 600)
    try:
        with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
            row = _rank_turnover_state().get(ticker)
            if isinstance(row, dict) and now_ts - safe_float(row.get("updated_at", 0), 0) <= ttl:
                return dict(row)
    except Exception:
        pass
    # 네트워크 호출 없이 이미 쌓인 minute1 캐시만 사용한다.
    try:
        cached = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1") * 3, copy_dataframe=True)
        if cached is not None:
            vals = _compute_turnover_from_minute_df(cached)
            if int(vals.get("rows", 0)) > 0:
                vals.update({"status": "ok", "source": "minute1_cache", "verified": True})
                _save_verified_turnover_state(ticker, vals)
                return vals
    except Exception:
        pass
    return {}


def apply_verified_turnover_to_row(row: dict) -> dict:
    if not isinstance(row, dict):
        return row
    try:
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return row
        info = get_cached_verified_turnover_for_ticker(ticker)
        if not isinstance(info, dict) or not info:
            return row
        status = str(info.get("status", "") or "").lower().strip()
        row["turnover_verify_status"] = status or row.get("turnover_verify_status", "")
        row["turnover_verified_ts"] = safe_float(info.get("updated_at", 0), 0)
        row["turnover_verify_requested_ts"] = safe_float(info.get("requested_at", row.get("turnover_verify_requested_ts", 0)), 0)
        row["turnover_verify_source"] = str(info.get("source", "") or row.get("turnover_verify_source", ""))
        row["turnover_verify_reason"] = str(info.get("reason", "") or row.get("turnover_verify_reason", ""))
        row["turnover_verify_fail_detail"] = str(info.get("fail_detail", "") or row.get("turnover_verify_fail_detail", ""))
        if status in {"suspect", "volume_suspect", "retry"}:
            row["turnover_verified"] = False
            row["actual_turnover_verified"] = False
            row["turnover_unknown_snapshot"] = True
            row["snapshot_turnover_unknown"] = True
            return row
        if status == "ok" or bool(info.get("verified", False)):
            t1 = safe_float(info.get("turnover_1m", 0), 0)
            t3 = safe_float(info.get("turnover_3m", 0), 0)
            t5 = safe_float(info.get("turnover_5m", 0), 0)
            t15 = safe_float(info.get("turnover_15m", 0), 0)
            row["turnover_verified"] = True
            row["actual_turnover_verified"] = True
            # v2.5.202: 검증값은 authoritative로 통일한다. 예전처럼 max()로 섞으면
            # 같은 코인이 섹션마다 1,164만/465만/308원처럼 다르게 보일 수 있다.
            row["turnover_recent_1m"] = t1
            row["turnover_recent_3m"] = t3
            row["turnover_5m"] = t5
            row["turnover"] = t5
            row["turnover_15m"] = t15
            row["turnover_unknown_snapshot"] = False
            row["snapshot_turnover_unknown"] = False
        return row
    except Exception:
        return row



def _rank_reuse_fail(reason: str):
    try:
        reason = str(reason or "unknown")[:40]
        d = globals().setdefault("RANK_STATE_REUSE_FAIL_REASONS", {})
        if not isinstance(d, dict):
            globals()["RANK_STATE_REUSE_FAIL_REASONS"] = {}
            d = globals()["RANK_STATE_REUSE_FAIL_REASONS"]
        d[reason] = int(safe_float(d.get(reason, 0), 0)) + 1
    except Exception:
        pass


def reset_rank_reuse_fail_reasons():
    try:
        globals()["RANK_STATE_REUSE_FAIL_REASONS"] = {}
    except Exception:
        pass


def _precision_minute1_fetch_quota_open(now_ts: float = None) -> bool:
    try:
        now_ts = safe_float(now_ts, time.time())
        arr = globals().setdefault("PRECISION_MINUTE1_FETCH_TIMES", [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= 60]
        globals()["PRECISION_MINUTE1_FETCH_TIMES"] = arr
        return len(arr) < int(safe_float(globals().get("PRECISION_MINUTE1_MAX_FETCH_PER_MIN", 5), 5))
    except Exception:
        return False


def _precision_minute1_record_fetch(now_ts: float = None):
    try:
        now_ts = safe_float(now_ts, time.time())
        arr = globals().setdefault("PRECISION_MINUTE1_FETCH_TIMES", [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= 60]
        arr.append(now_ts)
        globals()["PRECISION_MINUTE1_FETCH_TIMES"] = arr[-30:]
    except Exception:
        pass


def _precision_minute1_global_cooldown_left(now_ts: float = None) -> float:
    try:
        now_ts = safe_float(now_ts, time.time())
        return max(0.0, safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_CIRCUIT_UNTIL", 0.0), 0.0) - now_ts)
    except Exception:
        return 0.0


def _precision_minute1_note_timeout(now_ts: float = None):
    try:
        now_ts = safe_float(now_ts, time.time())
        window = max(60.0, safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_CIRCUIT_WINDOW_SEC", 300), 300))
        arr = globals().setdefault("PRECISION_MINUTE1_TIMEOUT_TIMES", [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= window]
        arr.append(now_ts)
        globals()["PRECISION_MINUTE1_TIMEOUT_TIMES"] = arr[-20:]
        limit = int(safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_CIRCUIT_FAIL_LIMIT", 4), 4))
        if len(arr) >= max(1, limit):
            cd = max(120.0, safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_CIRCUIT_COOLDOWN_SEC", 900), 900))
            globals()["PRECISION_MINUTE1_TIMEOUT_CIRCUIT_UNTIL"] = now_ts + cd
            globals()["PRECISION_MINUTE1_TIMEOUT_CIRCUIT_REASON"] = f"minute1 timeout {len(arr)}건/{int(window)}초"
            try:
                append_runtime_event_log("precision_minute1_timeout_circuit", "정밀 1분봉 timeout이 몰려 REST 검증만 잠깐 중단", extra={"count": len(arr), "window": int(window), "cooldown_sec": int(cd)})
            except Exception:
                pass
    except Exception:
        pass


def _precision_minute1_state_dict() -> dict:
    d = globals().setdefault("PRECISION_MINUTE1_STATE", {})
    if not isinstance(d, dict):
        globals()["PRECISION_MINUTE1_STATE"] = {}
        d = globals()["PRECISION_MINUTE1_STATE"]
    return d



def _precision_minute1_cooldown_dict() -> dict:
    d = globals().setdefault("PRECISION_MINUTE1_COOLDOWN_BY_TICKER", {})
    if not isinstance(d, dict):
        globals()["PRECISION_MINUTE1_COOLDOWN_BY_TICKER"] = {}
        d = globals()["PRECISION_MINUTE1_COOLDOWN_BY_TICKER"]
    return d


def _precision_minute1_reject(reason: str, ticker: str = "", profile: dict = None):
    try:
        reason = str(reason or "unknown")[:60]
        d = globals().setdefault("PRECISION_MINUTE1_QUEUE_REJECT_REASONS", {})
        if not isinstance(d, dict):
            d = {}
            globals()["PRECISION_MINUTE1_QUEUE_REJECT_REASONS"] = d
        d[reason] = int(safe_float(d.get(reason, 0), 0)) + 1
        globals()["PRECISION_MINUTE1_QUEUE_REJECT_COUNT"] = int(safe_float(globals().get("PRECISION_MINUTE1_QUEUE_REJECT_COUNT", 0), 0)) + 1
        globals()["PRECISION_MINUTE1_QUEUE_LAST_DECISION"] = f"거절:{reason} {ticker or ''}"[:120]
        if isinstance(profile, dict):
            globals()["PRECISION_MINUTE1_QUEUE_LAST_PROFILE"] = dict(profile)
    except Exception:
        pass


def _precision_minute1_accept(ticker: str = "", profile: dict = None):
    try:
        globals()["PRECISION_MINUTE1_QUEUE_ACCEPT_COUNT"] = int(safe_float(globals().get("PRECISION_MINUTE1_QUEUE_ACCEPT_COUNT", 0), 0)) + 1
        globals()["PRECISION_MINUTE1_QUEUE_LAST_DECISION"] = f"등록:{ticker or '-'}"
        if isinstance(profile, dict):
            globals()["PRECISION_MINUTE1_QUEUE_LAST_PROFILE"] = dict(profile)
    except Exception:
        pass


def _precision_minute1_set_cooldown(ticker: str, sec: float, reason: str = ""):
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker:
            return
        sec = max(0.0, safe_float(sec, 0))
        d = _precision_minute1_cooldown_dict()
        d[ticker] = {"until": time.time() + sec, "reason": str(reason or "cooldown")[:80], "sec": sec, "ts": time.time()}
        now_ts = time.time()
        for k, v in list(d.items()):
            if not isinstance(v, dict) or safe_float(v.get("until", 0), 0) + 60 < now_ts:
                d.pop(k, None)
    except Exception:
        pass


def _precision_minute1_cooldown_remaining(ticker: str, now_ts: float = None) -> float:
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker:
            return 0.0
        now_ts = safe_float(now_ts, time.time())
        d = _precision_minute1_cooldown_dict()
        row = d.get(ticker)
        if not isinstance(row, dict):
            return 0.0
        remain = safe_float(row.get("until", 0), 0) - now_ts
        if remain <= 0:
            d.pop(ticker, None)
            return 0.0
        return remain
    except Exception:
        return 0.0


def precision_minute1_candidate_profile_v249(row: dict, reason: str = "") -> dict:
    """v2.5.249: REST minute1로 가기 전에 WebSocket/스냅샷으로 자격심사한다."""
    try:
        row = row if isinstance(row, dict) else {}
        reason = str(reason or "")
        ticker = str(row.get("ticker", "") or "").upper().strip()
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", row.get("score", 0))), 0)
        app_windows = int(safe_float(row.get("app_compare_window_count", 0), 0))
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        strongest = max(ch3, ch5, ch15, safe_float(row.get("change_30", 0), 0), safe_float(row.get("change_1", 0), 0))
        turnover = max(
            safe_float(row.get("turnover_5m", 0), 0), safe_float(row.get("turnover", 0), 0),
            safe_float(row.get("turnover_recent_5m", 0), 0), safe_float(row.get("recent_5m_turnover", 0), 0),
            safe_float(row.get("ws_trade_amount_60s", 0), 0),
        )
        ws_cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        ws_buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        ws_amount = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        ws_good = ws_cnt >= 5 and ws_buy >= safe_float(globals().get("PRECISION_MINUTE1_GOOD_BUY_RATIO", 55.0), 55.0) and ws_amount >= safe_float(globals().get("PRECISION_MINUTE1_MIN_WS_AMOUNT", 800_000), 800_000)
        sell_heavy = ws_cnt >= 5 and 0 < ws_buy <= safe_float(globals().get("PRECISION_MINUTE1_SELL_HEAVY_BUY_RATIO", 45.0), 45.0)
        try:
            sustain = classify_money_sustain_for_row(row) if 'classify_money_sustain_for_row' in globals() else {}
            sustain_label = str((sustain or {}).get("label", row.get("money_sustain_label", "")) or "")
            if "매도우세" in sustain_label:
                sell_heavy = True
        except Exception:
            sustain_label = str(row.get("money_sustain_label", "") or "")
        try:
            money_code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
        except Exception:
            money_code = "unknown"
        money_text = str(row.get("money_status_text", row.get("money_status", "")) or "")
        money_weak = money_code in {"actual_zero", "tiny", "thin"} or "돈얇" in money_text or "실제돈작음" in money_text
        current_label = str(row.get("current_candle_label", row.get("current_candle_code", "")) or "")
        try:
            current_weak = bool(is_current_candle_weak_for_label_v244(row)) if 'is_current_candle_weak_for_label_v244' in globals() else False
        except Exception:
            current_weak = False
        if "밀림" in current_label or "위꼬리" in current_label:
            current_weak = True
        rank_action = str(row.get("rank_watch_action", row.get("final_decision", row.get("final_class", ""))) or "")
        review_only = "복기" in rank_action or "움직임만 기록" in rank_action
        internal_reason = "internal_watch" in reason
        low_structure = False
        try:
            low_structure = bool(low_defense_structure_route_is_good_v248(row)) if 'low_defense_structure_route_is_good_v248' in globals() else False
        except Exception:
            low_structure = False
        high_near = 0 <= safe_float(row.get("below_30m_high_pct", row.get("below_high", 999)), 999) <= 0.35
        priority = score
        if internal_reason: priority += 2.0
        if app_windows >= 2: priority += 1.2 + min(app_windows, 5) * 0.25
        if ws_good: priority += 2.2
        if turnover >= safe_float(globals().get("PRECISION_MINUTE1_MIN_GOOD_TURNOVER", 10_000_000), 10_000_000): priority += 1.5
        if low_structure: priority += 1.0
        if high_near: priority += 0.3
        if sell_heavy: priority -= 2.0
        if current_weak: priority -= 1.2
        if money_weak: priority -= 2.0
        if review_only and not internal_reason: priority -= 1.5
        block_reasons = []
        if money_weak and not (ws_good and app_windows >= 3 and score >= 8.0): block_reasons.append("money_weak")
        if sell_heavy and not (turnover >= 50_000_000 and app_windows >= 3): block_reasons.append("sell_heavy")
        if current_weak and money_weak: block_reasons.append("weak_candle_money_weak")
        if review_only and not internal_reason and score < 8.0: block_reasons.append("review_only_low_score")
        if score < safe_float(globals().get("PRECISION_MINUTE1_MIN_ACCEPT_SCORE", 5.5), 5.5) and app_windows < 2 and not internal_reason: block_reasons.append("low_score")
        allowed = not block_reasons
        if internal_reason and (ws_good or turnover >= safe_float(globals().get("PRECISION_MINUTE1_MIN_GOOD_TURNOVER", 30_000_000), 30_000_000) or (app_windows >= 3 and not money_weak) or (low_structure and not money_weak)) and not (sell_heavy and money_weak):
            allowed = True
            # v2.5.252: 내부감시라도 돈얇음/실제돈작음은 REST minute1 우선권을 쉽게 주지 않는다.
            # WebSocket 매수세가 확실하거나 대금이 충분할 때만 low_score류를 풀고, 나머지는 스냅샷 보조 상태로 둔다.
            block_reasons = [x for x in block_reasons if x not in {"review_only_low_score", "low_score"}]
            if money_weak and (ws_good or turnover >= safe_float(globals().get("PRECISION_MINUTE1_MIN_GOOD_TURNOVER", 30_000_000), 30_000_000)):
                block_reasons = [x for x in block_reasons if x != "money_weak"]
                allowed = not block_reasons
        return {"ticker": ticker, "allowed": bool(allowed), "priority": round(float(priority), 3), "score": round(float(score), 3), "strongest": strongest, "turnover": turnover, "ws_count": ws_cnt, "ws_buy": ws_buy, "ws_amount": ws_amount, "ws_good": ws_good, "sell_heavy": sell_heavy, "money_code": money_code, "money_weak": money_weak, "current_weak": current_weak, "app_windows": app_windows, "review_only": review_only, "low_structure": low_structure, "reason": reason, "block_reasons": block_reasons, "decision": "allow" if allowed else "/".join(block_reasons[:3]) or "blocked"}
    except Exception as e:
        return {"allowed": False, "priority": 0.0, "decision": f"profile_error:{e.__class__.__name__}"}


def record_rank_negative_age_sample_v249(ticker: str, now_ts: float, updated_ts: float, computed_ts: float = 0.0, snapshot_ts: float = 0.0, source: str = ""):
    try:
        arr = globals().setdefault("RANK_STATE_NEGATIVE_AGE_SAMPLES", [])
        if not isinstance(arr, list): arr = []
        src = str(source or "rank_state")[:40]
        age = round(safe_float(now_ts, 0) - safe_float(updated_ts, 0), 3)
        kind = "stale_build_clock" if src == "stale_build_now" else "true_negative_age"
        arr.append({"ticker": str(ticker or "")[:16], "now_ts": round(safe_float(now_ts, 0), 3), "updated_ts": round(safe_float(updated_ts, 0), 3), "computed_ts": round(safe_float(computed_ts, 0), 3), "snapshot_ts": round(safe_float(snapshot_ts, 0), 3), "age": age, "source": src, "kind": kind})
        globals()["RANK_STATE_NEGATIVE_AGE_SAMPLES"] = arr[-5:]
    except Exception:
        pass

def store_precision_minute1_chart_state(ticker: str, df=None, source: str = "minute1_ohlcv", reason: str = "worker", row_hint: dict = None) -> dict:
    """v2.5.247: minute1 df를 대금확인에만 쓰지 않고 저점방어/현재봉 상태로 저장한다."""
    global PRECISION_MINUTE1_DONE, PRECISION_MINUTE1_FAIL, PRECISION_MINUTE1_LAST_ITEM, PRECISION_MINUTE1_LAST_RESULT, PRECISION_MINUTE1_LAST_UPDATED_TS
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return {}
    now_ts = time.time()
    row_hint = row_hint if isinstance(row_hint, dict) else {}
    state = {"ticker": ticker, "updated_ts": now_ts, "reason": str(reason or "worker")[:80]}
    try:
        price = safe_float(row_hint.get("price", row_hint.get("current_price", 0)), 0)
        if df is not None and len(df) >= 4:
            try:
                price = safe_float(df["close"].iloc[-1], price)
            except Exception:
                pass
            state.update({
                "precision_chart_source": str(source or "minute1_ohlcv"),
                "precision_chart_verified": True,
                "precision_minute1_verified": True,
                "sample_candles_1m": int(len(df)),
                "minute1_candles": int(len(df)),
                "precision_chart_updated_ts": now_ts,
            })
            try:
                low_ctx = compute_low_defense_context_v195(df, current_price=price)
                if isinstance(low_ctx, dict):
                    state.update(low_ctx)
            except Exception as e:
                state["precision_low_error"] = str(e)[:80]
            try:
                candle_ctx = compute_current_candle_context_from_df(df, current_price=price)
                if isinstance(candle_ctx, dict):
                    state.update(candle_ctx)
                    state["body_ratio_1"] = safe_float(candle_ctx.get("current_candle_body_ratio", 0), 0)
                    state["close_pos_1"] = safe_float(candle_ctx.get("current_candle_close_pos_ratio", 0), 0)
                    state["upper_wick_pct_1"] = safe_float(candle_ctx.get("current_candle_upper_wick_pct", 0), 0)
                    state["lower_wick_pct_1"] = safe_float(candle_ctx.get("current_candle_lower_wick_pct", 0), 0)
                    state["body_ratio_3"] = safe_float(candle_ctx.get("current_candle_recent_body_ratio", 0), 0)
                    state["upper_wick_pct_3"] = safe_float(candle_ctx.get("current_candle_recent_upper_wick_pct", 0), 0)
                    state["lower_wick_pct_3"] = safe_float(candle_ctx.get("current_candle_recent_lower_wick_pct", 0), 0)
            except Exception as e:
                state["precision_candle_error"] = str(e)[:80]
            try:
                snap = compute_pre_alert_snapshot_from_df(df, current_price=price)
                if isinstance(snap, dict):
                    for k, v in snap.items():
                        if k not in state:
                            state[k] = v
            except Exception:
                pass
            state["price"] = price
            state["current_price"] = price
            try:
                qrow = dict(row_hint or {})
                qrow.update(state)
                qrow = apply_low_defense_quality_v248(qrow) if 'apply_low_defense_quality_v248' in globals() else qrow
                qrow = apply_high_rebreakout_hold_v248(qrow) if 'apply_high_rebreakout_hold_v248' in globals() else qrow
                for _k in ("low_defense_quality_v248", "low_defense_final_label_v248", "low_defense_quality_short_v248", "low_defense_promote_ok_v248", "low_defense_block_reason_text_v248", "high_rebreakout_v248_label", "high_rebreakout_v248_code", "high_rebreakout_v248_score", "high_rebreakout_v248_gap"):
                    if _k in qrow:
                        state[_k] = qrow.get(_k)
            except Exception:
                pass
            state["precision_chart_note"] = "정밀 1분봉 확인됨"
            PRECISION_MINUTE1_DONE = int(safe_float(globals().get("PRECISION_MINUTE1_DONE", 0), 0)) + 1
            PRECISION_MINUTE1_LAST_RESULT = f"확인 {int(len(df))}봉"
        else:
            pseudo_df = None
            try:
                price_hint = price
                if price_hint <= 0:
                    price_hint = safe_float((globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {}) or {}).get(ticker, 0), 0)
                pseudo_df = build_light_snapshot_pseudo_df(ticker, price=price_hint) if 'build_light_snapshot_pseudo_df' in globals() else None
            except Exception:
                pseudo_df = None
            state.update({
                "precision_chart_source": "ws_light_snapshot_pseudo",
                "precision_chart_verified": False,
                "precision_minute1_verified": False,
                "sample_candles_1m": int(len(pseudo_df)) if pseudo_df is not None else 0,
                "minute1_candles": int(len(pseudo_df)) if pseudo_df is not None else 0,
                "precision_chart_updated_ts": now_ts,
                "precision_chart_note": "정밀 1분봉 대기 / WS·스냅샷 보조",
            })
            if pseudo_df is not None and len(pseudo_df) >= 4:
                try:
                    if price <= 0:
                        price = safe_float(pseudo_df["close"].iloc[-1], 0)
                    candle_ctx = compute_current_candle_context_from_df(pseudo_df, current_price=price)
                    if isinstance(candle_ctx, dict):
                        state.update(candle_ctx)
                except Exception:
                    pass
            PRECISION_MINUTE1_LAST_RESULT = "대기/스냅샷보조"
        PRECISION_MINUTE1_LAST_ITEM = ticker
        PRECISION_MINUTE1_LAST_UPDATED_TS = now_ts
        d = _precision_minute1_state_dict()
        d[ticker] = state
        # 오래된 state 정리
        ttl = safe_float(globals().get("PRECISION_MINUTE1_STATE_TTL_SEC", 1200), 1200)
        for k, v in list(d.items()):
            if not isinstance(v, dict) or now_ts - safe_float(v.get("updated_ts", 0), 0) > ttl:
                d.pop(k, None)
        return dict(state)
    except Exception as e:
        PRECISION_MINUTE1_FAIL = int(safe_float(globals().get("PRECISION_MINUTE1_FAIL", 0), 0)) + 1
        PRECISION_MINUTE1_LAST_ITEM = ticker
        PRECISION_MINUTE1_LAST_RESULT = f"오류:{e.__class__.__name__}"
        append_runtime_event_log("precision_minute1_store_error", "정밀 1분봉 상태 저장 오류", extra={"ticker": ticker, "error": str(e)[:120]})
        return {}


def get_precision_minute1_chart_state(ticker: str, max_age_sec: float = None) -> dict:
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker:
            return {}
        max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("PRECISION_MINUTE1_STATE_TTL_SEC", 1200), 1200)
        st = _precision_minute1_state_dict().get(ticker)
        if not isinstance(st, dict):
            return {}
        age = time.time() - safe_float(st.get("updated_ts", 0), 0)
        if age < 0 or age > max_age_sec:
            return {}
        out = dict(st)
        out["precision_chart_age_sec"] = round(age, 1)
        return out
    except Exception:
        return {}


def apply_precision_minute1_state_to_row(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return row
        st = get_precision_minute1_chart_state(ticker)
        if not st:
            return row
        out = dict(row)
        # 정밀 minute1 확인값은 스냅샷 유사차트보다 우선한다.
        keys = [
            "precision_chart_source", "precision_chart_verified", "precision_minute1_verified", "precision_chart_updated_ts", "precision_chart_age_sec", "precision_chart_note",
            "sample_candles_1m", "minute1_candles", "low_defense_v2_score", "low_defense_v2_label", "low_defense_v2_grade",
            "low_structure_score_v2", "low_structure_route_v244", "low_structure_summary_v2", "low_recent_reclaim_bars_v244",
            "low_zone_defense_score", "recovery_quality_score", "low_zone_stay_bars", "low_zone_reclaim_count",
            "turnover_persistence_score", "turnover_sustain_ratio_3v10", "turnover_sustain_ratio_5v20", "turnover_keep_bars_5", "turnover_keep_bars_10",
            "current_candle_code", "current_candle_label", "current_candle_warning", "current_candle_live_score", "current_candle_reclaim_score", "current_candle_pressure_score", "current_candle_follow_score",
            "current_candle_quality_grade", "current_candle_change_pct", "current_candle_body_ratio", "current_candle_body_pct", "current_candle_range_pct", "current_candle_close_pos_ratio",
            "current_candle_upper_wick_pct", "current_candle_lower_wick_pct", "current_candle_bullish", "current_candle_upper_dump", "current_candle_lower_reclaim", "current_candle_live_ok",
            "body_ratio_1", "close_pos_1", "upper_wick_pct_1", "lower_wick_pct_1", "body_ratio_3", "upper_wick_pct_3", "lower_wick_pct_3",
            "low_defense_quality_v248", "low_defense_final_label_v248", "low_defense_quality_short_v248", "low_defense_promote_ok_v248", "low_defense_block_reason_text_v248",
            "high_rebreakout_v248_label", "high_rebreakout_v248_code", "high_rebreakout_v248_score", "high_rebreakout_v248_gap",
        ]
        for k in keys:
            if k in st:
                out[k] = st.get(k)
        if bool(st.get("precision_chart_verified", False)):
            out["current_candle_source"] = "minute1_ohlcv"
            out["source"] = str(out.get("source", "") or "") or "minute1_precision_state"
        out = apply_low_defense_quality_v248(out) if 'apply_low_defense_quality_v248' in globals() else out
        out = apply_high_rebreakout_hold_v248(out) if 'apply_high_rebreakout_hold_v248' in globals() else out
        return out
    except Exception:
        return row


def queue_precision_minute1_chart_verify(row: dict, reason: str = "internal_watch") -> bool:
    try:
        if not bool(globals().get("PRECISION_MINUTE1_CHART_ON", True)):
            return False
        row = row if isinstance(row, dict) else {}
        reason = str(reason or "internal_watch")[:80]
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            _precision_minute1_reject("bad_ticker", ticker)
            return False
        now_ts = time.time()
        remain = _precision_minute1_cooldown_remaining(ticker, now_ts)
        if remain > 0:
            _precision_minute1_reject("cooldown", ticker, {"remain": round(remain, 1), "reason": reason})
            return False
        any_state = get_precision_minute1_chart_state(ticker, max_age_sec=safe_float(globals().get("PRECISION_MINUTE1_RECENT_STATE_BLOCK_SEC", 75), 75))
        if any_state:
            if bool(any_state.get("precision_chart_verified", False)):
                _precision_minute1_reject("recent_verified", ticker, {"reason": reason})
                return False
            _precision_minute1_reject("recent_pending_state", ticker, {"reason": reason, "source": any_state.get("precision_chart_source", "")})
            return False
        profile = precision_minute1_candidate_profile_v249(row, reason=reason)
        if not bool(profile.get("allowed", False)):
            _precision_minute1_reject(str(profile.get("decision", "not_qualified") or "not_qualified"), ticker, profile)
            try:
                hint = dict(row)
                hint["precision_queue_blocked_v249"] = True
                hint["precision_queue_block_reason_v249"] = str(profile.get("decision", "not_qualified") or "not_qualified")
                store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason=f"blocked:{reason}", row_hint=hint)
            except Exception:
                pass
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_LOW_PRIORITY_MIN_DELAY_SEC", 180), 180), "blocked")
            return False
        try:
            hint = dict(row)
            hint["precision_queue_priority_v249"] = safe_float(profile.get("priority", 0), 0)
            hint["precision_queue_reason_v249"] = reason
            store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason=f"queued:{reason}", row_hint=hint)
        except Exception:
            pass
        with PRECISION_MINUTE1_QUEUE_LOCK:
            q = globals().setdefault("PRECISION_MINUTE1_QUEUE", [])
            if not isinstance(q, list):
                globals()["PRECISION_MINUTE1_QUEUE"] = []
                q = globals()["PRECISION_MINUTE1_QUEUE"]
            if any(isinstance(x, dict) and str(x.get("ticker", "") or "").upper().strip() == ticker for x in q):
                _precision_minute1_reject("already_queued", ticker, profile)
                return False
            max_q = int(safe_float(globals().get("PRECISION_MINUTE1_QUEUE_MAX", 24), 24))
            item = {"ticker": ticker, "requested_at": now_ts, "reason": reason, "score": safe_float(profile.get("score", 0), 0), "priority": safe_float(profile.get("priority", 0), 0), "profile": profile}
            q.append(item)
            q.sort(key=lambda x: (safe_float((x or {}).get("priority", 0), 0), -safe_float((x or {}).get("requested_at", 0), 0)), reverse=True)
            if len(q) > max_q:
                del q[max_q:]
        _precision_minute1_accept(ticker, profile)
        return True
    except Exception as e:
        append_runtime_event_log("precision_minute1_queue_error", "정밀 1분봉 큐 등록 오류", extra={"error": str(e)[:120]})
        return False

def process_precision_minute1_chart_once(ticker: str, reason: str = "worker") -> bool:
    global PRECISION_MINUTE1_FAIL, PRECISION_MINUTE1_LAST_ITEM, PRECISION_MINUTE1_LAST_RESULT
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    PRECISION_MINUTE1_LAST_ITEM = ticker
    try:
        remain = _precision_minute1_cooldown_remaining(ticker) if '_precision_minute1_cooldown_remaining' in globals() else 0.0
        if remain > 0:
            PRECISION_MINUTE1_LAST_RESULT = f"쿨다운 {int(remain)}초"
            return False
    except Exception:
        pass
    try:
        cached_df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1") * 4, copy_dataframe=True)
        if cached_df is not None and len(cached_df) >= 4:
            st = store_precision_minute1_chart_state(ticker, cached_df, source="minute1_cache", reason=reason)
            if bool(st.get("precision_chart_verified", False)):
                _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC", 180), 180), "success_cache")
            return bool(st.get("precision_chart_verified", False))
    except Exception:
        pass
    try:
        global_left = _precision_minute1_global_cooldown_left() if '_precision_minute1_global_cooldown_left' in globals() else 0.0
        if global_left > 0:
            store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason="precision_timeout_circuit", row_hint={"ticker": ticker})
            _precision_minute1_set_cooldown(ticker, min(global_left, safe_float(globals().get("PRECISION_MINUTE1_QUOTA_COOLDOWN_SEC", 180), 180)), "timeout_circuit")
            PRECISION_MINUTE1_LAST_RESULT = f"대기/timeout쿨다운 {int(global_left)}초"
            return False
        if is_ohlcv_circuit_open() or (not _precision_minute1_fetch_quota_open()):
            store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason="quota_or_circuit", row_hint={"ticker": ticker})
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_QUOTA_COOLDOWN_SEC", 180), 180), "quota_or_circuit")
            PRECISION_MINUTE1_LAST_RESULT = "대기/쿼터"
            return False
        _precision_minute1_record_fetch()
        try:
            shorten_ohlcv_cooldown_for_priority(ticker, "minute1", max_cooldown_sec=5)
        except Exception:
            pass
        df = get_ohlcv(ticker, "minute1", allow_slow_fetch=True)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source="minute1_ohlcv", reason=reason)
            if bool(st.get("precision_chart_verified", False)):
                _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC", 180), 180), "success_fetch")
            return bool(st.get("precision_chart_verified", False))
        PRECISION_MINUTE1_FAIL = int(safe_float(globals().get("PRECISION_MINUTE1_FAIL", 0), 0)) + 1
        PRECISION_MINUTE1_LAST_RESULT = "실패/표본없음"
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_FAIL_COOLDOWN_SEC", 420), 420), "no_rows")
        store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason="minute1_no_rows", row_hint={"ticker": ticker})
        return False
    except Exception as e:
        PRECISION_MINUTE1_FAIL = int(safe_float(globals().get("PRECISION_MINUTE1_FAIL", 0), 0)) + 1
        PRECISION_MINUTE1_LAST_RESULT = f"오류:{e.__class__.__name__}"
        err_text = str(e)[:160].lower()
        is_timeout = ("timeout" in err_text or "timed out" in err_text)
        cd = safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_COOLDOWN_SEC", 1200), 1200) if is_timeout else safe_float(globals().get("PRECISION_MINUTE1_FAIL_COOLDOWN_SEC", 900), 900)
        if is_timeout and '_precision_minute1_note_timeout' in globals():
            _precision_minute1_note_timeout()
        _precision_minute1_set_cooldown(ticker, cd, "timeout" if is_timeout else "error")
        append_runtime_event_log("precision_minute1_worker_error", "정밀 1분봉 검증 오류", extra={"ticker": ticker, "error": str(e)[:120]})
        return False


def precision_minute1_chart_worker_loop():
    while True:
        try:
            time.sleep(safe_float(globals().get("PRECISION_MINUTE1_WORKER_SLEEP_SEC", 1.15), 1.15))
            if not bool(globals().get("PRECISION_MINUTE1_CHART_ON", True)):
                continue
            item = None
            with PRECISION_MINUTE1_QUEUE_LOCK:
                q = globals().setdefault("PRECISION_MINUTE1_QUEUE", [])
                if isinstance(q, list) and q:
                    q.sort(key=lambda x: (safe_float((x or {}).get("priority", (x or {}).get("score", 0)), 0), -safe_float((x or {}).get("requested_at", 0), 0)), reverse=True)
                    item = q.pop(0)
            if not isinstance(item, dict):
                continue
            ticker = str(item.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            process_precision_minute1_chart_once(ticker, reason=str(item.get("reason", "worker") or "worker"))
        except Exception as e:
            append_runtime_event_log("precision_minute1_worker_loop_error", "정밀 1분봉 워커 루프 오류", extra={"error": str(e)[:120]})
            time.sleep(2.0)

def should_verify_rank_turnover(row: dict) -> bool:
    try:
        if not bool(globals().get("REALTIME_RANK_TURNOVER_VERIFY_ON", True)):
            return False
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            return False
        if bool(row.get("rank_tick_noise_block", False)) or is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            return False
        if not is_money_unverified_for_row(row):
            return False
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        strongest = max(
            safe_float(row.get("change_3", 0), 0),
            safe_float(row.get("change_5", 0), 0),
            safe_float(row.get("change_15", 0), 0),
            safe_float(row.get("change_30", 0), 0),
            safe_float(row.get("change_60", 0), 0),
        )
        if score >= safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_MIN_SCORE", 2.0), 2.0):
            return True
        if strongest >= safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_MIN_MOVE", 0.70), 0.70):
            return True
        return False
    except Exception:
        return False


def queue_realtime_rank_turnover_verify(row: dict, reason: str = "rank_watch") -> bool:
    try:
        if not should_verify_rank_turnover(row):
            return False
        ticker = str(row.get("ticker", "") or "").upper().strip()
        now_ts = time.time()
        repeat_sec = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_MIN_REPEAT_SEC", 90), 90)
        with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
            state = _rank_turnover_state()
            prev = state.get(ticker) if isinstance(state.get(ticker), dict) else {}
            if str(prev.get("status", "") or "").lower() == "pending":
                return False
            next_retry_at = safe_float(prev.get("next_retry_at", 0), 0)
            if next_retry_at > now_ts:
                return False
            last_req = safe_float(prev.get("requested_at", prev.get("updated_at", 0)), 0)
            prev_status = str(prev.get("status", "") or "").lower()
            cooldown = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC", 180), 180) if prev_status in {"failed", "timeout", "error", "retry", "suspect", "volume_suspect"} else repeat_sec
            # v2.5.238: 대금확인 상태표의 next_retry_at을 기준으로 재확인 폭주를 막는다.
            if last_req > 0 and now_ts - last_req < cooldown:
                return False
            q = _rank_turnover_queue()
            if ticker in q:
                return False
            max_q = int(safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_QUEUE_MAX", 40), 40))
            if len(q) >= max_q:
                q.pop(-1)
            q.append(ticker)
            state[ticker] = {
                "ticker": ticker,
                "status": "pending",
                "requested_at": now_ts,
                "updated_at": now_ts,
                "reason": str(reason or "rank_watch")[:80],
                "snapshot_rank_score": safe_float(row.get("snapshot_rank_score", 0), 0),
                "next_retry_at": now_ts + max(10.0, safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_DELAY_SEC", 45), 45)),
            }
            row["turnover_verify_status"] = "pending"
            row["turnover_verify_requested_ts"] = now_ts
        return True
    except Exception as e:
        append_runtime_event_log("rank_turnover_verify_queue_error", "순위권 거래대금 확인 예약 오류", extra={"error": str(e)[:120]})
        return False


def is_rank_turnover_verify_soft_cooldown_open(now_ts: float = None) -> bool:
    try:
        now_ts = safe_float(now_ts, time.time())
        until = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_SOFT_COOLDOWN_UNTIL", 0), 0)
        return until > now_ts
    except Exception:
        return False


def record_rank_turnover_verify_failure_v245(ticker: str = "", reason: str = ""):
    try:
        now_ts = time.time()
        window = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_SOFT_FAIL_WINDOW_SEC", 300), 300)
        limit = int(safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_SOFT_FAIL_LIMIT", 8), 8))
        arr = globals().setdefault("REALTIME_RANK_TURNOVER_VERIFY_SOFT_FAIL_TIMES", [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= window]
        arr.append(now_ts)
        globals()["REALTIME_RANK_TURNOVER_VERIFY_SOFT_FAIL_TIMES"] = arr[-max(limit * 2, 20):]
        if len(arr) >= limit:
            cooldown = safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_SOFT_COOLDOWN_SEC", 180), 180)
            globals()["REALTIME_RANK_TURNOVER_VERIFY_SOFT_COOLDOWN_UNTIL"] = now_ts + cooldown
            append_runtime_event_log("rank_turnover_verify_soft_cooldown", "순위권 대금확인 minute1 실패가 몰려 잠시 중단", extra={"ticker": ticker, "reason": reason, "fail_count": len(arr), "cooldown_sec": cooldown})
    except Exception:
        pass


def verify_realtime_rank_turnover_once(ticker: str, reason: str = "worker") -> bool:
    global REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM, REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT, REALTIME_RANK_TURNOVER_VERIFY_DONE, REALTIME_RANK_TURNOVER_VERIFY_FAIL
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM = ticker
    if is_rank_turnover_verify_soft_cooldown_open():
        info = {"ticker": ticker, "status": "deferred", "source": "minute1_ohlcv", "reason": "soft_cooldown", "fail_detail": "순위권 대금확인 minute1 실패가 몰려 잠시 중단", "verified": False, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_SOFT_COOLDOWN_SEC", 180), 180)}
        _save_verified_turnover_state(ticker, info)
        REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "대금확인 잠시중단"
        return False
    try:
        cached_df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1") * 3, copy_dataframe=True)
        if cached_df is not None:
            vals = _compute_turnover_from_minute_df(cached_df)
            if int(vals.get("rows", 0)) > 0:
                vals.update({"status": "ok", "source": "minute1_cache", "reason": str(reason or "worker")[:80], "verified": True, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC", 600), 600)})
                try:
                    store_precision_minute1_chart_state(ticker, cached_df, source="minute1_cache", reason="turnover_verify_cache")
                except Exception:
                    pass
                _save_verified_turnover_state(ticker, vals)
                REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
                REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"캐시확인 {safe_float(vals.get('turnover_5m',0),0):,.0f}원"
                return True
    except Exception:
        pass
    try:
        # v2.5.202: 순위권 후보는 한번 실패했다고 길게 막지 말고 빠르게 재시도하게 만든다.
        try:
            shorten_ohlcv_cooldown_for_priority(ticker, "minute1", max_cooldown_sec=3)
        except Exception:
            pass
        df = get_ohlcv(ticker, "minute1", allow_slow_fetch=True)
        vals = _compute_turnover_from_minute_df(df)
        if int(vals.get("rows", 0)) <= 0:
            detail = explain_ohlcv_failure_reason(ticker, "minute1", raw_reason="no_rows_retry")
            info = {"ticker": ticker, "status": "retry", "source": "minute1_ohlcv", "reason": "no_rows_retry", "fail_detail": detail, "verified": False, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC", 210), 210)}
            _save_verified_turnover_state(ticker, info)
            REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
            record_rank_turnover_verify_failure_v245(ticker, "no_rows_retry")
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "재확인대기"
            return False
        try:
            with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
                prev = dict(_rank_turnover_state().get(ticker) or {})
            score_hint = safe_float(prev.get("snapshot_rank_score", 0), 0)
        except Exception:
            score_hint = 0.0
        turn5 = safe_float(vals.get("turnover_5m", 0), 0)
        rows = int(vals.get("rows", 0))
        nonzero_rows = int(safe_float(vals.get("nonzero_volume_rows_5m", 0), 0))
        if rows > 0 and score_hint >= safe_float(globals().get("REALTIME_RANK_TURNOVER_SUSPECT_SCORE", 2.0), 2.0) and (turn5 < safe_float(globals().get("REALTIME_RANK_TURNOVER_SUSPECT_MIN_KRW", 100000), 100000) or nonzero_rows <= 0):
            vals.update({"status": "suspect", "source": "minute1_ohlcv", "reason": "suspicious_tiny_turnover", "fail_detail": explain_ohlcv_failure_reason(ticker, "minute1", raw_reason="suspicious_tiny_turnover"), "verified": False, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC", 210), 210)})
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
            record_rank_turnover_verify_failure_v245(ticker, "suspicious_tiny_turnover")
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "대금값 의심"
            return False
        vals.update({"status": "ok", "source": "minute1_ohlcv", "reason": str(reason or "worker")[:80], "verified": True, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC", 600), 600)})
        try:
            store_precision_minute1_chart_state(ticker, df, source="minute1_ohlcv", reason="turnover_verify_fetch")
        except Exception:
            pass
        _save_verified_turnover_state(ticker, vals)
        price = safe_float(vals.get("price", 0), 0)
        turn5 = safe_float(vals.get("turnover_5m", 0), 0)
        if price > 0:
            record_light_price_snapshot(ticker, price, turnover_hint=turn5, source="turnover_verify")
        REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
        REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"확인 {turn5:,.0f}원"
        return True
    except Exception as e:
        raw_reason = f"exception:{e.__class__.__name__}"
        info = {"ticker": ticker, "status": "error", "source": "minute1_ohlcv", "reason": raw_reason, "fail_detail": explain_ohlcv_failure_reason(ticker, "minute1", raw_reason=raw_reason), "verified": False, "next_retry_at": time.time() + safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC", 210), 210)}
        _save_verified_turnover_state(ticker, info)
        REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
        record_rank_turnover_verify_failure_v245(ticker, raw_reason)
        REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "오류"
        append_runtime_event_log("rank_turnover_verify_error", "순위권 거래대금 실제 확인 오류", extra={"ticker": ticker, "error": str(e)[:120]})
        return False


def realtime_rank_turnover_verify_worker_loop():
    while True:
        try:
            time.sleep(safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_WORKER_SLEEP_SEC", 0.85), 0.85))
            if not bool(globals().get("REALTIME_RANK_TURNOVER_VERIFY_ON", True)):
                continue
            ticker = None
            with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
                q = _rank_turnover_queue()
                if q:
                    ticker = q.pop(0)
            if not ticker:
                continue
            if is_ohlcv_circuit_open():
                with REALTIME_RANK_TURNOVER_VERIFY_LOCK:
                    q = _rank_turnover_queue()
                    if ticker not in q:
                        q.insert(0, ticker)
                time.sleep(1.5)
                continue
            verify_realtime_rank_turnover_once(ticker, reason="turnover_worker")
        except Exception as e:
            append_runtime_event_log("rank_turnover_verify_worker_error", "거래대금 확인 워커 오류", extra={"error": str(e)[:120]})
            time.sleep(1.5)

