def normalize_ticker_query_key(value: str) -> str:
    try:
        s = str(value or "").strip().upper()
        for ch in [" ", "-", "_", "/", "\\", "(", ")", "[", "]", "{", "}", ".", ",", "·"]:
            s = s.replace(ch, "")
        return s
    except Exception:
        return str(value or "").strip().upper()

def resolve_user_ticker_query(query: str) -> tuple:
    """사용자가 한글명/영문 프로젝트명으로 넣어도 실제 빗썸 티커로 최대한 맞춘다."""
    raw = str(query or "").strip()
    up = raw.upper().strip()
    key = normalize_ticker_query_key(raw)
    alias_map = globals().get("BITHUMB_ALIAS_TICKER_MAP", {}) if isinstance(globals().get("BITHUMB_ALIAS_TICKER_MAP", {}), dict) else {}
    # 정확 alias 우선
    for cand in (up, key, raw.strip()):
        if cand in alias_map:
            return str(alias_map.get(cand) or cand).upper().strip(), f"{raw}→{str(alias_map.get(cand)).upper().strip()} 별칭 매핑"
    # 이미 실제 티커처럼 보이는 경우
    known = set()
    try:
        known.update(str(x or "").upper().strip() for x in (market_all_tickers if isinstance(market_all_tickers, list) else []))
    except Exception:
        pass
    try:
        if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict):
            known.update(str(x or "").upper().strip() for x in LIGHT_SNAPSHOT_BULK_PRICE_CACHE.keys())
    except Exception:
        pass
    try:
        with LIGHT_SNAPSHOT_LOCK:
            known.update(str(x or "").upper().strip() for x in LIGHT_SNAPSHOT_HISTORY.keys())
    except Exception:
        pass
    if up in known:
        return up, ""
    # 정규화해서 한 번 더 비교
    for t in known:
        if normalize_ticker_query_key(t) == key:
            return t, f"{raw}→{t} 정규화 매핑"
    return up, ""

def cleanup_forced_light_snapshot_tickers(now_ts: float = None):
    try:
        now_ts = safe_float(now_ts, time.time())
        state = globals().setdefault("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        if not isinstance(state, dict):
            globals()["LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS"] = {}
            return
        expired = [k for k, v in list(state.items()) if safe_float(v.get("expires_at", 0) if isinstance(v, dict) else 0, 0) <= now_ts]
        for k in expired:
            state.pop(k, None)
        max_n = int(safe_float(globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_MAX", 120), 120))
        if len(state) > max_n:
            ordered = sorted(state.items(), key=lambda kv: safe_float((kv[1] or {}).get("last_touch", 0) if isinstance(kv[1], dict) else 0, 0), reverse=True)
            keep = {k for k, _v in ordered[:max_n]}
            for k in list(state.keys()):
                if k not in keep:
                    state.pop(k, None)
    except Exception:
        pass

def force_track_light_snapshot_ticker(ticker: str, price: float = 0.0, reason: str = "manual_detail", now_ts: float = None) -> bool:
    """현재가 최신값은 있는데 스냅샷 표본이 없는 코인을 감시 대상에 강제로 올린다."""
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            return False
        now_ts = safe_float(now_ts, time.time())
        cleanup_forced_light_snapshot_tickers(now_ts=now_ts)
        state = globals().setdefault("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        if not isinstance(state, dict):
            globals()["LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS"] = {}
            state = globals()["LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS"]
        pv = safe_float(price, 0)
        if pv <= 0:
            try:
                pv = safe_float((LIGHT_SNAPSHOT_BULK_PRICE_CACHE or {}).get(ticker, 0), 0) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else 0.0
            except Exception:
                pv = 0.0
        state[ticker] = {
            "ticker": ticker,
            "reason": str(reason or "force_track"),
            "last_price": pv,
            "last_touch": now_ts,
            "expires_at": now_ts + int(safe_float(globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TTL_SEC", 2700), 2700)),
        }
        if pv > 0:
            record_light_price_snapshot(ticker, pv, turnover_hint=0.0, source=f"force_track:{reason}", now_ts=now_ts)
        return True
    except Exception as e:
        append_runtime_error_log("force_track_light_snapshot", str(e), exc=e, include_traceback=False)
        return False

def sweep_bulk_prices_into_light_snapshots(reason: str = "bulk_sweep_all", max_tickers: int = None, bulk_prices: dict = None) -> int:
    """전체 현재가 캐시가 있으면 모든 티커를 스냅샷 이력에 넓게 주입한다.

    v2.5.215: 이미 받아온 bulk_prices를 재사용한다. worker 안에서 같은 회차에
    get_current_price(ALL)를 두 번 부르던 경로를 끊어 bulk timeout을 줄인다.
    """
    try:
        if bulk_prices is None:
            bulk_prices = get_bulk_current_price_snapshot() if LIGHT_SNAPSHOT_BULK_PRICE_ON else {}
        if not isinstance(bulk_prices, dict) or not bulk_prices:
            return 0
        nmax = int(safe_float(max_tickers if max_tickers is not None else globals().get("LIGHT_SNAPSHOT_BULK_SWEEP_MAX_TICKERS", 1000), 1000))
        count = 0
        now_ts = time.time()
        # 가격 큰 순서가 아니라 원본 전체를 안정적으로 훑는다.
        for tk, pr in list(bulk_prices.items())[:max(1, nmax)]:
            tku = str(tk or "").upper().strip()
            if not tku or tku == "BTC" or is_watch_excluded_ticker(tku):
                continue
            pv = safe_float(pr, 0)
            if pv <= 0:
                continue
            record_light_price_snapshot(tku, pv, turnover_hint=0.0, source=reason, now_ts=now_ts)
            count += 1
        globals()["LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT"] = count
        globals()["LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS"] = now_ts
        return count
    except Exception as e:
        append_runtime_error_log("bulk_sweep_all_light_snapshots", str(e), exc=e, include_traceback=False)
        return 0


def _api_counter_add(name: str, delta: int = 1):
    try:
        with API_CALL_LOCK:
            globals()[name] = int(safe_float(globals().get(name, 0), 0)) + int(delta)
    except Exception:
        pass

def _api_counter_set(name: str, value):
    try:
        with API_CALL_LOCK:
            globals()[name] = value
    except Exception:
        pass

def cleanup_ohlcv_fail_states(now_ts: float = None, keep_recent_sec: int = 20):
    """쿨다운이 끝난 OHLCV 실패 상태를 정리한다.

    예전에는 한 번 실패한 종목이 성공 전까지 실패상태에 오래 남아서
    실제 활성 실패보다 훨씬 큰 숫자로 보였다. 1분봉 정밀분석 재시도도
    불필요하게 막힐 수 있으므로, 쿨다운이 끝난 항목은 정리한다.
    """
    try:
        now_ts = safe_float(now_ts, time.time())
        if not isinstance(API_OHLCV_FAIL_STATE, dict):
            return 0
        removed = 0
        for key, row in list(API_OHLCV_FAIL_STATE.items()):
            if not isinstance(row, dict):
                API_OHLCV_FAIL_STATE.pop(key, None)
                removed += 1
                continue
            cd_until = safe_float(row.get("cooldown_until", 0), 0)
            last_failed = safe_float(row.get("last_failed_ts", 0), 0)
            if cd_until > 0 and now_ts >= cd_until and (last_failed <= 0 or now_ts - last_failed >= max(0, int(keep_recent_sec))):
                API_OHLCV_FAIL_STATE.pop(key, None)
                removed += 1
        return removed
    except Exception:
        return 0

def get_ohlcv_fail_state_counts(now_ts: float = None) -> dict:
    try:
        now_ts = safe_float(now_ts, time.time())
        cleanup_ohlcv_fail_states(now_ts=now_ts)
        active = 0
        stored = 0
        active_by_interval = {}
        rows = list(API_OHLCV_FAIL_STATE.items()) if isinstance(API_OHLCV_FAIL_STATE, dict) else []
        for key, row in rows:
            if not isinstance(row, dict):
                continue
            stored += 1
            interval = str(key[1] if isinstance(key, tuple) and len(key) > 1 else row.get("interval", "unknown") or "unknown").lower()
            if safe_float(row.get("cooldown_until", 0), 0) > now_ts:
                active += 1
                active_by_interval[interval] = active_by_interval.get(interval, 0) + 1
        return {"stored": stored, "active": active, "active_by_interval": active_by_interval}
    except Exception:
        return {"stored": 0, "active": 0, "active_by_interval": {}}



def _guess_ohlcv_caller() -> str:
    """실패 시점의 OHLCV 호출 경로를 가볍게 추정한다."""
    try:
        skip = {"get_ohlcv", "record_ohlcv_failure", "_guess_ohlcv_caller", "_call_with_timeout"}
        for frame in inspect.stack()[2:10]:
            fn = str(getattr(frame, "function", "") or "")
            if not fn or fn in skip:
                continue
            if fn.startswith("_") and fn not in {"_enrich_rank_precision_chart_context"}:
                continue
            return fn[:80]
    except Exception:
        pass
    return "unknown"


def record_ohlcv_caller_stat(ticker: str, interval: str, caller: str = "", result: str = "call", reason: str = ""):
    try:
        caller = str(caller or "unknown")[:80]
        result = str(result or "call")[:30]
        ticker = str(ticker or "").upper().strip()
        interval = str(interval or "").lower().strip()
        with API_OHLCV_CALLER_STATS_LOCK:
            row = API_OHLCV_CALLER_STATS.get(caller)
            if not isinstance(row, dict):
                row = {"count": 0, "ok": 0, "timeout": 0, "empty": 0, "exception": 0, "cooldown": 0, "last_ts": 0.0, "last_item": "", "last_reason": ""}
            row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
            if result in {"ok", "timeout", "empty", "exception", "cooldown"}:
                row[result] = int(safe_float(row.get(result, 0), 0)) + 1
            row["last_ts"] = time.time()
            row["last_item"] = f"{ticker}:{interval}"[:80]
            row["last_reason"] = str(reason or "")[:100]
            API_OHLCV_CALLER_STATS[caller] = row
            if len(API_OHLCV_CALLER_STATS) > API_OHLCV_CALLER_STAT_MAX:
                old = sorted(API_OHLCV_CALLER_STATS.items(), key=lambda kv: safe_float(kv[1].get("last_ts", 0), 0))
                for k, _ in old[:max(1, len(old) - API_OHLCV_CALLER_STAT_MAX)]:
                    API_OHLCV_CALLER_STATS.pop(k, None)
    except Exception:
        pass


def get_ohlcv_caller_stats_text(limit: int = 5) -> str:
    try:
        with API_OHLCV_CALLER_STATS_LOCK:
            rows = [(k, dict(v)) for k, v in API_OHLCV_CALLER_STATS.items() if isinstance(v, dict)]
        if not rows:
            return "- OHLCV 호출자: 아직 기록 없음"
        rows.sort(key=lambda kv: (safe_float(kv[1].get("timeout", 0), 0) + safe_float(kv[1].get("exception", 0), 0) + safe_float(kv[1].get("empty", 0), 0), safe_float(kv[1].get("count", 0), 0)), reverse=True)
        parts = []
        for caller, row in rows[:max(1, int(limit))]:
            bad = int(safe_float(row.get("timeout",0),0)) + int(safe_float(row.get("exception",0),0)) + int(safe_float(row.get("empty",0),0))
            parts.append(f"{caller} {int(safe_float(row.get('count',0),0))}회/실패 {bad} / 최근 {row.get('last_item','-')}")
        return "- OHLCV 호출자: " + ", ".join(parts)
    except Exception:
        return "- OHLCV 호출자: 확인 실패"


def get_api_bottleneck_snapshot() -> dict:
    try:
        with API_CALL_LOCK:
            api_part = {
                "api_inflight": int(safe_float(API_CALL_INFLIGHT, 0)),
                "api_timeout_count": int(safe_float(API_CALL_TIMEOUT_COUNT, 0)),
                "api_rejected_count": int(safe_float(API_CALL_REJECTED_COUNT, 0)),
                "api_last_timeout_age": int(time.time() - API_CALL_LAST_TIMEOUT_TS) if API_CALL_LAST_TIMEOUT_TS else None,
                "api_last_reject_age": int(time.time() - API_CALL_LAST_REJECT_TS) if API_CALL_LAST_REJECT_TS else None,
                "api_last_slow_name": str(API_CALL_LAST_SLOW_NAME or ""),
                "api_last_reject_name": str(API_CALL_LAST_REJECT_NAME or ""),
                "api_caller_top": sorted([(k, dict(v)) for k, v in API_CALL_CALLER_STATS.items() if isinstance(v, dict)], key=lambda kv: (safe_float(kv[1].get("timeout",0),0)+safe_float(kv[1].get("busy",0),0)+safe_float(kv[1].get("exception",0),0)+safe_float(kv[1].get("slow",0),0), safe_float(kv[1].get("count",0),0)), reverse=True)[:8] if isinstance(API_CALL_CALLER_STATS, dict) else [],
            }
        with API_OHLCV_FETCH_LOCK:
            now_ts = time.time()
            fail_counts = get_ohlcv_fail_state_counts(now_ts=now_ts)
            ohlcv_rows = [f"{k[0]}:{k[1]}({int(now_ts-safe_float(v, now_ts))}초)" for k, v in list(API_OHLCV_INFLIGHT.items())[:8]]
            fail_interval_top = sorted(API_OHLCV_FAIL_BY_INTERVAL.items(), key=lambda kv: kv[1], reverse=True)[:6] if isinstance(API_OHLCV_FAIL_BY_INTERVAL, dict) else []
            fail_ticker_top = sorted(API_OHLCV_FAIL_BY_TICKER.items(), key=lambda kv: kv[1], reverse=True)[:8] if isinstance(API_OHLCV_FAIL_BY_TICKER, dict) else []
            defer_interval_top = sorted(API_OHLCV_DEFER_BY_INTERVAL.items(), key=lambda kv: kv[1], reverse=True)[:6] if isinstance(API_OHLCV_DEFER_BY_INTERVAL, dict) else []
            fail_reason_top = sorted(API_OHLCV_FAIL_BY_REASON.items(), key=lambda kv: kv[1], reverse=True)[:6] if isinstance(API_OHLCV_FAIL_BY_REASON, dict) else []
            with SLOW_OHLCV_PREFETCH_LOCK:
                slow_queue_len = len(SLOW_OHLCV_PREFETCH_QUEUE)
            ohlcv_part = {
                "ohlcv_inflight": len(API_OHLCV_INFLIGHT),
                "ohlcv_inflight_rows": ohlcv_rows,
                "ohlcv_dup_skip_count": int(safe_float(API_OHLCV_DUP_SKIP_COUNT, 0)),
                "ohlcv_last_dup_skip_age": int(now_ts - API_OHLCV_LAST_DUP_SKIP_TS) if API_OHLCV_LAST_DUP_SKIP_TS else None,
                "ohlcv_last_dup_skip_key": str(API_OHLCV_LAST_DUP_SKIP_KEY or ""),
                "ohlcv_fail_state_count": int(fail_counts.get("stored", 0)),
                "ohlcv_fail_state_active_count": int(fail_counts.get("active", 0)),
                "ohlcv_fail_state_active_by_interval": fail_counts.get("active_by_interval", {}),
                "ohlcv_fail_interval_top": fail_interval_top,
                "ohlcv_fail_ticker_top": fail_ticker_top,
                "ohlcv_defer_interval_top": defer_interval_top,
                "ohlcv_fail_reason_top": fail_reason_top,
                "slow_prefetch_queue_len": slow_queue_len,
                "slow_prefetch_done": int(safe_float(SLOW_OHLCV_PREFETCH_DONE, 0)),
                "slow_prefetch_fail": int(safe_float(SLOW_OHLCV_PREFETCH_FAIL, 0)),
                "slow_prefetch_deferred": int(safe_float(SLOW_OHLCV_PREFETCH_DEFERRED, 0)),
                "slow_prefetch_last_item": str(SLOW_OHLCV_PREFETCH_LAST_ITEM or ""),
                "slow_prefetch_last_result": str(SLOW_OHLCV_PREFETCH_LAST_RESULT or ""),
                "slow_prefetch_interval_cooldowns": {k: int(max(0, safe_float(v, 0) - now_ts)) for k, v in (globals().get("SLOW_OHLCV_PREFETCH_INTERVAL_COOLDOWN_UNTIL", {}) or {}).items() if safe_float(v, 0) > now_ts},
                "ohlcv_caller_top": sorted([(k, dict(v)) for k, v in API_OHLCV_CALLER_STATS.items() if isinstance(v, dict)], key=lambda kv: (safe_float(kv[1].get("timeout",0),0)+safe_float(kv[1].get("exception",0),0)+safe_float(kv[1].get("empty",0),0), safe_float(kv[1].get("count",0),0)), reverse=True)[:6] if isinstance(API_OHLCV_CALLER_STATS, dict) else [],
            }
        api_part.update(ohlcv_part)
        return api_part
    except Exception as e:
        return {"bottleneck_snapshot_error": str(e)}

def _record_api_call_failure(func_name: str, reason: str, detail: str = "", extra: dict = None):
    try:
        name = str(func_name or "api_call")
        row = {
            "ts": time.time(),
            "reason": str(reason or "unknown")[:80],
            "detail": str(detail or "")[:160],
        }
        if isinstance(extra, dict):
            row.update({k: v for k, v in extra.items() if k not in row})
        API_CALL_LAST_FAILURE_REASON[name] = row
    except Exception:
        pass


def get_api_call_last_failure_reason(func_name: str, max_age_sec: float = 4.0) -> str:
    try:
        row = API_CALL_LAST_FAILURE_REASON.get(str(func_name or ""))
        if not isinstance(row, dict):
            return ""
        if time.time() - safe_float(row.get("ts", 0), 0) > max(0.5, float(max_age_sec)):
            return ""
        reason = str(row.get("reason", "") or "").strip()
        detail = str(row.get("detail", "") or "").strip()
        if reason and detail:
            return f"{reason}:{detail}"
        return reason
    except Exception:
        return ""


def _normalize_data_fail_reason(raw_reason: str) -> str:
    raw = str(raw_reason or "").strip()
    low = raw.lower()
    if not raw:
        return "원인 미확인"
    if "api_busy" in low or "rejected" in low:
        return "API 동시호출 슬롯이 가득 차서 이번 조회를 건너뜀"
    if "api_timeout" in low or "timeout" in low:
        return "거래소/API 응답이 제한시간 안에 안 옴"
    if "empty_response" in low or "none" in low:
        return "응답은 왔지만 OHLCV 값이 비어 있음"
    if "cooldown" in low:
        return "직전 실패 후 짧은 재시도 대기 중"
    if "circuit" in low:
        return "OHLCV 실패가 몰려 회로차단으로 잠깐 쉬는 중"
    if "no_rows" in low:
        return "분봉 데이터 행이 비어 있어 재확인 대기"
    if "suspicious" in low or "suspect" in low:
        return "대금값이 비정상적으로 작아 재확인 필요"
    if "exception" in low:
        return "조회 중 예외 발생"
    return raw[:120]


def explain_ohlcv_failure_reason(ticker: str = "", interval: str = "minute1", raw_reason: str = "") -> str:
    try:
        ticker = str(ticker or "").upper().strip()
        interval = str(interval or "minute1").lower().strip()
        reason = str(raw_reason or "").strip()
        row = get_ohlcv_fail_state(ticker, interval) if ticker else {}
        if not reason and isinstance(row, dict):
            reason = str(row.get("reason", "") or "")
        parts = []
        if reason:
            parts.append(_normalize_data_fail_reason(reason))
        left = get_ohlcv_cooldown_left(ticker, interval) if ticker else 0
        if left > 0:
            parts.append(f"재시도 대기 {int(left)}초")
        circuit_left = get_ohlcv_circuit_left()
        if circuit_left > 0:
            parts.append(f"전체 OHLCV 회로차단 {int(circuit_left)}초")
        if not parts:
            return "원인 미확인. /scan_health에서 API/OHLCV 병목 확인 필요"
        return " / ".join(dict.fromkeys([p for p in parts if p]))
    except Exception:
        return _normalize_data_fail_reason(raw_reason)


def _bump_ohlcv_reason_counter(reason: str, count: int = 1):
    try:
        reason_key = str(reason or "unknown").split(":", 1)[0][:60] or "unknown"
        API_OHLCV_FAIL_BY_REASON[reason_key] = int(safe_float(API_OHLCV_FAIL_BY_REASON.get(reason_key, 0), 0)) + int(count)
    except Exception:
        pass


def _guess_api_call_caller() -> str:
    try:
        skip = {"_guess_api_call_caller", "_record_api_call_caller", "_call_with_timeout", "runner"}
        frame = sys._getframe(2)
        depth = 0
        while frame is not None and depth < 12:
            name = str(frame.f_code.co_name or "")
            if name and name not in skip:
                return name[:80]
            frame = frame.f_back
            depth += 1
    except Exception:
        pass
    return "unknown"

def _record_api_call_caller(func_name: str, caller: str, elapsed: float = 0.0, result: str = "call"):
    try:
        key = f"{str(caller or 'unknown')[:60]}->{str(func_name or 'api')[:60]}"
        row = API_CALL_CALLER_STATS.get(key)
        if not isinstance(row, dict):
            row = {"count": 0, "timeout": 0, "busy": 0, "exception": 0, "slow": 0, "last_ts": 0.0, "last_elapsed": 0.0, "func": str(func_name or ""), "caller": str(caller or "")}
            API_CALL_CALLER_STATS[key] = row
        row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
        row["last_ts"] = time.time()
        row["last_elapsed"] = round(safe_float(elapsed, 0), 3)
        if result in {"timeout", "busy", "exception", "slow"}:
            row[result] = int(safe_float(row.get(result, 0), 0)) + 1
        if len(API_CALL_CALLER_STATS) > API_CALL_CALLER_STATS_MAX:
            old_keys = sorted(API_CALL_CALLER_STATS.items(), key=lambda kv: safe_float((kv[1] or {}).get("last_ts", 0), 0))[:20]
            for k, _v in old_keys:
                API_CALL_CALLER_STATS.pop(k, None)
    except Exception:
        pass

def _call_with_timeout(func, *args, timeout_sec: float = API_CALL_TIMEOUT_SEC, default=None, **kwargs):
    """전역 API 동시호출 제한이 있는 timeout wrapper.

    기존 방식은 timeout 이후에도 실제 pybithumb 호출 스레드가 살아 있을 수 있는데,
    그 상태에서 새 호출을 계속 만들면 스레드/API 호출이 누적된다.
    v2.5.169부터는 semaphore가 실제 호출 완료 때까지 잡혀 있으므로,
    오래 걸리는 호출이 쌓이면 새 호출은 빠르게 포기하고 기존 캐시/스냅샷을 쓰게 한다.
    """
    func_name = getattr(func, "__name__", str(func))
    caller_name = _guess_api_call_caller()
    try:
        # v2.5.215 중요 수정: API 세마포어는 반드시 1번만 acquire하고 1번만 release한다.
        # acquire가 중복되면 시간이 지날수록 API 슬롯이 줄어 timeout/api_busy가 폭증할 수 있다.
        acquired = API_CALL_SEMAPHORE.acquire(timeout=max(0.0, safe_float(API_CALL_ACQUIRE_TIMEOUT_SEC, 0.04)))
    except Exception:
        acquired = False
    if not acquired:
        _api_counter_add("API_CALL_REJECTED_COUNT", 1)
        _api_counter_set("API_CALL_LAST_REJECT_TS", time.time())
        _api_counter_set("API_CALL_LAST_REJECT_NAME", func_name)
        _record_api_call_caller(func_name, caller_name, result="busy")
        _record_api_call_failure(func_name, "api_busy", "동시호출 슬롯 부족", extra={"max_concurrent": API_CALL_MAX_CONCURRENT, "caller": caller_name})
        cnt = int(safe_float(globals().get("API_CALL_REJECTED_COUNT", 0), 0))
        if cnt in {1, 2, 3, 5, 10} or cnt % 25 == 0:
            append_runtime_event_log("api_call_rejected_busy", "API 호출 동시 실행이 많아 새 호출을 건너뜀", extra={"func": func_name, "rejected_count": cnt, "max_concurrent": API_CALL_MAX_CONCURRENT})
        return default

    holder = {"done": False, "value": default, "error": None}
    start_ts = time.time()
    _api_counter_add("API_CALL_INFLIGHT", 1)

    def runner():
        try:
            holder["value"] = func(*args, **kwargs)
        except Exception as e:
            holder["error"] = e
        finally:
            holder["done"] = True
            elapsed = time.time() - start_ts
            try:
                with API_CALL_LOCK:
                    globals()["API_CALL_INFLIGHT"] = max(0, int(safe_float(globals().get("API_CALL_INFLIGHT", 0), 0)) - 1)
                    globals()["API_CALL_LAST_DONE_TS"] = time.time()
                    if elapsed >= max(float(timeout_sec), 0.1):
                        globals()["API_CALL_LAST_SLOW_NAME"] = func_name
            except Exception:
                pass
            try:
                API_CALL_SEMAPHORE.release()
            except Exception:
                pass

    t = threading.Thread(target=runner, daemon=True, name=f"api_call_{func_name}")
    t.start()
    t.join(max(float(timeout_sec), 0.1))
    if t.is_alive():
        _api_counter_add("API_CALL_TIMEOUT_COUNT", 1)
        _api_counter_set("API_CALL_LAST_TIMEOUT_TS", time.time())
        _api_counter_set("API_CALL_LAST_SLOW_NAME", func_name)
        _record_api_call_caller(func_name, caller_name, elapsed=time.time() - start_ts, result="timeout")
        _record_api_call_failure(func_name, "api_timeout", f"{timeout_sec}초 초과", extra={"inflight": int(safe_float(globals().get("API_CALL_INFLIGHT", 0), 0)), "caller": caller_name})
        cnt = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
        if cnt in {1, 2, 3, 5, 10} or cnt % 25 == 0:
            append_runtime_event_log("api_call_timeout", "API 호출 timeout. 실제 호출은 뒤에서 끝날 때까지 동시호출 슬롯을 잡고 있음", extra={"func": func_name, "timeout_sec": timeout_sec, "timeout_count": cnt, "inflight": int(safe_float(globals().get("API_CALL_INFLIGHT", 0), 0))})
        return default
    if holder["error"] is not None:
        _record_api_call_caller(func_name, caller_name, elapsed=time.time() - start_ts, result="exception")
        _record_api_call_failure(func_name, "api_exception", holder["error"].__class__.__name__, extra={"caller": caller_name})
        raise holder["error"]
    elapsed = time.time() - start_ts
    _record_api_call_caller(func_name, caller_name, elapsed=elapsed, result="slow" if elapsed >= max(float(timeout_sec), 0.1) else "call")
    return holder["value"]

def get_price(ticker: str) -> float:
    try:
        caller = sys._getframe(1).f_code.co_name
    except Exception:
        caller = "unknown"
    cache_key = str(ticker or "").upper().strip()

    # v2.5.218: 개별 get_current_price 호출 전에 WebSocket/REST direct/light snapshot 가격을 먼저 쓴다.
    # 특히 update_active_price_check_refs 같은 내부감시 경로가 timeout을 만들지 않게 하는 핵심 안전장치다.
    try:
        fast_price, fast_source, _fast_age = get_cached_realtime_price(cache_key, caller=caller, allow_api_cache=True)
        if fast_price > 0:
            _record_get_price_caller(caller, fast_source if fast_source else "fast_cache")
            try:
                set_api_cache_entry(API_PRICE_CACHE, cache_key, float(fast_price))
            except Exception:
                pass
            return float(fast_price)
    except Exception:
        pass

    cached = get_api_cache_entry(API_PRICE_CACHE, cache_key, API_PRICE_CACHE_TTL_SEC)
    if cached is not None:
        try:
            _record_get_price_caller(caller, "cache")
            _record_price_source(caller, "api_cache", cache_key)
            return float(cached)
        except Exception:
            pass
    before_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
    try:
        _record_get_price_caller(caller, "call")
        _record_price_source(caller, "individual_api", cache_key)
        p = _call_with_timeout(pybithumb.get_current_price, ticker, default=None)
        after_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
        if p is None:
            _record_get_price_caller(caller, "timeout" if after_timeout > before_timeout else "none")
            return -1
        value = float(p)
        set_api_cache_entry(API_PRICE_CACHE, cache_key, value)
        try:
            record_light_price_snapshot(cache_key, value, source="get_price")
        except Exception:
            pass
        return value
    except Exception:
        _record_get_price_caller(caller, "exception")
        stale = get_api_cache_entry(API_PRICE_CACHE, cache_key, API_PRICE_CACHE_TTL_SEC * 3)
        if stale is not None:
            try:
                _record_price_source(caller, "api_stale", cache_key)
                return float(stale)
            except Exception:
                pass
        return -1


def _parse_bulk_price_payload(payload) -> dict:
    """pybithumb 현재가 전체 응답 형태가 버전마다 달라도 가격만 최대한 뽑는다."""
    out = {}
    try:
        data = payload
        if isinstance(payload, dict) and isinstance(payload.get("data"), dict):
            data = payload.get("data")
        if not isinstance(data, dict):
            return out
        for raw_key, raw_val in data.items():
            ticker = str(raw_key or "").upper().strip()
            if not ticker or ticker in {"DATE", "STATUS"}:
                continue
            price = 0.0
            if isinstance(raw_val, dict):
                for k in ("closing_price", "close", "price", "current_price", "prev_closing_price"):
                    if k in raw_val:
                        price = safe_float(raw_val.get(k), 0)
                        if price > 0:
                            break
            else:
                price = safe_float(raw_val, 0)
            if price > 0:
                out[ticker] = price
    except Exception:
        return {}
    return out


def _fetch_bithumb_all_ticker_direct(timeout_sec: float = None) -> dict:
    """공식 Public API 전체 현재가를 직접 호출한다.

    pybithumb.get_current_price("ALL")가 timeout을 자주 만들면 REST/스냅샷 백업 구조가
    웹소켓 장애 시 대체 수단이 되지 못한다. 그래서 전체 현재가는 공식
    /public/ticker/ALL_KRW 엔드포인트를 우선 사용한다.
    """
    timeout_sec = safe_float(timeout_sec if timeout_sec is not None else globals().get("LIGHT_SNAPSHOT_BULK_FETCH_TIMEOUT_SEC", 2.2), 2.2)
    url = str(globals().get("LIGHT_SNAPSHOT_BULK_DIRECT_URL", "https://api.bithumb.com/public/ticker/ALL_KRW"))
    req = urllib.request.Request(url, headers={"User-Agent": "trading-bot/2.5.218", "accept": "application/json"})
    with urllib.request.urlopen(req, timeout=max(0.5, timeout_sec)) as resp:
        raw = resp.read().decode("utf-8", errors="replace")
    payload = json.loads(raw)
    return _parse_bulk_price_payload(payload)


def get_bulk_current_price_snapshot(force: bool = False) -> dict:
    """전체 현재가 스냅샷을 가져온다.

    v2.5.215 근본 수정:
    - pybithumb.get_current_price("ALL") 반복 timeout을 줄이기 위해 공식 Public REST를 우선 사용한다.
    - 실패 직후에는 fail cooldown 동안 다시 API를 두드리지 않고 최근 캐시를 반환한다.
    - 캐시가 조금 낡아도 30초까지는 백업 스냅샷으로 사용해 개별 get_price 폭증을 막는다.
    """
    global LIGHT_SNAPSHOT_BULK_PRICE_CACHE, LIGHT_SNAPSHOT_BULK_PRICE_TS, LIGHT_SNAPSHOT_BULK_LAST_NOTE, LIGHT_SNAPSHOT_BULK_LAST_FAIL_TS
    if not LIGHT_SNAPSHOT_BULK_PRICE_ON:
        return {}
    now_ts = time.time()
    try:
        cache_age = now_ts - safe_float(LIGHT_SNAPSHOT_BULK_PRICE_TS, 0)
        if (not force) and isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) and LIGHT_SNAPSHOT_BULK_PRICE_CACHE:
            if cache_age <= LIGHT_SNAPSHOT_BULK_PRICE_TTL_SEC:
                return dict(LIGHT_SNAPSHOT_BULK_PRICE_CACHE)
            # 실패 쿨다운 중에는 낡은 캐시라도 백업으로 쓴다.
            if now_ts - safe_float(globals().get("LIGHT_SNAPSHOT_BULK_LAST_FAIL_TS", 0), 0) <= safe_float(globals().get("LIGHT_SNAPSHOT_BULK_FAIL_COOLDOWN_SEC", 10), 10):
                if cache_age <= safe_float(globals().get("LIGHT_SNAPSHOT_BULK_STALE_KEEP_SEC", 30), 30):
                    LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"전체현재가 stale 사용({int(cache_age)}초)"
                    return dict(LIGHT_SNAPSHOT_BULK_PRICE_CACHE)
        # 공식 REST 직접 호출 우선
        try:
            _record_get_price_caller("bulk_current_price_direct", "call")
            parsed = _fetch_bithumb_all_ticker_direct(timeout_sec=LIGHT_SNAPSHOT_BULK_FETCH_TIMEOUT_SEC)
            if parsed:
                LIGHT_SNAPSHOT_BULK_PRICE_CACHE = parsed
                LIGHT_SNAPSHOT_BULK_PRICE_TS = time.time()
                LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"전체현재가 direct {len(parsed)}개"
                return dict(parsed)
            _record_get_price_caller("bulk_current_price_direct", "none")
        except Exception as e:
            LIGHT_SNAPSHOT_BULK_LAST_FAIL_TS = time.time()
            _record_get_price_caller("bulk_current_price_direct", "exception")
            LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"direct 실패:{e.__class__.__name__}"
            # pybithumb ALL fallback은 기본 비활성. 이 경로가 timeout 폭증의 주범이었다.
            if bool(globals().get("LIGHT_SNAPSHOT_BULK_PYBITHUMB_FALLBACK_ON", False)):
                before_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
                _record_get_price_caller("bulk_current_price", "call")
                payload = _call_with_timeout(pybithumb.get_current_price, "ALL", timeout_sec=1.15, default=None)
                if payload is None:
                    after_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
                    _record_get_price_caller("bulk_current_price", "timeout" if after_timeout > before_timeout else "none")
                parsed = _parse_bulk_price_payload(payload)
                if parsed:
                    LIGHT_SNAPSHOT_BULK_PRICE_CACHE = parsed
                    LIGHT_SNAPSHOT_BULK_PRICE_TS = time.time()
                    LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"전체현재가 pybithumb {len(parsed)}개"
                    return dict(parsed)
        # 실패해도 stale 캐시가 있으면 반환한다. 새 개별조회 폭증보다 낫다.
        if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) and LIGHT_SNAPSHOT_BULK_PRICE_CACHE:
            cache_age = now_ts - safe_float(LIGHT_SNAPSHOT_BULK_PRICE_TS, 0)
            if cache_age <= safe_float(globals().get("LIGHT_SNAPSHOT_BULK_STALE_KEEP_SEC", 30), 30):
                return dict(LIGHT_SNAPSHOT_BULK_PRICE_CACHE)
    except Exception as e:
        LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"전체현재가 오류:{str(e)[:40]}"
    return dict(LIGHT_SNAPSHOT_BULK_PRICE_CACHE) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else {}



def _ws_ticker_set_state(**kwargs):
    try:
        with WS_TICKER_LOCK:
            state = globals().setdefault("WS_TICKER_STATE", {})
            if not isinstance(state, dict):
                globals()["WS_TICKER_STATE"] = {}
                state = globals()["WS_TICKER_STATE"]
            for k, v in kwargs.items():
                state[k] = v
    except Exception:
        pass


def _ticker_to_ws_market_code(ticker: str) -> str:
    raw = str(ticker or "").upper().strip()
    if not raw:
        return ""
    if raw.startswith("KRW-"):
        return raw
    if raw.endswith("_KRW"):
        return "KRW-" + raw.split("_")[0]
    if raw.endswith("-KRW"):
        return "KRW-" + raw.split("-")[0]
    if "_" in raw:
        left, right = raw.split("_", 1)
        if right == "KRW":
            return f"KRW-{left}"
    if "-" in raw:
        parts = raw.split("-")
        if len(parts) == 2 and parts[0] == "KRW":
            return raw
    return f"KRW-{raw}"


def _ws_market_code_to_ticker(code: str) -> str:
    code = str(code or "").upper().strip()
    if code.startswith("KRW-"):
        return code.split("-", 1)[1]
    if code.endswith("_KRW"):
        return code.split("_", 1)[0]
    return code.replace("KRW-", "").replace("_KRW", "").strip()


def _ticker_to_legacy_ws_symbol(ticker_or_code: str) -> str:
    """legacy pub/ws 구독용 심볼(BTC_KRW)을 만든다."""
    raw = str(ticker_or_code or "").upper().strip()
    if not raw:
        return ""
    if raw.startswith("KRW-"):
        return raw.split("-", 1)[1] + "_KRW"
    if raw.endswith("_KRW"):
        return raw
    if raw.endswith("-KRW"):
        return raw.split("-", 1)[0] + "_KRW"
    if "_" in raw:
        left, right = raw.split("_", 1)
        if right == "KRW":
            return f"{left}_KRW"
    return f"{raw}_KRW"


def _ws_ticker_candidate_codes(limit: int = None) -> list:
    """WS 구독용 마켓 코드 목록을 만든다.

    너무 많은 종목을 한 번에 구독하면 WS 요청/메시지가 커지므로,
    유니버스/시장캐시/REST 전체현재가 순서로 우선순위를 잡아 제한한다.
    """
    limit = int(limit or globals().get("WS_TICKER_MAX_CODES", 180) or 180)
    candidates = []
    seen = set()

    def add(ticker):
        code = _ticker_to_ws_market_code(ticker)
        if not code or code in seen:
            return
        seen.add(code)
        candidates.append(code)

    try:
        for row in list(market_universe or []):
            if isinstance(row, dict):
                add(row.get("ticker"))
            else:
                add(row)
            if len(candidates) >= limit:
                return candidates[:limit]
    except Exception:
        pass
    try:
        for ticker in list(shared_market_cache.keys()) if isinstance(shared_market_cache, dict) else []:
            add(ticker)
            if len(candidates) >= limit:
                return candidates[:limit]
    except Exception:
        pass
    try:
        bulk = globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {})
        for ticker in list(bulk.keys()) if isinstance(bulk, dict) else []:
            add(ticker)
            if len(candidates) >= limit:
                return candidates[:limit]
    except Exception:
        pass
    try:
        bulk = get_bulk_current_price_snapshot(force=False)
        for ticker in list(bulk.keys()) if isinstance(bulk, dict) else []:
            add(ticker)
            if len(candidates) >= limit:
                return candidates[:limit]
    except Exception:
        pass
    return candidates[:limit]


def _parse_ws_ticker_payload(raw_msg):
    """빗썸 ticker websocket payload를 내부 ticker/price 형태로 변환.

    v2 websocket(KRW-BTC)과 legacy pub/ws(BTC_KRW/content)를 모두 받는다.
    수신은 됐는데 파싱이 안 되는 경우를 구분하기 위해 empty_parse_count를 올린다.
    """
    try:
        if isinstance(raw_msg, (bytes, bytearray)):
            raw_msg = raw_msg.decode("utf-8", errors="ignore")
        msg = json.loads(raw_msg) if isinstance(raw_msg, str) else raw_msg
    except Exception:
        return []
    if isinstance(msg, list):
        out = []
        for one in msg:
            out.extend(_parse_ws_ticker_payload(one))
        return out
    if not isinstance(msg, dict):
        return []

    content = msg.get("content") if isinstance(msg.get("content"), dict) else None
    if content:
        typ = str(msg.get("type", "") or "").lower()
        if typ and typ != "ticker":
            return []
        code = content.get("symbol", content.get("code", content.get("cd", "")))
        price = safe_float(content.get("closePrice", content.get("close_price", content.get("trade_price", content.get("tp", 0)))), 0)
        if not code or price <= 0:
            return []
        turnover = safe_float(content.get("value", content.get("volumePower", content.get("acc_trade_price_24h", 0))), 0)
        return [{
            "ticker": _ws_market_code_to_ticker(code),
            "code": str(code).upper(),
            "price": price,
            "turnover": turnover,
            "stream_type": "legacy",
            "raw_ts": safe_float(content.get("date", 0), 0),
        }]

    if msg.get("status"):
        _ws_ticker_set_state(last_note=str(msg.get("status"))[:80])
        return []
    typ = str(msg.get("type", msg.get("ty", "")) or "").lower()
    if typ and typ != "ticker":
        return []
    code = msg.get("code", msg.get("market", msg.get("cd", "")))
    price = safe_float(msg.get("trade_price", msg.get("tp", 0)), 0)
    if not code or price <= 0:
        return []
    ticker = _ws_market_code_to_ticker(code)
    turnover = safe_float(msg.get("acc_trade_price_24h", msg.get("atp24h", msg.get("acc_trade_price", msg.get("atp", 0)))), 0)
    return [{
        "ticker": ticker,
        "code": str(code).upper(),
        "price": price,
        "turnover": turnover,
        "stream_type": str(msg.get("stream_type", msg.get("st", "")) or ""),
        "raw_ts": safe_float(msg.get("timestamp", msg.get("tms", 0)), 0),
    }]


def _apply_ws_ticker_update(ticker: str, price: float, turnover_hint: float = 0.0, stream_type: str = ""):
    global LIGHT_SNAPSHOT_BULK_PRICE_CACHE, LIGHT_SNAPSHOT_BULK_PRICE_TS, LIGHT_SNAPSHOT_BULK_LAST_NOTE
    ticker = str(ticker or "").upper().strip()
    price = safe_float(price, 0)
    if not ticker or price <= 0:
        return
    now_ts = time.time()
    try:
        record_light_price_snapshot(ticker, price, turnover_hint=turnover_hint, source="ws_ticker", now_ts=now_ts)
    except Exception:
        pass
    try:
        with WS_TICKER_LOCK:
            cache = globals().setdefault("WS_TICKER_CACHE", {})
            if not isinstance(cache, dict):
                globals()["WS_TICKER_CACHE"] = {}
                cache = globals()["WS_TICKER_CACHE"]
            cache[ticker] = {
                "price": price,
                "turnover": safe_float(turnover_hint, 0),
                "ts": now_ts,
                "stream_type": str(stream_type or ""),
            }
            st = globals().setdefault("WS_TICKER_STATE", {})
            if isinstance(st, dict):
                st["last_msg_ts"] = now_ts
                st["message_count"] = int(safe_float(st.get("message_count", 0), 0)) + 1
                st["price_count"] = int(safe_float(st.get("price_count", 0), 0)) + 1
                st["last_ticker"] = ticker
                st["last_price"] = price
                st["last_note"] = "수신중"
        if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict):
            LIGHT_SNAPSHOT_BULK_PRICE_CACHE[ticker] = price
            LIGHT_SNAPSHOT_BULK_PRICE_TS = now_ts
            LIGHT_SNAPSHOT_BULK_LAST_NOTE = f"WS 현재가 보강({ticker})"
    except Exception:
        pass
    try:
        if isinstance(shared_market_cache, dict) and ticker in shared_market_cache:
            row = dict(shared_market_cache.get(ticker) or {})
            row["price"] = price
            row["current_price"] = price
            row["ws_price"] = price
            row["ws_price_ts"] = now_ts
            row["cache_source"] = str(row.get("cache_source", "")) or "ws_ticker"
            try:
                row = apply_light_snapshot_metrics_to_item(row)
            except Exception:
                pass
            shared_market_cache[ticker] = row
            if isinstance(shared_cache_row_times, dict):
                shared_cache_row_times[ticker] = now_ts
    except Exception:
        pass


def get_ws_ticker_status_snapshot() -> dict:
    try:
        now_ts = time.time()
        with WS_TICKER_LOCK:
            st = dict(globals().get("WS_TICKER_STATE", {}) if isinstance(globals().get("WS_TICKER_STATE", {}), dict) else {})
            cache = dict(globals().get("WS_TICKER_CACHE", {}) if isinstance(globals().get("WS_TICKER_CACHE", {}), dict) else {})
        live_count = 0
        ttl = safe_float(globals().get("WS_TICKER_CACHE_TTL_SEC", 20), 20)
        for row in cache.values():
            if isinstance(row, dict) and now_ts - safe_float(row.get("ts", 0), 0) <= ttl:
                live_count += 1
        st["cache_count"] = len(cache)
        st["live_count"] = live_count
        st["last_msg_age_sec"] = int(max(0, now_ts - safe_float(st.get("last_msg_ts", 0), 0))) if safe_float(st.get("last_msg_ts", 0), 0) > 0 else None
        return st
    except Exception:
        return {"status": "확인 실패"}


def get_ws_ticker_status_text() -> str:
    st = get_ws_ticker_status_snapshot()
    if not bool(globals().get("WS_TICKER_ON", True)):
        return "- WebSocket 현재가: 꺼짐"
    status = str(st.get("status", "대기") or "대기")
    conn = "연결" if bool(st.get("connected", False)) else "미연결"
    age = st.get("last_msg_age_sec")
    age_text = f"최근 {age}초 전" if age is not None else "수신 전"
    code_count = int(safe_float(st.get("code_count", 0), 0))
    live_count = int(safe_float(st.get("live_count", 0), 0))
    cache_count = int(safe_float(st.get("cache_count", 0), 0))
    msg_count = int(safe_float(st.get("message_count", 0), 0))
    last = str(st.get("last_ticker", "") or "-")
    err = str(st.get("last_error", "") or "")[:80]
    mode = str(st.get("endpoint_mode", "") or "")
    raw_count = int(safe_float(st.get("raw_count", 0), 0))
    empty_count = int(safe_float(st.get("empty_parse_count", 0), 0))
    no_msg = int(safe_float(st.get("no_message_count", 0), 0))
    mode_txt = f" / 모드 {mode}" if mode else ""
    base = f"- WebSocket 현재가: {status} / {conn}{mode_txt} / 구독 {code_count}개 / 활성 {live_count}/{cache_count}개 / {age_text} / 수신 {msg_count}건 / raw {raw_count}건 / 미파싱 {empty_count}건 / 최근 {last}"
    if no_msg:
        base += f" / 무수신전환 {no_msg}회"
    if err:
        base += f" / 오류 {err}"
    return base


def _ws_trade_set_state(**kwargs):
    try:
        with WS_TRADE_LOCK:
            state = globals().setdefault("WS_TRADE_STATE", {})
            if not isinstance(state, dict):
                globals()["WS_TRADE_STATE"] = {}
                state = globals()["WS_TRADE_STATE"]
            for k, v in kwargs.items():
                state[k] = v
    except Exception:
        pass


def _normalize_ws_trade_side(v) -> str:
    raw = str(v or "").upper().strip()
    if raw in {"BID", "BUY", "B", "1", "매수"}:
        return "buy"
    if raw in {"ASK", "SELL", "S", "2", "매도"}:
        return "sell"
    return "unknown"


def _parse_ws_trade_payload(raw_msg):
    """빗썸 trade/transaction websocket payload를 내부 체결 형태로 변환한다."""
    try:
        if isinstance(raw_msg, (bytes, bytearray)):
            raw_msg = raw_msg.decode("utf-8", errors="ignore")
        msg = json.loads(raw_msg) if isinstance(raw_msg, str) else raw_msg
    except Exception:
        return []
    if isinstance(msg, list):
        out = []
        for one in msg:
            out.extend(_parse_ws_trade_payload(one))
        return out
    if not isinstance(msg, dict):
        return []

    content = msg.get("content")
    if isinstance(content, dict):
        typ = str(msg.get("type", "") or "").lower().strip()
        if typ and typ not in {"transaction", "trade"}:
            return []
        rows = content.get("list") if isinstance(content.get("list"), list) else [content]
        out = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            code = row.get("symbol", row.get("code", row.get("cd", "")))
            price = safe_float(row.get("contPrice", row.get("trade_price", row.get("price", row.get("tp", 0)))), 0)
            qty = safe_float(row.get("contQty", row.get("trade_volume", row.get("volume", row.get("tv", 0)))), 0)
            amount = safe_float(row.get("contAmt", row.get("trade_amount", 0)), 0)
            if amount <= 0 and price > 0 and qty > 0:
                amount = price * qty
            side = _normalize_ws_trade_side(row.get("buySellGb", row.get("ask_bid", row.get("side", ""))))
            if code and price > 0:
                out.append({
                    "ticker": _ws_market_code_to_ticker(code),
                    "code": str(code).upper(),
                    "price": price,
                    "volume": qty,
                    "amount": amount,
                    "side": side,
                    "stream_type": "legacy",
                    "raw_ts": safe_float(row.get("contDtm", row.get("timestamp", 0)), 0),
                })
        return out

    if msg.get("status"):
        _ws_trade_set_state(last_note=str(msg.get("status"))[:80])
        return []
    typ = str(msg.get("type", msg.get("ty", "")) or "").lower().strip()
    if typ and typ not in {"trade", "transaction"}:
        return []
    code = msg.get("code", msg.get("market", msg.get("cd", "")))
    price = safe_float(msg.get("trade_price", msg.get("tp", msg.get("price", 0))), 0)
    qty = safe_float(msg.get("trade_volume", msg.get("tv", msg.get("volume", 0))), 0)
    amount = safe_float(msg.get("trade_amount", msg.get("atp", 0)), 0)
    if amount <= 0 and price > 0 and qty > 0:
        amount = price * qty
    if not code or price <= 0:
        return []
    return [{
        "ticker": _ws_market_code_to_ticker(code),
        "code": str(code).upper(),
        "price": price,
        "volume": qty,
        "amount": amount,
        "side": _normalize_ws_trade_side(msg.get("ask_bid", msg.get("side", ""))),
        "stream_type": str(msg.get("stream_type", msg.get("st", "")) or ""),
        "raw_ts": safe_float(msg.get("timestamp", msg.get("tms", 0)), 0),
    }]


def _apply_ws_trade_update(ticker: str, price: float, volume: float = 0.0, amount: float = 0.0, side: str = "", stream_type: str = ""):
    ticker = str(ticker or "").upper().strip()
    price = safe_float(price, 0)
    if not ticker or price <= 0:
        return
    now_ts = time.time()
    volume = safe_float(volume, 0)
    amount = safe_float(amount, 0)
    if amount <= 0 and price > 0 and volume > 0:
        amount = price * volume
    side = _normalize_ws_trade_side(side)
    try:
        # 체결 가격도 가격 스냅샷에 남겨 3분/5분 표본이 비는 시간을 줄인다.
        record_light_price_snapshot(ticker, price, turnover_hint=amount, source="ws_trade", now_ts=now_ts)
    except Exception:
        pass
    try:
        with WS_TRADE_LOCK:
            cache = globals().setdefault("WS_TRADE_CACHE", {})
            if not isinstance(cache, dict):
                globals()["WS_TRADE_CACHE"] = {}
                cache = globals()["WS_TRADE_CACHE"]
            rows = cache.get(ticker)
            if not isinstance(rows, list):
                rows = []
            ttl = safe_float(globals().get("WS_TRADE_ROW_TTL_SEC", 300), 300)
            rows = [r for r in rows if isinstance(r, dict) and now_ts - safe_float(r.get("ts", 0), 0) <= ttl]
            rows.append({"ts": now_ts, "price": price, "volume": volume, "amount": amount, "side": side, "stream_type": str(stream_type or "")})
            cache[ticker] = rows[-int(safe_float(globals().get("WS_TRADE_MAX_ROWS_PER_TICKER", 160), 160)):]
            st = globals().setdefault("WS_TRADE_STATE", {})
            if isinstance(st, dict):
                st["last_msg_ts"] = now_ts
                st["message_count"] = int(safe_float(st.get("message_count", 0), 0)) + 1
                st["last_ticker"] = ticker
                st["last_price"] = price
                st["last_side"] = side
                st["last_note"] = "수신중"
    except Exception:
        pass


def get_ws_trade_summary_for_ticker(ticker: str, window_sec: float = 60.0) -> dict:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return {}
    now_ts = time.time()
    window_sec = safe_float(window_sec, 60.0)
    try:
        with WS_TRADE_LOCK:
            rows = list((globals().get("WS_TRADE_CACHE", {}) or {}).get(ticker) or [])
        recent = [r for r in rows if isinstance(r, dict) and now_ts - safe_float(r.get("ts", 0), 0) <= window_sec]
        if not recent:
            return {"ticker": ticker, "count": 0, "amount": 0.0, "buy_count": 0, "sell_count": 0, "buy_ratio": 0.0, "label": "체결없음"}
        buy = [r for r in recent if str(r.get("side", "")) == "buy"]
        sell = [r for r in recent if str(r.get("side", "")) == "sell"]
        amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in recent)
        buy_amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in buy)
        sell_amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in sell)
        known_amount = buy_amount + sell_amount
        buy_ratio = (buy_amount / known_amount * 100.0) if known_amount > 0 else ((len(buy) / max(1, len(buy) + len(sell))) * 100.0 if (buy or sell) else 0.0)
        if len(recent) >= 8 and buy_ratio >= 62:
            label = "매수체결 우세"
        elif len(recent) >= 8 and buy_ratio <= 38 and (buy or sell):
            label = "매도체결 우세"
        elif len(recent) >= 5:
            label = "체결 활발"
        else:
            label = "체결 적음"
        return {
            "ticker": ticker,
            "count": len(recent),
            "amount": amount,
            "buy_count": len(buy),
            "sell_count": len(sell),
            "buy_amount": buy_amount,
            "sell_amount": sell_amount,
            "buy_ratio": buy_ratio,
            "label": label,
            "window_sec": window_sec,
        }
    except Exception:
        return {}



def get_ws_trade_score_adjustment_for_row(row: dict) -> tuple[float, str]:
    """v2.5.222: 최근 체결을 순위점수에 약하게만 반영한다."""
    try:
        if not bool(globals().get("WS_TRADE_SCORE_ON", True)):
            return 0.0, "체결점수 꺼짐"
        row = apply_ws_trade_metrics_to_item(row if isinstance(row, dict) else {})
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        buy_ratio = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        short_momentum = max(ch3, ch5)
        label = str(row.get("ws_trade_label_60s", "") or "")
        min_count = int(safe_float(globals().get("WS_TRADE_SCORE_MIN_COUNT", 4), 4))
        good_ratio = safe_float(globals().get("WS_TRADE_SCORE_BUY_RATIO_GOOD", 62), 62)
        bad_ratio = safe_float(globals().get("WS_TRADE_SCORE_SELL_RATIO_BAD", 38), 38)
        min_amt = safe_float(globals().get("WS_TRADE_SCORE_MIN_AMOUNT_GOOD", 1_000_000), 1_000_000)
        strong_amt = safe_float(globals().get("WS_TRADE_SCORE_STRONG_AMOUNT", 10_000_000), 10_000_000)
        tiny_amt = safe_float(globals().get("WS_TRADE_SCORE_TINY_AMOUNT", 500_000), 500_000)
        if cnt <= 0:
            return 0.0, "체결 표본 없음"
        adj = 0.0
        reasons = []
        if cnt < min_count or amt < tiny_amt:
            adj -= 0.08
            reasons.append("체결 적음")
        if cnt >= min_count and amt >= min_amt and buy_ratio >= good_ratio:
            adj += 0.22
            reasons.append("매수체결 우세")
            if short_momentum >= 0.15:
                adj += 0.13
                reasons.append("가격 유지")
            if amt >= strong_amt:
                adj += 0.12
                reasons.append("체결대금 큼")
        if cnt >= min_count and buy_ratio <= bad_ratio:
            adj -= 0.22
            reasons.append("매도체결 우세")
            if min(ch3, ch5) < 0 or short_momentum <= 0.05:
                adj -= 0.13
                reasons.append("가격 밀림")
        if amt >= strong_amt and short_momentum >= 0.10 and buy_ratio >= 50:
            adj += 0.08
            reasons.append("돈 유지")
        if ch15 < -0.20 and buy_ratio <= 45:
            adj -= 0.08
            reasons.append("중기 약함")
        adj = max(safe_float(globals().get("WS_TRADE_SCORE_MAX_PENALTY", -0.55), -0.55), min(safe_float(globals().get("WS_TRADE_SCORE_MAX_BONUS", 0.65), 0.65), adj))
        return round(adj, 3), ", ".join(reasons[:3]) if reasons else (label or "체결 보통")
    except Exception:
        return 0.0, "체결점수 실패"


def apply_ws_trade_score_adjustment(row: dict) -> dict:
    """순위 row에 체결 보조점수를 붙인다. 기존 점수는 snapshot_rank_base_score로 보관."""
    try:
        if not isinstance(row, dict):
            return row
        base = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        if "snapshot_rank_base_score" not in row:
            row["snapshot_rank_base_score"] = base
        adj, reason = get_ws_trade_score_adjustment_for_row(row)
        row["snapshot_rank_trade_adjust"] = round(adj, 3)
        row["snapshot_rank_trade_reason"] = str(reason or "")[:120]
        row["snapshot_rank_score"] = round(max(0.0, base + adj), 3)
        if adj > 0:
            row["ws_trade_rank_hint"] = f"체결 +{adj:.2f}"
        elif adj < 0:
            row["ws_trade_rank_hint"] = f"체결 {adj:.2f}"
        else:
            row["ws_trade_rank_hint"] = ""
        return row
    except Exception:
        return row


def is_ws_trade_low_activity_for_precision(row: dict) -> bool:
    """체결이 거의 없는데 점수만 큰 후보가 내부감시를 많이 차지하지 않게 한다."""
    try:
        if not bool(globals().get("WS_TRADE_LOW_ACTIVITY_PRECISION_BLOCK_ON", True)):
            return False
        row = apply_ws_trade_metrics_to_item(row if isinstance(row, dict) else {})
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        if cnt <= 0:
            # 수신 커버리지가 아직 낮을 수 있으므로 미수신은 강하게 막지 않는다.
            return False
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        strongest = _row_strongest_rank_move(row)
        keep_score = safe_float(globals().get("WS_TRADE_LOW_ACTIVITY_MIN_SCORE_KEEP", 6.0), 6.0)
        keep_move = safe_float(globals().get("WS_TRADE_LOW_ACTIVITY_MIN_MOVE_KEEP", 1.5), 1.5)
        tiny_amt = safe_float(globals().get("WS_TRADE_SCORE_TINY_AMOUNT", 500_000), 500_000)
        if cnt < int(safe_float(globals().get("WS_TRADE_SCORE_MIN_COUNT", 4), 4)) and amt < tiny_amt and score < keep_score and strongest < keep_move:
            return True
        return False
    except Exception:
        return False


def apply_ws_trade_metrics_to_item(item: dict) -> dict:
    if not isinstance(item, dict) or not bool(globals().get("WS_TRADE_ON", True)):
        return item
    ticker = str(item.get("ticker", "") or "").upper().strip()
    if not ticker:
        return item
    s60 = get_ws_trade_summary_for_ticker(ticker, 60)
    if not isinstance(s60, dict) or int(s60.get("count", 0)) <= 0:
        return item
    item["ws_trade_count_60s"] = int(s60.get("count", 0))
    item["ws_trade_amount_60s"] = safe_float(s60.get("amount", 0), 0)
    item["ws_trade_buy_ratio_60s"] = safe_float(s60.get("buy_ratio", 0), 0)
    item["ws_trade_label_60s"] = str(s60.get("label", "") or "")
    return item


def format_ws_trade_signal_for_row(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        if not bool(row.get("command_rank_snapshot_frozen", False)):
            row = apply_ws_trade_metrics_to_item(row)
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        if cnt <= 0:
            return "아직 적음"
        amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        br = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        label = str(row.get("ws_trade_label_60s", "") or "확인")
        label_map = {
            "매수체결 우세": "매수 우세",
            "매도체결 우세": "매도 우세",
            "체결 활발": "활발",
            "체결 적음": "적음",
            "체결없음": "없음",
        }
        label = label_map.get(label, label)
        if label.startswith("체결 "):
            label = label.replace("체결 ", "", 1)
        hint = str(row.get("ws_trade_rank_hint", "") or "").strip()
        hint_txt = f"·{hint}" if hint else ""
        return f"{label} {cnt}건/60초·매수{br:.0f}%·{format_money_compact_amount_krw(amt) if 'format_money_compact_amount_krw' in globals() else fmt_price(amt)}{hint_txt}"
    except Exception:
        return "확인실패"


def get_ws_trade_status_snapshot() -> dict:
    try:
        now_ts = time.time()
        with WS_TRADE_LOCK:
            st = dict(globals().get("WS_TRADE_STATE", {}) if isinstance(globals().get("WS_TRADE_STATE", {}), dict) else {})
            cache = dict(globals().get("WS_TRADE_CACHE", {}) if isinstance(globals().get("WS_TRADE_CACHE", {}), dict) else {})
        ttl = safe_float(globals().get("WS_TRADE_CACHE_TTL_SEC", 120), 120)
        live_count = 0
        recent_count = 0
        recent_amount = 0.0
        recent_buy = 0
        recent_sell = 0
        for rows in cache.values():
            if not isinstance(rows, list):
                continue
            has_live = False
            for r in rows:
                if not isinstance(r, dict):
                    continue
                age = now_ts - safe_float(r.get("ts", 0), 0)
                if age <= ttl:
                    has_live = True
                if age <= 60:
                    recent_count += 1
                    recent_amount += max(0.0, safe_float(r.get("amount", 0), 0))
                    if str(r.get("side", "")) == "buy":
                        recent_buy += 1
                    elif str(r.get("side", "")) == "sell":
                        recent_sell += 1
            if has_live:
                live_count += 1
        st["cache_count"] = len(cache)
        st["live_count"] = live_count
        st["recent_60_count"] = recent_count
        st["recent_60_amount"] = recent_amount
        st["recent_60_buy"] = recent_buy
        st["recent_60_sell"] = recent_sell
        st["last_msg_age_sec"] = int(max(0, now_ts - safe_float(st.get("last_msg_ts", 0), 0))) if safe_float(st.get("last_msg_ts", 0), 0) > 0 else None
        return st
    except Exception:
        return {"status": "확인 실패"}


def get_ws_trade_status_text() -> str:
    st = get_ws_trade_status_snapshot()
    if not bool(globals().get("WS_TRADE_ON", True)):
        return "- WebSocket 체결: 꺼짐"
    status = str(st.get("status", "대기") or "대기")
    conn = "연결" if bool(st.get("connected", False)) else "미연결"
    age = st.get("last_msg_age_sec")
    age_text = f"최근 {age}초 전" if age is not None else "수신 전"
    mode = str(st.get("endpoint_mode", "") or "")
    mode_txt = f" / 모드 {mode}" if mode else ""
    code_count = int(safe_float(st.get("code_count", 0), 0))
    live_count = int(safe_float(st.get("live_count", 0), 0))
    cache_count = int(safe_float(st.get("cache_count", 0), 0))
    msg_count = int(safe_float(st.get("message_count", 0), 0))
    raw_count = int(safe_float(st.get("raw_count", 0), 0))
    empty_count = int(safe_float(st.get("empty_parse_count", 0), 0))
    no_msg = int(safe_float(st.get("no_message_count", 0), 0))
    last = str(st.get("last_ticker", "") or "-")
    side = str(st.get("last_side", "") or "")
    recent_count = int(safe_float(st.get("recent_60_count", 0), 0))
    recent_amt = safe_float(st.get("recent_60_amount", 0), 0)
    buy = int(safe_float(st.get("recent_60_buy", 0), 0))
    sell = int(safe_float(st.get("recent_60_sell", 0), 0))
    side_txt = f"/{side}" if side else ""
    recent_txt = f" / 60초 {recent_count}건·{format_money_compact_amount_krw(recent_amt) if 'format_money_compact_amount_krw' in globals() else fmt_price(recent_amt)}·매수/매도 {buy}/{sell}"
    base = f"- WebSocket 체결: {status} / {conn}{mode_txt} / 구독 {code_count}개 / 활성 {live_count}/{cache_count}개 / {age_text} / 체결 {msg_count}건 / raw {raw_count}건 / 미파싱 {empty_count}건 / 최근 {last}{side_txt}{recent_txt}"
    if no_msg:
        base += f" / 무수신전환 {no_msg}회"
    err = str(st.get("last_error", "") or "")[:80]
    if err:
        base += f" / 오류 {err}"
    return base


def websocket_trade_worker_loop():
    """Bithumb public WebSocket trade worker. 현재는 분석/진단 보조값만 쌓는다."""
    if not bool(globals().get("WS_TRADE_ON", True)):
        _ws_trade_set_state(enabled=False, status="꺼짐", connected=False)
        return
    mode_index = 0
    modes = ["v2", "legacy"] if bool(globals().get("WS_TRADE_MODE_FALLBACK_ON", True)) else ["v2"]
    while True:
        ws = None
        endpoint_mode = modes[mode_index % len(modes)]
        try:
            codes = _ws_ticker_candidate_codes(limit=globals().get("WS_TRADE_MAX_CODES", 180))
            if not codes:
                _ws_trade_set_state(status="대기", connected=False, last_note="구독 대상 없음", endpoint_mode=endpoint_mode)
                time.sleep(3.0)
                continue
            try:
                import websocket  # websocket-client
            except Exception as e:
                _ws_trade_set_state(status="라이브러리 없음", connected=False, last_error=f"websocket import {e.__class__.__name__}", code_count=len(codes), endpoint_mode=endpoint_mode)
                time.sleep(30.0)
                continue
            url = str(globals().get("WS_TRADE_URL", "wss://ws-api.bithumb.com/websocket/v1"))
            if endpoint_mode == "legacy":
                url = str(globals().get("WS_TRADE_LEGACY_URL", "wss://pubwss.bithumb.com/pub/ws"))
            _ws_trade_set_state(status="연결중", connected=False, code_count=len(codes), last_error="", endpoint_mode=endpoint_mode)
            ws = websocket.create_connection(url, timeout=5, enable_multithread=True)
            try:
                ws.settimeout(safe_float(globals().get("WS_TRADE_RECV_TIMEOUT_SEC", 1.0), 1.0))
            except Exception:
                pass
            if endpoint_mode == "legacy":
                symbols = [_ticker_to_legacy_ws_symbol(c) for c in codes]
                symbols = [s for s in symbols if s]
                req = {"type": "transaction", "symbols": symbols}
                send_count = len(symbols)
            else:
                req = [
                    {"ticket": f"coinbot-trade-{int(time.time())}"},
                    {"type": "trade", "codes": codes},
                    {"format": "DEFAULT"},
                ]
                send_count = len(codes)
            ws.send(json.dumps(req))
            opened = time.time()
            _ws_trade_set_state(status="수신중", connected=True, last_open_ts=opened, code_count=send_count, last_note=f"구독 완료:{endpoint_mode}", endpoint_mode=endpoint_mode)
            last_ping = opened
            got_any_parsed = False
            while bool(globals().get("WS_TRADE_ON", True)):
                now_ts = time.time()
                if now_ts - opened >= safe_float(globals().get("WS_TRADE_SUBSCRIBE_REFRESH_SEC", 600), 600):
                    _ws_trade_set_state(last_note="구독 목록 갱신을 위해 재연결")
                    break
                if (not got_any_parsed) and (now_ts - opened >= safe_float(globals().get("WS_TRADE_NO_MESSAGE_SWITCH_SEC", 25.0), 25.0)):
                    try:
                        with WS_TRADE_LOCK:
                            st = globals().setdefault("WS_TRADE_STATE", {})
                            if isinstance(st, dict):
                                st["no_message_count"] = int(safe_float(st.get("no_message_count", 0), 0)) + 1
                                st["last_note"] = f"{endpoint_mode} 체결 무수신 → fallback 전환"
                    except Exception:
                        pass
                    break
                if now_ts - last_ping >= safe_float(globals().get("WS_TRADE_PING_SEC", 45), 45):
                    try:
                        ws.ping()
                    except Exception:
                        break
                    last_ping = now_ts
                try:
                    raw = ws.recv()
                except Exception as e:
                    name = e.__class__.__name__.lower()
                    if "timeout" in name:
                        continue
                    raise
                if not raw:
                    continue
                try:
                    with WS_TRADE_LOCK:
                        st = globals().setdefault("WS_TRADE_STATE", {})
                        if isinstance(st, dict):
                            st["raw_count"] = int(safe_float(st.get("raw_count", 0), 0)) + 1
                except Exception:
                    pass
                parsed_items = _parse_ws_trade_payload(raw)
                if not parsed_items:
                    try:
                        with WS_TRADE_LOCK:
                            st = globals().setdefault("WS_TRADE_STATE", {})
                            if isinstance(st, dict):
                                st["empty_parse_count"] = int(safe_float(st.get("empty_parse_count", 0), 0)) + 1
                                st["last_note"] = f"raw 수신/체결 파싱대기:{endpoint_mode}"
                    except Exception:
                        pass
                    continue
                got_any_parsed = True
                for item in parsed_items:
                    _apply_ws_trade_update(item.get("ticker"), item.get("price"), item.get("volume"), item.get("amount"), item.get("side"), item.get("stream_type"))
        except Exception as e:
            try:
                with WS_TRADE_LOCK:
                    st = globals().setdefault("WS_TRADE_STATE", {})
                    if isinstance(st, dict):
                        st["status"] = "재연결 대기"
                        st["connected"] = False
                        st["last_close_ts"] = time.time()
                        st["last_error"] = f"{e.__class__.__name__}: {str(e)[:80]}"
                        st["reconnect_count"] = int(safe_float(st.get("reconnect_count", 0), 0)) + 1
                        st["endpoint_mode"] = endpoint_mode
            except Exception:
                pass
            try:
                append_runtime_event_log("ws_trade_reconnect", "WebSocket trade 재연결 대기", extra={"error": str(e)[:160], "mode": endpoint_mode})
            except Exception:
                pass
        finally:
            try:
                if ws is not None:
                    ws.close()
            except Exception:
                pass
            try:
                _ws_trade_set_state(connected=False, last_close_ts=time.time())
            except Exception:
                pass
        mode_index += 1
        time.sleep(safe_float(globals().get("WS_TRADE_RECONNECT_SEC", 5.0), 5.0))



def _record_price_source(caller: str, source: str, ticker: str = ""):
    """v2.5.218: 가격값을 어느 소스에서 가져왔는지 누적 기록한다."""
    try:
        caller = str(caller or "unknown")[:80]
        source = str(source or "unknown")[:40]
        ticker = str(ticker or "").upper().strip()[:20]
        key = f"{caller}:{source}"
        now_ts = time.time()
        with PRICE_SOURCE_STATS_LOCK:
            row = PRICE_SOURCE_STATS.get(key)
            if not isinstance(row, dict):
                row = {"count": 0, "caller": caller, "source": source, "last_ts": 0.0, "last_ticker": ""}
            row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
            row["last_ts"] = now_ts
            if ticker:
                row["last_ticker"] = ticker
            PRICE_SOURCE_STATS[key] = row
            if len(PRICE_SOURCE_STATS) > PRICE_SOURCE_STAT_MAX:
                old = sorted(PRICE_SOURCE_STATS.items(), key=lambda kv: safe_float(kv[1].get("last_ts", 0), 0))
                for k, _v in old[:max(1, len(old) - PRICE_SOURCE_STAT_MAX)]:
                    PRICE_SOURCE_STATS.pop(k, None)
    except Exception:
        pass


def get_price_source_stats_text(limit: int = 6) -> str:
    try:
        with PRICE_SOURCE_STATS_LOCK:
            rows = [(k, dict(v)) for k, v in PRICE_SOURCE_STATS.items() if isinstance(v, dict)]
        if not rows:
            return "- 가격소스: 아직 기록 없음"
        rows.sort(key=lambda kv: (safe_float(kv[1].get("count", 0), 0), safe_float(kv[1].get("last_ts", 0), 0)), reverse=True)
        parts = []
        for _key, row in rows[:max(1, int(limit))]:
            caller = str(row.get("caller", "-") or "-")
            source = str(row.get("source", "-") or "-")
            cnt = int(safe_float(row.get("count", 0), 0))
            last = str(row.get("last_ticker", "") or "-")
            parts.append(f"{caller}:{source} {cnt}회/최근 {last}")
        tail = ""
        try:
            srcs = {str(row.get("source", "") or "") for _key, row in rows}
            if "rest_bulk" in srcs or "local_rest_bulk" in srcs:
                tail = " / rest_bulk=WS 미수신·오래됨 때 백업"
            if "miss" in srcs:
                tail += " / miss=해당 시점 가격소스 없음"
        except Exception:
            pass
        return "- 가격소스: " + ", ".join(parts) + tail
    except Exception:
        return "- 가격소스: 확인 실패"


def _get_ws_recent_price(ticker: str, max_age_sec: float = None):
    ticker = str(ticker or "").upper().strip()
    if not ticker or not bool(globals().get("PRICE_TRACK_USE_WS_FIRST", True)):
        return 0.0, 0.0
    max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("PRICE_TRACK_WS_TTL_SEC", 20.0), 20.0)
    try:
        now_ts = time.time()
        with WS_TICKER_LOCK:
            cache = globals().get("WS_TICKER_CACHE", {})
            row = dict(cache.get(ticker) or {}) if isinstance(cache, dict) else {}
        price = safe_float(row.get("price", 0), 0)
        ts = safe_float(row.get("ts", 0), 0)
        age = now_ts - ts if ts > 0 else 999999.0
        if price > 0 and age <= max_age_sec:
            return price, age
    except Exception:
        pass
    return 0.0, 0.0


def _get_light_recent_price(ticker: str, max_age_sec: float = None):
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return 0.0, 0.0
    max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("PRICE_TRACK_LIGHT_TTL_SEC", 45.0), 45.0)
    try:
        rows = _light_snapshot_rows(ticker)
        if not rows:
            return 0.0, 0.0
        row = rows[-1]
        price = safe_float(row.get("price", 0), 0)
        ts = safe_float(row.get("ts", 0), 0)
        age = time.time() - ts if ts > 0 else 999999.0
        if price > 0 and age <= max_age_sec:
            return price, age
    except Exception:
        pass
    return 0.0, 0.0


def _get_bulk_cached_price(ticker: str, max_age_sec: float = None):
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return 0.0, 0.0
    max_age_sec = safe_float(max_age_sec if max_age_sec is not None else globals().get("PRICE_TRACK_REST_STALE_SEC", 30.0), 30.0)
    try:
        cache = globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {})
        ts = safe_float(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_TS", 0), 0)
        age = time.time() - ts if ts > 0 else 999999.0
        if isinstance(cache, dict) and age <= max_age_sec:
            price = safe_float(cache.get(ticker, 0), 0)
            if price > 0:
                return price, age
    except Exception:
        pass
    return 0.0, 0.0


def get_cached_realtime_price(ticker: str, caller: str = "", allow_api_cache: bool = True):
    """WebSocket/REST/light/API 캐시 순서로 최근 가격을 가져온다. 개별 API는 호출하지 않는다."""
    ticker = str(ticker or "").upper().strip()
    caller = str(caller or "unknown")[:80]
    if not ticker:
        return 0.0, "none", 0.0
    price, age = _get_ws_recent_price(ticker)
    if price > 0:
        _record_price_source(caller, "ws", ticker)
        return price, "ws", age
    price, age = _get_bulk_cached_price(ticker)
    if price > 0:
        _record_price_source(caller, "rest_bulk", ticker)
        return price, "rest_bulk", age
    price, age = _get_light_recent_price(ticker)
    if price > 0:
        _record_price_source(caller, "light_snapshot", ticker)
        return price, "light_snapshot", age
    if allow_api_cache:
        try:
            cached = get_api_cache_entry(API_PRICE_CACHE, ticker, API_PRICE_CACHE_TTL_SEC * 3)
            if cached is not None:
                price = safe_float(cached, 0)
                if price > 0:
                    _record_price_source(caller, "api_cache", ticker)
                    return price, "api_cache", 0.0
        except Exception:
            pass
    _record_price_source(caller, "miss", ticker)
    return 0.0, "none", 0.0


def get_price_for_tracking_with_source(ticker: str, caller: str = "price_track", allow_api_fallback: bool = None):
    """내부감시 가격 추적용 통합 가격 함수.

    반환: (price, source, age_sec)
    v2.5.219 핵심:
    - update_active_price_check_refs/send_price_check_result는 이 함수만 타게 한다.
    - WebSocket -> REST direct 전체현재가 -> light snapshot -> API cache -> 개별 API 최후 순서.
    """
    ticker_key = str(ticker or "").upper().strip()
    price, source, age = get_cached_realtime_price(ticker_key, caller=caller, allow_api_cache=True)
    if price > 0:
        try:
            set_api_cache_entry(API_PRICE_CACHE, ticker_key, price)
        except Exception:
            pass
        return float(price), str(source or "cache"), safe_float(age, 0)
    if allow_api_fallback is None:
        allow_api_fallback = bool(globals().get("PRICE_TRACK_ALLOW_INDIVIDUAL_API_FALLBACK", False))
    if allow_api_fallback:
        price = get_price(ticker_key)
        if price > 0:
            _record_price_source(caller, "individual_api_fallback", ticker_key)
            return float(price), "individual_api_fallback", 0.0
    return -1.0, str(source or "none"), safe_float(age, 0)


def get_price_for_tracking(ticker: str, caller: str = "price_track", allow_api_fallback: bool = None) -> float:
    """내부감시 가격 추적용. 기본은 개별 get_current_price를 호출하지 않는다."""
    price, _source, _age = get_price_for_tracking_with_source(ticker, caller=caller, allow_api_fallback=allow_api_fallback)
    return price

def websocket_ticker_worker_loop():
    """Bithumb public WebSocket ticker worker.

    v2.5.217 보강:
    - v2 endpoint가 연결만 되고 수신 0건이면 자동으로 legacy pub/ws 방식으로 전환한다.
    - v2 구독 요청은 isOnlySnapshot/isOnlyRealtime 필드를 빼고 최소 포맷으로 보낸다.
    - raw 수신/미파싱/무수신 전환 횟수를 상태에 남겨 다음 원인 추적을 쉽게 한다.
    """
    if not bool(globals().get("WS_TICKER_ON", True)):
        _ws_ticker_set_state(enabled=False, status="꺼짐", connected=False)
        return
    mode_index = 0
    modes = ["v2", "legacy"] if bool(globals().get("WS_TICKER_MODE_FALLBACK_ON", True)) else ["v2"]
    while True:
        ws = None
        endpoint_mode = modes[mode_index % len(modes)]
        try:
            codes = _ws_ticker_candidate_codes(limit=globals().get("WS_TICKER_MAX_CODES", 180))
            if not codes:
                _ws_ticker_set_state(status="대기", connected=False, last_note="구독 대상 없음", endpoint_mode=endpoint_mode)
                time.sleep(3.0)
                continue
            try:
                import websocket  # websocket-client
            except Exception as e:
                _ws_ticker_set_state(status="라이브러리 없음", connected=False, last_error=f"websocket import {e.__class__.__name__}", code_count=len(codes), endpoint_mode=endpoint_mode)
                time.sleep(30.0)
                continue
            url = str(globals().get("WS_TICKER_URL", "wss://ws-api.bithumb.com/websocket/v1"))
            if endpoint_mode == "legacy":
                url = str(globals().get("WS_TICKER_LEGACY_URL", "wss://pubwss.bithumb.com/pub/ws"))
            _ws_ticker_set_state(status="연결중", connected=False, code_count=len(codes), last_error="", endpoint_mode=endpoint_mode)
            ws = websocket.create_connection(url, timeout=5, enable_multithread=True)
            try:
                ws.settimeout(safe_float(globals().get("WS_TICKER_RECV_TIMEOUT_SEC", 1.0), 1.0))
            except Exception:
                pass

            if endpoint_mode == "legacy":
                symbols = [_ticker_to_legacy_ws_symbol(c) for c in codes]
                symbols = [s for s in symbols if s]
                req = {"type": "ticker", "symbols": symbols, "tickTypes": ["24H"]}
                send_count = len(symbols)
            else:
                req = [
                    {"ticket": f"coinbot-{int(time.time())}"},
                    {"type": "ticker", "codes": codes},
                    {"format": "DEFAULT"},
                ]
                send_count = len(codes)
            ws.send(json.dumps(req))
            opened = time.time()
            _ws_ticker_set_state(status="수신중", connected=True, last_open_ts=opened, code_count=send_count, last_note=f"구독 완료:{endpoint_mode}", endpoint_mode=endpoint_mode)
            last_ping = opened
            got_any_parsed = False
            while bool(globals().get("WS_TICKER_ON", True)):
                now_ts = time.time()
                if now_ts - opened >= safe_float(globals().get("WS_TICKER_SUBSCRIBE_REFRESH_SEC", 600), 600):
                    _ws_ticker_set_state(last_note="구독 목록 갱신을 위해 재연결")
                    break
                if (not got_any_parsed) and (now_ts - opened >= safe_float(globals().get("WS_TICKER_NO_MESSAGE_SWITCH_SEC", 25.0), 25.0)):
                    try:
                        with WS_TICKER_LOCK:
                            st = globals().setdefault("WS_TICKER_STATE", {})
                            if isinstance(st, dict):
                                st["no_message_count"] = int(safe_float(st.get("no_message_count", 0), 0)) + 1
                                st["last_note"] = f"{endpoint_mode} 무수신 → fallback 전환"
                    except Exception:
                        pass
                    break
                if now_ts - last_ping >= safe_float(globals().get("WS_TICKER_PING_SEC", 45), 45):
                    try:
                        ws.ping()
                    except Exception:
                        break
                    last_ping = now_ts
                try:
                    raw = ws.recv()
                except Exception as e:
                    name = e.__class__.__name__.lower()
                    if "timeout" in name:
                        continue
                    raise
                if not raw:
                    continue
                try:
                    with WS_TICKER_LOCK:
                        st = globals().setdefault("WS_TICKER_STATE", {})
                        if isinstance(st, dict):
                            st["raw_count"] = int(safe_float(st.get("raw_count", 0), 0)) + 1
                except Exception:
                    pass
                parsed_items = _parse_ws_ticker_payload(raw)
                if not parsed_items:
                    try:
                        with WS_TICKER_LOCK:
                            st = globals().setdefault("WS_TICKER_STATE", {})
                            if isinstance(st, dict):
                                st["empty_parse_count"] = int(safe_float(st.get("empty_parse_count", 0), 0)) + 1
                                st["last_note"] = f"raw 수신/파싱대기:{endpoint_mode}"
                    except Exception:
                        pass
                    continue
                got_any_parsed = True
                for item in parsed_items:
                    _apply_ws_ticker_update(item.get("ticker"), item.get("price"), item.get("turnover"), item.get("stream_type"))
        except Exception as e:
            try:
                with WS_TICKER_LOCK:
                    st = globals().setdefault("WS_TICKER_STATE", {})
                    if isinstance(st, dict):
                        st["status"] = "재연결 대기"
                        st["connected"] = False
                        st["last_close_ts"] = time.time()
                        st["last_error"] = f"{e.__class__.__name__}: {str(e)[:80]}"
                        st["reconnect_count"] = int(safe_float(st.get("reconnect_count", 0), 0)) + 1
                        st["endpoint_mode"] = endpoint_mode
            except Exception:
                pass
            try:
                append_runtime_event_log("ws_ticker_reconnect", "WebSocket ticker 재연결 대기", extra={"error": str(e)[:160], "mode": endpoint_mode})
            except Exception:
                pass
        finally:
            try:
                if ws is not None:
                    ws.close()
            except Exception:
                pass
            try:
                _ws_ticker_set_state(connected=False, last_close_ts=time.time())
            except Exception:
                pass
        mode_index += 1
        time.sleep(safe_float(globals().get("WS_TICKER_RECONNECT_SEC", 5.0), 5.0))

def _light_snapshot_trim_rows(rows: list, now_ts: float = None) -> list:
    now_ts = safe_float(now_ts, time.time())
    kept = []
    for row in list(rows or []):
        if not isinstance(row, dict):
            continue
        ts = safe_float(row.get("ts", 0), 0)
        price = safe_float(row.get("price", 0), 0)
        if ts <= 0 or price <= 0:
            continue
        if now_ts - ts <= LIGHT_SNAPSHOT_TTL_SEC:
            kept.append(row)
    return kept[-LIGHT_SNAPSHOT_MAX_ROWS_PER_TICKER:]


def record_light_price_snapshot(ticker: str, price: float, turnover_hint: float = 0.0, source: str = "", now_ts: float = None):
    if not LIGHT_SNAPSHOT_ENGINE_ON:
        return
    ticker = str(ticker or "").upper().strip()
    price = safe_float(price, 0)
    if not ticker or price <= 0:
        return
    now_ts = safe_float(now_ts, time.time())
    try:
        with LIGHT_SNAPSHOT_LOCK:
            rows = _light_snapshot_trim_rows(LIGHT_SNAPSHOT_HISTORY.get(ticker, []), now_ts=now_ts)
            if rows:
                last = rows[-1]
                if now_ts - safe_float(last.get("ts", 0), 0) < LIGHT_SNAPSHOT_PRICE_CACHE_TTL_SEC and abs(safe_float(last.get("price", 0), 0) - price) <= max(price * 0.000001, 1e-12):
                    return
            rows.append({
                "ts": now_ts,
                "price": price,
                "turnover_hint": safe_float(turnover_hint, 0),
                "source": str(source or "")[:40],
            })
            LIGHT_SNAPSHOT_HISTORY[ticker] = rows[-LIGHT_SNAPSHOT_MAX_ROWS_PER_TICKER:]
    except Exception:
        pass


def _light_snapshot_rows(ticker: str) -> list:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return []
    try:
        with LIGHT_SNAPSHOT_LOCK:
            rows = _light_snapshot_trim_rows(LIGHT_SNAPSHOT_HISTORY.get(ticker, []), now_ts=time.time())
            LIGHT_SNAPSHOT_HISTORY[ticker] = rows
            return list(rows)
    except Exception:
        return []


def _snapshot_price_at_or_before(rows: list, target_ts: float, return_meta: bool = False):
    if not rows:
        return (None, False, 0.0) if return_meta else None
    candidate = None
    first = rows[0]
    for row in rows:
        ts = safe_float(row.get("ts", 0), 0)
        if ts <= target_ts:
            candidate = row
        else:
            break
    covered = candidate is not None
    if candidate is None:
        candidate = first
    price = safe_float(candidate.get("price", 0), 0)
    base_ts = safe_float(candidate.get("ts", 0), 0)
    if return_meta:
        return price, bool(covered), base_ts
    return price


def _snapshot_change_info(rows: list, seconds: int, current_price: float, now_ts: float = None) -> dict:
    now_ts = safe_float(now_ts, time.time())
    current_price = safe_float(current_price, 0)
    out = {"value": 0.0, "ready": False, "base_age_sec": 0.0}
    if not rows or current_price <= 0:
        return out
    base, covered, base_ts = _snapshot_price_at_or_before(rows, now_ts - int(seconds), return_meta=True)
    if not base or base <= 0:
        return out
    age = max(0.0, now_ts - safe_float(base_ts, 0))
    # 최소 80% 이상 과거 기준가가 있을 때만 해당 시간대 계산 완료로 본다.
    ready = bool(covered and age >= max(30.0, int(seconds) * 0.80))
    out.update({"value": round(((current_price - base) / base) * 100.0, 2), "ready": ready, "base_age_sec": round(age, 1)})
    return out


def _snapshot_change_pct(rows: list, seconds: int, current_price: float, now_ts: float = None) -> float:
    return safe_float(_snapshot_change_info(rows, seconds, current_price, now_ts).get("value", 0), 0)


def compute_light_snapshot_metrics(ticker: str, current_price: float = 0.0) -> dict:
    rows = _light_snapshot_rows(ticker)
    if not rows:
        return {}
    rows.sort(key=lambda x: safe_float(x.get("ts", 0), 0))
    now_ts = time.time()
    current_price = safe_float(current_price, 0)
    if current_price <= 0:
        current_price = safe_float(rows[-1].get("price", 0), 0)
    if current_price <= 0:
        return {}
    first_ts = safe_float(rows[0].get("ts", 0), 0)
    last_ts = safe_float(rows[-1].get("ts", 0), 0)
    span_sec = max(0.0, last_ts - first_ts)
    if len(rows) < LIGHT_SNAPSHOT_READY_MIN_ROWS or span_sec < LIGHT_SNAPSHOT_MIN_SPAN_SEC:
        return {"snapshot_ready": False, "snapshot_rows": len(rows), "snapshot_span_sec": round(span_sec, 1), "snapshot_price": current_price}
    recent_rows_30 = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 30 * 60] or rows
    recent_rows_5 = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 5 * 60] or rows[-min(len(rows), 5):]
    prices_30 = [safe_float(r.get("price", 0), 0) for r in recent_rows_30 if safe_float(r.get("price", 0), 0) > 0]
    if not prices_30:
        return {}
    low30 = min(prices_30)
    high30 = max(prices_30)
    sample_limited_30m = bool(span_sec < LIGHT_SNAPSHOT_MIN_RANGE_SPAN_SEC or len(prices_30) < 6)
    flat_sample_30m = bool(high30 > 0 and low30 > 0 and abs(high30 - low30) <= max(current_price * 0.0002, 1e-12))
    # 표본이 너무 적고 고가=저가처럼 보이면 고점거리 0.00%로 늦음 판정하지 않는다.
    # 이 상태는 실제 횡보가 아니라 스냅샷 부족일 수 있으므로 별도 플래그로 넘긴다.
    if sample_limited_30m and flat_sample_30m:
        from_low = 0.0
        below_high = 999.0
    else:
        from_low = ((current_price - low30) / low30) * 100.0 if low30 > 0 else 0.0
        below_high = ((high30 - current_price) / high30) * 100.0 if high30 > 0 else 999.0
    turnover_hints = [safe_float(r.get("turnover_hint", 0), 0) for r in recent_rows_5 if safe_float(r.get("turnover_hint", 0), 0) > 0]
    turnover_hint = max(turnover_hints) if turnover_hints else 0.0
    info_1 = _snapshot_change_info(rows, 60, current_price, now_ts)
    info_3 = _snapshot_change_info(rows, 3 * 60, current_price, now_ts)
    info_5 = _snapshot_change_info(rows, 5 * 60, current_price, now_ts)
    info_15 = _snapshot_change_info(rows, 15 * 60, current_price, now_ts)
    info_30 = _snapshot_change_info(rows, 30 * 60, current_price, now_ts)
    info_60 = _snapshot_change_info(rows, 60 * 60, current_price, now_ts)
    chg_1 = safe_float(info_1.get("value", 0), 0)
    chg_3 = safe_float(info_3.get("value", 0), 0)
    chg_5 = safe_float(info_5.get("value", 0), 0)
    chg_15 = safe_float(info_15.get("value", 0), 0)
    chg_30 = safe_float(info_30.get("value", 0), 0)
    chg_60 = safe_float(info_60.get("value", 0), 0)
    if abs(chg_60) < 0.0001 and span_sec < 60 * 60:
        info_60 = _snapshot_change_info(rows, int(max(span_sec, 60)), current_price, now_ts)
        chg_60 = safe_float(info_60.get("value", 0), 0)
    vol_proxy = 0.0
    if len(recent_rows_5) >= 2:
        pvals = [safe_float(r.get("price", 0), 0) for r in recent_rows_5 if safe_float(r.get("price", 0), 0) > 0]
        if len(pvals) >= 2:
            swing = ((max(pvals) - min(pvals)) / max(min(pvals), 1e-12)) * 100.0
            vol_proxy = min(max(0.55 + swing * 1.25 + abs(chg_5) * 0.35, 0.0), 6.0)
    return {
        "snapshot_ready": True,
        "snapshot_rows": len(rows),
        "snapshot_span_sec": round(span_sec, 1),
        "snapshot_price": current_price,
        "snapshot_turnover_hint": turnover_hint,
        "change_1": chg_1,
        "change_3": chg_3,
        "change_5": chg_5,
        "change_15": chg_15,
        "change_30": chg_30,
        "change_60": chg_60,
        "change_1_ready": bool(info_1.get("ready", False)),
        "change_3_ready": bool(info_3.get("ready", False)),
        "change_5_ready": bool(info_5.get("ready", False)),
        "change_15_ready": bool(info_15.get("ready", False)),
        "change_30_ready": bool(info_30.get("ready", False)),
        "change_60_ready": bool(info_60.get("ready", False)),
        "change_1_base_age_sec": safe_float(info_1.get("base_age_sec", 0), 0),
        "change_3_base_age_sec": safe_float(info_3.get("base_age_sec", 0), 0),
        "change_5_base_age_sec": safe_float(info_5.get("base_age_sec", 0), 0),
        "change_15_base_age_sec": safe_float(info_15.get("base_age_sec", 0), 0),
        "change_30_base_age_sec": safe_float(info_30.get("base_age_sec", 0), 0),
        "change_60_base_age_sec": safe_float(info_60.get("base_age_sec", 0), 0),
        "from_low": round(from_low, 2),
        "below_high": round(below_high, 2),
        "recent_30m_low_price": round(low30, 8),
        "recent_30m_high_price": round(high30, 8),
        "snapshot_sample_limited_30m": sample_limited_30m,
        "snapshot_flat_range_guard": bool(sample_limited_30m and flat_sample_30m),
        "vol_ratio_snapshot": round(vol_proxy, 2),
    }


def apply_light_snapshot_metrics_to_item(item: dict) -> dict:
    if not isinstance(item, dict) or not LIGHT_SNAPSHOT_ENGINE_ON:
        return item
    ticker = str(item.get("ticker", "") or "").upper().strip()
    price = safe_float(item.get("price", item.get("current_price", 0)), 0)
    if not ticker:
        return item
    metrics = compute_light_snapshot_metrics(ticker, current_price=price)
    if not metrics:
        return item
    item["light_snapshot"] = metrics
    if not metrics.get("snapshot_ready"):
        return item
    item["snapshot_engine_used"] = True
    price2 = safe_float(metrics.get("snapshot_price", 0), 0)
    if price2 > 0:
        item["price"] = price2
        item["current_price"] = price2
    for key in ("change_1", "change_3", "change_5", "change_15", "change_30", "change_60"):
        val = safe_float(metrics.get(key, 0), 0)
        if abs(val) > 0.0001 or abs(safe_float(item.get(key, 0), 0)) < 0.0001:
            item[key] = val
        item[f"{key}_ready"] = bool(metrics.get(f"{key}_ready", False))
    item["from_low"] = safe_float(metrics.get("from_low", item.get("from_low", 0)), item.get("from_low", 0))
    item["below_high"] = safe_float(metrics.get("below_high", item.get("below_high", 999)), item.get("below_high", 999))
    if metrics.get("snapshot_sample_limited_30m"):
        item["snapshot_sample_limited_30m"] = True
    if metrics.get("snapshot_flat_range_guard"):
        item["snapshot_flat_range_guard"] = True
    snap = item.get("pre_alert_snapshot") if isinstance(item.get("pre_alert_snapshot"), dict) else {}
    snap.update({
        "chg_5m": safe_float(item.get("change_5", 0), 0),
        "chg_15m": safe_float(item.get("change_15", 0), 0),
        "chg_30m": safe_float(item.get("change_30", 0), 0),
        "from_30m_low_pct": safe_float(item.get("from_low", 0), 0),
        "below_30m_high_pct": safe_float(item.get("below_high", 999), 999),
        "recent_30m_low_price": safe_float(metrics.get("recent_30m_low_price", 0), 0),
        "recent_30m_high_price": safe_float(metrics.get("recent_30m_high_price", 0), 0),
        "snapshot_engine_used": True,
        "snapshot_sample_limited_30m": bool(metrics.get("snapshot_sample_limited_30m", False)),
        "snapshot_flat_range_guard": bool(metrics.get("snapshot_flat_range_guard", False)),
    })
    item["pre_alert_snapshot"] = snap
    vol_snap = safe_float(metrics.get("vol_ratio_snapshot", 0), 0)
    if safe_float(item.get("vol_ratio", 0), 0) <= 0 and vol_snap > 0:
        item["vol_ratio"] = vol_snap
    turn_hint = safe_float(metrics.get("snapshot_turnover_hint", 0), 0)
    if turn_hint > 0:
        item.setdefault("turnover", turn_hint)
        item.setdefault("turnover_5m", turn_hint)
    try:
        item = apply_ws_trade_metrics_to_item(item)
    except Exception:
        pass
    return item




def is_realtime_rank_tick_noise(row_or_metrics: dict) -> bool:
    """BTT형 초저가 한 틱 왜곡 분리.

    가격이 0.001원 이하인 코인은 한 호가만 움직여도 퍼센트가 비정상적으로 크게 보일 수 있다.
    이런 경우는 순위에는 보이더라도 정밀검토/알림 후보로 올리지 않고 노이즈 표본으로만 남긴다.
    """
    try:
        if not bool(globals().get("REALTIME_RANK_TICK_NOISE_ON", True)):
            return False
        row = row_or_metrics if isinstance(row_or_metrics, dict) else {}
        price = safe_float(row.get("price", row.get("current_price", row.get("snapshot_price", 0))), 0)
        if price <= 0 or price > safe_float(globals().get("REALTIME_RANK_TICK_NOISE_PRICE_MAX", 0.001), 0.001):
            return False
        moves = [
            safe_float(row.get("change_1", 0), 0),
            safe_float(row.get("change_3", 0), 0),
            safe_float(row.get("change_5", 0), 0),
            safe_float(row.get("change_15", 0), 0),
            safe_float(row.get("change_30", 0), 0),
            safe_float(row.get("change_60", 0), 0),
        ]
        strongest = max(moves) if moves else 0.0
        return strongest >= safe_float(globals().get("REALTIME_RANK_TICK_NOISE_MOVE_PCT", 8.0), 8.0)
    except Exception:
        return False


def classify_rank_watch_chart_state(row: dict) -> dict:
    """OHLCV 정밀분석 전 순위감시용 1차 차트 상태.

    정밀 차트수치가 붙기 전에는 0값을 차트 판단처럼 보여주지 말고,
    3/5/15/30/60분 흐름만으로 '초입/재출발/식는 중/늦음/노이즈'를 가볍게 분류한다.
    """
    try:
        row = row if isinstance(row, dict) else {}
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        ch30 = safe_float(row.get("change_30", 0), 0)
        ch60 = safe_float(row.get("change_60", 0), 0)
        from_low = safe_float(row.get("from_low", row.get("from_30m_low_pct", 0)), 0)
        gap = safe_float(row.get("below_high", row.get("below_30m_high_pct", 999)), 999)
        score = safe_float(row.get("snapshot_rank_score", 0), 0)
        if is_realtime_rank_tick_noise(row):
            return {
                "code": "NOISE",
                "label": "초저가 틱노이즈 가능성",
                "early": 0.0,
                "restart": 0.0,
                "late": 0.0,
                "warning": "가격 단위가 너무 작아 한 틱 상승률이 크게 보일 수 있음",
            }
        if 'is_money_or_candle_flash_watch_limited_v244' in globals() and is_money_or_candle_flash_watch_limited_v244(row):
            return {
                "code": "FLASH",
                "label": "반짝형 관찰",
                "early": max(ch3, ch5, 0) * 0.25,
                "restart": max(ch15, ch30, 0) * 0.20,
                "late": max(0.5, from_low * 0.45),
                "warning": "돈흐름/현재봉이 식는 쪽이라 초입 강세 문구는 보류",
            }
        if 'is_current_candle_weak_for_label_v244' in globals() and is_current_candle_weak_for_label_v244(row) and max(ch3, ch5) <= 1.20:
            return {
                "code": "CANDLE_WEAK",
                "label": "위꼬리/현재봉 밀림",
                "early": max(ch3, ch5, 0) * 0.30,
                "restart": max(ch15, ch30, 0) * 0.25,
                "late": max(0.6, from_low * 0.50),
                "warning": "현재봉이 밀려서 바로 초입 강세로 보기는 어려움",
            }
        low_route_v244 = get_low_structure_route_label_v244(row) if 'get_low_structure_route_label_v244' in globals() else ""
        if low_route_v244 in {"저점높임 재출발형", "저점방어 재출발형"} and max(ch3, ch5) >= -0.10 and from_low <= safe_float(globals().get("LOW_STRUCTURE_V244_MAX_FROM_LOW_FOR_RESTART", 3.20), 3.20):
            return {
                "code": "LOW_RESTART",
                "label": low_route_v244,
                "early": max(ch3, ch5, 0) * 0.65,
                "restart": min(9.9, score * 0.35 + max(ch15, ch30, 0) * 0.50 + 1.20),
                "late": max(0.0, from_low - 2.8),
                "warning": "저점방어/저점높임이 살아 있어 재출발 여부 확인",
            }
        if from_low >= 4.8 or (ch60 >= 6.0 and ch3 < 0.8):
            return {
                "code": "LATE",
                "label": "이미 많이 오른 늦은 자리",
                "early": max(ch3, 0) * 0.4,
                "restart": max(ch15, 0) * 0.3,
                "late": min(9.9, from_low + max(ch60, 0) * 0.45),
                "warning": "저점대비 진행폭이 커서 추격 위험 먼저 확인",
            }
        if ch15 >= 1.2 and ch30 >= 0.8 and max(ch3, ch5) >= 0.20:
            return {
                "code": "RESTART",
                "label": "중간가속/재출발 확인중",
                "early": max(ch3, ch5, 0) * 0.8,
                "restart": min(9.9, ch15 * 1.1 + ch30 * 0.6 + score * 0.25),
                "late": max(0.0, from_low - 2.6),
                "warning": "15분 힘은 있으니 다음 봉 돈 유지 확인",
            }
        if ch15 >= 1.0 and ch3 <= 0.0 and ch5 <= 0.35:
            return {
                "code": "FADING",
                "label": "위에서 식는 중",
                "early": 0.0,
                "restart": max(ch15, 0) * 0.35,
                "late": max(1.0, from_low * 0.6),
                "warning": "15분은 남아 있으나 3/5분 재가속이 약함",
            }
        if ch3 >= 0.70 or ch5 >= 0.90 or (ch15 >= 0.80 and max(ch3, ch5) >= 0.35):
            return {
                "code": "EARLY",
                "label": "초입 강세 확인중",
                "early": min(9.9, max(ch3, ch5) * 1.25 + score * 0.30),
                "restart": max(ch15, ch30, 0) * 0.45,
                "late": max(0.0, from_low - 3.0),
                "warning": "정밀 차트와 거래대금이 붙으면 알림 후보 여부 판단",
            }
        return {
            "code": "WATCH",
            "label": "순위권 움직임만 기록",
            "early": max(ch3, ch5, 0) * 0.5,
            "restart": max(ch15, ch30, 0) * 0.35,
            "late": max(0.0, from_low - 3.2),
            "warning": "아직 바로 알림감은 아니고 복기용",
        }
    except Exception:
        return {"code": "UNKNOWN", "label": "차트상태 확인중", "early": 0.0, "restart": 0.0, "late": 0.0, "warning": ""}


def apply_rank_watch_chart_state(item: dict) -> dict:
    try:
        if not isinstance(item, dict):
            return item
        item = apply_precision_minute1_state_to_row(item) if 'apply_precision_minute1_state_to_row' in globals() else item
        state = classify_rank_watch_chart_state(item)
        item["rank_watch_chart_state"] = state.get("label", "차트상태 확인중")
        item["chart_lifecycle_code"] = state.get("code", "UNKNOWN")
        item["chart_lifecycle_label"] = state.get("label", "차트상태 확인중")
        item["chart_lifecycle_early_score"] = safe_float(state.get("early", 0), 0)
        item["chart_lifecycle_restart_score"] = safe_float(state.get("restart", 0), 0)
        item["chart_lifecycle_late_score"] = safe_float(state.get("late", 0), 0)
        item["chart_lifecycle_gap_pct"] = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
        item["chart_lifecycle_from_low_pct"] = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
        item["chart_lifecycle_warning"] = str(state.get("warning", "") or "")
        if state.get("code") == "NOISE":
            item["rank_tick_noise_block"] = True
            item["ultra_low_tick_noise_block"] = True
        return item
    except Exception:
        return item


def format_reverse_trace_chart_line(row: dict, rebreakout_gap_text: str = "") -> str:
    try:
        detail_cnt = _review_dump_meaningful_chart_field_count(row)
        if detail_cnt < 3:
            state = classify_rank_watch_chart_state(row)
            src = str(row.get('precision_chart_source', '') or '').strip()
            src_text = f" / 연결상태 {src}" if src else ""
            return (
                f"- 정밀차트: 아직 미검증{src_text} / 1차상태 {state.get('label','확인중')} / "
                f"15분 {safe_float(row.get('change_15',0),0):+.2f}% / "
                f"정밀검토 대기면 내부감시에 등록해 10분·30분 결과를 남김"
            )
        return f"- 차트수치: {format_chart_quant_summary_text(row, compact=False)}{rebreakout_gap_text}"
    except Exception:
        return f"- 정밀차트: 확인중{rebreakout_gap_text}"

def _snapshot_rank_score(metrics: dict, turnover_hint: float = 0.0) -> float:
    """현재가 스냅샷만으로 만든 내부 실시간 상승률 점수."""
    try:
        metrics = metrics if isinstance(metrics, dict) else {}
        ch1 = safe_float(metrics.get("change_1", 0), 0)
        ch3 = safe_float(metrics.get("change_3", 0), 0)
        ch5 = safe_float(metrics.get("change_5", 0), 0)
        ch15 = safe_float(metrics.get("change_15", 0), 0)
        ch30 = safe_float(metrics.get("change_30", 0), 0)
        ch60 = safe_float(metrics.get("change_60", 0), 0)
        from_low = safe_float(metrics.get("from_low", 0), 0)
        if is_realtime_rank_tick_noise({**metrics, "price": metrics.get("snapshot_price", metrics.get("price", 0))}):
            return safe_float(globals().get("REALTIME_RANK_TICK_NOISE_SCORE_CAP", 0.15), 0.15)
        turnover_hint = safe_float(turnover_hint if turnover_hint > 0 else metrics.get("snapshot_turnover_hint", 0), 0)
        money_bonus = 0.0
        if turnover_hint >= 50_000_000:
            money_bonus = 2.0
        elif turnover_hint >= 10_000_000:
            money_bonus = 1.0
        elif turnover_hint >= 1_000_000:
            money_bonus = 0.35
        app_bonus = 0.0
        try:
            app_info = rank_app_compare_window_score(metrics) if 'rank_app_compare_window_score' in globals() else {"count": 0, "score": 0}
            if int(safe_float(app_info.get("count", 0), 0)) >= int(safe_float(globals().get("REALTIME_RANK_APP_COMPARE_MIN_WINDOWS", 2), 2)):
                app_bonus = min(3.0, safe_float(globals().get("REALTIME_RANK_APP_COMPARE_BONUS", 1.25), 1.25) + safe_float(app_info.get("score", 0), 0) * 0.12)
        except Exception:
            app_bonus = 0.0
        return round(
            max(ch1, 0) * 1.25
            + max(ch3, 0) * 1.70
            + max(ch5, 0) * 1.35
            + max(ch15, 0) * 0.70
            + max(ch30, 0) * 0.45
            + max(ch60, 0) * 0.25
            + max(min(from_low, 8.0), 0) * 0.12
            + money_bonus
            + app_bonus,
            3,
        )
    except Exception:
        return 0.0


def rank_app_compare_window_score(row: dict) -> dict:
    """v2.5.245: 앱 시간대별 상승률 대조용 반복등장 점수.

    앱 순위를 직접 읽는 기능은 아니다. 현재가 스냅샷에서 1/3/5/15/30분 중
    여러 구간에 동시에 힘이 보이는 후보를 rank_watch에서 덜 빠지게 하는 보조값이다.
    """
    try:
        row = row if isinstance(row, dict) else {}
        windows = [
            ("1m", safe_float(row.get("change_1", 0), 0), 0.45),
            ("3m", safe_float(row.get("change_3", 0), 0), 0.55),
            ("5m", safe_float(row.get("change_5", 0), 0), 0.65),
            ("15m", safe_float(row.get("change_15", 0), 0), 0.90),
            ("30m", safe_float(row.get("change_30", 0), 0), 1.05),
            ("1h", safe_float(row.get("change_60", 0), 0), 1.20),
        ]
        hits = [(name, val) for name, val, th in windows if val >= th]
        score = sum(max(0.0, min(val, 5.0)) for _name, val in hits)
        if len(hits) >= 3:
            score += 1.0
        elif len(hits) >= 2:
            score += 0.45
        return {"count": len(hits), "score": round(score, 3), "hits": hits}
    except Exception:
        return {"count": 0, "score": 0.0, "hits": []}


def apply_rank_app_compare_overlay_v245(row: dict) -> dict:
    try:
        if not isinstance(row, dict) or not bool(globals().get("REALTIME_RANK_APP_COMPARE_ON", True)):
            return row
        info = rank_app_compare_window_score(row)
        row["app_compare_window_count"] = int(safe_float(info.get("count", 0), 0))
        row["app_compare_score"] = safe_float(info.get("score", 0), 0)
        row["app_compare_hits"] = ",".join([str(x[0]) for x in info.get("hits", [])])
        if row["app_compare_window_count"] >= int(safe_float(globals().get("REALTIME_RANK_APP_COMPARE_MIN_WINDOWS", 2), 2)):
            row["app_compare_candidate"] = True
            row["snapshot_rank_score"] = safe_float(row.get("snapshot_rank_score", 0), 0) + min(3.0, safe_float(globals().get("REALTIME_RANK_APP_COMPARE_BONUS", 1.25), 1.25) + row["app_compare_score"] * 0.12)
        return row
    except Exception:
        return row


def is_realtime_rank_precision_candidate(row: dict) -> bool:
    """순위권 강세를 복기용으로만 두지 않고 정밀검토 대기로 올릴지 판단한다."""
    try:
        if not bool(globals().get("REALTIME_RANK_PRECISION_ON", True)):
            return False
        row = row if isinstance(row, dict) else {}
        score = safe_float(row.get("snapshot_rank_score", 0), 0)
        rank = int(safe_float(row.get("snapshot_rank", 999), 999))
        ch1 = safe_float(row.get("change_1", 0), 0)
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        ch30 = safe_float(row.get("change_30", 0), 0)
        ch60 = safe_float(row.get("change_60", 0), 0)
        strongest = max(ch1, ch3, ch5, ch15, ch30, ch60)
        if is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            try:
                row["rank_tick_noise_block"] = True
                row["ultra_low_tick_noise_block"] = True
            except Exception:
                pass
            return False
        row = apply_ws_trade_metrics_to_item(row)
        if is_ws_trade_low_activity_for_precision(row):
            return False
        trade_cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        trade_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        trade_buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        if trade_cnt >= 8 and trade_amt >= 1_000_000 and trade_buy >= 68 and max(ch3, ch5) >= 0.25 and score >= 4.35:
            return True
        if trade_cnt >= 8 and trade_buy <= 35 and max(ch3, ch5) <= 0.15 and score < 6.20:
            return False
        if score >= safe_float(globals().get("REALTIME_RANK_PRECISION_SCORE", 5.0), 5.0):
            return True
        if 0 < rank <= int(safe_float(globals().get("REALTIME_RANK_PRECISION_TOP_RANK", 3), 3)) and score >= safe_float(globals().get("REALTIME_RANK_PRECISION_TOP_SCORE", 4.0), 4.0):
            return True
        if ch3 >= safe_float(globals().get("REALTIME_RANK_PRECISION_MOVE3", 1.20), 1.20):
            return True
        if ch5 >= safe_float(globals().get("REALTIME_RANK_PRECISION_MOVE5", 1.35), 1.35):
            return True
        if ch15 >= safe_float(globals().get("REALTIME_RANK_PRECISION_MOVE15", 1.50), 1.50) and max(ch3, ch5) >= 0.15:
            return True
        if ch30 >= safe_float(globals().get("REALTIME_RANK_PRECISION_MOVE30", 1.70), 1.70) and max(ch3, ch5) >= 0.20:
            return True
        if strongest >= 2.20 and score >= 3.40:
            return True
        return False
    except Exception:
        return False


def realtime_rank_watch_action_label(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        if bool(row.get("rank_tick_noise_block", False)) or is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            return "틱노이즈 제외"
        sustain_ctx = classify_money_sustain_for_row(row)
        if ('is_money_or_candle_flash_watch_limited_v244' in globals() and is_money_or_candle_flash_watch_limited_v244(row)) or (bool(sustain_ctx.get("flash_risk", False)) and safe_float(row.get("snapshot_rank_score", 0), 0) < 7.0):
            return "반짝형 관찰"
        if str(sustain_ctx.get("watch_priority", "")) == "low" and money_status_code_for_row(row) in {"actual_zero", "tiny", "thin"}:
            return "복기용 기록"
        return "정밀검토 대기" if bool(row.get("rank_precision_watch", False)) or is_realtime_rank_precision_candidate(row) else "복기용 기록"
    except Exception:
        return "복기용 기록"


def realtime_rank_watch_action_explain(row: dict) -> str:
    label = realtime_rank_watch_action_label(row)
    if label == "정밀검토 대기":
        return "순위권 강세라 내부 감시 후보로 한 번 더 올려서 차트와 돈을 확인할 자리야. 바로 매수 신호는 아님"
    if label == "틱노이즈 제외":
        return "가격 단위가 너무 작아 한 틱 상승률이 크게 보이는 노이즈 가능성이 커서 정밀검토/알림에서는 제외한 기록이야"
    if label == "반짝형 관찰":
        return "가격은 움직였지만 돈/체결 유지가 약하거나 현재봉이 식는 쪽이라 내부감시 우선순위를 낮춘 기록이야"
    return "바로 매수 신호는 아니고, 나중에 놓침/승격 여부를 비교하려고 남긴 기록이야"



def _rank_state_snapshot_meta(ticker: str, now_ts: float = None) -> dict:
    """v2.5.252: 단일 티커 fallback용 메타. 대량 rank_source에서는 bulk 메타를 쓴다."""
    try:
        metas = _rank_state_snapshot_meta_bulk(now_ts=now_ts, only_ticker=str(ticker or "").upper().strip())
        return metas[0] if metas else {}
    except Exception:
        return {}


def _rank_state_snapshot_meta_bulk(now_ts: float = None, only_ticker: str = "") -> list:
    """v2.5.252: LIGHT_SNAPSHOT_HISTORY를 한 번만 잠그고 rank 재사용용 메타를 만든다.

    기존 방식은 400개 이상 티커마다 lock + rows 복사를 반복해서 시간이 지나면 meta 단계가
    20초 이상으로 튀었다. 여기서는 마지막/첫 유효 row만 확인해 build_rank_source 병목을 줄인다.
    """
    out = []
    try:
        now_ts = safe_float(now_ts, time.time())
        only_ticker = str(only_ticker or "").upper().strip()
        ttl = safe_float(globals().get("LIGHT_SNAPSHOT_TTL_SEC", 900), 900)
        with LIGHT_SNAPSHOT_LOCK:
            items = list(LIGHT_SNAPSHOT_HISTORY.items()) if isinstance(LIGHT_SNAPSHOT_HISTORY, dict) else []
            for tk, rows in items:
                ticker = str(tk or "").upper().strip()
                if only_ticker and ticker != only_ticker:
                    continue
                if not ticker or is_watch_excluded_ticker(ticker):
                    continue
                if not isinstance(rows, list) or not rows:
                    continue
                first = None
                last = None
                for r in rows:
                    if isinstance(r, dict):
                        first = r
                        break
                for r in reversed(rows):
                    if isinstance(r, dict):
                        last = r
                        break
                if not isinstance(first, dict) or not isinstance(last, dict):
                    continue
                last_ts = safe_float(last.get("ts", 0), 0)
                first_ts = safe_float(first.get("ts", 0), 0)
                price = safe_float(last.get("price", 0), 0)
                if price <= 0 or last_ts <= 0 or now_ts - last_ts > ttl:
                    continue
                out.append({
                    "ticker": ticker,
                    "last_ts": last_ts,
                    "first_ts": first_ts,
                    "price": price,
                    "turnover_hint": safe_float(last.get("turnover_hint", 0), 0),
                    "rows": len(rows),
                    "span_sec": max(0.0, last_ts - first_ts),
                })
        return out
    except Exception:
        return out

def _rank_state_get_cached_row(ticker: str, meta: dict, min_move_pct: float, now_ts: float = None) -> dict:
    """v2.5.241: 티커별 rank_state 재사용.

    v2.5.239에서 돈흐름 라벨을 rank row에 얹은 뒤 build 시간이 길어지면서,
    기존 상태표의 updated_ts가 재사용 때 갱신되지 않아 안정된 코인도 18~45초 뒤 대량 재계산됐다.
    재사용할 때 last_seen/updated_ts를 갱신하고, 강제 재계산은 computed_ts 기준으로 분리한다.
    돈흐름처럼 자주 바뀌는 값은 rank_state 무효화 조건으로 쓰지 않는다.
    """
    global RANK_STATE_REUSE_COUNT
    try:
        ticker = str(ticker or "").upper().strip()
        meta = meta if isinstance(meta, dict) else {}
        now_ts = safe_float(now_ts, time.time())
        if not ticker or not meta:
            _rank_reuse_fail("no_meta")
            return {}
        with RANK_STATE_LOCK:
            state = globals().get("RANK_STATE_BY_TICKER", {})
            row_state = state.get(ticker) if isinstance(state, dict) else None
            if not isinstance(row_state, dict):
                _rank_reuse_fail("no_state")
                return {}
            row = row_state.get("row") if isinstance(row_state.get("row"), dict) else {}
            if not row:
                _rank_reuse_fail("no_row")
                return {}
            updated_ts = safe_float(row_state.get("updated_ts", row_state.get("last_seen_ts", 0)), 0)
            computed_ts = safe_float(row_state.get("computed_ts", updated_ts), updated_ts)
            last_price = safe_float(row_state.get("last_price", 0), 0)
            last_snapshot_ts = safe_float(row_state.get("last_snapshot_ts", 0), 0)
        # v2.5.249: build 시작 시각이 오래된 상태에서 다른 캐시 라운드가 row를 갱신하면 age가 음수처럼 보일 수 있다.
        # 샘플은 남기고, 비교 기준은 실제 현재시각으로 통일한다.
        compare_ts = max(safe_float(now_ts, 0), time.time())
        if updated_ts > compare_ts:
            record_rank_negative_age_sample_v249(ticker, compare_ts, updated_ts, computed_ts, last_snapshot_ts, source="rank_state_get") if 'record_rank_negative_age_sample_v249' in globals() else None
            _rank_reuse_fail("negative_age")
            return {}
        if updated_ts > safe_float(now_ts, 0):
            record_rank_negative_age_sample_v249(ticker, now_ts, updated_ts, computed_ts, last_snapshot_ts, source="stale_build_now") if 'record_rank_negative_age_sample_v249' in globals() else None
        age = compare_ts - updated_ts if updated_ts > 0 else 999999
        computed_age = compare_ts - computed_ts if computed_ts > 0 else 999999
        # 가격이 거의 그대로인 코인을 전부 같은 시각에 강제 재계산하지 않도록 티커별로 흩뿌린다.
        force_base = max(300.0, safe_float(globals().get("RANK_STATE_FORCE_RECALC_SEC", 1200.0), 1200.0))
        # v2.5.252: 장시간 실행 뒤 모든 티커가 한 라운드에 force 재계산되는 폭주를 막기 위해 분산폭을 넓힌다.
        jitter = float(sum(ord(c) for c in ticker) % 600)
        if computed_age > force_base + jitter:
            _rank_reuse_fail("force_recalc_age")
            return {}
        price = safe_float(meta.get("price", 0), 0)
        if price <= 0 or last_price <= 0:
            _rank_reuse_fail("bad_price")
            return {}
        price_diff_pct = abs(price - last_price) / max(abs(last_price), 1e-12) * 100.0
        eps = safe_float(globals().get("RANK_STATE_PRICE_EPS_PCT", 0.025), 0.025)
        max_reuse = max(30.0, safe_float(globals().get("RANK_STATE_MAX_REUSE_SEC", 18.0), 18.0))

        def _refresh_and_return():
            nonlocal row, price, age, computed_age, computed_ts, last_snapshot_ts
            out = dict(row)
            out["price"] = price
            out["current_price"] = price
            out["rank_state_reused"] = True
            out["rank_state_age_sec"] = round(age, 2)
            out["rank_state_computed_age_sec"] = round(computed_age, 2)
            out["snapshot_rank_detected_ts"] = safe_float(row.get("snapshot_rank_detected_ts", computed_ts), computed_ts)
            if safe_float(out.get("snapshot_rank_strength", 0), 0) < safe_float(min_move_pct, 0):
                return {}
            try:
                with RANK_STATE_LOCK:
                    state2 = globals().get("RANK_STATE_BY_TICKER", {})
                    rs2 = state2.get(ticker) if isinstance(state2, dict) else None
                    if isinstance(rs2, dict):
                        rs2["updated_ts"] = now_ts
                        rs2["last_seen_ts"] = now_ts
                        rs2["last_price"] = price
                        rs2["last_snapshot_ts"] = safe_float(meta.get("last_ts", last_snapshot_ts), last_snapshot_ts)
                        cached = dict(rs2.get("row") or {})
                        if cached:
                            cached["price"] = price
                            cached["current_price"] = price
                            cached["rank_state_reused"] = True
                            rs2["row"] = cached
            except Exception:
                pass
            RANK_STATE_REUSE_COUNT = int(safe_float(globals().get("RANK_STATE_REUSE_COUNT", 0), 0)) + 1
            return out

        # 가격이 거의 그대로면 last_ts가 새로 찍혔어도 상태표를 재사용한다.
        if age <= max_reuse and price_diff_pct <= eps:
            return _refresh_and_return()
        # 표본 시간만 새로 쌓이고 가격 변화가 작으면 너무 자주 재계산하지 않는다.
        if age <= max_reuse and price_diff_pct <= eps * 3.0 and last_snapshot_ts > 0:
            return _refresh_and_return()
        return {}
    except Exception:
        return {}


def _rank_state_store_row(ticker: str, row: dict, meta: dict, now_ts: float = None):
    global RANK_STATE_RECALC_COUNT
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker or not isinstance(row, dict):
            return
        meta = meta if isinstance(meta, dict) else {}
        now_ts = safe_float(now_ts, time.time())
        with RANK_STATE_LOCK:
            state = globals().setdefault("RANK_STATE_BY_TICKER", {})
            if not isinstance(state, dict):
                globals()["RANK_STATE_BY_TICKER"] = {}
                state = globals()["RANK_STATE_BY_TICKER"]
            state[ticker] = {
                "row": dict(row),
                "updated_ts": now_ts,
                "last_seen_ts": now_ts,
                "computed_ts": now_ts,
                "last_price": safe_float(meta.get("price", row.get("price", row.get("current_price", 0))), 0),
                "last_snapshot_ts": safe_float(meta.get("last_ts", row.get("snapshot_rank_detected_ts", 0)), 0),
                "rows": int(safe_float(meta.get("rows", row.get("snapshot_rows", 0)), 0)),
                "span_sec": safe_float(meta.get("span_sec", row.get("snapshot_span_sec", 0)), 0),
            }
            keep_max = int(safe_float(globals().get("RANK_STATE_KEEP_MAX", 900), 900))
            if len(state) > keep_max:
                old = sorted(state.items(), key=lambda kv: safe_float((kv[1] or {}).get("updated_ts", 0), 0))[:max(1, len(state)-keep_max)]
                for k, _ in old:
                    state.pop(k, None)
        RANK_STATE_RECALC_COUNT = int(safe_float(globals().get("RANK_STATE_RECALC_COUNT", 0), 0)) + 1
    except Exception:
        pass


def _rank_state_build_row_from_metrics(ticker: str, metrics: dict, min_move_pct: float, now_ts: float) -> dict:
    try:
        metrics = metrics if isinstance(metrics, dict) else {}
        if not bool(metrics.get("snapshot_ready")):
            return {}
        price = safe_float(metrics.get("snapshot_price", metrics.get("price", 0)), 0)
        if price <= 0:
            return {}
        ch1 = safe_float(metrics.get("change_1", 0), 0)
        ch3 = safe_float(metrics.get("change_3", 0), 0)
        ch5 = safe_float(metrics.get("change_5", 0), 0)
        ch15 = safe_float(metrics.get("change_15", 0), 0)
        ch30 = safe_float(metrics.get("change_30", 0), 0)
        ch60 = safe_float(metrics.get("change_60", 0), 0)
        strongest = max(ch1, ch3, ch5, ch15, ch30, ch60)
        if strongest < safe_float(min_move_pct, 0):
            return {}
        turnover_hint = safe_float(metrics.get("snapshot_turnover_hint", 0), 0)
        verified_turnover = get_cached_verified_turnover_for_ticker(ticker)
        if isinstance(verified_turnover, dict) and str(verified_turnover.get("status", "") or "").lower() == "ok":
            turnover_hint = max(turnover_hint, safe_float(verified_turnover.get("turnover_5m", 0), 0))
        score = _snapshot_rank_score(metrics, turnover_hint)
        row = {
            "ticker": ticker,
            "price": price,
            "current_price": price,
            "change_1": ch1,
            "change_3": ch3,
            "change_5": ch5,
            "change_15": ch15,
            "change_30": ch30,
            "change_60": ch60,
            "from_low": safe_float(metrics.get("from_low", 0), 0),
            "below_high": safe_float(metrics.get("below_high", 999), 999),
            "turnover_5m": turnover_hint,
            "turnover": turnover_hint,
            "vol_ratio": safe_float(metrics.get("vol_ratio_snapshot", 0), 0),
            "snapshot_rank_score": score,
            "snapshot_rank_strength": strongest,
            "snapshot_rank_detected_ts": now_ts,
            "snapshot_rows": int(safe_float(metrics.get("snapshot_rows", 0), 0)),
            "snapshot_span_sec": safe_float(metrics.get("snapshot_span_sec", 0), 0),
            "change_1_ready": bool(metrics.get("change_1_ready", False)),
            "change_3_ready": bool(metrics.get("change_3_ready", False)),
            "change_5_ready": bool(metrics.get("change_5_ready", False)),
            "change_15_ready": bool(metrics.get("change_15_ready", False)),
            "change_30_ready": bool(metrics.get("change_30_ready", False)),
            "change_60_ready": bool(metrics.get("change_60_ready", False)),
            "snapshot_sample_limited_30m": bool(metrics.get("snapshot_sample_limited_30m", False)),
            "snapshot_flat_range_guard": bool(metrics.get("snapshot_flat_range_guard", False)),
            "cache_source": "light_snapshot_rank_state",
            "source": "realtime_snapshot_rank",
            "rank_state_reused": False,
        }
        row = apply_rank_app_compare_overlay_v245(row) if 'apply_rank_app_compare_overlay_v245' in globals() else row
        row = apply_precision_minute1_state_to_row(row) if 'apply_precision_minute1_state_to_row' in globals() else row
        row = apply_ws_trade_score_adjustment(row)
        if is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            row["rank_tick_noise_block"] = True
            row["ultra_low_tick_noise_block"] = True
            row["snapshot_rank_score"] = min(safe_float(row.get("snapshot_rank_score", score), score), safe_float(globals().get("REALTIME_RANK_TICK_NOISE_SCORE_CAP", 0.15), 0.15))
        row = apply_rank_watch_chart_state(row)
        row = apply_verified_turnover_to_row(row)
        # v2.5.241: 돈흐름은 rank_state 무효화 요인이 아니므로 저장 row에 고정하지 않는다.
        # 출력 직전 상위 row에 overlay로만 붙인다.
        return row
    except Exception:
        return {}

def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    """빗썸 앱 순위를 직접 읽지는 못하므로, 현재가 스냅샷으로 내부 유사 순위를 만든다.

    v2.5.247:
    - rank_source가 1~2시간 뒤 무거워지는 원인을 단계별로 기록한다.
    - 작은 가격 흔들림은 상태표 재사용으로 넘기고, 무거운 지표는 필요한 티커만 재계산한다.
    """
    global RANK_STATE_LAST_REUSE_COUNT, RANK_STATE_LAST_RECALC_COUNT, RANK_STATE_LAST_TOTAL_COUNT, RANK_STATE_LAST_BUILD_TS, RANK_STATE_LAST_NOTE
    rows = []
    timings = {}
    t0 = time.time()
    light_create_count = 0
    skipped_count = 0
    precision_merge_count = 0
    build_reuse_start = int(safe_float(globals().get("RANK_STATE_REUSE_COUNT", 0), 0))
    build_recalc_start = int(safe_float(globals().get("RANK_STATE_RECALC_COUNT", 0), 0))
    reset_rank_reuse_fail_reasons() if 'reset_rank_reuse_fail_reasons' in globals() else None
    try:
        try:
            s = time.time()
            if not (bool(globals().get("COMMAND_DISPLAY_READONLY_BUILDING", False)) and bool(globals().get("COMMAND_DISPLAY_SKIP_BULK_SWEEP_WHILE_CACHE_BUILD", True))):
                sweep_bulk_prices_into_light_snapshots(reason="rank_watch_pre_sweep")
            timings["bulk_sweep"] = time.time() - s
        except Exception:
            timings["bulk_sweep"] = time.time() - s if 's' in locals() else 0.0
        now_ts = time.time()
        s = time.time()
        metas = _rank_state_snapshot_meta_bulk(now_ts=now_ts) if '_rank_state_snapshot_meta_bulk' in globals() else []
        tickers = [str((m or {}).get("ticker", "") or "").upper().strip() for m in metas if isinstance(m, dict)]
        timings["snapshot_keys"] = time.time() - s
        meta_sec = timings.get("snapshot_keys", 0.0)
        reuse_sec = metric_sec = build_sec = store_sec = 0.0
        for meta in metas:
            if not isinstance(meta, dict):
                continue
            ticker = str(meta.get("ticker", "") or "").upper().strip()
            if not ticker or is_watch_excluded_ticker(ticker):
                continue
            s = time.time(); cached_row = _rank_state_get_cached_row(ticker, meta, min_move_pct=min_move_pct, now_ts=now_ts); reuse_sec += time.time() - s
            if cached_row:
                rows.append(cached_row)
                continue
            s = time.time(); metrics = compute_light_snapshot_metrics(ticker); metric_sec += time.time() - s
            s = time.time(); row = _rank_state_build_row_from_metrics(ticker, metrics, min_move_pct=min_move_pct, now_ts=now_ts); build_sec += time.time() - s
            if not row:
                skipped_count += 1
                continue
            light_create_count += 1
            s = time.time(); _rank_state_store_row(ticker, row, meta, now_ts=now_ts); store_sec += time.time() - s
            rows.append(row)
        timings["meta"] = meta_sec
        timings["reuse_check"] = reuse_sec
        timings["metrics"] = metric_sec
        timings["row_build"] = build_sec
        timings["store"] = store_sec
        s = time.time()
        rows.sort(
            key=lambda x: (
                safe_float(x.get("snapshot_rank_score", 0), 0),
                safe_float(x.get("change_3", 0), 0),
                safe_float(x.get("change_5", 0), 0),
                safe_float(x.get("change_30", 0), 0),
            ),
            reverse=True,
        )
        rows = rows[:max(1, int(limit))]
        timings["sort"] = time.time() - s
        s = time.time()
        try:
            enrich_limit = max(3, min(len(rows), int(safe_float(globals().get("REALTIME_RANK_PSEUDO_DF_ENRICH_LIMIT", 12), 12))))
            for _enrich_row in rows[:enrich_limit]:
                try:
                    _tk = str(_enrich_row.get("ticker", "") or "").upper().strip()
                    _price = safe_float(_enrich_row.get("price", _enrich_row.get("current_price", 0)), 0)
                    _enrich_row = apply_precision_minute1_state_to_row(_enrich_row) if 'apply_precision_minute1_state_to_row' in globals() else _enrich_row
                    if not bool(_enrich_row.get("precision_chart_verified", False)):
                        pseudo_df = build_light_snapshot_pseudo_df(_tk, price=_price)
                        if pseudo_df is not None and len(pseudo_df) >= 4:
                            _enrich_row.update(compute_current_candle_context_from_df(pseudo_df, current_price=_price))
                            _enrich_row["current_candle_source"] = "light_snapshot"
                except Exception:
                    pass
        except Exception:
            pass
        timings["pseudo_enrich"] = time.time() - s
        s = time.time()
        for idx, row in enumerate(rows, start=1):
            row["snapshot_rank"] = idx
            _before_precision_verified = bool(row.get("precision_chart_verified", False))
            row = apply_precision_minute1_state_to_row(row) if 'apply_precision_minute1_state_to_row' in globals() else row
            if bool(row.get("precision_chart_verified", False)) and not _before_precision_verified:
                precision_merge_count += 1
            row = apply_low_defense_quality_v248(row) if 'apply_low_defense_quality_v248' in globals() else row
            row = apply_high_rebreakout_hold_v248(row) if 'apply_high_rebreakout_hold_v248' in globals() else row
            row = apply_money_sustain_context(row)
            row["rank_precision_watch"] = bool(is_realtime_rank_precision_candidate(row))
            row = apply_rank_watch_chart_state(row)
            row = apply_final_candidate_display_context_v251(row) if 'apply_final_candidate_display_context_v251' in globals() else row
            row["rank_watch_action"] = str(row.get("final_candidate_action_v251", "") or realtime_rank_watch_action_label(row))
            try:
                if bool(row.get("rank_precision_watch", False)) or realtime_rank_watch_action_label(row) == "정밀검토 대기":
                    queue_precision_minute1_chart_verify(row, reason="rank_source_top")
            except Exception:
                pass
            rows[idx-1] = row
        timings["overlay"] = time.time() - s
        globals()["RANK_SOURCE_LIGHT_CREATE_COUNT"] = light_create_count
        globals()["RANK_SOURCE_SKIPPED_COUNT"] = skipped_count
        globals()["RANK_SOURCE_PRECISION_MERGE_COUNT"] = precision_merge_count
        reuse_delta = int(safe_float(globals().get("RANK_STATE_REUSE_COUNT", 0), 0)) - build_reuse_start
        recalc_delta = int(safe_float(globals().get("RANK_STATE_RECALC_COUNT", 0), 0)) - build_recalc_start
        RANK_STATE_LAST_REUSE_COUNT = reuse_delta
        RANK_STATE_LAST_RECALC_COUNT = recalc_delta
        RANK_STATE_LAST_TOTAL_COUNT = len(tickers)
        RANK_STATE_LAST_BUILD_TS = now_ts
        total = time.time() - t0
        measured = sum(safe_float(v, 0) for k, v in timings.items() if k != "total")
        unmeasured = max(0.0, total - measured)
        timings["기타/미계측"] = unmeasured
        timings["total"] = total
        globals()["RANK_SOURCE_STEP_UNMEASURED_SEC"] = round(unmeasured, 3)
        globals()["RANK_SOURCE_STEP_LAST_TIMINGS"] = {k: round(safe_float(v, 0), 3) for k, v in timings.items()}
        slow = sorted([(k, v) for k, v in timings.items() if k != "total"], key=lambda kv: kv[1], reverse=True)[:6]
        fail_reasons = globals().get("RANK_STATE_REUSE_FAIL_REASONS", {}) if isinstance(globals().get("RANK_STATE_REUSE_FAIL_REASONS", {}), dict) else {}
        fail_text = ", ".join([f"{k} {v}" for k, v in sorted(fail_reasons.items(), key=lambda kv: kv[1], reverse=True)[:3]]) or "-"
        globals()["RANK_SOURCE_STEP_LAST_NOTE"] = ", ".join([f"{k} {v:.2f}s" for k, v in slow])
        RANK_STATE_LAST_NOTE = f"상태표 재사용 {reuse_delta} / 경량생성 {light_create_count} / 재계산저장 {recalc_delta} / 스킵 {skipped_count} / 정밀병합 {precision_merge_count} / 대상 {len(tickers)} / 재사용실패 {fail_text}"
        return rows
    except Exception as e:
        append_runtime_error_log("snapshot_rank_rows", str(e), exc=e, include_traceback=False)
        return []



def build_light_snapshot_rank_row_for_ticker(ticker: str, metrics: dict = None) -> dict:
    """특정 티커 detail 조회용: 현재가 스냅샷 지표를 rank_watch 저장 row로 변환한다."""
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            return {}
        metrics = metrics if isinstance(metrics, dict) else compute_light_snapshot_metrics(ticker)
        if not isinstance(metrics, dict) or not bool(metrics.get("snapshot_ready")):
            return {}
        price = safe_float(metrics.get("snapshot_price", metrics.get("price", 0)), 0)
        if price <= 0:
            return {}
        turnover_hint = safe_float(metrics.get("snapshot_turnover_hint", 0), 0)
        ch1 = safe_float(metrics.get("change_1", 0), 0)
        ch3 = safe_float(metrics.get("change_3", 0), 0)
        ch5 = safe_float(metrics.get("change_5", 0), 0)
        ch15 = safe_float(metrics.get("change_15", 0), 0)
        ch30 = safe_float(metrics.get("change_30", 0), 0)
        ch60 = safe_float(metrics.get("change_60", 0), 0)
        strongest = max(ch1, ch3, ch5, ch15, ch30, ch60)
        score = _snapshot_rank_score(metrics, turnover_hint)
        out = {
            "ticker": ticker, "price": price, "current_price": price,
            "change_1": ch1, "change_3": ch3, "change_5": ch5, "change_15": ch15, "change_30": ch30, "change_60": ch60,
            "from_low": safe_float(metrics.get("from_low", 0), 0),
            "below_high": safe_float(metrics.get("below_high", 999), 999),
            "recent_30m_low_price": safe_float(metrics.get("recent_30m_low_price", 0), 0),
            "recent_30m_high_price": safe_float(metrics.get("recent_30m_high_price", 0), 0),
            "turnover_5m": turnover_hint, "turnover": turnover_hint,
            "vol_ratio": safe_float(metrics.get("vol_ratio_snapshot", 0), 0),
            "snapshot_rank_score": score, "snapshot_rank_strength": strongest,
            "snapshot_rank_detected_ts": time.time(),
            "snapshot_rows": int(safe_float(metrics.get("snapshot_rows", 0), 0)),
            "snapshot_span_sec": safe_float(metrics.get("snapshot_span_sec", 0), 0),
            "change_1_ready": bool(metrics.get("change_1_ready", False)),
            "change_3_ready": bool(metrics.get("change_3_ready", False)),
            "change_5_ready": bool(metrics.get("change_5_ready", False)),
            "change_15_ready": bool(metrics.get("change_15_ready", False)),
            "change_30_ready": bool(metrics.get("change_30_ready", False)),
            "change_60_ready": bool(metrics.get("change_60_ready", False)),
            "snapshot_sample_limited_30m": bool(metrics.get("snapshot_sample_limited_30m", False)),
            "snapshot_flat_range_guard": bool(metrics.get("snapshot_flat_range_guard", False)),
            "cache_source": "light_snapshot_rank_detail", "source": "realtime_snapshot_rank",
            "rank_precision_watch": bool(is_realtime_rank_precision_candidate({
                "snapshot_rank_score": score,
                "snapshot_rank_strength": strongest,
                "change_1": ch1, "change_3": ch3, "change_5": ch5,
                "change_15": ch15, "change_30": ch30, "change_60": ch60,
                "from_low": safe_float(metrics.get("from_low", 0), 0),
                "below_high": safe_float(metrics.get("below_high", 999), 999),
            })),
            "rank_watch_action": realtime_rank_watch_action_label({
                "snapshot_rank_score": score,
                "snapshot_rank_strength": strongest,
                "change_1": ch1, "change_3": ch3, "change_5": ch5,
                "change_15": ch15, "change_30": ch30, "change_60": ch60,
                "from_low": safe_float(metrics.get("from_low", 0), 0),
                "below_high": safe_float(metrics.get("below_high", 999), 999),
            }),
        }
        out = apply_precision_minute1_state_to_row(out) if 'apply_precision_minute1_state_to_row' in globals() else out
        out = apply_ws_trade_score_adjustment(out)
        if is_realtime_rank_tick_noise(out) or is_rank_watch_low_price_tick_noise_v237(out):
            out["rank_tick_noise_block"] = True
            out["ultra_low_tick_noise_block"] = True
            out["snapshot_rank_score"] = min(safe_float(out.get("snapshot_rank_score", 0), 0), safe_float(globals().get("REALTIME_RANK_TICK_NOISE_SCORE_CAP", 0.15), 0.15))
            out["rank_precision_watch"] = False
        out["rank_precision_watch"] = bool(is_realtime_rank_precision_candidate(out))
        out = apply_rank_watch_chart_state(out)
        out = apply_money_sustain_context(out)
        out["rank_watch_action"] = realtime_rank_watch_action_label(out)
        return out
    except Exception as e:
        append_runtime_error_log("snapshot_rank_row_for_ticker", str(e), exc=e, include_traceback=False)
        return {}

def has_recent_realtime_rank_trace(ticker: str, lookback_sec: int = None) -> bool:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    lookback_sec = int(safe_float(lookback_sec if lookback_sec is not None else globals().get("REALTIME_RANK_TRACE_LOOKBACK_SEC", 6 * 3600), 6 * 3600))
    cutoff = time.time() - max(60, lookback_sec)
    try:
        load_reverse_trace_logs()
    except Exception:
        pass
    try:
        for prev in reversed(reverse_trace_logs[-600:]):
            if not isinstance(prev, dict):
                continue
            if str(prev.get("ticker", "") or "").upper().strip() != ticker:
                continue
            if str(prev.get("stage", "") or "") != "rank_watch":
                continue
            if safe_float(prev.get("ts", 0), 0) >= cutoff:
                return True
    except Exception:
        return False
    return False


def _should_append_realtime_rank_trace(ticker: str, row: dict, now_ts: float = None, force: bool = False) -> bool:
    now_ts = safe_float(now_ts, time.time())
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    try:
        score = safe_float(row.get("snapshot_rank_score", 0), 0)
        strongest = max(
            safe_float(row.get("change_3", 0), 0),
            safe_float(row.get("change_5", 0), 0),
            safe_float(row.get("change_30", 0), 0),
            safe_float(row.get("change_60", 0), 0),
        )
        if (not force) and score < 1.60 and strongest < 0.80:
            return False
        if has_recent_realtime_rank_trace(ticker, lookback_sec=REALTIME_RANK_TRACE_LOOKBACK_SEC):
            return False
        state = globals().setdefault("REALTIME_RANK_TRACE_LAST_TS", {})
        if not isinstance(state, dict):
            globals()["REALTIME_RANK_TRACE_LAST_TS"] = {}
            state = globals()["REALTIME_RANK_TRACE_LAST_TS"]
        cooldown = int(safe_float(globals().get("REALTIME_RANK_TRACE_COOLDOWN_SEC", 180), 180))
        last = safe_float(state.get(ticker, 0), 0)
        if now_ts - last < max(30, cooldown):
            return False
        state[ticker] = now_ts
        return True
    except Exception:
        return False


def append_realtime_rank_min_trace(row: dict, item: dict = None, now_ts: float = None, force: bool = False):
    """순위권 후보는 알림/정밀분석 전이라도 복기용/정밀검토 기록을 남긴다."""
    try:
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker", (item or {}).get("ticker", "")) or "").upper().strip()
        if not ticker or not _should_append_realtime_rank_trace(ticker, row, now_ts=now_ts, force=force):
            return False
        row = apply_verified_turnover_to_row(row)
        base = apply_verified_turnover_to_row(dict(item)) if isinstance(item, dict) else {}
        price = safe_float(row.get("price", row.get("current_price", base.get("price", base.get("current_price", 0)))), 0)
        tick_noise = bool(row.get("rank_tick_noise_block", False)) or is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row)
        precision_watch = False if tick_noise else (bool(row.get("rank_precision_watch", False)) or is_realtime_rank_precision_candidate(row))
        action_label = realtime_rank_watch_action_label({**row, "rank_precision_watch": precision_watch, "rank_tick_noise_block": tick_noise})
        if precision_watch:
            try:
                force_track_light_snapshot_ticker(ticker, price=price, reason="rank_precision_watch")
            except Exception:
                pass
            try:
                queue_realtime_rank_turnover_verify(row, reason="rank_precision_trace")
            except Exception:
                pass
        base.update({
            "ticker": ticker,
            "price": price,
            "current_price": price,
            "alert_bucket": "rank_watch",
            "bucket": "rank_watch",
            "alert_grade": "C" if tick_noise else ("B" if precision_watch else "C"),
            "grade": "C" if tick_noise else ("B" if precision_watch else "C"),
            "primary_reason": "초저가 틱노이즈 제외" if tick_noise else ("순위권 정밀검토 후보" if precision_watch else "순위권 포착 기록"),
            "label_text": "초저가 틱노이즈 제외" if tick_noise else ("순위권 정밀검토 대기" if precision_watch else "순위권에서 발견됨"),
            "one_liner": "초저가 한 틱 왜곡 가능성이 커서 정밀검토/알림에서 제외. 기록만 남김" if tick_noise else ("순위권 강세라 내부 감시 후보로 한 번 더 확인할 자리. 바로 매수 신호는 아님" if precision_watch else "순위권 움직임은 보여서 복기용으로 남김. 알림 후보 여부는 돈/차트 확인 필요"),
            "candidate_source": "realtime_snapshot_rank_tick_noise" if tick_noise else ("realtime_snapshot_rank_precision" if precision_watch else "realtime_snapshot_rank"),
            "source": "realtime_snapshot_rank",
            "cache_source": "light_snapshot_rank",
            "realtime_rank_injected": True,
            "rank_precision_watch": precision_watch,
            "rank_tick_noise_block": tick_noise,
            "ultra_low_tick_noise_block": tick_noise,
            "rank_watch_action": action_label,
            "precision_stage": "초저가 틱노이즈 → 정밀검토 제외" if tick_noise else ("순위권 강세 → 내부감시 정밀검토" if precision_watch else "순위권 포착 → 복기용 저장"),
            "snapshot_rank": int(safe_float(row.get("snapshot_rank", base.get("snapshot_rank", 999)), 999)),
            "snapshot_rank_score": safe_float(row.get("snapshot_rank_score", base.get("snapshot_rank_score", 0)), 0),
            "snapshot_rank_strength": safe_float(row.get("snapshot_rank_strength", base.get("snapshot_rank_strength", 0)), 0),
            "change_1": safe_float(row.get("change_1", base.get("change_1", 0)), 0),
            "change_3": safe_float(row.get("change_3", base.get("change_3", 0)), 0),
            "change_5": safe_float(row.get("change_5", base.get("change_5", 0)), 0),
            "change_15": safe_float(row.get("change_15", base.get("change_15", 0)), 0),
            "change_30": safe_float(row.get("change_30", base.get("change_30", 0)), 0),
            "change_60": safe_float(row.get("change_60", base.get("change_60", 0)), 0),
            "from_low": safe_float(row.get("from_low", base.get("from_low", 0)), 0),
            "below_high": safe_float(row.get("below_high", base.get("below_high", 999)), 999),
            "vol_ratio": safe_float(row.get("vol_ratio", base.get("vol_ratio", 0)), 0),
            "leader_score": max(safe_float(base.get("leader_score", 0), 0), min(4.0, safe_float(row.get("snapshot_rank_score", 0), 0) * 0.55)),
            "turnover_5m": safe_float(row.get("turnover_5m", row.get("turnover", base.get("turnover_5m", 0))), 0),
            "turnover_recent_1m": safe_float(row.get("turnover_recent_1m", base.get("turnover_recent_1m", 0)), 0),
            "turnover_recent_3m": safe_float(row.get("turnover_recent_3m", base.get("turnover_recent_3m", 0)), 0),
            "turnover_15m": safe_float(row.get("turnover_15m", base.get("turnover_15m", 0)), 0),
            "turnover_verified": bool(row.get("turnover_verified", base.get("turnover_verified", False))),
            "actual_turnover_verified": bool(row.get("actual_turnover_verified", base.get("actual_turnover_verified", False))),
            "turnover_verify_status": str(row.get("turnover_verify_status", base.get("turnover_verify_status", "")) or ""),
            "turnover_verified_ts": safe_float(row.get("turnover_verified_ts", base.get("turnover_verified_ts", 0)), 0),
            "turnover_unknown_snapshot": safe_float(row.get("turnover_5m", row.get("turnover", base.get("turnover_5m", 0))), 0) <= 0 and not bool(row.get("turnover_verified", base.get("turnover_verified", False))),
            "reasons": ["초저가 한 틱 왜곡 가능성", "정밀검토/알림 제외", "복기용으로만 기록"] if tick_noise else (["순위권 강세 → 정밀검토 대기", "알림 전 내부감시 후보", "거래대금 실제확인 워커 예약"] if precision_watch else ["순위권 움직임 감지", "알림 전 복기용 기록", "거래대금은 이 경로에서 미확인 가능"]),
            "pre_alert_snapshot": {
                "chg_5m": safe_float(row.get("change_5", 0), 0),
                "chg_15m": safe_float(row.get("change_15", 0), 0),
                "chg_30m": safe_float(row.get("change_30", 0), 0),
                "from_30m_low_pct": safe_float(row.get("from_low", 0), 0),
                "below_30m_high_pct": safe_float(row.get("below_high", 999), 999),
                "recent_30m_low_price": safe_float(row.get("recent_30m_low_price", base.get("recent_30m_low_price", 0)), 0),
                "recent_30m_high_price": safe_float(row.get("recent_30m_high_price", base.get("recent_30m_high_price", 0)), 0),
                "snapshot_engine_used": True,
            },
        })
        base = apply_rank_watch_chart_state(base)
        base = _enrich_rank_precision_chart_context(base, precision_watch=precision_watch)
        extra = (
            f"{action_label} / 3분 {safe_float(base.get('change_3',0),0):+.2f}% / "
            f"5분 {safe_float(base.get('change_5',0),0):+.2f}% / "
            f"15분 {safe_float(base.get('change_15',0),0):+.2f}% / "
            f"30분 {safe_float(base.get('change_30',0),0):+.2f}% / "
            f"1시간 {safe_float(base.get('change_60',0),0):+.2f}% / "
            f"점수 {safe_float(base.get('snapshot_rank_score',0),0):.2f}"
        )
        append_reverse_trace(base, stage="rank_watch", extra_reason=extra, now_ts=now_ts)
        if precision_watch and not tick_noise:
            register_rank_precision_internal_watch(base, now_ts=now_ts, reason="rank_watch_trace")
        persist_reverse_trace_logs(force=True)
        return True
    except Exception as e:
        append_runtime_error_log("realtime_rank_min_trace", str(e), exc=e, include_traceback=False)
        return False


def inject_realtime_snapshot_rows_into_cache(cache: dict, limit: int = REALTIME_RANK_INJECT_LIMIT) -> dict:
    """내부 유사 실시간 순위권을 fast scan 후보 풀에 강제로 섞는다.

    이건 사용자 알림 강제승격이 아니라, ENSO/MIRA 같은 순위권 코인이
    최소 review_trace/review_dump에 남게 하기 위한 탐색 커버리지 보강이다.
    """
    if not REALTIME_RANK_INJECT_ON:
        return cache if isinstance(cache, dict) else {}
    if not isinstance(cache, dict):
        cache = {}
    try:
        rank_rows = get_light_snapshot_rank_rows(limit=max(1, int(limit)), min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
        for row in rank_rows:
            ticker = str(row.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            metrics = compute_light_snapshot_metrics(ticker)
            if bool(row.get("rank_tick_noise_block", False)) or is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
                append_realtime_rank_min_trace({**row, "rank_tick_noise_block": True}, item=None, now_ts=time.time(), force=True)
                continue
            item = build_snapshot_cache_item_from_row(ticker, row)
            if not item:
                continue
            item = apply_rank_watch_chart_state(item)
            item["candidate_source"] = "realtime_snapshot_rank"
            item["realtime_rank_injected"] = True
            item["rank_precision_watch"] = bool(is_realtime_rank_precision_candidate(row))
            item["rank_watch_action"] = realtime_rank_watch_action_label({**row, "rank_precision_watch": item["rank_precision_watch"]})
            if item["rank_precision_watch"]:
                item["candidate_source"] = "realtime_snapshot_rank_precision"
                item["precision_stage"] = "스냅샷 강세 → 정밀검토 대기"
            item["snapshot_rank"] = int(safe_float(row.get("snapshot_rank", 999), 999))
            item["snapshot_rank_score"] = safe_float(row.get("snapshot_rank_score", 0), 0)
            item["snapshot_rank_strength"] = safe_float(row.get("snapshot_rank_strength", 0), 0)
            # 순위권은 fast scan에서 보이게 점수만 보강한다. 실제 알림은 기존 돈/위치/차트 필터를 그대로 통과해야 한다.
            item["leader_score"] = max(
                safe_float(item.get("leader_score", 0), 0),
                min(4.0, safe_float(row.get("snapshot_rank_score", 0), 0) * 0.55),
            )
            item["vol_ratio"] = max(
                safe_float(item.get("vol_ratio", 0), 0),
                1.05 + min(3.2, safe_float(row.get("snapshot_rank_score", 0), 0) * 0.20),
            )
            item["surge_rank"] = min(
                int(safe_float(item.get("surge_rank", 999), 999)),
                int(safe_float(row.get("snapshot_rank", 999), 999)),
            )
            item = apply_verified_turnover_to_row(item)
            item["turnover_unknown_snapshot"] = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0) <= 0 and not bool(item.get("turnover_verified", False))
            if bool(item.get("rank_precision_watch", False)):
                queue_realtime_rank_turnover_verify(item, reason="rank_inject")
                item = _enrich_rank_precision_chart_context(item, precision_watch=True)
            append_realtime_rank_min_trace(row, item=item, now_ts=time.time())
            existing = cache.get(ticker)
            if isinstance(existing, dict):
                merged = dict(existing)
                if safe_float(item.get("snapshot_rank_score", 0), 0) >= safe_float(existing.get("snapshot_rank_score", -1), -1):
                    merged.update({k: v for k, v in item.items() if v not in (None, "")})
                else:
                    merged.setdefault("realtime_rank_injected", True)
                cache[ticker] = merged
            else:
                cache[ticker] = item
    except Exception as e:
        append_runtime_error_log("realtime_rank_inject", str(e), exc=e, include_traceback=False)
    return cache


def enrich_cache_with_light_snapshots(cache: dict) -> dict:
    if not LIGHT_SNAPSHOT_ENGINE_ON or not isinstance(cache, dict) or not cache:
        return cache
    out = {}
    for ticker, row in cache.items():
        if not isinstance(row, dict):
            continue
        item = dict(row)
        item.setdefault("ticker", ticker)
        out[ticker] = apply_light_snapshot_metrics_to_item(item)
    return out


def build_light_snapshot_pseudo_df(ticker: str, price: float = 0.0):
    rows = _light_snapshot_rows(ticker)
    if len(rows) < LIGHT_SNAPSHOT_READY_MIN_ROWS:
        return None
    now_ts = time.time()
    price = safe_float(price, 0)
    if price <= 0:
        price = safe_float(rows[-1].get("price", 0), 0)
    if price <= 0:
        return None
    try:
        rows = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 30 * 60]
        if len(rows) < LIGHT_SNAPSHOT_READY_MIN_ROWS:
            return None
        bins = {}
        for r in rows:
            ts = floor_minute_ts(safe_float(r.get("ts", 0), 0))
            p = safe_float(r.get("price", 0), 0)
            if ts <= 0 or p <= 0:
                continue
            bins.setdefault(ts, []).append(r)
        ohlc_rows = []
        last_close = None
        for ts in sorted(bins.keys()):
            vals = [safe_float(r.get("price", 0), 0) for r in bins[ts] if safe_float(r.get("price", 0), 0) > 0]
            if not vals:
                continue
            op = last_close if last_close and last_close > 0 else vals[0]
            cl = vals[-1]
            hi = max(vals + [op, cl])
            lo = min(vals + [op, cl])
            turn = max([safe_float(r.get("turnover_hint", 0), 0) for r in bins[ts]] or [0])
            vol = max(turn / max(cl, 1e-12) / 5.0, 1.0) if turn > 0 else 1.0
            ohlc_rows.append({"open": op, "high": hi, "low": lo, "close": cl, "volume": vol})
            last_close = cl
        if len(ohlc_rows) < 12:
            if not ohlc_rows:
                return None
            first = dict(ohlc_rows[0])
            while len(ohlc_rows) < 12:
                ohlc_rows.insert(0, dict(first))
        return pd.DataFrame(ohlc_rows[-36:])
    except Exception:
        return None



def _fallback_market_snapshot_seed_rows(existing: set = None, limit: int = None) -> list:
    """스냅샷 직원용 예비 대상.

    유니버스/OHLCV가 막히면 기존 구조는 볼 코인 명단 자체가 2~10개로 줄었다.
    v2.5.177부터는 현재가 스냅샷 직원이 기본 티커 목록까지 넓게 훑고,
    괜찮아진 애만 정밀분석으로 넘긴다.
    """
    existing = existing if isinstance(existing, set) else set()
    limit = max(1, int(limit or LIGHT_SNAPSHOT_FALLBACK_TARGET))
    out = []
    seen = {str(x or '').upper().strip() for x in existing if str(x or '').strip()}
    sources = []
    try:
        if isinstance(market_all_tickers, list) and market_all_tickers:
            sources += list(market_all_tickers)
    except Exception:
        pass
    try:
        sources += list(DEFAULT_MARKET_TICKERS)
    except Exception:
        pass
    try:
        if isinstance(recent_watch_snapshots, dict):
            sources += list(recent_watch_snapshots.keys())
    except Exception:
        pass
    for raw in sources:
        t = str(raw or '').upper().strip()
        if not t or t == 'BTC' or t in seen or is_watch_excluded_ticker(t):
            continue
        seen.add(t)
        out.append({
            'ticker': t,
            'snapshot_seed': True,
            'turnover_recent': 0.0,
            'turnover_score': 0.0,
            'surge_score': 0.0,
            'leader_score': 0.0,
            'short_change': 0.0,
            'change_15': 0.0,
            'change_30': 0.0,
            'change_60': 0.0,
            'vol_ratio': 0.0,
            'range_pct': 0.0,
        })
        if len(out) >= limit:
            break
    return out


def build_snapshot_cache_item_from_row(ticker: str, row: dict):
    """OHLCV 없이 스냅샷 기록만으로 빠른 캐시에 넣을 수 있는 가벼운 row를 만든다."""
    ticker = str(ticker or '').upper().strip()
    if not ticker or not LIGHT_SNAPSHOT_ENGINE_ON:
        return None
    row = row if isinstance(row, dict) else {}
    price_hint = safe_float(row.get('price', row.get('last_price', 0)), 0)
    metrics = compute_light_snapshot_metrics(ticker, current_price=price_hint)
    if not isinstance(metrics, dict) or not metrics.get('snapshot_ready'):
        return None
    price = safe_float(metrics.get('snapshot_price', price_hint), price_hint)
    if price <= 0:
        return None
    turn = safe_float(row.get('turnover_5m', row.get('turnover', row.get('turnover_recent', metrics.get('snapshot_turnover_hint', 0)))), 0)
    item = {
        'ticker': ticker,
        'price': price,
        'current_price': price,
        'df_1m': None,
        'df_3m': row.get('df_3m'),
        'turnover': turn,
        'turnover_5m': turn,
        'turnover_recent': turn,
        'surge_score': safe_float(row.get('surge_score', 0), 0),
        'leader_score': safe_float(row.get('leader_score', 0), 0),
        'turnover_rank': safe_float(row.get('turnover_rank', 999), 999),
        'surge_rank': safe_float(row.get('surge_rank', 999), 999),
        'vol_ratio': safe_float(metrics.get('vol_ratio_snapshot', row.get('vol_ratio', 0)), 0),
        'change_1': safe_float(metrics.get('change_1', 0), 0),
        'change_3': safe_float(metrics.get('change_3', 0), 0),
        'change_5': safe_float(metrics.get('change_5', 0), 0),
        'change_15': safe_float(metrics.get('change_15', 0), 0),
        'change_30': safe_float(metrics.get('change_30', 0), 0),
        'change_60': safe_float(metrics.get('change_60', 0), 0),
        'from_low': safe_float(metrics.get('from_low', 0), 0),
        'below_high': safe_float(metrics.get('below_high', 999), 999),
        'rsi': 0,
        'cache_updated_at': time.time(),
        'cache_source': 'light_snapshot_seed',
        'snapshot_cache_only': True,
    }
    item = apply_light_snapshot_metrics_to_item(item)
    item = apply_money_sustain_context(item)
    return item


def build_light_snapshot_cache_item_from_row(ticker: str, row: dict):
    """v2.5.232 호환 alias.

    v2.5.228에서 잘못 호출했던 옛 함수명이 다른 경로에 남아도
    NameError로 루프를 계속 더럽히지 않게 실제 함수로 연결한다.
    """
    return build_snapshot_cache_item_from_row(ticker, row)


def seed_universe_with_snapshot_rows(tickers: list, base_map: dict, limit: int = None) -> dict:
    """유니버스가 OHLCV 실패로 비지 않게 스냅샷/기본목록으로 먼저 밭을 채운다."""
    base_map = base_map if isinstance(base_map, dict) else {}
    limit = max(1, int(limit or LIGHT_SNAPSHOT_UNIVERSE_SEED_TARGET))
    existing = {str(k or '').upper().strip() for k in base_map.keys()}
    seed_rows = []
    try:
        if isinstance(tickers, list):
            seed_rows += [{'ticker': str(t or '').upper().strip()} for t in tickers]
    except Exception:
        pass
    seed_rows += _fallback_market_snapshot_seed_rows(existing=existing, limit=limit)
    for row in seed_rows:
        if len(base_map) >= limit:
            break
        t = str(row.get('ticker', '') or '').upper().strip()
        if not t or t == 'BTC' or t in base_map or is_watch_excluded_ticker(t):
            continue
        metrics = compute_light_snapshot_metrics(t, current_price=safe_float(row.get('price', 0), 0)) if LIGHT_SNAPSHOT_ENGINE_ON else {}
        chg5 = safe_float(metrics.get('change_5', 0), 0) if isinstance(metrics, dict) else 0.0
        chg30 = safe_float(metrics.get('change_30', 0), 0) if isinstance(metrics, dict) else 0.0
        turn = safe_float(metrics.get('snapshot_turnover_hint', 0), 0) if isinstance(metrics, dict) else 0.0
        vol = safe_float(metrics.get('vol_ratio_snapshot', 0), 0) if isinstance(metrics, dict) else 0.0
        base_map[t] = {
            'ticker': t,
            'snapshot_seed': True,
            'last_price': safe_float(metrics.get('snapshot_price', 0), 0) if isinstance(metrics, dict) else 0.0,
            'turnover_recent': turn,
            'turnover_score': math.log10(max(turn, 1)),
            'surge_score': max(chg5, 0) * 2.5 + max(chg30, 0) * 0.8 + max(vol - 1.0, 0) * 0.8,
            'short_change': chg5,
            'change_15': safe_float(metrics.get('change_15', 0), 0) if isinstance(metrics, dict) else 0.0,
            'change_30': chg30,
            'change_60': safe_float(metrics.get('change_60', 0), 0) if isinstance(metrics, dict) else 0.0,
            'vol_ratio': vol,
            'range_pct': 0.0,
        }
    return base_map

def _light_snapshot_source_rows() -> list:
    rows = []
    try:
        if isinstance(shared_market_cache, dict):
            for ticker, data in shared_market_cache.items():
                if isinstance(data, dict):
                    d = dict(data)
                    d.setdefault("ticker", ticker)
                    rows.append(d)
        if isinstance(market_universe, list):
            existing = {str(r.get("ticker", "")).upper() for r in rows if isinstance(r, dict)}
            for row in market_universe:
                if not isinstance(row, dict):
                    continue
                t = str(row.get("ticker", "") or "").upper().strip()
                if t and t not in existing:
                    rows.append(dict(row))
                    existing.add(t)
    except Exception:
        pass
    try:
        # 이미 쌓인 현재가 스냅샷 기준 내부 순위권을 먼저 다시 넣는다.
        # 유니버스 밖 급등 코인이 다음 루프에서 빠지지 않게 하기 위함.
        existing = {str(r.get("ticker", "")).upper().strip() for r in rows if isinstance(r, dict)}
        for rr in get_light_snapshot_rank_rows(limit=LIGHT_SNAPSHOT_TARGET_MAX, min_move_pct=0.0):
            t = str(rr.get("ticker", "") or "").upper().strip()
            if t and t not in existing:
                rows.append(rr)
                existing.add(t)
        # v2.5.192: detail/rank_watch에서 감시 등록한 티커는 유니버스 밖이어도 스냅샷 직원이 계속 가격을 쌓게 한다.
        try:
            cleanup_forced_light_snapshot_tickers()
            forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
            if isinstance(forced, dict):
                for ft, meta in list(forced.items()):
                    t = str(ft or "").upper().strip()
                    if t and t not in existing and not is_watch_excluded_ticker(t):
                        rows.append({"ticker": t, "snapshot_forced_watch": True, "force_reason": (meta or {}).get("reason", "force_track") if isinstance(meta, dict) else "force_track"})
                        existing.add(t)
        except Exception:
            pass
        if len(rows) < LIGHT_SNAPSHOT_FALLBACK_TARGET:
            rows.extend(_fallback_market_snapshot_seed_rows(existing=existing, limit=LIGHT_SNAPSHOT_FALLBACK_TARGET - len(rows)))
    except Exception:
        pass
    def score(row):
        return (
            max(100 - int(safe_float(row.get("turnover_rank", 999), 999)), 0) * 0.8
            + max(100 - int(safe_float(row.get("surge_rank", 999), 999)), 0) * 0.6
            + safe_float(row.get("leader_score", 0), 0) * 12.0
            + safe_float(row.get("turnover_5m", row.get("turnover", row.get("turnover_recent", 0))), 0) * 0.00000001
            + max(safe_float(row.get("change_5", row.get("short_change", 0)), 0), 0) * 4.0
            + max(safe_float(row.get("change_30", 0), 0), 0) * 1.3
        )
    rows.sort(key=score, reverse=True)
    return rows[:LIGHT_SNAPSHOT_TARGET_MAX]


def light_snapshot_worker_loop():
    global LIGHT_SNAPSHOT_CURSOR, LIGHT_SNAPSHOT_LAST_RUN_TS, LIGHT_SNAPSHOT_LAST_UPDATED, LIGHT_SNAPSHOT_LAST_TRIED
    global LIGHT_SNAPSHOT_LAST_NOTE, LIGHT_SNAPSHOT_LAST_DURATION_SEC, LIGHT_SNAPSHOT_LAST_SOURCE_SIZE
    global LIGHT_SNAPSHOT_FAIL_COUNT, LIGHT_SNAPSHOT_SUCCESS_COUNT
    global LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS, LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT
    while True:
        time.sleep(LIGHT_SNAPSHOT_WORKER_SLEEP_SEC)
        if not LIGHT_SNAPSHOT_ENGINE_ON:
            continue
        started = time.time()
        tried = 0
        updated = 0
        try:
            rows = _light_snapshot_source_rows()
            LIGHT_SNAPSHOT_LAST_SOURCE_SIZE = len(rows)
            if not rows:
                LIGHT_SNAPSHOT_LAST_NOTE = "대상 없음"
                continue
            n = len(rows)
            start = int(LIGHT_SNAPSHOT_CURSOR or 0) % n
            batch = (rows[start:] + rows[:start])[:max(1, int(LIGHT_SNAPSHOT_BATCH_SIZE))]
            LIGHT_SNAPSHOT_CURSOR = (start + len(batch)) % n
            bulk_prices = get_bulk_current_price_snapshot() if LIGHT_SNAPSHOT_BULK_PRICE_ON else {}
            # v2.5.188: 전체 현재가 응답이 있으면 일부 배치만이 아니라 넓은 스윕 기록도 남긴다.
            # 이렇게 해야 빗썸 실시간 순위권에 뜬 코인이 유니버스 밖이어도 최소 스냅샷 순위/누락진단에 잡힌다.
            try:
                now_for_sweep = time.time()
                if isinstance(bulk_prices, dict) and bulk_prices and now_for_sweep - safe_float(LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS, 0) >= LIGHT_SNAPSHOT_BULK_SWEEP_INTERVAL_SEC:
                    sweep_bulk_prices_into_light_snapshots(reason="bulk_sweep_all", max_tickers=LIGHT_SNAPSHOT_BULK_SWEEP_MAX_TICKERS, bulk_prices=bulk_prices)
            except Exception as e:
                append_runtime_error_log("snapshot_bulk_sweep", str(e), exc=e, include_traceback=False)
            fallback_calls = 0
            for row in batch:
                ticker = str(row.get("ticker", "") or "").upper().strip()
                if not ticker or is_watch_excluded_ticker(ticker):
                    continue
                tried += 1
                price = safe_float(bulk_prices.get(ticker, 0), 0) if isinstance(bulk_prices, dict) else 0.0
                source = "snapshot_bulk"
                if price <= 0:
                    if fallback_calls >= LIGHT_SNAPSHOT_PER_TICKER_FALLBACK_LIMIT:
                        LIGHT_SNAPSHOT_FAIL_COUNT += 1
                        continue
                    fallback_calls += 1
                    source = "snapshot_worker"
                    price = get_price(ticker)
                if price <= 0:
                    LIGHT_SNAPSHOT_FAIL_COUNT += 1
                    continue
                turnover_hint = safe_float(row.get("turnover_5m", row.get("turnover", row.get("turnover_recent", 0))), 0)
                record_light_price_snapshot(ticker, price, turnover_hint=turnover_hint, source=source)
                LIGHT_SNAPSHOT_SUCCESS_COUNT += 1
                updated += 1
            base_note = "정상" if updated else "가격 갱신 없음"
            if LIGHT_SNAPSHOT_BULK_PRICE_ON:
                base_note += f" / {LIGHT_SNAPSHOT_BULK_LAST_NOTE}"
            LIGHT_SNAPSHOT_LAST_NOTE = base_note
        except Exception as e:
            LIGHT_SNAPSHOT_LAST_NOTE = f"오류:{str(e)[:60]}"
            append_runtime_event_log("light_snapshot_worker_error", "경량 스냅샷 루프 오류", extra={"error": str(e)[:120]})
        finally:
            LIGHT_SNAPSHOT_LAST_RUN_TS = time.time()
            LIGHT_SNAPSHOT_LAST_TRIED = tried
            LIGHT_SNAPSHOT_LAST_UPDATED = updated
            LIGHT_SNAPSHOT_LAST_DURATION_SEC = round(time.time() - started, 2)

def get_orderbook_best_ask(ticker: str) -> float:
    cache_key = str(ticker or "").upper().strip()
    cached = get_api_cache_entry(API_ORDERBOOK_CACHE, cache_key, API_ORDERBOOK_CACHE_TTL_SEC)
    if isinstance(cached, dict):
        ob = cached
    else:
        ob = None
    try:
        if ob is None:
            ob = _call_with_timeout(pybithumb.get_orderbook, ticker, default=None)
            if ob:
                set_api_cache_entry(API_ORDERBOOK_CACHE, cache_key, ob)
        if not ob:
            return -1
        if isinstance(ob, dict) and "asks" in ob and ob["asks"]:
            ask0 = ob["asks"][0]
            return float(ask0.get("price", -1))
        if isinstance(ob, dict) and "data" in ob and "asks" in ob["data"] and ob["data"]["asks"]:
            ask0 = ob["data"]["asks"][0]
            return float(ask0.get("price", -1))
        return -1
    except Exception:
        return -1


def is_slow_ohlcv_interval(interval: str) -> bool:
    return str(interval or "").lower().strip() in SLOW_OHLCV_INTERVALS

def is_fast_scan_critical_stage() -> bool:
    """빠른 후보 생산/시장 캐시 루프에서 무거운 상위봉 호출을 막기 위한 판단."""
    try:
        stage = str(last_main_loop_stage or "")
        th_name = threading.current_thread().name or ""
        if stage.startswith(("scan_watchlist", "build_cache", "market_refresh", "scan_wait_market")):
            return True
        if "fast_scan" in th_name or "market_refresh" in th_name:
            return True
    except Exception:
        pass
    return False

def _bump_ohlcv_interval_counter(target: dict, interval: str, delta: int = 1):
    try:
        key = str(interval or "unknown").lower().strip() or "unknown"
        target[key] = int(safe_float(target.get(key, 0), 0)) + int(delta)
    except Exception:
        pass

def _bump_ohlcv_ticker_counter(target: dict, ticker: str, interval: str, delta: int = 1):
    try:
        t = str(ticker or "").upper().strip() or "?"
        i = str(interval or "unknown").lower().strip() or "unknown"
        key = f"{t}:{i}"
        target[key] = int(safe_float(target.get(key, 0), 0)) + int(delta)
    except Exception:
        pass

def _slow_prefetch_failure_cooldown_active(ticker: str, interval: str, now_ts: float = None) -> bool:
    try:
        now_ts = safe_float(now_ts, time.time())
        row = get_ohlcv_fail_state(ticker, interval)
        if not isinstance(row, dict):
            return False
        last_failed = safe_float(row.get("last_failed_ts", 0), 0)
        if last_failed <= 0:
            return False
        return (now_ts - last_failed) < SLOW_OHLCV_PREFETCH_FAIL_REPEAT_SEC
    except Exception:
        return False

def _slow_prefetch_interval_cooldown_active(interval: str, now_ts: float = None) -> bool:
    try:
        now_ts = safe_float(now_ts, time.time())
        interval = str(interval or "").lower().strip()
        until = safe_float(globals().get("SLOW_OHLCV_PREFETCH_INTERVAL_COOLDOWN_UNTIL", {}).get(interval, 0), 0)
        return until > now_ts
    except Exception:
        return False


def _maybe_open_slow_prefetch_interval_cooldown(ticker: str, interval: str):
    """특정 상위봉 interval이 반복 실패하면 그 interval만 잠깐 쉬게 한다.

    전체 OHLCV나 빠른 스캔을 멈추는 게 아니라, 실패가 몰리는 4시간봉 같은
    느린 선조회만 격리한다.
    """
    try:
        interval = str(interval or "").lower().strip()
        if not interval:
            return
        window = safe_float(globals().get("SLOW_OHLCV_PREFETCH_INTERVAL_FAIL_WINDOW_SEC", 900), 900)
        limit = int(safe_float(globals().get("SLOW_OHLCV_PREFETCH_INTERVAL_FAIL_LIMIT", 8), 8))
        if interval != "minute240":
            limit = max(limit + 4, 12)
        now_ts = time.time()
        bad = 0
        try:
            for key, row in list(API_OHLCV_FAIL_STATE.items()) if isinstance(API_OHLCV_FAIL_STATE, dict) else []:
                if not isinstance(row, dict):
                    continue
                iv = str(key[1] if isinstance(key, tuple) and len(key) > 1 else row.get("interval", "") or "").lower()
                if iv != interval:
                    continue
                last_failed = safe_float(row.get("last_failed_ts", 0), 0)
                if last_failed > 0 and now_ts - last_failed <= window:
                    bad += 1
        except Exception:
            bad = 0
        if bad >= limit:
            until = now_ts + safe_float(globals().get("SLOW_OHLCV_PREFETCH_INTERVAL_FAIL_COOLDOWN_SEC", 1200), 1200)
            globals().setdefault("SLOW_OHLCV_PREFETCH_INTERVAL_COOLDOWN_UNTIL", {})[interval] = until
            append_runtime_event_log(
                "slow_ohlcv_interval_cooldown",
                "상위봉 선조회 실패가 몰려 해당 interval만 잠깐 쉬게 함",
                extra={"ticker": str(ticker or ""), "interval": interval, "recent_fail": bad, "cooldown_sec": int(until - now_ts)},
            )
    except Exception:
        pass


def _slow_prefetch_candidate_score(item: dict) -> float:
    try:
        item = item if isinstance(item, dict) else {}
        score = safe_float(item.get("lite_score", 0), 0)
        bucket = str(item.get("alert_bucket", "") or "")
        grade = str(item.get("alert_grade", item.get("user_alert_grade", "")) or "").upper().strip()
        if bucket == "user_alert":
            score += 60
        elif bucket == "internal_watch":
            score += 28
        if grade == "S":
            score += 35
        elif grade == "A":
            score += 25
        elif grade == "B":
            score += 12
        score += min(max(safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0) / 10_000_000, 0), 20)
        score += max(safe_float(item.get("change_5", 0), 0), 0) * 2.5
        score += max(safe_float(item.get("change_30", 0), 0), 0) * 1.0
        score += safe_float(item.get("leader_score", 0), 0) * 4.0
        return round(score, 2)
    except Exception:
        return 0.0

def _should_prefetch_slow_ohlcv_for_item(item: dict) -> bool:
    """빠른 루프에서 상위봉 캐시를 예약할지 결정한다.

    v2.5.172: 1/3/5/15/30/60분의 가벼운 흐름은 계속 보되,
    무거운 상위봉 OHLCV 예약은 진짜 후보에게만 맡긴다.
    """
    try:
        item = item if isinstance(item, dict) else {}
        bucket = str(item.get("alert_bucket", "") or "")
        grade = str(item.get("alert_grade", item.get("user_alert_grade", "")) or "").upper().strip()
        primary = str(item.get("primary_reason", "") or "")
        turn5 = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0)
        turn3 = safe_float(item.get("turnover_recent_3m", 0), 0)
        chg5 = safe_float(item.get("change_5", 0), 0)
        chg15 = safe_float(item.get("change_15", 0), 0)
        chg30 = safe_float(item.get("change_30", 0), 0)
        chg60 = safe_float(item.get("change_60", 0), 0)
        leader = safe_float(item.get("leader_score", 0), 0)
        lite = safe_float(item.get("lite_score", 0), 0)
        from_low = safe_float(item.get("from_low", 0), 0)
        below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
        max_mid = max(chg15, chg30, chg60)
        max_short = max(chg5, chg15, chg30)
        if bucket == "user_alert":
            return True
        if bucket == "internal_watch" and grade in {"S", "A", "B"}:
            return (turn5 >= SLOW_OHLCV_PREFETCH_MIN_TURNOVER_5M or turn3 >= 9_000_000) and max_short >= 0.20
        if primary in {"실시간 폭발 초입 후보", "1시간 급등 초입 후보", "관찰 후 승격 후보"}:
            return turn5 >= SLOW_OHLCV_PREFETCH_MIN_TURNOVER_5M and max(chg5, max_mid) >= 0.55 and leader >= 1.0
        if lite >= SLOW_OHLCV_PREFETCH_MIN_LITE_SCORE and turn5 >= SLOW_OHLCV_PREFETCH_MIN_TURNOVER_5M and max_mid >= 0.55 and from_low <= 4.5:
            return True
        if turn5 >= 45_000_000 and max_short >= 0.45 and leader >= 1.2 and below_high >= 0.60:
            return True
        return False
    except Exception:
        return False

def _mark_candidate_precision_gate(item: dict) -> dict:
    """정밀분석 전 후보는 사용자 알림으로 바로 보내지 않도록 최종 안전장치."""
    try:
        item = item if isinstance(item, dict) else {}
        item.setdefault("candidate_source", "fast_scan_cache")
        item.setdefault("entry_path", str(item.get("primary_reason", "") or "fast_scan"))
        ctx = item.get("alert_chart_context") if isinstance(item.get("alert_chart_context"), dict) else {}
        precision_ok = bool(ctx) and not bool(item.get("lite_scan_only", False))
        item["precision_stage"] = "정밀분석 완료" if precision_ok else "정밀분석 전/부분"
        if str(item.get("alert_bucket", "")) == "user_alert" and not precision_ok:
            item["alert_bucket"] = "internal_watch"
            item["alert_grade"] = "B" if str(item.get("alert_grade", "C")) in {"S", "A"} else str(item.get("alert_grade", "C") or "C")
            item["bucket_rank"] = 2
            item["decision_path"] = "정밀분석 전이라 사용자 알림 보류"
            reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
            if "정밀분석 전이라 사용자 알림 보류" not in reasons:
                reasons.insert(0, "정밀분석 전이라 사용자 알림 보류")
            item["reasons"] = reasons[:6]
        else:
            item.setdefault("decision_path", "정밀분석 완료 후 후보 분류")
        return item
    except Exception:
        return item if isinstance(item, dict) else {}

def record_slow_ohlcv_deferred(ticker: str, interval: str, reason: str = "fast_loop_defer"):
    global SLOW_OHLCV_PREFETCH_DEFERRED
    try:
        SLOW_OHLCV_PREFETCH_DEFERRED += 1
        _bump_ohlcv_interval_counter(API_OHLCV_DEFER_BY_INTERVAL, interval, 1)
        cnt = int(safe_float(SLOW_OHLCV_PREFETCH_DEFERRED, 0))
        if cnt in {1, 2, 3, 5, 10} or cnt % 50 == 0:
            append_runtime_event_log(
                "slow_ohlcv_deferred_fast_loop",
                "빠른 스캔 중 상위봉 OHLCV 직접 조회를 미루고 캐시/느린 큐로 넘김",
                extra={"ticker": str(ticker or "").upper().strip(), "interval": str(interval or ""), "count": cnt, "reason": reason},
            )
    except Exception:
        pass

def _slow_prefetch_priority(ticker: str, interval: str, reason: str = "") -> float:
    """느린 OHLCV 큐 우선순위. 대상을 줄이지 않고, 먼저 볼 순서만 정한다."""
    try:
        interval = str(interval or "").lower().strip()
        reason = str(reason or "").lower()
        score = 0.0
        if "user" in reason or "alert" in reason:
            score += 100
        if "watch" in reason or "internal" in reason:
            score += 45
        if "hot" in reason or "ignition" in reason or "hour" in reason:
            score += 35
        score += {"minute15": 34, "minute30": 32, "minute60": 28, "minute240": 16, "day": 12}.get(interval, 10)
        return float(score)
    except Exception:
        return 0.0

def _sort_slow_prefetch_queue_locked():
    try:
        SLOW_OHLCV_PREFETCH_QUEUE.sort(
            key=lambda k: (
                -safe_float(SLOW_OHLCV_PREFETCH_META.get(k, {}).get("priority", 0), 0),
                safe_float(SLOW_OHLCV_PREFETCH_META.get(k, {}).get("ts", 0), 0),
            )
        )
    except Exception:
        pass

def _wait_for_ohlcv_inflight_result(cache_key, stale_ttl: float, wait_sec: float):
    """같은 OHLCV 요청이 이미 진행 중이면 아주 짧게 결과 공유를 기다린다."""
    try:
        end_ts = time.time() + max(0.0, safe_float(wait_sec, 0.0))
        while time.time() < end_ts:
            time.sleep(0.04)
            cached = get_api_cache_entry(API_OHLCV_CACHE, cache_key, stale_ttl, copy_dataframe=True)
            if cached is not None:
                return cached
            with API_OHLCV_FETCH_LOCK:
                if cache_key not in API_OHLCV_INFLIGHT:
                    break
        return get_api_cache_entry(API_OHLCV_CACHE, cache_key, stale_ttl, copy_dataframe=True)
    except Exception:
        return None

def _note_ohlcv_global_failure(ticker: str = "", interval: str = "", reason: str = ""):
    """OHLCV 실패가 몰리면 새 OHLCV 네트워크 호출을 잠깐 멈춘다."""
    global OHLCV_GLOBAL_FAIL_TIMES, OHLCV_GLOBAL_CIRCUIT_UNTIL, OHLCV_GLOBAL_CIRCUIT_REASON
    if not OHLCV_CIRCUIT_BREAKER_ON:
        return
    try:
        now_ts = time.time()
        window = max(30, int(OHLCV_CIRCUIT_FAIL_WINDOW_SEC))
        OHLCV_GLOBAL_FAIL_TIMES = [x for x in list(OHLCV_GLOBAL_FAIL_TIMES or []) if now_ts - safe_float(x, 0) <= window]
        OHLCV_GLOBAL_FAIL_TIMES.append(now_ts)
        if len(OHLCV_GLOBAL_FAIL_TIMES) >= int(OHLCV_CIRCUIT_FAIL_THRESHOLD):
            until = now_ts + max(30, int(OHLCV_CIRCUIT_COOLDOWN_SEC))
            if until > safe_float(OHLCV_GLOBAL_CIRCUIT_UNTIL, 0):
                OHLCV_GLOBAL_CIRCUIT_UNTIL = until
                OHLCV_GLOBAL_CIRCUIT_REASON = f"OHLCV 실패 과다: {len(OHLCV_GLOBAL_FAIL_TIMES)}건/{window}초"
                append_runtime_event_log(
                    "ohlcv_circuit_open",
                    "OHLCV 실패가 몰려 새 OHLCV 조회를 잠깐 중단",
                    extra={"ticker": str(ticker or ""), "interval": str(interval or ""), "reason": str(reason or "")[:80], "cooldown_sec": int(until - now_ts)},
                )
    except Exception:
        pass


def is_ohlcv_circuit_open(now_ts: float = None) -> bool:
    try:
        if not OHLCV_CIRCUIT_BREAKER_ON:
            return False
        now_ts = safe_float(now_ts, time.time())
        return safe_float(OHLCV_GLOBAL_CIRCUIT_UNTIL, 0) > now_ts
    except Exception:
        return False


def get_ohlcv_circuit_left(now_ts: float = None) -> int:
    try:
        now_ts = safe_float(now_ts, time.time())
        return max(0, int(safe_float(OHLCV_GLOBAL_CIRCUIT_UNTIL, 0) - now_ts))
    except Exception:
        return 0


def queue_slow_ohlcv_prefetch(ticker: str, interval: str, reason: str = "fast_scan") -> bool:
    """상위봉/일봉 캐시를 느린 루프에서 채우도록 예약한다.
    빠른 스캔 루프에서는 네트워크 직접 호출 대신 이 큐만 넣는다.
    v2.5.171: 실패 직후/중복/과다 예약을 더 강하게 막는다.
    """
    if not SLOW_OHLCV_PREFETCH_ON:
        return False
    ticker = str(ticker or "").upper().strip()
    interval = str(interval or "").lower().strip()
    if not ticker or not interval or not is_slow_ohlcv_interval(interval):
        return False
    now_ts = time.time()
    key = (ticker, interval)
    try:
        if _slow_prefetch_failure_cooldown_active(ticker, interval, now_ts=now_ts):
            return False
        if _slow_prefetch_interval_cooldown_active(interval, now_ts=now_ts):
            return False
        with SLOW_OHLCV_PREFETCH_LOCK:
            last_ts = safe_float(SLOW_OHLCV_PREFETCH_SEEN.get(key, 0), 0)
            if now_ts - last_ts < SLOW_OHLCV_PREFETCH_MIN_REPEAT_SEC:
                return False
            if key in SLOW_OHLCV_PREFETCH_QUEUE:
                return False
            if len(SLOW_OHLCV_PREFETCH_QUEUE) >= SLOW_OHLCV_PREFETCH_MAX_QUEUE:
                dropped = SLOW_OHLCV_PREFETCH_QUEUE.pop(-1)
                SLOW_OHLCV_PREFETCH_META.pop(dropped, None)
            SLOW_OHLCV_PREFETCH_QUEUE.append(key)
            SLOW_OHLCV_PREFETCH_META[key] = {"ts": now_ts, "reason": str(reason or ""), "priority": _slow_prefetch_priority(ticker, interval, reason)}
            _sort_slow_prefetch_queue_locked()
            SLOW_OHLCV_PREFETCH_SEEN[key] = now_ts
        append_runtime_event_log("slow_ohlcv_prefetch_queued", "상위봉/일봉 느린 캐시 갱신 예약", extra={"ticker": ticker, "interval": interval, "reason": reason})
        return True
    except Exception:
        return False

def queue_slow_ohlcv_prefetch_for_items(items, reason: str = "fast_scan_result", max_items: int = None):
    """상위봉 느린 캐시 예약.

    v2.5.171: 빠른 스캔이 힘들어하지 않도록, 상위권/알림 직전 후보만 예약한다.
    """
    try:
        if not SLOW_OHLCV_PREFETCH_ON:
            return
        max_items = SLOW_OHLCV_PREFETCH_MAX_PER_FAST_SCAN if max_items is None else min(int(max_items), SLOW_OHLCV_PREFETCH_MAX_PER_FAST_SCAN)
        rows = [x for x in list(items or []) if isinstance(x, dict) and x.get("ticker") and _should_prefetch_slow_ohlcv_for_item(x)]
        rows.sort(key=lambda x: _slow_prefetch_candidate_score(x), reverse=True)
        queued = 0
        for item in rows[:max(0, int(max_items))]:
            ticker = str(item.get("ticker", "")).upper().strip()
            if not ticker:
                continue
            # v2.5.172: 한 후보가 여러 상위봉을 한꺼번에 예약하지 않게 제한한다.
            # 사용자 알림 직전만 4시간+일봉, 일반 내부감시는 대표 상위봉 1개만.
            if str(item.get("alert_bucket", "")) == "user_alert":
                intervals = list(SLOW_OHLCV_PREFETCH_PER_TICKER_INTERVALS)
            else:
                intervals = [ALERT_HTF_INTERVAL]
            for interval in intervals:
                if queue_slow_ohlcv_prefetch(ticker, interval, reason=reason):
                    queued += 1
        if queued:
            append_runtime_event_log("slow_ohlcv_prefetch_batch", "상위봉 느린 캐시 예약 묶음 처리", extra={"queued": queued, "candidates": len(rows), "reason": reason})
    except Exception as e:
        append_runtime_event_log("slow_ohlcv_prefetch_queue_error", "상위봉 느린 큐 등록 오류", extra={"error": str(e)[:120]})

def _ohlcv_fail_key(ticker: str, interval: str = "minute3"):
    return (str(ticker or "").upper().strip(), str(interval or "minute3").lower().strip())

def get_ohlcv_fail_state(ticker: str, interval: str = "minute3") -> dict:
    key = _ohlcv_fail_key(ticker, interval)
    row = API_OHLCV_FAIL_STATE.get(key)
    return row if isinstance(row, dict) else {}

def get_ohlcv_cooldown_left(ticker: str, interval: str = "minute3", now_ts: float = None) -> float:
    now_ts = safe_float(now_ts, time.time())
    row = get_ohlcv_fail_state(ticker, interval)
    until_ts = safe_float(row.get("cooldown_until", 0), 0)
    return max(0.0, until_ts - now_ts)

def is_ohlcv_fetch_on_cooldown(ticker: str, interval: str = "minute3", now_ts: float = None) -> bool:
    return get_ohlcv_cooldown_left(ticker, interval, now_ts=now_ts) > 0

def record_ohlcv_success(ticker: str, interval: str = "minute3"):
    try:
        API_OHLCV_FAIL_STATE.pop(_ohlcv_fail_key(ticker, interval), None)
        _bump_ohlcv_interval_counter(API_OHLCV_SUCCESS_BY_INTERVAL, interval, 1)
    except Exception:
        pass

def record_ohlcv_failure(ticker: str, interval: str = "minute3", reason: str = "", caller: str = ""):
    try:
        key = _ohlcv_fail_key(ticker, interval)
        now_ts = time.time()
        caller = str(caller or _guess_ohlcv_caller() or "unknown")[:80]
        prev = API_OHLCV_FAIL_STATE.get(key)
        prev_count = int(safe_float(prev.get("count", 0), 0)) if isinstance(prev, dict) else 0
        count = min(prev_count + 1, 20)
        base = OHLCV_FAIL_COOLDOWN_BASE_SEC
        max_cd = OHLCV_FAIL_COOLDOWN_MAX_SEC
        # v2.5.202: 기존 코드는 max(base, 12), max(max_cd, 70) 구조라 minute1도 실제로는
        # 기본 45초/최대 900초 쿨다운을 먹었다. 이 때문에 한 번 실패한 1분봉이 오래 막혀
        # 차트정교화와 거래대금 검증이 계속 0/확인전으로 남았다. 분봉별로 진짜 의도한 값을 직접 지정한다.
        if key[1] == "minute1":
            base = 10
            max_cd = 70
        elif key[1] in {"minute3", "minute5", "minute10"}:
            base = 16
            max_cd = 120
        elif key[1] in {"minute15", "minute30"}:
            base = 45
            max_cd = 300
        elif key[1] == "minute60":
            base = 90
            max_cd = 600
        elif key[1] == "minute240":
            # v2.5.237: 4시간봉 실패가 누적되면 같은 코인을 계속 두드려 timeout 폭증이 난다.
            base = 600
            max_cd = 3600
        elif key[1] == "day":
            base = 900
            max_cd = 7200
        cooldown = min(max_cd, base * (1 if count <= 1 else min(count, 6)))
        API_OHLCV_FAIL_STATE[key] = {
            "count": count,
            "last_failed_ts": now_ts,
            "cooldown_until": now_ts + cooldown,
            "next_retry_at": now_ts + cooldown,
            "reason": str(reason or "조회 실패")[:80],
            "caller": caller,
            "status": "cooldown",
        }
        _bump_ohlcv_interval_counter(API_OHLCV_FAIL_BY_INTERVAL, key[1], 1)
        _bump_ohlcv_ticker_counter(API_OHLCV_FAIL_BY_TICKER, key[0], key[1], 1)
        _bump_ohlcv_reason_counter(reason or "unknown", 1)
        low_reason = str(reason or "").lower()
        result = "timeout" if "timeout" in low_reason else ("exception" if "exception" in low_reason else ("empty" if "empty" in low_reason or "none" in low_reason else "fail"))
        record_ohlcv_caller_stat(key[0], key[1], caller=caller, result=result, reason=reason)
        if count in {1, 2, 3, 5}:
            append_runtime_event_log(
                "ohlcv_fail_cooldown",
                "OHLCV 조회 실패 종목은 잠깐 건너뜀",
                extra={"ticker": key[0], "interval": key[1], "count": count, "cooldown_sec": int(cooldown), "reason": str(reason or "")[:80]},
            )
        _note_ohlcv_global_failure(key[0], key[1], reason=reason)
    except Exception:
        pass

def register_data_failure_missed_probe(ticker: str, source_row: dict = None, reason: str = ""):
    """데이터 실패가 실시간 스캔을 막지 않도록 별도 missed 후보로만 남긴다.

    그냥 실패만 한 종목은 사용자 알림/상위 후보에 올리지 않는다.
    다만 기준가를 잡을 수 있는 경우엔 30분 뒤 실제로 움직였는지 확인해서
    움직였으면 /missed에 '데이터 실패로 못 봄'으로 기록한다.
    """
    try:
        if not MISSED_REVIEW_ON:
            return
        ticker = str(ticker or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            return
        now_ts = time.time()
        last_ts = safe_float(DATA_FAIL_MISSED_RECENT.get(ticker, 0), 0)
        if now_ts - last_ts < DATA_FAIL_MISSED_COOLDOWN_SEC:
            return
        source_row = source_row if isinstance(source_row, dict) else {}
        price = safe_float(source_row.get("last_price", source_row.get("price", 0)), 0)
        df3 = source_row.get("df_3m")
        if price <= 0 and df3 is not None:
            try:
                price = safe_float(df3["close"].iloc[-1], 0)
            except Exception:
                price = 0
        if price <= 0:
            return
        item = {
            "ticker": ticker,
            "current_price": price,
            "price": price,
            "strategy": "DATA_FAIL",
            "strategy_label": "데이터 조회 실패",
            "trade_tier": "C",
            "user_alert_grade": "C",
            "signal_score": 0.0,
            "edge_score": 0.0,
            "vol_ratio": safe_float(source_row.get("vol_ratio", 0), 0),
            "leader_score": safe_float(source_row.get("leader_score", 0), 0),
            "change_1": 0.0,
            "change_3": 0.0,
            "change_5": 0.0,
            "change_pct": 0.0,
            "turnover": safe_float(source_row.get("turnover_recent", source_row.get("turnover", 0)), 0),
            "turnover_rank": int(safe_float(source_row.get("turnover_rank", 0), 0)),
            "surge_rank": int(safe_float(source_row.get("surge_rank", 0), 0)),
            "quality_block_reason": "데이터 조회 실패로 이번 스캔 제외",
            "data_fetch_failed": True,
            "data_fail_reason": str(reason or "OHLCV 조회 실패")[:120],
        }
        row = build_missed_review_row_from_item(item, now_ts=now_ts)
        if not row:
            return
        row["data_fetch_failed"] = True
        row["data_fail_reason"] = str(reason or "OHLCV 조회 실패")[:120]
        row["quality_block_reason"] = "데이터 조회 실패로 이번 스캔 제외"
        row["seen_market"] = True
        row["seen_shortlist"] = False
        row["seen_signal"] = False
        existing = missed_review_queue.get(ticker)
        if isinstance(existing, dict):
            missed_review_queue[ticker] = merge_missed_review_row(existing, row)
        else:
            missed_review_queue[ticker] = row
        DATA_FAIL_MISSED_RECENT[ticker] = now_ts
        cleanup_missed_review_queue(now_ts)
        persist_missed_review_state()
    except Exception as e:
        append_runtime_event_log("data_fail_missed_register_error", "데이터 실패 missed 등록 오류", extra={"ticker": str(ticker or ""), "error": str(e)[:120]})

def _begin_ohlcv_fetch(cache_key) -> bool:
    global API_OHLCV_DUP_SKIP_COUNT, API_OHLCV_LAST_DUP_SKIP_TS, API_OHLCV_LAST_DUP_SKIP_KEY
    now_ts = time.time()
    try:
        with API_OHLCV_FETCH_LOCK:
            stale_keys = [k for k, ts in API_OHLCV_INFLIGHT.items() if now_ts - safe_float(ts, 0) > 90]
            for k in stale_keys:
                API_OHLCV_INFLIGHT.pop(k, None)
            if cache_key in API_OHLCV_INFLIGHT:
                API_OHLCV_DUP_SKIP_COUNT += 1
                API_OHLCV_LAST_DUP_SKIP_TS = now_ts
                API_OHLCV_LAST_DUP_SKIP_KEY = f"{cache_key[0]}:{cache_key[1]}"
                cnt = int(safe_float(API_OHLCV_DUP_SKIP_COUNT, 0))
                if cnt in {1, 2, 3, 5, 10} or cnt % 25 == 0:
                    append_runtime_event_log("ohlcv_duplicate_inflight_skip", "같은 OHLCV 요청이 이미 진행 중이라 중복 호출을 막음", extra={"ticker": cache_key[0], "interval": cache_key[1], "dup_skip_count": cnt})
                return False
            API_OHLCV_INFLIGHT[cache_key] = now_ts
            return True
    except Exception:
        return True

def _end_ohlcv_fetch(cache_key):
    try:
        with API_OHLCV_FETCH_LOCK:
            API_OHLCV_INFLIGHT.pop(cache_key, None)
    except Exception:
        pass

def get_ohlcv(ticker: str, interval: str = "minute3", allow_slow_fetch: bool = False):
    cache_key = (str(ticker or "").upper().strip(), str(interval or "minute3").lower().strip())
    interval_key = cache_key[1]
    ohlcv_caller = _guess_ohlcv_caller()
    ttl_sec = get_ohlcv_cache_ttl(interval)
    cached = get_api_cache_entry(API_OHLCV_CACHE, cache_key, ttl_sec, copy_dataframe=True)
    if cached is not None:
        return cached
    if interval_key == "minute1":
        timeout_sec = API_OHLCV_MINUTE1_TIMEOUT_SEC
    elif interval_key in {"minute3", "minute5", "minute10"}:
        timeout_sec = API_OHLCV_MINUTE3_TIMEOUT_SEC
    else:
        timeout_sec = API_OHLCV_SLOW_TIMEOUT_SEC
    stale_ttl = max(ttl_sec * API_OHLCV_STALE_FALLBACK_MULTIPLIER, ttl_sec + 6.0)
    stale = get_api_cache_entry(API_OHLCV_CACHE, cache_key, stale_ttl, copy_dataframe=True)
    # v2.5.245: 명령어 캐시/리뷰 출력은 읽기전용이다. 여기서 새 OHLCV 네트워크 호출을 만들면
    # build_rank_source가 다시 20~50초로 튀고 저점방어/상위봉 표시도 같이 흔들린다.
    if bool(globals().get("COMMAND_DISPLAY_READONLY_BUILDING", False)) and (not allow_slow_fetch):
        if stale is not None:
            return stale
        return None
    # v2.5.181: 빠른 스캔/시장 캐시/리뷰 출력 단계에서는 새 OHLCV 네트워크 호출을 만들지 않는다.
    # 캐시가 있으면 쓰고, 없으면 None으로 넘겨 스냅샷 엔진이 계속 돌게 한다.
    if (not OHLCV_NETWORK_FETCH_IN_FAST_STAGE_ON) and (not allow_slow_fetch) and is_fast_scan_critical_stage():
        if stale is not None:
            return stale
        return None
    if is_ohlcv_circuit_open():
        if stale is not None:
            return stale
        return None
    # v2.5.170: 빠른 스캔/시장 캐시 루프에서는 day/minute60/minute240 같은
    # 상위봉 조회를 직접 실행하지 않는다. 캐시가 있으면 쓰고, 없으면 느린 prefetch 큐에 넘긴다.
    if FAST_LOOP_SLOW_OHLCV_DEFER_ON and is_slow_ohlcv_interval(interval_key) and (not allow_slow_fetch) and is_fast_scan_critical_stage():
        # v2.5.172: 빠른 루프가 15/30/60/240/day 요청을 마구 만들어내면
        # 느린 큐도 같이 밀린다. 직접 조회는 금지하고, 큐 예약도 큰 상위봉만 제한적으로 한다.
        if interval_key in SLOW_OHLCV_FAST_DEFER_QUEUEABLE_INTERVALS:
            queue_slow_ohlcv_prefetch(cache_key[0], interval_key, reason="deferred_from_fast_loop")
        record_slow_ohlcv_deferred(cache_key[0], interval_key)
        if stale is not None:
            return stale
        return None
    # v2.5.146: 실패 종목은 네트워크를 다시 물고 있지 않는다.
    # stale 캐시가 있으면 그걸 쓰고, 없으면 이번 차수는 바로 건너뛴다.
    # v2.5.202: 단, 쿨다운이 이미 끝난 실패 상태는 바로 청소해서 재시도 기회를 준다.
    cleanup_ohlcv_fail_states(now_ts=time.time())
    if is_ohlcv_fetch_on_cooldown(cache_key[0], interval_key):
        if stale is not None:
            return stale
        return None
    if not _begin_ohlcv_fetch(cache_key):
        wait_sec = OHLCV_DUP_WAIT_SLOW_SEC if is_slow_ohlcv_interval(interval_key) else OHLCV_DUP_WAIT_FAST_SEC
        shared = _wait_for_ohlcv_inflight_result(cache_key, stale_ttl, wait_sec)
        if shared is not None:
            return shared
        if stale is not None:
            return stale
        return None
    try:
        df = _call_with_timeout(pybithumb.get_ohlcv, ticker, interval=interval, timeout_sec=timeout_sec, default=None)
        if df is not None:
            set_api_cache_entry(API_OHLCV_CACHE, cache_key, df, copy_dataframe=True)
            record_ohlcv_success(cache_key[0], interval_key)
            record_ohlcv_caller_stat(cache_key[0], interval_key, caller=ohlcv_caller, result="ok")
            try:
                return df.copy(deep=True)
            except Exception:
                return df
        fail_reason = get_api_call_last_failure_reason("get_ohlcv", max_age_sec=max(timeout_sec + 1.0, 2.0))
        if not fail_reason:
            fail_reason = "empty_response"
        record_ohlcv_failure(cache_key[0], interval_key, reason=fail_reason, caller=ohlcv_caller)
        if stale is not None:
            return stale
        return None
    except Exception as e:
        record_ohlcv_failure(cache_key[0], interval_key, reason=f"exception:{e.__class__.__name__}", caller=ohlcv_caller)
        if stale is not None:
            return stale
        return None
    finally:
        _end_ohlcv_fetch(cache_key)

def slow_ohlcv_prefetch_loop():
    """상위봉/일봉 전용 느린 캐시 갱신 루프.

    빠른 스캔이 minute60/day 조회에 묶이지 않도록, fast scan은 큐에만 넣고
    이 루프가 천천히 캐시를 채운다.
    """
    global SLOW_OHLCV_PREFETCH_DONE, SLOW_OHLCV_PREFETCH_FAIL, SLOW_OHLCV_PREFETCH_LAST_ITEM, SLOW_OHLCV_PREFETCH_LAST_RESULT
    while True:
        time.sleep(SLOW_OHLCV_PREFETCH_SLEEP_SEC)
        if not SLOW_OHLCV_PREFETCH_ON:
            continue
        key = None
        try:
            with SLOW_OHLCV_PREFETCH_LOCK:
                if SLOW_OHLCV_PREFETCH_QUEUE:
                    key = SLOW_OHLCV_PREFETCH_QUEUE.pop(0)
                    SLOW_OHLCV_PREFETCH_META.pop(key, None)
            if not key:
                time.sleep(0.8)
                continue
            if is_ohlcv_circuit_open():
                # 실패가 몰린 상태에서는 상위봉 직원도 잠깐 쉰다.
                with SLOW_OHLCV_PREFETCH_LOCK:
                    if key not in SLOW_OHLCV_PREFETCH_QUEUE:
                        SLOW_OHLCV_PREFETCH_QUEUE.insert(0, key)
                time.sleep(1.5)
                continue
            ticker, interval = key
            SLOW_OHLCV_PREFETCH_LAST_ITEM = f"{ticker}:{interval}"
            df = get_ohlcv(ticker, interval, allow_slow_fetch=True)
            if df is not None and len(df) > 0:
                SLOW_OHLCV_PREFETCH_DONE += 1
                SLOW_OHLCV_PREFETCH_LAST_RESULT = "성공"
            else:
                SLOW_OHLCV_PREFETCH_FAIL += 1
                SLOW_OHLCV_PREFETCH_LAST_RESULT = "실패/캐시없음"
                _maybe_open_slow_prefetch_interval_cooldown(ticker, interval)
            cnt = int(safe_float(SLOW_OHLCV_PREFETCH_DONE + SLOW_OHLCV_PREFETCH_FAIL, 0))
            if cnt in {1, 2, 3, 5, 10} or cnt % 40 == 0:
                append_runtime_event_log("slow_ohlcv_prefetch_done", "상위봉/일봉 느린 캐시 처리", extra={"ticker": ticker, "interval": interval, "result": SLOW_OHLCV_PREFETCH_LAST_RESULT, "done": SLOW_OHLCV_PREFETCH_DONE, "fail": SLOW_OHLCV_PREFETCH_FAIL})
        except Exception as e:
            SLOW_OHLCV_PREFETCH_FAIL += 1
            SLOW_OHLCV_PREFETCH_LAST_RESULT = f"오류:{str(e)[:60]}"
            append_runtime_event_log("slow_ohlcv_prefetch_error", "상위봉 느린 캐시 루프 오류", extra={"key": str(key), "error": str(e)[:120]})

def get_balance(ticker: str) -> float:
    try:
        bal = _call_with_timeout(bithumb.get_balance, ticker, default=None)
        return float(bal[0] or 0) if bal else 0.0
    except Exception:
        return 0.0

def get_krw_balance():
    try:
        bal = _call_with_timeout(bithumb.get_balance, "BTC", default=None)
        if not bal or len(bal) < 4:
            return 0.0
        return float(bal[2] or 0)
    except Exception:
        return 0.0

def get_cached_market_tickers(force=False):
    global market_all_tickers, market_all_tickers_time, last_ticker_fetch_attempt_ts
    now_ts = time.time()
    cached_age = now_ts - market_all_tickers_time if market_all_tickers_time else None

    # 티커 목록은 장중에 자주 바뀌지 않는다.
    # v2.5.141까지는 force 요청이 쌓이면 get_tickers를 계속 두드려 fetch_tickers 병목이 생겼다.
    if market_all_tickers:
        if cached_age is not None and cached_age < TICKER_LIST_REFRESH_SEC:
            return list(market_all_tickers)
        if force and (now_ts - safe_float(last_ticker_fetch_attempt_ts, 0)) < TICKER_LIST_FORCE_MIN_INTERVAL_SEC:
            append_runtime_event_log(
                "ticker_fetch_skip_cached",
                "force 요청이지만 최근 티커 목록을 재사용",
                extra={"age_sec": int(cached_age or 0), "force": force},
            )
            return list(market_all_tickers)
    elif force and (now_ts - safe_float(last_ticker_fetch_attempt_ts, 0)) < TICKER_FALLBACK_RETRY_SEC:
        fallback = [t for t in DEFAULT_MARKET_TICKERS if t]
        if fallback:
            return list(fallback)

    try:
        mark_main_loop_heartbeat(stage="fetch_tickers")
    except Exception:
        pass
    last_ticker_fetch_attempt_ts = now_ts
    try:
        tickers = _call_with_timeout(pybithumb.get_tickers, timeout_sec=TICKER_LIST_CALL_TIMEOUT_SEC, default=None)
        clean = []
        for raw in tickers or []:
            ticker = str(raw or "").upper().strip()
            if not ticker or ticker == "BTC":
                continue
            clean.append(ticker)
        if clean:
            market_all_tickers = clean
            market_all_tickers_time = now_ts
            append_runtime_event_log("ticker_fetch_done", "티커 목록 갱신 완료", extra={"count": len(clean), "force": force})
        elif not market_all_tickers:
            market_all_tickers = [t for t in DEFAULT_MARKET_TICKERS if t]
            market_all_tickers_time = now_ts
            append_runtime_event_log("ticker_fetch_fallback", "티커 목록이 비어 기본 목록으로 임시 운영", extra={"count": len(market_all_tickers)})
    except Exception as e:
        print(f"[티커 목록 조회 오류] {e}", flush=True)
        if not market_all_tickers:
            market_all_tickers = [t for t in DEFAULT_MARKET_TICKERS if t]
            market_all_tickers_time = now_ts
            append_runtime_event_log("ticker_fetch_fallback", "티커 조회 실패로 기본 목록 사용", extra={"count": len(market_all_tickers), "error": str(e)[:120]})
    return list(market_all_tickers)

def request_market_refresh(force: bool = False, reason: str = "loop") -> bool:
    global market_refresh_in_progress, market_refresh_started_ts, market_refresh_generation
    global last_market_refresh_request_ts, last_market_refresh_reason, last_market_refresh_result
    global last_market_refresh_stuck_log_ts, last_market_refresh_stuck_suppressed
    now_ts = time.time()
    with market_refresh_lock:
        if market_refresh_in_progress:
            age = now_ts - market_refresh_started_ts if market_refresh_started_ts else 0.0
            target_fresh_sec = safe_float(globals().get("MARKET_REFRESH_TARGET_FRESH_SEC", 30), 30)
            stuck_reset_sec = safe_float(globals().get("MARKET_REFRESH_STUCK_RESET_SEC", 45), 45)
            hard_restart_sec = safe_float(globals().get("MARKET_REFRESH_HARD_RESTART_SEC", 60), 60)
            should_log = (now_ts - safe_float(last_market_refresh_stuck_log_ts, 0)) >= MARKET_REFRESH_STUCK_LOG_COOLDOWN_SEC

            if age < target_fresh_sec:
                # 30초 목표 안에서는 기존 갱신을 기다린다. 중복 worker를 만들면 API 호출만 겹친다.
                if force and reason:
                    last_market_refresh_reason = str(reason)
                return False

            if age < stuck_reset_sec:
                # v2.5.161: 30초 목표는 넘겼지만 아직 stuck 확정은 아니다.
                # 후보 생산자는 기존 캐시로 계속 돌고, refresh는 조금 더 기다린다.
                if force and reason:
                    last_market_refresh_reason = str(reason)
                last_market_refresh_result = f"30초 목표 초과 / 기존 갱신 대기 {int(age)}초"
                if should_log:
                    suppressed = int(safe_float(last_market_refresh_stuck_suppressed, 0))
                    suffix = f" / suppressed={suppressed}" if suppressed else ""
                    print(f"[market_refresh] target over / {age:.1f}초 / reason={last_market_refresh_reason}{suffix}", flush=True)
                    append_runtime_event_log(
                        "market_refresh_target_over",
                        f"{age:.1f}초 지연, 45초 전까지 기존 worker 대기",
                        extra={"force": force, "reason": reason, "last_reason": last_market_refresh_reason, "suppressed": suppressed},
                    )
                    last_market_refresh_stuck_log_ts = now_ts
                    last_market_refresh_stuck_suppressed = 0
                else:
                    last_market_refresh_stuck_suppressed = int(safe_float(last_market_refresh_stuck_suppressed, 0)) + 1
                return False

            # 45초 이상이면 초입 선점 봇 기준으로 너무 늦다.
            # 기존 worker 결과는 generation guard로 버리고, 새 worker를 빠르게 시작한다.
            event_tag = "market_refresh_hard_restart" if age >= hard_restart_sec else "market_refresh_stuck_reset"
            event_msg = "하드 복구" if age >= hard_restart_sec else "stuck 복구"
            if should_log:
                suppressed = int(safe_float(last_market_refresh_stuck_suppressed, 0))
                extra = {
                    "force": force,
                    "reason": reason,
                    "last_reason": last_market_refresh_reason,
                    "suppressed": suppressed,
                    "target_fresh_sec": target_fresh_sec,
                    "stuck_reset_sec": stuck_reset_sec,
                    "hard_restart_sec": hard_restart_sec,
                }
                suffix = f" / suppressed={suppressed}" if suppressed else ""
                print(f"[market_refresh] {event_msg} / {age:.1f}초 / reason={last_market_refresh_reason}{suffix}", flush=True)
                append_runtime_event_log(event_tag, f"{age:.1f}초 지연, 새 worker로 교체", extra=extra)
                last_market_refresh_stuck_log_ts = now_ts
                last_market_refresh_stuck_suppressed = 0
            else:
                last_market_refresh_stuck_suppressed = int(safe_float(last_market_refresh_stuck_suppressed, 0)) + 1
            market_refresh_in_progress = False
            market_refresh_started_ts = 0.0
            last_market_refresh_result = f"{event_msg} 재시도 / {int(age)}초 정체"

        market_refresh_generation = int(safe_float(market_refresh_generation, 0)) + 1
        worker_generation = market_refresh_generation
        market_refresh_in_progress = True
        market_refresh_started_ts = now_ts
        last_market_refresh_request_ts = now_ts
        last_market_refresh_reason = str(reason or "loop")
        last_market_refresh_result = "실행 중"
    threading.Thread(target=_market_refresh_worker, kwargs={"force": force, "reason": reason, "generation": worker_generation}, daemon=True, name=f"market_refresh_{reason}").start()
    return True

def _save_fast_scan_state(items, note: str = "", stage: str = "", cache_age=None):
    global latest_fast_scan_items, latest_fast_scan_result_ts, latest_fast_scan_note, latest_fast_scan_stage, latest_fast_scan_cache_age
    with fast_scan_state_lock:
        latest_fast_scan_items = list(items or [])[:FAST_SCAN_RESULT_MAX]
        latest_fast_scan_result_ts = time.time()
        latest_fast_scan_note = str(note or "")
        latest_fast_scan_stage = str(stage or "")
        latest_fast_scan_cache_age = cache_age
    try:
        update_scan_debug_snapshot([dict(x) for x in latest_fast_scan_items], note=latest_fast_scan_note)
    except Exception:
        pass


def _mark_fast_scan_meta(note: str = "", stage: str = "", cache_age=None):
    """마지막 후보 목록은 보존하고, 상태 메모만 갱신한다.

    v2.5.144 핵심:
    - 내부 스캔이 잠깐 시장 데이터를 기다릴 때도 기존 후보 스냅샷을 지우지 않는다.
    - 텔레그램 명령어는 이 마지막 완성 스냅샷을 보여주는 소비자 역할만 한다.
    """
    global latest_fast_scan_note, latest_fast_scan_stage, latest_fast_scan_cache_age
    with fast_scan_state_lock:
        if note:
            latest_fast_scan_note = str(note or "")
        if stage:
            latest_fast_scan_stage = str(stage or "")
        latest_fast_scan_cache_age = cache_age
    try:
        update_scan_debug_snapshot([dict(x) for x in latest_fast_scan_items], note=latest_fast_scan_note)
    except Exception:
        pass


def get_fast_scan_state(now_ts: float = None) -> dict:
    now_ts = safe_float(now_ts, time.time())
    with fast_scan_state_lock:
        age_sec = int(now_ts - latest_fast_scan_result_ts) if latest_fast_scan_result_ts else None
        cache_age = latest_fast_scan_cache_age
        is_stale = bool(age_sec is not None and age_sec >= FAST_SCAN_STATE_STALE_SEC)
        # v2.5.144: 표시자는 마지막 완성 스냅샷을 소비만 한다.
        # 20~40초 됐다고 후보를 바로 지우면, 사용자는 "스캔이 멈춘 것"처럼 보게 된다.
        # 너무 오래된 경우만 숨기고, 그 전까지는 나이를 명확히 보여준다.
        # v2.5.150: 후보 계산 시간이 최근이어도 시장 데이터가 오래됐으면
        # 그 후보는 실전용 최신 후보로 보여주면 안 된다.
        # 마지막 후보는 내부에 보존하되, 표시자는 시장 데이터 나이 기준으로 숨긴다.
        hide_candidates = bool(
            (cache_age is not None and cache_age >= FAST_SCAN_DISPLAY_HIDE_SEC)
            or (age_sec is not None and age_sec >= FAST_SCAN_CONSUMER_HARD_HIDE_SEC)
            or ((not latest_fast_scan_items) and cache_age is not None and cache_age >= FAST_SCAN_DISPLAY_HIDE_SEC)
        )
        return {
            "items": list(latest_fast_scan_items),
            "age_sec": age_sec,
            "note": str(latest_fast_scan_note or ""),
            "stage": str(latest_fast_scan_stage or ""),
            "cache_age": cache_age,
            "is_stale": is_stale,
            "hide_candidates": hide_candidates,
        }


def should_hide_stale_fast_scan_candidates(now_ts: float = None) -> bool:
    state = get_fast_scan_state(now_ts)
    return bool(state.get("hide_candidates", False))


def fast_scan_background_refresh_loop():
    global last_fast_scan_background_refresh_ts, last_fast_scan_stale_refresh_request_ts
    while True:
        time.sleep(FAST_SCAN_BACKGROUND_REFRESH_SEC)
        try:
            now_ts = time.time()
            cache = shared_market_cache if isinstance(shared_market_cache, dict) else {}
            cache_age = int(now_ts - shared_market_cache_time) if shared_market_cache_time else None
            fast = get_fast_scan_state(now_ts)
            cache_ready = bool(cache) and (cache_age is None or cache_age < FAST_SCAN_BUILD_CACHE_MAX_AGE_SEC)
            if cache_ready:
                try:
                    cache = enrich_cache_with_light_snapshots(cache)
                    cache = inject_realtime_snapshot_rows_into_cache(cache, limit=REALTIME_RANK_INJECT_LIMIT)
                except Exception:
                    pass
                need_refresh = (
                    fast.get("age_sec") is None
                    or safe_float(fast.get("age_sec"), 0) >= FAST_SCAN_BACKGROUND_FORCE_REFRESH_SEC
                    or fast.get("stage") in {"scan_watchlist_empty", "scan_watchlist_empty_done"}
                    or safe_float(fast.get("cache_age"), 999999) > max(safe_float(cache_age, 0), 0)
                )
                if need_refresh and (now_ts - last_fast_scan_background_refresh_ts) >= FAST_SCAN_BACKGROUND_REFRESH_SEC:
                    items = build_fast_scan_candidates_from_cache(cache, limit=FAST_SCAN_RESULT_MAX)
                    _save_fast_scan_state(items, note='빠른 후보 백그라운드 갱신', stage='scan_watchlist_fast', cache_age=cache_age)
                    last_fast_scan_background_refresh_ts = now_ts
            else:
                if (now_ts - last_fast_scan_stale_refresh_request_ts) >= FAST_SCAN_STALE_REFRESH_COOLDOWN_SEC:
                    stale_force = bool(cache_age is None or safe_float(cache_age, 0) >= SCAN_CACHE_HARD_RESET_SEC or not market_all_tickers)
                    request_market_refresh(force=stale_force, reason='fast_scan_bg_stale')
                    last_fast_scan_stale_refresh_request_ts = now_ts
                if fast.get("items"):
                    _mark_fast_scan_meta(note='시장 데이터 다시 받는 중 / 마지막 완성 후보 유지', stage='scan_wait_market', cache_age=cache_age)
                elif fast.get("age_sec") is None or safe_float(fast.get("age_sec"), 0) >= FAST_SCAN_BACKGROUND_FORCE_REFRESH_SEC:
                    _save_fast_scan_state([], note='시장 데이터 다시 받는 중', stage='scan_watchlist_empty', cache_age=cache_age)
        except Exception as e:
            print(f"[fast_scan_background 오류] {e}", flush=True)


def format_fast_scan_high_gap_text(gap_pct: float) -> str:
    gap_pct = safe_float(gap_pct, 999)
    if gap_pct >= 900:
        return "고점 거리 확인 안 됨"
    if gap_pct >= 0:
        return f"최근30분 고점까지 {gap_pct:.2f}% 남음"
    return f"최근30분 고점 {abs(gap_pct):.2f}% 돌파"

