def build_fast_scan_one_liner(primary_reason: str, from_low: float, below_high: float, grade: str = "", bucket: str = "", item: dict = None) -> str:
    item = item if isinstance(item, dict) else {}
    label = get_fast_scan_label_text(primary_reason)
    gap_text = format_fast_scan_high_gap_text(below_high)
    recovery_quality = safe_float(item.get("recovery_quality_score", 0), 0)
    low_zone_stay = int(safe_float(item.get("low_zone_stay_bars", 0), 0))
    low_reclaim = int(safe_float(item.get("low_zone_reclaim_count", 0), 0))
    turnover_persist = safe_float(item.get("turnover_persistence_score", 0), 0)
    chg_5 = safe_float(item.get("change_5", 0), 0)
    soft_recovery = bool(
        below_high >= 1.00
        and from_low <= 1.60
        and (
            recovery_quality >= 1.10
            or (low_zone_stay >= 2 or low_reclaim >= 1)
            or turnover_persist >= 0.90
            or chg_5 >= 0.18
        )
    )
    if str(bucket or "") == "discard":
        if soft_recovery and str(primary_reason or "") in {"막 뜨기 직전 후보", "초입/회복 확인 후보", "재출발 확인 후보"}:
            return f"{label}. 실전 진입감은 약하지만 흐름은 한 번 더 볼 자리 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
        return f"지금 사기엔 별로. 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "실시간 폭발 초입 후보":
        return f"{label}. 3~30분 가속이 붙는 중. 다만 지속성 확인은 필요 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "1시간 급등 초입 후보":
        return f"{label}. 1시간 급등판에 뜨기 전 중간 가속 감시 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "순위권 정밀검토 후보":
        return f"{label}. 빗썸 순위권처럼 강하게 보여서 정밀분석 대기로 올림. 바로 매수 신호는 아님 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "실시간 급등 초입":
        return f"{label}. 거래량 붙는 초입이라 빠르게 볼 자리 / {gap_text}"
    if str(primary_reason or "") == "초입 가능 후보":
        return f"{label}. 힘 붙기 시작하는지 볼 자리 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "재출발 확인 후보":
        return f"{label}. 다시 사는지 확인할 자리 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "막 뜨기 직전 후보":
        return f"{label}. 아직 뚫은 건 아니고, 힘이 이어지는지 먼저 확인할 자리 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "재돌파 대기 후보":
        return f"{label}. 지금 바로 추격은 말고, 고점 다시 뚫는지 확인할 자리 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "반짝 확인 후보":
        return f"{label}. 거래량은 튀었지만 고점 바로 앞이라 알림은 보류 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "초저가 잡음형":
        return f"초저가 틱 잡음형. 퍼센트가 과장돼 실전 후보에서 제외 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    if str(primary_reason or "") == "초입/회복 확인 후보":
        if soft_recovery:
            return f"{label}. 되살아나는 흔적은 있지만 지금 바로 살 자린 아님 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
        return f"{label}. 흐름은 살아 있지만 실전 진입감은 더 확인 필요 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"
    return f"지금은 구경만 / 30분 저점대비 {from_low:+.2f}% / {gap_text}"


def compute_fast_scan_turnover_metrics(df1, price: float = 0.0) -> dict:
    price = safe_float(price, 0)
    if df1 is None or len(df1) < 1:
        return {"turnover_1m": 0.0, "turnover_3m": 0.0, "turnover_5m": 0.0}
    try:
        closes = df1["close"].astype(float)
        vols = df1["volume"].astype(float)
        values = closes * vols
        if price > 0 and len(values) >= 1:
            values = values.copy()
            values.iloc[-1] = float(vols.iloc[-1]) * price
        return {
            "turnover_1m": float(values.tail(1).sum()),
            "turnover_3m": float(values.tail(3).sum()),
            "turnover_5m": float(values.tail(5).sum()),
        }
    except Exception:
        return {"turnover_1m": 0.0, "turnover_3m": 0.0, "turnover_5m": 0.0}


def fast_scan_turnover_gate(item: dict, level: str = "watch") -> bool:
    level = str(level or "watch").strip().lower()
    turnover_15m = safe_float(item.get("turnover", 0), 0)
    turnover_3m = safe_float(item.get("turnover_3m", 0), 0)
    turnover_5m = safe_float(item.get("turnover_5m", 0), 0)
    turnover_rank = int(safe_float(item.get("turnover_rank", 999), 999))
    if level == "strong":
        if turnover_15m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_15M:
            return True
        if turnover_3m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_STRONG_ALERT_MIN_TURNOVER_5M:
            return True
        return turnover_rank > 0 and turnover_rank <= 18 and turnover_3m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_3M
    if level == "user":
        if turnover_15m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_15M:
            return True
        if turnover_3m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_USER_ALERT_MIN_TURNOVER_5M:
            return True
        return turnover_rank > 0 and turnover_rank <= 25 and turnover_3m >= FAST_SCAN_WATCH_MIN_TURNOVER_3M and turnover_5m >= FAST_SCAN_WATCH_MIN_TURNOVER_5M
    if turnover_15m >= FAST_SCAN_WATCH_MIN_TURNOVER_15M:
        return True
    if turnover_3m >= FAST_SCAN_WATCH_MIN_TURNOVER_3M or turnover_5m >= FAST_SCAN_WATCH_MIN_TURNOVER_5M:
        return True
    return turnover_rank > 0 and turnover_rank <= 35 and turnover_5m >= max(5000000, FAST_SCAN_WATCH_MIN_TURNOVER_3M * 0.8)


def get_fast_scan_early_quality(item: dict) -> str:
    primary = str(item.get("primary_reason", "") or "")
    change_5 = safe_float(item.get("change_5", 0), 0)
    change_3 = safe_float(item.get("change_3", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    chart_gap = safe_float(item.get("chart_gap_pct", below_high), below_high)
    chart_rise = safe_float(item.get("chart_rise_pct", from_low), from_low)
    zone_ratio = safe_float(item.get("chart_zone_ratio", -1), -1)
    ctx = item.get("alert_chart_context", {}) if isinstance(item.get("alert_chart_context"), dict) else {}
    state_code = str(ctx.get("chart_state_code", "") or "")
    turnover_ok_user = fast_scan_turnover_gate(item, level="user")
    turnover_ok_strong = fast_scan_turnover_gate(item, level="strong")

    if primary == "실시간 급등 초입":
        if (
            change_5 >= 0.95 and change_3 >= 0.28 and vol_ratio >= 4.0 and leader >= 1.35
            and from_low <= 2.20 and below_high >= 1.00 and chart_gap >= 1.00
            and chart_rise <= 2.70 and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}
            and turnover_ok_strong
        ):
            return "strong"
        if (
            change_5 >= 0.70 and vol_ratio >= 2.40 and leader >= 0.95 and below_high >= 0.85
            and chart_gap >= 0.85 and chart_rise <= 3.20 and state_code not in {"FADE_AFTER_SPIKE", "EXTENDED"}
            and turnover_ok_user
        ):
            return "user"
        return "watch"

    if primary == "초입 가능 후보":
        if (
            change_5 >= 0.55 and change_3 >= 0.10 and vol_ratio >= 2.20 and leader >= 0.95
            and from_low <= 1.90 and below_high >= 1.15 and chart_gap >= 1.15
            and chart_rise <= 2.50 and zone_ratio <= 0.72
            and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}
            and turnover_ok_user
        ):
            return "user"
        if (
            change_5 >= 0.35 and vol_ratio >= 1.45 and leader >= 0.70 and below_high >= 0.90
            and chart_gap >= 0.90 and chart_rise <= 3.30 and state_code not in {"FADE_AFTER_SPIKE", "EXTENDED"}
            and fast_scan_turnover_gate(item, level="watch")
        ):
            return "watch"
        return "discard"

    if primary == "재출발 확인 후보":
        if (
            change_5 >= 0.85 and vol_ratio >= 3.00 and leader >= 1.05 and from_low >= 1.00
            and below_high >= 2.05 and chart_gap >= 1.60 and chart_rise <= 2.90
            and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}
            and turnover_ok_user
        ):
            return "user"
        if (
            change_5 >= 0.25 and vol_ratio >= 1.25 and leader >= 0.55 and from_low >= 0.35
            and below_high >= 0.90 and fast_scan_turnover_gate(item, level="watch")
        ):
            return "watch"
        return "discard"

    return "watch" if fast_scan_turnover_gate(item, level="watch") else "discard"


def refine_fast_scan_item_with_chart(item: dict, df1):
    try:
        if not isinstance(item, dict) or df1 is None or len(df1) < 12:
            return item
        price = safe_float(item.get("price", 0), 0)
        apply_chart_position_profile(item, df1, lookback=CHART_POS_LOOKBACK_1M)
        item.update(compute_rebreakout_structure_context(str(item.get("ticker", "") or "").upper().strip(), price, df1=df1))
        item["alert_chart_context"] = compute_alert_chart_context_from_df(df1, df4h=None, current_price=price)
        ctx = item.get("alert_chart_context", {}) if isinstance(item.get("alert_chart_context"), dict) else {}
        # alert_chart_context 안의 고점 직전 준비도 값을 display item에도 올려 둔다.
        # 이후 보수화/문구/승격 판단이 같은 값을 보도록 한다.
        for _k in (
            "prebreakout_ready_score", "prebreakout_label",
            "prebreakout_hold_near_high_bars", "prebreakout_pullback_depth_pct",
            "prebreakout_retest_gap_bars", "prebreakout_volume_reaccel_score",
            "chart_lifecycle_code", "chart_lifecycle_label", "chart_lifecycle_warning",
            "chart_lifecycle_early_score", "chart_lifecycle_restart_score", "chart_lifecycle_late_score",
            "chart_lifecycle_good_early", "chart_lifecycle_good_restart", "chart_lifecycle_late_flag",
            "chart_lifecycle_gap_pct", "chart_lifecycle_from_low_pct", "chart_lifecycle_zone_ratio",
            "chart_lifecycle_bars_since_high", "chart_lifecycle_bars_since_low",
            "chart_lifecycle_close_strength_3", "chart_lifecycle_wick_pressure_3",
            "chart_lifecycle_vol_reaccel", "chart_lifecycle_higher_low",
            "current_candle_code", "current_candle_label", "current_candle_warning",
            "current_candle_live_score", "current_candle_reclaim_score", "current_candle_pressure_score",
            "current_candle_follow_score", "current_candle_quality_grade",
            "current_candle_change_pct", "current_candle_prev_change_pct", "current_candle_body_ratio", "current_candle_body_pct",
            "current_candle_range_pct", "current_candle_close_pos_ratio",
            "current_candle_upper_wick_pct", "current_candle_lower_wick_pct", "current_candle_volume_ratio",
            "current_candle_recent_close_strength", "current_candle_recent_upper_wick_pct", "current_candle_recent_lower_wick_pct", "current_candle_recent_body_ratio",
            "current_candle_bullish", "current_candle_upper_dump", "current_candle_lower_reclaim", "current_candle_live_ok",
            "current_candle_soft_pressure", "current_candle_hard_pressure", "current_candle_micro_noise",
        ):
            if _k in ctx:
                item[_k] = ctx.get(_k)
        state_code = str(ctx.get("chart_state_code", "") or "")
        lifecycle_code = str(item.get("chart_lifecycle_code", ctx.get("chart_lifecycle_code", "")) or "")
        lifecycle_late_score = safe_float(item.get("chart_lifecycle_late_score", ctx.get("chart_lifecycle_late_score", 0)), 0)
        lifecycle_good_early = bool(item.get("chart_lifecycle_good_early", ctx.get("chart_lifecycle_good_early", False)))
        lifecycle_good_restart = bool(item.get("chart_lifecycle_good_restart", ctx.get("chart_lifecycle_good_restart", False)))
        current_candle_code = str(item.get("current_candle_code", ctx.get("current_candle_code", "")) or "")
        current_candle_pressure = safe_float(item.get("current_candle_pressure_score", ctx.get("current_candle_pressure_score", 0)), 0)
        current_candle_follow = safe_float(item.get("current_candle_follow_score", ctx.get("current_candle_follow_score", 0)), 0)
        current_candle_live_ok = bool(item.get("current_candle_live_ok", ctx.get("current_candle_live_ok", False)))
        current_candle_lower_reclaim = bool(item.get("current_candle_lower_reclaim", ctx.get("current_candle_lower_reclaim", False)))
        current_candle_soft_pressure = bool(item.get("current_candle_soft_pressure", ctx.get("current_candle_soft_pressure", False)))
        current_candle_hard_pressure = bool(item.get("current_candle_hard_pressure", ctx.get("current_candle_hard_pressure", False)))
        current_candle_micro_noise = bool(item.get("current_candle_micro_noise", ctx.get("current_candle_micro_noise", False)))
        chart_gap = safe_float(item.get("chart_gap_pct", item.get("below_high", 999)), 999)
        chart_rise = safe_float(item.get("chart_rise_pct", item.get("from_low", 0)), 0)
        zone_ratio = safe_float(item.get("chart_zone_ratio", -1), -1)
        vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
        leader_score = safe_float(item.get("leader_score", 0), 0)
        change_5 = safe_float(item.get("change_5", 0), 0)
        from_low = safe_float(item.get("from_low", 0), 0)
        below_high = safe_float(item.get("below_high", 999), 999)
        section = str(item.get("section", "") or "")
        primary = str(item.get("primary_reason", "") or "")
        reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
        def add_reason(text: str):
            if text and text not in reasons:
                reasons.append(text)
        if lifecycle_code == "LATE_CHASE":
            add_reason("차트 위치상 이미 늦은 추격권")
            if section == "strong":
                section = "watch"
            if lifecycle_late_score >= 2.60 and primary in {"실시간 급등 초입", "초입 가능 후보", "막 뜨기 직전 후보"}:
                section = "weak"
                primary = "지금은 구경만"
        elif lifecycle_good_restart:
            add_reason("재출발 구조가 살아 있음")
            if section == "weak" and primary in {"재출발 확인 후보", "초입/회복 확인 후보"}:
                section = "watch"
        elif lifecycle_good_early:
            add_reason("초입 구조가 살아 있음")
            if section == "weak" and primary in {"실시간 급등 초입", "초입 가능 후보"} and fast_scan_turnover_gate(item, level="watch"):
                section = "watch"
        if state_code in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
            add_reason("차트 모양이 아직 별로")
            if section == "strong":
                section = "watch"
                if primary == "실시간 급등 초입":
                    primary = "초입/회복 확인 후보"
        if current_candle_hard_pressure:
            add_reason("현재봉이 강하게 밀려 추격 주의")
            if section == "strong":
                section = "watch"
                if primary in {"실시간 급등 초입", "초입 가능 후보"}:
                    primary = "초입/회복 확인 후보"
            elif section == "watch" and lifecycle_code == "LATE_CHASE":
                section = "weak"
                primary = "지금은 구경만"
        elif current_candle_soft_pressure:
            add_reason("현재봉이 약간 밀려 한 번 더 확인")
            # v2.5.225: 소프트 밀림만으로는 후보를 죽이지 않는다. 이미 고점권인 경우만 한 단계 보수화한다.
            if section == "strong" and chart_gap <= 0.75 and chart_rise >= 1.45:
                section = "watch"
                if primary in {"실시간 급등 초입", "초입 가능 후보"}:
                    primary = "초입/회복 확인 후보"
        elif current_candle_lower_reclaim and section == "weak" and lifecycle_good_restart:
            add_reason("현재봉 아랫꼬리 회복으로 재출발 여지 있음")
            section = "watch"
        elif current_candle_live_ok and section == "weak" and lifecycle_good_early and fast_scan_turnover_gate(item, level="watch"):
            add_reason("현재봉이 살아나 초입 확인 가치 있음")
            section = "watch"
        if current_candle_micro_noise and not fast_scan_turnover_gate(item, level="watch"):
            add_reason("현재봉 움직임이 작고 실제 돈도 약함")
        if current_candle_follow >= CURRENT_CANDLE_V2_FOLLOW_GOOD_SCORE and section == "weak" and (lifecycle_good_early or lifecycle_good_restart) and fast_scan_turnover_gate(item, level="watch"):
            add_reason("현재봉 따라붙기 점수가 좋아 내부감시 유지")
            section = "watch"
        if chart_gap <= 1.05 and chart_rise >= 0.95:
            add_reason("고점이 가까워서 늦을 수 있음")
            if section == "strong":
                section = "watch"
        if zone_ratio >= 0.82 and chart_gap <= 1.45 and chart_rise >= 0.90:
            add_reason("위쪽 구간이라 더 확인 필요")
            if section == "strong":
                section = "watch"
        if not fast_scan_turnover_gate(item, level="watch"):
            add_reason("실제 거래대금이 아직 작음")
            if section == "strong":
                section = "watch"
        if bool(item.get("box_stall_flag", False)):
            add_reason("박스 횡보라서 더 확인 필요")
            if section == "strong":
                section = "watch"
            elif section == "watch" and below_high <= 0.90 and change_5 < 0.20:
                section = "weak"
                primary = "지금은 구경만"
        early_quality = get_fast_scan_early_quality(item)
        if primary == "실시간 급등 초입":
            if early_quality == "watch":
                add_reason("실시간 강세 초입으로 보기엔 힘이 덜 붙음")
                section = "watch"
            elif early_quality == "discard":
                add_reason("실시간 강세 초입으로 보기엔 아직 애매함")
                section = "weak"
                primary = "지금은 구경만"
        elif primary == "초입 가능 후보":
            if early_quality == "watch":
                add_reason("막 힘 붙는 자리로 보기엔 아직 애매함")
                section = "watch"
            elif early_quality == "discard":
                add_reason("초반 선점형으로 보기엔 아직 너무 약함")
                section = "weak"
                primary = "지금은 구경만"
        elif primary == "막 뜨기 직전 후보":
            if state_code in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
                add_reason("막 뜨기 직전형으로 보기엔 이미 한 번 쏜 뒤 식는 자리")
                section = "weak"
                primary = "지금은 구경만"
            elif below_high < 0.75:
                add_reason("막 뜨기 직전형이라기엔 바로 위 고점이 너무 가까움")
                section = "watch"
            elif from_low > 2.10:
                add_reason("막 뜨기 직전형이라기엔 이미 너무 올라와 있음")
                section = "watch"
        if primary == "재출발 확인 후보":
            strong_restart = (
                change_5 >= 0.85 and vol_ratio >= 3.00 and leader_score >= 1.05 and from_low >= 1.00 and below_high >= 2.05 and chart_gap >= 1.60 and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"} and fast_scan_turnover_gate(item, level="user")
            )
            if not strong_restart:
                add_reason("재출발 힘이 아직 약함")
                section = "watch"

        # ETH형: 거래량 재가속만 보고 고점 전 준비를 과대평가하지 않도록 보수화.
        item = _dampen_prebreakout_if_thrust_weak(item)

        # ENJ형: 이미 크게 튄 뒤 고점권에서 흔드는 후보는 거래량 부족이 아니라 늦은 변동성으로 설명한다.
        if _is_late_high_volatility_item(item):
            item["late_high_volatility_block"] = True
            section = "weak"
            primary = "지금은 구경만"
            reasons = [r for r in reasons if str(r) != "거래량이 아직 약함"]
            add_reason("거래량은 있지만 이미 늦은 고점권 흔들림")
            add_reason("추격 진입 위험이 큼")

        # CVC형: 고점은 가깝지만 저점 방어/돈 유지/재돌파 힘이 같이 좋으면 버리지 않고 내부 감시로 남김.
        if _is_near_high_rebreakout_watch(item):
            item["near_high_rebreakout_watch"] = True
            section = "watch"
            primary = "재돌파 대기 후보"
            reasons = [r for r in reasons if str(r) not in {"고점이 가까워서 늦을 수 있음", "고점이 너무 가까움"}]
            add_reason("재돌파 확인 전이라 알림은 보류")
            add_reason("고점은 가깝지만 구조가 좋아 내부 감시")

        item["section"] = section
        item["reasons"] = reasons[:5]
        item["primary_reason"] = primary
    except Exception:
        return item
    return item


def _hot_ignition_score(item: dict) -> float:
    """v2.5.154: 1시간 급등으로 보이기 전에 3~30분 가속을 잡는 점수."""
    item = item if isinstance(item, dict) else {}
    if not HOT_IGNITION_ON:
        return 0.0
    if is_watch_excluded_ticker(str(item.get("ticker", ""))):
        return 0.0
    if bool(item.get("ultra_low_tick_noise_block", False)) or bool(item.get("flash_low_liquidity_near_high_block", False)):
        return 0.0
    if _is_late_high_volatility_item(item):
        return 0.0
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    chg60 = safe_float(item.get("change_60", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    t5 = safe_float(item.get("turnover_5m", 0), 0)
    t15 = safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0)
    if HOT_IGNITION_BLOCK_IF_24H_LIKE_SPIKE and (chg30 >= 14.0 or chg60 >= 22.0 or from_low >= 12.0):
        return 0.0
    if t5 < 8_000_000 and t15 < 25_000_000:
        return 0.0
    if vol < 1.20 and leader < 0.55:
        return 0.0
    live_accel = max(chg3, chg5)
    mid_accel = max(chg15, chg30)
    if live_accel < 0.35 and mid_accel < 1.25:
        return 0.0
    score = 0.0
    score += max(chg3, 0) * 1.25
    score += max(chg5, 0) * 1.05
    score += max(chg15, 0) * 0.62
    score += max(chg30, 0) * 0.45
    score += max(vol - 1.0, 0) * 1.35
    score += leader * 1.25
    score += min(max(t5, 0) / 20_000_000, 2.5) * 0.70
    if 0 <= below_high <= 0.18:
        score += 0.60 if (chg3 >= 0.75 or chg5 >= 1.10) else -0.90
    elif below_high >= 0.55:
        score += min(below_high, 3.0) * 0.25
    if from_low > HOT_IGNITION_MAX_FROM_LOW_ALERT:
        score -= (from_low - HOT_IGNITION_MAX_FROM_LOW_ALERT) * 0.45
    return round(max(score, 0.0), 2)


def _is_hot_ignition_watch(item: dict) -> bool:
    score = _hot_ignition_score(item)
    if score <= 0:
        return False
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    t5 = safe_float(item.get("turnover_5m", 0), 0)
    t15 = safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0)
    return bool(
        score >= 5.2
        and (chg3 >= HOT_IGNITION_MIN_CHANGE3 or chg5 >= HOT_IGNITION_MIN_CHANGE5 or chg15 >= HOT_IGNITION_MIN_CHANGE15 or chg30 >= HOT_IGNITION_MIN_CHANGE30)
        and (vol >= HOT_IGNITION_MIN_VOL_RATIO or leader >= HOT_IGNITION_MIN_LEADER)
        and (t5 >= HOT_IGNITION_MIN_TURNOVER_5M or t15 >= HOT_IGNITION_MIN_TURNOVER_15M)
    )


def _is_hot_ignition_user_alert(item: dict) -> bool:
    if not _is_hot_ignition_watch(item):
        return False
    score = _hot_ignition_score(item)
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    chg60 = safe_float(item.get("change_60", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    t5 = safe_float(item.get("turnover_5m", 0), 0)
    if get_user_alert_momentum_decay_reason(item, section="strong"):
        return False
    if from_low > HOT_IGNITION_MAX_FROM_LOW_ALERT or chg30 > HOT_IGNITION_MAX_30M_ALERT or chg60 > HOT_IGNITION_MAX_60M_ALERT:
        return False
    # v2.5.176: COS형 보정. 15/30/60분은 좋아 보여도 현재 3~5분 흐름과 거래량이 꺾이면 사용자 알림이 아니라 내부 감시로만 둔다.
    if chg5 < 0.05 and chg3 < 0.25:
        return False
    if chg5 < -0.20:
        return False
    if vol < 0.85 and leader < 1.40:
        return False
    if 0 <= below_high <= 0.15 and not (chg3 >= 0.85 or chg5 >= 1.20):
        return False
    return bool(
        score >= 7.0
        and (chg3 >= 0.85 or chg5 >= 1.20 or chg15 >= 2.40 or chg30 >= 3.50)
        and (vol >= 2.15 or leader >= 1.05)
        and t5 >= HOT_IGNITION_USER_MIN_TURNOVER_5M
    )


def _hourly_momentum_score(item: dict) -> float:
    """v2.5.155: 1시간 급등 순위에 뜨기 전 중간 가속 후보를 잡는 점수."""
    item = item if isinstance(item, dict) else {}
    if is_watch_excluded_ticker(str(item.get("ticker", ""))):
        return 0.0
    if bool(item.get("ultra_low_tick_noise_block", False)) or bool(item.get("flash_low_liquidity_near_high_block", False)):
        return 0.0
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    chg60 = safe_float(item.get("change_60", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    vol = safe_float(item.get("vol_ratio", item.get("vol_ratio_1m", 0)), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    t5 = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0)
    t15 = safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0)
    # 이미 1시간 급등판 상단에 오른 뒤 추격하는 후보는 여기서 알림용으로 보지 않는다.
    if chg60 >= 24.0 or chg30 >= 16.0 or from_low >= 14.0:
        return 0.0
    if max(chg15, chg30, chg60) < 1.35 and max(chg3, chg5) < 0.55:
        return 0.0
    if t5 < 8_000_000 and t15 < 35_000_000:
        return 0.0
    score = 0.0
    score += max(chg60, 0) * 0.55
    score += max(chg30, 0) * 0.82
    score += max(chg15, 0) * 1.00
    score += max(chg5, 0) * 1.18
    score += max(chg3, 0) * 1.10
    score += max(vol - 1.0, 0) * 1.05
    score += leader * 1.20
    score += min(max(t5, 0) / 25_000_000, 2.6) * 0.65
    # 고점까지 공간이 조금은 있어야 '뜨기 전' 감시 의미가 있다.
    if 0 <= below_high < 0.20:
        score -= 1.1
    elif below_high < 900:
        score += min(below_high, 4.0) * 0.18
    if 0.20 <= from_low <= 7.5:
        score += 0.55
    elif from_low > 9.5:
        score -= (from_low - 9.5) * 0.35
    return round(max(score, 0.0), 2)


def _is_hourly_momentum_watch(item: dict) -> bool:
    item = item if isinstance(item, dict) else {}
    score = _hourly_momentum_score(item)
    if score < 5.6:
        return False
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    chg60 = safe_float(item.get("change_60", 0), 0)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    t5 = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0)
    t15 = safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0)
    return bool(
        (chg60 >= 2.2 or chg30 >= 1.45 or chg15 >= 1.05 or (chg5 >= 0.75 and chg3 >= 0.35))
        and (vol >= 1.35 or leader >= 0.75)
        and (t5 >= 12_000_000 or t15 >= 45_000_000)
    )


def _is_hourly_momentum_user_alert(item: dict) -> bool:
    if not _is_hourly_momentum_watch(item):
        return False
    score = _hourly_momentum_score(item)
    chg3 = safe_float(item.get("change_3", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg15 = safe_float(item.get("change_15", 0), 0)
    chg30 = safe_float(item.get("change_30", 0), 0)
    chg60 = safe_float(item.get("change_60", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    t5 = safe_float(item.get("turnover_5m", 0), 0)
    if get_user_alert_momentum_decay_reason(item, section="strong"):
        return False
    if chg60 > 16.0 or chg30 > 11.0 or from_low > 9.0:
        return False
    # v2.5.176: 1시간 급등 초입형도 현재 3~5분 재가속이 죽어 있으면 사용자 알림 보류.
    if chg5 < 0.05 and chg3 < 0.25:
        return False
    if chg5 < -0.20:
        return False
    if 0 <= below_high < 0.28 and not (chg5 >= 1.10 or chg3 >= 0.80):
        return False
    return bool(
        score >= 7.2
        and (chg5 >= 0.95 or chg15 >= 1.75 or chg30 >= 2.50 or chg60 >= 3.60)
        and t5 >= 22_000_000
    )


def build_hourly_momentum_watch_rows(cache: dict, limit: int = 8):
    """review_dump용 1시간 급등 감시판. 빗썸 화면 직접 연동이 아니라 내부 캐시 기준이다."""
    rows = []
    if not isinstance(cache, dict):
        return rows
    for ticker, data in cache.items():
        if not isinstance(data, dict):
            continue
        item = dict(data)
        item.setdefault("ticker", ticker)
        score = _hourly_momentum_score(item)
        chg60 = safe_float(item.get("change_60", 0), 0)
        chg30 = safe_float(item.get("change_30", 0), 0)
        chg15 = safe_float(item.get("change_15", 0), 0)
        chg5 = safe_float(item.get("change_5", 0), 0)
        # 점수는 낮아도 실제 60분/30분 상승률 상위는 감시판에 보여준다.
        if score <= 0 and max(chg60, chg30, chg15, chg5) < 1.2:
            continue
        rows.append((ticker, item, score))
    rows.sort(key=lambda x: (x[2], safe_float(x[1].get("change_60", 0), 0), safe_float(x[1].get("change_30", 0), 0), safe_float(x[1].get("turnover_5m", x[1].get("turnover", 0)), 0)), reverse=True)
    return rows[:max(1, int(limit))]


def format_hourly_momentum_watch_report(cache: dict, limit: int = 8, detail_index: dict = None) -> str:
    rows = build_hourly_momentum_watch_rows(cache, limit=limit)
    detail_index = detail_index if isinstance(detail_index, dict) else build_review_dump_rich_detail_index()
    lines = ["🚀 [1시간 급등 감시판 상세]", "- 참고: 빗썸 실시간 순위 직접값이 아니라 봇 내부 캐시 기준이야", "- 원칙: 급등 감시판도 최근 역추적/내부감시 정밀 수치가 있으면 같은 티커에 붙여 보여줌"]
    if not rows:
        lines.append("- 아직 1시간 급등 감시 후보가 없어")
        return "\n".join(lines)
    for idx, (ticker, item, score) in enumerate(rows, start=1):
        bucket = "알림후보" if _is_hourly_momentum_user_alert(item) else "감시" if _is_hourly_momentum_watch(item) else "기록"
        item = dict(item)
        item.setdefault('ticker', str(ticker).upper())
        item.setdefault('alert_bucket', 'user_alert' if bucket == '알림후보' else ('internal_watch' if bucket == '감시' else 'record'))
        item.setdefault('label_text', bucket)
        rich = detail_index.get(str(ticker).upper()) if isinstance(detail_index, dict) else None
        if rich and _review_dump_detail_score(rich) > _review_dump_detail_score(item):
            item = _review_dump_merge_latest_with_rich(item, rich)
        lines.append("")
        lines.append(
            f"{idx}. {str(ticker).upper()} / {bucket} / 점수 {score:.2f} / "
            f"5분 {safe_float(item.get('change_5',0)):+.2f}% / 15분 {safe_float(item.get('change_15',0)):+.2f}% / "
            f"30분 {safe_float(item.get('change_30',0)):+.2f}% / 60분 {safe_float(item.get('change_60',0)):+.2f}% / "
            f"거래대금 {format_money_or_tiny(item.get('turnover_5m', item.get('turnover',0)))}"
        )
        lines.append(format_review_dump_saved_chart_detail(item, idx=idx, group_label=f"1시간 급등 감시판/{bucket}"))
    return "\n".join(lines)

def classify_fast_scan_alert_section(change_5: float, change_3: float, vol_ratio: float, leader_score: float, from_low: float, below_high: float, rsi: float) -> tuple[str, str, list]:
    reasons = []
    primary = "지금은 구경만"
    section = "weak"
    strong_surge = (
        change_5 >= FAST_SCAN_SURGE_CHANGE5
        and vol_ratio >= FAST_SCAN_SURGE_VOL
        and leader_score >= FAST_SCAN_SURGE_LEADER
        and below_high >= 0.90
        and from_low <= 2.60
        and rsi < 82
    )
    strong_early = (
        change_5 >= FAST_SCAN_STRONG_CHANGE5
        and change_3 >= FAST_SCAN_ALERT_MIN_CHANGE3
        and vol_ratio >= FAST_SCAN_STRONG_VOL
        and leader_score >= FAST_SCAN_STRONG_LEADER
        and below_high >= FAST_SCAN_ALERT_MIN_HIGH_GAP
        and FAST_SCAN_ALERT_MIN_FROM_LOW <= from_low <= FAST_SCAN_ALERT_MAX_FROM_LOW
        and (change_5 + max(change_3, 0)) >= FAST_SCAN_ALERT_MIN_COMBINED
        and rsi < 84
    )
    prelaunch_watch = (
        FAST_SCAN_PRELAUNCH_MIN_CHANGE5 <= change_5 <= FAST_SCAN_PRELAUNCH_MAX_CHANGE5
        and change_3 >= FAST_SCAN_PRELAUNCH_MIN_CHANGE3
        and vol_ratio >= FAST_SCAN_PRELAUNCH_MIN_VOL
        and leader_score >= FAST_SCAN_PRELAUNCH_MIN_LEADER
        and below_high >= FAST_SCAN_PRELAUNCH_MIN_HIGH_GAP
        and FAST_SCAN_PRELAUNCH_MIN_FROM_LOW <= from_low <= FAST_SCAN_PRELAUNCH_MAX_FROM_LOW
        and rsi < 79
    )
    recovery_watch = (
        from_low >= 0.18
        and change_5 >= 0.12
        and vol_ratio >= 1.20
        and leader_score >= 0.45
        and below_high >= 0.75
        and from_low <= 2.80
    )
    if strong_surge:
        section = "strong"
        primary = "실시간 급등 초입"
    elif strong_early:
        section = "strong"
        primary = "초입 가능 후보"
    elif prelaunch_watch:
        section = "watch"
        primary = "막 뜨기 직전 후보"
    elif recovery_watch:
        section = "watch"
        primary = "재출발 확인 후보"
    elif from_low >= 0.10 and vol_ratio >= FAST_SCAN_WATCH_VOL and leader_score >= FAST_SCAN_WATCH_LEADER:
        section = "watch"
        primary = "초입/회복 확인 후보"

    if below_high <= 0.35:
        reasons.append("고점이 너무 가까움")
        if section == "strong":
            section = "watch"
            primary = "초입/회복 확인 후보"
    if from_low > 3.60 and below_high < 1.20:
        reasons.append("이미 많이 올라와서 늦음")
        section = "weak"
        primary = "지금은 구경만"
    if change_5 < FAST_SCAN_WATCH_CHANGE5:
        reasons.append("5분 상승이 아직 약함")
        if section == "strong":
            section = "watch"
    if vol_ratio < 1.15:
        reasons.append("거래량이 아직 약함")
        if section == "strong":
            section = "watch"
    if leader_score < 0.30 and vol_ratio < 1.30:
        reasons.append("시장주목도가 아직 약함")
        if section != "weak":
            section = "watch" if change_5 >= 0.12 else "weak"
    if rsi >= 84 or (change_5 >= 1.90 and vol_ratio < 6.00):
        reasons.append("너무 빠르게 오른 편")
        if section == "strong":
            section = "watch"
    if primary == "막 뜨기 직전 후보" and change_5 <= -0.45:
        reasons.append("5분은 약하지만 막 출발 직전일 수 있어 더 확인 필요")

    ordered = [primary] + [r for r in reasons if r != primary]
    return section, primary, ordered[:4]


def is_restart_low_defense_watch_v226(item: dict) -> bool:
    """v2.5.226: 저점방어/저점높임이 좋은 재출발형은 버리지 말고 내부감시로 살린다.

    이건 알림 조건 완화가 아니라 차트 정교화 2파트다.
    사용자 알림은 여전히 5분/3분 힘과 거래대금 확인이 붙어야 한다.
    """
    if not RESTART_LOW_DEFENSE_WATCH_ON:
        return False
    item = item if isinstance(item, dict) else {}
    try:
        low_score = max(
            safe_float(item.get("low_defense_v2_score", 0), 0),
            safe_float(item.get("low_structure_score_v2", 0), 0),
            safe_float(item.get("low_zone_defense_score", 0), 0),
        )
        rising = safe_float(item.get("low_rising_score_v2", 0), 0)
        turnover_keep = safe_float(item.get("turnover_persistence_score", 0), 0)
        high_gap = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
        from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
        chg5 = safe_float(item.get("change_5", 0), 0)
        chg30 = safe_float(item.get("change_30", 0), 0)
        if bool(item.get("low_dead_stay_flag_v2", False)) or bool(item.get("low_break_weak_reclaim_flag_v2", False)):
            return False
        if high_gap < RESTART_LOW_DEFENSE_MIN_HIGH_GAP:
            return False
        if from_low > 2.90:
            return False
        if chg5 < -0.18 and chg30 < -0.35:
            return False
        return bool(
            low_score >= RESTART_LOW_DEFENSE_MIN_SCORE
            and rising >= RESTART_LOW_RISING_MIN_SCORE
            and turnover_keep >= RESTART_LOW_TURNOVER_KEEP_MIN
        )
    except Exception:
        return False


def get_fast_scan_user_alert_flow_block_reason_v226(item: dict, section: str = "", primary_reason: str = "") -> str:
    """v2.5.226: CRTS형 누수 차단.

    5분/15분/30분/60분이 모두 약한데 거래량·대금만으로 A/rescue 문구가 붙는 경우는
    사용자 알림이 아니라 내부감시/복기여야 한다. 전체 문턱을 조이는 게 아니라
    "흐름은 음수인데 좋은 후보처럼 보이는" 경로만 막는다.
    """
    if not RESCUE_LEAK_BLOCK_ON:
        return ""
    item = item if isinstance(item, dict) else {}
    try:
        ch1 = safe_float(item.get("change_1", 0), 0)
        ch3 = safe_float(item.get("change_3", 0), 0)
        ch5 = safe_float(item.get("change_5", 0), 0)
        ch15 = safe_float(item.get("change_15", 0), 0)
        ch30 = safe_float(item.get("change_30", 0), 0)
        ch60 = safe_float(item.get("change_60", 0), 0)
        primary = str(primary_reason or item.get("primary_reason", "") or "")
        one = str(item.get("one_liner", "") or "")
        reasons = " / ".join([str(x) for x in item.get("reasons", [])[:5]]) if isinstance(item.get("reasons"), list) else str(item.get("reasons", "") or "")
        has_rescue_text = ("rescue" in reasons.lower()) or ("승격" in reasons) or ("막 뜨기 직전" in primary) or ("막 뜨기 직전" in one) or ("미리" in str(item.get("label_text", "")))
        all_mid_weak = (ch5 < 0.00 and ch15 < 0.00 and ch30 < 0.00 and (ch60 < 0.00 if RESCUE_LEAK_REQUIRE_60M_NEG else True))
        no_short_recover = (ch1 <= 0.12 and ch3 <= 0.12)
        current_follow = safe_float(item.get("current_candle_follow_score", 0), 0)
        current_live = safe_float(item.get("current_candle_live_score", 0), 0)
        current_reclaim = safe_float(item.get("current_candle_reclaim_score", 0), 0)
        low_score = max(
            safe_float(item.get("low_defense_v2_score", 0), 0),
            safe_float(item.get("low_structure_score_v2", 0), 0),
            safe_float(item.get("low_zone_defense_score", 0), 0),
        )
        turnover_keep = safe_float(item.get("turnover_persistence_score", 0), 0)
        has_real_chart_recovery = (
            current_follow >= RESCUE_LEAK_MIN_STRONG_CANDLE_FOLLOW
            or current_live >= CURRENT_CANDLE_V2_LIVE_STRONG_SCORE
            or current_reclaim >= CURRENT_CANDLE_V2_RECLAIM_STRONG_SCORE
            or (low_score >= RESCUE_LEAK_MIN_STRONG_LOW_DEFENSE and turnover_keep >= RESCUE_LEAK_MIN_STRONG_TURNOVER_KEEP)
        )
        if all_mid_weak and no_short_recover and not has_real_chart_recovery:
            return "5/15/30/60분 흐름이 전부 약해 rescue/A 알림은 보류하고 내부감시만 유지"
        if all_mid_weak and has_rescue_text and not has_real_chart_recovery:
            return "흐름은 음수인데 rescue 문구만 강해서 사용자 알림 보류"
        if "1분봉 확인 전" in one and (ch5 < 0.10 and ch30 < 0.05):
            return "1분봉 확인 전이고 단기 흐름이 약해 사용자 알림 보류"
        return ""
    except Exception:
        return ""


def demote_fast_scan_user_alert_v226(item: dict, reason: str) -> dict:
    """v2.5.226: 사용자 알림 후보를 내부감시로만 낮춘다."""
    item = dict(item or {})
    if not reason:
        return item
    item["alert_bucket"] = "internal_watch"
    item["alert_grade"] = "B" if str(item.get("alert_grade", "") or "") in {"S", "A"} else str(item.get("alert_grade", "B") or "B")
    item["bucket_rank"] = max(2, int(safe_float(item.get("bucket_rank", 2), 2)))
    item["quality_block_reason"] = reason
    item["user_alert_block_reason_detail"] = reason
    reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
    reasons = [r for r in reasons if "좋은 흐름이라 rescue 승격" not in str(r)]
    if reason not in reasons:
        reasons.insert(0, reason)
    item["reasons"] = reasons[:6]
    one = str(item.get("one_liner", "") or "").strip()
    if one and "알림 보류" not in one:
        item["one_liner"] = one + " / 흐름 확인 전이라 알림은 보류"
    elif not one:
        item["one_liner"] = "흐름 확인 전이라 알림은 보류"
    return item



def classify_fast_scan_grade_bucket(section: str, primary_reason: str, change_5: float, change_3: float, vol_ratio: float, leader_score: float, from_low: float, below_high: float, rsi: float, lite_score: float, item: dict | None = None) -> tuple[str, str]:
    section = str(section or '').strip()
    primary_reason = str(primary_reason or '').strip()
    item = item or {}
    chart_bad = _fast_chart_bad(item)
    turnover_s_ok = _fast_abs_turnover_ok(item, 's')
    turnover_a_ok = _fast_abs_turnover_ok(item, 'a')
    turnover_watch_ok = _fast_abs_turnover_ok(item, 'watch')
    turnover_rescue_ok = _fast_abs_turnover_ok(item, 'rescue')
    drought_sec = _fast_user_alert_drought_sec()

    if bool(item.get('ultra_low_tick_noise_block', False)) or primary_reason == '초저가 잡음형':
        return 'C', 'discard'
    if bool(item.get('flash_low_liquidity_near_high_block', False)) or primary_reason == '반짝 확인 후보':
        return 'C', 'internal_watch'

    # v2.5.226: CRTS형 누수 방지. 등급/문구가 A로 올라가도 실제 5/15/30/60 흐름이 전부 약하면
    # 사용자 알림으로 보내지 않고 내부감시에서만 검증한다.
    flow_block_reason_v226 = get_fast_scan_user_alert_flow_block_reason_v226(item, section=section, primary_reason=primary_reason)
    if flow_block_reason_v226:
        item['quality_block_reason'] = flow_block_reason_v226
        item['user_alert_block_reason_detail'] = flow_block_reason_v226
        return 'B', 'internal_watch'
    final_gate_reason_v227 = get_user_alert_final_gate_block_reason_v227(item, section=section, primary_reason=primary_reason)
    if final_gate_reason_v227:
        item['quality_block_reason'] = final_gate_reason_v227
        item['user_alert_block_reason_detail'] = final_gate_reason_v227
        return 'B', 'internal_watch'

    if section == 'strong':
        direct_live = primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보', '초입 가능 후보'}
        direct_early = primary_reason == '초반 선점형'
        s_change5 = 0.92
        s_change3 = 0.18
        s_vol = 2.45
        s_leader = 1.05
        s_from_low_min = 0.10
        s_from_low_max = 2.05
        s_below_high = 1.05

        a_change5 = 0.34
        a_change3 = -0.02
        a_vol = 1.35
        a_leader = 0.62
        a_from_low_min = 0.04
        a_from_low_max = 2.35
        a_below_high = 0.82
        a_lite = 9.3

        # v2.5.165: WIKEN형 보정. 초입 감시는 살리되, 60분 강세 뒤 15/30분 힘이 꺾이면 사용자 알림 승격은 보류한다.
        decay_reason = get_user_alert_momentum_decay_reason(item, section='strong')
        if decay_reason and primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보'}:
            item['user_alert_block_reason_detail'] = decay_reason
            return 'B', 'internal_watch'

        # v2.5.154: 1시간 +20~30%로 인기순위에 오른 뒤가 아니라, 3~30분 가속 초입을 별도 알림 후보로 살린다.
        if primary_reason == '실시간 폭발 초입 후보' and _is_hot_ignition_user_alert(item) and turnover_a_ok and not chart_bad:
            return 'A', 'user_alert'
        if primary_reason == '1시간 급등 초입 후보' and _is_hourly_momentum_user_alert(item) and turnover_a_ok and not chart_bad:
            return 'A', 'user_alert'

        # 알림이 너무 마르면 직접 잡힌 실시간/초반형만 한 단계 더 살린다.
        if drought_sec >= 7200 and (direct_live or direct_early):
            a_change5 = 0.22
            a_change3 = -0.06
            a_vol = 1.18
            a_leader = 0.45
            a_from_low_min = 0.02
            a_from_low_max = 2.45
            a_below_high = 0.72
            a_lite = 8.6

        if (
            primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보'}
            and change_5 >= s_change5 and change_3 >= s_change3
            and vol_ratio >= s_vol and leader_score >= s_leader
            and s_from_low_min <= from_low <= s_from_low_max and below_high >= s_below_high
            and rsi < 80 and turnover_s_ok and not chart_bad
        ):
            return 'S', 'user_alert'
        if (
            primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보', '초입 가능 후보', '초반 선점형'}
            and change_5 >= a_change5 and change_3 >= a_change3
            and vol_ratio >= a_vol and leader_score >= a_leader
            and a_from_low_min <= from_low <= a_from_low_max and below_high >= a_below_high
            and lite_score >= a_lite and rsi < 82 and turnover_a_ok and not chart_bad
        ):
            change_30 = safe_float(item.get('change_30', 0), 0)
            if primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보'} and (change_3 < 0.10 or change_30 < 0.05 or from_low >= 1.25):
                return 'B', 'internal_watch'
            if primary_reason == '초입 가능 후보' and (change_30 < -0.05 and from_low >= 0.95):
                return 'B', 'internal_watch'
            if primary_reason == '초반 선점형' and (change_3 < 0.00 and change_30 < 0.10 and from_low >= 1.10):
                return 'B', 'internal_watch'
            return 'A', 'user_alert'
        if turnover_watch_ok and change_5 >= 0.10 and vol_ratio >= 0.98 and below_high >= 0.62:
            return 'B', 'internal_watch'
        return 'C', 'discard'

    if section == 'watch':
        if bool(item.get('near_high_rebreakout_watch', False)) or primary_reason == '재돌파 대기 후보':
            return 'B', 'internal_watch'
        restart_like = primary_reason == '재출발 확인 후보'
        weak_restart = _fast_rescue_has_weak_reason(item)
        rescue_like = (
            primary_reason in {'재출발 확인 후보', '초입/회복 확인 후보', '초입 가능 후보'}
            and change_5 >= 0.66 and vol_ratio >= 2.20 and leader_score >= 0.78
            and 0.28 <= from_low <= 2.10 and below_high >= 1.45
            and lite_score >= max(FAST_SCAN_RESCUE_SCORE_MIN - 0.6, 13.8) and rsi < 78
            and turnover_rescue_ok and not chart_bad and not weak_restart
            and safe_float(item.get('change_30', 0), 0) >= -0.55
        )
        prelaunch_like = (
            primary_reason == '막 뜨기 직전 후보'
            and max(FAST_SCAN_PRELAUNCH_MIN_CHANGE5, -0.35) <= change_5 <= min(FAST_SCAN_PRELAUNCH_MAX_CHANGE5, 0.35)
            and change_3 >= max(FAST_SCAN_PRELAUNCH_MIN_CHANGE3, -0.10)
            and vol_ratio >= max(FAST_SCAN_PRELAUNCH_MIN_VOL, 1.25)
            and leader_score >= max(FAST_SCAN_PRELAUNCH_MIN_LEADER, 0.45)
            and max(FAST_SCAN_PRELAUNCH_MIN_FROM_LOW, 0.20) <= from_low <= min(FAST_SCAN_PRELAUNCH_MAX_FROM_LOW, 1.55)
            and below_high >= max(FAST_SCAN_PRELAUNCH_MIN_HIGH_GAP, 1.20)
            and lite_score >= 12.4 and rsi < 79
            and safe_float(item.get('turnover_5m', 0), 0) >= max(14000000, FAST_SCAN_PRELAUNCH_MIN_TURNOVER_5M * 0.95)
            and not chart_bad
            and safe_float(item.get('change_30', 0), 0) >= -2.20
            and (change_3 >= 0.00 or safe_float(item.get('change_1', 0), 0) >= 0.10)
            and (
                vol_ratio >= 1.70
                or leader_score >= 0.70
                or int(safe_float(item.get('turnover_rank', 999), 999)) <= 18
            )
            and (
                int(safe_float(item.get('change5_rank', 999), 999)) <= 12
                or int(safe_float(item.get('turnover_rank', 999), 999)) <= 24
                or int(safe_float(item.get('leader_rank', 999), 999)) <= 20
            )
        )
        if rescue_like:
            return 'A', 'user_alert'
        if prelaunch_like:
            return 'A', 'user_alert'
        if restart_like:
            if (
                change_5 >= 0.72 and vol_ratio >= 2.55 and leader_score >= 0.95
                and from_low >= 0.55 and below_high >= 2.10 and lite_score >= 14.8
                and turnover_a_ok and not chart_bad and not weak_restart
                and safe_float(item.get('change_30', 0), 0) >= -0.45
            ):
                return 'A', 'user_alert'
            # v2.5.226: 저점방어/저점높임이 좋은 재출발형은 버리지 않고 내부감시로 살린다.
            # 단, 바로 사용자 알림으로 올리지는 않는다.
            if is_restart_low_defense_watch_v226(item) and turnover_watch_ok and change_5 >= -0.08 and below_high >= 0.85:
                item['restart_low_defense_watch_v226'] = True
                return 'B', 'internal_watch'
            if turnover_watch_ok and change_5 >= 0.12 and from_low >= 0.18 and below_high >= 0.75:
                return 'B', 'internal_watch'
            return 'C', 'discard'
        if primary_reason == '막 뜨기 직전 후보' and turnover_watch_ok and change_5 >= -0.90 and vol_ratio >= 1.02 and leader_score >= 0.30 and below_high >= 0.55:
            return 'B', 'internal_watch'
        if turnover_watch_ok and change_5 >= 0.10 and vol_ratio >= 1.02 and leader_score >= 0.30 and below_high >= 0.55:
            return 'B', 'internal_watch'
        return 'C', 'discard'

    return 'C', 'discard'



def _observation_snapshot(item: dict, now_ts: float = None) -> dict:
    """관찰 후보 재평가용 최소 스냅샷."""
    now_ts = safe_float(now_ts, time.time())
    return {
        "ts": now_ts,
        "ticker": str(item.get("ticker", "") or "").upper().strip(),
        "price": safe_float(item.get("price", item.get("current_price", 0)), 0),
        "change_1": safe_float(item.get("change_1", 0), 0),
        "change_3": safe_float(item.get("change_3", 0), 0),
        "change_5": safe_float(item.get("change_5", 0), 0),
        "change_30": safe_float(item.get("change_30", 0), 0),
        "from_low": safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0),
        "below_high": safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999),
        "vol_ratio": safe_float(item.get("vol_ratio", 0), 0),
        "leader_score": safe_float(item.get("leader_score", 0), 0),
        "turnover_5m": safe_float(item.get("turnover_5m", 0), 0),
        "lite_score": safe_float(item.get("lite_score", 0), 0),
        "bucket": str(item.get("alert_bucket", "") or ""),
        "grade": str(item.get("alert_grade", "") or ""),
        "primary_reason": str(item.get("primary_reason", "") or ""),
        "one_liner": str(item.get("one_liner", "") or ""),
        "low_defense": safe_float(item.get("low_zone_defense_score", item.get("recovery_quality_score", 0)), 0),
        "turnover_keep": safe_float(item.get("turnover_persistence_score", 0), 0),
        "rebreakout": safe_float(item.get("rebreakout_score", item.get("rebreakout_display_score", 0)), 0),
    }


def _cleanup_observation_reeval_queue(now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    if not isinstance(OBSERVATION_REEVAL_QUEUE, dict):
        return
    for ticker in list(OBSERVATION_REEVAL_QUEUE.keys()):
        row = OBSERVATION_REEVAL_QUEUE.get(ticker)
        if not isinstance(row, dict):
            OBSERVATION_REEVAL_QUEUE.pop(ticker, None)
            continue
        ts = safe_float(row.get("ts", 0), 0)
        if ts <= 0 or now_ts - ts > OBS_REEVAL_TTL_SEC:
            OBSERVATION_REEVAL_QUEUE.pop(ticker, None)


def _is_observation_reeval_candidate(item: dict) -> bool:
    """처음엔 알림이 아니지만, 좋아지면 승격할 가치가 있는 관찰 후보인지 판단."""
    if not OBS_REEVAL_ON or not isinstance(item, dict):
        return False
    ticker = str(item.get("ticker", "") or "").upper().strip()
    if not ticker or is_watch_excluded_ticker(ticker):
        return False
    if str(item.get("alert_bucket", "") or "") == "user_alert":
        return False
    if item.get("lite_scan_only"):
        return False
    if bool(item.get("ultra_low_tick_noise_block", False)) or bool(item.get("flash_low_liquidity_near_high_block", False)):
        return False
    if _is_late_high_volatility_item(item):
        return False
    high_gap = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    if not (OBS_REEVAL_MIN_HIGH_GAP_PCT <= high_gap <= OBS_REEVAL_MAX_HIGH_GAP_PCT):
        return False
    if from_low > OBS_REEVAL_MAX_FROM_LOW_PCT:
        return False
    turnover_5m = safe_float(item.get("turnover_5m", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    turnover_rank = int(safe_float(item.get("turnover_rank", 999), 999))
    if turnover_5m < 5_000_000 and vol_ratio < 2.0 and leader < 1.0 and turnover_rank > 20:
        return False
    if _fast_chart_bad(item) and not _is_near_high_rebreakout_watch(item):
        return False
    return True


def _observation_improve_score(prev: dict, item: dict) -> tuple[float, list]:
    reasons = []
    score = 0.0
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg3 = safe_float(item.get("change_3", 0), 0)
    from_low = safe_float(item.get("from_low", 0), 0)
    below_high = safe_float(item.get("below_high", 999), 999)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    turn = safe_float(item.get("turnover_5m", 0), 0)
    lite = safe_float(item.get("lite_score", 0), 0)
    prev_chg5 = safe_float(prev.get("change_5", 0), 0)
    prev_chg3 = safe_float(prev.get("change_3", 0), 0)
    prev_from_low = safe_float(prev.get("from_low", 0), 0)
    prev_below = safe_float(prev.get("below_high", 999), 999)
    prev_vol = safe_float(prev.get("vol_ratio", 0), 0)
    prev_turn = safe_float(prev.get("turnover_5m", 0), 0)
    prev_lite = safe_float(prev.get("lite_score", 0), 0)
    if chg5 - prev_chg5 >= 0.22 and chg5 >= 0.18:
        score += 1.25
        reasons.append(f"5분 흐름 개선({prev_chg5:+.2f}%→{chg5:+.2f}%)")
    if chg3 - prev_chg3 >= 0.18 and chg3 >= 0.12:
        score += 0.90
        reasons.append(f"3분 흐름 개선({prev_chg3:+.2f}%→{chg3:+.2f}%)")
    if from_low >= prev_from_low + 0.25 and from_low >= 0.45:
        score += 0.75
        reasons.append(f"저점 회복 강화({prev_from_low:+.2f}%→{from_low:+.2f}%)")
    if prev_below < 999 and below_high >= prev_below + 0.35 and below_high >= 1.00:
        score += 0.65
        reasons.append("고점까지 공간이 더 생김")
    if prev_turn > 0 and turn >= prev_turn * 1.45 and turn >= OBS_REEVAL_MIN_TURNOVER_5M:
        score += 1.00
        reasons.append("거래대금 유지/증가")
    elif turn >= max(OBS_REEVAL_MIN_TURNOVER_5M * 1.7, 24_000_000):
        score += 0.65
        reasons.append("실제 거래대금 충분")
    if vol - prev_vol >= 0.45 and vol >= OBS_REEVAL_MIN_VOL_RATIO:
        score += 0.75
        reasons.append(f"거래량 배수 개선({prev_vol:.2f}→{vol:.2f})")
    if lite >= prev_lite + 2.2 and lite >= 10.0:
        score += 0.85
        reasons.append("종합 점수 개선")
    if safe_float(item.get("turnover_persistence_score", 0), 0) >= 1.25:
        score += 0.45
        reasons.append("돈이 계속 붙는 힘 유지")
    if safe_float(item.get("rebreakout_score", 0), 0) >= 2.20 and below_high >= 0.90:
        score += 0.45
        reasons.append("고점 다시도전 힘 유지")
    if chg5 < -0.15:
        score -= 1.20
    if from_low + 0.35 < prev_from_low:
        score -= 1.00
    if below_high < 0.55:
        score -= 1.20
    if turn < 6_000_000 and vol < 1.20 and leader < 0.80:
        score -= 0.80
    return round(score, 2), reasons[:5]


def _is_observation_upgrade_candidate(prev: dict, item: dict, now_ts: float = None) -> tuple[bool, str, float]:
    now_ts = safe_float(now_ts, time.time())
    if not isinstance(prev, dict) or not isinstance(item, dict):
        return False, "", 0.0
    age = now_ts - safe_float(prev.get("ts", 0), 0)
    if age < OBS_REEVAL_MIN_SEC or age > OBS_REEVAL_MAX_SEC:
        return False, "", 0.0
    if not _is_observation_reeval_candidate(item):
        return False, "", 0.0
    high_gap = safe_float(item.get("below_high", 999), 999)
    from_low = safe_float(item.get("from_low", 0), 0)
    chg5 = safe_float(item.get("change_5", 0), 0)
    chg3 = safe_float(item.get("change_3", 0), 0)
    vol = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    turn = safe_float(item.get("turnover_5m", 0), 0)
    if high_gap < 0.80 or from_low > OBS_REEVAL_MAX_FROM_LOW_PCT:
        return False, "", 0.0
    if turn < OBS_REEVAL_MIN_TURNOVER_5M and vol < 1.80 and leader < 0.85:
        return False, "", 0.0
    if chg5 < 0.10 and chg3 < 0.12:
        return False, "", 0.0
    if bool(item.get("low_actual_turnover_flag", False)) and turn < OBS_REEVAL_MIN_TURNOVER_5M * 1.5:
        return False, "", 0.0
    improve_score, reasons = _observation_improve_score(prev, item)
    if improve_score < OBS_REEVAL_MIN_IMPROVE_SCORE:
        return False, "", improve_score
    reason = "관찰 후 좋아져 알림 승격"
    if reasons:
        reason += " · " + " / ".join(reasons[:3])
    return True, reason, improve_score


def _apply_observation_reeval_queue(items: list) -> list:
    """관찰 후보를 저장하고, 1~3분 뒤 좋아진 후보는 user_alert로 승격한다."""
    if not OBS_REEVAL_ON or not items:
        return list(items or [])
    now_ts = time.time()
    _cleanup_observation_reeval_queue(now_ts)
    upgrades = {}
    promoted = 0
    for item in items:
        try:
            ticker = str(item.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            prev = OBSERVATION_REEVAL_QUEUE.get(ticker)
            ok, reason, score = _is_observation_upgrade_candidate(prev, item, now_ts=now_ts)
            if ok and promoted < OBS_REEVAL_MAX_PROMOTE_PER_SCAN:
                flow_block_reason_v226 = get_fast_scan_user_alert_flow_block_reason_v226(item, section=str(item.get('section', '') or ''), primary_reason=str(item.get('primary_reason', '') or ''))
                if flow_block_reason_v226:
                    item['quality_block_reason'] = flow_block_reason_v226
                    item['user_alert_block_reason_detail'] = flow_block_reason_v226
                    continue
                new_item = dict(item)
                new_item["alert_bucket"] = "user_alert"
                new_item["alert_grade"] = "A"
                new_item["bucket_rank"] = 3
                new_item["observation_upgrade"] = True
                new_item["observation_upgrade_score"] = score
                new_item["primary_reason"] = "관찰 후 승격 후보"
                reasons = list(new_item.get("reasons", [])) if isinstance(new_item.get("reasons"), list) else []
                reasons = [r for r in reasons if "지금 사기엔 별로" not in str(r) and "구경만" not in str(r)]
                reasons.insert(0, reason)
                new_item["reasons"] = reasons[:6]
                new_item["label_text"] = "관찰 후 승격"
                new_item["user_label_text"] = "관찰 후 힘 붙은 후보"
                new_item["alert_header_text"] = "✅ 관찰 후보 승격 알림"
                new_item["one_liner"] = reason
                upgrades[ticker] = new_item
                promoted += 1
                OBSERVATION_REEVAL_QUEUE.pop(ticker, None)
                append_runtime_event_log("observation_upgrade", reason, extra={"ticker": ticker, "score": score})
        except Exception:
            continue
    merged = [upgrades.get(str(x.get("ticker", "") or "").upper().strip(), x) for x in items]
    for item in merged:
        try:
            ticker = str(item.get("ticker", "") or "").upper().strip()
            if not ticker or ticker in upgrades:
                continue
            if _is_observation_reeval_candidate(item):
                prev = OBSERVATION_REEVAL_QUEUE.get(ticker)
                if not isinstance(prev, dict) or now_ts - safe_float(prev.get("ts", 0), 0) > OBS_REEVAL_MAX_SEC:
                    OBSERVATION_REEVAL_QUEUE[ticker] = _observation_snapshot(item, now_ts=now_ts)
        except Exception:
            continue
    if upgrades:
        merged.sort(
            key=lambda x: (
                safe_float(x.get("bucket_rank", 0)),
                3 if str(x.get("alert_grade", "")) == "S" else 2 if str(x.get("alert_grade", "")) == "A" else 1 if str(x.get("alert_grade", "")) == "B" else 0,
                safe_float(x.get("section_rank", 0)),
                safe_float(x.get("observation_upgrade_score", 0)),
                _fast_rescue_score(x),
            ),
            reverse=True,
        )
    return merged
def _rescue_internal_watch_items(items):
    if not items:
        return []
    now_ts = time.time()
    drought_sec = _fast_user_alert_drought_sec(now_ts)
    promoted = 0
    user_count = sum(1 for x in items if str(x.get('alert_bucket', '')) == 'user_alert' and str(x.get('alert_grade', '')) in {'S', 'A'})
    if user_count >= FAST_SCAN_ALERT_LIMIT:
        return list(items)
    internal_sorted = sorted(
        [x for x in items if str(x.get('alert_bucket', '')) == 'internal_watch'],
        key=_fast_rescue_score,
        reverse=True,
    )
    upgrades = {}
    dynamic_limit = FAST_SCAN_RESCUE_LIMIT + (1 if drought_sec >= 7200 else 0)
    for item in internal_sorted:
        if promoted >= dynamic_limit or user_count + promoted >= FAST_SCAN_ALERT_LIMIT:
            break
        ticker = str(item.get('ticker', '') or '')
        if not ticker:
            continue
        if _fast_rescue_score(item) < FAST_SCAN_RESCUE_SCORE_MIN:
            continue
        quality_rescue_ok = _fast_quality_rescue_ok(item)
        if ((not _fast_abs_turnover_ok(item, 'rescue')) and not quality_rescue_ok) or _fast_chart_bad(item) or _fast_rescue_has_weak_reason(item):
            continue
        regime = item.get('market_regime') if isinstance(item.get('market_regime'), dict) else get_market_regime()
        good_market = is_good_market_for_user_rescue(regime)
        change_5 = safe_float(item.get('change_5', 0), 0)
        change_30 = safe_float(item.get('change_30', 0), 0)
        change_3 = safe_float(item.get('change_3', 0), 0)
        change_1 = safe_float(item.get('change_1', 0), 0)
        vol_ratio = safe_float(item.get('vol_ratio', 0), 0)
        leader = safe_float(item.get('leader_score', 0), 0)
        below_high = safe_float(item.get('below_high', 999), 999)
        from_low = safe_float(item.get('from_low', 0), 0)
        turnover_5m = safe_float(item.get('turnover_5m', 0), 0)
        turnover_rank = int(safe_float(item.get('turnover_rank', 999), 999))
        change5_rank = int(safe_float(item.get('change5_rank', 999), 999))
        leader_rank = int(safe_float(item.get('leader_rank', 999), 999))
        shortlist_rank = int(safe_float(item.get('shortlist_rank', 999), 999))
        primary_reason = str(item.get('primary_reason', '') or '')
        rescue_ok = (
            change_5 >= 0.50
            and vol_ratio >= 2.00
            and leader >= 0.72
            and below_high >= 1.25
            and 0.12 <= from_low <= 2.10
            and turnover_5m >= FAST_SCAN_RESCUE_MIN_TURNOVER_5M
            and change_30 >= -0.55
        )
        strong_rank_hint = (
            shortlist_rank <= 6
            or turnover_rank <= 12
            or change5_rank <= 10
            or leader_rank <= 18
        )
        rank_recovery_ok = (
            strong_rank_hint
            and below_high >= 1.85
            and vol_ratio >= 1.45
            and leader >= 0.55
            and turnover_5m >= 15000000
            and from_low <= 2.45
            and (
                change_30 >= 0.90
                or change_5 >= 0.18
                or change_3 >= 0.10
                or change_1 >= 0.18
                or (change_5 >= 0.00 and change_30 >= 0.35)
            )
        )
        bottom_reclaim_ok = (
            strong_rank_hint
            and from_low <= 0.12
            and below_high >= 2.00
            and vol_ratio >= 1.35
            and leader >= 0.45
            and turnover_5m >= 14000000
            and (change_1 >= 0.18 or change_3 >= 0.12)
        )
        quality_rescue_ok = quality_rescue_ok and strong_rank_hint and turnover_5m >= 6500000 and below_high >= 0.90 and from_low <= 2.60
        if primary_reason in {'실시간 급등 초입', '실시간 폭발 초입 후보', '1시간 급등 초입 후보'}:
            rescue_ok = rescue_ok and change_5 >= 0.76 and change_3 >= 0.00 and vol_ratio >= 2.20 and leader >= 0.82 and below_high >= 1.45 and turnover_5m >= 22000000 and change_30 >= -0.35
            if drought_sec >= 7200:
                rescue_ok = rescue_ok and change_5 >= 0.62 and vol_ratio >= 1.90 and below_high >= 1.20 and turnover_5m >= 19000000
            if not good_market:
                rescue_ok = rescue_ok and turnover_5m >= 36000000 and change_5 >= 1.05 and below_high >= 2.10 and change_30 >= -0.05
            if (not rescue_ok) and rank_recovery_ok and below_high >= 2.00 and (change_3 >= 0.10 or change_1 >= 0.18 or change_30 >= 1.00):
                rescue_ok = True
        elif primary_reason == '초반 선점형':
            rescue_ok = rescue_ok and change_5 >= 0.62 and change_3 >= -0.02 and vol_ratio >= 1.90 and leader >= 0.70 and below_high >= 1.30 and turnover_5m >= 19000000 and from_low <= 1.95
            if drought_sec >= 7200:
                rescue_ok = rescue_ok and change_5 >= 0.52 and vol_ratio >= 1.70 and below_high >= 1.10 and turnover_5m >= 17000000
            if (not rescue_ok) and (rank_recovery_ok or bottom_reclaim_ok) and below_high >= 1.90 and from_low <= 2.35 and turnover_5m >= 15000000 and (change_3 >= 0.00 or change_1 >= 0.15 or change_30 >= 0.80):
                rescue_ok = True
        elif primary_reason == '재출발 확인 후보':
            # 재출발형은 계속 보수적으로 유지하되, 상위 shortlist + 늦지 않은 회복형은 한 단계만 구제
            rescue_ok = rescue_ok and change_5 >= 0.92 and vol_ratio >= 3.00 and leader >= 1.02 and from_low >= 0.70 and below_high >= 2.55 and turnover_5m >= 30000000 and change_30 >= -0.15
            if (not rescue_ok) and rank_recovery_ok and below_high >= 2.10 and turnover_5m >= 16000000 and from_low <= 2.45 and (change_3 >= 0.10 or change_1 >= 0.20 or change_30 >= 0.55):
                rescue_ok = True
        else:
            rescue_ok = rescue_ok and change_5 >= 0.74 and vol_ratio >= 2.55 and below_high >= 1.90 and turnover_5m >= 28000000
            if (not rescue_ok) and rank_recovery_ok and below_high >= 1.95 and (change_3 >= 0.08 or change_1 >= 0.15 or change_30 >= 0.90):
                rescue_ok = True
        if (not rescue_ok) and quality_rescue_ok:
            rescue_ok = True
        if not rescue_ok:
            continue
        # v2.5.227: 내부감시 rescue 승격 단계에서도 최종 사용자 알림 게이트를 반드시 통과하게 한다.
        final_gate_reason_v227 = get_user_alert_final_gate_block_reason_v227(item, section=str(item.get('section', '') or ''), primary_reason=primary_reason)
        if final_gate_reason_v227:
            item['quality_block_reason'] = final_gate_reason_v227
            item['user_alert_block_reason_detail'] = final_gate_reason_v227
            continue
        new_item = dict(item)
        new_item['alert_bucket'] = 'user_alert'
        new_item['alert_grade'] = 'A'
        new_item['bucket_rank'] = 2
        reasons = list(new_item.get('reasons', [])) if isinstance(new_item.get('reasons'), list) else []
        reasons = [r for r in reasons if '힘이 아직 약함' not in str(r) and '다시 사는지 확인할 자리' not in str(r)]
        q_score, q_reasons = _fast_defense_money_quality(new_item)
        rescue_reason_text = '저점방어+돈유지 좋아 rescue 승격' if q_score >= 2.55 else '좋은 흐름이라 rescue 승격'
        if rescue_reason_text not in reasons:
            reasons.insert(0, rescue_reason_text)
        for _qr in q_reasons[:2]:
            if _qr not in reasons:
                reasons.append(_qr)
        if primary_reason == '재출발 확인 후보':
            if '유지력 확인이 더 필요한 자리' not in reasons:
                reasons.append('재출발은 다시 밀릴 수 있어 유지력도 같이 확인')
        else:
            reasons = [r for r in reasons if '유지력 확인이 더 필요한 자리' not in str(r)]
        new_item['reasons'] = reasons[:5]
        one_liner = str(new_item.get('one_liner', '') or '지금은 흐름만 확인')
        if primary_reason == '재출발 확인 후보':
            one_liner = one_liner.replace('재출발 힘이 아직 약함', '재출발 힘이 붙는지 재확인')
            new_item['one_liner'] = one_liner + ' / 감시 상위라 다시 올렸지만 재출발은 끝까지 확인 필요'
        else:
            new_item['one_liner'] = one_liner
        upgrades[ticker] = new_item
        promoted += 1
    if not upgrades:
        return list(items)
    merged = [upgrades.get(str(x.get('ticker', '') or ''), x) for x in items]
    merged.sort(
        key=lambda x: (
            safe_float(x.get('bucket_rank', 0)),
            3 if str(x.get('alert_grade', '')) == 'S' else 2 if str(x.get('alert_grade', '')) == 'A' else 1 if str(x.get('alert_grade', '')) == 'B' else 0,
            safe_float(x.get('section_rank', 0)),
            _fast_rescue_score(x),
        ),
        reverse=True,
    )
    return merged


def _promote_survivor_user_alerts(items):
    """상위 후보 강제 user_alert 승격 비활성화.
    차트 정교화/분류 정합성 점검이 우선이라,
    상위 후보라는 이유만으로 실제 알림으로 올리는 기능은 잠시 끈다.
    """
    return list(items) if isinstance(items, list) else []


def get_fast_scan_stage1_rows(cache: dict, limit: int = FAST_SCAN_INPUT_LIMIT):
    if not isinstance(cache, dict) or not cache:
        return []
    ranked_rows = get_watchlist_ranked_cache_items(cache, limit=max(int(limit), FAST_SCAN_STAGE1_POOL_LIMIT))
    picked = {}

    def add_rows(rows):
        for ticker, data, score in rows:
            key = str(ticker or '').upper().strip()
            if not key or key in picked:
                continue
            picked[key] = (ticker, data, score)
            if len(picked) >= max(int(limit), FAST_SCAN_STAGE1_POOL_LIMIT):
                break

    add_rows(ranked_rows[:FAST_SCAN_STAGE1_SCORE_TOP])

    # v2.5.188: 내부 유사 실시간 순위권은 후보 풀에 먼저 넣어 기록 누락을 줄인다.
    realtime_ranked_rows = [
        x for x in ranked_rows
        if isinstance(x[1], dict) and (
            bool(x[1].get("realtime_rank_injected"))
            or str(x[1].get("cache_source", "") or "").startswith("light_snapshot_rank")
        )
    ]
    add_rows(realtime_ranked_rows[:REALTIME_RANK_FORCE_STAGE1_TOP])

    # v2.5.196: 순위권 강세 상위 후보는 공장라인 회전에서 밀리지 않게 stage1에 우선 투입한다.
    rank_precision_rows = sorted(
        [x for x in ranked_rows if isinstance(x[1], dict) and is_realtime_rank_precision_candidate(x[1])],
        key=lambda x: (
            safe_float(x[1].get('snapshot_rank_score', 0), 0),
            safe_float(x[1].get('change_3', 0), 0),
            safe_float(x[1].get('change_5', 0), 0),
            safe_float(x[1].get('change_30', 0), 0),
        ),
        reverse=True,
    )
    add_rows(rank_precision_rows[:REALTIME_RANK_PRECISION_STAGE1_TOP])

    turnover_rows = sorted(
        ranked_rows,
        key=lambda x: (
            safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0),
            -int(safe_float(x[1].get('turnover_rank', 999), 999)),
        ),
        reverse=True,
    )
    surge_rows = sorted(
        ranked_rows,
        key=lambda x: (
            safe_float(x[1].get('change_5', 0), 0),
            safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0),
            safe_float(x[1].get('leader_score', 0), 0),
        ),
        reverse=True,
    )
    leader_rows = sorted(
        ranked_rows,
        key=lambda x: (
            safe_float(x[1].get('leader_score', 0), 0),
            safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0),
            safe_float(x[1].get('change_5', 0), 0),
        ),
        reverse=True,
    )
    change_rows = sorted(
        ranked_rows,
        key=lambda x: (
            safe_float(x[1].get('change_3', 0), 0) + safe_float(x[1].get('change_5', 0), 0),
            safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0),
            safe_float(x[1].get('leader_score', 0), 0),
        ),
        reverse=True,
    )

    prelaunch_rows = sorted(
        ranked_rows,
        key=lambda x: (
            safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0) * 0.00000001
            + safe_float(x[1].get('leader_score', 0), 0) * 1.35
            + max(safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0) - 0.9, 0) * 0.95
            + max(min(safe_float(x[1].get('below_high', 999), 999), 3.5), 0) * 0.55
            + max(1.8 - abs(safe_float(x[1].get('change_5', 0), 0)), 0) * 0.45
            + max(1.8 - max(safe_float(x[1].get('from_low', 0), 0), 0), 0) * 0.30
            + max(60 - min([r for r in [
                int(safe_float(x[1].get('change_1_rank', 0), 0) or 0),
                int(safe_float(x[1].get('change_5_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank_pulse', 0), 0) or 0),
                int(safe_float(x[1].get('surge_rank', 0), 0) or 0),
                int(safe_float(x[1].get('leader_rank', 0), 0) or 0),
            ] if r > 0] or [999]), 0) * 0.06
        ),
        reverse=True,
    )
    hot_rows = sorted(
        ranked_rows,
        key=lambda x: (
            max(60 - min([r for r in [
                int(safe_float(x[1].get('change_1_rank', 0), 0) or 0),
                int(safe_float(x[1].get('change_5_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank_pulse', 0), 0) or 0),
                int(safe_float(x[1].get('surge_rank', 0), 0) or 0),
            ] if r > 0] or [999]), 0),
            safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0),
            safe_float(x[1].get('leader_score', 0), 0),
        ),
        reverse=True,
    )

    ignition_rows = sorted(
        ranked_rows,
        key=lambda x: (
            max(safe_float(x[1].get('change_3', 0), 0), 0) * 1.20
            + max(safe_float(x[1].get('change_5', 0), 0), 0) * 1.10
            + max(safe_float(x[1].get('change_15', 0), 0), 0) * 0.65
            + max(safe_float(x[1].get('change_30', 0), 0), 0) * 0.45
            + max(safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0) - 1.0, 0) * 1.15
            + safe_float(x[1].get('leader_score', 0), 0) * 1.20
            + safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0) * 0.000000018
        ),
        reverse=True,
    )
    hourly_rows = sorted(
        ranked_rows,
        key=lambda x: (
            max(safe_float(x[1].get('change_60', 0), 0), 0) * 0.72
            + max(safe_float(x[1].get('change_30', 0), 0), 0) * 0.95
            + max(safe_float(x[1].get('change_15', 0), 0), 0) * 1.05
            + max(safe_float(x[1].get('change_5', 0), 0), 0) * 0.92
            + max(safe_float(x[1].get('change_3', 0), 0), 0) * 0.62
            + max(safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0) - 1.0, 0) * 0.95
            + safe_float(x[1].get('leader_score', 0), 0) * 1.15
            + safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0) * 0.000000014
        ),
        reverse=True,
    )

    add_rows(turnover_rows[:FAST_SCAN_STAGE1_TURNOVER_TOP])
    add_rows(surge_rows[:FAST_SCAN_STAGE1_SURGE_TOP])
    add_rows(leader_rows[:FAST_SCAN_STAGE1_LEADER_TOP])
    add_rows(change_rows[:FAST_SCAN_STAGE1_CHANGE5_TOP])
    add_rows(prelaunch_rows[:FAST_SCAN_STAGE1_PRELAUNCH_TOP])
    add_rows(hourly_rows[:FAST_SCAN_STAGE1_HOURLY_TOP])
    add_rows(ignition_rows[:FAST_SCAN_STAGE1_IGNITION_TOP])
    add_rows(hot_rows[:FAST_SCAN_STAGE1_HOT_TOP])

    rows = list(picked.values())
    rows.sort(
        key=lambda x: (
            safe_float(x[1].get('turnover_5m', x[1].get('turnover', 0)), 0) * 0.00000001
            + safe_float(x[1].get('leader_score', 0), 0) * 1.35
            + max(safe_float(x[1].get('vol_ratio', x[1].get('vol_ratio_1m', 0)), 0) - 0.9, 0) * 1.0
            + max(safe_float(x[1].get('change_5', 0), 0), 0) * 0.65
            + max(safe_float(x[1].get('change_3', 0), 0), 0) * 0.35
            + max(safe_float(x[1].get('change_15', 0), 0), 0) * 0.26
            + max(safe_float(x[1].get('change_30', 0), 0), 0) * 0.22
            + max(safe_float(x[1].get('change_60', 0), 0), 0) * 0.14
            + max(min(safe_float(x[1].get('below_high', 999), 999), 3.5), 0) * 0.30
            + safe_float(x[1].get('snapshot_rank_score', 0), 0) * 0.95
            + (8.0 if is_realtime_rank_precision_candidate(x[1]) else 0.0)
            + max(50 - min([r for r in [
                int(safe_float(x[1].get('change_1_rank', 0), 0) or 0),
                int(safe_float(x[1].get('change_5_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank', 0), 0) or 0),
                int(safe_float(x[1].get('turnover_rank_pulse', 0), 0) or 0),
                int(safe_float(x[1].get('surge_rank', 0), 0) or 0),
            ] if r > 0] or [999]), 0) * 0.05
        ),
        reverse=True,
    )
    return rows[:max(1, int(limit))]


def build_fast_scan_candidates_from_cache(cache: dict, limit: int = FAST_SCAN_RESULT_MAX):
    limit = max(1, int(limit))
    if not isinstance(cache, dict) or not cache:
        return []
    try:
        cache = enrich_cache_with_light_snapshots(cache)
        cache = inject_realtime_snapshot_rows_into_cache(cache, limit=REALTIME_RANK_INJECT_LIMIT)
    except Exception:
        pass
    # main loop / background loop / command가 동시에 후보 조립을 돌리면
    # 같은 df와 정렬을 중복 계산하면서 freshness가 더 밀린다.
    if not fast_scan_build_lock.acquire(blocking=False):
        append_runtime_event_log("fast_scan_build_skip_busy", "이미 후보 조립 중이라 이번 차수는 건너뜀", extra={"limit": limit})
        try:
            return list(latest_fast_scan_items or [])[:limit]
        except Exception:
            return []
    try:
        snapshot_ready_count = 0
        try:
            snapshot_ready_count = sum(1 for _r in cache.values() if isinstance(_r, dict) and isinstance(_r.get("light_snapshot"), dict) and _r.get("light_snapshot", {}).get("snapshot_ready"))
        except Exception:
            snapshot_ready_count = 0
        stage1_limit = int(max(limit * FAST_SCAN_BUILD_STAGE1_MULTIPLIER, FAST_SCAN_BUILD_MIN_ITEMS))
        if snapshot_ready_count >= 12:
            stage1_limit = max(stage1_limit, min(FAST_SCAN_INPUT_LIMIT + 10, 34))
        stage1_limit = min(max(stage1_limit, FAST_SCAN_BUILD_MIN_ITEMS), max(FAST_SCAN_INPUT_LIMIT, 34 if snapshot_ready_count >= 12 else FAST_SCAN_INPUT_LIMIT))
        stage1_rows = get_fast_scan_stage1_rows(cache, limit=stage1_limit)

        # v2.5.182: 공장라인 방식.
        # 매번 전체 정밀 후보를 다 처리하려고 하다가 fast scan이 부분 종료되는 문제를 막는다.
        # 상위 핵심 후보는 매번 보고, 나머지는 회전 처리해서 넓게 감시한다.
        global FAST_SCAN_STAGE1_CURSOR, LAST_FAST_FACTORY_SLICE_INFO
        original_stage1_count = len(stage1_rows)
        if FAST_SCAN_FACTORY_LINE_ON and original_stage1_count > FAST_SCAN_FACTORY_ROTATE_ROWS:
            core_n = max(0, min(FAST_SCAN_FACTORY_CORE_ROWS, original_stage1_count))
            core_rows = list(stage1_rows[:core_n])
            rest_rows = list(stage1_rows[core_n:])
            rotate_n = max(0, FAST_SCAN_FACTORY_ROTATE_ROWS - len(core_rows))
            rotated = []
            if rest_rows and rotate_n > 0:
                start_pos = int(safe_float(FAST_SCAN_STAGE1_CURSOR, 0)) % len(rest_rows)
                for j in range(min(rotate_n, len(rest_rows))):
                    rotated.append(rest_rows[(start_pos + j) % len(rest_rows)])
                FAST_SCAN_STAGE1_CURSOR = (start_pos + rotate_n) % len(rest_rows)
            stage1_rows = core_rows + rotated
            LAST_FAST_FACTORY_SLICE_INFO = {
                "mode": "factory_slice",
                "original": original_stage1_count,
                "used": len(stage1_rows),
                "core": len(core_rows),
                "rotated": len(rotated),
                "cursor": FAST_SCAN_STAGE1_CURSOR,
            }
        else:
            LAST_FAST_FACTORY_SLICE_INFO = {
                "mode": "full_or_small",
                "original": original_stage1_count,
                "used": len(stage1_rows),
                "core": len(stage1_rows),
                "rotated": 0,
                "cursor": int(safe_float(FAST_SCAN_STAGE1_CURSOR, 0)),
            }
        items = []
        started = time.time()
        built_count = 0
        tried_count = 0
        for idx, (ticker, data, _score) in enumerate(stage1_rows, start=1):
            tried_count = idx
            if idx == 1 or idx % FAST_SCAN_BUILD_HEARTBEAT_EVERY == 0:
                try:
                    mark_main_loop_heartbeat(stage="scan_watchlist_fast")
                except Exception:
                    pass
            elapsed_before = time.time() - started
            if elapsed_before >= FAST_SCAN_BUILD_HARD_MAX_SEC:
                _record_fast_scan_budget_event(
                    "fast_scan_hard_break",
                    f"{elapsed_before:.2f}초 제한으로 후보 조립 강제 종료",
                    extra={"tried": idx - 1, "built": built_count, "stage1_limit": stage1_limit, "limit": limit, "factory": LAST_FAST_FACTORY_SLICE_INFO},
                )
                break
            item = _build_fast_scan_item(ticker, data)
            if item and is_fast_scan_factory_keep_candidate(item):
                items.append(item)
                built_count += 1
            elapsed = time.time() - started
            if elapsed >= FAST_SCAN_BUILD_MAX_SEC:
                factory_mode = str((LAST_FAST_FACTORY_SLICE_INFO or {}).get("mode", ""))
                if factory_mode == "factory_slice":
                    _record_fast_scan_budget_event(
                        "fast_scan_cycle_defer",
                        f"{elapsed:.2f}초 예산 도달. 남은 후보는 다음 순환으로 넘김",
                        extra={"tried": idx, "built": built_count, "stage1_limit": stage1_limit, "limit": limit, "factory": LAST_FAST_FACTORY_SLICE_INFO},
                    )
                else:
                    _record_fast_scan_budget_event(
                        "fast_scan_partial_break",
                        f"{elapsed:.2f}초 제한으로 후보 조립 부분 종료",
                        extra={"tried": idx, "built": built_count, "stage1_limit": stage1_limit, "limit": limit, "factory": LAST_FAST_FACTORY_SLICE_INFO},
                    )
                break
            if built_count >= limit:
                break
        if items:
            try:
                queue_slow_ohlcv_prefetch_for_items(items, reason="fast_scan_candidates")
            except Exception:
                pass
            try:
                update_internal_watch_tracking(items, now_ts=time.time())
            except Exception:
                pass
            items = _apply_observation_reeval_queue(items)
            items = _rescue_internal_watch_items(items)
            items = _promote_survivor_user_alerts(items)
            items.sort(
                key=lambda x: (
                    safe_float(x.get("bucket_rank", 0)),
                    3 if str(x.get("alert_grade", "")) == "S" else 2 if str(x.get("alert_grade", "")) == "A" else 1 if str(x.get("alert_grade", "")) == "B" else 0,
                    safe_float(x.get("section_rank", 0)),
                    _fast_rescue_score(x),
                    safe_float(x.get("change_5", 0)),
                ),
                reverse=True,
            )
        append_runtime_event_log(
            "fast_scan_build_done",
            "빠른 후보 조립 완료",
            extra={"tried": tried_count, "built": len(items), "stage1_limit": stage1_limit, "limit": limit, "sec": round(time.time() - started, 3), "factory": LAST_FAST_FACTORY_SLICE_INFO},
        )
        return items[:max(1, limit)]
    finally:
        try:
            fast_scan_build_lock.release()
        except Exception:
            pass

def _short_reset_reason(reason: str) -> str:
    reason = str(reason or "").strip()
    if not reason:
        return ""
    if "시장 캐시" in reason and "정체" in reason:
        return "시장 데이터 갱신이 늦어져 복구함"
    if "유니버스" in reason:
        return "감시 종목 목록 갱신이 늦어져 복구함"
    if "fetch" in reason or "ticker" in reason:
        return "티커/시장 데이터 조회가 늦어져 복구함"
    return reason[:45]


def build_scan_health_warning_text(now_ts: float = None) -> str:
    now_ts = safe_float(now_ts, time.time())
    info = get_scan_runtime_health(now_ts)
    fast = get_fast_scan_state(now_ts)
    lines = []
    fast_age = fast.get("age_sec")
    cache_age = fast.get("cache_age")
    if fast_age is None:
        lines.append("⚠️ 아직 새 후보 기록 없음")
    elif fast_age >= SCAN_HEARTBEAT_WARN_SEC:
        lines.append(f"⚠️ 후보 계산 지연: {fast_age}초째 새 결과 없음")
    if cache_age is not None and cache_age >= FAST_SCAN_DISPLAY_HIDE_SEC:
        lines.append(f"⚠️ 시장 데이터 {cache_age}초 전 → 예전 후보 숨기고 갱신 중")
    elif cache_age is not None and cache_age >= FAST_SCAN_STATE_STALE_SEC:
        lines.append(f"ℹ️ 시장 데이터 {cache_age}초 전 → 새 후보로 교체 중")
    if fast.get("hide_candidates") and not any("예전 후보" in x for x in lines):
        lines.append("🚫 예전 후보 숨김 / 새 데이터 대기")
    refresh_info = get_market_refresh_status(now_ts)
    if refresh_info.get("in_progress"):
        lines.append(f"🔄 시장 데이터 받는 중 ({refresh_info.get('age_sec', 0)}초)")
    if int(safe_float(last_market_refresh_stuck_suppressed, 0)) > 0:
        lines.append(f"ℹ️ market_refresh 지연 자동복구 {int(safe_float(last_market_refresh_stuck_suppressed, 0))}회는 로그 줄임")
    reset_reason = _short_reset_reason(info.get("reset_reason"))
    if reset_reason:
        lines.append(f"🛠 자동복구: {reset_reason}")
    return "\n".join(lines[:4]).strip()

def read_recent_runtime_events(limit: int = 500) -> list:
    try:
        if not os.path.exists(RUNTIME_EVENT_LOG_FILE):
            return []
        with open(RUNTIME_EVENT_LOG_FILE, 'r', encoding='utf-8') as f:
            rows = f.readlines()[-max(1, int(limit)):]
        out = []
        for line in rows:
            try:
                row = json.loads(line)
                if isinstance(row, dict):
                    out.append(row)
            except Exception:
                continue
        return out
    except Exception:
        return []

def summarize_runtime_events_for_scan_health(limit: int = 500) -> dict:
    tags = {}
    for row in read_recent_runtime_events(limit=limit):
        tag = str(row.get('tag', '') or '')
        if not tag:
            continue
        tags[tag] = tags.get(tag, 0) + 1
    return tags

def _parse_runtime_event_ts(ts_text: str):
    try:
        return datetime.strptime(str(ts_text or ""), "%Y-%m-%d %H:%M:%S")
    except Exception:
        return None

def summarize_runtime_events_recent_for_scan_health(window_sec: int = SCAN_HEALTH_RECENT_WINDOW_SEC, limit: int = 1200) -> dict:
    tags = {}
    try:
        now_dt = now_kst().replace(tzinfo=None)
    except Exception:
        now_dt = datetime.now()
    for row in read_recent_runtime_events(limit=limit):
        tag = str(row.get('tag', '') or '')
        if not tag:
            continue
        dt = _parse_runtime_event_ts(row.get('ts', ''))
        if dt is not None and (now_dt - dt).total_seconds() > max(1, int(window_sec)):
            continue
        tags[tag] = tags.get(tag, 0) + 1
    return tags

def _bot_uptime_sec() -> int:
    try:
        return max(0, int(time.time() - safe_float(BOT_START_TS, time.time())))
    except Exception:
        return 0

def _health_level_text(cache_age, fast_age, tags: dict, api: dict, uptime_sec: int = None) -> str:
    uptime_sec = _bot_uptime_sec() if uptime_sec is None else int(uptime_sec)
    if uptime_sec < SCAN_HEALTH_WARMUP_SEC:
        return '🟡 워밍업 중'
    cache_age_val = safe_float(cache_age, -1) if cache_age is not None else -1
    fast_age_val = safe_float(fast_age, -1) if fast_age is not None else -1
    ohlcv_fail = int(tags.get('ohlcv_fail_cooldown', 0))
    partials = int(tags.get('fast_scan_partial_break', 0)) + int(tags.get('cache_partial_break', 0))
    cycle_defer = int(tags.get('fast_scan_cycle_defer', 0))
    rejected = int(safe_float(api.get('api_rejected_count', 0), 0))
    inflight = int(safe_float(api.get('api_inflight', 0), 0))
    active_fail = int(safe_float(api.get('ohlcv_fail_state_active_count', api.get('ohlcv_fail_state_count', 0)), 0))
    active_by_interval = api.get('ohlcv_fail_state_active_by_interval') if isinstance(api.get('ohlcv_fail_state_active_by_interval'), dict) else {}
    active_minute1 = int(safe_float(active_by_interval.get('minute1', 0), 0))
    slow_only_intervals = {'minute60', 'minute240', 'day'}
    active_fast_fail = 0
    try:
        for k, v in active_by_interval.items():
            if str(k).lower() not in slow_only_intervals:
                active_fast_fail += int(safe_float(v, 0))
    except Exception:
        active_fast_fail = active_fail

    data_fresh = (cache_age_val >= 0 and cache_age_val < 15) and (fast_age_val >= 0 and fast_age_val < 20)
    api_ok = rejected < 10 and inflight < API_CALL_MAX_CONCURRENT and ohlcv_fail < 10 and active_fast_fail < 18 and active_minute1 < 12

    if cache_age_val >= 75 or fast_age_val >= 180 or rejected >= 30 or active_fast_fail >= 70 or (inflight >= API_CALL_MAX_CONCURRENT and cache_age_val >= 30):
        return '🔴 심각'
    if active_minute1 >= 20 or active_fast_fail >= 35:
        return '🟠 차트 데이터 불안정'
    if data_fresh and api_ok and (partials >= 5 or cycle_defer >= 4):
        return '🟡 분할 처리 중'
    if cache_age_val >= 30 or fast_age_val >= 60 or ohlcv_fail >= 15 or rejected >= 15 or active_fast_fail >= 20:
        return '⚠️ 느림'
    return '🟢 정상권'

def build_scan_health_text(compact: bool = False) -> str:
    now_ts = time.time()
    info = get_scan_runtime_health(now_ts)
    fast = get_fast_scan_state(now_ts)
    refresh = get_market_refresh_status(now_ts)
    tags = summarize_runtime_events_for_scan_health(limit=700)
    recent_tags = summarize_runtime_events_recent_for_scan_health(window_sec=SCAN_HEALTH_RECENT_WINDOW_SEC, limit=1200)
    api = get_api_bottleneck_snapshot()
    cache_stats = info.get('cache_stats') or {}
    uni_stats = info.get('universe_stats') or {}
    cache_age = fast.get('cache_age') if fast.get('cache_age') is not None else info.get('cache_age')
    if cache_age is None:
        cache_age = get_market_cache_age_for_display(now_ts=now_ts)
    fast_age = fast.get('age_sec') if fast.get('age_sec') is not None else info.get('snapshot_age')
    uptime_sec = _bot_uptime_sec()
    level = _health_level_text(cache_age, fast_age, recent_tags, api, uptime_sec=uptime_sec)
    lines = [
        '🩺 스캔 상태 진단',
        f'- 전체 판단: {level}',
        f'- 가동 시간: {format_elapsed_text(uptime_sec)}' + (' / 캐시 채우는 중' if uptime_sec < SCAN_HEALTH_WARMUP_SEC else ''),
        f'- 시장 데이터: {cache_age}초 전' if cache_age is not None else '- 시장 데이터: 없음',
        f'- 마지막 후보 완성: {fast_age}초 전' if fast_age is not None else '- 마지막 후보 완성: 없음',
        f'- 메인 루프: {info.get("loop_age")}초 전 / 단계 {info.get("stage") or "-"}',
        f'- market_refresh: {"진행 중" if refresh.get("in_progress") else "대기"} / {refresh.get("age_sec", 0)}초 / 사유 {refresh.get("reason") or "-"}',
    ]
    if compact:
        partial_recent = int(recent_tags.get('fast_scan_partial_break', 0)) + int(recent_tags.get('cache_partial_break', 0))
        cycle_recent = int(recent_tags.get('fast_scan_cycle_defer', 0))
        lines += [
            '',
            '[핵심 병목만]',
            f'- OHLCV 실패: 최근 {int(recent_tags.get("ohlcv_fail_cooldown", 0))}건 / 활성 {api.get("ohlcv_fail_state_active_count", 0)}개 / 저장 {api.get("ohlcv_fail_state_count", 0)}개',
            f'- 계획 순환/부분종료: 순환 {cycle_recent}건 / 부분종료 {partial_recent}건 / API 동시 {api.get("api_inflight", 0)}/{API_CALL_MAX_CONCURRENT}',
            f'- timeout: 최근 {int(recent_tags.get("api_call_timeout", 0))}건 / 누적 {api.get("api_timeout_count", 0)}건',
            get_ws_ticker_status_text(),
            get_ws_trade_status_text(),
            get_price_source_stats_text(limit=4),
            '- 본선분리: minute240/day 실패는 실시간 순위·내부감시를 막지 않음',
            f'- 실패원인: ' + (', '.join([f"{ohlcv_reason_label(k)} {v}건" for k, v in (api.get("ohlcv_fail_reason_top") or [])[:3]]) if api.get("ohlcv_fail_reason_top") else '뚜렷한 원인 없음'),
            f'- 캐시: {cache_stats.get("note", "-")} / {cache_stats.get("duration_sec", "-")}초',
            f'- 유니버스: {uni_stats.get("note", "-")} / 현재 {int(safe_float(uni_stats.get("selected",0),0))}개',
            f'- 강세대조 커버리지: 내부캐시 {len(shared_market_cache) if isinstance(shared_market_cache, dict) else 0}개 / 유니버스 {len(market_universe) if isinstance(market_universe, list) else 0}개',
            '- 정밀분석 OHLCV: 출력용 새 조회 차단 / 진짜 후보 검증용만 허용',
            '',
            '[판단]',
        ]
        compact_causes = []
        if cache_age is None or safe_float(cache_age, 999) >= 30:
            compact_causes.append('시장 캐시가 늦음')
        active_fail = int(safe_float(api.get('ohlcv_fail_state_active_count', 0), 0))
        active_by_interval = api.get('ohlcv_fail_state_active_by_interval') if isinstance(api.get('ohlcv_fail_state_active_by_interval'), dict) else {}
        active_minute1 = int(safe_float(active_by_interval.get('minute1', 0), 0))
        if active_minute1 >= 12:
            compact_causes.append('1분봉 조회 실패 많음 → 차트정밀 불안정')
        elif active_fail >= 20:
            compact_causes.append('OHLCV 활성 실패 많음')
        elif int(recent_tags.get('ohlcv_fail_cooldown', 0)) >= 10:
            compact_causes.append('OHLCV 실패 많음/스냅샷 우선')
        if cycle_recent >= 4:
            compact_causes.append('계획 순환 처리 중')
        elif partial_recent >= 4:
            if cache_age is not None and safe_float(cache_age, 999) < 15 and fast_age is not None and safe_float(fast_age, 999) < 20 and int(recent_tags.get('ohlcv_fail_cooldown', 0)) < 10:
                compact_causes.append('정상 분할 처리 중')
            else:
                compact_causes.append('한 루프가 시간 예산 초과')
        if int(safe_float(api.get('api_inflight', 0), 0)) >= API_CALL_MAX_CONCURRENT:
            compact_causes.append('API 슬롯 가득 참')
        if int(safe_float(api.get('slow_prefetch_deferred', 0), 0)) > 0:
            compact_causes.append('상위봉은 느린 큐로 분리 중')
        lines.append('- ' + (' / '.join(compact_causes[:4]) if compact_causes else '큰 병목은 뚜렷하지 않음'))
        lines.append('- 자세히는 /scan_health, 후보 판단은 /review_dump')
        return "\n".join(lines)
    lines += [
        '',
        f'[최근 {int(SCAN_HEALTH_RECENT_WINDOW_SEC/60)}분 병목 신호]',
        f'- OHLCV 실패 cooldown: {int(recent_tags.get("ohlcv_fail_cooldown", 0))}건 / 누적표본 {int(tags.get("ohlcv_fail_cooldown", 0))}건',
        f'- fast scan 계획 순환: {int(recent_tags.get("fast_scan_cycle_defer", 0))}건 / 누적표본 {int(tags.get("fast_scan_cycle_defer", 0))}건',
        f'- fast scan 실제 부분종료: {int(recent_tags.get("fast_scan_partial_break", 0))}건 / 누적표본 {int(tags.get("fast_scan_partial_break", 0))}건',
        f'- cache 부분 종료: {int(recent_tags.get("cache_partial_break", 0))}건 / 누적표본 {int(tags.get("cache_partial_break", 0))}건',
        f'- cache batch skip: {int(recent_tags.get("cache_batch_skip", 0))}건 / 누적표본 {int(tags.get("cache_batch_skip", 0))}건',
        f'- market_refresh 지연/복구: {int(recent_tags.get("market_refresh_target_over",0)) + int(recent_tags.get("market_refresh_stuck_reset",0)) + int(recent_tags.get("market_refresh_hard_restart",0))}건 / 누적표본 {int(tags.get("market_refresh_target_over",0)) + int(tags.get("market_refresh_stuck_reset",0)) + int(tags.get("market_refresh_hard_restart",0))}건',
        '',
        '[API/OHLCV 병목]',
        f'- API 동시 실행: {api.get("api_inflight", 0)}/{API_CALL_MAX_CONCURRENT}',
        f'- API timeout: 최근로그 {int(recent_tags.get("api_call_timeout", 0))}건 / 현재실행 누적 {api.get("api_timeout_count", 0)}건',
        f'- API 바쁨 스킵: 최근로그 {int(recent_tags.get("api_call_rejected_busy", 0))}건 / 현재실행 누적 {api.get("api_rejected_count", 0)}건',
        get_ws_ticker_status_text(),
        get_ws_trade_status_text(),
        f'- OHLCV 진행 중: {api.get("ohlcv_inflight", 0)}개 / 중복 OHLCV 차단 누적: {api.get("ohlcv_dup_skip_count", 0)}',
        f'- OHLCV 실패 상태: 활성 {api.get("ohlcv_fail_state_active_count", 0)}개 / 저장 {api.get("ohlcv_fail_state_count", 0)}개' + (f" / 회로차단 {get_ohlcv_circuit_left()}초" if get_ohlcv_circuit_left() > 0 else ""),
        '- 본선분리: minute240/day 상위봉 실패는 표시만 하고 실시간 순위·내부감시는 계속 진행',
        f'- 상위봉 느린 큐: 대기 {api.get("slow_prefetch_queue_len", 0)} / 성공 {api.get("slow_prefetch_done", 0)} / 실패 {api.get("slow_prefetch_fail", 0)} / fast루프 이관 {api.get("slow_prefetch_deferred", 0)}',
    ]
    active_by_interval = api.get('ohlcv_fail_state_active_by_interval') if isinstance(api.get('ohlcv_fail_state_active_by_interval'), dict) else {}
    if active_by_interval:
        lines.append('- 활성 실패 분봉: ' + ', '.join([f"{k} {v}개" for k, v in sorted(active_by_interval.items(), key=lambda kv: kv[1], reverse=True)[:5]]))
    inflight_rows = api.get('ohlcv_inflight_rows') or []
    if inflight_rows:
        lines.append(f'- 진행 중 OHLCV: {", ".join(inflight_rows[:6])}')
    fail_intervals = api.get('ohlcv_fail_interval_top') or []
    if fail_intervals:
        lines.append('- 실패 많은 분봉: ' + ', '.join([f"{k} {v}건" for k, v in fail_intervals[:5]]))
    fail_tickers = api.get('ohlcv_fail_ticker_top') or []
    if fail_tickers:
        lines.append('- 실패 많은 종목: ' + ', '.join([f"{k} {v}건" for k, v in fail_tickers[:5]]))
    fail_reasons = api.get('ohlcv_fail_reason_top') or []
    if fail_reasons:
        lines.append('- 실패 원인 상위: ' + ', '.join([f"{_normalize_data_fail_reason(k)} {v}건" for k, v in fail_reasons[:5]]))
    caller_rows = api.get('ohlcv_caller_top') or []
    if caller_rows:
        parts = []
        for caller, row in caller_rows[:5]:
            bad = int(safe_float(row.get("timeout",0),0)) + int(safe_float(row.get("exception",0),0)) + int(safe_float(row.get("empty",0),0))
            parts.append(f"{caller} {int(safe_float(row.get('count',0),0))}회/실패 {bad}")
        lines.append("- OHLCV 호출자 상위: " + ", ".join(parts))
    defer_intervals = api.get('ohlcv_defer_interval_top') or []
    if defer_intervals:
        lines.append('- 빠른루프에서 넘긴 상위봉: ' + ', '.join([f"{k} {v}건" for k, v in defer_intervals[:5]]))
    if api.get('slow_prefetch_last_item'):
        lines.append(f'- 느린 큐 마지막: {api.get("slow_prefetch_last_item")} / {api.get("slow_prefetch_last_result") or "-"}')
    lines += [
        '',
        '[최근 갱신 결과]',
        f'- 캐시: 시도 {int(safe_float(cache_stats.get("tried",0),0))} / 성공 {int(safe_float(cache_stats.get("success",0),0))} / 유지 {int(safe_float(cache_stats.get("kept",0),0))} / {cache_stats.get("duration_sec", "-")}초 / {cache_stats.get("note", "-")}',
        f'- 유니버스: 시도 {int(safe_float(uni_stats.get("tried",0),0))} / 성공 {int(safe_float(uni_stats.get("success",0),0))} / 현재 {int(safe_float(uni_stats.get("selected",0),0))} / {uni_stats.get("duration_sec", "-")}초 / {uni_stats.get("note", "-")}',
        f'- 강세대조 커버리지: 내부캐시 {len(shared_market_cache) if isinstance(shared_market_cache, dict) else 0}개 / 유니버스 {len(market_universe) if isinstance(market_universe, list) else 0}개 / 목표 {max(UNIVERSE_COLD_START_TARGET, CACHE_COLD_START_TARGET, 20)}개',
        f'- 빠른스캔 공장라인: {LAST_FAST_FACTORY_SLICE_INFO.get("used", "-")}/{LAST_FAST_FACTORY_SLICE_INFO.get("original", "-")}개 처리 / 핵심 {LAST_FAST_FACTORY_SLICE_INFO.get("core", "-")} + 회전 {LAST_FAST_FACTORY_SLICE_INFO.get("rotated", "-")}',
        '- 정밀분석 OHLCV: 출력용 새 조회 차단 / 진짜 후보 검증용만 허용',
        '',
        '[역할 분리 상태]',
        '- 시장 스냅샷 직원: 현재가를 먼저 넓게 쌓고, OHLCV는 진짜 후보 검증용으로만 제한',
        f'- 스냅샷 상태: {LIGHT_SNAPSHOT_LAST_NOTE} / 최근 {LIGHT_SNAPSHOT_LAST_UPDATED}/{LIGHT_SNAPSHOT_LAST_TRIED}개 갱신 / 대상 {LIGHT_SNAPSHOT_LAST_SOURCE_SIZE}개',
        '- 빠른 스캔: 넓게 발견만 담당. 핵심 후보는 매번 보고, 나머지는 회전 처리',
        '- 정밀분석 직원: 진짜 후보만 OHLCV/차트정교화로 검증하고, 출력/리뷰는 저장값만 읽음',
        '- 상위봉 직원: 4시간/일봉 등 무거운 정보는 느린 큐에서 캐시로 채움',
        '- 명령어: 새 스캔을 돌리지 않고 저장된 스냅샷만 읽음',
        '',
        '[원인 해석]',
    ]
    causes = []
    if cache_age is None or safe_float(cache_age, 999) >= 30:
        causes.append('시장 캐시가 30초 기준을 넘김 → 후보 표시 지연/보류 가능')
    if int(recent_tags.get('ohlcv_fail_cooldown', 0)) >= 10:
        reason_hint = ''
        fail_reasons = api.get('ohlcv_fail_reason_top') or []
        if fail_reasons:
            reason_hint = ' / 주원인: ' + _normalize_data_fail_reason(str(fail_reasons[0][0]))
        causes.append('OHLCV 실패가 많음 → 빠른 감지는 스냅샷으로 우회하고, OHLCV는 검증용으로만 제한' + reason_hint)
    if int(recent_tags.get('fast_scan_cycle_defer', 0)) >= 3:
        causes.append('계획 순환 처리 중 → 핵심 후보는 먼저 보고 남은 후보는 다음 차수로 넘김')
    elif int(recent_tags.get('fast_scan_partial_break', 0)) + int(recent_tags.get('cache_partial_break', 0)) >= 4:
        if cache_age is not None and safe_float(cache_age, 999) < 15 and fast_age is not None and safe_float(fast_age, 999) < 20 and int(recent_tags.get('ohlcv_fail_cooldown', 0)) < 10:
            causes.append('부분 종료는 있지만 시장 데이터/후보는 최신 → 감지는 유지됨')
        else:
            causes.append('실제 부분종료 반복 → 처리 예산/후보 조립 단계 재점검 필요')
    if int(safe_float(api.get('api_inflight', 0), 0)) >= API_CALL_MAX_CONCURRENT:
        causes.append('API 동시 실행 슬롯이 가득 참 → pybithumb 응답 지연/중복 호출 누적 의심')
    if int(safe_float(api.get('slow_prefetch_deferred', 0), 0)) > 0:
        causes.append('상위봉/day 조회를 빠른 루프에서 분리 중 → 빠른 후보는 먼저 만들고 상위봉은 느린 캐시에 채움')
    if int(safe_float(api.get('slow_prefetch_queue_len', 0), 0)) >= 20:
        causes.append('상위봉 느린 큐가 많이 쌓임 → 정밀분석/상위봉 확인이 뒤로 밀릴 수 있음')
    if not causes:
        causes.append('큰 병목은 아직 뚜렷하지 않음. 후보 품질은 review_dump로 확인')
    lines += [f'- {c}' for c in causes[:6]]
    lines += [
        '',
        '[운영 원칙]',
        '- 이 명령어는 새 전체 스캔을 돌리지 않고 저장된 상태/로그만 읽음',
        '- 느리다고 바로 조건을 조이지 말고, 병목 단계부터 확인',
        '- 자세한 후보 판단은 /review_dump에서 확인',
    ]
    return "\n".join(lines)

def scan_health_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    try:
        send_cached_or_build_command("scan_health", build_scan_health_cached_text, prefix='', reply_markup=None, cache_keyboard=False, limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        send(f"⚠️ 스캔 진단 에러: {e}")


def get_scan_debug_candidates():
    """텔레그램 표시용 후보 조회.

    v2.5.147 원칙:
    - /status, /scan_debug, /review_dump가 모두 같은 최신 fast-scan 표시 스냅샷을 본다.
    - 여기서는 절대 새 스캔을 돌리지 않는다.
    - 내부 스캔 생산자가 저장해 둔 마지막 완성 스냅샷만 소비한다.
    """
    display = get_latest_scan_display_state(limit=3)
    return display.get("results", []), display.get("note", "")


def get_latest_scan_display_state(now_ts: float = None, limit: int = 3) -> dict:
    """현재 텔레그램에 보여줄 fast-scan 스냅샷을 한 곳에서만 만든다.

    이 함수가 v2.5.147의 스냅샷 단일 기준이다.
    /status, /scan_debug, /review_dump가 따로따로 오래된 결과를 읽지 않도록 한다.
    """
    now_ts = safe_float(now_ts, time.time())
    fast = get_fast_scan_state(now_ts)
    items = list(fast.get('items') or [])
    age_sec = fast.get('age_sec')
    cache_age = fast.get('cache_age')
    stage = str(fast.get('stage', '') or '')
    hide_candidates = bool(fast.get('hide_candidates', False))
    results = []
    note = ''
    if items and not hide_candidates:
        results = items
        age_text = '방금 고른 후보 기준' if age_sec is None else f'마지막 완성 후보 {age_sec}초 전 기준'
        cache_text = ''
        if cache_age is not None:
            cache_text = f' / 시장 데이터 {cache_age}초 전'
        state_text = ''
        if age_sec is not None and age_sec >= FAST_SCAN_CONSUMER_WARN_SEC:
            state_text = ' / 내부 스캔은 새 후보 갱신 중'
        if market_refresh_in_progress:
            state_text += ' / 시장 데이터 받는 중'
        note = age_text + cache_text + state_text
    elif items and hide_candidates:
        results = []
        cache_part = f'시장 데이터 {int(cache_age)}초 전' if cache_age is not None else '시장 데이터 오래됨'
        age_part = f'마지막 완성 후보 {int(age_sec)}초 전' if age_sec is not None else '마지막 후보 있음'
        note = f'{age_part} / {cache_part} / 최신성 부족이라 후보 표시는 보류하고 새 데이터 받는 중'
    else:
        results = []
        if market_refresh_in_progress:
            note = '아직 완성된 후보 스냅샷은 없고, 내부 스캔이 시장 데이터를 받는 중이야'
        elif stage:
            note = f'아직 완성된 후보 스냅샷은 없어. 내부 스캔 단계: {stage}'
        else:
            note = '아직 완성된 후보 스냅샷이 없어'
    try:
        shortlist, user_items, internal_items, discard_items = get_scan_debug_display_shortlist(results, limit=limit) if results else ([], [], [], [])
    except Exception:
        shortlist, user_items, internal_items, discard_items = [], [], [], []
    return {
        'results': results,
        'note': note,
        'fast': fast,
        'age_sec': age_sec,
        'cache_age': cache_age,
        'stage': stage,
        'hide_candidates': hide_candidates,
        'shortlist': shortlist,
        'user_items': user_items,
        'internal_items': internal_items,
        'discard_items': discard_items,
        'created_ts': now_ts,
    }


def format_scan_display_state_line(display: dict) -> str:
    display = display if isinstance(display, dict) else {}
    note = str(display.get('note', '') or '').strip()
    if note:
        return note
    age_sec = display.get('age_sec')
    cache_age = display.get('cache_age')
    parts = []
    if age_sec is not None:
        parts.append(f'마지막 완성 후보 {int(age_sec)}초 전 기준')
    if cache_age is not None:
        parts.append(f'시장 데이터 {int(cache_age)}초 전')
    return ' / '.join(parts) if parts else '현재 스캔 상태 확인중'


def _scan_candidate_strength_texts(item: dict) -> list[str]:
    strengths = []
    change_5 = safe_float(item.get('change_5', 0), 0)
    vol_ratio = safe_float(item.get('vol_ratio', 0), 0)
    from_low = safe_float(item.get('from_low', 0), 0)
    below_high = safe_float(item.get('below_high', 999), 999)
    keep5 = int(safe_float(item.get('turnover_keep_bars_5', 0), 0))
    keep10 = int(safe_float(item.get('turnover_keep_bars_10', 0), 0))
    re_score = safe_float(item.get('rebreakout_score', item.get('rebreakout_prep_score', 0)), 0)
    if change_5 >= 0.35:
        strengths.append(f'5분 흐름 {change_5:+.2f}%')
    if vol_ratio >= 2.0:
        if _fast_actual_turnover_tier(item) in {'normal', 'strong'}:
            strengths.append(f'거래량 {vol_ratio:.2f}배')
        else:
            strengths.append('거래량 배수는 높지만 실제 돈은 작음')
    if 0.25 <= from_low <= 2.20:
        strengths.append(f'저점에서 {from_low:.2f}% 회복')
    if below_high >= 1.20 and below_high < 900:
        strengths.append(f'고점까지 {below_high:.2f}% 여유')
    if keep5 >= 2 or keep10 >= 3:
        strengths.append('거래대금 유지 괜찮음')
    lifecycle_code = str(item.get('chart_lifecycle_code', '') or '').strip()
    lifecycle_early = safe_float(item.get('chart_lifecycle_early_score', 0), 0)
    lifecycle_restart = safe_float(item.get('chart_lifecycle_restart_score', 0), 0)
    current_candle_code = str(item.get('current_candle_code', '') or '').strip()
    current_candle_live = safe_float(item.get('current_candle_live_score', 0), 0)
    if current_candle_code in {'LIVE_UP', 'LIVE_UP_STRONG', 'LIVE_UP_WEAK'} or current_candle_live >= CURRENT_CANDLE_V2_LIVE_WEAK_SCORE:
        strengths.append('현재봉 살아나는 중')
    if current_candle_code in {'LOWER_RECLAIM', 'LOWER_RECLAIM_STRONG', 'LOWER_RECLAIM_WEAK'} or bool(item.get('current_candle_lower_reclaim', False)):
        strengths.append('현재봉 아랫꼬리 회복')
    if lifecycle_code == 'EARLY_GOOD' or lifecycle_early >= 2.55:
        strengths.append('차트상 초입 구조')
    if lifecycle_code == 'RESTART_GOOD' or lifecycle_restart >= 2.65:
        strengths.append('차트상 재출발 구조')
    if bool(item.get('near_high_rebreakout_watch', False)):
        strengths.append('재돌파 대기 구조')
    elif re_score >= 1.4:
        strengths.append('고점 다시도전 힘 있음')
    prep_label = format_prebreakout_simple_label(item)
    if prep_label in {'고점 전 준비 좋음', '고점 전 준비 보통'}:
        strengths.append(prep_label)
    htf_text = format_htf_position_simple_text(item)
    if htf_text and any(x in htf_text for x in ['바닥', '중단', '저점 높임', '반등 1일차', '반등 2일차']):
        strengths.append(htf_text)
    return strengths


def _scan_candidate_risk_texts(item: dict) -> list[str]:
    risks = []
    change_5 = safe_float(item.get('change_5', 0), 0)
    vol_ratio = safe_float(item.get('vol_ratio', 0), 0)
    from_low = safe_float(item.get('from_low', 0), 0)
    below_high = safe_float(item.get('below_high', 999), 999)
    recovery_speed = safe_float(item.get('recovery_speed_pct', 0), 0)
    one_liner = str(item.get('one_liner', '') or '')
    if bool(item.get('ultra_low_tick_noise_block', False)):
        risks.append('초저가 틱 잡음형이라 실전 제외')
    if bool(item.get('flash_low_liquidity_near_high_block', False)):
        risks.append('고점 바로 앞 반짝형이라 알림 보류')
    if bool(item.get('low_actual_turnover_flag', False)) and vol_ratio >= 4.0:
        risks.append('거래량 배수 대비 실제 거래대금 작음')
    lifecycle_code = str(item.get('chart_lifecycle_code', '') or '').strip()
    lifecycle_late = safe_float(item.get('chart_lifecycle_late_score', 0), 0)
    current_candle_code = str(item.get('current_candle_code', '') or '').strip()
    current_candle_pressure = safe_float(item.get('current_candle_pressure_score', 0), 0)
    current_candle_hard_pressure = bool(item.get('current_candle_hard_pressure', False))
    current_candle_soft_pressure = bool(item.get('current_candle_soft_pressure', False))
    if current_candle_hard_pressure:
        risks.append('현재봉 강한 위꼬리/밀림')
    elif current_candle_soft_pressure or current_candle_pressure >= CURRENT_CANDLE_PRESSURE_SCORE_BLOCK or current_candle_code in {'UPPER_WICK_DUMP', 'CLOSING_WEAK'}:
        risks.append('현재봉 약한 위꼬리/밀림')
    if lifecycle_code == 'LATE_CHASE' or lifecycle_late >= CHART_LIFE_LATE_SCORE_BLOCK:
        risks.append('차트상 늦은 추격권')
    if bool(item.get('late_high_volatility_block', False)):
        risks.append('이미 크게 튄 뒤 고점권 흔들림')
    elif bool(item.get('near_high_rebreakout_watch', False)):
        risks.append('재돌파 확인 전이라 알림 보류')
    elif 0 <= below_high <= 0.75:
        risks.append('고점이 너무 가까움')
    if change_5 <= 0.0:
        risks.append('5분 흐름이 아직 약함')
    if vol_ratio < 1.0 and not bool(item.get('late_high_volatility_block', False)):
        risks.append('거래량이 아직 약함')
    if from_low <= 0.15:
        risks.append('저점 반등이 아직 얕음')
    if recovery_speed <= 0.05:
        risks.append('다시 붙는 속도가 느림')
    if '지금 사기엔 별로' in one_liner:
        risks.append('실전 진입감은 아직 약함')
    prep_label = format_prebreakout_simple_label(item)
    if prep_label == '고점 전 힘 약함':
        risks.append('고점 전 준비가 아직 약함')
    htf_gap = safe_float(item.get('htf_gap_pct', 999), 999)
    daily_gap = safe_float(item.get('daily_gap_pct', 999), 999)
    if htf_gap >= 900 or daily_gap >= 900:
        risks.append('상위봉 데이터 확인 필요')
    return risks


def _format_scan_candidate_price_line(item: dict) -> str:
    snap = item.get('pre_alert_snapshot', {}) if isinstance(item.get('pre_alert_snapshot'), dict) else {}
    current_price = safe_float(item.get('price', item.get('current_price', 0)), 0)
    high30 = safe_float(snap.get('recent_30m_high', item.get('recent_30m_high', 0)), 0)
    low30 = safe_float(snap.get('recent_30m_low', item.get('recent_30m_low', 0)), 0)
    if high30 > 0 and low30 > 0 and current_price > 0:
        return f"- 기준값: 30분 고점 {fmt_price(high30)} / 저점 {fmt_price(low30)} / 현재 {fmt_price(current_price)}"
    return ''


def _format_scan_candidate_chart_core(item: dict) -> str:
    quant = str(item.get('chart_quant_label', '차트 확인중') or '차트 확인중')
    defense = safe_float(item.get('low_zone_defense_score', item.get('recovery_quality_score', 0)), 0)
    persist = safe_float(item.get('turnover_persistence_score', 0), 0)
    flash = format_turnover_flash_label(safe_float(item.get('turnover_flash_score', 0), 0))
    attempts = int(safe_float(item.get('rebreakout_attempts', 0), 0))
    re_score = safe_float(item.get('rebreakout_score', item.get('rebreakout_prep_score', 0)), 0)
    retry_text = f'고점 다시도전 힘 {re_score:.2f}' if attempts > 0 else f'고점 다시도전 준비 {re_score:.2f}'
    current_candle_label = str(item.get('current_candle_label', '') or '').strip()
    if current_candle_label:
        candle_text = f'현재봉 {current_candle_label}'
    else:
        candle_text = '현재봉은 아직 힘이 약함' if is_chart_current_candle_uninformative(item) else '현재봉은 조금 살아 있음'
    prep_text = format_prebreakout_simple_label(item)
    htf_text = format_htf_position_simple_text(item)
    near_type = str(item.get('near_high_quality_type', '') or '').strip()
    if near_type:
        quant = near_type
    tail = [quant, f'저점 버틴 힘 {defense:.2f}', f'돈이 계속 붙는 힘 {persist:.2f}', retry_text, prep_text, flash, candle_text]
    if htf_text:
        tail.append(htf_text)
    return "- 차트 핵심: " + " / ".join([x for x in tail if str(x).strip()])


def _append_scan_item_layout(lines: list, idx: int, item: dict, icon: str = '👀', detailed: bool = False):
    bucket = str(item.get('alert_bucket', '') or '')
    user_label = str(item.get('user_label_text', item.get('label_text', '후보')) or '후보')
    grade = str(item.get('alert_grade', 'B') or 'B')
    status_label = '바로 볼 후보' if bucket == 'user_alert' else '조금 더 볼 후보'
    lines.append('')
    lines.append(highlight_line(idx, item.get('ticker', '?'), icon))
    lines.append(f"- 지금 상태: {status_label} / {user_label} / 등급 {grade}")
    one_liner = str(item.get('one_liner', '') or '').strip()
    if one_liner:
        lines.append(f"- 한줄 판단: {one_liner}")
    lines.append(
        f"- 핵심 흐름: 5분 {safe_float(item.get('change_5',0)):+.2f}% / 거래량 {safe_float(item.get('vol_ratio',0)):.2f}배 / 최근 5분 거래대금 {format_money_or_tiny(item.get('turnover_5m', 0))}"
    )
    lines.append(
        f"- 위치: 30분 저점대비 {safe_float(item.get('from_low',0),0):+.2f}% / {format_fast_scan_high_gap_text(safe_float(item.get('below_high',999),999))}"
    )
    strengths = _scan_candidate_strength_texts(item)
    risks = _scan_candidate_risk_texts(item)
    if strengths:
        lines.append(f"- 좋은 점: {' / '.join(strengths[:3])}")
    if risks:
        lines.append(f"- 아쉬운 점: {' / '.join(risks[:3])}")
    price_line = _format_scan_candidate_price_line(item)
    if detailed and price_line:
        lines.append(price_line)
    lines.append(_format_scan_candidate_chart_core(item))


def build_scan_debug_text():
    now_ts = time.time()
    display = get_latest_scan_display_state(now_ts=now_ts, limit=3)
    lines = ['🔎 지금 볼 후보 보기']
    health_warning = build_scan_health_warning_text(now_ts)
    if health_warning:
        lines.append(health_warning)
    note = format_scan_display_state_line(display)
    hide_candidates = bool(display.get('hide_candidates', False))
    results = list(display.get('results') or [])
    if hide_candidates:
        lines.append(f'안내: {note}')
        lines.append('')
        lines.append('지금 볼 후보 없음')
        return "\n".join(lines)
    if not results:
        lines.append(f'안내: {note}')
        lines.append('')
        lines.append('지금 볼 후보 없음')
        return "\n".join(lines)
    lines.append(f'안내: {note}')
    user_items = list(display.get('user_items') or [])
    internal_items = list(display.get('internal_items') or [])
    discard_items = list(display.get('discard_items') or [])
    display_internal_items = [x for x in internal_items if not is_scan_debug_overblocked_candidate(x)]
    if not display_internal_items:
        display_internal_items = list(internal_items)
    def append_group(title: str, rows, icon: str):
        if not rows:
            return
        lines.append('')
        lines.append(title)
        for i, item in enumerate(rows[:3], 1):
            _append_scan_item_layout(lines, i, item, icon=icon, detailed=True)
    append_group('🌱 바로 볼 후보', user_items, '🔥')
    append_group('👀 조금 더 볼 후보', display_internal_items, '👀')
    hidden_count = len(discard_items)
    if hidden_count:
        lines.append('')
        lines.append(f'🙈 내부에서만 넘긴 후보 {hidden_count}개 (평소엔 숨김)')
    return "\n".join(lines)


def append_debug_shortlist_parts(parts: list):
    try:
        display = get_latest_scan_display_state(limit=3)
        note = format_scan_display_state_line(display)
        header = '🔎 지금 확인할 상위 후보'
        if note:
            header += f' ({note})'
        results = list(display.get('results') or [])
        if not results:
            parts.append(header + '\n\n- 지금은 올릴 만한 후보 없음')
            return
        shortlist = list(display.get('shortlist') or [])
        discard_items = list(display.get('discard_items') or [])
        lines = [header]
        if not shortlist:
            hidden_count = len(discard_items)
            watch_count = len(display.get('internal_items') or [])
            lines.append('- 알림 보낼 후보 없음')
            if watch_count:
                lines.append(f'- 관찰 후보 {watch_count}개 있음')
            if hidden_count:
                lines.append(f'- 내부에서 넘긴 후보 {hidden_count}개 (평소엔 숨김)')
            parts.append("\n".join(lines))
            return
        for idx, item in enumerate(shortlist, 1):
            bucket = str(item.get('alert_bucket', '') or '')
            icon = '🔥' if bucket == 'user_alert' else '👀'
            _append_scan_item_layout(lines, idx, item, icon=icon, detailed=False)
        hidden_count = len(discard_items)
        if hidden_count:
            lines.append('')
            lines.append(f'🙈 내부에서 넘긴 후보 {hidden_count}개 (평소엔 숨기고 놓쳤을 때만 이유 확인)')
        parts.append("\n".join(lines))
    except Exception as e:
        parts.append(f'⚠️ 상위 후보 표시 에러: {e}')


def _build_fast_alert_signature(item: dict) -> str:
    ticker = str(item.get('ticker', '') or '')
    grade = str(item.get('alert_grade', '') or '')
    bucket = str(item.get('alert_bucket', '') or '')
    label = str(item.get('label_text', '') or '')
    reasons = list(item.get('reasons', [])) if isinstance(item.get('reasons'), list) else []
    key_reasons = tuple(sorted(str(x).strip() for x in reasons[:2] if str(x).strip()))
    turnover_bin = int(safe_float(item.get('turnover_5m', 0), 0) // 10000000)
    vol_bin = int(safe_float(item.get('vol_ratio', 0), 0) // 1.5)
    score_bin = int(safe_float(item.get('lite_score', 0), 0) // 5)
    return f"{ticker}|{grade}|{bucket}|{label}|{turnover_bin}|{vol_bin}|{score_bin}|{'/'.join(key_reasons)}"


def _fast_alert_has_meaningful_upgrade(prev: dict, item: dict) -> bool:
    if not isinstance(prev, dict) or not prev:
        return True
    grade_rank = {'C': 0, 'B': 1, 'A': 2, 'S': 3}
    prev_grade = str(prev.get('grade', '') or '')
    now_grade = str(item.get('alert_grade', '') or '')
    if grade_rank.get(now_grade, 0) > grade_rank.get(prev_grade, 0) and now_grade == 'S':
        return True
    prev_label = str(prev.get('label_text', '') or '')
    now_label = str(item.get('label_text', '') or '')
    if prev_label != now_label and grade_rank.get(now_grade, 0) > grade_rank.get(prev_grade, 0):
        return True
    prev_price = safe_float(prev.get('price', 0), 0)
    now_price = safe_float(item.get('price', 0), 0)
    prev_turn = safe_float(prev.get('turnover_5m', 0), 0)
    now_turn = safe_float(item.get('turnover_5m', 0), 0)
    prev_score = safe_float(prev.get('lite_score', 0), 0)
    now_score = safe_float(item.get('lite_score', 0), 0)
    if prev_price > 0 and abs((now_price - prev_price) / prev_price) * 100.0 >= FAST_SCAN_ALERT_REPEAT_PRICE_MOVE_PCT:
        if (now_score - prev_score) >= max(FAST_SCAN_ALERT_REPEAT_SCORE_JUMP - 1.0, 4.5) or (prev_turn > 0 and now_turn > prev_turn * 1.55):
            return True
    if prev_turn > 0 and (now_turn / prev_turn) >= 1.85 and now_score >= prev_score + 2.6:
        return True
    if (now_score - prev_score) >= FAST_SCAN_ALERT_REPEAT_SCORE_JUMP and (prev_turn <= 0 or now_turn > prev_turn * 1.20):
        return True
    prev_vol = safe_float(prev.get('vol_ratio', 0), 0)
    now_vol = safe_float(item.get('vol_ratio', 0), 0)
    if (now_vol - prev_vol) >= FAST_SCAN_ALERT_REPEAT_VOL_JUMP and (prev_turn <= 0 or now_turn > prev_turn * 1.45) and now_score >= prev_score + 2.0:
        return True
    return False


def _send_fast_scan_alerts(items, now_ts: float):
    """실제 fast-scan 알림 전송.

    v2.5.155 핵심:
    - '사용자 알림' 판정이 났다는 이유만으로 최근 알림/미스 복기에 alert_sent=True를 먼저 찍지 않는다.
    - 실제 Telegram 전송 성공 후에만 user_alert_sent로 기록한다.
    - 전송 직전 차단/전송 실패는 alert_blocked + 차단 사유로 남긴다.
    """
    sent = 0
    for item in items:
        if sent >= FAST_SCAN_ALERT_LIMIT:
            break
        if str(item.get('alert_bucket', '')) != 'user_alert':
            continue
        if str(item.get('alert_grade', '')) not in {'S', 'A'}:
            continue
        ticker = str(item.get('ticker', '') or '').upper().strip()
        if not ticker or ticker in active_positions or is_watch_excluded_ticker(ticker):
            continue
        type_key = str(item.get('primary_reason', '') or '')
        key = f'{ticker}:{type_key}'
        sig = _build_fast_alert_signature(item)
        prev = recent_fast_alert_signatures.get(key, {})
        last_ts = safe_float(prev.get('ts', 0), 0) if isinstance(prev, dict) else 0
        last_sig = str(prev.get('sig', '')) if isinstance(prev, dict) else ''
        if (now_ts - last_ts) < FAST_SCAN_ALERT_COOLDOWN_SEC:
            if sig == last_sig and not _fast_alert_has_meaningful_upgrade(prev, item):
                continue
            if not _fast_alert_has_meaningful_upgrade(prev, item):
                continue
        recent_signal_key = f'{ticker}:{type_key}'
        last = safe_float(recent_signal_alerts.get(recent_signal_key, 0), 0)
        if (now_ts - last) < FAST_SCAN_ALERT_COOLDOWN_SEC and not _fast_alert_has_meaningful_upgrade(prev, item):
            continue

        final_gate_reason_v227 = get_user_alert_final_gate_block_reason_v227(item, section=str(item.get('section', '') or ''), primary_reason=str(item.get('primary_reason', '') or ''))
        if final_gate_reason_v227:
            block = '알림 직전 차단: ' + final_gate_reason_v227
            append_reverse_trace(item, stage='alert_blocked', extra_reason=block, now_ts=now_ts)
            try:
                register_missed_review_candidate(item, now_ts=now_ts, seen_market=True, seen_shortlist=True, seen_signal=True, alert_sent=False, alert_section='blocked', quality_block_reason=block)
            except Exception:
                pass
            continue

        grade = str(item.get('alert_grade','A') or 'A')
        label_text = str(item.get('label_text','후보') or '후보')
        user_label_text = str(item.get('user_label_text', label_text) or label_text)
        one_liner = str(item.get('one_liner','') or '지금은 흐름만 확인')
        if any(word in one_liner for word in ['지금 사기엔 별로', '구경만', '실전 진입감은 약함']) and str(item.get('alert_bucket', '')) == 'user_alert':
            block = '알림 직전 차단: 한줄 판단이 약함'
            append_reverse_trace(item, stage='alert_blocked', extra_reason=block, now_ts=now_ts)
            try:
                register_missed_review_candidate(item, now_ts=now_ts, seen_market=True, seen_shortlist=True, seen_signal=True, alert_sent=False, alert_section='blocked', quality_block_reason=block)
            except Exception:
                pass
            continue

        prepared_item = dict(item)
        prepared_item.setdefault('ticker', ticker)
        prepared_item.setdefault('current_price', safe_float(item.get('price', 0), 0))
        prepared_item.setdefault('strategy_label', user_label_text)
        prepared_item.setdefault('below_30m_high_pct', safe_float(item.get('below_high', 999), 999))
        prepared_item.setdefault('chg_5m', safe_float(item.get('change_5', 0), 0))
        prepared_item.setdefault('chg_30m', safe_float(item.get('change_30', 0), 0))
        prepared_item.setdefault('from_30m_low_pct', safe_float(item.get('from_low', 0), 0))
        prepared_item.setdefault('judgement_text', one_liner)
        prepared_item.setdefault('pre_alert_snapshot', item.get('pre_alert_snapshot', {}) if isinstance(item.get('pre_alert_snapshot'), dict) else {})
        header_text = str(item.get('alert_header_text', '') or get_fast_scan_alert_header_text(str(item.get('primary_reason', '') or '')))
        ref_id = make_price_check_ref(prepared_item, alert_type='fast_scan', source_label=header_text, judgement_text=one_liner)
        msg = ''.join([
            f"{header_text}\n"
            f"━━━━━━━━━━\n"
            f"{bold_number_badge(1)} {bold_ticker_text(ticker)}\n\n"
            f"- 구분/등급: {user_label_text} / {grade}\n"
            f"- 현재가: {fmt_price(item.get('price', 0))}\n"
            f"- 5분 상승: {safe_float(item.get('change_5',0)):.2f}%\n"
            f"- 15분/30분/60분: {safe_float(item.get('change_15',0)):+.2f}% / {safe_float(item.get('change_30',0)):+.2f}% / {safe_float(item.get('change_60',0)):+.2f}%\n"
            f"- 거래량: {safe_float(item.get('vol_ratio',0)):.2f}배\n"
            f"- 시장주목도: {safe_float(item.get('leader_score',0)):.2f}\n"
            f"- 최근 5분 거래대금: {fmt_price(item.get('turnover_5m', 0))}\n"
            f"- 30분 저점대비: {safe_float(item.get('from_low',0),0):+.2f}%\n"
            f"- 최근고점 거리: {format_fast_scan_high_gap_text(safe_float(item.get('below_high',999),999))}\n"
            f"- 한줄평: {one_liner}\n"
            f"- 판단: {' / '.join(item.get('reasons', [])[:3])}"
        ])
        markup = build_fast_scan_alert_markup(ticker, ref_id=ref_id)
        sent_msg = send(msg, reply_markup=markup)
        if sent_msg and getattr(sent_msg, 'message_id', None):
            PRICE_CHECK_REFS[ref_id]['root_message_id'] = sent_msg.message_id
            schedule_fast_scan_auto_check(ref_id, CHAT_ID, target_min=30, now_ts=now_ts)
            persist_price_check_state()
            recent_signal_alerts[recent_signal_key] = now_ts
            recent_fast_alert_signatures[key] = {
                'ts': now_ts,
                'sig': sig,
                'grade': str(item.get('alert_grade', '') or ''),
                'price': safe_float(item.get('price', 0), 0),
                'lite_score': safe_float(item.get('lite_score', 0), 0),
                'vol_ratio': safe_float(item.get('vol_ratio', 0), 0),
                'turnover_5m': safe_float(item.get('turnover_5m', 0), 0),
                'label_text': str(item.get('label_text', '') or ''),
            }
            append_reverse_trace(item, stage='user_alert_sent', extra_reason=str(item.get('primary_reason', '') or '빠른 후보 알림'), now_ts=now_ts)
            try:
                register_missed_review_candidate(item, now_ts=now_ts, seen_market=True, seen_shortlist=True, seen_signal=True, alert_sent=True, alert_section='live', quality_block_reason='실제 텔레그램 알림 전송 성공')
            except Exception:
                pass
            sent += 1
        else:
            block = '사용자 알림 판정 후 텔레그램 전송 실패/응답 없음'
            append_reverse_trace(item, stage='alert_blocked', extra_reason=block, now_ts=now_ts)
            try:
                register_missed_review_candidate(item, now_ts=now_ts, seen_market=True, seen_shortlist=True, seen_signal=True, alert_sent=False, alert_section='blocked', quality_block_reason=block)
            except Exception:
                pass


def _register_fast_scan_items_for_missed_review(items, now_ts: float):
    if not items:
        return
    changed = False
    for item in list(items)[:max(FAST_SCAN_RESULT_MAX, 10)]:
        try:
            bucket = str(item.get('alert_bucket', '') or '')
            block_reason = ''
            if bucket != 'user_alert':
                one_liner = str(item.get('one_liner', '') or '').strip()
                reasons = list(item.get('reasons', [])) if isinstance(item.get('reasons'), list) else []
                block_reason = one_liner or ' / '.join([str(x).strip() for x in reasons[:3] if str(x).strip()])
            key = str(item.get('ticker', '') or '').upper()
            before = dict(missed_review_queue.get(key, {})) if isinstance(missed_review_queue.get(key), dict) else None
            pre_send_candidate = bool(bucket == 'user_alert' and str(item.get('alert_grade', '')) in {'S', 'A'})
            register_missed_review_candidate(
                item,
                now_ts=now_ts,
                seen_market=True,
                seen_shortlist=True,
                seen_signal=True,
                alert_sent=False,
                alert_section='candidate' if pre_send_candidate else str(item.get('section', 'watch') or 'watch'),
                quality_block_reason=('사용자 알림 후보 판정됨(전송 전)' if pre_send_candidate else block_reason),
                persist=False,
            )
            after = missed_review_queue.get(key, {})
            trace_reason = block_reason if block_reason else ('알림 후보' if bucket == 'user_alert' else str(item.get('primary_reason', '') or '후보'))
            append_reverse_trace(item, stage=('alert' if bucket == 'user_alert' else 'shortlist'), extra_reason=trace_reason, now_ts=now_ts)
            if before != after:
                changed = True
        except Exception:
            continue
    if changed:
        cleanup_missed_review_queue(now_ts)
        persist_missed_review_state()


def scan_watchlist(shared_cache=None):
    global last_watchlist_market_register_ts
    started_at = time.time()
    mark_main_loop_heartbeat(stage='scan_watchlist_fast')
    cache = shared_cache if isinstance(shared_cache, dict) and shared_cache else (shared_market_cache if isinstance(shared_market_cache, dict) and shared_market_cache else None)
    if not cache:
        request_market_refresh(force=True, reason='empty_cache')
        fast = get_fast_scan_state(time.time())
        if fast.get('items'):
            _mark_fast_scan_meta(note='시장 데이터 대기 중 / 마지막 완성 후보 유지', stage='scan_wait_market', cache_age=None)
        else:
            _save_fast_scan_state([], note='최근 시장 데이터가 아직 없음', stage='scan_watchlist_empty', cache_age=None)
        mark_main_loop_heartbeat(stage='scan_watchlist_empty_done')
        return
    cache_age = int(started_at - shared_market_cache_time) if shared_market_cache_time else None
    try:
        cache = enrich_cache_with_light_snapshots(cache)
    except Exception:
        pass
    if cache_age is not None and cache_age >= FAST_SCAN_BUILD_CACHE_MAX_AGE_SEC:
        request_market_refresh(force=False, reason='scan_watchlist_cache_stale')
        fast = get_fast_scan_state(time.time())
        if fast.get('items'):
            _mark_fast_scan_meta(note='시장 데이터 갱신 대기 중 / 마지막 완성 후보 유지', stage='scan_wait_market', cache_age=cache_age)
        else:
            _save_fast_scan_state([], note='시장 데이터 다시 받는 중', stage='scan_watchlist_empty', cache_age=cache_age)
        mark_main_loop_heartbeat(stage='scan_watchlist_wait_market')
        return
    now_ts = time.time()
    if (now_ts - safe_float(last_watchlist_market_register_ts, 0)) >= SCAN_WATCHLIST_MARKET_REGISTER_INTERVAL_SEC:
        try:
            market_cache = get_watchlist_subset_cache(cache, limit=SCAN_WATCHLIST_MARKET_CACHE_LIMIT) or cache
            register_missed_review_market_candidates(market_cache, now_ts=now_ts, limit=SCAN_WATCHLIST_PREPARE_MISSED_LIMIT)
            last_watchlist_market_register_ts = now_ts
        except Exception as e:
            print(f'[fast_scan_missed_market 오류] {e}', flush=True)
    items = build_fast_scan_candidates_from_cache(cache, limit=FAST_SCAN_RESULT_MAX)
    try:
        _register_fast_scan_items_for_missed_review(items, now_ts)
    except Exception as e:
        print(f'[fast_scan_missed_shortlist 오류] {e}', flush=True)
    try:
        update_internal_watch_tracking(items, now_ts=now_ts)
    except Exception as e:
        print(f'[internal_watch_track 오류] {e}', flush=True)
    _save_fast_scan_state(items, note='빠른 후보 스캔 기준', stage='scan_watchlist_fast', cache_age=cache_age)
    try:
        _send_fast_scan_alerts(items, started_at)
    except Exception as e:
        print(f'[fast_scan_alert 오류] {e}', flush=True)
    mark_main_loop_heartbeat(stage='scan_watchlist_done')


def ping_command(update, context: CallbackContext):
    """가장 가벼운 생존 확인 명령어. 스캔/대금/OHLCV 계산을 절대 하지 않는다."""
    try:
        cache_age = 0
        with COMMAND_DISPLAY_CACHE_LOCK:
            if COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS:
                cache_age = int(max(0, time.time() - COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS))
        lines = [
            "🏓 봇 살아있음",
            f"- 버전: {BOT_VERSION}",
            f"- 단계: {last_main_loop_stage or 'starting'}",
            f"- 메인루프: {format_elapsed_text(time.time() - last_main_loop_heartbeat_ts) if last_main_loop_heartbeat_ts else '아직 시작 준비중'} 전",
            f"- 명령어 캐시: {'생성됨' if COMMAND_DISPLAY_CACHE_DONE > 0 else '아직 준비중'} / 최근 {cache_age}초 전",
            "- 이 명령은 새 스캔/OHLCV 조회를 하지 않는 생존 확인용",
        ]
        send("\n".join(lines))
    except Exception as e:
        send(f"🏓 봇 수신은 됐지만 ping 출력 중 오류: {e}")


def send_receiver_ready_message():
    """start_polling 직후 보내는 최소 알림. 무거운 복구/스캔 작업보다 먼저 수신이 열렸는지 확인용."""
    try:
        send(
            "\n".join([
                "✅ 텔레그램 수신 시작",
                f"현재 버전: {BOT_VERSION}",
                "- 무거운 시작 작업보다 명령어 수신을 먼저 열었어.",
                "- 시작 직후 확인은 /ping 또는 /cache_status",
            ])
        )
    except Exception as e:
        log_exception_details("receiver_ready_send", e, prefix="[수신 시작 알림 오류]")


def safe_start_polling(updater):
    """python-telegram-bot 세부 버전 차이와 pending 명령 폐기를 함께 방지한다."""
    try:
        return updater.start_polling(drop_pending_updates=False)
    except TypeError:
        # 구버전 python-telegram-bot은 drop_pending_updates 인자를 모를 수 있다.
        return updater.start_polling()



