def _v253_collect_light_rows(now_ts: float = None) -> list:
    """Light snapshot을 lock 짧게 잡고 복사한다. 실패하면 rank_state fallback으로 간다."""
    global RANK_V253_LAST_SOURCE_COUNT, RANK_V253_LAST_LOCK_MISS
    now_ts = safe_float(now_ts, time.time())
    out = []
    lock = globals().get("LIGHT_SNAPSHOT_LOCK")
    got = False
    try:
        if lock is None:
            return []
        try:
            got = lock.acquire(timeout=safe_float(globals().get("RANK_V253_LOCK_TIMEOUT_SEC", 0.04), 0.04))
        except TypeError:
            got = lock.acquire(False)
        if not got:
            RANK_V253_LAST_LOCK_MISS = int(safe_float(globals().get("RANK_V253_LAST_LOCK_MISS", 0), 0)) + 1
            return []
        history = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        if not isinstance(history, dict):
            return []
        ttl = max(60.0, safe_float(globals().get("RANK_V253_DEAD_STALE_SEC", 300), 300))
        keep_n = max(12, int(safe_float(globals().get("RANK_V253_HISTORY_ROWS", 100), 100)))
        for tk, rows in list(history.items()):
            ticker = str(tk or "").upper().strip()
            if not ticker or is_watch_excluded_ticker(ticker) or not isinstance(rows, list) or not rows:
                continue
            valid = []
            for r in rows[-keep_n:]:
                if not isinstance(r, dict):
                    continue
                ts = safe_float(r.get("ts", 0), 0)
                price = safe_float(r.get("price", 0), 0)
                if ts > 0 and price > 0 and now_ts - ts <= ttl:
                    valid.append({"ts": ts, "price": price, "turnover_hint": safe_float(r.get("turnover_hint", 0), 0), "source": str(r.get("source", "") or "")[:30]})
            if valid:
                out.append({"ticker": ticker, "rows": valid, "last_ts": safe_float(valid[-1].get("ts", 0), 0), "price": safe_float(valid[-1].get("price", 0), 0)})
        RANK_V253_LAST_SOURCE_COUNT = len(out)
        return out
    except Exception:
        return out
    finally:
        if got:
            try:
                lock.release()
            except Exception:
                pass


def _v253_change(rows: list, seconds: int, current_price: float, now_ts: float) -> dict:
    try:
        target = now_ts - int(seconds)
        cand = None
        for r in rows:
            if safe_float(r.get("ts", 0), 0) <= target:
                cand = r
            else:
                break
        if cand is None:
            cand = rows[0] if rows else {}
        base = safe_float(cand.get("price", 0), 0)
        base_ts = safe_float(cand.get("ts", 0), 0)
        if base <= 0 or current_price <= 0:
            return {"value": 0.0, "ready": False, "base_age_sec": 0.0}
        age = max(0.0, now_ts - base_ts)
        return {"value": round(((current_price - base) / base) * 100.0, 2), "ready": bool(base_ts <= target and age >= max(30.0, seconds * 0.80)), "base_age_sec": round(age, 1)}
    except Exception:
        return {"value": 0.0, "ready": False, "base_age_sec": 0.0}


def _v253_metrics_from_rows(rows: list, now_ts: float = None) -> dict:
    try:
        now_ts = safe_float(now_ts, time.time())
        rows = [r for r in list(rows or []) if isinstance(r, dict) and safe_float(r.get("ts", 0), 0) > 0 and safe_float(r.get("price", 0), 0) > 0]
        rows.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
        if not rows:
            return {}
        price = safe_float(rows[-1].get("price", 0), 0)
        first_ts = safe_float(rows[0].get("ts", 0), 0)
        last_ts = safe_float(rows[-1].get("ts", 0), 0)
        span_sec = max(0.0, last_ts - first_ts)
        if len(rows) < LIGHT_SNAPSHOT_READY_MIN_ROWS or span_sec < safe_float(globals().get("RANK_V253_MIN_SPAN_SEC", 35), 35):
            return {"snapshot_ready": False, "snapshot_rows": len(rows), "snapshot_span_sec": round(span_sec, 1), "snapshot_price": price, "last_ts": last_ts}
        recent30 = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 1800] or rows
        recent5 = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 300] or rows[-min(len(rows), 5):]
        prices = [safe_float(r.get("price", 0), 0) for r in recent30 if safe_float(r.get("price", 0), 0) > 0]
        if not prices:
            return {}
        low30, high30 = min(prices), max(prices)
        limited = bool(span_sec < LIGHT_SNAPSHOT_MIN_RANGE_SPAN_SEC or len(prices) < 6)
        flat = bool(high30 > 0 and low30 > 0 and abs(high30-low30) <= max(price * 0.0002, 1e-12))
        from_low = 0.0 if limited and flat else (((price-low30)/low30)*100.0 if low30 > 0 else 0.0)
        below_high = 999.0 if limited and flat else (((high30-price)/high30)*100.0 if high30 > 0 else 999.0)
        turns = [safe_float(r.get("turnover_hint", 0), 0) for r in recent5 if safe_float(r.get("turnover_hint", 0), 0) > 0]
        turnover_hint = max(turns) if turns else 0.0
        infos = {n: _v253_change(rows, sec, price, now_ts) for n, sec in [(1,60),(3,180),(5,300),(15,900),(30,1800),(60,3600)]}
        if abs(safe_float(infos[60].get("value", 0), 0)) < 0.0001 and span_sec < 3600:
            infos[60] = _v253_change(rows, int(max(span_sec, 60)), price, now_ts)
        p5 = [safe_float(r.get("price", 0), 0) for r in recent5 if safe_float(r.get("price", 0), 0) > 0]
        vol_proxy = 0.0
        if len(p5) >= 2:
            swing = ((max(p5)-min(p5))/max(min(p5),1e-12))*100.0
            vol_proxy = min(max(0.55 + swing*1.25 + abs(safe_float(infos[5].get("value",0),0))*0.35, 0.0), 6.0)
        return {
            "snapshot_ready": True, "snapshot_rows": len(rows), "snapshot_span_sec": round(span_sec, 1), "snapshot_price": price, "last_ts": last_ts,
            "snapshot_turnover_hint": turnover_hint,
            "change_1": safe_float(infos[1].get("value", 0), 0), "change_3": safe_float(infos[3].get("value", 0), 0),
            "change_5": safe_float(infos[5].get("value", 0), 0), "change_15": safe_float(infos[15].get("value", 0), 0),
            "change_30": safe_float(infos[30].get("value", 0), 0), "change_60": safe_float(infos[60].get("value", 0), 0),
            "change_1_ready": bool(infos[1].get("ready", False)), "change_3_ready": bool(infos[3].get("ready", False)),
            "change_5_ready": bool(infos[5].get("ready", False)), "change_15_ready": bool(infos[15].get("ready", False)),
            "change_30_ready": bool(infos[30].get("ready", False)), "change_60_ready": bool(infos[60].get("ready", False)),
            "from_low": round(from_low, 2), "below_high": round(below_high, 2),
            "recent_30m_low_price": round(low30, 8), "recent_30m_high_price": round(high30, 8),
            "snapshot_sample_limited_30m": limited, "snapshot_flat_range_guard": bool(limited and flat),
            "vol_ratio_snapshot": round(vol_proxy, 2),
        }
    except Exception:
        return {}


def _v253_row_from_metrics(ticker: str, metrics: dict, min_move_pct: float, now_ts: float) -> dict:
    try:
        if not isinstance(metrics, dict) or not bool(metrics.get("snapshot_ready")):
            return {}
        price = safe_float(metrics.get("snapshot_price", 0), 0)
        if price <= 0:
            return {}
        ch = {k: safe_float(metrics.get(k, 0), 0) for k in ("change_1","change_3","change_5","change_15","change_30","change_60")}
        strongest = max(ch.values()) if ch else 0.0
        if strongest < safe_float(min_move_pct, 0):
            return {}
        turnover_hint = safe_float(metrics.get("snapshot_turnover_hint", 0), 0)
        verified = get_cached_verified_turnover_for_ticker(ticker)
        if isinstance(verified, dict) and str(verified.get("status","")).lower() == "ok":
            turnover_hint = max(turnover_hint, safe_float(verified.get("turnover_5m", 0), 0))
        raw_score = _snapshot_rank_score(metrics, turnover_hint)
        last_ts = safe_float(metrics.get("last_ts", 0), 0)
        age = max(0.0, now_ts - last_ts) if last_ts > 0 else 999999.0
        factor = 1.0
        stale_label = "fresh"
        if age > RANK_V253_WARN_STALE_SEC:
            factor, stale_label = 0.30, "stale_warn"
        elif age > RANK_V253_FRESH_SEC:
            factor, stale_label = 0.70, "slightly_stale"
        row = {
            "ticker": ticker, "price": price, "current_price": price,
            "change_1": ch["change_1"], "change_3": ch["change_3"], "change_5": ch["change_5"], "change_15": ch["change_15"], "change_30": ch["change_30"], "change_60": ch["change_60"],
            "from_low": safe_float(metrics.get("from_low", 0), 0), "below_high": safe_float(metrics.get("below_high", 999), 999),
            "recent_30m_low_price": safe_float(metrics.get("recent_30m_low_price", 0), 0), "recent_30m_high_price": safe_float(metrics.get("recent_30m_high_price", 0), 0),
            "turnover_5m": turnover_hint, "turnover": turnover_hint, "vol_ratio": safe_float(metrics.get("vol_ratio_snapshot", 0), 0),
            "snapshot_rank_score": round(raw_score * factor, 4), "snapshot_rank_score_raw_v253": round(raw_score, 4),
            "snapshot_rank_strength": strongest, "snapshot_rank_detected_ts": last_ts or now_ts, "snapshot_rank_row_age_sec": round(age, 1), "snapshot_rank_stale_label_v253": stale_label,
            "snapshot_rows": int(safe_float(metrics.get("snapshot_rows", 0), 0)), "snapshot_span_sec": safe_float(metrics.get("snapshot_span_sec", 0), 0),
            "change_1_ready": bool(metrics.get("change_1_ready", False)), "change_3_ready": bool(metrics.get("change_3_ready", False)),
            "change_5_ready": bool(metrics.get("change_5_ready", False)), "change_15_ready": bool(metrics.get("change_15_ready", False)),
            "change_30_ready": bool(metrics.get("change_30_ready", False)), "change_60_ready": bool(metrics.get("change_60_ready", False)),
            "snapshot_sample_limited_30m": bool(metrics.get("snapshot_sample_limited_30m", False)), "snapshot_flat_range_guard": bool(metrics.get("snapshot_flat_range_guard", False)),
            "cache_source": "light_snapshot_rank_v253", "source": "realtime_snapshot_rank_v253", "rank_state_reused": False,
        }
        row = apply_ws_trade_score_adjustment(row)
        if is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            row["rank_tick_noise_block"] = True
            row["ultra_low_tick_noise_block"] = True
            row["snapshot_rank_score"] = min(safe_float(row.get("snapshot_rank_score", 0), 0), safe_float(globals().get("REALTIME_RANK_TICK_NOISE_SCORE_CAP", 0.15), 0.15))
        return row
    except Exception:
        return {}


def _v253_rank_state_fallback(limit: int, now_ts: float = None) -> list:
    try:
        now_ts = safe_float(now_ts, time.time())
        rows = []
        with RANK_STATE_LOCK:
            items = list((globals().get("RANK_STATE_BY_TICKER", {}) or {}).items())
        for ticker, st in items:
            if not isinstance(st, dict):
                continue
            ts = safe_float(st.get("updated_ts", st.get("computed_ts", 0)), 0)
            if ts <= 0 or now_ts - ts > RANK_V253_HARD_STALE_SEC:
                continue
            row = dict(st.get("row") or {})
            if row:
                row["rank_state_reused"] = True
                row["snapshot_rank_row_age_sec"] = round(now_ts - ts, 1)
                rows.append(row)
        rows.sort(key=lambda x: (safe_float(x.get("snapshot_rank_score",0),0), safe_float(x.get("change_3",0),0), safe_float(x.get("change_5",0),0)), reverse=True)
        for idx, row in enumerate(rows[:max(1,int(limit))], start=1):
            row["snapshot_rank"] = idx
        return rows[:max(1,int(limit))]
    except Exception:
        return []


def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    """v2.5.253: rank는 WebSocket/light snapshot 메모리만 읽고, API/OHLCV/내부감시 등록을 하지 않는다."""
    global RANK_STATE_LAST_REUSE_COUNT, RANK_STATE_LAST_RECALC_COUNT, RANK_STATE_LAST_TOTAL_COUNT, RANK_STATE_LAST_BUILD_TS, RANK_STATE_LAST_NOTE
    global RANK_V253_LAST_BUILT_COUNT, RANK_V253_LAST_STALE_SKIPPED, RANK_V253_LAST_TOTAL_SEC, RANK_V253_LAST_NOTE
    t0 = time.time()
    now_ts = t0
    max_limit = max(1, int(limit))
    stale_skip = 0
    try:
        reset_rank_reuse_fail_reasons() if 'reset_rank_reuse_fail_reasons' in globals() else None
        s = time.time()
        source = _v253_collect_light_rows(now_ts)
        timings = {"snapshot_copy": time.time()-s}
        if not source:
            rows = _v253_rank_state_fallback(max_limit, now_ts)
            RANK_V253_LAST_NOTE = "snapshot lock fallback" if rows else "rank rows 없음"
            return rows
        rows = []
        s = time.time()
        for item in source:
            ticker = str(item.get("ticker","")).upper().strip()
            last_ts = safe_float(item.get("last_ts",0),0)
            if not ticker or last_ts <= 0:
                continue
            if now_ts - last_ts > RANK_V253_HARD_STALE_SEC:
                stale_skip += 1
                continue
            row = _v253_row_from_metrics(ticker, _v253_metrics_from_rows(item.get("rows", []), now_ts), min_move_pct, now_ts)
            if row:
                rows.append(row)
        timings["metrics"] = time.time()-s
        rows.sort(key=lambda x: (safe_float(x.get("snapshot_rank_score",0),0), safe_float(x.get("change_3",0),0), safe_float(x.get("change_5",0),0), safe_float(x.get("change_30",0),0)), reverse=True)
        rows = rows[:max_limit]
        s = time.time()
        overlay_limit = max(3, min(len(rows), int(safe_float(globals().get("RANK_V253_OVERLAY_LIMIT", 24), 24))))
        for idx, row in enumerate(rows, start=1):
            row["snapshot_rank"] = idx
            if idx <= overlay_limit:
                try:
                    row = apply_precision_minute1_state_to_row(row) if 'apply_precision_minute1_state_to_row' in globals() else row
                    row = apply_low_defense_quality_v248(row) if 'apply_low_defense_quality_v248' in globals() else row
                    row = apply_high_rebreakout_hold_v248(row) if 'apply_high_rebreakout_hold_v248' in globals() else row
                    row = apply_money_sustain_context(row)
                    row["rank_precision_watch"] = bool(is_realtime_rank_precision_candidate(row))
                    row = apply_rank_watch_chart_state(row)
                    row = apply_final_candidate_display_context_v251(row) if 'apply_final_candidate_display_context_v251' in globals() else row
                    row["rank_watch_action"] = str(row.get("final_candidate_action_v251", "") or realtime_rank_watch_action_label(row))
                except Exception:
                    row.setdefault("rank_precision_watch", False)
            else:
                row.setdefault("rank_precision_watch", False)
                row.setdefault("rank_watch_action", realtime_rank_watch_action_label(row))
            try:
                _rank_state_store_row(str(row.get("ticker","")).upper().strip(), row, {"price": safe_float(row.get("price",0),0), "last_ts": safe_float(row.get("snapshot_rank_detected_ts",now_ts),now_ts), "rows": int(safe_float(row.get("snapshot_rows",0),0)), "span_sec": safe_float(row.get("snapshot_span_sec",0),0)}, now_ts=now_ts)
            except Exception:
                pass
            rows[idx-1] = row
        timings["overlay"] = time.time()-s
        total = time.time()-t0
        timings["total"] = total
        globals()["RANK_SOURCE_STEP_LAST_TIMINGS"] = dict(timings)
        globals()["RANK_SOURCE_LIGHT_CREATE_COUNT"] = len(rows)
        globals()["RANK_SOURCE_SKIPPED_COUNT"] = stale_skip
        globals()["RANK_SOURCE_PRECISION_MERGE_COUNT"] = 0
        RANK_STATE_LAST_REUSE_COUNT = 0
        RANK_STATE_LAST_RECALC_COUNT = len(rows)
        RANK_STATE_LAST_TOTAL_COUNT = len(source)
        RANK_STATE_LAST_BUILD_TS = now_ts
        RANK_STATE_LAST_NOTE = f"v253 snapshot-only / source {len(source)} / rows {len(rows)} / stale_skip {stale_skip} / {total:.2f}s"
        RANK_V253_LAST_NOTE = RANK_STATE_LAST_NOTE
        RANK_V253_LAST_STALE_SKIPPED = stale_skip
        RANK_V253_LAST_BUILT_COUNT = len(rows)
        RANK_V253_LAST_TOTAL_SEC = round(total, 3)
        return rows
    except Exception as e:
        append_runtime_event_log("rank_v253_error", "v2.5.253 순위 엔진 오류", extra={"error": str(e)[:160]})
        return _v253_rank_state_fallback(max_limit, now_ts)


def _maybe_register_rank_precision_rows_from_snapshot(rows: list, now_ts: float = None):
    """v2.5.253: 캐시 생성 중 직접 내부감시 등록하지 않고, 큐에만 넣는다."""
    global RANK_V253_REGISTER_LAST
    try:
        now_ts = safe_float(now_ts, time.time())
        source = [dict(x) for x in list(rows or []) if isinstance(x, dict)]
        source.sort(key=lambda x: (safe_float(x.get("snapshot_rank_score",0),0), _row_strongest_rank_move(x)), reverse=True)
        pushed = 0
        with RANK_V253_REGISTER_LOCK:
            q = globals().setdefault("RANK_V253_REGISTER_QUEUE", [])
            if not isinstance(q, list):
                q = []
                globals()["RANK_V253_REGISTER_QUEUE"] = q
            known = {str((x or {}).get("ticker","")).upper().strip() for x in q if isinstance(x, dict)}
            for row in source[:12]:
                ticker = str(row.get("ticker","")).upper().strip()
                if not ticker or ticker in known or ticker in _active_internal_watch_tickers():
                    continue
                if bool(row.get("rank_tick_noise_block", False)) or bool(row.get("ultra_low_tick_noise_block", False)) or is_rank_watch_low_price_tick_noise_v237(row):
                    continue
                if not (bool(row.get("rank_precision_watch", False)) or is_realtime_rank_precision_candidate(row)):
                    continue
                q.append({"ticker": ticker, "row": dict(row), "queued_at": now_ts, "score": safe_float(row.get("snapshot_rank_score",0),0), "move": _row_strongest_rank_move(row)})
                known.add(ticker)
                pushed += 1
            q.sort(key=lambda x: (safe_float((x or {}).get("score",0),0), safe_float((x or {}).get("move",0),0)), reverse=True)
            max_q = int(safe_float(globals().get("RANK_V253_REGISTER_QUEUE_MAX", 40), 40))
            if len(q) > max_q:
                del q[max_q:]
        RANK_V253_REGISTER_LAST = f"큐적재 {pushed}개 / 대기 {len(globals().get('RANK_V253_REGISTER_QUEUE', []) or [])}개"
    except Exception as e:
        RANK_V253_REGISTER_LAST = f"큐적재 오류:{e.__class__.__name__}"


def rank_precision_registration_worker_loop_v253():
    global RANK_V253_REGISTER_DONE, RANK_V253_REGISTER_SKIP, RANK_V253_REGISTER_LAST
    time.sleep(3.0)
    while True:
        try:
            time.sleep(max(3.0, safe_float(globals().get("RANK_V253_REGISTER_WORKER_SLEEP_SEC", 8.0), 8.0)))
            per_round = max(1, int(safe_float(globals().get("RANK_V253_REGISTER_PER_ROUND", 2), 2)))
            for _ in range(per_round):
                item = None
                with RANK_V253_REGISTER_LOCK:
                    q = globals().setdefault("RANK_V253_REGISTER_QUEUE", [])
                    if isinstance(q, list) and q:
                        item = q.pop(0)
                if not isinstance(item, dict):
                    break
                row = dict(item.get("row") or {})
                ticker = str(row.get("ticker", item.get("ticker",""))).upper().strip()
                if not ticker or ticker in _active_internal_watch_tickers():
                    RANK_V253_REGISTER_SKIP += 1
                    continue
                now_ts = time.time()
                active_dict, _logs = _get_internal_watch_state_parts()
                max_active = get_internal_watch_dynamic_max_active(active=active_dict)
                if len(active_dict) >= max_active and not _make_internal_watch_slot_for_candidate(row, now_ts=now_ts):
                    RANK_V253_REGISTER_SKIP += 1
                    continue
                row["rank_precision_watch"] = True
                if register_rank_precision_internal_watch(row, now_ts=now_ts, reason="rank_precision_worker_v253"):
                    RANK_V253_REGISTER_DONE += 1
                    RANK_V253_REGISTER_LAST = f"등록 {ticker} / done {RANK_V253_REGISTER_DONE}"
                else:
                    RANK_V253_REGISTER_SKIP += 1
                    RANK_V253_REGISTER_LAST = f"스킵 {ticker} / skip {RANK_V253_REGISTER_SKIP}"
        except Exception as e:
            RANK_V253_REGISTER_LAST = f"worker 오류:{e.__class__.__name__}"
            append_runtime_event_log("rank_precision_worker_v253_error", "분리형 rank precision 등록 worker 오류", extra={"error": str(e)[:160]})
            time.sleep(5.0)


def _light_snapshot_source_rows() -> list:
    """v2.5.253: snapshot worker가 rank 엔진을 다시 호출하지 않게 피드백 루프 제거."""
    rows = []
    try:
        if isinstance(shared_market_cache, dict):
            for ticker, data in shared_market_cache.items():
                if isinstance(data, dict):
                    d = dict(data); d.setdefault("ticker", ticker); rows.append(d)
        existing = {str(r.get("ticker","")).upper().strip() for r in rows if isinstance(r, dict)}
        if isinstance(market_universe, list):
            for row in market_universe:
                if isinstance(row, dict):
                    t = str(row.get("ticker","")).upper().strip()
                    if t and t not in existing:
                        rows.append(dict(row)); existing.add(t)
        try:
            cleanup_forced_light_snapshot_tickers()
            forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
            if isinstance(forced, dict):
                for ft, meta in list(forced.items()):
                    t = str(ft or "").upper().strip()
                    if t and t not in existing and not is_watch_excluded_ticker(t):
                        rows.append({"ticker": t, "snapshot_forced_watch": True, "force_reason": (meta or {}).get("reason","force_track") if isinstance(meta, dict) else "force_track"}); existing.add(t)
        except Exception:
            pass
        try:
            with RANK_STATE_LOCK:
                state_items = list((globals().get("RANK_STATE_BY_TICKER", {}) or {}).items())
            state_items.sort(key=lambda kv: safe_float(((kv[1] or {}).get("row") or {}).get("snapshot_rank_score",0),0), reverse=True)
            for t, st in state_items[:30]:
                tk = str(t or "").upper().strip()
                if tk and tk not in existing and not is_watch_excluded_ticker(tk):
                    rows.append({"ticker": tk, "snapshot_rank_state_seed": True}); existing.add(tk)
        except Exception:
            pass
        if len(rows) < LIGHT_SNAPSHOT_FALLBACK_TARGET:
            rows.extend(_fallback_market_snapshot_seed_rows(existing=existing, limit=LIGHT_SNAPSHOT_FALLBACK_TARGET-len(rows)))
    except Exception:
        pass
    rows.sort(key=lambda r: (
        max(100-int(safe_float(r.get("turnover_rank",999),999)),0)*0.8
        + max(100-int(safe_float(r.get("surge_rank",999),999)),0)*0.6
        + safe_float(r.get("leader_score",0),0)*12.0
        + safe_float(r.get("turnover_5m", r.get("turnover", r.get("turnover_recent",0))),0)*0.00000001
        + max(safe_float(r.get("change_5", r.get("short_change",0)),0),0)*4.0
        + max(safe_float(r.get("change_30",0),0),0)*1.3
    ), reverse=True)
    return rows[:LIGHT_SNAPSHOT_TARGET_MAX]


def queue_precision_minute1_chart_verify(row: dict, reason: str = "internal_watch") -> bool:
    """v2.5.253: 정밀 minute1 큐 등록 기준을 좁히고, rank 캐시 경로의 폭주를 차단."""
    try:
        if not bool(globals().get("PRECISION_MINUTE1_CHART_ON", True)):
            return False
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker","")).upper().strip()
        reason = str(reason or "internal_watch")[:80]
        if not ticker or is_watch_excluded_ticker(ticker):
            _precision_minute1_reject("bad_ticker", ticker); return False
        now_ts = time.time()
        if _precision_minute1_global_cooldown_left(now_ts) > 0:
            _precision_minute1_reject("global_timeout_circuit", ticker, {"reason": reason}); return False
        remain = _precision_minute1_cooldown_remaining(ticker, now_ts)
        if remain > 0:
            _precision_minute1_reject("cooldown", ticker, {"remain": round(remain,1), "reason": reason}); return False
        any_state = get_precision_minute1_chart_state(ticker, max_age_sec=safe_float(globals().get("PRECISION_MINUTE1_RECENT_STATE_BLOCK_SEC", 180), 180))
        if any_state:
            _precision_minute1_reject("recent_state", ticker, {"reason": reason}); return False
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score",0)), 0)
        strongest = _row_strongest_rank_move(row)
        money_code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
        ws_amount = safe_float(row.get("ws_trade_amount_60s",0),0)
        ws_count = int(safe_float(row.get("ws_trade_count_60s",0),0))
        turnover = safe_float(row.get("turnover_5m", row.get("turnover",0)),0)
        if str(reason).startswith("rank") and score < 10.0 and strongest < 1.60:
            _precision_minute1_reject("rank_v253_low_priority", ticker, {"score": score, "move": strongest})
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_LOW_PRIORITY_MIN_DELAY_SEC",600),600), "rank_low_priority")
            return False
        if money_code in {"actual_zero","tiny","thin"} and ws_amount < PRECISION_MINUTE1_MIN_WS_AMOUNT and turnover < PRECISION_MINUTE1_MIN_GOOD_TURNOVER:
            _precision_minute1_reject("money_weak_v253", ticker, {"money_code": money_code})
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_LOW_PRIORITY_MIN_DELAY_SEC",600),600), "money_weak")
            return False
        if ws_count <= 0 and turnover <= 0 and score < 12.0:
            _precision_minute1_reject("no_trade_money_v253", ticker, {"score": score}); return False
        profile = precision_minute1_candidate_profile_v249(row, reason=reason)
        if not bool(profile.get("allowed", False)):
            _precision_minute1_reject(str(profile.get("decision","not_qualified") or "not_qualified"), ticker, profile)
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_LOW_PRIORITY_MIN_DELAY_SEC",600),600), "blocked")
            return False
        with PRECISION_MINUTE1_QUEUE_LOCK:
            q = globals().setdefault("PRECISION_MINUTE1_QUEUE", [])
            if not isinstance(q, list): q = []; globals()["PRECISION_MINUTE1_QUEUE"] = q
            if any(isinstance(x, dict) and str(x.get("ticker","")).upper().strip() == ticker for x in q):
                _precision_minute1_reject("already_queued", ticker, profile); return False
            q.append({"ticker": ticker, "requested_at": now_ts, "reason": reason, "score": safe_float(profile.get("score",score),score), "priority": safe_float(profile.get("priority",0),0), "profile": profile})
            q.sort(key=lambda x: (safe_float((x or {}).get("priority",0),0), -safe_float((x or {}).get("requested_at",0),0)), reverse=True)
            del q[int(safe_float(globals().get("PRECISION_MINUTE1_QUEUE_MAX",6),6)):]
        hint = dict(row); hint["precision_queue_reason_v249"] = reason
        store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason=f"queued:{reason}", row_hint=hint)
        _precision_minute1_accept(ticker, profile)
        return True
    except Exception as e:
        append_runtime_event_log("precision_minute1_queue_error_v253", "정밀 1분봉 큐 등록 오류", extra={"error": str(e)[:120]})
        return False


def verify_realtime_rank_turnover_once(ticker: str, reason: str = "worker") -> bool:
    """v2.5.253: 순위 대금 확인에서 신규 minute1 REST 호출 제거. 캐시/WS/스냅샷만 사용."""
    global REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM, REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT, REALTIME_RANK_TURNOVER_VERIFY_DONE, REALTIME_RANK_TURNOVER_VERIFY_FAIL, RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY
    ticker = str(ticker or "").upper().strip()
    if not ticker: return False
    REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM = ticker
    try:
        cached_df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1")*6, copy_dataframe=True)
        if cached_df is not None and len(cached_df) >= 1:
            vals = _compute_turnover_from_minute_df(cached_df)
            if int(vals.get("rows",0)) > 0:
                vals.update({"status":"ok","source":"minute1_cache_only_v253","reason":str(reason)[:80],"verified":True,"next_retry_at":time.time()+REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC})
                store_precision_minute1_chart_state(ticker, cached_df, source="minute1_cache_only_v253", reason="turnover_verify_cache_v253")
                _save_verified_turnover_state(ticker, vals)
                REALTIME_RANK_TURNOVER_VERIFY_DONE += 1; RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY += 1
                REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"캐시확인 {safe_float(vals.get('turnover_5m',0),0):,.0f}원"
                return True
    except Exception:
        pass
    try:
        s60 = get_ws_trade_summary_for_ticker(ticker, 60) if 'get_ws_trade_summary_for_ticker' in globals() else {}
        amount60 = safe_float((s60 or {}).get("amount",0),0)
        if amount60 > 0:
            vals = {"ticker":ticker,"turnover_1m":amount60,"turnover_3m":amount60,"turnover_5m":amount60,"turnover_15m":amount60,"rows":int(safe_float((s60 or {}).get("count",0),0)),"status":"ok","source":"ws_trade_amount_v253","reason":str(reason)[:80],"verified":True,"next_retry_at":time.time()+180}
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"WS대금 {amount60:,.0f}원"
            return True
    except Exception:
        pass
    try:
        rows = _light_snapshot_rows(ticker) if '_light_snapshot_rows' in globals() else []
        recent = [r for r in rows if time.time()-safe_float((r or {}).get("ts",0),0) <= 300]
        turn = max([safe_float((r or {}).get("turnover_hint",0),0) for r in recent] or [0])
        if turn > 0:
            vals = {"ticker":ticker,"turnover_1m":turn,"turnover_3m":turn,"turnover_5m":turn,"turnover_15m":turn,"rows":len(recent),"status":"ok","source":"light_snapshot_turnover_hint_v253","reason":str(reason)[:80],"verified":False,"next_retry_at":time.time()+240}
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"스냅샷대금 {turn:,.0f}원"
            return True
    except Exception:
        pass
    _save_verified_turnover_state(ticker, {"ticker":ticker,"status":"deferred","source":"cache_ws_only_v253","reason":"no_cached_turnover","fail_detail":"v2.5.253: 신규 minute1 REST 대금확인 금지, 캐시/WS 대기","verified":False,"next_retry_at":time.time()+REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC})
    REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
    REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "캐시/WS대금 대기"
    return False


def get_missed_review_window_stats(ticker: str, base_price: float, eval_start_ts: float = 0.0, eval_end_ts: float = 0.0):
    """v2.5.253: 놓침 복기도 신규 OHLCV 호출 금지. 캐시 또는 light snapshot으로만 계산."""
    now_ts = time.time()
    start_ts = safe_float(eval_start_ts, 0) or now_ts-1800
    end_ts = safe_float(eval_end_ts, 0) or start_ts+1800
    if end_ts < start_ts: end_ts = start_ts+1800
    stats = {"best_up_pct":0.0,"end_up_pct":0.0,"worst_down_pct":0.0,"best_price":base_price,"end_price":base_price,"worst_price":base_price,"best_price_ts":0.0,"worst_price_ts":0.0,"end_price_ts":0.0,"eval_start_ts":floor_minute_ts(start_ts) or start_ts,"eval_end_ts":floor_minute_ts(end_ts) or end_ts,"pending":now_ts<end_ts,"window_candles":0,"source_interval":"cache_or_light_snapshot","window_source_ok":False}
    if base_price <= 0 or now_ts < end_ts: return stats
    def apply_pts(points, source):
        pts=[(safe_float(ts,0), safe_float(p,0)) for ts,p in points if start_ts <= safe_float(ts,0) <= end_ts and safe_float(p,0)>0]
        if not pts: return False
        pts.sort(key=lambda x:x[0])
        best_ts,best_p=max(pts,key=lambda x:x[1]); worst_ts,worst_p=min(pts,key=lambda x:x[1]); end_ts2,end_p=pts[-1]
        stats.update({"best_price":best_p,"worst_price":worst_p,"end_price":end_p,"best_price_ts":best_ts,"worst_price_ts":worst_ts,"end_price_ts":end_ts2,"window_candles":len(pts),"best_up_pct":((best_p-base_price)/base_price)*100.0,"end_up_pct":((end_p-base_price)/base_price)*100.0,"worst_down_pct":((worst_p-base_price)/base_price)*100.0,"pending":False,"window_source_ok":True,"source_interval":source})
        return True
    try:
        df=get_api_cache_entry(API_OHLCV_CACHE,(str(ticker).upper().strip(),"minute1"),3600,copy_dataframe=True)
        if df is not None and len(df)>=1:
            idx_ts=df.index.map(lambda x: float(x.timestamp()) if hasattr(x,'timestamp') else 0.0)
            tmp=df.assign(_ts=idx_ts)
            pts=[]
            for _,row in tmp.iterrows():
                ts=safe_float(row.get("_ts",0),0)
                pts += [(ts,safe_float(row.get("high",row.get("close",0)),0)),(ts,safe_float(row.get("low",row.get("close",0)),0)),(ts,safe_float(row.get("close",0),0))]
            if apply_pts(pts,"minute1_cache_only_v253"): return stats
    except Exception:
        pass
    try:
        rows=_light_snapshot_rows(str(ticker).upper().strip()) if '_light_snapshot_rows' in globals() else []
        if apply_pts([(safe_float((r or {}).get("ts",0),0),safe_float((r or {}).get("price",0),0)) for r in rows],"light_snapshot_v253"): return stats
    except Exception:
        pass
    return stats


def process_precision_minute1_chart_once(ticker: str, reason: str = "worker") -> bool:
    """v2.5.253: 캐시 우선. 신규 REST는 전역 쿼터와 회로차단 뒤에만."""
    global PRECISION_MINUTE1_FAIL, PRECISION_MINUTE1_LAST_ITEM, PRECISION_MINUTE1_LAST_RESULT
    ticker = str(ticker or "").upper().strip()
    if not ticker: return False
    PRECISION_MINUTE1_LAST_ITEM = ticker
    try:
        remain = _precision_minute1_cooldown_remaining(ticker) if '_precision_minute1_cooldown_remaining' in globals() else 0.0
        if remain > 0:
            PRECISION_MINUTE1_LAST_RESULT = f"쿨다운 {int(remain)}초"; return False
    except Exception: pass
    try:
        df = get_api_cache_entry(API_OHLCV_CACHE, (ticker,"minute1"), get_ohlcv_cache_ttl("minute1")*8, copy_dataframe=True)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source="minute1_cache_only_v253", reason=reason)
            if bool(st.get("precision_chart_verified", False)):
                _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC",300),300), "success_cache")
            PRECISION_MINUTE1_LAST_RESULT = "캐시확인"
            return bool(st.get("precision_chart_verified", False))
    except Exception: pass
    try:
        global_left = _precision_minute1_global_cooldown_left() if '_precision_minute1_global_cooldown_left' in globals() else 0.0
        if global_left > 0 or is_ohlcv_circuit_open() or (not _precision_minute1_fetch_quota_open()):
            store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason="quota_or_circuit_v253", row_hint={"ticker":ticker})
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_QUOTA_COOLDOWN_SEC",180),180), "quota_or_circuit")
            PRECISION_MINUTE1_LAST_RESULT = "대기/쿼터"; return False
        _precision_minute1_record_fetch()
        df = get_ohlcv(ticker, "minute1", allow_slow_fetch=True)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source="minute1_ohlcv_v253_limited", reason=reason)
            if bool(st.get("precision_chart_verified", False)):
                _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC",300),300), "success_fetch")
            PRECISION_MINUTE1_LAST_RESULT = "REST제한확인"
            return bool(st.get("precision_chart_verified", False))
        PRECISION_MINUTE1_FAIL += 1
        PRECISION_MINUTE1_LAST_RESULT = "실패/표본없음"
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_FAIL_COOLDOWN_SEC",1800),1800), "no_rows")
        store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo", reason="minute1_no_rows_v253", row_hint={"ticker":ticker})
        return False
    except Exception as e:
        PRECISION_MINUTE1_FAIL += 1
        PRECISION_MINUTE1_LAST_RESULT = f"오류:{e.__class__.__name__}"
        if "timeout" in str(e).lower() and '_precision_minute1_note_timeout' in globals():
            _precision_minute1_note_timeout()
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_TIMEOUT_COOLDOWN_SEC",2400),2400), "timeout_or_error")
        append_runtime_event_log("precision_minute1_worker_error_v253", "정밀 1분봉 검증 오류", extra={"ticker":ticker,"error":str(e)[:120]})
        return False


_ORIG_BUILD_CACHE_STATUS_TEXT_V253 = build_cache_status_text
def build_cache_status_text():
    try:
        base = _ORIG_BUILD_CACHE_STATUS_TEXT_V253()
    except Exception as e:
        base = f"🧊 명령어 캐시 상태 /cache_status\n- 기본 상태 생성 오류: {e}"
    try:
        q_len = len(globals().get("RANK_V253_REGISTER_QUEUE", []) or []) if isinstance(globals().get("RANK_V253_REGISTER_QUEUE", []), list) else 0
        extra = [
            "",
            "🧩 v2.5.253 엔진분리",
            f"- rank 엔진: snapshot-only / 원본 {int(safe_float(globals().get('RANK_V253_LAST_SOURCE_COUNT',0),0))}개 / 생성 {int(safe_float(globals().get('RANK_V253_LAST_BUILT_COUNT',0),0))}개 / stale 제외 {int(safe_float(globals().get('RANK_V253_LAST_STALE_SKIPPED',0),0))}개 / {safe_float(globals().get('RANK_V253_LAST_TOTAL_SEC',0),0):.2f}s",
            f"- lock 미획득: {int(safe_float(globals().get('RANK_V253_LAST_LOCK_MISS',0),0))}회 / 상태: {globals().get('RANK_V253_LAST_NOTE','-')}",
            f"- 내부감시 등록분리: 대기 {q_len}개 / 완료 {int(safe_float(globals().get('RANK_V253_REGISTER_DONE',0),0))} / 스킵 {int(safe_float(globals().get('RANK_V253_REGISTER_SKIP',0),0))} / 최근 {globals().get('RANK_V253_REGISTER_LAST','-')}",
            f"- OHLCV 절감: 대금확인 신규 REST 금지 / 캐시·WS 처리 {int(safe_float(globals().get('RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY',0),0))}회",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base



