def _v254_strongest_move(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    return max(
        safe_float(row.get("change_1", 0), 0),
        safe_float(row.get("change_3", 0), 0),
        safe_float(row.get("change_5", 0), 0),
        safe_float(row.get("change_15", 0), 0),
        safe_float(row.get("change_30", 0), 0),
        safe_float(row.get("change_60", 0), 0),
    )


def _v254_ws_money_amount(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    return max(
        safe_float(row.get("ws_trade_amount_60s", 0), 0),
        safe_float(row.get("turnover_5m", 0), 0),
        safe_float(row.get("turnover", 0), 0),
        safe_float(row.get("verified_turnover_5m", 0), 0),
        safe_float(row.get("actual_turnover_5m", 0), 0),
    )


def _v254_attach_ws_and_money(row: dict, ticker: str = "") -> dict:
    """WS 체결대금/기존 검증대금을 row에 강제로 붙인다. 신규 REST는 호출하지 않는다."""
    global RANK_V254_WS_MONEY_ATTACH_COUNT
    try:
        row = dict(row) if isinstance(row, dict) else {}
        ticker = str(ticker or row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return row
        before = _v254_ws_money_amount(row)
        try:
            row = apply_ws_trade_metrics_to_item(row) if 'apply_ws_trade_metrics_to_item' in globals() else row
        except Exception:
            pass
        try:
            verified = get_cached_verified_turnover_for_ticker(ticker) if 'get_cached_verified_turnover_for_ticker' in globals() else None
            if isinstance(verified, dict) and str(verified.get("status", "")).lower() == "ok":
                tv = max(
                    safe_float(verified.get("turnover_5m", 0), 0),
                    safe_float(verified.get("turnover_3m", 0), 0),
                    safe_float(verified.get("turnover_1m", 0), 0),
                )
                if tv > 0:
                    row["turnover_5m"] = max(safe_float(row.get("turnover_5m", 0), 0), tv)
                    row["turnover"] = max(safe_float(row.get("turnover", 0), 0), tv)
                    row["verified_turnover_5m"] = tv
                    row["turnover_verified"] = True
                    row["turnover_verify_status"] = "ok"
                    row["turnover_verify_source"] = str(verified.get("source", "cache") or "cache")
        except Exception:
            pass
        ws_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        if ws_amt > 0:
            row["turnover_1m"] = max(safe_float(row.get("turnover_1m", 0), 0), ws_amt)
            row["turnover_3m"] = max(safe_float(row.get("turnover_3m", 0), 0), ws_amt)
            row["turnover_5m"] = max(safe_float(row.get("turnover_5m", 0), 0), ws_amt)
            row["turnover"] = max(safe_float(row.get("turnover", 0), 0), ws_amt)
            row["turnover_verified"] = True
            row["turnover_verify_status"] = "ok"
            row["turnover_verify_source"] = "ws_trade_amount_v254"
            row["money_source_v254"] = "ws_trade"
        after = _v254_ws_money_amount(row)
        if after > before:
            RANK_V254_WS_MONEY_ATTACH_COUNT += 1
        return row
    except Exception:
        return row if isinstance(row, dict) else {}


def _v254_money_unverified(row: dict) -> bool:
    try:
        row = row if isinstance(row, dict) else {}
        status = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
        ws_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        ws_cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        return status in {"checking", "delayed", "verify_failed", "unknown", "suspect"} and ws_amt <= 0 and ws_cnt <= 0 and _row_turnover_value(row) <= 0
    except Exception:
        return True


def _v254_apply_unverified_demote(row: dict) -> dict:
    """돈 확인전 후보가 rank/watch 상단과 내부감시 슬롯을 먹는 문제를 강하게 차단한다."""
    global RANK_V254_UNVERIFIED_DEMOTE_COUNT
    try:
        row = dict(row) if isinstance(row, dict) else {}
        row = _v254_attach_ws_and_money(row)
        strongest = _v254_strongest_move(row)
        ws_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        score = safe_float(row.get("snapshot_rank_score", 0), 0)
        if _v254_money_unverified(row):
            cap = safe_float(globals().get("RANK_V254_UNVERIFIED_SCORE_CAP", 5.8), 5.8)
            if strongest >= safe_float(globals().get("RANK_V254_STRONG_MOVE_ALLOW_UNVERIFIED", 3.0), 3.0) and ws_amt >= safe_float(globals().get("RANK_V254_STRONG_MOVE_MIN_WS_AMOUNT", 300000), 300000):
                cap = safe_float(globals().get("RANK_V254_UNVERIFIED_HUGE_MOVE_SCORE_CAP", 7.2), 7.2)
            if score > cap:
                row["snapshot_rank_score_before_v254_money_cap"] = score
                row["snapshot_rank_score"] = cap
            row["rank_precision_watch"] = False
            row["rank_watch_action"] = "대금 확인 대기"
            row["money_unverified_gate_v254"] = True
            row["money_gate_reason_v254"] = "돈/체결 미확인 → 정밀검토·내부감시 승격 차단"
            row.setdefault("reasons", [])
            if isinstance(row.get("reasons"), list):
                row["reasons"].append("돈/체결 미확인 → 정식 후보 아님")
            RANK_V254_UNVERIFIED_DEMOTE_COUNT += 1
        else:
            row["money_unverified_gate_v254"] = False
        return row
    except Exception:
        return row if isinstance(row, dict) else {}


_ORIG_V253_ROW_FROM_METRICS_V254 = _v253_row_from_metrics
def _v253_row_from_metrics(ticker: str, metrics: dict, min_move_pct: float, now_ts: float) -> dict:
    row = _ORIG_V253_ROW_FROM_METRICS_V254(ticker, metrics, min_move_pct, now_ts)
    try:
        if not row:
            return row
        return _v254_apply_unverified_demote(row)
    except Exception:
        return row


_ORIG_GET_LIGHT_SNAPSHOT_RANK_ROWS_V254 = get_light_snapshot_rank_rows
def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    """v2.5.254: rank row 생성 뒤 돈확인전/WS미확인 후보를 강제 강등하고 노출 개수를 제한한다."""
    global RANK_V254_LAST_NOTE, RANK_V254_LAST_STRICT_TS
    try:
        max_limit = min(max(1, int(limit)), int(safe_float(globals().get("RANK_V254_MAX_RANK_SOURCE_LIMIT", 70), 70)))
        rows = _ORIG_GET_LIGHT_SNAPSHOT_RANK_ROWS_V254(max_limit, min_move_pct)
        out = []
        unver = 0
        for row in list(rows or []):
            if not isinstance(row, dict):
                continue
            row = _v254_apply_unverified_demote(row)
            if bool(row.get("money_unverified_gate_v254", False)):
                unver += 1
                if unver > int(safe_float(globals().get("RANK_V254_MAX_UNVERIFIED_ROWS", 8), 8)):
                    row["snapshot_rank_hidden_v254"] = True
                    continue
            out.append(row)
        out.sort(key=lambda x: (safe_float(x.get("snapshot_rank_score", 0), 0), safe_float(x.get("change_3", 0), 0), safe_float(x.get("change_5", 0), 0)), reverse=True)
        for i, row in enumerate(out, start=1):
            row["snapshot_rank"] = i
            try:
                _rank_state_store_row(str(row.get("ticker", "")).upper().strip(), row, {"price": safe_float(row.get("price", 0), 0), "last_ts": safe_float(row.get("snapshot_rank_detected_ts", time.time()), time.time())}, now_ts=time.time())
            except Exception:
                pass
        RANK_V254_LAST_STRICT_TS = time.time()
        RANK_V254_LAST_NOTE = f"strict money gate / rows {len(out)} / unver {unver}"
        return out[:max_limit]
    except Exception as e:
        RANK_V254_LAST_NOTE = f"strict error:{e.__class__.__name__}"
        return _ORIG_GET_LIGHT_SNAPSHOT_RANK_ROWS_V254(limit, min_move_pct)


_ORIG_REALTIME_RANK_WATCH_ACTION_LABEL_V254 = realtime_rank_watch_action_label
def realtime_rank_watch_action_label(row: dict) -> str:
    try:
        row = _v254_apply_unverified_demote(row if isinstance(row, dict) else {})
        if bool(row.get("money_unverified_gate_v254", False)):
            return "대금 확인 대기"
        if is_money_weak_but_not_unknown_for_row(row) and safe_float(row.get("ws_trade_amount_60s", 0), 0) < safe_float(globals().get("RANK_V254_MIN_WS_AMOUNT_FOR_WATCH", 1_000_000), 1_000_000):
            return "복기용 기록"
        return _ORIG_REALTIME_RANK_WATCH_ACTION_LABEL_V254(row)
    except Exception:
        return "복기용 기록"


_ORIG_IS_REALTIME_RANK_PRECISION_CANDIDATE_V254 = is_realtime_rank_precision_candidate
def is_realtime_rank_precision_candidate(row: dict) -> bool:
    """v2.5.254: 돈/체결 확인 없는 후보는 정밀검토 후보로 승격 금지."""
    try:
        row = _v254_apply_unverified_demote(row if isinstance(row, dict) else {})
        if bool(row.get("money_unverified_gate_v254", False)):
            return False
        status = money_status_code_for_row(row)
        ws_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        ws_cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        strongest = _v254_strongest_move(row)
        score = safe_float(row.get("snapshot_rank_score", 0), 0)
        if status in {"tiny", "thin"}:
            if not (strongest >= 1.20 and score >= 9.0 and ws_amt >= 1_000_000 and ws_cnt >= 3):
                return False
        if status not in {"ok", "thin"}:
            return False
        if ws_amt < safe_float(globals().get("RANK_V254_MIN_WS_AMOUNT_FOR_WATCH", 1_000_000), 1_000_000) and _row_turnover_value(row) < 30_000_000:
            return False
        if ws_cnt < int(safe_float(globals().get("RANK_V254_MIN_WS_COUNT_FOR_WATCH", 3), 3)) and _row_turnover_value(row) < 80_000_000:
            return False
        return _ORIG_IS_REALTIME_RANK_PRECISION_CANDIDATE_V254(row)
    except Exception:
        return False


_ORIG_REGISTER_RANK_PRECISION_INTERNAL_WATCH_V254 = register_rank_precision_internal_watch
def register_rank_precision_internal_watch(item: dict, now_ts: float = None, reason: str = "rank_precision_watch") -> bool:
    """v2.5.254: 내부감시는 돈/체결 확인된 후보만. 돈확인전 후보는 대기/복기만 남긴다."""
    global RANK_V254_INTERNAL_WATCH_BLOCK_COUNT
    try:
        if not isinstance(item, dict):
            return False
        watch = _v254_apply_unverified_demote(dict(item))
        if bool(watch.get("money_unverified_gate_v254", False)):
            RANK_V254_INTERNAL_WATCH_BLOCK_COUNT += 1
            append_runtime_event_log("internal_watch_v254_unverified_block", "돈확인전 후보 내부감시 승격 차단", extra={"ticker": str(watch.get("ticker", "")), "score": safe_float(watch.get("snapshot_rank_score", 0), 0)})
            return False
        if not is_realtime_rank_precision_candidate(watch):
            RANK_V254_INTERNAL_WATCH_BLOCK_COUNT += 1
            return False
        try:
            active, _logs = _get_internal_watch_state_parts()
            active_rows = [v for v in (active or {}).values() if isinstance(v, dict)] if isinstance(active, dict) else []
            unverified_active = sum(1 for r in active_rows if _v254_money_unverified(r))
            if unverified_active >= int(safe_float(globals().get("RANK_V254_MAX_UNVERIFIED_ACTIVE_WATCH", 2), 2)):
                RANK_V254_INTERNAL_WATCH_BLOCK_COUNT += 1
                return False
        except Exception:
            pass
        return _ORIG_REGISTER_RANK_PRECISION_INTERNAL_WATCH_V254(watch, now_ts=now_ts, reason=reason)
    except Exception as e:
        try:
            append_runtime_event_log("rank_precision_internal_watch_error_v254", "v254 내부감시 등록 오류", extra={"error": str(e)[:120]})
        except Exception:
            pass
        return False


_ORIG_QUEUE_SLOW_OHLCV_PREFETCH_FOR_ITEMS_V254 = globals().get('queue_slow_ohlcv_prefetch_for_items')
def queue_slow_ohlcv_prefetch_for_items(items, reason: str = "", max_items: int = 1):
    """v2.5.254: minute240/day 선조회가 timeout을 재발시켜 안정화 전까지 차단."""
    try:
        globals()["RANK_V254_REST_BLOCKED_COUNT"] = int(safe_float(globals().get("RANK_V254_REST_BLOCKED_COUNT", 0), 0)) + 1
        globals()["SLOW_OHLCV_PREFETCH_LAST_RESULT"] = "v254 상위봉 REST 차단"
    except Exception:
        pass
    return 0


_ORIG_QUEUE_PRECISION_MINUTE1_CHART_VERIFY_V254 = queue_precision_minute1_chart_verify
def queue_precision_minute1_chart_verify(row: dict, reason: str = "internal_watch") -> bool:
    """v2.5.254: 정밀 1분봉은 돈/WS 확인된 최상위 후보만 큐 등록. 실제 worker도 신규 REST 금지."""
    try:
        row = _v254_apply_unverified_demote(row if isinstance(row, dict) else {})
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return False
        if bool(row.get("money_unverified_gate_v254", False)):
            _precision_minute1_reject("money_unverified_v254", ticker, {"reason": reason})
            return False
        status = money_status_code_for_row(row)
        ws_amt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        ws_cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        turnover = _row_turnover_value(row)
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        strongest = _v254_strongest_move(row)
        if status not in {"ok", "thin"}:
            _precision_minute1_reject("money_status_block_v254", ticker, {"status": status})
            return False
        if score < 12.0 and strongest < 1.8:
            _precision_minute1_reject("score_block_v254", ticker, {"score": score, "move": strongest})
            return False
        if ws_amt < 5_000_000 and turnover < 80_000_000:
            _precision_minute1_reject("ws_money_block_v254", ticker, {"ws": ws_amt, "turnover": turnover})
            return False
        if ws_cnt < 3 and turnover < 100_000_000:
            _precision_minute1_reject("ws_count_block_v254", ticker, {"cnt": ws_cnt, "turnover": turnover})
            return False
        return _ORIG_QUEUE_PRECISION_MINUTE1_CHART_VERIFY_V254(row, reason=reason)
    except Exception as e:
        try:
            append_runtime_event_log("precision_minute1_queue_error_v254", "v254 정밀 1분봉 큐 오류", extra={"error": str(e)[:120]})
        except Exception:
            pass
        return False


def verify_realtime_rank_turnover_once(ticker: str, reason: str = "worker") -> bool:
    """v2.5.254: 대금확인은 캐시/WS/light snapshot만. 신규 minute1 REST 절대 금지."""
    global REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM, REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT, REALTIME_RANK_TURNOVER_VERIFY_DONE, REALTIME_RANK_TURNOVER_VERIFY_FAIL, RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM = ticker
    now_ts = time.time()
    try:
        cached_df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1") * 8, copy_dataframe=True)
        if cached_df is not None and len(cached_df) >= 1:
            vals = _compute_turnover_from_minute_df(cached_df)
            if int(vals.get("rows", 0)) > 0:
                vals.update({"ticker": ticker, "status": "ok", "source": "minute1_cache_only_v254", "reason": str(reason)[:80], "verified": True, "next_retry_at": now_ts + REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC})
                _save_verified_turnover_state(ticker, vals)
                store_precision_minute1_chart_state(ticker, cached_df, source="minute1_cache_only_v254", reason="turnover_verify_cache_v254")
                REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
                RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY += 1
                REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"캐시확인 {safe_float(vals.get('turnover_5m', 0), 0):,.0f}원"
                return True
    except Exception:
        pass
    try:
        s60 = get_ws_trade_summary_for_ticker(ticker, 60) if 'get_ws_trade_summary_for_ticker' in globals() else {}
        amount60 = safe_float((s60 or {}).get("amount", 0), 0)
        count60 = int(safe_float((s60 or {}).get("count", 0), 0))
        if amount60 > 0:
            vals = {"ticker": ticker, "turnover_1m": amount60, "turnover_3m": amount60, "turnover_5m": amount60, "turnover_15m": amount60, "rows": count60, "status": "ok", "source": "ws_trade_amount_v254", "reason": str(reason)[:80], "verified": True, "next_retry_at": now_ts + 300}
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
            RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY += 1
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"WS대금 {amount60:,.0f}원"
            return True
    except Exception:
        pass
    try:
        rows = _light_snapshot_rows(ticker) if '_light_snapshot_rows' in globals() else []
        recent = [r for r in rows if now_ts - safe_float((r or {}).get("ts", 0), 0) <= 300]
        turn = max([safe_float((r or {}).get("turnover_hint", 0), 0) for r in recent] or [0])
        if turn > 0:
            vals = {"ticker": ticker, "turnover_1m": turn, "turnover_3m": turn, "turnover_5m": turn, "turnover_15m": turn, "rows": len(recent), "status": "ok", "source": "light_snapshot_turnover_hint_v254", "reason": str(reason)[:80], "verified": False, "next_retry_at": now_ts + 600}
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
            RANK_V253_OHLCV_SAVED_BY_CACHE_ONLY += 1
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"스냅샷대금 {turn:,.0f}원"
            return True
    except Exception:
        pass
    _save_verified_turnover_state(ticker, {"ticker": ticker, "status": "deferred", "source": "cache_ws_only_v254", "reason": "no_cached_ws_turnover", "fail_detail": "v2.5.254: 신규 minute1 REST 금지. 돈 확인전 후보는 승격하지 않고 WS/캐시 대기", "verified": False, "next_retry_at": now_ts + REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC})
    REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
    REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = "캐시/WS대금 대기"
    return False


def process_precision_minute1_chart_once(ticker: str, reason: str = "worker") -> bool:
    """v2.5.254: 정밀 1분봉 신규 REST 호출 완전 차단. 캐시 또는 light snapshot pseudo만 사용."""
    global PRECISION_MINUTE1_FAIL, PRECISION_MINUTE1_LAST_ITEM, PRECISION_MINUTE1_LAST_RESULT, RANK_V254_PRECISION_PSEUDO_COUNT, RANK_V254_REST_BLOCKED_COUNT
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    PRECISION_MINUTE1_LAST_ITEM = ticker
    try:
        df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), get_ohlcv_cache_ttl("minute1") * 10, copy_dataframe=True)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source="minute1_cache_only_v254", reason=reason)
            PRECISION_MINUTE1_LAST_RESULT = "캐시확인"
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC", 600), 600), "success_cache_v254")
            return bool(st.get("precision_chart_verified", False))
    except Exception:
        pass
    try:
        price = 0.0
        rows = _light_snapshot_rows(ticker) if '_light_snapshot_rows' in globals() else []
        if rows:
            price = safe_float((rows[-1] or {}).get("price", 0), 0)
        pseudo = build_light_snapshot_pseudo_df(ticker, price=price) if 'build_light_snapshot_pseudo_df' in globals() else None
        if pseudo is not None and len(pseudo) >= 8:
            st = store_precision_minute1_chart_state(ticker, pseudo, source="ws_light_snapshot_pseudo_v254", reason=reason)
            RANK_V254_PRECISION_PSEUDO_COUNT += 1
            PRECISION_MINUTE1_LAST_RESULT = "스냅샷보조"
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC", 600), 600), "pseudo_v254")
            return bool(st.get("precision_chart_verified", False))
        store_precision_minute1_chart_state(ticker, df=None, source="ws_light_snapshot_pseudo_v254", reason="no_cache_no_pseudo_v254", row_hint={"ticker": ticker})
        RANK_V254_REST_BLOCKED_COUNT += 1
        PRECISION_MINUTE1_LAST_RESULT = "REST차단/스냅샷부족"
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_QUOTA_COOLDOWN_SEC", 900), 900), "rest_blocked_v254")
        return False
    except Exception as e:
        PRECISION_MINUTE1_FAIL += 1
        PRECISION_MINUTE1_LAST_RESULT = f"오류:{e.__class__.__name__}"
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get("PRECISION_MINUTE1_FAIL_COOLDOWN_SEC", 3600), 3600), "pseudo_error_v254")
        try:
            append_runtime_event_log("precision_minute1_worker_error_v254", "v254 정밀 1분봉 캐시/스냅샷 처리 오류", extra={"ticker": ticker, "error": str(e)[:120]})
        except Exception:
            pass
        return False


_ORIG_BUILD_CACHE_STATUS_TEXT_V254 = build_cache_status_text
def build_cache_status_text():
    try:
        base = _ORIG_BUILD_CACHE_STATUS_TEXT_V254()
    except Exception as e:
        base = f"🧊 명령어 캐시 상태 /cache_status\n- 기본 상태 생성 오류: {e}"
    try:
        extra = [
            "",
            "🧱 v2.5.254 강제 안정화",
            f"- 신규 OHLCV 차단: 정밀1분봉/상위봉 prefetch 신규 REST 금지 / 차단 {int(safe_float(globals().get('RANK_V254_REST_BLOCKED_COUNT',0),0))}회",
            f"- 돈확인 게이트: WS/캐시 대금 부착 {int(safe_float(globals().get('RANK_V254_WS_MONEY_ATTACH_COUNT',0),0))}회 / 돈확인전 강등 {int(safe_float(globals().get('RANK_V254_UNVERIFIED_DEMOTE_COUNT',0),0))}회 / 내부감시 차단 {int(safe_float(globals().get('RANK_V254_INTERNAL_WATCH_BLOCK_COUNT',0),0))}회",
            f"- 정밀차트: 캐시 또는 스냅샷 보조만 사용 / pseudo {int(safe_float(globals().get('RANK_V254_PRECISION_PSEUDO_COUNT',0),0))}회",
            f"- v254 상태: {globals().get('RANK_V254_LAST_NOTE','대기')}",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base

