def _m1v255_decision(reason: str, ticker: str = ""):
    try:
        d = globals().setdefault('MINUTE1_CENTRAL_DECISIONS_V255', {})
        if not isinstance(d, dict):
            d = {}
        k = str(reason or 'unknown')[:40]
        d[k] = int(safe_float(d.get(k, 0), 0)) + 1
        globals()['MINUTE1_CENTRAL_DECISIONS_V255'] = d
        globals()['MINUTE1_CENTRAL_LAST_V255'] = f"{k} {ticker}"[:120]
    except Exception:
        pass


def _m1v255_cache(ticker: str, mult: float = 16.0):
    try:
        ticker = str(ticker or '').upper().strip()
        if not ticker:
            return None
        return get_api_cache_entry(API_OHLCV_CACHE, (ticker, 'minute1'), get_ohlcv_cache_ttl('minute1') * max(1.0, safe_float(mult, 16.0)), copy_dataframe=True)
    except Exception:
        return None


def _m1v255_circuit_left() -> float:
    try:
        return max(0.0, safe_float(globals().get('MINUTE1_CENTRAL_CIRCUIT_UNTIL_V255', 0), 0) - time.time())
    except Exception:
        return 0.0


def _m1v255_note_timeout(ticker: str = '', reason: str = ''):
    try:
        now_ts = time.time()
        window = safe_float(globals().get('MINUTE1_CENTRAL_TIMEOUT_WINDOW_SEC_V255', 300), 300)
        limit = int(safe_float(globals().get('MINUTE1_CENTRAL_TIMEOUT_LIMIT_V255', 3), 3))
        arr = globals().setdefault('MINUTE1_CENTRAL_TIMEOUT_TIMES_V255', [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= window]
        arr.append(now_ts)
        globals()['MINUTE1_CENTRAL_TIMEOUT_TIMES_V255'] = arr[-20:]
        globals()['MINUTE1_CENTRAL_TIMEOUT_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_TIMEOUT_V255', 0), 0)) + 1
        try:
            if '_precision_minute1_note_timeout' in globals():
                _precision_minute1_note_timeout()
        except Exception:
            pass
        if len(arr) >= limit:
            cd = safe_float(globals().get('MINUTE1_CENTRAL_TIMEOUT_COOLDOWN_SEC_V255', 420), 420)
            globals()['MINUTE1_CENTRAL_CIRCUIT_UNTIL_V255'] = now_ts + cd
            globals()['MINUTE1_CENTRAL_CIRCUIT_REASON_V255'] = f"minute1 timeout {len(arr)}건/{int(window)}초"
            append_runtime_event_log('minute1_central_circuit_v255', '1분봉 중앙 큐 timeout 누적으로 잠시 쿨다운', extra={'ticker': ticker, 'reason': reason, 'cooldown_sec': cd})
    except Exception:
        pass


def _m1v255_store_wait(ticker: str, reason: str, row: dict = None, note: str = ''):
    try:
        ticker = str(ticker or '').upper().strip()
        if not ticker:
            return {}
        hint = dict(row or {}) if isinstance(row, dict) else {'ticker': ticker}
        hint['ticker'] = ticker
        hint['precision_waiting_v255'] = True
        hint['precision_waiting_reason_v255'] = str(reason or '')[:100]
        if note:
            hint['precision_waiting_note_v255'] = str(note)[:160]
        st = store_precision_minute1_chart_state(ticker, df=None, source='minute1_central_wait_v255', reason=str(reason)[:80], row_hint=hint)
        try:
            d = _precision_minute1_state_dict()
            if isinstance(d.get(ticker), dict):
                d[ticker]['precision_chart_source'] = 'minute1_central_wait_v255'
                d[ticker]['precision_chart_note'] = note or '정밀 1분봉 중앙 큐 대기'
                d[ticker]['precision_waiting_v255'] = True
                d[ticker]['precision_waiting_reason_v255'] = str(reason or '')[:100]
        except Exception:
            pass
        return st
    except Exception:
        return {}


def _m1v255_fetch_quota_open() -> bool:
    try:
        now_ts = time.time()
        arr = globals().setdefault('PRECISION_MINUTE1_FETCH_TIMES', [])
        if not isinstance(arr, list):
            arr = []
        arr = [x for x in arr if now_ts - safe_float(x, 0) <= 60]
        globals()['PRECISION_MINUTE1_FETCH_TIMES'] = arr
        return len(arr) < int(safe_float(globals().get('MINUTE1_CENTRAL_MAX_FETCH_PER_MIN_V255', 2), 2))
    except Exception:
        return False


def _m1v255_record_fetch():
    try:
        arr = globals().setdefault('PRECISION_MINUTE1_FETCH_TIMES', [])
        if not isinstance(arr, list):
            arr = []
        arr.append(time.time())
        globals()['PRECISION_MINUTE1_FETCH_TIMES'] = arr[-30:]
    except Exception:
        pass


def _m1v255_enqueue(ticker: str, reason: str = 'central', row: dict = None, priority: float = 0.0, force: bool = False) -> bool:
    global MINUTE1_CENTRAL_REQ_V255, MINUTE1_CENTRAL_ACCEPT_V255, MINUTE1_CENTRAL_DUP_V255
    try:
        ticker = str(ticker or '').upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            _m1v255_decision('skip_ticker', ticker)
            return False
        row = dict(row or {}) if isinstance(row, dict) else {'ticker': ticker}
        row['ticker'] = ticker
        MINUTE1_CENTRAL_REQ_V255 += 1
        try:
            remain = _precision_minute1_cooldown_remaining(ticker) if '_precision_minute1_cooldown_remaining' in globals() else 0.0
            if remain > 0 and not force:
                _m1v255_store_wait(ticker, 'cooldown_wait_v255', row, f'쿨다운 {int(remain)}초, 후보는 유지')
                _m1v255_decision('cooldown_wait', ticker)
                return False
        except Exception:
            pass
        with PRECISION_MINUTE1_QUEUE_LOCK:
            q = globals().setdefault('PRECISION_MINUTE1_QUEUE', [])
            if not isinstance(q, list):
                q = []
                globals()['PRECISION_MINUTE1_QUEUE'] = q
            if any(isinstance(x, dict) and str(x.get('ticker', '') or '').upper().strip() == ticker for x in q):
                MINUTE1_CENTRAL_DUP_V255 += 1
                _m1v255_store_wait(ticker, 'already_queued_v255', row, '이미 중앙 큐에 있음')
                _m1v255_decision('duplicate', ticker)
                return False
            item = {'ticker': ticker, 'requested_at': time.time(), 'reason': str(reason or 'central')[:80], 'score': safe_float(row.get('snapshot_rank_score', row.get('lite_score', 0)), 0), 'priority': safe_float(priority, 0), 'row_hint': row}
            q.append(item)
            q.sort(key=lambda x: (safe_float((x or {}).get('priority', 0), 0), safe_float((x or {}).get('score', 0), 0), -safe_float((x or {}).get('requested_at', 0), 0)), reverse=True)
            max_q = int(safe_float(globals().get('MINUTE1_CENTRAL_QUEUE_MAX_V255', 12), 12))
            if len(q) > max_q:
                dropped = q[max_q:]
                del q[max_q:]
                for d in dropped:
                    if isinstance(d, dict):
                        _m1v255_store_wait(str(d.get('ticker', '')), 'queue_overflow_v255', d.get('row_hint', {}), '중앙 큐가 꽉 차서 다음 차수 대기')
        MINUTE1_CENTRAL_ACCEPT_V255 += 1
        _m1v255_store_wait(ticker, f'queued:{reason}', row, '정밀 1분봉 중앙 큐 대기')
        _m1v255_decision('accepted', ticker)
        return True
    except Exception as e:
        append_runtime_event_log('minute1_central_enqueue_error_v255', '1분봉 중앙 큐 등록 오류', extra={'ticker': ticker, 'error': str(e)[:120]})
        return False


def queue_precision_minute1_chart_verify(row: dict, reason: str = 'internal_watch') -> bool:
    """v2.5.255: v254 score_block을 완화하고, 신규 REST 대신 중앙 큐로만 보낸다."""
    try:
        if not bool(globals().get('PRECISION_MINUTE1_CHART_ON', True)):
            return False
        row = dict(row or {}) if isinstance(row, dict) else {}
        ticker = str(row.get('ticker', '') or '').upper().strip()
        if not ticker:
            _precision_minute1_reject('empty_ticker_v255', ticker, {})
            return False
        if bool(row.get('rank_tick_noise_block', False)) or is_realtime_rank_tick_noise(row) or is_rank_watch_low_price_tick_noise_v237(row):
            _precision_minute1_reject('tick_noise_v255', ticker, {})
            _m1v255_store_wait(ticker, 'tick_noise_v255', row, '틱노이즈라 정밀 1분봉 우선순위 제외')
            return False
        try:
            st = get_precision_minute1_chart_state(ticker, max_age_sec=safe_float(globals().get('PRECISION_MINUTE1_RECENT_STATE_BLOCK_SEC', 90), 90))
            if st:
                _precision_minute1_reject('recent_state_v255', ticker, {})
                return False
        except Exception:
            pass
        try:
            row = _v254_attach_ws_and_money(row) if '_v254_attach_ws_and_money' in globals() else row
        except Exception:
            pass
        score = safe_float(row.get('snapshot_rank_score', row.get('lite_score', 0)), 0)
        strongest = _row_strongest_rank_move(row) if '_row_strongest_rank_move' in globals() else max(safe_float(row.get('change_3', 0), 0), safe_float(row.get('change_5', 0), 0), safe_float(row.get('change_30', 0), 0))
        ws_amt = safe_float(row.get('ws_trade_amount_60s', 0), 0)
        ws_cnt = int(safe_float(row.get('ws_trade_count_60s', 0), 0))
        turnover = _row_turnover_value(row) if '_row_turnover_value' in globals() else safe_float(row.get('turnover_5m', 0), 0)
        money_code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else 'unknown'
        low_signal = score < 4.2 and strongest < 0.65 and ws_amt <= 0 and turnover <= 0
        if low_signal:
            _precision_minute1_reject('low_priority_wait_v255', ticker, {'score': score, 'move': strongest})
            _m1v255_store_wait(ticker, 'low_priority_wait_v255', row, '점수/상승/돈이 모두 약해서 정밀대기만 유지')
            return False
        if money_code in {'actual_zero', 'tiny'} and score < 7.0 and strongest < 1.3 and ws_amt < 300_000:
            _precision_minute1_reject('money_tiny_wait_v255', ticker, {'money': money_code, 'score': score})
            _m1v255_store_wait(ticker, 'money_tiny_wait_v255', row, '실제돈이 작아 정밀대기만 유지, 후보 기록은 버리지 않음')
            return False
        priority = 0.0
        if score >= 8.0: priority += 2.0
        elif score >= 5.2: priority += 1.2
        if strongest >= 1.8: priority += 2.0
        elif strongest >= 0.9: priority += 1.0
        if ws_amt >= 900_000 or ws_cnt >= 3: priority += 1.3
        if turnover >= 24_000_000: priority += 1.2
        if str(reason or '').lower() in {'internal_watch', 'rank_precision_watch', 'turnover_verify', 'callback'}: priority += 0.6
        _precision_minute1_accept(ticker, {'ticker': ticker, 'score': score, 'strongest': strongest, 'priority': priority, 'decision': 'central_queue_v255', 'reason': reason})
        return _m1v255_enqueue(ticker, f'precision:{reason}', row, priority)
    except Exception as e:
        append_runtime_event_log('precision_minute1_queue_error_v255', 'v255 정밀 1분봉 큐 오류', extra={'error': str(e)[:120]})
        return False


def get_ohlcv(ticker: str, interval: str = 'minute3', allow_slow_fetch: bool = False):
    """v2.5.255: minute1 신규 REST 직접 호출 금지. 중앙 큐만 네트워크 호출한다."""
    try:
        interval_key = str(interval or 'minute3').lower().strip()
        ticker_key = str(ticker or '').upper().strip()
        if interval_key != 'minute1' or not bool(globals().get('MINUTE1_CENTRAL_QUEUE_V255_ON', True)):
            return _ORIG_GET_OHLCV_V255(ticker, interval=interval, allow_slow_fetch=allow_slow_fetch)
        cached = _m1v255_cache(ticker_key, 16.0)
        if cached is not None:
            return cached
        now_ts = time.time()
        d = globals().setdefault('MINUTE1_CENTRAL_DIRECT_TS_V255', {})
        if not isinstance(d, dict): d = {}
        if now_ts - safe_float(d.get(ticker_key, 0), 0) >= safe_float(globals().get('MINUTE1_CENTRAL_DIRECT_COOLDOWN_SEC_V255', 45), 45):
            d[ticker_key] = now_ts
            globals()['MINUTE1_CENTRAL_DIRECT_TS_V255'] = d
            globals()['MINUTE1_CENTRAL_DIRECT_REDIRECT_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_DIRECT_REDIRECT_V255', 0), 0)) + 1
            _m1v255_enqueue(ticker_key, 'direct_get_ohlcv_redirect_v255', {'ticker': ticker_key}, 0.2)
        return None
    except Exception:
        try:
            return _ORIG_GET_OHLCV_V255(ticker, interval=interval, allow_slow_fetch=False)
        except Exception:
            return None


def verify_realtime_rank_turnover_once(ticker: str, reason: str = 'worker') -> bool:
    """v2.5.255: 대금확인도 직접 minute1 REST를 기다리지 않고 중앙 큐로 예약한다."""
    global REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM, REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT, REALTIME_RANK_TURNOVER_VERIFY_DONE, REALTIME_RANK_TURNOVER_VERIFY_FAIL
    ticker = str(ticker or '').upper().strip()
    if not ticker: return False
    REALTIME_RANK_TURNOVER_VERIFY_LAST_ITEM = ticker
    now_ts = time.time()
    try:
        df = _m1v255_cache(ticker, 12.0)
        if df is not None and len(df) >= 1:
            vals = _compute_turnover_from_minute_df(df)
            if int(vals.get('rows', 0)) > 0:
                vals.update({'ticker': ticker, 'status': 'ok', 'source': 'minute1_cache_v255', 'reason': str(reason)[:80], 'verified': True, 'next_retry_at': now_ts + REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC})
                _save_verified_turnover_state(ticker, vals)
                try: store_precision_minute1_chart_state(ticker, df, source='minute1_cache_v255', reason='turnover_verify_cache_v255')
                except Exception: pass
                REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
                REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"캐시확인 {safe_float(vals.get('turnover_5m',0),0):,.0f}원"
                globals()['MINUTE1_CENTRAL_CACHE_OK_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_CACHE_OK_V255', 0), 0)) + 1
                return True
    except Exception:
        pass
    try:
        s60 = get_ws_trade_summary_for_ticker(ticker, 60) if 'get_ws_trade_summary_for_ticker' in globals() else {}
        amount60 = safe_float((s60 or {}).get('amount', 0), 0)
        count60 = int(safe_float((s60 or {}).get('count', 0), 0))
        if amount60 > 0:
            vals = {'ticker': ticker, 'turnover_1m': amount60, 'turnover_3m': amount60, 'turnover_5m': amount60, 'turnover_15m': amount60, 'rows': count60, 'status': 'ok', 'source': 'ws_trade_amount_v255', 'reason': str(reason)[:80], 'verified': True, 'next_retry_at': now_ts + 240}
            _save_verified_turnover_state(ticker, vals)
            REALTIME_RANK_TURNOVER_VERIFY_DONE += 1
            REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = f"WS대금 {amount60:,.0f}원"
            return True
    except Exception:
        pass
    try:
        _m1v255_enqueue(ticker, f'turnover_verify:{reason}', {'ticker': ticker}, 1.0)
        _save_verified_turnover_state(ticker, {'ticker': ticker, 'status': 'pending', 'source': 'minute1_central_queue_v255', 'reason': str(reason)[:80], 'fail_detail': '1분봉 중앙 큐 대기. 명령어/순위는 API를 기다리지 않음', 'verified': False, 'next_retry_at': now_ts + REALTIME_RANK_TURNOVER_VERIFY_FAIL_REPEAT_SEC})
        REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = '중앙큐 대기'
        return False
    except Exception:
        REALTIME_RANK_TURNOVER_VERIFY_FAIL += 1
        REALTIME_RANK_TURNOVER_VERIFY_LAST_RESULT = '중앙큐 등록 실패'
        return False


def process_precision_minute1_chart_once(ticker: str, reason: str = 'worker') -> bool:
    """v2.5.255: 중앙 큐 worker만 신규 minute1 REST를 제한 호출한다."""
    global PRECISION_MINUTE1_FAIL, PRECISION_MINUTE1_LAST_ITEM, PRECISION_MINUTE1_LAST_RESULT, MINUTE1_CENTRAL_LAST_TICKER_V255, MINUTE1_CENTRAL_LAST_REASON_V255, MINUTE1_CENTRAL_LAST_V255
    ticker = str(ticker or '').upper().strip()
    if not ticker: return False
    PRECISION_MINUTE1_LAST_ITEM = ticker
    MINUTE1_CENTRAL_LAST_TICKER_V255 = ticker
    MINUTE1_CENTRAL_LAST_REASON_V255 = str(reason or 'worker')[:80]
    try:
        df = _m1v255_cache(ticker, 12.0)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source='minute1_cache_v255', reason=reason)
            vals = _compute_turnover_from_minute_df(df)
            if int(vals.get('rows', 0)) > 0:
                vals.update({'ticker': ticker, 'status': 'ok', 'source': 'minute1_cache_v255', 'reason': str(reason)[:80], 'verified': True, 'next_retry_at': time.time() + REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC})
                _save_verified_turnover_state(ticker, vals)
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get('PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC', 300), 300), 'success_cache_v255')
            PRECISION_MINUTE1_LAST_RESULT = '중앙큐/캐시확인'
            MINUTE1_CENTRAL_LAST_V255 = '캐시확인'
            globals()['MINUTE1_CENTRAL_CACHE_OK_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_CACHE_OK_V255', 0), 0)) + 1
            return bool(st.get('precision_chart_verified', False))
    except Exception:
        pass
    try:
        left = _m1v255_circuit_left()
        if left > 0 or is_ohlcv_circuit_open() or (not _m1v255_fetch_quota_open()):
            note = f"중앙 큐 쿨다운/쿼터 대기 {int(left)}초" if left > 0 else '중앙 큐 쿼터 대기'
            _m1v255_store_wait(ticker, 'central_quota_or_circuit_v255', {'ticker': ticker}, note)
            _precision_minute1_set_cooldown(ticker, 180, 'central_defer_v255')
            PRECISION_MINUTE1_LAST_RESULT = note
            MINUTE1_CENTRAL_LAST_V255 = note
            globals()['MINUTE1_CENTRAL_DEFER_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_DEFER_V255', 0), 0)) + 1
            return False
        _m1v255_record_fetch()
        try: shorten_ohlcv_cooldown_for_priority(ticker, 'minute1', max_cooldown_sec=4)
        except Exception: pass
        df = _ORIG_GET_OHLCV_V255(ticker, interval='minute1', allow_slow_fetch=True)
        if df is not None and len(df) >= 4:
            st = store_precision_minute1_chart_state(ticker, df, source='minute1_central_rest_v255', reason=reason)
            vals = _compute_turnover_from_minute_df(df)
            if int(vals.get('rows', 0)) > 0:
                vals.update({'ticker': ticker, 'status': 'ok', 'source': 'minute1_central_rest_v255', 'reason': str(reason)[:80], 'verified': True, 'next_retry_at': time.time() + REALTIME_RANK_TURNOVER_VERIFY_TTL_SEC})
                _save_verified_turnover_state(ticker, vals)
            _precision_minute1_set_cooldown(ticker, safe_float(globals().get('PRECISION_MINUTE1_SUCCESS_COOLDOWN_SEC', 300), 300), 'success_rest_v255')
            PRECISION_MINUTE1_LAST_RESULT = '중앙큐/REST확인'
            MINUTE1_CENTRAL_LAST_V255 = 'REST확인'
            globals()['MINUTE1_CENTRAL_REST_OK_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_REST_OK_V255', 0), 0)) + 1
            return bool(st.get('precision_chart_verified', False))
        reason_txt = get_api_call_last_failure_reason('get_ohlcv', max_age_sec=5.0) if 'get_api_call_last_failure_reason' in globals() else 'no_rows'
        is_timeout = 'timeout' in str(reason_txt).lower() or '초과' in str(reason_txt)
        if is_timeout: _m1v255_note_timeout(ticker, reason_txt)
        try:
            price = 0.0
            rows = _light_snapshot_rows(ticker) if '_light_snapshot_rows' in globals() else []
            if rows: price = safe_float((rows[-1] or {}).get('price', 0), 0)
            pseudo = build_light_snapshot_pseudo_df(ticker, price=price) if 'build_light_snapshot_pseudo_df' in globals() else None
            if pseudo is not None and len(pseudo) >= 4:
                store_precision_minute1_chart_state(ticker, pseudo, source='ws_light_snapshot_pseudo_v255_after_rest_fail', reason=reason)
                globals()['MINUTE1_CENTRAL_PSEUDO_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_PSEUDO_V255', 0), 0)) + 1
                MINUTE1_CENTRAL_LAST_V255 = f"스냅샷보조({reason_txt})"
            else:
                _m1v255_store_wait(ticker, 'rest_fail_wait_v255', {'ticker': ticker}, f"1분봉 REST 실패 후 정밀대기: {str(reason_txt)[:80]}")
                MINUTE1_CENTRAL_LAST_V255 = f"정밀대기({reason_txt})"
        except Exception:
            _m1v255_store_wait(ticker, 'rest_fail_wait_v255', {'ticker': ticker}, '1분봉 REST 실패 후 정밀대기')
        PRECISION_MINUTE1_FAIL = int(safe_float(globals().get('PRECISION_MINUTE1_FAIL', 0), 0)) + 1
        globals()['MINUTE1_CENTRAL_REST_FAIL_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_REST_FAIL_V255', 0), 0)) + 1
        _precision_minute1_set_cooldown(ticker, safe_float(globals().get('PRECISION_MINUTE1_TIMEOUT_COOLDOWN_SEC' if is_timeout else 'PRECISION_MINUTE1_FAIL_COOLDOWN_SEC', 600), 600), 'timeout_v255' if is_timeout else 'rest_fail_v255')
        PRECISION_MINUTE1_LAST_RESULT = MINUTE1_CENTRAL_LAST_V255
        return False
    except Exception as e:
        PRECISION_MINUTE1_FAIL = int(safe_float(globals().get('PRECISION_MINUTE1_FAIL', 0), 0)) + 1
        globals()['MINUTE1_CENTRAL_REST_FAIL_V255'] = int(safe_float(globals().get('MINUTE1_CENTRAL_REST_FAIL_V255', 0), 0)) + 1
        if 'timeout' in str(e).lower(): _m1v255_note_timeout(ticker, str(e))
        _m1v255_store_wait(ticker, 'central_error_v255', {'ticker': ticker}, f"중앙 큐 오류 후 후보 유지: {e.__class__.__name__}")
        _precision_minute1_set_cooldown(ticker, 600, 'central_error_v255')
        PRECISION_MINUTE1_LAST_RESULT = f"오류:{e.__class__.__name__}"
        MINUTE1_CENTRAL_LAST_V255 = PRECISION_MINUTE1_LAST_RESULT
        append_runtime_event_log('minute1_central_process_error_v255', '1분봉 중앙 큐 처리 오류', extra={'ticker': ticker, 'error': str(e)[:120]})
        return False


def build_cache_status_text():
    try:
        base = _ORIG_BUILD_CACHE_STATUS_TEXT_V255()
    except Exception as e:
        base = f"🧊 명령어 캐시 상태 /cache_status\n- 기본 상태 생성 오류: {e}"
    try:
        if isinstance(base, str) and '\n🧱 v2.5.254 강제 안정화' in base:
            base = base.split('\n🧱 v2.5.254 강제 안정화')[0].rstrip()
        q = globals().get('PRECISION_MINUTE1_QUEUE', [])
        q_len = len(q) if isinstance(q, list) else 0
        decisions = globals().get('MINUTE1_CENTRAL_DECISIONS_V255', {}) if isinstance(globals().get('MINUTE1_CENTRAL_DECISIONS_V255', {}), dict) else {}
        dec_text = ', '.join([f"{k}:{v}" for k, v in sorted(decisions.items(), key=lambda kv: safe_float(kv[1], 0), reverse=True)[:5]]) or '-'
        left = _m1v255_circuit_left()
        circuit = f" / 회로 {int(left)}초 남음({globals().get('MINUTE1_CENTRAL_CIRCUIT_REASON_V255','')})" if left > 0 else ""
        extra = [
            '',
            '🧠 v2.5.255 1분봉 중앙 큐',
            f"- 원칙: minute1 직접 REST 금지 → 중앙 큐만 제한 호출 / 대기 {q_len}개{circuit}",
            f"- 큐: 요청 {int(safe_float(globals().get('MINUTE1_CENTRAL_REQ_V255',0),0))} / 등록 {int(safe_float(globals().get('MINUTE1_CENTRAL_ACCEPT_V255',0),0))} / 중복 {int(safe_float(globals().get('MINUTE1_CENTRAL_DUP_V255',0),0))} / 직접호출전환 {int(safe_float(globals().get('MINUTE1_CENTRAL_DIRECT_REDIRECT_V255',0),0))}",
            f"- 처리: 캐시 {int(safe_float(globals().get('MINUTE1_CENTRAL_CACHE_OK_V255',0),0))} / REST성공 {int(safe_float(globals().get('MINUTE1_CENTRAL_REST_OK_V255',0),0))} / 실패 {int(safe_float(globals().get('MINUTE1_CENTRAL_REST_FAIL_V255',0),0))} / timeout {int(safe_float(globals().get('MINUTE1_CENTRAL_TIMEOUT_V255',0),0))} / 스냅샷보조 {int(safe_float(globals().get('MINUTE1_CENTRAL_PSEUDO_V255',0),0))} / 대기처리 {int(safe_float(globals().get('MINUTE1_CENTRAL_DEFER_V255',0),0))}",
            f"- 최근: {globals().get('MINUTE1_CENTRAL_LAST_TICKER_V255','') or '-'} / {globals().get('MINUTE1_CENTRAL_LAST_V255','-')} / 이유 {globals().get('MINUTE1_CENTRAL_LAST_REASON_V255','-')}",
            f"- 큐판정: {dec_text}",
            '- v255 의미: 1분봉은 살리되 캐시/순위/명령어는 절대 1분봉 API를 기다리지 않음',
        ]
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base



# =========================================================
# v2.5.256: 매수/손절/익절 신호 1차 + 알림 라우팅 정리 + API 병목 추가 차단
# =========================================================
PUSH_ONLY_TRADE_SIGNAL_V256 = True
WATCH_PUSH_ALERTS_DISABLED_V256 = True
SIGNAL_COMMAND_DEFAULT_LIMIT_V256 = 5
SIGNAL_COMMAND_SOURCE_LIMIT_V256 = 24
SIGNAL_V256_HISTORY = deque(maxlen=80)
SIGNAL_V256_STATS = {"built": 0, "buy": 0, "pullback": 0, "breakout": 0, "discard": 0, "watch_push_blocked": 0}

# get_tickers는 시장 전체를 여는 첫 관문이라 timeout이 나면 모든 스캔이 흔들린다.
# v256부터는 티커 목록을 매우 오래 재사용하고, force 요청도 쿨다운 안에서는 캐시만 쓴다.
TICKER_LIST_REFRESH_SEC = max(int(safe_float(globals().get("TICKER_LIST_REFRESH_SEC", 300), 300)), 3600)
TICKER_LIST_FORCE_MIN_INTERVAL_SEC = max(int(safe_float(globals().get("TICKER_LIST_FORCE_MIN_INTERVAL_SEC", 180), 180)), 900)
TICKER_LIST_CALL_TIMEOUT_SEC = min(float(safe_float(globals().get("TICKER_LIST_CALL_TIMEOUT_SEC", 2.5), 2.5)), 1.2)
TICKER_LIST_STALE_KEEP_SEC_V256 = 6 * 3600
TICKER_LIST_FORCE_CACHE_REUSE_SEC_V256 = 900
TICKER_LIST_FETCH_FAIL_COOLDOWN_SEC_V256 = 900
TICKER_LIST_V256_REUSE_COUNT = 0
TICKER_LIST_V256_FETCH_COUNT = 0
TICKER_LIST_V256_FAIL_COUNT = 0
TICKER_LIST_V256_SKIP_COUNT = 0
TICKER_LIST_V256_LAST_NOTE = "대기"

# 내부감시 가격 추적은 WS를 더 오래 믿고, light snapshot을 rest_bulk보다 먼저 본다.
PRICE_TRACK_WS_TTL_SEC = max(float(safe_float(globals().get("PRICE_TRACK_WS_TTL_SEC", 20.0), 20.0)), 45.0)
PRICE_TRACK_LIGHT_TTL_SEC = max(float(safe_float(globals().get("PRICE_TRACK_LIGHT_TTL_SEC", 45.0), 45.0)), 90.0)
PRICE_TRACK_REST_STALE_SEC = min(float(safe_float(globals().get("PRICE_TRACK_REST_STALE_SEC", 30.0), 30.0)), 15.0)
PRICE_TRACK_V256_WS_FIRST_COUNT = 0
PRICE_TRACK_V256_LIGHT_FIRST_COUNT = 0
PRICE_TRACK_V256_REST_BULK_COUNT = 0
PRICE_TRACK_V256_MISS_COUNT = 0
PRICE_TRACK_V256_LAST_NOTE = "대기"

_ORIG_GET_CACHED_MARKET_TICKERS_V256 = get_cached_market_tickers
def get_cached_market_tickers(force=False):
    """v2.5.256: get_tickers timeout 뿌리 차단."""
    global market_all_tickers, market_all_tickers_time, last_ticker_fetch_attempt_ts
    global TICKER_LIST_V256_REUSE_COUNT, TICKER_LIST_V256_FETCH_COUNT, TICKER_LIST_V256_FAIL_COUNT, TICKER_LIST_V256_SKIP_COUNT, TICKER_LIST_V256_LAST_NOTE
    now_ts = time.time()
    try:
        cached = [str(t or "").upper().strip() for t in list(market_all_tickers or []) if str(t or "").strip()]
        age = now_ts - safe_float(market_all_tickers_time, 0) if market_all_tickers_time else 999999.0
        since_attempt = now_ts - safe_float(last_ticker_fetch_attempt_ts, 0)
        if cached:
            if age <= TICKER_LIST_REFRESH_SEC:
                TICKER_LIST_V256_REUSE_COUNT += 1
                TICKER_LIST_V256_LAST_NOTE = f"캐시 재사용({int(age)}초)"
                return list(cached)
            if force and age <= TICKER_LIST_STALE_KEEP_SEC_V256 and since_attempt < TICKER_LIST_FORCE_CACHE_REUSE_SEC_V256:
                TICKER_LIST_V256_SKIP_COUNT += 1
                TICKER_LIST_V256_LAST_NOTE = f"force 캐시 재사용({int(age)}초/재시도 {int(since_attempt)}초)"
                return list(cached)
            if age <= TICKER_LIST_STALE_KEEP_SEC_V256 and since_attempt < TICKER_LIST_FETCH_FAIL_COOLDOWN_SEC_V256:
                TICKER_LIST_V256_SKIP_COUNT += 1
                TICKER_LIST_V256_LAST_NOTE = f"stale 캐시 유지({int(age)}초/재시도대기)"
                return list(cached)
        else:
            if since_attempt < TICKER_FALLBACK_RETRY_SEC:
                fallback = [t for t in DEFAULT_MARKET_TICKERS if t]
                if fallback:
                    TICKER_LIST_V256_SKIP_COUNT += 1
                    TICKER_LIST_V256_LAST_NOTE = "캐시 없음/기본목록 사용"
                    return list(fallback)
        before_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
        TICKER_LIST_V256_FETCH_COUNT += 1
        rows = _ORIG_GET_CACHED_MARKET_TICKERS_V256(force=force)
        after_timeout = int(safe_float(globals().get("API_CALL_TIMEOUT_COUNT", 0), 0))
        clean = [str(t or "").upper().strip() for t in list(rows or []) if str(t or "").strip()]
        if clean:
            if after_timeout > before_timeout:
                TICKER_LIST_V256_FAIL_COUNT += 1
                TICKER_LIST_V256_LAST_NOTE = f"timeout 뒤 캐시/기본목록 {len(clean)}개 유지"
            else:
                TICKER_LIST_V256_LAST_NOTE = f"정상/캐시 {len(clean)}개"
            return clean
        fallback = list(cached or [t for t in DEFAULT_MARKET_TICKERS if t])
        if fallback:
            TICKER_LIST_V256_FAIL_COUNT += 1
            TICKER_LIST_V256_LAST_NOTE = "빈 응답 → 기존/기본목록 유지"
            return fallback
        return []
    except Exception as e:
        TICKER_LIST_V256_FAIL_COUNT += 1
        TICKER_LIST_V256_LAST_NOTE = f"오류:{e.__class__.__name__}"
        fallback = list(market_all_tickers or [t for t in DEFAULT_MARKET_TICKERS if t])
        return fallback

_ORIG_GET_CACHED_REALTIME_PRICE_V256 = get_cached_realtime_price
def get_cached_realtime_price(ticker: str, caller: str = "", allow_api_cache: bool = True):
    """v2.5.256: 내부감시 성과추적은 WS/light snapshot 우선, rest_bulk는 짧은 stale 백업으로 제한한다."""
    global PRICE_TRACK_V256_WS_FIRST_COUNT, PRICE_TRACK_V256_LIGHT_FIRST_COUNT, PRICE_TRACK_V256_REST_BULK_COUNT, PRICE_TRACK_V256_MISS_COUNT, PRICE_TRACK_V256_LAST_NOTE
    caller_key = str(caller or "unknown")[:80]
    ticker_key = str(ticker or "").upper().strip()
    if caller_key == "internal_watch_tracking":
        try:
            price, age = _get_ws_recent_price(ticker_key, max_age_sec=PRICE_TRACK_WS_TTL_SEC)
            if price > 0:
                PRICE_TRACK_V256_WS_FIRST_COUNT += 1
                PRICE_TRACK_V256_LAST_NOTE = f"WS {ticker_key}/{int(age)}초"
                _record_price_source(caller_key, "ws", ticker_key)
                return price, "ws", age
            price, age = _get_light_recent_price(ticker_key, max_age_sec=PRICE_TRACK_LIGHT_TTL_SEC)
            if price > 0:
                PRICE_TRACK_V256_LIGHT_FIRST_COUNT += 1
                PRICE_TRACK_V256_LAST_NOTE = f"light {ticker_key}/{int(age)}초"
                _record_price_source(caller_key, "light_snapshot", ticker_key)
                return price, "light_snapshot", age
            if allow_api_cache:
                try:
                    cached = get_api_cache_entry(API_PRICE_CACHE, ticker_key, API_PRICE_CACHE_TTL_SEC * 6)
                    p = safe_float(cached, 0) if cached is not None else 0.0
                    if p > 0:
                        PRICE_TRACK_V256_LIGHT_FIRST_COUNT += 1
                        PRICE_TRACK_V256_LAST_NOTE = f"api_cache {ticker_key}"
                        _record_price_source(caller_key, "api_cache", ticker_key)
                        return p, "api_cache", 0.0
                except Exception:
                    pass
            # rest_bulk는 네트워크 직접 호출이 아니라 이미 만들어진 전체현재가 캐시만 짧게 사용한다.
            price, age = _get_bulk_cached_price(ticker_key, max_age_sec=PRICE_TRACK_REST_STALE_SEC)
            if price > 0:
                PRICE_TRACK_V256_REST_BULK_COUNT += 1
                PRICE_TRACK_V256_LAST_NOTE = f"rest_bulk backup {ticker_key}/{int(age)}초"
                _record_price_source(caller_key, "rest_bulk_backup_v256", ticker_key)
                return price, "rest_bulk_backup_v256", age
            PRICE_TRACK_V256_MISS_COUNT += 1
            PRICE_TRACK_V256_LAST_NOTE = f"miss {ticker_key}"
            _record_price_source(caller_key, "miss", ticker_key)
            return 0.0, "none", 999999.0
        except Exception:
            PRICE_TRACK_V256_MISS_COUNT += 1
            return 0.0, "none", 999999.0
    return _ORIG_GET_CACHED_REALTIME_PRICE_V256(ticker_key, caller=caller, allow_api_cache=allow_api_cache)


def _signal_v256_price(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    for k in ["current_price", "price", "last_price", "close", "base_price"]:
        p = safe_float(row.get(k, 0), 0)
        if p > 0:
            return p
    try:
        ticker = str(row.get("ticker", "") or "").upper().strip()
        p, _src, _age = get_cached_realtime_price(ticker, caller="signal_v256", allow_api_cache=True)
        return safe_float(p, 0)
    except Exception:
        return 0.0


def _signal_v256_high_gap(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    for k in ["below_30m_high_pct", "below_high", "rebreakout_gap_pct", "high_gap_pct", "chart_lifecycle_gap_pct", "chart_gap_pct"]:
        f = safe_float(row.get(k, 999), 999)
        if 0 <= f < 900:
            return f
    try:
        return safe_float(get_effective_high_gap_pct(row), 999) if 'get_effective_high_gap_pct' in globals() else 999.0
    except Exception:
        return 999.0


def _signal_v256_from_low(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    for k in ["from_30m_low_pct", "from_low", "chart_lifecycle_from_low_pct", "chart_rise_pct", "low_from_ref_pct_v2"]:
        f = safe_float(row.get(k, 0), 0)
        if abs(f) > 0.0001:
            return f
    return 0.0


def _signal_v256_money_status(row: dict):
    try:
        code = money_status_code_for_row(row) if 'money_status_code_for_row' in globals() else "unknown"
    except Exception:
        code = "unknown"
    try:
        sustain = format_money_sustain_compact(row) if 'format_money_sustain_compact' in globals() else "확인중"
    except Exception:
        sustain = "확인중"
    amount = max(safe_float(row.get("ws_trade_amount_60s", 0), 0), safe_float(row.get("turnover_5m", 0), 0), safe_float(row.get("turnover", 0), 0), safe_float(row.get("verified_turnover_5m", 0), 0))
    cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
    buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
    return code, sustain, amount, cnt, buy


def _signal_v256_classify(row: dict) -> dict:
    row = row if isinstance(row, dict) else {}
    ticker = str(row.get("ticker", "") or "").upper().strip()
    price = _signal_v256_price(row)
    score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", row.get("edge_score", 0))), 0)
    chg3 = safe_float(row.get("change_3", row.get("chg_3m", 0)), 0)
    chg5 = safe_float(row.get("change_5", row.get("chg_5m", 0)), 0)
    chg15 = safe_float(row.get("change_15", row.get("chg_15m", 0)), 0)
    chg30 = safe_float(row.get("change_30", row.get("chg_30m", 0)), 0)
    high_gap = _signal_v256_high_gap(row)
    from_low = _signal_v256_from_low(row)
    money_code, money_sustain, money_amount, trade_count, buy_ratio = _signal_v256_money_status(row)
    try:
        weak_candle = bool(is_current_candle_weak_for_label_v244(row)) if 'is_current_candle_weak_for_label_v244' in globals() else False
    except Exception:
        weak_candle = False
    candle_label = str(row.get("current_candle_label", row.get("current_candle_code", "")) or "")
    try:
        high_ctx = classify_high_rebreakout_hold_v248(row) if 'classify_high_rebreakout_hold_v248' in globals() else {}
    except Exception:
        high_ctx = {}
    high_code = str((high_ctx or {}).get("code", row.get("high_rebreakout_v248_code", "")) or "")
    high_label = str((high_ctx or {}).get("label", row.get("high_rebreakout_v248_label", "")) or "")
    try:
        low_route = get_low_structure_route_label_v244(row) if 'get_low_structure_route_label_v244' in globals() else str(row.get("low_structure_route_v244", "") or "")
    except Exception:
        low_route = str(row.get("low_structure_route_v244", "") or "")
    try:
        final_ctx = build_final_candidate_display_context_v251(row) if 'build_final_candidate_display_context_v251' in globals() else {}
    except Exception:
        final_ctx = {}
    reasons = []
    good_money = money_code in {"ok", "thin"} and money_amount >= 1_000_000
    strong_money = money_amount >= 30_000_000 or safe_float(row.get("turnover", 0), 0) >= 100_000_000
    buy_ok = (trade_count <= 0 or buy_ratio <= 0 or buy_ratio >= 50.0)
    sell_heavy = (trade_count >= 5 and 0 < buy_ratio <= 45.0) or ("매도우세" in money_sustain)
    current_good = ("살아남" in candle_label or "회복" in candle_label or safe_float(row.get("current_candle_live_score", 0), 0) >= 1.8) and not weak_candle
    current_bad = weak_candle or "밀림" in candle_label or "위꼬리" in candle_label
    near_high_bad = 0 <= high_gap <= 0.25 and high_code != "rebreak_hold"
    too_extended = (from_low >= 3.2 and 0 <= high_gap <= 1.0) or str((final_ctx or {}).get("state_label", "")).find("추격금지") >= 0

    if money_code in {"actual_zero", "tiny"} or money_amount < 100_000:
        decision = "버림"; grade = "DISCARD"; reasons.append("실제 돈이 너무 작음")
    elif sell_heavy:
        decision = "버림"; grade = "DISCARD"; reasons.append("최근 체결이 매도 우세")
    elif current_bad:
        decision = "버림"; grade = "DISCARD"; reasons.append("현재봉이 밀림/위꼬리")
    elif too_extended:
        decision = "버림"; grade = "DISCARD"; reasons.append("저점대비 진행 후 고점 근처라 늦음")
    elif high_code == "rebreak_hold" and good_money and current_good and score >= 5.8:
        decision = "돌파 확인 대기"; grade = "BREAKOUT_WAIT"; reasons.append("고점 재돌파 유지 확인")
    elif high_code in {"near_high_watch", "near_high_reject"} or near_high_bad:
        decision = "돌파 확인 대기"; grade = "BREAKOUT_WAIT"; reasons.append("고점 앞이라 유지 확인 필요")
    elif low_route in {"저점높임 재출발형", "저점방어 재출발형", "저점방어 관찰형"} and good_money and not current_bad:
        decision = "눌림 대기"; grade = "PULLBACK_WAIT"; reasons.append(low_route)
    elif score >= 7.2 and good_money and buy_ok and current_good and high_gap >= 0.45 and from_low <= 2.8:
        decision = "지금 매수 가능"; grade = "BUY_OK"; reasons.append("돈/현재봉/거리 조건 통과")
    elif score >= 5.0 and strong_money and max(chg3, chg5) >= 0.25 and not current_bad:
        decision = "눌림 대기"; grade = "PULLBACK_WAIT"; reasons.append("움직임은 있으나 바로 추격은 애매")
    else:
        decision = "버림"; grade = "DISCARD"; reasons.append("매수 신호로는 근거 부족")

    if not reasons:
        reasons.append(str((final_ctx or {}).get("one_liner", "판단 근거 확인중")) or "판단 근거 확인중")
    action = {
        "BUY_OK": "지금 가격대 진입 가능. 단, 손절 기준 깨지면 바로 버림.",
        "PULLBACK_WAIT": "지금 시장가 추격 말고 매수 가능 구간까지 눌릴 때만 봄.",
        "BREAKOUT_WAIT": "고점 위에서 유지 확인되기 전까지 시장가 추격 금지.",
        "DISCARD": "지금 돈 넣을 후보 아님. 명령어/복기에서만 추적.",
    }.get(grade, "상태 확인")
    try:
        reasons = _dedupe_reason_bits_v251(reasons) if '_dedupe_reason_bits_v251' in globals() else reasons
    except Exception:
        pass
    return {"ticker": ticker, "price": price, "score": score, "chg3": chg3, "chg5": chg5, "chg15": chg15, "chg30": chg30, "high_gap": high_gap, "from_low": from_low, "money_code": money_code, "money_sustain": money_sustain, "money_amount": money_amount, "trade_count": trade_count, "buy_ratio": buy_ratio, "weak_candle": weak_candle, "candle_label": candle_label, "high_code": high_code, "high_label": high_label, "low_route": low_route, "decision": decision, "grade": grade, "reasons": reasons, "action": action}


def _signal_v256_compute_prices(row: dict, cls: dict) -> dict:
    price = safe_float(cls.get("price", 0), 0)
    high_gap = safe_float(cls.get("high_gap", 999), 999)
    from_low = safe_float(cls.get("from_low", 0), 0)
    if price <= 0:
        return {"entry_low": 0, "entry_high": 0, "chase_stop": 0, "stop": 0, "tp1": 0, "tp2": 0, "tp3": 0, "support": 0, "resistance": 0, "risk_pct": 0}
    resistance = price / max(0.0001, (1.0 - high_gap / 100.0)) if 0 < high_gap < 80 else price * 1.012
    support = price / (1.0 + from_low / 100.0) if from_low > 0 else price * 0.985
    if resistance <= price:
        resistance = price * 1.012
    grade = str(cls.get("grade", ""))
    if grade == "BUY_OK":
        entry_low, entry_high = price * 0.996, price * 1.003
        chase_stop = min(price * 1.018, resistance * 1.004 if resistance > price else price * 1.018)
    elif grade == "BREAKOUT_WAIT":
        entry_low, entry_high = max(price, resistance * 0.998), resistance * 1.006
        chase_stop = resistance * 1.018
    elif grade == "PULLBACK_WAIT":
        entry_low, entry_high = max(support * 1.003, price * 0.982), price * 0.997
        if entry_low > entry_high:
            entry_low, entry_high = price * 0.985, price * 0.998
        chase_stop = price * 1.006
    else:
        entry_low, entry_high, chase_stop = 0.0, 0.0, price * 1.004
    stop = min(support * 0.996, price * 0.986)
    if grade == "BREAKOUT_WAIT":
        stop = min(price * 0.986, resistance * 0.988)
    stop = max(stop, price * 0.965)
    risk_pct = max(((price - stop) / price) * 100.0, 0.6)
    tp1 = max(resistance, price * (1.0 + max(0.90, risk_pct * 0.85) / 100.0))
    tp2 = max(tp1 * 1.006, price * (1.0 + max(1.80, risk_pct * 1.55) / 100.0))
    tp3 = max(tp2 * 1.008, price * (1.0 + max(3.00, risk_pct * 2.40) / 100.0))
    return {"entry_low": entry_low, "entry_high": entry_high, "chase_stop": chase_stop, "stop": stop, "tp1": tp1, "tp2": tp2, "tp3": tp3, "support": support, "resistance": resistance, "risk_pct": risk_pct}


def _signal_v256_rows(source_limit: int = None) -> list:
    source_limit = int(source_limit or SIGNAL_COMMAND_SOURCE_LIMIT_V256)
    try:
        rows = list(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", []) or [])
    except Exception:
        rows = []
    if not rows:
        try:
            rows = list(get_light_snapshot_rank_rows(limit=source_limit, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT) or [])
        except Exception:
            rows = []
    out, seen = [], set()
    for row in rows[:max(source_limit, 1)]:
        if not isinstance(row, dict):
            continue
        tk = str(row.get("ticker", "") or "").upper().strip()
        if not tk or tk in seen:
            continue
        seen.add(tk)
        try:
            rr = apply_watch_display_consistency_v244(dict(row)) if 'apply_watch_display_consistency_v244' in globals() else dict(row)
        except Exception:
            rr = dict(row)
        out.append(rr)
    return out


def _signal_v256_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    cls = _signal_v256_classify(row)
    prices = _signal_v256_compute_prices(row, cls)
    SIGNAL_V256_STATS["built"] = int(safe_float(SIGNAL_V256_STATS.get("built", 0), 0)) + 1
    grade = str(cls.get("grade", ""))
    stat_key = {"BUY_OK": "buy", "PULLBACK_WAIT": "pullback", "BREAKOUT_WAIT": "breakout", "DISCARD": "discard"}.get(grade, "discard")
    SIGNAL_V256_STATS[stat_key] = int(safe_float(SIGNAL_V256_STATS.get(stat_key, 0), 0)) + 1
    ticker = cls.get("ticker", "?") or "?"
    price = safe_float(cls.get("price", 0), 0)
    icon = {"BUY_OK": "🔥", "PULLBACK_WAIT": "🟡", "BREAKOUT_WAIT": "🟠", "DISCARD": "⛔"}.get(grade, "📌")
    reasons = "·".join([str(x) for x in list(cls.get("reasons") or [])[:3]])
    money_amt = safe_float(cls.get("money_amount", 0), 0)
    money_text = f"{money_amt:,.0f}원" if money_amt >= 1000000 else fmt_price(money_amt)
    lines = [
        f"{order}. {icon} {ticker} / {cls.get('decision')} / 현재가 {fmt_price_detail(price)} / 점수 {safe_float(cls.get('score',0),0):.2f}",
        f"- 흐름: 3m {safe_float(cls.get('chg3',0),0):+.2f}% / 5m {safe_float(cls.get('chg5',0),0):+.2f}% / 15m {safe_float(cls.get('chg15',0),0):+.2f}% / 30m {safe_float(cls.get('chg30',0),0):+.2f}% / 저점대비 {safe_float(cls.get('from_low',0),0):+.2f}% / 고점거리 {safe_float(cls.get('high_gap',999),999):.2f}%",
        f"- 돈/체결: {cls.get('money_sustain')} / 대금 {money_text} / 60초 {int(safe_float(cls.get('trade_count',0),0))}건·매수 {safe_float(cls.get('buy_ratio',0),0):.0f}% / 현재봉 {str(cls.get('candle_label','') or '확인중')}",
        f"- 결론: {cls.get('action')} / 이유: {reasons}",
    ]
    if grade == "DISCARD":
        lines.append(f"- 가격표: 매수 신호 아님 / 추격금지 {fmt_price_detail(prices.get('chase_stop',0))} 이상")
    else:
        lines.append(f"- 가격표: 진입 {fmt_price_detail(prices.get('entry_low',0))} ~ {fmt_price_detail(prices.get('entry_high',0))} / 추격금지 {fmt_price_detail(prices.get('chase_stop',0))} 이상 / 손절 {fmt_price_detail(prices.get('stop',0))}")
        lines.append(f"- 익절: TP1 {fmt_price_detail(prices.get('tp1',0))} / TP2 {fmt_price_detail(prices.get('tp2',0))} / TP3 {fmt_price_detail(prices.get('tp3',0))}")
    if show_detail:
        extra = []
        if str(cls.get("high_label", "") or ""):
            extra.append(f"고점 {cls.get('high_label')}")
        if str(cls.get("low_route", "") or ""):
            extra.append(f"저점 {cls.get('low_route')}")
        if extra:
            lines.append("- 구조: " + " / ".join(extra))
    try:
        SIGNAL_V256_HISTORY.append({"ts": time.time(), "ticker": ticker, "grade": grade, "decision": cls.get("decision"), "price": price, "entry_low": prices.get("entry_low", 0), "entry_high": prices.get("entry_high", 0), "stop": prices.get("stop", 0), "tp1": prices.get("tp1", 0), "tp2": prices.get("tp2", 0), "tp3": prices.get("tp3", 0)})
    except Exception:
        pass
    return "\n".join(lines)


def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v256_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V256, limit * 3))
    if target:
        rows = [r for r in rows if str(r.get("ticker", "") or "").upper().strip() == target]
    if not rows:
        return "\n".join(["🎯 매수·손절·익절 신호 /signal", "- 아직 신호 계산에 쓸 순위 스냅샷이 없어.", "- 먼저 /rank_short에서 후보가 보이는지 확인해줘.", "- 이 명령은 새 OHLCV/API를 직접 호출하지 않고 저장된 스냅샷만 사용해."])
    ranked = []
    weight = {"BUY_OK": 4, "BREAKOUT_WAIT": 3, "PULLBACK_WAIT": 2, "DISCARD": 1}
    for r in rows:
        c = _signal_v256_classify(r)
        ranked.append((weight.get(c.get("grade"), 0), safe_float(c.get("score", 0), 0), safe_float(c.get("chg3", 0), 0), r))
    ranked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
    picked = [r for *_rest, r in ranked[:max(1, limit)]]
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    lines = ["🎯 매수·손절·익절 신호 /signal", f"- 시각: {now_line}", "- 새 API/OHLCV 직접조회 없음. 최신 rank 스냅샷 기준 계산.", "- 자동매수 연결 전 검증용 1차 계산표. 실제 체결 전에는 차트/호가 확인 필요.", "- 즉시 푸시 알림은 앞으로 매수·매도 신호만 허용. 관심/복기/내부감시는 명령어에서만 봄.", ""]
    for idx, row in enumerate(picked, start=1):
        lines.append(_signal_v256_format_one(row, order=idx, show_detail=bool(target)))
        lines.append("")
    lines.append("명령어: /signal 코인명  예) /signal A")
    return "\n".join(lines).strip()


