def signal_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    try:
        args = getattr(context, 'args', []) if context is not None else []
        send_text_chunks(build_signal_text_v256(args=args), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('signal_command_v256', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /signal 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


