def is_trade_signal_push_allowed_v256(payload: dict) -> bool:
    if not PUSH_ONLY_TRADE_SIGNAL_V256:
        return True
    if not isinstance(payload, dict):
        return False
    kind = str(payload.get("kind", payload.get("signal_kind", "")) or "").upper()
    grade = str(payload.get("grade", "") or "").upper()
    return kind in {"BUY_SIGNAL", "SELL_SIGNAL", "STOP_LOSS_SIGNAL", "TAKE_PROFIT_SIGNAL", "STRONG_BREAKOUT_ENTRY"} or grade in {"BUY_OK", "SELL", "STOP", "TP"}

_ORIG_SEND_WATCH_ALERT_BUNDLE_V256 = send_watch_alert_bundle
def send_watch_alert_bundle(header: str, entries, section_key: str = ""):
    """v2.5.256: 관심/봐야할/내부감시 후보 즉시푸시 금지."""
    try:
        if not PUSH_ONLY_TRADE_SIGNAL_V256:
            return _ORIG_SEND_WATCH_ALERT_BUNDLE_V256(header, entries, section_key=section_key)
        trade_entries, normal_entries = [], []
        for entry in list(entries or []):
            item = entry[0] if isinstance(entry, (list, tuple)) and entry else entry
            if isinstance(item, dict) and is_trade_signal_push_allowed_v256(item):
                trade_entries.append(entry)
            else:
                normal_entries.append(entry)
        if trade_entries:
            return _ORIG_SEND_WATCH_ALERT_BUNDLE_V256(header, trade_entries, section_key=section_key)
        if normal_entries:
            SIGNAL_V256_STATS["watch_push_blocked"] = int(safe_float(SIGNAL_V256_STATS.get("watch_push_blocked", 0), 0)) + len(normal_entries)
            try:
                save_recent_candidate_alerts(normal_entries, header=f"[명령어 전용 기록] {header}")
            except Exception:
                pass
            try:
                append_runtime_event_log('watch_push_blocked_v256', '관심/내부감시 후보 즉시알림 차단', extra={'section_key': section_key, 'count': len(normal_entries), 'header': str(header or '')[:120]})
            except Exception:
                pass
        return None
    except Exception as e:
        append_runtime_error_log('send_watch_alert_bundle_v256', str(e), exc=e, include_traceback=True)
        return None

_ORIG_MAYBE_SEND_MISSED_REVIEW_ALERT_V256 = maybe_send_missed_review_alert
