# =========================================================
# v2.5.257: /signal 코인명 탐색 정상화 + 약한 돌파대기 강등
# =========================================================
# v256에서 전체 /signal은 동작했지만 /signal 코인명은 상위 rank 일부만 보다가
# "스냅샷 없음"으로 빠질 수 있었다. v257은 rank/review/internal_watch/최근 후보
# 스냅샷을 모두 뒤져서 특정 코인을 계산하고, 체결 없는 고점맞닿음 후보는 상위 신호에서 내린다.
SIGNAL_COMMAND_SOURCE_LIMIT_V257 = 140
SIGNAL_V257_STATS = {"specific_hit": 0, "specific_miss": 0, "weak_breakout_downgrade": 0, "source_rows": 0}


def _signal_v257_ticker(row: dict) -> str:
    try:
        return str((row or {}).get("ticker", "") or "").upper().strip()
    except Exception:
        return ""


def _signal_v257_merge_row(row: dict, source: str = "") -> dict:
    """내부감시 row는 last_snapshot 안에 실제 rank 필드가 들어있는 경우가 많다."""
    row = row if isinstance(row, dict) else {}
    merged = {}
    for key in ["snapshot", "last_snapshot", "rank_snapshot", "source_snapshot", "item", "candidate"]:
        v = row.get(key)
        if isinstance(v, dict):
            merged.update(v)
    merged.update(row)
    ticker = _signal_v257_ticker(merged)
    if not ticker:
        # active dict의 key를 넣어 호출하는 경우 대비
        ticker = _signal_v257_ticker(row)
    if ticker:
        merged["ticker"] = ticker
    if source:
        merged["signal_v257_source"] = source
    # 내부감시 row의 기준/현재가를 signal price 후보로 보강
    for k in ["current", "current_price", "last_price", "price", "base_price", "start_price", "entry_price", " 기준"]:
        p = safe_float(merged.get(k, 0), 0)
        if p > 0:
            merged.setdefault("current_price", p)
            merged.setdefault("price", p)
            break
    return merged


def _signal_v257_collect_rows(source_limit: int = None) -> list:
    source_limit = int(source_limit or SIGNAL_COMMAND_SOURCE_LIMIT_V257)
    rows = []

    def add_many(seq, source):
        try:
            for x in list(seq or []):
                if isinstance(x, dict):
                    rows.append(_signal_v257_merge_row(x, source))
        except Exception:
            pass

    # 1) 명령어 캐시 rank 원본: 전체 /signal이 쓰던 주 소스
    try:
        add_many(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", []) or [], "rank_cache")
    except Exception:
        pass

    # 2) 실시간 light rank 스냅샷: 캐시에 없는 코인 보강
    try:
        add_many(get_light_snapshot_rank_rows(limit=max(source_limit, 80), min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT) or [], "light_rank")
    except Exception:
        pass

    # 3) 내부감시 active/logs: /review_watch에 보이는 코인을 /signal 코인명에서도 찾게 함
    try:
        active, logs = _get_internal_watch_state_parts()
        if isinstance(active, dict):
            for tk, row in list(active.items()):
                if isinstance(row, dict):
                    rr = dict(row)
                    rr.setdefault("ticker", str(tk or "").upper().strip())
                    rows.append(_signal_v257_merge_row(rr, "internal_watch_active"))
        add_many(dedupe_internal_watch_logs(logs or []) if 'dedupe_internal_watch_logs' in globals() else (logs or []), "internal_watch_log")
    except Exception:
        pass

    # 4) 최근 후보/놓침 큐: 상위 rank에서 빠진 특정 코인 조회 보강
    for name, source in [
        ("RECENT_CANDIDATE_ALERTS", "recent_candidate"),
        ("missed_review_logs", "missed_review_log"),
    ]:
        try:
            add_many(globals().get(name, []) or [], source)
        except Exception:
            pass
    try:
        mq = globals().get("missed_review_queue", {}) or {}
        if isinstance(mq, dict):
            add_many(list(mq.values()), "missed_review_queue")
    except Exception:
        pass

    out, seen = [], set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        tk = _signal_v257_ticker(row)
        if not tk:
            continue
        # 같은 코인은 먼저 들어온 rank_cache/light_rank를 우선하되, 내부감시 row도 의미 있으면 병합
        if tk in seen:
            continue
        seen.add(tk)
        try:
            rr = apply_watch_display_consistency_v244(dict(row)) if 'apply_watch_display_consistency_v244' in globals() else dict(row)
        except Exception:
            rr = dict(row)
        out.append(rr)
    SIGNAL_V257_STATS["source_rows"] = len(out)
    return out


def _signal_v257_classify(row: dict) -> dict:
    cls = _signal_v256_classify(row)
    try:
        grade = str(cls.get("grade", "") or "")
        high_gap = safe_float(cls.get("high_gap", 999), 999)
        trade_count = int(safe_float(cls.get("trade_count", 0), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
        score = safe_float(cls.get("score", 0), 0)
        candle = str(cls.get("candle_label", "") or "")
        money_sustain = str(cls.get("money_sustain", "") or "")
        weak_no_trade = trade_count <= 0 and buy_ratio <= 0
        weak_buy_zero = trade_count > 0 and buy_ratio <= 1
        high_touch = 0 <= high_gap <= 0.08
        candle_unclear = (not candle) or ("확인중" in candle) or ("의미 작음" in candle) or ("작은움직임" in candle)
        flash_or_cooling = ("반짝" in money_sustain) or ("식는" in money_sustain)
        downgrade_reason = ""
        if grade == "BREAKOUT_WAIT":
            if weak_no_trade and high_touch:
                downgrade_reason = "60초 체결/매수 없음 + 고점 맞닿음"
            elif weak_buy_zero and high_touch:
                downgrade_reason = "최근 매수 0% + 고점 맞닿음"
            elif weak_no_trade and score < 7.0:
                downgrade_reason = "체결 없는 약한 돌파대기"
            elif score < 5.2:
                downgrade_reason = "점수 낮은 약한 돌파대기"
            elif high_touch and candle_unclear and score < 7.5:
                downgrade_reason = "고점 맞닿음 + 현재봉 확인 부족"
            elif flash_or_cooling and high_touch:
                downgrade_reason = "반짝/식는 중 + 고점 맞닿음"
        if downgrade_reason:
            SIGNAL_V257_STATS["weak_breakout_downgrade"] = int(safe_float(SIGNAL_V257_STATS.get("weak_breakout_downgrade", 0), 0)) + 1
            cls["grade"] = "DISCARD"
            cls["decision"] = "버림"
            cls["action"] = "지금 매수 신호 아님. 돌파대기처럼 보여도 체결/현재봉 근거가 부족해서 명령어 참고용만 유지."
            reasons = list(cls.get("reasons") or [])
            reasons.insert(0, downgrade_reason)
            try:
                reasons = _dedupe_reason_bits_v251(reasons) if '_dedupe_reason_bits_v251' in globals() else reasons
            except Exception:
                pass
            cls["reasons"] = reasons[:4]
            cls["signal_v257_downgraded"] = True
    except Exception:
        pass
    return cls


def _signal_v257_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    cls = _signal_v257_classify(row)
    prices = _signal_v256_compute_prices(row, cls)
    SIGNAL_V256_STATS["built"] = int(safe_float(SIGNAL_V256_STATS.get("built", 0), 0)) + 1
    grade = str(cls.get("grade", ""))
    stat_key = {"BUY_OK": "buy", "PULLBACK_WAIT": "pullback", "BREAKOUT_WAIT": "breakout", "DISCARD": "discard"}.get(grade, "discard")
    SIGNAL_V256_STATS[stat_key] = int(safe_float(SIGNAL_V256_STATS.get(stat_key, 0), 0)) + 1
    ticker = cls.get("ticker", "?") or "?"
    price = safe_float(cls.get("price", 0), 0)
    icon = {"BUY_OK": "🔥", "PULLBACK_WAIT": "🟡", "BREAKOUT_WAIT": "🟠", "DISCARD": "⛔"}.get(grade, "📌")
    reasons = "·".join([str(x) for x in list(cls.get("reasons") or [])[:3]])
    money_amt = safe_float(cls.get("money_amount", 0), 0)
    money_text = f"{money_amt:,.0f}원" if money_amt >= 1000000 else fmt_price(money_amt)
    src = str((row or {}).get("signal_v257_source", "") or "")
    source_note = f" / 출처 {src}" if show_detail and src else ""
    lines = [
        f"{order}. {icon} {ticker} / {cls.get('decision')} / 현재가 {fmt_price_detail(price)} / 점수 {safe_float(cls.get('score',0),0):.2f}{source_note}",
        f"- 흐름: 3m {safe_float(cls.get('chg3',0),0):+.2f}% / 5m {safe_float(cls.get('chg5',0),0):+.2f}% / 15m {safe_float(cls.get('chg15',0),0):+.2f}% / 30m {safe_float(cls.get('chg30',0),0):+.2f}% / 저점대비 {safe_float(cls.get('from_low',0),0):+.2f}% / 고점거리 {safe_float(cls.get('high_gap',999),999):.2f}%",
        f"- 돈/체결: {cls.get('money_sustain')} / 대금 {money_text} / 60초 {int(safe_float(cls.get('trade_count',0),0))}건·매수 {safe_float(cls.get('buy_ratio',0),0):.0f}% / 현재봉 {str(cls.get('candle_label','') or '확인중')}",
        f"- 결론: {cls.get('action')} / 이유: {reasons}",
    ]
    if grade == "DISCARD":
        lines.append(f"- 가격표: 매수 신호 아님 / 추격금지 {fmt_price_detail(prices.get('chase_stop',0))} 이상")
    else:
        lines.append(f"- 가격표: 진입 {fmt_price_detail(prices.get('entry_low',0))} ~ {fmt_price_detail(prices.get('entry_high',0))} / 추격금지 {fmt_price_detail(prices.get('chase_stop',0))} 이상 / 손절 {fmt_price_detail(prices.get('stop',0))}")
        lines.append(f"- 익절: TP1 {fmt_price_detail(prices.get('tp1',0))} / TP2 {fmt_price_detail(prices.get('tp2',0))} / TP3 {fmt_price_detail(prices.get('tp3',0))}")
    if show_detail:
        extra = []
        if str(cls.get("high_label", "") or ""):
            extra.append(f"고점 {cls.get('high_label')}")
        if str(cls.get("low_route", "") or ""):
            extra.append(f"저점 {cls.get('low_route')}")
        if bool(cls.get("signal_v257_downgraded", False)):
            extra.append("v257 약한 돌파대기 강등")
        if extra:
            lines.append("- 구조: " + " / ".join(extra))
    try:
        SIGNAL_V256_HISTORY.append({"ts": time.time(), "ticker": ticker, "grade": grade, "decision": cls.get("decision"), "price": price, "entry_low": prices.get("entry_low", 0), "entry_high": prices.get("entry_high", 0), "stop": prices.get("stop", 0), "tp1": prices.get("tp1", 0), "tp2": prices.get("tp2", 0), "tp3": prices.get("tp3", 0)})
    except Exception:
        pass
    return "\n".join(lines)


def build_signal_text_v256(args=None, limit: int = None) -> str:
    # 이름은 v256으로 유지한다. batch 처리부가 이 이름을 직접 호출하기 때문.
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 12))
    if target:
        target_rows = [r for r in rows if _signal_v257_ticker(r) == target]
        now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
        if not target_rows:
            SIGNAL_V257_STATS["specific_miss"] = int(safe_float(SIGNAL_V257_STATS.get("specific_miss", 0), 0)) + 1
            return "\n".join([
                "🎯 매수·손절·익절 신호 /signal",
                f"- 시각: {now_line}",
                f"- {target}는 현재 rank/review/internal_watch 스냅샷에서 못 찾았어.",
                "- 이건 API/OHLCV를 새로 부르지 않는 명령이라, 최근 스냅샷에 없으면 계산하지 않아.",
                "- /rank_short 또는 /review_watch에 먼저 보이는지 확인.",
            ])
        SIGNAL_V257_STATS["specific_hit"] = int(safe_float(SIGNAL_V257_STATS.get("specific_hit", 0), 0)) + 1
        # 같은 코인이 여러 출처에 있으면 가장 강한 판단을 우선 표시
        ranked_target = []
        weight = {"BUY_OK": 4, "BREAKOUT_WAIT": 3, "PULLBACK_WAIT": 2, "DISCARD": 1}
        for r in target_rows:
            c = _signal_v257_classify(r)
            ranked_target.append((weight.get(c.get("grade"), 0), safe_float(c.get("score", 0), 0), safe_float(c.get("chg3", 0), 0), r))
        ranked_target.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
        picked = [ranked_target[0][-1]]
    else:
        ranked = []
        weight = {"BUY_OK": 4, "BREAKOUT_WAIT": 3, "PULLBACK_WAIT": 2, "DISCARD": 1}
        for r in rows:
            c = _signal_v257_classify(r)
            ranked.append((weight.get(c.get("grade"), 0), safe_float(c.get("score", 0), 0), safe_float(c.get("chg3", 0), 0), c.get("grade"), r))
        ranked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
        valid = [r for *_prefix, grade, r in ranked if grade != "DISCARD"]
        if valid:
            picked = valid[:max(1, limit)]
        else:
            # 진짜 신호가 없으면 버림 후보를 참고용으로만 3개 보여준다.
            picked = [r for *_prefix, r in ranked[:min(3, max(1, limit))]]
    if not rows:
        return "\n".join(["🎯 매수·손절·익절 신호 /signal", "- 아직 신호 계산에 쓸 스냅샷이 없어.", "- 먼저 /rank_short에서 후보가 보이는지 확인해줘.", "- 이 명령은 새 OHLCV/API를 직접 호출하지 않고 저장된 스냅샷만 사용해."])
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    lines = ["🎯 매수·손절·익절 신호 /signal", f"- 시각: {now_line}", "- 새 API/OHLCV 직접조회 없음. rank/review/internal_watch 저장 스냅샷 기준 계산.", "- v2.5.257: /signal 코인명은 내부감시 기록까지 찾아서 계산하고, 체결 없는 고점맞닿음 후보는 강등.", "- 즉시 푸시 알림은 매수·매도 신호만 허용. 관심/복기/내부감시는 명령어에서만 봄.", ""]
    if (not target):
        try:
            valid_count = 0
            for r in rows:
                if _signal_v257_classify(r).get("grade") != "DISCARD":
                    valid_count += 1
            if valid_count <= 0:
                lines.append("- 현재 강한 매수/대기 신호 없음. 아래는 버림/약한 후보 참고용.")
                lines.append("")
        except Exception:
            pass
    for idx, row in enumerate(picked, start=1):
        lines.append(_signal_v257_format_one(row, order=idx, show_detail=True if target else False))
        lines.append("")
    lines.append("명령어: /signal 코인명  예) /signal A")
    return "\n".join(lines).strip()


def build_mock_signal_text_v256() -> str:
    row = {"ticker": "TEST", "price": 100.0, "snapshot_rank_score": 8.2, "change_3": 0.72, "change_5": 0.95, "change_15": 1.35, "change_30": 1.80, "below_30m_high_pct": 1.10, "from_30m_low_pct": 1.25, "turnover_5m": 55000000, "ws_trade_amount_60s": 1800000, "ws_trade_count_60s": 8, "ws_trade_buy_ratio_60s": 64.0, "current_candle_label": "현재봉 확실히 살아남", "high_rebreakout_v248_code": "not_near_high", "high_rebreakout_v248_label": "고점 여유 확인", "low_structure_route_v244": "저점높임 재출발형", "signal_v257_source": "mock"}
    return "🧪 모의 신호 테스트\n- 실제 주문 없음 / 계산 함수만 점검\n- v2.5.257 기준 특정 코인 조회/약한 돌파대기 강등 로직 포함\n\n" + _signal_v257_format_one(row, order=1, show_detail=True)


_ORIG_BUILD_CACHE_STATUS_TEXT_V257 = build_cache_status_text
def build_cache_status_text():
    try:
        base = _ORIG_BUILD_CACHE_STATUS_TEXT_V257()
    except Exception as e:
        base = f"🧊 명령어 캐시 상태 /cache_status\n- 기본 상태 생성 오류: {e}"
    try:
        extra = [
            "",
            "🎯 v2.5.257 /signal 보정",
            f"- 특정코인 조회: 성공 {int(safe_float(SIGNAL_V257_STATS.get('specific_hit',0),0))} / 실패 {int(safe_float(SIGNAL_V257_STATS.get('specific_miss',0),0))} / 수집소스 {int(safe_float(SIGNAL_V257_STATS.get('source_rows',0),0))}개",
            f"- 약한 돌파대기 강등: {int(safe_float(SIGNAL_V257_STATS.get('weak_breakout_downgrade',0),0))}건",
            "- 원칙: /signal 코인명은 rank 캐시뿐 아니라 review/internal_watch 기록까지 찾고, 체결 없는 고점맞닿음은 상위 신호에서 제외한다.",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


def signal_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    try:
        args = getattr(context, 'args', []) if context is not None else []
        send_text_chunks(build_signal_text_v256(args=args), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('signal_command_v257', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /signal 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


def mock_signal_command(update, context: CallbackContext):
    try:
        send_text_chunks(build_mock_signal_text_v256(), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('mock_signal_command_v257', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /mock_signal 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


# =========================================================
# v2.5.258: 모의매매 엔진 / 신호 성과 검증
# =========================================================
# 원칙:
# - 실제 주문 없음.
# - 실전 알림 문턱과 모의매매 등록 문턱을 분리한다.
# - paper_positions.json / paper_trade_log.json은 버전 수정 후에도 자동 초기화하지 않는다.
# - 전체 누적, 오늘, 현재 반나절, 최근 12시간/24시간을 로그 필터로 계산한다. 원본 로그는 보존한다.
PAPER_TRADING_ON = True
PAPER_POSITIONS_FILE = data_file("paper_positions.json")
PAPER_TRADE_LOG_FILE = data_file("paper_trade_log.json")
PAPER_MAX_ACTIVE = 24
PAPER_MAX_NEW_PER_SCAN = 5
PAPER_AUTO_REGISTER_INTERVAL_SEC = 12
PAPER_WORKER_SLEEP_SEC = 4
PAPER_PENDING_TTL_SEC = 45 * 60
PAPER_OPEN_TTL_SEC = 90 * 60
PAPER_DUPLICATE_COOLDOWN_SEC = 15 * 60
PAPER_TRADE_LOG_MAX = 3000
PAPER_FEE_ROUND_TRIP_PCT = 0.10
PAPER_LOOSE_TEST_ON = True
PAPER_LOOSE_SCORE_MIN = 6.2
PAPER_LOOSE_MONEY_MIN = 30_000_000
PAPER_MIN_MONEY_FOR_STRICT = 1_000_000
PAPER_STATE_LOCK = threading.RLock()
paper_positions = {}
paper_trade_log = []
PAPER_V258_STATS = {
    "loaded_positions": 0,
    "loaded_logs": 0,
    "registered": 0,
    "entered": 0,
    "closed": 0,
    "expired": 0,
    "auto_scans": 0,
    "last_auto_ts": 0,
    "last_save_ts": 0,
    "last_note": "대기",
}


def _paper_now_ts_v258():
    return time.time()


def _paper_make_id_v258(ticker: str) -> str:
    return f"P{int(time.time()*1000)}_{str(ticker or '').upper().strip()}"


def _paper_ticker_v258(row: dict) -> str:
    try:
        return str((row or {}).get("ticker", "") or "").upper().strip()
    except Exception:
        return ""


def load_paper_state_v258():
    global paper_positions, paper_trade_log
    try:
        pos_raw = load_json_file(PAPER_POSITIONS_FILE, {})
        log_raw = load_json_file(PAPER_TRADE_LOG_FILE, [])
        with PAPER_STATE_LOCK:
            if isinstance(pos_raw, dict) and "positions" in pos_raw and isinstance(pos_raw.get("positions"), dict):
                paper_positions = dict(pos_raw.get("positions") or {})
            elif isinstance(pos_raw, dict):
                paper_positions = dict(pos_raw)
            else:
                paper_positions = {}
            paper_trade_log = list(log_raw or []) if isinstance(log_raw, list) else []
            PAPER_V258_STATS["loaded_positions"] = len(paper_positions)
            PAPER_V258_STATS["loaded_logs"] = len(paper_trade_log)
            PAPER_V258_STATS["last_note"] = "기존 모의매매 파일 로드/유지"
    except Exception as e:
        append_runtime_error_log("load_paper_state_v258", str(e), exc=e, include_traceback=True)


def save_paper_state_v258():
    try:
        with PAPER_STATE_LOCK:
            pos_snapshot = {str(k): dict(v) for k, v in (paper_positions or {}).items() if isinstance(v, dict)}
            log_snapshot = list(paper_trade_log or [])[-PAPER_TRADE_LOG_MAX:]
            paper_trade_log[:] = log_snapshot
        save_json_file(PAPER_POSITIONS_FILE, {"schema": "paper_v258", "updated_ts": time.time(), "positions": pos_snapshot})
        save_json_file(PAPER_TRADE_LOG_FILE, log_snapshot)
        PAPER_V258_STATS["last_save_ts"] = time.time()
    except Exception as e:
        append_runtime_error_log("save_paper_state_v258", str(e), exc=e, include_traceback=False)


def _paper_open_rows_v258():
    with PAPER_STATE_LOCK:
        return [dict(v) for v in (paper_positions or {}).values() if isinstance(v, dict) and str(v.get("status", "")).upper() in {"PENDING", "OPEN"}]


def _paper_has_active_ticker_v258(ticker: str) -> bool:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return True
    with PAPER_STATE_LOCK:
        for pos in (paper_positions or {}).values():
            if not isinstance(pos, dict):
                continue
            if str(pos.get("ticker", "")).upper().strip() != ticker:
                continue
            if str(pos.get("status", "")).upper() in {"PENDING", "OPEN"}:
                return True
    return False


def _paper_recent_closed_cooldown_v258(ticker: str, now_ts: float = None) -> bool:
    ticker = str(ticker or "").upper().strip()
    now_ts = safe_float(now_ts, time.time())
    try:
        with PAPER_STATE_LOCK:
            for row in reversed(list(paper_trade_log or [])[-80:]):
                if not isinstance(row, dict):
                    continue
                if str(row.get("ticker", "")).upper().strip() != ticker:
                    continue
                close_ts = safe_float(row.get("close_ts", row.get("cancel_ts", 0)), 0)
                if close_ts > 0 and now_ts - close_ts <= PAPER_DUPLICATE_COOLDOWN_SEC:
                    return True
    except Exception:
        pass
    return False


def _paper_price_v258(ticker: str, fallback: float = 0.0):
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return safe_float(fallback, 0), "none", 0.0
    try:
        p, src, age = get_price_for_tracking_with_source(ticker, caller="paper_trade", allow_api_fallback=False)
        if safe_float(p, 0) > 0:
            return float(p), str(src or "cache"), safe_float(age, 0)
    except Exception:
        pass
    p = safe_float(fallback, 0)
    return p, "fallback" if p > 0 else "none", 0.0


def _paper_pct_v258(entry: float, price: float) -> float:
    entry = safe_float(entry, 0)
    price = safe_float(price, 0)
    if entry <= 0 or price <= 0:
        return 0.0
    return ((price - entry) / entry) * 100.0


def _paper_classify_for_register_v258(row: dict):
    cls = _signal_v257_classify(row) if '_signal_v257_classify' in globals() else _signal_v256_classify(row)
    cls = dict(cls or {})
    grade = str(cls.get("grade", "") or "")
    lane = "strict_signal"
    register_ok = grade in {"BUY_OK", "BREAKOUT_WAIT", "PULLBACK_WAIT"}
    reason = "신호층"
    if register_ok:
        if safe_float(cls.get("money_amount", 0), 0) < PAPER_MIN_MONEY_FOR_STRICT:
            register_ok = False
            reason = "실제돈 부족"
    if (not register_ok) and PAPER_LOOSE_TEST_ON:
        score = safe_float(cls.get("score", 0), 0)
        money = safe_float(cls.get("money_amount", 0), 0)
        trade_count = int(safe_float(cls.get("trade_count", 0), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
        weak_candle = bool(cls.get("weak_candle", False))
        reasons = " ".join([str(x) for x in list(cls.get("reasons") or [])])
        bad = ("실제 돈이 너무 작" in reasons) or ("매도 우세" in reasons) or weak_candle
        if (not bad) and score >= PAPER_LOOSE_SCORE_MIN and money >= PAPER_LOOSE_MONEY_MIN and (trade_count >= 2 or buy_ratio >= 50):
            lane = "loose_threshold_test"
            register_ok = True
            reason = "실전 문턱 완화 검증층"
            cls["paper_original_grade"] = grade
            # 매수 신호 아님으로 강등된 후보라도 모의에서는 현재가 진입 실험을 해본다.
            cls["grade"] = "BUY_OK"
            cls["decision"] = "모의검증 진입"
    return register_ok, lane, reason, cls


def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    if not PAPER_TRADING_ON:
        return False
    try:
        ticker = _paper_ticker_v258(row)
        if not ticker:
            return False
        now_ts = time.time()
        if _paper_has_active_ticker_v258(ticker) or _paper_recent_closed_cooldown_v258(ticker, now_ts):
            return False
        if len(_paper_open_rows_v258()) >= PAPER_MAX_ACTIVE:
            return False
        ok, lane, reason, cls = _paper_classify_for_register_v258(row)
        if not ok:
            return False
        prices = _signal_v256_compute_prices(row, cls)
        price = safe_float(cls.get("price", 0), 0)
        if price <= 0:
            return False
        grade = str(cls.get("grade", "") or "")
        entry_rule = "now" if grade == "BUY_OK" else ("breakout" if grade == "BREAKOUT_WAIT" else "pullback")
        status = "OPEN" if entry_rule == "now" else "PENDING"
        entry_price = price if status == "OPEN" else 0.0
        pos_id = _paper_make_id_v258(ticker)
        pos = {
            "id": pos_id,
            "ticker": ticker,
            "status": status,
            "lane": lane,
            "trigger": str(trigger or "auto"),
            "register_reason": reason,
            "signal_grade": grade,
            "signal_decision": str(cls.get("decision", "") or ""),
            "original_grade": str(cls.get("paper_original_grade", grade) or grade),
            "created_ts": now_ts,
            "entry_rule": entry_rule,
            "planned_entry_low": safe_float(prices.get("entry_low", 0), 0),
            "planned_entry_high": safe_float(prices.get("entry_high", 0), 0),
            "chase_stop": safe_float(prices.get("chase_stop", 0), 0),
            "entry_price": entry_price,
            "entered_ts": now_ts if status == "OPEN" else 0.0,
            "last_price": price,
            "last_price_source": "signal_snapshot",
            "stop": safe_float(prices.get("stop", 0), 0),
            "tp1": safe_float(prices.get("tp1", 0), 0),
            "tp2": safe_float(prices.get("tp2", 0), 0),
            "tp3": safe_float(prices.get("tp3", 0), 0),
            "remaining_ratio": 1.0,
            "realized_pct": 0.0,
            "tp1_hit": False,
            "tp2_hit": False,
            "tp3_hit": False,
            "max_up_pct": 0.0,
            "min_down_pct": 0.0,
            "score": safe_float(cls.get("score", 0), 0),
            "money_amount": safe_float(cls.get("money_amount", 0), 0),
            "trade_count": int(safe_float(cls.get("trade_count", 0), 0)),
            "buy_ratio": safe_float(cls.get("buy_ratio", 0), 0),
            "reasons": list(cls.get("reasons") or [])[:5],
            "note": "실제 주문 아님 / 모의매매",
        }
        with PAPER_STATE_LOCK:
            paper_positions[pos_id] = pos
        PAPER_V258_STATS["registered"] = int(safe_float(PAPER_V258_STATS.get("registered", 0), 0)) + 1
        if status == "OPEN":
            PAPER_V258_STATS["entered"] = int(safe_float(PAPER_V258_STATS.get("entered", 0), 0)) + 1
        PAPER_V258_STATS["last_note"] = f"등록 {ticker}/{status}/{lane}"
        save_paper_state_v258()
        return True
    except Exception as e:
        append_runtime_error_log("paper_register_candidate_v258", str(e), exc=e, include_traceback=False)
        return False


def paper_auto_register_from_signal_snapshot_v258(trigger: str = "worker") -> int:
    if not PAPER_TRADING_ON:
        return 0
    added = 0
    try:
        rows = _signal_v257_collect_rows(source_limit=80) if '_signal_v257_collect_rows' in globals() else []
        ranked = []
        weight = {"BUY_OK": 4, "BREAKOUT_WAIT": 3, "PULLBACK_WAIT": 2, "DISCARD": 1}
        for row in list(rows or []):
            try:
                cls = _signal_v257_classify(row)
                ranked.append((weight.get(cls.get("grade"), 0), safe_float(cls.get("score", 0), 0), safe_float(cls.get("money_amount", 0), 0), row))
            except Exception:
                continue
        ranked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
        for _w, _score, _money, row in ranked[:30]:
            if added >= PAPER_MAX_NEW_PER_SCAN:
                break
            if paper_register_candidate_v258(row, trigger=trigger):
                added += 1
        PAPER_V258_STATS["auto_scans"] = int(safe_float(PAPER_V258_STATS.get("auto_scans", 0), 0)) + 1
        PAPER_V258_STATS["last_auto_ts"] = time.time()
    except Exception as e:
        append_runtime_error_log("paper_auto_register_v258", str(e), exc=e, include_traceback=False)
    return added


def _paper_close_position_v258(pos_id: str, pos: dict, price: float, reason: str, now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    entry = safe_float(pos.get("entry_price", 0), 0)
    remaining = max(0.0, min(1.0, safe_float(pos.get("remaining_ratio", 1.0), 1.0)))
    realized = safe_float(pos.get("realized_pct", 0), 0)
    pnl_now = _paper_pct_v258(entry, price)
    gross = realized + remaining * pnl_now
    net = gross - safe_float(PAPER_FEE_ROUND_TRIP_PCT, 0.10)
    row = dict(pos)
    row.update({
        "status": "CLOSED",
        "close_ts": now_ts,
        "close_price": safe_float(price, 0),
        "close_reason": str(reason or "close"),
        "gross_pnl_pct": round(gross, 4),
        "pnl_pct": round(net, 4),
        "fee_assumed_pct": PAPER_FEE_ROUND_TRIP_PCT,
        "held_sec": int(max(0, now_ts - safe_float(pos.get("entered_ts", pos.get("created_ts", now_ts)), now_ts))),
    })
    with PAPER_STATE_LOCK:
        paper_positions.pop(pos_id, None)
        paper_trade_log.append(row)
        if len(paper_trade_log) > PAPER_TRADE_LOG_MAX:
            del paper_trade_log[:-PAPER_TRADE_LOG_MAX]
    PAPER_V258_STATS["closed"] = int(safe_float(PAPER_V258_STATS.get("closed", 0), 0)) + 1
    PAPER_V258_STATS["last_note"] = f"청산 {row.get('ticker')}/{reason}/{net:+.2f}%"
    save_paper_state_v258()


def _paper_cancel_pending_v258(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    row = dict(pos)
    row.update({"status": "CANCELLED", "cancel_ts": now_ts, "close_ts": now_ts, "close_reason": str(reason or "cancel"), "pnl_pct": 0.0})
    with PAPER_STATE_LOCK:
        paper_positions.pop(pos_id, None)
        paper_trade_log.append(row)
        if len(paper_trade_log) > PAPER_TRADE_LOG_MAX:
            del paper_trade_log[:-PAPER_TRADE_LOG_MAX]
    PAPER_V258_STATS["expired"] = int(safe_float(PAPER_V258_STATS.get("expired", 0), 0)) + 1
    save_paper_state_v258()


def paper_update_positions_once_v258():
    if not PAPER_TRADING_ON:
        return
    now_ts = time.time()
    changed = False
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            status = str(pos.get("status", "") or "").upper()
            fallback = safe_float(pos.get("last_price", pos.get("entry_price", 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            pos["last_price"] = price
            pos["last_price_source"] = src
            pos["last_price_age"] = safe_float(age, 0)
            pos["updated_ts"] = now_ts
            if status == "PENDING":
                if now_ts - safe_float(pos.get("created_ts", now_ts), now_ts) >= PAPER_PENDING_TTL_SEC:
                    _paper_cancel_pending_v258(pid, pos, "pending_timeout", now_ts)
                    continue
                entry_rule = str(pos.get("entry_rule", "") or "")
                low = safe_float(pos.get("planned_entry_low", 0), 0)
                high = safe_float(pos.get("planned_entry_high", 0), 0)
                chase = safe_float(pos.get("chase_stop", 0), 0)
                enter = False
                if entry_rule == "breakout" and low > 0 and price >= low and (chase <= 0 or price <= chase):
                    enter = True
                elif entry_rule == "pullback" and low > 0 and high > 0 and low <= price <= high:
                    enter = True
                elif entry_rule == "now":
                    enter = True
                if chase > 0 and price > chase and entry_rule != "now":
                    _paper_cancel_pending_v258(pid, pos, "chase_over_before_entry", now_ts)
                    continue
                if enter:
                    pos["status"] = "OPEN"
                    pos["entry_price"] = price
                    pos["entered_ts"] = now_ts
                    pos["remaining_ratio"] = 1.0
                    pos["realized_pct"] = 0.0
                    PAPER_V258_STATS["entered"] = int(safe_float(PAPER_V258_STATS.get("entered", 0), 0)) + 1
                    changed = True
            if str(pos.get("status", "") or "").upper() == "OPEN":
                entry = safe_float(pos.get("entry_price", 0), 0)
                if entry <= 0:
                    continue
                pnl = _paper_pct_v258(entry, price)
                pos["max_up_pct"] = max(safe_float(pos.get("max_up_pct", pnl), pnl), pnl)
                pos["min_down_pct"] = min(safe_float(pos.get("min_down_pct", pnl), pnl), pnl)
                remaining = max(0.0, min(1.0, safe_float(pos.get("remaining_ratio", 1.0), 1.0)))
                realized = safe_float(pos.get("realized_pct", 0), 0)
                tp1 = safe_float(pos.get("tp1", 0), 0)
                tp2 = safe_float(pos.get("tp2", 0), 0)
                tp3 = safe_float(pos.get("tp3", 0), 0)
                stop = safe_float(pos.get("stop", 0), 0)
                if tp1 > 0 and (not bool(pos.get("tp1_hit", False))) and price >= tp1:
                    hit_pct = _paper_pct_v258(entry, tp1)
                    realized += 0.40 * hit_pct
                    remaining = max(0.0, remaining - 0.40)
                    pos["tp1_hit"] = True
                    pos["tp1_ts"] = now_ts
                    pos["stop"] = max(stop, entry * 1.001)
                    pos["realized_pct"] = realized
                    pos["remaining_ratio"] = remaining
                    changed = True
                if tp2 > 0 and (not bool(pos.get("tp2_hit", False))) and price >= tp2:
                    hit_pct = _paper_pct_v258(entry, tp2)
                    take = min(0.30, remaining)
                    realized += take * hit_pct
                    remaining = max(0.0, remaining - take)
                    pos["tp2_hit"] = True
                    pos["tp2_ts"] = now_ts
                    pos["stop"] = max(safe_float(pos.get("stop", 0), 0), tp1 * 0.995 if tp1 > 0 else entry * 1.003)
                    pos["realized_pct"] = realized
                    pos["remaining_ratio"] = remaining
                    changed = True
                stop = safe_float(pos.get("stop", 0), 0)
                open_age = now_ts - safe_float(pos.get("entered_ts", now_ts), now_ts)
                close_reason = ""
                if tp3 > 0 and price >= tp3:
                    pos["tp3_hit"] = True
                    close_reason = "TP3_full_exit"
                elif remaining <= 0.001:
                    close_reason = "partial_all_taken"
                elif stop > 0 and price <= stop:
                    close_reason = "stop_loss" if not bool(pos.get("tp1_hit", False)) else "protect_stop_after_tp"
                elif open_age >= PAPER_OPEN_TTL_SEC:
                    close_reason = "time_exit"
                elif open_age >= 45 * 60 and (not bool(pos.get("tp1_hit", False))) and pnl <= 0.15:
                    close_reason = "slow_no_progress_exit"
                if close_reason:
                    _paper_close_position_v258(pid, pos, price, close_reason, now_ts)
                    continue
                with PAPER_STATE_LOCK:
                    if pid in paper_positions:
                        paper_positions[pid].update(pos)
                changed = True
        if changed:
            save_paper_state_v258()
    except Exception as e:
        append_runtime_error_log("paper_update_positions_v258", str(e), exc=e, include_traceback=False)


def paper_trade_worker_loop_v258():
    last_register_ts = 0.0
    while True:
        try:
            paper_update_positions_once_v258()
            now_ts = time.time()
            if PAPER_TRADING_ON and now_ts - last_register_ts >= PAPER_AUTO_REGISTER_INTERVAL_SEC:
                paper_auto_register_from_signal_snapshot_v258(trigger="worker")
                last_register_ts = now_ts
        except Exception as e:
            append_runtime_error_log("paper_worker_v258", str(e), exc=e, include_traceback=False)
        time.sleep(max(1.0, safe_float(PAPER_WORKER_SLEEP_SEC, 4)))


def _paper_closed_logs_v258(include_cancelled: bool = False):
    with PAPER_STATE_LOCK:
        rows = [dict(x) for x in list(paper_trade_log or []) if isinstance(x, dict)]
    if include_cancelled:
        return rows
    return [x for x in rows if str(x.get("status", "")).upper() == "CLOSED" and safe_float(x.get("entry_price", 0), 0) > 0]


def _paper_window_start_v258(kind: str, now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    kind = str(kind or "total")
    if kind == "total":
        return 0.0
    if kind == "12h":
        return now_ts - 12 * 3600
    if kind == "24h":
        return now_ts - 24 * 3600
    if kind == "6h":
        return now_ts - 6 * 3600
    try:
        n = now_kst()
        if kind == "today":
            start = n.replace(hour=0, minute=0, second=0, microsecond=0)
            return start.timestamp()
        if kind == "halfday":
            hour = 0 if n.hour < 12 else 12
            start = n.replace(hour=hour, minute=0, second=0, microsecond=0)
            return start.timestamp()
    except Exception:
        pass
    return 0.0


def _paper_stats_for_rows_v258(rows: list) -> dict:
    closed = [r for r in list(rows or []) if str(r.get("status", "")).upper() == "CLOSED"]
    n = len(closed)
    wins = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) > 0]
    losses = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) < 0]
    flats = n - len(wins) - len(losses)
    total = sum(safe_float(r.get("pnl_pct", 0), 0) for r in closed)
    gross_profit = sum(wins)
    gross_loss = abs(sum(losses))
    avg_win = (sum(wins) / len(wins)) if wins else 0.0
    avg_loss = (sum(losses) / len(losses)) if losses else 0.0
    pf = (gross_profit / gross_loss) if gross_loss > 0 else (999.0 if gross_profit > 0 else 0.0)
    rr = (avg_win / abs(avg_loss)) if avg_loss < 0 else 0.0
    return {"n": n, "wins": len(wins), "losses": len(losses), "flats": flats, "win_rate": (len(wins)/n*100.0 if n else 0.0), "total_pct": total, "avg_win": avg_win, "avg_loss": avg_loss, "profit_factor": pf, "rr": rr}


def _paper_stats_line_v258(label: str, rows: list) -> str:
    st = _paper_stats_for_rows_v258(rows)
    if st["n"] <= 0:
        return f"- {label}: 거래 없음"
    pf = st["profit_factor"]
    pf_text = "∞" if pf >= 900 else f"{pf:.2f}"
    return f"- {label}: {st['n']}전 {st['wins']}승 {st['losses']}패 / 승률 {st['win_rate']:.1f}% / 누적 {st['total_pct']:+.2f}% / 평균익 {st['avg_win']:+.2f}% / 평균손 {st['avg_loss']:+.2f}% / 손익비 {st['rr']:.2f} / PF {pf_text}"


def build_paper_stats_text_v258() -> str:
    now_ts = time.time()
    rows = _paper_closed_logs_v258()
    def filt(kind):
        start = _paper_window_start_v258(kind, now_ts)
        return [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= start]
    with PAPER_STATE_LOCK:
        active_count = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "OPEN")
        pending_count = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "PENDING")
    lines = [
        "📊 모의매매 성과 /paper_stats",
        f"- 시각: {now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(now_ts)}",
        "- 실제 주문 아님. 기록 파일은 버전 수정/재시작 때 자동 초기화하지 않음.",
        f"- 진행 중: 보유가정 {active_count} / 진입대기 {pending_count}",
        _paper_stats_line_v258("전체 누적", rows),
        _paper_stats_line_v258("오늘", filt("today")),
        _paper_stats_line_v258("현재 반나절", filt("halfday")),
        _paper_stats_line_v258("최근 12시간", filt("12h")),
        _paper_stats_line_v258("최근 24시간", filt("24h")),
        "",
        "[해석] 승률만 보지 말고 누적수익률·평균익/평균손·PF를 같이 본다.",
    ]
    return "\n".join(lines)


def build_paper_text_v258(limit: int = 10) -> str:
    paper_update_positions_once_v258()
    with PAPER_STATE_LOCK:
        rows = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() in {"PENDING", "OPEN"}]
    rows.sort(key=lambda x: (0 if str(x.get("status", "")).upper() == "OPEN" else 1, -safe_float(x.get("created_ts", 0), 0)))
    lines = [
        "🧪 모의매매 /paper",
        "- 실제 매수 아님. 신호가 돈이 되는지 검증하는 장부야.",
        "- 버전 수정/재시작 후에도 paper_positions.json, paper_trade_log.json 유지.",
        "",
    ]
    if not rows:
        lines.append("- 진행 중인 모의 포지션 없음. /signal 후보가 쌓이면 자동 등록됨.")
    for i, p in enumerate(rows[:max(1, int(limit))], start=1):
        ticker = str(p.get("ticker", "?") or "?")
        status = str(p.get("status", "") or "")
        price = safe_float(p.get("last_price", 0), 0)
        entry = safe_float(p.get("entry_price", 0), 0)
        pnl = _paper_pct_v258(entry, price) if status == "OPEN" else 0.0
        if status == "PENDING":
            lines += [
                f"{i}. ⏳ {ticker} / 진입대기 / {p.get('entry_rule')} / {p.get('lane')}",
                f"- 현재 {fmt_price_detail(price)} / 진입예정 {fmt_price_detail(p.get('planned_entry_low',0))} ~ {fmt_price_detail(p.get('planned_entry_high',0))} / 추격금지 {fmt_price_detail(p.get('chase_stop',0))}",
                f"- 손절 {fmt_price_detail(p.get('stop',0))} / TP1 {fmt_price_detail(p.get('tp1',0))} / TP2 {fmt_price_detail(p.get('tp2',0))} / TP3 {fmt_price_detail(p.get('tp3',0))}",
            ]
        else:
            lines += [
                f"{i}. ✅ {ticker} / 보유가정 / {p.get('lane')} / 현재수익 {pnl:+.2f}%",
                f"- 진입 {fmt_price_detail(entry)} / 현재 {fmt_price_detail(price)} / 최고 {safe_float(p.get('max_up_pct',0),0):+.2f}% / 최저 {safe_float(p.get('min_down_pct',0),0):+.2f}%",
                f"- 손절 {fmt_price_detail(p.get('stop',0))} / TP1 {'완료' if p.get('tp1_hit') else fmt_price_detail(p.get('tp1',0))} / TP2 {'완료' if p.get('tp2_hit') else fmt_price_detail(p.get('tp2',0))} / TP3 {fmt_price_detail(p.get('tp3',0))}",
            ]
        lines.append("")
    lines.append("명령어: /paper_stats, /paper_recent")
    return "\n".join(lines).strip()


def build_paper_recent_text_v258(limit: int = 10) -> str:
    rows = _paper_closed_logs_v258(include_cancelled=True)
    rows.sort(key=lambda r: safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0), reverse=True)
    lines = ["🧾 최근 모의매매 /paper_recent", "- 실제 주문 아님 / 취소·만료 포함", ""]
    if not rows:
        lines.append("- 기록 없음")
    for i, r in enumerate(rows[:max(1, int(limit))], start=1):
        status = str(r.get("status", "") or "")
        ticker = str(r.get("ticker", "?") or "?")
        pnl = safe_float(r.get("pnl_pct", 0), 0)
        reason = str(r.get("close_reason", "") or "-")
        lane = str(r.get("lane", "") or "-")
        if status == "CANCELLED":
            lines.append(f"{i}. {ticker} / 진입취소 / {reason} / {lane}")
        else:
            lines.append(f"{i}. {ticker} / {pnl:+.2f}% / {reason} / {lane} / 최고 {safe_float(r.get('max_up_pct',0),0):+.2f}%·최저 {safe_float(r.get('min_down_pct',0),0):+.2f}%")
    return "\n".join(lines)


def paper_command_v258(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    try:
        args = [str(x).lower() for x in (getattr(context, 'args', []) if context is not None else [])]
        if args and args[0] in {"stats", "stat"}:
            send_text_chunks(build_paper_stats_text_v258(), limit=TG_MESSAGE_SOFT_LIMIT)
        elif args and args[0] in {"recent", "log"}:
            send_text_chunks(build_paper_recent_text_v258(), limit=TG_MESSAGE_SOFT_LIMIT)
        else:
            send_text_chunks(build_paper_text_v258(), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('paper_command_v258', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /paper 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


def paper_stats_command_v258(update, context: CallbackContext):
    try:
        send_text_chunks(build_paper_stats_text_v258(), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('paper_stats_command_v258', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /paper_stats 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


def paper_recent_command_v258(update, context: CallbackContext):
    try:
        send_text_chunks(build_paper_recent_text_v258(), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        append_runtime_error_log('paper_recent_command_v258', str(e), exc=e, include_traceback=True)
        send(f"⚠️ /paper_recent 생성 오류: {e.__class__.__name__}: {str(e)[:120]}")


_ORIG_BUILD_SIGNAL_TEXT_V257_FOR_PAPER = build_signal_text_v256
def build_signal_text_v256(args=None, limit: int = None) -> str:
    text = _ORIG_BUILD_SIGNAL_TEXT_V257_FOR_PAPER(args=args, limit=limit)
    try:
        # /signal을 사용한 시점에도 모의 후보를 등록한다. 실제 푸시 알림은 보내지 않는다.
        paper_auto_register_from_signal_snapshot_v258(trigger="signal_command")
    except Exception as e:
        append_runtime_error_log("paper_register_from_signal_command_v258", str(e), exc=e, include_traceback=False)
    return text


_ORIG_BUILD_CACHE_STATUS_TEXT_V258 = build_cache_status_text
def build_cache_status_text():
    try:
        base = _ORIG_BUILD_CACHE_STATUS_TEXT_V258()
    except Exception as e:
        base = f"🧊 명령어 캐시 상태 /cache_status\n- 기본 상태 생성 오류: {e}"
    try:
        with PAPER_STATE_LOCK:
            active_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "OPEN")
            pending_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "PENDING")
            logs_n = len(paper_trade_log or [])
        recent_rows = [r for r in _paper_closed_logs_v258() if safe_float(r.get("close_ts", 0), 0) >= time.time() - 12*3600]
        st = _paper_stats_for_rows_v258(recent_rows)
        extra = [
            "",
            "🧪 v2.5.258 모의매매",
            f"- 상태: {'켜짐' if PAPER_TRADING_ON else '꺼짐'} / 보유가정 {active_n} / 진입대기 {pending_n} / 로그 {logs_n}",
            f"- 최근 12시간: {st['n']}전 {st['wins']}승 {st['losses']}패 / 승률 {st['win_rate']:.1f}% / 누적 {st['total_pct']:+.2f}%",
            f"- 등록 {int(safe_float(PAPER_V258_STATS.get('registered',0),0))} / 진입 {int(safe_float(PAPER_V258_STATS.get('entered',0),0))} / 청산 {int(safe_float(PAPER_V258_STATS.get('closed',0),0))} / 최근 {PAPER_V258_STATS.get('last_note','')}",
            "- 원칙: 모의매매 파일은 버전 수정/재시작 때 초기화하지 않고, 전체·오늘·반나절·최근12시간 성과를 따로 계산한다.",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base

