    threading.Thread(target=rank_precision_registration_worker_loop_v253, daemon=True, name="rank_precision_register_v253").start()
    threading.Thread(target=light_snapshot_worker_loop, daemon=True, name="light_snapshot_worker").start()
    # v2.5.217: WebSocket 현재가 1차 보강. 실패해도 REST direct 전체현재가가 백업으로 계속 돈다.
    threading.Thread(target=websocket_ticker_worker_loop, daemon=True, name="ws_ticker_worker").start()
