        return {"allowed": allowed, "priority": round(priority, 3), "ticker": ticker, "turnover": turnover, "ws_count": ws_cnt, "ws_buy": ws_buy, "strongest": strongest, "high_gap": high_gap, "from_low": from_low, "money_weak": money_weak, "precision_watch": precision_watch, "reason": reason}
