_ORIG_SIGNAL_V257_CLASSIFY_FOR_V260 = globals().get('_signal_v257_classify', globals().get('_signal_v256_classify'))
def _signal_v257_classify(row: dict) -> dict:
    cls = _ORIG_SIGNAL_V257_CLASSIFY_FOR_V260(row) if callable(_ORIG_SIGNAL_V257_CLASSIFY_FOR_V260) else _signal_v256_classify(row)
    cls = dict(cls or {})
    try:
        if str(cls.get("grade", "") or "").upper() != "BUY_OK": return cls
        trade_count = int(safe_float(cls.get("trade_count", 0), 0)); buy_ratio = safe_float(cls.get("buy_ratio", 0), 0); chg3 = safe_float(cls.get("chg3", 0), 0)
        money_sustain = str(cls.get("money_sustain", "") or ""); money_code = str(cls.get("money_code", "") or ""); money_amount = safe_float(cls.get("money_amount", 0), 0)
        bad = []
        if trade_count < PAPER_V260_BUY_OK_MIN_TRADE: bad.append("60초 체결 부족")
        if buy_ratio <= 0 or buy_ratio < PAPER_V260_BUY_OK_MIN_BUY_RATIO: bad.append("매수비율 부족")
        if chg3 < 0: bad.append("3분 흐름 음수")
        if "반짝" in money_sustain or "식는" in money_sustain or "매도우세" in money_sustain: bad.append("돈흐름 약함")
        if money_code in {"actual_zero", "tiny", "thin"} or money_amount < 30_000_000: bad.append("대금 부족")
        if bad:
            _paper_v260_inc("buy_ok_demoted", f"BUY_OK 강등 {cls.get('ticker','?')}/" + ",".join(bad[:2]))
            cls["paper_original_grade"] = "BUY_OK"
            if money_amount >= 100_000_000 and chg3 >= -0.2 and "매도우세" not in money_sustain:
                cls.update({"grade": "PULLBACK_WAIT", "decision": "눌림 대기", "action": "지금 시장가 추격 말고 매수 가능 구간까지 눌릴 때만 봄."})
                cls["reasons"] = list(cls.get("reasons") or []) + ["v260 즉시매수 금지: " + ", ".join(bad[:3])]
            else:
                cls.update({"grade": "DISCARD", "decision": "버림", "action": "지금 매수 신호 아님. 모의/복기에서만 확인."})
                cls["reasons"] = list(cls.get("reasons") or []) + ["v260 즉시매수 차단: " + ", ".join(bad[:3])]
        return cls
    except Exception:
        return cls

