# =========================================================
# v2.5.262: 후보품질 + 차트정교화 1차 + 신호/통계 표시 보강
# =========================================================
# 목표:
# - 후보를 더 많이 보여주는 것이 아니라, 진짜 매수 후보와 참고 후보를 분리한다.
# - 현재봉/고점/돈흐름을 더 잘 나눠서 고점 앞 잡후보가 상위 신호처럼 보이는 문제를 줄인다.
# - /signal에 데이터품질과 차트상태를 쉽게 표시한다.
# - /paper_stats는 기존 기록을 초기화하지 않고 v262 적용 이후 성과를 따로 보여준다.
PAPER_V262_START_TS = time.time()
PAPER_V262_STATS = {
    "buy_ok_demoted": 0,
    "breakout_demoted": 0,
    "reference_only": 0,
    "chart_weak_block": 0,
    "money_flash_block": 0,
    "signal_trade_count": 0,
    "signal_reference_count": 0,
    "last_note": "대기",
}


def _v262_inc(key: str, note: str = ""):
    try:
        PAPER_V262_STATS[key] = int(safe_float(PAPER_V262_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V262_STATS["last_note"] = str(note)[:120]
    except Exception:
        pass


def _v262_has_text(text: str, words) -> bool:
    text = str(text or "")
    return any(str(w) in text for w in list(words or []))


def _signal_v262_chart_state(row: dict, cls: dict = None) -> dict:
    row = row if isinstance(row, dict) else {}
    cls = cls if isinstance(cls, dict) else {}
    candle = str(cls.get("candle_label", row.get("current_candle_label", row.get("current_candle_code", ""))) or "")
    money = str(cls.get("money_sustain", "") or "")
    high_code = str(cls.get("high_code", row.get("high_rebreakout_v248_code", "")) or "")
    high_label = str(cls.get("high_label", row.get("high_rebreakout_v248_label", "")) or "")
    high_gap = safe_float(cls.get("high_gap", _signal_v256_high_gap(row) if '_signal_v256_high_gap' in globals() else 999), 999)
    trade_count = int(safe_float(cls.get("trade_count", 0), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
    live_score = safe_float(row.get("current_candle_live_score", row.get("current_candle_follow_score", 0)), 0)
    upper_wick = safe_float(row.get("current_upper_wick_ratio", row.get("upper_wick_ratio", 0)), 0)
    lower_wick = safe_float(row.get("current_lower_wick_ratio", row.get("lower_wick_ratio", 0)), 0)

    if _v262_has_text(candle, ["막판강밀림", "강밀림", "밀림", "위꼬리", "윗꼬리"]):
        candle_code = "weak"; candle_text = "현재봉 밀림/윗꼬리"
    elif _v262_has_text(candle, ["아랫꼬리강회복", "아랫꼬리 회복", "회복"]):
        candle_code = "recover"; candle_text = "아랫꼬리 회복"
    elif _v262_has_text(candle, ["확실살아남", "확실히 살아남", "살아남"]) or live_score >= 2.2:
        candle_code = "alive"; candle_text = "현재봉 살아남"
    elif _v262_has_text(candle, ["작은움직임", "의미 작음", "확인중"]) or not candle:
        candle_code = "small"; candle_text = "현재봉 근거 약함"
    else:
        candle_code = "watch"; candle_text = candle[:24] or "현재봉 확인중"

    if high_code == "rebreak_hold" and trade_count >= 3 and buy_ratio >= 45:
        high_state = "hold"; high_text = "고점 돌파 후 유지"
    elif 0 <= high_gap <= 0.08:
        high_state = "touch"; high_text = "고점 바로 앞/맞닿음"
    elif 0.08 < high_gap <= 0.6:
        high_state = "near"; high_text = "고점 근처 대기"
    elif high_code in {"near_high_reject", "reject", "false_break"} or _v262_has_text(high_label, ["밀림", "거절", "막힘"]):
        high_state = "reject"; high_text = "고점에서 막힘"
    else:
        high_state = "room"; high_text = "고점 여유/확인중"

    if _v262_has_text(money, ["매도우세", "매도 우세"]):
        money_state = "sell"; money_text = "돈은 있지만 매도우세"
    elif _v262_has_text(money, ["반짝", "식는"]):
        money_state = "flash"; money_text = "반짝/식는중"
    elif _v262_has_text(money, ["돈얇", "실제돈작음", "대금확인전"]):
        money_state = "thin"; money_text = "돈 약함/얇음"
    elif _v262_has_text(money, ["돈유지 강함", "돈유지"]):
        money_state = "sustain"; money_text = str(money)[:28] or "돈유지"
    else:
        money_state = "watch"; money_text = str(money)[:28] or "돈흐름 확인중"

    return {
        "candle_code": candle_code, "candle_text": candle_text,
        "high_state": high_state, "high_text": high_text,
        "money_state": money_state, "money_text": money_text,
        "high_gap": high_gap, "trade_count": trade_count, "buy_ratio": buy_ratio,
        "upper_wick": upper_wick, "lower_wick": lower_wick,
    }


_PREV_SIGNAL_V257_CLASSIFY_V262 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_PREV_SIGNAL_V257_CLASSIFY_V262(row) or {})
    try:
        st = _signal_v262_chart_state(row, cls)
        grade = str(cls.get("grade", "") or "").upper()
        score = safe_float(cls.get("score", 0), 0)
        chg3 = safe_float(cls.get("chg3", 0), 0)
        high_gap = safe_float(cls.get("high_gap", st.get("high_gap", 999)), 999)
        trade_count = int(safe_float(cls.get("trade_count", st.get("trade_count", 0)), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", st.get("buy_ratio", 0)), 0)
        money_amount = safe_float(cls.get("money_amount", 0), 0)
        reasons = list(cls.get("reasons") or [])
        data_q = {}
        try:
            data_q = get_data_quality_v261(row if isinstance(row, dict) else {}) if 'get_data_quality_v261' in globals() else {}
        except Exception:
            data_q = {}
        data_grade = str(data_q.get("grade", "") or "")

        cls["chart_v262_candle"] = st.get("candle_text")
        cls["chart_v262_high"] = st.get("high_text")
        cls["chart_v262_money"] = st.get("money_text")
        cls["chart_v262_candle_code"] = st.get("candle_code")
        cls["chart_v262_high_state"] = st.get("high_state")
        cls["chart_v262_money_state"] = st.get("money_state")
        cls["data_quality_v262"] = data_grade

        downgrade = ""
        if grade == "BUY_OK":
            if st.get("candle_code") in {"weak", "small"}:
                downgrade = "현재봉 근거 부족"
            elif st.get("money_state") in {"sell", "flash", "thin"}:
                downgrade = "돈흐름 약함"
            elif trade_count < 2 or buy_ratio < 45:
                downgrade = "60초 체결/매수 근거 부족"
            elif chg3 < 0:
                downgrade = "3분 흐름 음수"
            elif data_grade == "D":
                downgrade = "데이터 부족"
            if downgrade:
                _v262_inc("buy_ok_demoted", f"BUY_OK 강등 {cls.get('ticker','?')}/{downgrade}")
                cls["grade"] = "PULLBACK_WAIT" if st.get("money_state") not in {"thin", "sell"} else "DISCARD"
                cls["decision"] = "눌림 대기" if cls["grade"] == "PULLBACK_WAIT" else "버림"
                cls["action"] = "지금 바로 사는 건 금지. 근거가 더 쌓이거나 눌림 구간에 들어올 때만 본다." if cls["grade"] == "PULLBACK_WAIT" else "지금 매수 신호 아님. 명령어/복기에서만 추적."
                reasons.insert(0, downgrade)
                cls["signal_v262_demoted"] = True

        grade = str(cls.get("grade", "") or "").upper()
        if grade == "BREAKOUT_WAIT":
            if st.get("money_state") in {"sell", "flash", "thin"}:
                downgrade = "돈흐름이 약해서 돌파대기 강등"
            elif st.get("candle_code") == "weak":
                downgrade = "현재봉이 밀려서 돌파대기 강등"
            elif st.get("high_state") == "touch" and (trade_count < 3 or buy_ratio < 45):
                downgrade = "고점 맞닿음 + 체결 근거 부족"
            elif money_amount < 50_000_000 and score < 8.0:
                downgrade = "대금/점수 부족"
            else:
                downgrade = ""
            if downgrade:
                _v262_inc("breakout_demoted", f"돌파대기 강등 {cls.get('ticker','?')}/{downgrade}")
                cls["grade"] = "DISCARD"
                cls["decision"] = "참고 후보"
                cls["action"] = "지금 매수 신호는 아님. 고점 위에서 버티는지 더 확인할 참고 후보."
                reasons.insert(0, downgrade)
                cls["signal_v262_reference_only"] = True

        grade = str(cls.get("grade", "") or "").upper()
        if grade == "PULLBACK_WAIT":
            if st.get("money_state") in {"sell", "thin"} or st.get("candle_code") == "weak":
                _v262_inc("chart_weak_block", f"눌림 약화 {cls.get('ticker','?')}")
                cls["grade"] = "DISCARD"
                cls["decision"] = "참고 후보"
                cls["action"] = "눌림처럼 보여도 돈흐름/현재봉이 약해서 지금은 참고만 한다."
                reasons.insert(0, "눌림 후보지만 돈흐름/현재봉 약함")
                cls["signal_v262_reference_only"] = True

        if str(cls.get("grade", "") or "").upper() == "DISCARD":
            _v262_inc("reference_only")
        try:
            reasons = _dedupe_reason_bits_v251(reasons) if '_dedupe_reason_bits_v251' in globals() else reasons
        except Exception:
            pass
        cls["reasons"] = reasons[:5]
    except Exception as e:
        try:
            append_runtime_error_log("signal_v262_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    return cls


_PREV_SIGNAL_V257_FORMAT_ONE_V262 = _signal_v257_format_one

def _signal_v257_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _PREV_SIGNAL_V257_FORMAT_ONE_V262(row, order=order, show_detail=show_detail)
    try:
        rr = apply_precision_minute1_state_to_row(dict(row or {})) if 'apply_precision_minute1_state_to_row' in globals() and isinstance(row, dict) else dict(row or {})
    except Exception:
        rr = dict(row or {})
    try:
        cls = _signal_v257_classify(rr)
        st = _signal_v262_chart_state(rr, cls)
        dq = get_data_quality_v261(rr) if 'get_data_quality_v261' in globals() else {}
        dq_text = str(dq.get("text", "데이터품질 확인중") or "데이터품질 확인중")
        ws_count = int(safe_float(dq.get("ws_count", cls.get("trade_count", 0)), 0))
        ws_buy = safe_float(dq.get("ws_buy_ratio", cls.get("buy_ratio", 0)), 0)
        lines = str(text).splitlines()
        insert_at = 1 if len(lines) > 1 else len(lines)
        if not any("데이터품질" in x for x in lines[:5]):
            lines.insert(insert_at, f"- 데이터품질: {dq_text} / 실시간체결 {ws_count}건·매수 {ws_buy:.0f}%")
            insert_at += 1
        chart_line = f"- 차트상태: 현재봉 {st.get('candle_text')} / 고점 {st.get('high_text')} / 돈흐름 {st.get('money_text')}"
        if not any("차트상태:" in x for x in lines[:6]):
            lines.insert(insert_at, chart_line)
        for i, line in enumerate(lines):
            if line.startswith("- 익절: TP1") and "소액모드" not in "\n".join(lines[i:i+2]):
                lines[i] = line + "\n- 소액모드: 1만원 시작 기준은 TP1~3 분할보다 단일익절·보호손절 우선"
                break
        return "\n".join(lines)
    except Exception:
        return text


def _signal_v262_weight(cls: dict) -> tuple:
    grade = str((cls or {}).get("grade", "") or "").upper()
    base = {"BUY_OK": 5, "PULLBACK_WAIT": 3, "BREAKOUT_WAIT": 3, "DISCARD": 1}.get(grade, 1)
    score = safe_float((cls or {}).get("score", 0), 0)
    money = safe_float((cls or {}).get("money_amount", 0), 0)
    chg = max(safe_float((cls or {}).get("chg3", 0), 0), safe_float((cls or {}).get("chg5", 0), 0))
    return (base, score, money, chg)


_PREV_BUILD_SIGNAL_TEXT_V262 = build_signal_text_v256

def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 14))
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    if not rows:
        return "\n".join([
            "🎯 매수·손절·익절 신호 /signal",
            f"- 시각: {now_line}",
            "- 아직 신호 계산에 쓸 스냅샷이 없어.",
            "- 먼저 /rank_short에서 후보가 보이는지 확인해줘.",
        ])

    if target:
        target_rows = [r for r in rows if _signal_v257_ticker(r) == target]
        if not target_rows:
            SIGNAL_V257_STATS["specific_miss"] = int(safe_float(SIGNAL_V257_STATS.get("specific_miss", 0), 0)) + 1
            return "\n".join([
                "🎯 매수·손절·익절 신호 /signal",
                f"- 시각: {now_line}",
                f"- {target}는 현재 저장 스냅샷에서 못 찾았어.",
                "- 새 API를 부르지 않는 명령이라 최근 스냅샷에 없으면 계산하지 않아.",
            ])
        SIGNAL_V257_STATS["specific_hit"] = int(safe_float(SIGNAL_V257_STATS.get("specific_hit", 0), 0)) + 1
        best = sorted(target_rows, key=lambda r: _signal_v262_weight(_signal_v257_classify(r)), reverse=True)[0]
        lines = [
            "🎯 매수·손절·익절 신호 /signal",
            f"- 시각: {now_line}",
            "- 새 API/OHLCV 직접조회 없음. 저장된 rank/review/internal_watch + WS 보조 기준.",
            "- v2.5.262: 데이터품질·현재봉·고점·돈흐름을 같이 보고, 진짜 매수 후보와 참고 후보를 분리.",
            "- 즉시 푸시 알림은 매수·매도 신호만 허용. 관심/복기/내부감시는 명령어에서만 봄.",
            "",
            _signal_v257_format_one(best, order=1, show_detail=True),
            "",
            "명령어: /signal 코인명  예) /signal A",
        ]
        return "\n".join(lines).strip()

    classified = []
    for r in rows:
        try:
            c = _signal_v257_classify(r)
            classified.append((c, r))
        except Exception:
            continue
    classified.sort(key=lambda x: _signal_v262_weight(x[0]), reverse=True)
    trade = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() == "BUY_OK"]
    wait = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() in {"BREAKOUT_WAIT", "PULLBACK_WAIT"}]
    ref = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() == "DISCARD"]
    PAPER_V262_STATS["signal_trade_count"] = len(trade)
    PAPER_V262_STATS["signal_reference_count"] = len(wait) + len(ref)

    lines = [
        "🎯 매수·손절·익절 신호 /signal",
        f"- 시각: {now_line}",
        "- 새 API/OHLCV 직접조회 없음. 저장된 rank/review/internal_watch + WS 보조 기준.",
        "- v2.5.262: 데이터품질·현재봉·고점·돈흐름을 같이 보고, 진짜 매수 후보와 참고 후보를 분리.",
        "- 즉시 푸시 알림은 매수·매도 신호만 허용. 관심/복기/내부감시는 명령어에서만 봄.",
        "",
    ]
    shown = 0
    if trade:
        lines.append("🔥 진짜 매수 후보")
        for c, r in trade[:max(1, min(2, limit))]:
            shown += 1
            lines.append(_signal_v257_format_one(r, order=shown, show_detail=False)); lines.append("")
    else:
        lines.append("- 현재 즉시 매수 신호 없음. 아래는 참고 후보만 보여줌."); lines.append("")
    refs_to_show = wait[:max(1, limit - shown)]
    if not refs_to_show:
        refs_to_show = ref[:min(3, max(1, limit))]
    if refs_to_show:
        lines.append("🧷 참고 후보 / 바로 매수 아님")
        for c, r in refs_to_show[:max(1, limit - shown if shown else limit)]:
            shown += 1
            lines.append(_signal_v257_format_one(r, order=shown, show_detail=False)); lines.append("")
    lines.append("명령어: /signal 코인명  예) /signal A")
    return "\n".join(lines).strip()


_PREV_BUILD_PAPER_STATS_TEXT_V262 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try:
        base = _PREV_BUILD_PAPER_STATS_TEXT_V262()
    except Exception as e:
        base = f"📊 모의매매 성과 /paper_stats\n- 기본 통계 생성 오류: {e}"
    try:
        now_ts = time.time()
        rows = _paper_closed_logs_v258()
        def by_start(ts):
            return [r for r in rows if safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0) >= ts]
        v262_rows = by_start(PAPER_V262_START_TS)
        six_rows = by_start(now_ts - 6 * 3600)
        extra = [
            "",
            "[버전별 성과 - 초기화 없이 따로 계산]",
            _paper_stats_line_v258("v262 적용 후", v262_rows),
            _paper_stats_line_v258("최근 6시간", six_rows),
        ]
        if v262_rows:
            strict_rows = [r for r in v262_rows if str(r.get("lane", "")) == "strict_signal"]
            loose_rows = [r for r in v262_rows if str(r.get("lane", "")) == "loose_threshold_test"]
            extra += [
                _paper_stats_line_v258("v262 실전급 strict", strict_rows),
                _paper_stats_line_v258("v262 실험층 loose", loose_rows),
            ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


