# =========================================================
# v2.5.264: v263 실패 보정판 - 후보층 세분화/문턱형 차단 안전 적용
# =========================================================
# 원칙:
# - 후보 입구(rank/review)는 막지 않는다.
# - 매수 알림/paper 진입만 문턱층으로 좁힌다.
# - 기존 v262 함수는 보존하고, 출력/분류만 얇게 덮는다.
PAPER_V264_START_TS = time.time()
PAPER_V264_STATS = {
    "buy_ready": 0,
    "breakout_watch": 0,
    "pullback_watch": 0,
    "watch_only": 0,
    "review_only": 0,
    "true_discard": 0,
    "paper_blocked": 0,
    "last_note": "대기",
}


def _v264_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V264_STATS:
            PAPER_V264_STATS[key] = int(safe_float(PAPER_V264_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V264_STATS["last_note"] = str(note)[:140]
    except Exception:
        pass


def _v264_text_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v264_bucket_from_cls(cls: dict, row: dict = None) -> dict:
    """후보를 죽이지 않고 층으로 나눈다. 매수/paper만 층별 문턱으로 막는다."""
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    grade = str(cls.get("grade", "") or "").upper()
    score = safe_float(cls.get("score", 0), 0)
    money = safe_float(cls.get("money_amount", 0), 0)
    trade_count = int(safe_float(cls.get("trade_count", 0), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
    chg3 = safe_float(cls.get("chg3", 0), 0)
    chg5 = safe_float(cls.get("chg5", 0), 0)
    high_gap = safe_float(cls.get("high_gap", 999), 999)
    candle = str(cls.get("chart_v262_candle", cls.get("candle_label", "")) or "")
    money_text = str(cls.get("chart_v262_money", cls.get("money_sustain", "")) or "")
    high_text = str(cls.get("chart_v262_high", cls.get("high_label", "")) or "")
    data_grade = str(cls.get("data_quality_v262", row.get("data_quality_grade_v261", "")) or "")
    max_chg = max(chg3, chg5)

    candle_weak = _v264_text_has(candle, ["밀림", "윗꼬리", "근거 약함", "의미 작음"])
    candle_alive = _v264_text_has(candle, ["살아남", "회복"])
    money_weak = _v264_text_has(money_text, ["매도우세", "반짝", "식는", "돈 약함", "돈얇", "실제돈작음", "대금확인전"])
    money_thin = _v264_text_has(money_text, ["돈 약함", "돈얇", "실제돈작음", "대금확인전"])
    high_touch = _v264_text_has(high_text, ["맞닿음", "바로 앞"])
    high_hold = _v264_text_has(high_text, ["돌파 후 유지"])

    # 진짜 버림: 돈/차트/체결이 모두 약해서 paper도 태우면 통계만 망가지는 후보
    if data_grade == "D":
        return {"bucket": "true_discard", "label": "진짜 버림", "reason": "데이터 부족"}
    if money < 5_000_000 and score < 8.0:
        return {"bucket": "true_discard", "label": "진짜 버림", "reason": "실제 돈이 너무 작음"}
    if money_thin and trade_count < 2 and score < 8.5:
        return {"bucket": "true_discard", "label": "진짜 버림", "reason": "돈얇음+체결부족"}
    if candle_weak and money_weak and max_chg <= 0.15:
        return {"bucket": "true_discard", "label": "진짜 버림", "reason": "현재봉/돈흐름 둘 다 약함"}

    if grade == "BUY_OK":
        bad = []
        if money < 150_000_000: bad.append("대금 부족")
        if trade_count < 5: bad.append("체결수 부족")
        if buy_ratio < 55: bad.append("매수비율 부족")
        if chg3 < 0: bad.append("3분 흐름 음수")
        if candle_weak or not candle_alive: bad.append("현재봉 근거 부족")
        if money_weak: bad.append("돈흐름 약함")
        if high_touch and buy_ratio < 62: bad.append("고점 맞닿음")
        if bad:
            return {"bucket": "watch_only", "label": "구경만", "reason": " / ".join(bad[:2])}
        return {"bucket": "buy_ready", "label": "진짜 매수", "reason": "돈/체결/현재봉 통과"}

    if grade == "BREAKOUT_WAIT":
        if money_weak or candle_weak:
            return {"bucket": "watch_only", "label": "구경만", "reason": "돌파대기지만 돈/현재봉 약함"}
        if trade_count >= 4 and buy_ratio >= 45 and money >= 100_000_000 and (high_hold or 0 <= high_gap <= 0.8):
            return {"bucket": "breakout_watch", "label": "돌파대기", "reason": "돌파 확인 대기"}
        return {"bucket": "review_only", "label": "복기/감시만", "reason": "돌파 근거 부족"}

    if grade == "PULLBACK_WAIT":
        if money_thin or candle_weak:
            return {"bucket": "watch_only", "label": "구경만", "reason": "눌림대기지만 돈/현재봉 약함"}
        if money >= 80_000_000 and max_chg >= 0 and (trade_count >= 2 or buy_ratio >= 45):
            return {"bucket": "pullback_watch", "label": "눌림대기", "reason": "눌림/재출발 대기"}
        return {"bucket": "review_only", "label": "복기/감시만", "reason": "눌림 근거 부족"}

    if money >= 100_000_000 and (trade_count >= 3 or score >= 6.0):
        return {"bucket": "review_only", "label": "복기/감시만", "reason": "매수는 아니지만 추적가치 있음"}
    return {"bucket": "true_discard", "label": "진짜 버림", "reason": "매수/감시 근거 부족"}


_BASE_SIGNAL_CLASSIFY_V264 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_BASE_SIGNAL_CLASSIFY_V264(row) or {})
    try:
        bucket = _v264_bucket_from_cls(cls, row if isinstance(row, dict) else {})
        b = str(bucket.get("bucket", "review_only") or "review_only")
        cls["v264_bucket"] = b
        cls["v264_label"] = str(bucket.get("label", ""))
        cls["v264_reason"] = str(bucket.get("reason", ""))
        _v264_inc(b, f"{cls.get('ticker','?')}/{bucket.get('label','')}/{bucket.get('reason','')}")
    except Exception as e:
        try:
            append_runtime_error_log("signal_v264_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    return cls


_BASE_SIGNAL_FORMAT_ONE_V264 = _signal_v257_format_one

def _signal_v264_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _BASE_SIGNAL_FORMAT_ONE_V264(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        label = str(cls.get("v264_label", "") or "")
        reason = str(cls.get("v264_reason", "") or "")
        if label:
            lines = str(text).splitlines()
            if not any("문턱층:" in x for x in lines[:8]):
                lines.insert(1 if len(lines) > 1 else len(lines), f"- 문턱층: {label} / {reason}")
            return "\n".join(lines)
    except Exception:
        pass
    return text


def _signal_v264_weight(cls: dict) -> tuple:
    bucket = str((cls or {}).get("v264_bucket", "") or "")
    bucket_score = {"buy_ready": 6, "breakout_watch": 4, "pullback_watch": 4, "review_only": 2, "watch_only": 1, "true_discard": 0}.get(bucket, 1)
    score = safe_float((cls or {}).get("score", 0), 0)
    money = safe_float((cls or {}).get("money_amount", 0), 0)
    trade = int(safe_float((cls or {}).get("trade_count", 0), 0))
    buy = safe_float((cls or {}).get("buy_ratio", 0), 0)
    return (bucket_score, score, min(money, 50_000_000_000), trade, buy)


_BASE_BUILD_SIGNAL_TEXT_V264 = build_signal_text_v256

def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 16))
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    if not rows:
        return "\n".join([
            "🎯 매수·손절·익절 신호 /signal",
            f"- 시각: {now_line}",
            "- 아직 신호 계산에 쓸 스냅샷이 없어.",
            "- 이건 매수 후보가 없다는 뜻이지 rank/review 탐색을 꺼버린 건 아니야.",
        ])
    classified = []
    for r in rows:
        try:
            c = _signal_v257_classify(r)
            classified.append((c, r))
        except Exception:
            continue
    classified.sort(key=lambda x: _signal_v264_weight(x[0]), reverse=True)

    if target:
        target_rows = [(c, r) for c, r in classified if _signal_v257_ticker(r) == target]
        if not target_rows:
            return "\n".join([
                "🎯 매수·손절·익절 신호 /signal",
                f"- 시각: {now_line}",
                f"- {target}는 현재 저장 스냅샷에서 못 찾았어.",
                "- 새 API를 부르지 않는 명령이라 최근 스냅샷에 없으면 계산하지 않아.",
            ])
        c, best = sorted(target_rows, key=lambda x: _signal_v264_weight(x[0]), reverse=True)[0]
        return "\n".join([
            "🎯 매수·손절·익절 신호 /signal",
            f"- 시각: {now_line}",
            "- 새 API/OHLCV 직접조회 없음. 저장된 rank/review/internal_watch + WS 보조 기준.",
            "- v2.5.264: 후보는 살리고, 매수 알림만 문턱층으로 좁게 분리.",
            "- 즉시 푸시 알림은 매수·매도 신호만 허용. 감시/복기는 명령어에서만 봄.",
            "",
            _signal_v264_format_one(best, order=1, show_detail=True),
            "",
            "명령어: /signal 코인명  예) /signal A",
        ]).strip()

    buy = [(c, r) for c, r in classified if c.get("v264_bucket") == "buy_ready"]
    wait = [(c, r) for c, r in classified if c.get("v264_bucket") in {"breakout_watch", "pullback_watch"}]
    review = [(c, r) for c, r in classified if c.get("v264_bucket") in {"review_only", "watch_only"}]
    discard = [(c, r) for c, r in classified if c.get("v264_bucket") == "true_discard"]

    lines = [
        "🎯 매수·손절·익절 신호 /signal",
        f"- 시각: {now_line}",
        "- 새 API/OHLCV 직접조회 없음. 저장된 rank/review/internal_watch + WS 보조 기준.",
        "- v2.5.264: 후보는 살리고, 매수 알림만 문턱층으로 좁게 분리.",
        "- 즉시 푸시 알림은 매수·매도 신호만 허용. 감시/복기는 명령어에서만 봄.",
        "",
    ]
    shown = 0
    if buy:
        lines.append("🔥 진짜 매수 후보")
        for c, r in buy[:min(2, limit)]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    else:
        lines.append("- 현재 즉시 매수 신호 없음. 후보는 아래 문턱층으로 나눠서 계속 추적함."); lines.append("")
    if wait and shown < limit:
        lines.append("🟡 대기 후보 / 조건 좋아지면 매수 후보로 승격 가능")
        for c, r in wait[:max(1, min(limit - shown, 4))]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    if review and shown < limit:
        lines.append("🧷 구경·복기 후보 / 지금 매수 아님")
        for c, r in review[:max(1, min(limit - shown, 3))]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    if not wait and not review and discard:
        lines.append("⛔ 진짜 버림 후보 / 참고만")
        for c, r in discard[:min(3, limit)]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    lines.append("명령어: /signal 코인명  예) /signal A")
    return "\n".join(lines).strip()


_BASE_PAPER_CLASSIFY_FOR_REGISTER_V264 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    try:
        ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_FOR_REGISTER_V264(row)
    except Exception as e:
        try:
            append_runtime_error_log("paper_classify_base_v264", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return False, "blocked_v264", f"기본 paper 분류 오류: {e}", {}
    try:
        cls = dict(cls or {})
        bucket = str(cls.get("v264_bucket", "") or "")
        if bucket not in {"buy_ready", "breakout_watch", "pullback_watch"}:
            _v264_inc("paper_blocked", f"paper 차단 {cls.get('ticker','?')}/{bucket or 'none'}")
            return False, "blocked_v264", f"v264 문턱층 paper 차단: {cls.get('v264_label','-')} / {cls.get('v264_reason','')}", cls
        return ok, lane, reason, cls
    except Exception:
        return ok, lane, reason, cls


