# =========================================================
# v2.5.265: 문턱층 문구 정리 + 상황별 단일매도/손절폭 안전장치
# =========================================================
# 쉬운 뜻:
# - 후보는 계속 살려두되, 진짜 버릴 후보만 "진짜 버림"이라고 표시한다.
# - 1만원 시작 기준은 분할매도보다 단일매도다. 단, 장/코인 힘에 따라 짧게 먹거나 더 끌고 간다.
# - POLA -5%대 같은 모의 손실이 반복되지 않도록 손절폭을 좁히고, paper에서는 stop 가격 기준으로 청산한다.
# - 매 수정마다 최종 목표 10단계와 같이 봐야 한다는 고정 원칙을 인수인계 상단에 유지한다.
PAPER_V265_START_TS = time.time()
PAPER_V265_STRICT_MAX_LOSS_PCT = 1.45
PAPER_V265_LOOSE_MAX_LOSS_PCT = 1.20
PAPER_V265_WEAK_MAX_LOSS_PCT = 1.05
PAPER_V265_HARD_LOSS_PCT = 1.85
PAPER_V265_QUICK_TP_PCT = 0.75
PAPER_V265_BASIC_TP_MIN_PCT = 0.90
PAPER_V265_TREND_MIN_HOLD_TP_PCT = 1.25
PAPER_V265_SLOW_EXIT_MIN_SEC = 22 * 60
PAPER_V265_STATS = {
    "stop_capped": 0,
    "hard_stop": 0,
    "quick_exit": 0,
    "basic_exit": 0,
    "trend_exit": 0,
    "protect_exit": 0,
    "slow_exit": 0,
    "paper_tagged": 0,
    "last_note": "대기",
}

def _v265_inc(key: str, note: str = ""):
    try:
        PAPER_V265_STATS[key] = int(safe_float(PAPER_V265_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V265_STATS["last_note"] = str(note)[:140]
    except Exception:
        pass


def _v265_market_mode() -> dict:
    """시장상태를 쉬운 매도모드용으로 줄인다. 조회 실패면 보통으로 단정하지 않는다."""
    try:
        reg = get_market_regime() if 'get_market_regime' in globals() else {}
        name = str((reg or {}).get('name', 'UNKNOWN') or 'UNKNOWN').upper()
        if name in {'BLOCK', 'WEAK'}:
            mode = 'weak'
            text = '약한 장'
        elif name == 'STRONG_UP':
            mode = 'strong'
            text = '강한 장'
        elif name in {'SIDEWAYS', 'NORMAL'}:
            mode = 'normal'
            text = '보통/횡보 장'
        else:
            mode = 'unknown'
            text = '시장 판단 부족'
        return {"mode": mode, "text": text, "raw": reg}
    except Exception:
        return {"mode": "unknown", "text": "시장 판단 오류", "raw": {}}


def _v265_trade_strength(ticker: str, pos: dict = None) -> dict:
    ticker = str(ticker or '').upper().strip()
    pos = pos if isinstance(pos, dict) else {}
    cnt = int(safe_float(pos.get('trade_count', 0), 0))
    buy = safe_float(pos.get('buy_ratio', 0), 0)
    amount = safe_float(pos.get('money_amount', 0), 0)
    try:
        if ticker and 'get_ws_trade_summary_for_ticker' in globals():
            s = get_ws_trade_summary_for_ticker(ticker, 60)
            if isinstance(s, dict):
                cnt = max(cnt, int(safe_float(s.get('count', 0), 0)))
                if int(safe_float(s.get('count', 0), 0)) > 0:
                    buy = safe_float(s.get('buy_ratio', buy), buy)
                amount = max(amount, safe_float(s.get('amount', 0), 0))
    except Exception:
        pass
    strong = cnt >= 8 and buy >= 55 and amount >= 50_000_000
    weak = (cnt <= 1) or (buy > 0 and buy < 35)
    sell_heavy = buy > 0 and buy < 45
    return {"count": cnt, "buy_ratio": buy, "amount": amount, "strong": strong, "weak": weak, "sell_heavy": sell_heavy}


def _v265_stop_cap_pct(pos: dict, market_mode: str = None) -> float:
    lane = str((pos or {}).get('lane', '') or '')
    entry_rule = str((pos or {}).get('entry_rule', '') or '')
    if lane == 'loose_threshold_test':
        cap = PAPER_V265_LOOSE_MAX_LOSS_PCT
    else:
        cap = PAPER_V265_STRICT_MAX_LOSS_PCT
    if entry_rule == 'breakout':
        cap = min(cap, 1.25)
    if market_mode == 'weak':
        cap = min(cap, PAPER_V265_WEAK_MAX_LOSS_PCT)
    return max(0.45, safe_float(cap, 1.3))


def _v265_tighten_stop(pos: dict, market_mode: str = None) -> dict:
    pos = dict(pos or {})
    entry = safe_float(pos.get('entry_price', 0), 0)
    if entry <= 0:
        return pos
    stop = safe_float(pos.get('stop', 0), 0)
    cap_pct = _v265_stop_cap_pct(pos, market_mode=market_mode)
    min_stop = entry * (1 - cap_pct / 100.0)
    if stop <= 0 or stop < min_stop:
        pos['stop'] = min_stop
        pos['v265_stop_cap_pct'] = cap_pct
        pos['v265_stop_capped'] = True
        _v265_inc('stop_capped', f"손절폭 보정 {pos.get('ticker','?')}/{cap_pct:.2f}%")
    return pos


def _v265_sell_mode(pos: dict, pnl: float, max_up: float, trade: dict, market: dict) -> dict:
    pos = pos if isinstance(pos, dict) else {}
    trade = trade if isinstance(trade, dict) else {}
    market = market if isinstance(market, dict) else {}
    m = str(market.get('mode', 'unknown'))
    entry_rule = str(pos.get('entry_rule', '') or '')
    buy = safe_float(trade.get('buy_ratio', 0), 0)
    cnt = int(safe_float(trade.get('count', 0), 0))
    strong_coin = bool(trade.get('strong')) or (max_up >= 1.2 and buy >= 50 and cnt >= 5)
    weak_coin = bool(trade.get('weak')) or bool(trade.get('sell_heavy'))
    if m == 'weak' or weak_coin:
        return {"mode": "quick", "text": "짧게 먹기", "why": "장/체결이 약해서 욕심 줄임"}
    if m == 'strong' and strong_coin:
        return {"mode": "trend", "text": "더 끌고 가기", "why": "장과 코인 힘이 살아있음"}
    if entry_rule == 'now' and buy < 50:
        return {"mode": "quick", "text": "짧게 먹기", "why": "즉시진입인데 매수세가 약함"}
    return {"mode": "basic", "text": "기본 익절", "why": "기본 기준"}


def _v265_close_price_for_stop(entry: float, price: float, stop: float) -> float:
    entry = safe_float(entry, 0); price = safe_float(price, 0); stop = safe_float(stop, 0)
    if entry > 0 and stop > 0 and price > 0 and price <= stop:
        return max(price, stop)
    return price

_PREV_PAPER_REGISTER_CANDIDATE_V265 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    ok = _PREV_PAPER_REGISTER_CANDIDATE_V265(row, trigger=trigger)
    if not ok:
        return False
    try:
        ticker = _paper_ticker_v258(row)
        cls = _signal_v257_classify(row if isinstance(row, dict) else {}) if '_signal_v257_classify' in globals() else {}
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            best_id = None; best_ts = -1.0
            for pid, p in (paper_positions or {}).items():
                if isinstance(p, dict) and str(p.get('ticker','')).upper().strip() == ticker:
                    ts = safe_float(p.get('created_ts', 0), 0)
                    if ts > best_ts:
                        best_ts = ts; best_id = pid
            if best_id and now_ts - best_ts <= 10:
                p = paper_positions[best_id]
                p['paper_version'] = 'v2.5.265'
                p['v265_bucket'] = str(cls.get('v264_bucket', p.get('v264_bucket', '')) or '')
                p['v265_label'] = str(cls.get('v264_label', p.get('v264_label', '')) or '')
                p['v265_reason'] = str(cls.get('v264_reason', p.get('v264_reason', '')) or '')
                old_reason = str(p.get('register_reason', '') or '')
                if p.get('v265_label'):
                    p['register_reason'] = f"{p.get('v265_label')} / {p.get('v265_reason')}"
                p['note'] = '실제 주문 아님 / v265 문턱층+상황별 단일매도 검증'
                if str(p.get('status','')).upper() == 'OPEN':
                    paper_positions[best_id] = _v265_tighten_stop(p, market_mode=_v265_market_mode().get('mode'))
                _v265_inc('paper_tagged', f"등록태그 {ticker}/{p.get('v265_label') or old_reason}")
        save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log('paper_register_v265_followup', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return True


def paper_update_positions_once_v258():
    if not PAPER_TRADING_ON:
        return
    now_ts = time.time()
    changed = False
    try:
        market = _v265_market_mode()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get('ticker', '') or '').upper().strip()
            if not ticker:
                continue
            status = str(pos.get('status', '') or '').upper()
            fallback = safe_float(pos.get('last_price', pos.get('entry_price', 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            pos['last_price'] = price
            pos['last_price_source'] = src
            pos['last_price_age'] = safe_float(age, 0)
            pos['updated_ts'] = now_ts
            if status == 'PENDING':
                if now_ts - safe_float(pos.get('created_ts', now_ts), now_ts) >= PAPER_PENDING_TTL_SEC:
                    _paper_cancel_pending_v258(pid, pos, 'pending_timeout', now_ts)
                    continue
                entry_rule = str(pos.get('entry_rule', '') or '')
                low = safe_float(pos.get('planned_entry_low', 0), 0)
                high = safe_float(pos.get('planned_entry_high', 0), 0)
                chase = safe_float(pos.get('chase_stop', 0), 0)
                enter = False
                if entry_rule == 'breakout' and low > 0 and price >= low and (chase <= 0 or price <= chase):
                    enter = True
                elif entry_rule == 'pullback' and low > 0 and high > 0 and low <= price <= high:
                    enter = True
                elif entry_rule == 'now':
                    enter = True
                if chase > 0 and price > chase and entry_rule != 'now':
                    _paper_cancel_pending_v258(pid, pos, 'chase_over_before_entry', now_ts)
                    continue
                if enter:
                    pos['status'] = 'OPEN'
                    pos['entry_price'] = price
                    pos['entered_ts'] = now_ts
                    pos['remaining_ratio'] = 1.0
                    pos['realized_pct'] = 0.0
                    pos['single_exit_mode_v265'] = True
                    pos = _v265_tighten_stop(pos, market_mode=market.get('mode'))
                    PAPER_V258_STATS['entered'] = int(safe_float(PAPER_V258_STATS.get('entered', 0), 0)) + 1
                    changed = True
            if str(pos.get('status', '') or '').upper() == 'OPEN':
                entry = safe_float(pos.get('entry_price', 0), 0)
                if entry <= 0:
                    continue
                pos = _v265_tighten_stop(pos, market_mode=market.get('mode'))
                pnl = _paper_pct_v258(entry, price)
                pos['max_up_pct'] = max(safe_float(pos.get('max_up_pct', pnl), pnl), pnl)
                pos['min_down_pct'] = min(safe_float(pos.get('min_down_pct', pnl), pnl), pnl)
                max_up = safe_float(pos.get('max_up_pct', pnl), pnl)
                tp1 = safe_float(pos.get('tp1', 0), 0)
                tp2 = safe_float(pos.get('tp2', 0), 0)
                tp3 = safe_float(pos.get('tp3', 0), 0)
                stop = safe_float(pos.get('stop', 0), 0)
                open_age = now_ts - safe_float(pos.get('entered_ts', now_ts), now_ts)
                trade = _v265_trade_strength(ticker, pos)
                sell_mode = _v265_sell_mode(pos, pnl, max_up, trade, market)
                pos['v265_sell_mode'] = sell_mode.get('mode')
                pos['v265_sell_mode_text'] = sell_mode.get('text')
                pos['v265_sell_mode_why'] = sell_mode.get('why')
                pos['v265_ws_trade_count'] = int(safe_float(trade.get('count',0),0))
                pos['v265_ws_buy_ratio'] = safe_float(trade.get('buy_ratio',0),0)
                close_reason = ''
                close_price = price
                if stop > 0 and price <= stop:
                    close_reason = 'stop_loss_v265' if max_up < PAPER_V261_LOCK1_UP_PCT else 'protect_stop_v265'
                    close_price = _v265_close_price_for_stop(entry, price, stop)
                    if max_up >= PAPER_V261_LOCK1_UP_PCT:
                        _v265_inc('protect_exit', f"보호청산 {ticker}/{pnl:+.2f}")
                    else:
                        _v265_inc('hard_stop', f"손절 {ticker}/{_paper_pct_v258(entry, close_price):+.2f}")
                elif pnl <= -PAPER_V265_HARD_LOSS_PCT:
                    hard_price = entry * (1 - PAPER_V265_HARD_LOSS_PCT / 100.0)
                    close_reason = 'hard_stop_v265'
                    close_price = max(price, hard_price)
                    _v265_inc('hard_stop', f"비상손절 {ticker}/{_paper_pct_v258(entry, close_price):+.2f}")
                else:
                    mode = str(sell_mode.get('mode','basic'))
                    tp1_pct = _paper_pct_v258(entry, tp1) if tp1 > 0 else 0.0
                    quick_target = max(PAPER_V265_QUICK_TP_PCT, min(1.05, tp1_pct if tp1_pct > 0 else PAPER_V265_QUICK_TP_PCT))
                    basic_target = max(PAPER_V265_BASIC_TP_MIN_PCT, tp1_pct if tp1_pct > 0 else PAPER_V265_BASIC_TP_MIN_PCT)
                    if mode == 'quick':
                        if pnl >= quick_target:
                            close_reason = 'quick_take_profit_v265'; _v265_inc('quick_exit', f"짧게익절 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK1_UP_PCT and pnl <= max(0.15, PAPER_V261_LOCK1_KEEP_PCT):
                            close_reason = 'quick_profit_protect_v265'; _v265_inc('protect_exit', f"빠른보호 {ticker}/{pnl:+.2f}")
                    elif mode == 'trend':
                        if tp3 > 0 and price >= tp3:
                            close_reason = 'trend_tp3_exit_v265'; _v265_inc('trend_exit', f"추세TP3 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK3_UP_PCT and pnl <= PAPER_V261_LOCK3_KEEP_PCT:
                            close_reason = 'trend_profit_lock_3_v265'; _v265_inc('protect_exit', f"추세보호3 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK2_UP_PCT and pnl <= PAPER_V261_LOCK2_KEEP_PCT:
                            close_reason = 'trend_profit_lock_2_v265'; _v265_inc('protect_exit', f"추세보호2 {ticker}/{pnl:+.2f}")
                        elif pnl >= basic_target and bool(trade.get('sell_heavy')):
                            close_reason = 'trend_weakening_exit_v265'; _v265_inc('trend_exit', f"힘빠짐청산 {ticker}/{pnl:+.2f}")
                    else:
                        if pnl >= basic_target or (tp1 > 0 and price >= tp1):
                            close_reason = 'basic_single_tp_v265'; _v265_inc('basic_exit', f"기본익절 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK2_UP_PCT and pnl <= PAPER_V261_LOCK2_KEEP_PCT:
                            close_reason = 'basic_profit_lock_2_v265'; _v265_inc('protect_exit', f"기본보호2 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_LOCK1_KEEP_PCT:
                            close_reason = 'basic_profit_lock_1_v265'; _v265_inc('protect_exit', f"기본보호1 {ticker}/{pnl:+.2f}")
                    if not close_reason:
                        if open_age >= PAPER_OPEN_TTL_SEC:
                            close_reason = f"time_exit_{mode}_v265"
                        elif open_age >= PAPER_V265_SLOW_EXIT_MIN_SEC and max_up < PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_SLOW_EXIT_MAX_PNL:
                            close_reason = f"slow_no_progress_exit_{mode}_v265"; _v265_inc('slow_exit', f"무진행정리 {ticker}/{pnl:+.2f}")
                if close_reason:
                    pos['v265_market_mode'] = market.get('text')
                    pos['v265_close_rule'] = close_reason
                    _paper_close_position_v258(pid, pos, close_price, close_reason, now_ts)
                    continue
                stop_now = safe_float(pos.get('stop', 0), 0)
                if max_up >= PAPER_V261_LOCK3_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK3_KEEP_PCT / 100.0))
                elif max_up >= PAPER_V261_LOCK2_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK2_KEEP_PCT / 100.0))
                elif max_up >= PAPER_V261_LOCK1_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK1_KEEP_PCT / 100.0))
                with PAPER_STATE_LOCK:
                    if pid in paper_positions:
                        paper_positions[pid].update(pos)
                changed = True
        if changed:
            save_paper_state_v258()
    except Exception as e:
        append_runtime_error_log('paper_update_positions_v265', str(e), exc=e, include_traceback=False)

_PREV_SIGNAL_V264_FORMAT_ONE_FOR_V265 = _signal_v264_format_one

def _signal_v264_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _PREV_SIGNAL_V264_FORMAT_ONE_FOR_V265(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        bucket = str(cls.get('v264_bucket', '') or '')
        lines = str(text).splitlines()
        if not lines:
            return text
        import re as _re
        m = _re.match(r'^(\d+\.\s+)(\S+)\s+([^/]+?)\s*/\s*([^/]+)(/.*)?$', lines[0])
        if m:
            prefix, icon, ticker_part, _old, tail = m.groups(); tail = tail or ''
            if bucket == 'review_only': lines[0] = f"{prefix}🧷 {ticker_part.strip()} / 복기·감시{tail}"
            elif bucket == 'watch_only': lines[0] = f"{prefix}👀 {ticker_part.strip()} / 구경만{tail}"
            elif bucket == 'true_discard': lines[0] = f"{prefix}⛔ {ticker_part.strip()} / 진짜 버림{tail}"
            elif bucket == 'breakout_watch': lines[0] = f"{prefix}🟠 {ticker_part.strip()} / 돌파대기{tail}"
            elif bucket == 'pullback_watch': lines[0] = f"{prefix}🟡 {ticker_part.strip()} / 눌림대기{tail}"
            elif bucket == 'buy_ready': lines[0] = f"{prefix}🔥 {ticker_part.strip()} / 진짜 매수 후보{tail}"
        if bucket in {'review_only', 'watch_only'}:
            lines = [x.replace('지금 돈 넣을 후보 아님. 명령어/복기에서만 추적.', '지금 매수는 아님. 감시/복기에서 계속 추적.') for x in lines]
        return "\n".join(lines)
    except Exception:
        return text

_PREV_BUILD_PAPER_TEXT_V265 = build_paper_text_v258

def build_paper_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_TEXT_V265(limit=limit)
    try:
        reps = {
            '- v261: REST/WS 혼합 데이터품질을 보고, 1만원 소액 기준은 단일익절·보호손절 중심.': '- v265: 후보층 기준으로 등록하고, 장/코인 힘에 따라 짧게 먹기·기본익절·더 끌고가기를 나눔.',
            '등록이유: strict 통과 v260': '등록이유: 문턱층 strict 대기후보',
            '등록이유: loose 문턱 검증층 v260': '등록이유: 문턱층 loose 실험후보',
            '등록이유: strict 통과': '등록이유: 문턱층 strict 대기후보',
        }
        for a,b in reps.items(): text = str(text).replace(a,b)
        with PAPER_STATE_LOCK:
            open_modes = {str(p.get('ticker','')).upper().strip(): (str(p.get('v265_sell_mode_text','') or ''), str(p.get('v265_sell_mode_why','') or '')) for p in (paper_positions or {}).values() if isinstance(p, dict)}
        lines = []
        for line in str(text).splitlines():
            lines.append(line)
            if line.startswith('- 손절 '):
                recent = '\n'.join(lines[-4:])
                import re as _re
                m = _re.search(r'✅\s+([A-Z0-9]+)\s+/', recent)
                if m:
                    mode, why = open_modes.get(m.group(1), ('',''))
                    if mode: lines.append(f"- 매도모드: {mode} / {why}")
        return '\n'.join(lines)
    except Exception:
        return text

