def build_paper_recent_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_RECENT_TEXT_V265(limit=limit)
    try:
        note_map = {
            'quick_take_profit_v265': '빠른익절', 'basic_single_tp_v265': '기본익절', 'trend_tp3_exit_v265': '강한장 길게먹기',
            'trend_weakening_exit_v265': '힘빠져 청산', 'quick_profit_protect_v265': '빠른 수익보호',
            'basic_profit_lock_1_v265': '기본 수익보호1', 'basic_profit_lock_2_v265': '기본 수익보호2',
            'trend_profit_lock_2_v265': '추세 수익보호2', 'trend_profit_lock_3_v265': '추세 수익보호3',
            'stop_loss_v265': '손절폭 제한 손절', 'hard_stop_v265': '비상손절',
            'slow_no_progress_exit_quick_v265': '약해서 무진행정리', 'slow_no_progress_exit_basic_v265': '무진행정리', 'slow_no_progress_exit_trend_v265': '추세 실패 정리'
        }
        out=[]
        for line in str(text).splitlines():
            extra=''
            for k,v in note_map.items():
                if k in line: extra=f" / {v}"; break
            out.append(line+extra)
        return '\n'.join(out)
    except Exception:
        return text

_PREV_BUILD_PAPER_STATS_TEXT_V265 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try: base = _PREV_BUILD_PAPER_STATS_TEXT_V265()
    except Exception as e: base = f"📊 모의매매 성과 /paper_stats\n- 기본 통계 생성 오류: {e}"
    try:
        rows = _paper_closed_logs_v258()
        v265_rows = [r for r in rows if safe_float(r.get('close_ts', r.get('cancel_ts', 0)), 0) >= PAPER_V265_START_TS]
        extra = ['', '[v265 이후 성과 - 상황별 매도/손절폭 보정 후]', _paper_stats_line_v258('v265 적용 후', v265_rows)]
        if v265_rows:
            strict_rows = [r for r in v265_rows if str(r.get('lane','')) == 'strict_signal']
            loose_rows = [r for r in v265_rows if str(r.get('lane','')) == 'loose_threshold_test']
            extra.append(_paper_stats_line_v258('v265 strict', strict_rows))
            extra.append(_paper_stats_line_v258('v265 loose', loose_rows))
            buckets=[('진짜매수','buy_ready'),('돌파대기','breakout_watch'),('눌림대기','pullback_watch'),('구경만','watch_only'),('복기/감시','review_only'),('진짜버림','true_discard')]
            extra.append(''); extra.append('[v265 후보층별 성과]')
            any_bucket=False
            for label,key in buckets:
                br=[r for r in v265_rows if str(r.get('v265_bucket', r.get('v264_bucket',''))) == key]
                if br: any_bucket=True; extra.append(_paper_stats_line_v258(label, br))
            if not any_bucket: extra.append('- 후보층 기록은 v265 신규 등록분부터 쌓임')
            reasons={}
            for r in v265_rows:
                reasons.setdefault(str(r.get('close_reason','') or '-'), []).append(r)
            if reasons:
                extra.append(''); extra.append('[v265 매도사유별 성과]')
                for reason, rr in sorted(reasons.items(), key=lambda kv: len(kv[1]), reverse=True)[:6]:
                    extra.append(_paper_stats_line_v258(reason, rr))
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base

