# =========================================================
# v2.5.267: 등록 후 재평가 + now 진입 분리 + 좋은표본 재승격 강화
# =========================================================
# 목적:
# - 좋은 자리로 등록한 뒤에도 계속 좋은 상태인지 다시 확인한다.
# - 진입대기 중 신호가 진짜버림/돈약함/체결0으로 바뀌면 pending_timeout까지 기다리지 않고 취소한다.
# - 보유가정 중 신호가 급격히 나빠지면 손절선 전이라도 빠른정리/보호청산한다.
# - now 즉시진입은 가장 위험하므로 체결/매수세/돈/현재봉이 충분할 때만 paper에 태운다.
# - review_watch의 좋은 표본/강세 유지 후보를 재출발·눌림 후보로 더 잘 연결한다.
PAPER_V267_START_TS = time.time()
PAPER_V267_STATS = {
    "pending_cancel": 0,
    "open_recheck_exit": 0,
    "protect_recheck_exit": 0,
    "now_blocked": 0,
    "now_to_wait": 0,
    "good_sample_boost": 0,
    "stale_signal_sync": 0,
    "last_note": "대기",
}


def _v267_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V267_STATS:
            PAPER_V267_STATS[key] = int(safe_float(PAPER_V267_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V267_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v267_text_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v267_is_true_discard(cls: dict, bits: dict = None) -> tuple[bool, str]:
    cls = cls if isinstance(cls, dict) else {}
    bits = bits if isinstance(bits, dict) else {}
    joined = " / ".join([
        str(cls.get("grade", "") or ""), str(cls.get("decision", "") or ""), str(cls.get("action", "") or ""),
        str(cls.get("v264_label", "") or ""), str(cls.get("v264_reason", "") or ""),
        str(cls.get("v266_label", "") or ""), str(cls.get("v266_reason", "") or ""),
        str(cls.get("reason", "") or ""), " / ".join([str(x) for x in (cls.get("reasons") or [])[:5]]) if isinstance(cls.get("reasons"), list) else str(cls.get("reasons", "") or ""),
    ])
    grade = str(cls.get("grade", "") or "").upper()
    v264_bucket = str(cls.get("v264_bucket", "") or "")
    v266_bucket = str(cls.get("v266_bucket", "") or "")
    money = safe_float(cls.get("money_amount", bits.get("money", 0)), 0)
    trade_count = int(safe_float(cls.get("trade_count", bits.get("trade_count", 0)), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", bits.get("buy_ratio", 0)), 0)
    if v264_bucket == "true_discard" or v266_bucket in {"true_discard", "late_block"}:
        return True, "현재 신호가 진짜버림/늦은진입 차단"
    if grade == "DISCARD" and _v267_text_has(joined, ["진짜 버림", "실제 돈이 너무 작음", "실제돈작음", "매수/감시 근거 부족"]):
        return True, "현재 신호가 진짜버림"
    if money <= 1_000_000 and trade_count <= 0:
        return True, "실제 돈 너무 작고 체결 없음"
    if trade_count <= 0 and buy_ratio <= 0 and grade == "DISCARD":
        return True, "체결/매수세 없음"
    return False, ""


def _v267_current_cls_for_pos(ticker: str, pos: dict = None) -> dict:
    ticker = str(ticker or "").upper().strip()
    pos = pos if isinstance(pos, dict) else {}
    cls = {}
    try:
        if "_v266_find_current_cls" in globals():
            cls = dict(_v266_find_current_cls(ticker) or {})
    except Exception:
        cls = {}
    if not cls:
        cls = dict(pos or {})
        cls.setdefault("ticker", ticker)
        cls.setdefault("trade_count", pos.get("trade_count", 0))
        cls.setdefault("buy_ratio", pos.get("buy_ratio", 0))
        cls.setdefault("money_amount", pos.get("money_amount", 0))
        cls.setdefault("score", pos.get("score", 0))
    return cls


# v266의 후보층 판단을 보강한다. 기존 판단이 좋은 후보를 잡으면 그대로 두고,
# 놓치던 검증표본/재출발 표본만 좁게 추가 승격한다.
_BASE_V266_BUCKET_FOR_V267 = _v266_bucket_from_cls

def _v266_bucket_from_cls(cls: dict, row: dict = None) -> dict:
    base = _BASE_V266_BUCKET_FOR_V267(cls, row)
    try:
        if isinstance(base, dict) and bool(base.get("paper_ok", False)):
            return base
        cls = cls if isinstance(cls, dict) else {}
        row = row if isinstance(row, dict) else {}
        bits = _v266_strength_bits(cls, row) if "_v266_strength_bits" in globals() else {}
        joined = str(bits.get("joined", "") or "")
        money = safe_float(bits.get("money", cls.get("money_amount", 0)), 0)
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", 0)), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", 0)), 0)
        from_low = safe_float(bits.get("from_low", cls.get("from_low", 0)), 0)
        high_gap = safe_float(bits.get("high_gap", cls.get("high_gap", 999)), 999)
        candle_weak = bool(bits.get("candle_weak", False))
        money_weak = bool(bits.get("money_weak", False))
        true_discard, _ = _v267_is_true_discard(cls, bits)
        if true_discard:
            return base
        good_words = ["검증 표본 좋음", "강세 후 유지 확인", "10분 감시 판단 좋음", "좋은표본", "감시 판단 좋음"]
        restart_words = ["재출발", "눌림", "저점방어", "초입/회복", "회복 확인", "다시 살아남"]
        good_sample = bool(bits.get("good_sample", False)) or _v267_text_has(joined, good_words)
        restart_like = _v267_text_has(joined, restart_words)
        # 좋은 표본은 돈이 너무 얇지 않고, 완전히 식은 상태가 아니면 눌림/재출발 후보로 살린다.
        if good_sample and money >= 30_000_000 and from_low <= 3.80 and not (candle_weak and money_weak):
            if trade_count >= 1 or buy_ratio >= 35 or bool(bits.get("candle_alive", False)):
                _v267_inc("good_sample_boost", f"좋은표본 재승격 {cls.get('ticker','?')}")
                return {"bucket": "good_sample_reentry", "label": "좋은표본 재승격", "reason": "검증표본 좋음→눌림/재출발 후보", "paper_ok": True, "entry_rule": "pullback"}
        # 눌림/재출발 문구가 있는데 기존 v266에서 감시만으로 빠진 경우를 좁게 복구.
        if restart_like and money >= 50_000_000 and from_low <= 2.80 and not candle_weak and not money_weak:
            if trade_count >= 2 or buy_ratio >= 45:
                _v267_inc("good_sample_boost", f"재출발 보강 {cls.get('ticker','?')}")
                return {"bucket": "restart_pullback", "label": "눌림·재출발 후보", "reason": "재출발 문구+돈/현재봉 유지", "paper_ok": True, "entry_rule": "pullback"}
        # 고점 맞닿음이면서 체결이 빈약한 돌파는 기존 대기라 해도 돈 넣는 길은 막는다.
        if (0 <= high_gap <= 0.12) and (trade_count <= 1 or buy_ratio < 35) and str(cls.get("grade", "")).upper() in {"BREAKOUT_WAIT", "BUY_OK"}:
            return {"bucket": "late_block", "label": "늦은진입 차단", "reason": "고점맞닿음+체결 부족", "paper_ok": False, "entry_rule": "observe"}
    except Exception:
        pass
    return base


_BASE_PAPER_CLASSIFY_V267 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V267(row)
    try:
        cls = dict(cls or {})
        bits = _v266_strength_bits(cls, row if isinstance(row, dict) else {}) if "_v266_strength_bits" in globals() else {}
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        if true_discard:
            _v267_inc("stale_signal_sync", f"등록차단 {cls.get('ticker','?')}/{td_reason}")
            return False, "blocked_v267_discard", f"v267 등록차단: {td_reason}", cls
        entry_rule = str(cls.get("paper_entry_rule_v259", cls.get("v266_entry_rule", "")) or "")
        grade = str(cls.get("grade", "") or "").upper()
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", 0)), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", 0)), 0)
        money = safe_float(bits.get("money", cls.get("money_amount", 0)), 0)
        high_gap = safe_float(bits.get("high_gap", cls.get("high_gap", 999)), 999)
        candle_alive = bool(bits.get("candle_alive", False))
        candle_weak = bool(bits.get("candle_weak", False))
        money_weak = bool(bits.get("money_weak", False))
        high_touch = bool(bits.get("high_touch", False))
        # now 즉시진입은 확실한 경우만 허용. 부족하면 후보는 남기고 paper 진입만 막는다.
        if ok and (entry_rule == "now" or grade == "BUY_OK"):
            strong_now = (money >= 100_000_000 and trade_count >= 4 and buy_ratio >= 55 and candle_alive and not money_weak and not candle_weak)
            high_ok = (not high_touch) or (trade_count >= 8 and buy_ratio >= 60 and high_gap >= 0.05)
            if not (strong_now and high_ok):
                _v267_inc("now_blocked", f"now 차단 {cls.get('ticker','?')}")
                cls["v267_now_block_reason"] = "즉시진입 근거 부족"
                return False, "blocked_v267_now", "v267 now 즉시진입 차단: 체결/매수세/현재봉/고점거리 부족", cls
    except Exception as e:
        try: append_runtime_error_log("paper_classify_v267", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return ok, lane, reason, cls


_BASE_PAPER_REGISTER_V267 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    ok = _BASE_PAPER_REGISTER_V267(row, trigger=trigger)
    if not ok:
        return ok
    try:
        ticker = _paper_ticker_v258(row)
        cls = _signal_v257_classify(row)
        with PAPER_STATE_LOCK:
            for pid, p in list((paper_positions or {}).items()):
                if isinstance(p, dict) and str(p.get("ticker", "")).upper().strip() == ticker and not p.get("v267_tagged"):
                    p["paper_version"] = "v2.5.267"
                    p["v267_tagged"] = True
                    p["v267_registered_ts"] = time.time()
                    p["v267_bucket"] = str(cls.get("v266_bucket", "") or p.get("v266_bucket", ""))
                    p["v267_label"] = str(cls.get("v266_label", "") or p.get("v266_label", ""))
                    p["v267_reason"] = str(cls.get("v266_reason", "") or p.get("v266_reason", ""))
                    if p.get("v267_label"):
                        p["register_reason"] = f"{p.get('v267_label')} / {p.get('v267_reason')}"
                    paper_positions[pid] = p
                    break
        save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log("paper_register_v267_followup", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return ok


def _v267_pending_cancel_reason(pos: dict, cls: dict, price: float, now_ts: float) -> str:
    try:
        bits = _v266_strength_bits(cls, cls) if "_v266_strength_bits" in globals() else {}
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        age = now_ts - safe_float(pos.get("created_ts", now_ts), now_ts)
        entry_rule = str(pos.get("entry_rule", "") or "")
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", pos.get("trade_count", 0))), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", pos.get("buy_ratio", 0))), 0)
        money = safe_float(bits.get("money", cls.get("money_amount", pos.get("money_amount", 0))), 0)
        if true_discard:
            return td_reason
        if age >= 45 and money <= 1_000_000 and trade_count <= 0:
            return "진입대기 중 실제돈/체결 사라짐"
        if age >= 60 and trade_count <= 0 and buy_ratio <= 0:
            return "진입대기 중 60초 체결 없음"
        if age >= 45 and bool(bits.get("candle_weak", False)) and bool(bits.get("money_weak", False)):
            return "진입대기 중 현재봉/돈흐름 식음"
        if entry_rule == "breakout" and age >= 45 and bool(bits.get("high_touch", False)) and trade_count < 2:
            return "돌파대기인데 고점 앞 체결 부족"
        if entry_rule == "now" and age >= 20 and (trade_count < 3 or buy_ratio < 45 or bool(bits.get("candle_weak", False))):
            return "즉시진입 대기 중 힘 부족"
    except Exception:
        pass
    return ""


def _v267_open_recheck_reason(pos: dict, cls: dict, price: float, now_ts: float) -> tuple[str, str]:
    try:
        entry = safe_float(pos.get("entry_price", 0), 0)
        if entry <= 0 or price <= 0:
            return "", ""
        bits = _v266_strength_bits(cls, cls) if "_v266_strength_bits" in globals() else {}
        pnl = _paper_pct_v258(entry, price)
        max_up = safe_float(pos.get("max_up_pct", pnl), pnl)
        open_age = now_ts - safe_float(pos.get("entered_ts", pos.get("created_ts", now_ts)), now_ts)
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", pos.get("trade_count", 0))), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", pos.get("buy_ratio", 0))), 0)
        if open_age < 25:
            return "", ""
        # 수익을 봤다가 신호가 약해지면 보호청산.
        if max_up >= 0.45 and (true_discard or bool(bits.get("candle_weak", False)) or bool(bits.get("money_weak", False)) or buy_ratio < 35):
            return "protect_recheck_exit_v267", "수익 후 신호 약화"
        # 손실이 작게 시작됐고 현재 신호가 버림/체결부족이면 손절선까지 기다리지 않고 정리.
        if pnl <= -0.25 and true_discard:
            return "open_recheck_exit_v267", td_reason or "보유 중 진짜버림 전환"
        if pnl <= -0.35 and trade_count <= 0 and buy_ratio <= 0:
            return "open_recheck_exit_v267", "보유 중 체결/매수세 없음"
        if pnl <= -0.45 and bool(bits.get("candle_weak", False)) and bool(bits.get("money_weak", False)):
            return "open_recheck_exit_v267", "보유 중 현재봉/돈흐름 식음"
        # now 진입은 엄격히 본다. 힘 없으면 빠른정리.
        if str(pos.get("entry_rule", "") or "") == "now" and open_age >= 60 and pnl <= 0.10 and (trade_count < 3 or buy_ratio < 45):
            return "now_recheck_exit_v267", "now 진입 후 힘 부족"
    except Exception:
        pass
    return "", ""


_BASE_PAPER_UPDATE_V267 = paper_update_positions_once_v258

def paper_update_positions_once_v258():
    # v267: 기존 v266/v265 업데이트 전에 대기/보유 상태를 현재 신호와 동기화한다.
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            status = str(pos.get("status", "") or "").upper()
            fallback = safe_float(pos.get("last_price", pos.get("entry_price", 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            cls = _v267_current_cls_for_pos(ticker, pos)
            if status == "PENDING":
                reason = _v267_pending_cancel_reason(pos, cls, price, now_ts)
                if reason:
                    pos["v267_cancel_reason"] = reason
                    pos["last_price"] = price
                    pos["last_price_source"] = src
                    _v267_inc("pending_cancel", f"대기취소 {ticker}/{reason}")
                    _paper_cancel_pending_v258(pid, pos, "early_pending_cancel_v267", now_ts)
                    continue
            elif status == "OPEN":
                close_reason, detail = _v267_open_recheck_reason(pos, cls, price, now_ts)
                if close_reason:
                    pos["v267_exit_reason"] = detail
                    pos["last_price"] = price
                    pos["last_price_source"] = src
                    if close_reason == "protect_recheck_exit_v267":
                        _v267_inc("protect_recheck_exit", f"보호정리 {ticker}/{detail}")
                    else:
                        _v267_inc("open_recheck_exit", f"보유정리 {ticker}/{detail}")
                    _paper_close_position_v258(pid, pos, price, close_reason, now_ts)
                    continue
    except Exception as e:
        try: append_runtime_error_log("paper_recheck_v267", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_PAPER_UPDATE_V267()


