# v2.5.271: 미리볼 후보는 "명령어 전용"으로 고정
# - 삭제가 아니라 /signal, /rank_short, /review_watch 같은 명령어에서만 보이게 둔다.
# - 즉시 텔레그램 푸시 알림으로 보내지 않는다.
# - paper 자동등록도 하지 않는다. paper는 진입준비/매수 문턱을 통과한 뒤에만 등록한다.
# - 조건 조이기 아님. 후보 입구는 넓게 두되, 돈 들어가는 단계만 좁게 유지한다.
PAPER_V271_START_TS = time.time()
PAPER_V271_STATS = {
    "preview_command_only": 0,
    "preview_push_blocked": 0,
    "preview_paper_blocked": 0,
    "last_note": "대기",
}


def _v271_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V271_STATS:
            PAPER_V271_STATS[key] = int(safe_float(PAPER_V271_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V271_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v271_payload_text(payload) -> str:
    try:
        if not isinstance(payload, dict):
            return str(payload or "")[:500]
        parts = []
        for k in [
            "ticker", "grade", "decision", "label_text", "user_label_text", "one_liner",
            "v270_bucket", "v270_reason", "v266_bucket", "v264_bucket",
            "quality_block_reason", "primary_reason", "alert_section", "section",
        ]:
            v = payload.get(k, "")
            if v not in (None, ""):
                parts.append(f"{k}={v}")
        rs = payload.get("reasons", [])
        if isinstance(rs, list):
            parts.extend([str(x) for x in rs[:5]])
        return " / ".join(parts)[:900]
    except Exception:
        return ""


def _v271_is_preview_command_only(payload) -> bool:
    """미리볼/예열 후보는 삭제하지 않고 명령어 전용으로만 남긴다."""
    try:
        if not isinstance(payload, dict):
            return False
        if str(payload.get("v270_bucket", "") or "") == "preheat_preview":
            return True
        if bool(payload.get("v270_preview_command_only")):
            return True
        txt = _v271_payload_text(payload)
        if "미리볼" in txt or "예열" in txt:
            grade = str(payload.get("grade", "") or "").upper()
            kind = str(payload.get("kind", payload.get("signal_kind", "")) or "").upper()
            if grade in {"BUY_OK", "SELL", "STOP", "TP"} or kind in {"BUY_SIGNAL", "SELL_SIGNAL", "STOP_LOSS_SIGNAL", "TAKE_PROFIT_SIGNAL"}:
                return False
            return True
        return False
    except Exception:
        return False


