try:
    _BASE_SEND_WATCH_ALERT_BUNDLE_V271 = send_watch_alert_bundle
    def send_watch_alert_bundle(header: str, entries, section_key: str = ""):
        try:
            normal_entries = []
            preview_entries = []
            for entry in list(entries or []):
                item = entry[0] if isinstance(entry, (list, tuple)) and entry else entry
                if isinstance(item, dict) and _v271_is_preview_command_only(item):
                    preview_entries.append(entry)
                else:
                    normal_entries.append(entry)
            if preview_entries:
                _v271_inc("preview_push_blocked", f"미리볼 알림차단 {len(preview_entries)}개")
                try:
                    save_recent_candidate_alerts(preview_entries, header=f"[명령어 전용 미리볼] {header}")
                except Exception:
                    pass
                try:
                    append_runtime_event_log(
                        'preview_command_only_v271',
                        '미리볼 후보 즉시푸시 차단, 명령어 전용 기록',
                        extra={'section_key': section_key, 'count': len(preview_entries), 'header': str(header or '')[:120]},
                    )
                except Exception:
                    pass
            if normal_entries:
                return _BASE_SEND_WATCH_ALERT_BUNDLE_V271(header, normal_entries, section_key=section_key)
            return None
        except Exception as e:
            try: append_runtime_error_log('send_watch_alert_bundle_v271', str(e), exc=e, include_traceback=True)
            except Exception: pass
            return None
except Exception:
    pass


