# =========================================================
# v2.5.272: 미리볼 후보 paper 잔여 정리 + 조건조이기 잠금 표시
# =========================================================
# 이번 수정 목적:
# - 미리볼 후보는 삭제하지 않고 명령어에서 넓게 본다.
# - 단, 미리볼 후보가 /paper 보유가정/진입대기로 남아 헷갈리는 문제를 정리한다.
# - paper는 진짜 매수/진입준비 문턱을 통과한 후보만 검증한다.
# - 조건을 더 조이는 수정은 사용자 허락 전에는 하지 않는 원칙을 상태창에 고정 표시한다.
PAPER_V272_START_TS = time.time()
PAPER_V272_STATS = {
    "preview_register_blocked": 0,
    "preview_paper_cleanup": 0,
    "approval_lock": 1,
    "last_note": "대기",
}


def _v272_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V272_STATS:
            PAPER_V272_STATS[key] = int(safe_float(PAPER_V272_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V272_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v272_join_text(obj) -> str:
    try:
        if not isinstance(obj, dict):
            return str(obj or "")[:800]
        vals = []
        for k in [
            "ticker", "lane", "trigger", "register_reason", "close_reason", "note",
            "v270_bucket", "v270_reason", "v266_bucket", "v264_bucket",
            "signal_decision", "original_grade", "signal_grade", "entry_rule",
        ]:
            v = obj.get(k, "")
            if v not in (None, ""):
                vals.append(f"{k}={v}")
        rs = obj.get("reasons", [])
        if isinstance(rs, list):
            vals.extend([str(x) for x in rs[:6]])
        return " / ".join(vals)[:1200]
    except Exception:
        return ""


def _v272_is_preview_paper_obj(obj) -> bool:
    """미리볼/예열 검증이 paper에 남아 있으면 정리 대상으로 본다."""
    try:
        if not isinstance(obj, dict):
            return False
        lane = str(obj.get("lane", "") or "").lower()
        if lane in {"preheat_preview_test", "preview_command_only_v271"}:
            return True
        if "preheat" in lane or "preview" in lane:
            return True
        if bool(obj.get("v270_preview_registered")) or bool(obj.get("v270_preview_command_only")):
            return True
        if str(obj.get("v270_bucket", "") or "") == "preheat_preview":
            return True
        txt = _v272_join_text(obj)
        if "미리볼" in txt or "예열" in txt or "preheat_preview" in txt:
            return True
        return False
    except Exception:
        return False


def cleanup_preview_paper_positions_v272(reason: str = "preview_command_only_cleanup_v272") -> int:
    """기존 paper_positions.json에 남아 있던 미리볼 검증 포지션을 취소 처리한다.
    실제 거래가 아니므로 손익 통계에는 CLOSED로 넣지 않고 CANCELLED로 남긴다.
    """
    removed = 0
    now_ts = time.time()
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items()
                     if isinstance(pos, dict) and str(pos.get("status", "")).upper() in {"PENDING", "OPEN"}]
        for pid, pos in items:
            if not _v272_is_preview_paper_obj(pos):
                continue
            row = dict(pos)
            row.update({
                "status": "CANCELLED",
                "cancel_ts": now_ts,
                "close_ts": now_ts,
                "close_reason": str(reason or "preview_command_only_cleanup_v272"),
                "pnl_pct": 0.0,
                "v272_preview_cleanup": True,
                "cleanup_note": "미리볼 후보는 명령어 전용이라 paper 잔여 포지션에서 제거",
            })
            with PAPER_STATE_LOCK:
                paper_positions.pop(pid, None)
                paper_trade_log.append(row)
                if len(paper_trade_log) > PAPER_TRADE_LOG_MAX:
                    del paper_trade_log[:-PAPER_TRADE_LOG_MAX]
            removed += 1
        if removed:
            PAPER_V272_STATS["preview_paper_cleanup"] = int(safe_float(PAPER_V272_STATS.get("preview_paper_cleanup", 0), 0)) + removed
            PAPER_V272_STATS["last_note"] = f"미리볼 paper 잔여정리 {removed}개"
            save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log("cleanup_preview_paper_positions_v272", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return removed


