def _v273_reason_top_lines(limit: int = 5) -> list:
    try:
        d = PAPER_V273_STATS.get('reason_counts', {})
        if not isinstance(d, dict) or not d:
            return ["- 아직 누적된 이유 없음"]
        items = sorted(d.items(), key=lambda kv: int(safe_float(kv[1], 0)), reverse=True)[:max(1, int(limit))]
        return [f"{i}. {k} {int(safe_float(v, 0))}회" for i, (k, v) in enumerate(items, start=1)]
    except Exception:
        return ["- 이유 집계 오류"]


