# =========================================================
# v2.5.275: WebSocket 체결흐름 패키지 1차
# - 러시체결 / 체결속도 증가 / 매수우세 유지 / 매도반전 / 고점맞닿음 시장가 금지
# - REST/OHLCV 추가 호출 없음. WS_TRADE_CACHE와 기존 row/cls 값만 사용.
# =========================================================
PAPER_V275_START_TS = time.time()
PAPER_V275_STATS = {"rush_detected":0,"speed_accel":0,"buy_sustain":0,"flow_bridge_ready":0,"flow_pullback_wait":0,"flow_breakout_wait":0,"sell_reversal_block":0,"high_touch_market_block":0,"weak_flow_watch":0,"last_note":"대기"}
V275_RUSH_5S_MIN_COUNT=3; V275_RUSH_5S_MIN_BUY_RATIO=70.0; V275_RUSH_5S_MIN_AMOUNT=500_000
V275_RUSH_15S_MIN_COUNT=5; V275_RUSH_15S_MIN_BUY_RATIO=64.0; V275_RUSH_15S_MIN_AMOUNT=1_000_000
V275_SUSTAIN_60S_MIN_COUNT=6; V275_SUSTAIN_60S_MIN_BUY_RATIO=55.0; V275_SUSTAIN_60S_MIN_AMOUNT=1_500_000
V275_SELL_REVERSAL_15S_BUY_RATIO_MAX=38.0; V275_SELL_REVERSAL_60S_BUY_RATIO_MAX=45.0
V275_HIGH_TOUCH_GAP_PCT=0.12; V275_FROM_LOW_MAX_FOR_FLOW_BRIDGE=3.30

def _v275_inc(k,n=""):
    try:
        if k in PAPER_V275_STATS: PAPER_V275_STATS[k]=int(safe_float(PAPER_V275_STATS.get(k,0),0))+1
        if n: PAPER_V275_STATS["last_note"]=str(n)[:180]
    except Exception: pass

def _v275_ticker(row,cls=None):
    try:
        if '_v273_ticker' in globals():
            t=_v273_ticker(row if isinstance(row,dict) else {}, cls if isinstance(cls,dict) else {})
            if t: return str(t).upper().strip()
        for o in (cls,row):
            if isinstance(o,dict):
                for k in ("ticker","symbol","coin"):
                    if o.get(k): return str(o.get(k)).upper().strip()
    except Exception: pass
    return ""

def _v275_ws(t,row,sec):
    try:
        if t and 'get_ws_trade_summary_for_ticker' in globals():
            s=get_ws_trade_summary_for_ticker(t,sec)
            if isinstance(s,dict) and int(s.get('count',0) or 0)>0: return s
    except Exception: pass
    row=row if isinstance(row,dict) else {}
    if int(sec)>=60:
        return {"ticker":t,"count":int(safe_float(row.get('ws_trade_count_60s',row.get('trade_count',0)),0)),"amount":safe_float(row.get('ws_trade_amount_60s',row.get('money_amount',row.get('turnover_5m',0))),0),"buy_ratio":safe_float(row.get('ws_trade_buy_ratio_60s',row.get('buy_ratio',0)),0),"label":str(row.get('ws_trade_label_60s','') or 'row값'),"window_sec":sec}
    return {"ticker":t,"count":0,"amount":0.0,"buy_ratio":0.0,"label":"체결없음","window_sec":sec}

def _v275_rate(s,sec,key='count'):
    try: return safe_float(s.get(key,0),0)/max(float(sec),1.0)
    except Exception: return 0.0

def _v275_eval(cls,row=None):
    cls=cls if isinstance(cls,dict) else {}; row=row if isinstance(row,dict) else {}
    out={"flow_score":0,"flow_label":"체결흐름 확인중","reason":"","rush":False,"speed_accel":False,"buy_sustain":False,"sell_reversal":False,"high_touch_market_block":False,"flow_bridge_ok":False,"entry_rule":"observe","grade":""}
    try:
        t=_v275_ticker(row,cls); c=_v270_ctx(cls,row) if '_v270_ctx' in globals() else {}
        joined=_v273_join_payload(cls,row) if '_v273_join_payload' in globals() else (str(cls)+str(row))[:1600]
        s5=_v275_ws(t,row,5); s15=_v275_ws(t,row,15); s60=_v275_ws(t,row,60)
        cnt5=int(safe_float(s5.get('count',0),0)); br5=safe_float(s5.get('buy_ratio',0),0); amt5=safe_float(s5.get('amount',0),0)
        cnt15=int(safe_float(s15.get('count',0),0)); br15=safe_float(s15.get('buy_ratio',0),0); amt15=safe_float(s15.get('amount',0),0)
        cnt60=int(safe_float(s60.get('count',c.get('trade_count',0)),0)); br60=max(safe_float(s60.get('buy_ratio',0),0),safe_float(c.get('buy_ratio',0),0)); amt60=max(safe_float(s60.get('amount',0),0),safe_float(c.get('money',0),0))
        high_gap=safe_float(c.get('high_gap',999),999); from_low=safe_float(c.get('from_low',0),0)
        candle_weak=bool(c.get('candle_weak',False)) or any(w in joined for w in ['현재봉 밀림','위꼬리','윗꼬리','막판 밀림'])
        candle_alive=bool(c.get('candle_alive',False)) or any(w in joined for w in ['현재봉 살아남','살아남','아랫꼬리 회복','회복 강함'])
        money_weak=bool(c.get('money_weak',False)) or any(w in joined for w in ['매도우세','매도 우세','반짝/식는','식는중','돈은 있지만 매도우세'])
        high_hold=any(w in joined for w in ['돌파 후 유지','재돌파 유지','유지 확인','고점 돌파 후 유지'])
        high_touch=(0<=high_gap<=V275_HIGH_TOUCH_GAP_PCT) or any(w in joined for w in ['고점 맞닿음','고점 바로 앞','최근30분 고점 바로 근처'])
        rush5=cnt5>=V275_RUSH_5S_MIN_COUNT and br5>=V275_RUSH_5S_MIN_BUY_RATIO and amt5>=V275_RUSH_5S_MIN_AMOUNT
        rush15=cnt15>=V275_RUSH_15S_MIN_COUNT and br15>=V275_RUSH_15S_MIN_BUY_RATIO and amt15>=V275_RUSH_15S_MIN_AMOUNT
        speed=(cnt5>=2 and cnt60>=3 and _v275_rate(s5,5)>=max(_v275_rate(s60,60)*1.8,0.35)) or (amt5>=300000 and amt60>=800000 and _v275_rate(s5,5,'amount')>=max(_v275_rate(s60,60,'amount')*1.8,120000)) or rush5
        sustain=(cnt5<=0 or br5>=62) and (cnt15<=0 or br15>=58) and cnt60>=V275_SUSTAIN_60S_MIN_COUNT and br60>=V275_SUSTAIN_60S_MIN_BUY_RATIO and amt60>=V275_SUSTAIN_60S_MIN_AMOUNT
        sellrev=(cnt15>=4 and 0<br15<=V275_SELL_REVERSAL_15S_BUY_RATIO_MAX and (br60<=V275_SELL_REVERSAL_60S_BUY_RATIO_MAX or candle_weak)) or (cnt5>=2 and 0<br5<=30 and (candle_weak or money_weak)) or (money_weak and cnt60>=5 and 0<br60<=V275_SELL_REVERSAL_60S_BUY_RATIO_MAX)
        score=0; why=[]
        if rush5 or rush15: score+=2; why.append('러시체결')
        if speed: score+=1; why.append('체결속도 증가')
        if sustain: score+=2; why.append('매수우세 유지')
        if candle_alive: score+=1; why.append('현재봉 생존')
        if from_low<=V275_FROM_LOW_MAX_FOR_FLOW_BRIDGE: score+=1; why.append('저점대비 과열 아님')
        if sellrev: score-=3; why.append('매도반전')
        if candle_weak: score-=1; why.append('현재봉 약함')
        label='체결흐름 확인중'
        if sellrev: label='매도반전 주의'
        elif rush5 or rush15: label='러시체결 감지'
        elif sustain: label='매수우세 유지'
        elif speed: label='체결속도 증가'
        elif cnt60<=0: label='체결 표본 없음'
        elif cnt60<3: label='체결 적음'
        bridge=score>=4 and (rush5 or rush15 or sustain) and not sellrev and not candle_weak and from_low<=V275_FROM_LOW_MAX_FOR_FLOW_BRIDGE
        entry='observe'; grade=''
        if bridge:
            if high_touch and not high_hold: entry='breakout_wait_only'; grade='BREAKOUT_WAIT'; bridge=False
            elif high_touch and high_hold: entry='breakout'; grade='BREAKOUT_WAIT'
            else: entry='pullback'; grade='PULLBACK_WAIT'
        out.update({'ticker':t,'flow_score':score,'flow_label':label,'reason':' / '.join(why[:5]) or label,'rush':bool(rush5 or rush15),'rush5':bool(rush5),'rush15':bool(rush15),'speed_accel':bool(speed),'buy_sustain':bool(sustain),'sell_reversal':bool(sellrev),'high_touch_market_block':bool(high_touch and not high_hold),'high_touch':bool(high_touch),'high_hold':bool(high_hold),'flow_bridge_ok':bool(bridge),'entry_rule':entry,'grade':grade,'cnt5':cnt5,'br5':br5,'cnt15':cnt15,'br15':br15,'cnt60':cnt60,'br60':br60})
    except Exception as e:
        try: append_runtime_error_log('v275_order_flow_eval',str(e),exc=e,include_traceback=False)
        except Exception: pass
    return out

