PAPER_V276_START_TS = time.time()
PAPER_V276_STATS = {"protect_v274":0,"protect_v275":0,"pure_cleanup":0,"cancel_candle":0,"cancel_sell":0,"cancel_high":0,"cancel_trade":0,"high_true":0,"high_hold":0,"high_snapshot":0,"high_data":0,"pullback_hint":0,"breakout_bias":0,"last_note":"대기"}

def _v276_inc(k,n=""):
    try:
        if k in PAPER_V276_STATS: PAPER_V276_STATS[k]=int(safe_float(PAPER_V276_STATS.get(k,0),0))+1
        if n: PAPER_V276_STATS["last_note"]=str(n)[:180]
    except Exception: pass

def _v276_text(o):
    try:
        if not isinstance(o,dict): return str(o or "")[:1200]
        vals=[]
        for k in ("ticker","lane","register_reason","close_reason","cleanup_note","note","v270_bucket","v270_reason","v266_bucket","v266_reason","v274_bridge_reason","v275_bridge_reason","signal_decision","decision","grade","signal_grade","original_grade","entry_rule","paper_entry_rule_v259"):
            v=o.get(k,"")
            if v not in (None,""): vals.append(f"{k}={v}")
        rs=o.get("reasons",[])
        if isinstance(rs,list): vals += [str(x) for x in rs[:6]]
        return " / ".join(vals)[:1600]
    except Exception: return ""

def _v276_protected_prepare(o):
    try:
        if not isinstance(o,dict): return (False,"")
        lane=str(o.get("lane","") or "").lower(); t=_v276_text(o).lower()
        grade=str(o.get("grade",o.get("signal_grade",o.get("original_grade",""))) or "").upper()
        er=str(o.get("entry_rule",o.get("paper_entry_rule_v259","") ) or "").lower()
        if lane in {"v274_preview_bridge_prepare","v275_order_flow_prepare"}: return (True,lane)
        if bool(o.get("v274_bridge_ok")) or "v274_preview_bridge_prepare" in t or "v274 미리볼" in t: return (True,"v274_preview_bridge_prepare")
        if bool(o.get("v275_flow_bridge_ok")) or "v275_order_flow_prepare" in t or "체결흐름 브릿지" in t or "v275 체결흐름" in t: return (True,"v275_order_flow_prepare")
        if grade in {"BREAKOUT_WAIT","PULLBACK_WAIT"} and er in {"breakout","pullback"} and ("진입준비" in t or "prepare" in t): return (True,"prepare_wait")
    except Exception: pass
    return (False,"")

def _v276_cleanup_bucket(o):
    t=_v276_text(o)
    if any(w in t for w in ["매도반전","매도우세","식는","sell_reversal"]): return ("cancel_sell","진입준비였지만 매도반전")
    if any(w in t for w in ["현재봉 약함","현재봉 밀림","막판 밀림","위꼬리","윗꼬리","candle_weak"]): return ("cancel_candle","진입준비였지만 현재봉 약화")
    if any(w in t for w in ["고점 맞닿음","고점 바로 앞","고점 유지 실패","high_touch"]): return ("cancel_high","진입준비였지만 고점 유지 실패")
    if any(w in t for w in ["체결0","체결 0","체결 적음","체결 약함","체결 부족"]): return ("cancel_trade","진입준비였지만 체결 약화")
    return ("pure_cleanup","순수 미리볼이라 paper 제외")

