            if prot:
                _v276_inc("protect_v275" if lane=="v275_order_flow_prepare" else "protect_v274", f"prepare 보호 {(obj or {}).get('ticker','?') if isinstance(obj,dict) else '?'}")
                return False
            res=bool(_BASE_V272_PREVIEW_OBJ_V276(obj))
            if res:
                k,n=_v276_cleanup_bucket(obj if isinstance(obj,dict) else {})
