def _v276_pullback_hint(cls,row=None):
    try:
        cls=cls if isinstance(cls,dict) else {}; row=row if isinstance(row,dict) else {}
        c=_v270_ctx(cls,row) if '_v270_ctx' in globals() else {}; joined=_v273_join_payload(cls,row) if '_v273_join_payload' in globals() else (_v276_text(cls)+_v276_text(row))
        hg=safe_float(c.get("high_gap",999),999); fl=safe_float(c.get("from_low",0),0); money=safe_float(c.get("money",0),0); tc=int(safe_float(c.get("trade_count",0),0)); br=safe_float(c.get("buy_ratio",0),0)
        low=any(w in joined for w in ["저점방어","저점높임","재출발","아랫꼬리 회복","눌림 뒤 재출발"])
        flow=bool(cls.get("v275_buy_sustain")) or bool(cls.get("v275_rush_detected")) or (tc>=5 and br>=55) or money>=20000000
        bad=bool(c.get("candle_weak",False)) or any(w in joined for w in ["현재봉 밀림","막판 밀림","위꼬리","윗꼬리"])
        if low and flow and 0.45<=hg<900 and fl<=2.8 and not bad: return True, f"저점방어/눌림 근거 + 고점여유 {hg:.2f}% + 체결유지"
        if str(cls.get("grade","") or "").upper()=="BREAKOUT_WAIT": _v276_inc("breakout_bias", f"돌파대기 쏠림 확인 {cls.get('ticker','?')}")
    except Exception: pass
    return False,""

