def _v277_stats_short_line(label: str, rows: list) -> str:
    try:
        st = _paper_stats_for_rows_v258(rows)
        if st.get("n", 0) <= 0:
            return f"- {label}: 거래 없음"
        pf = safe_float(st.get("profit_factor", 0), 0)
        pf_text = "∞" if pf >= 900 else f"{pf:.2f}"
        return f"- {label}: {st['n']}전 {st['wins']}승 {st['losses']}패 / 승률 {st['win_rate']:.1f}% / 누적 {st['total_pct']:+.2f}% / PF {pf_text}"
    except Exception:
        return f"- {label}: 계산 오류"

def _v277_cancel_reason_top(limit: int = 4):
    try:
        rows = _paper_closed_logs_v258(include_cancelled=True)
        rows = [r for r in rows if str(r.get("status", "")).upper() == "CANCELLED"]
        rows.sort(key=lambda r: safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0), reverse=True)
        counts = {}
        for r in rows[:80]:
            reason = str(r.get("close_reason", "") or "-")
            key = reason
            if "early_pending_cancel" in reason:
                key = "대기 중 신호악화"
            elif "preview_command_only" in reason:
                key = "순수 미리볼 paper 제외"
            elif "entry_precheck" in reason:
                key = "진입직전 힘빠짐"
            elif "chase_over" in reason:
                key = "추격금지 초과"
            elif "v276_prepare_sell" in reason:
                key = "진입준비 후 매도반전"
            elif "v276_prepare_high" in reason:
                key = "진입준비 후 고점유지 실패"
            counts[key] = counts.get(key, 0) + 1
        return sorted(counts.items(), key=lambda x: -x[1])[:max(1, int(limit))]
    except Exception:
        return []

