# ============================================================
# v2.5.280: 시장 캐시 정체 오판 정리 + rank_compare 3분 순위 보정
# - 전략/매수/paper 조건은 변경하지 않는다.
# - /rank_compare 3분은 현재 스냅샷의 change_3 기준으로 즉시 계산한다.
# - 시장 캐시 시간만 오래되고 WS/rank/fast 스냅샷이 최신이면 soft_recover를 억제한다.
# ============================================================
PAPER_V280_START_TS = time.time()
PAPER_V280_STATS = {
    "rank_build": 0, "rank_cache_hit": 0, "rank_rows": 0, "rank_app_rows": 0,
    "rank_3m_rows": 0, "rank_lack_15": 0, "rank_lack_30": 0, "rank_lack_60": 0,
    "rank_build_sec": 0.0, "rank_text_sec": 0.0, "rank_last_note": "대기",
    "market_diag": 0, "soft_suppress": 0, "soft_allow": 0,
    "apparent_stale": 0, "true_stale": 0, "refresh_request": 0,
    "last_market_state": "대기", "last_market_reason": "-", "last_signal_hint": 0,
}
_RANK_COMPARE_V280_CACHE = {"ts": 0.0, "gen": 0, "rank_ts": 0.0, "data": None}
_V280_SOFT_SUPPRESS_LAST_LOG = {"ts": 0.0, "reason": ""}


def _v280_inc(k, note=""):
    try:
        PAPER_V280_STATS[k] = int(safe_float(PAPER_V280_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V280_STATS["rank_last_note"] = str(note)[:160]
    except Exception:
        pass


def _v280_time(k, sec):
    try:
        PAPER_V280_STATS[k] = round(max(0.0, safe_float(sec, 0)), 4)
    except Exception:
        pass


def _v280_key(v):
    try:
        return str(v or "").upper().strip().replace("KRW-", "").replace("/KRW", "")
    except Exception:
        return ""


def _v280_row_ticker(row):
    try:
        row = row if isinstance(row, dict) else {}
        for k in ("ticker", "symbol", "coin", "asset", "market"):
            t = _v280_key(row.get(k, ""))
            if t:
                return t
    except Exception:
        pass
    return ""


def _v280_row_change(row, key):
    try:
        row = row if isinstance(row, dict) else {}
        aliases = {
            "change_3": ["change_3", "chg_3m", "change_3m", "pct_3m", "change3", "chg3"],
            "change_15": ["change_15", "chg_15m", "change_15m", "pct_15m", "change15", "chg15"],
            "change_30": ["change_30", "chg_30m", "change_30m", "pct_30m", "change30", "chg30"],
            "change_60": ["change_60", "chg_60m", "change_60m", "pct_60m", "change_1h", "change60", "chg60"],
        }.get(key, [key])
        for k in aliases:
            if k in row:
                return safe_float(row.get(k, 0), 0)
        if key == "change_3":
            return safe_float(row.get("short_change", row.get("change_pct", 0)), 0)
    except Exception:
        pass
    return 0.0


def _v280_row_money(row):
    try:
        row = row if isinstance(row, dict) else {}
        return safe_float(row.get("turnover", row.get("snapshot_turnover_hint", row.get("turnover_5m", row.get("trade_amount_krw", row.get("acc_trade_value_24h", 0))))), 0)
    except Exception:
        return 0.0


def _v280_row_score(row):
    try:
        row = row if isinstance(row, dict) else {}
        return safe_float(row.get("snapshot_rank_score", row.get("lite_score", row.get("score", row.get("leader_score", 0)))), 0)
    except Exception:
        return 0.0


def _v280_row_sample_age(row):
    try:
        row = row if isinstance(row, dict) else {}
        for k in ("sample_age_sec", "sample_sec", "history_age_sec", "price_history_age_sec", "rank_sample_age_sec", "snapshot_sample_age_sec"):
            if k in row:
                return safe_float(row.get(k, 0), 0)
    except Exception:
        pass
    return None


def _v280_collect_rank_rows(limit=140):
    t0 = time.time()
    by = {}
    def add(row, src=""):
        try:
            if not isinstance(row, dict):
                return
            t = _v280_row_ticker(row)
            if not t:
                return
            x = dict(row)
            if src and not x.get("v280_source"):
                x["v280_source"] = src
            old = by.get(t)
            old_score = _v280_row_score(old or {}) + max(_v280_row_change(old or {}, "change_3"), 0) * 2
            new_score = _v280_row_score(x) + max(_v280_row_change(x, "change_3"), 0) * 2
            if old is None or new_score >= old_score:
                by[t] = x
        except Exception:
            pass
    try:
        rr = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
        if isinstance(rr, list):
            for r in rr:
                add(r, "rank_rows")
    except Exception:
        pass
    try:
        idx = _v278_build_signal_index(False) if "_v278_build_signal_index" in globals() else {}
        if isinstance(idx, dict):
            for r in idx.values():
                add(r, "signal_index")
    except Exception:
        pass
    try:
        snap = globals().get("last_scan_debug_snapshot", [])
        if isinstance(snap, list):
            for r in snap:
                add(r, "scan_snapshot")
    except Exception:
        pass
    try:
        if len(by) < 20 and "get_light_snapshot_rank_rows" in globals():
            for r in list(get_light_snapshot_rank_rows(limit=min(80, max(20, int(limit or 80))), min_move_pct=0.0) or []):
                add(r, "light_snapshot")
    except Exception:
        pass
    rows = list(by.values())
    rows.sort(key=lambda r: (_v280_row_score(r), _v280_row_change(r, "change_3"), _v280_row_money(r)), reverse=True)
    _v280_time("rank_build_sec", time.time() - t0)
    PAPER_V280_STATS["rank_rows"] = len(rows)
    return rows[:max(1, int(limit or 140))]


def _v280_sample_ok(row, seconds, key):
    try:
        val = _v280_row_change(row, key)
        if seconds <= 180:
            return True, False
        sample_age = _v280_row_sample_age(row)
        if sample_age is not None:
            need = max(120.0, float(seconds) * 0.70)
            return sample_age >= need, sample_age < need
        if abs(val) <= 1e-9:
            return False, True
        return True, False
    except Exception:
        return True, False


def _v280_build_compare_data(force=False):
    t0 = time.time()
    try:
        gen = int(safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION", 0), 0))
        rank_ts = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS", 0), 0)
        c = _RANK_COMPARE_V280_CACHE
        if (not force) and isinstance(c.get("data"), dict) and c.get("gen") == gen and abs(safe_float(c.get("rank_ts", 0), 0) - rank_ts) < 0.001 and time.time() - safe_float(c.get("ts", 0), 0) <= 6.0:
            _v280_inc("rank_cache_hit", "rank_compare cache hit")
            return c.get("data")
        rows = _v280_collect_rank_rows(limit=160)
        specs = [("3분", "change_3", 180), ("15분", "change_15", 900), ("30분", "change_30", 1800), ("1시간", "change_60", 3600)]
        app = {}; app_counts = {}; insufficient = {}; row_by_ticker = {}
        for r in rows:
            t = _v280_row_ticker(r)
            if t:
                row_by_ticker[t] = r
        for label, key, seconds in specs:
            picked = []; lack = 0
            for r in rows:
                t = _v280_row_ticker(r)
                if not t:
                    continue
                ok, is_lack = _v280_sample_ok(r, seconds, key)
                if not ok:
                    if is_lack:
                        lack += 1
                    continue
                val = _v280_row_change(r, key)
                if val <= 0.0:
                    continue
                picked.append((val, _v280_row_score(r), _v280_row_money(r), t, r))
            picked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
            app[label] = picked[:10]
            insufficient[label] = lack
            for rank, item in enumerate(picked[:10], start=1):
                val, _, _, t, _ = item
                d = app_counts.setdefault(t, {"count": 0, "frames": [], "best_rank": 99, "best_change": -999})
                d["count"] += 1
                d["frames"].append(label)
                d["best_rank"] = min(int(d.get("best_rank", 99)), rank)
                d["best_change"] = max(safe_float(d.get("best_change", -999), -999), safe_float(val, 0))
        strategy_rows = []
        try:
            rr = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
            if isinstance(rr, list) and rr:
                strategy_rows = [r for r in rr if isinstance(r, dict) and _v280_row_ticker(r)][:8]
        except Exception:
            strategy_rows = []
        if not strategy_rows:
            strategy_rows = rows[:8]
        strategy = [_v280_row_ticker(r) for r in strategy_rows if _v280_row_ticker(r)]
        app_order = []
        for label, _, _ in specs:
            for item in app.get(label, [])[:8]:
                t = item[3]
                if t and t not in app_order:
                    app_order.append(t)
        overlap = [t for t in strategy if t in app_order]
        app_only = [t for t in app_order if t not in strategy]
        bot_only = [t for t in strategy if t not in app_order]
        repeated = [t for t, info in sorted(app_counts.items(), key=lambda kv: (kv[1].get("count", 0), -kv[1].get("best_rank", 99), kv[1].get("best_change", 0)), reverse=True) if int(info.get("count", 0)) >= 2]
        data = {"rows": rows, "row_by_ticker": row_by_ticker, "app": app, "app_counts": app_counts, "insufficient": insufficient, "strategy": strategy, "strategy_rows": strategy_rows, "app_order": app_order, "overlap": overlap, "app_only": app_only, "bot_only": bot_only, "repeated": repeated, "created_ts": time.time(), "build_sec": time.time() - t0}
        _RANK_COMPARE_V280_CACHE.update({"ts": time.time(), "gen": gen, "rank_ts": rank_ts, "data": data})
        PAPER_V280_STATS.update({"rank_app_rows": len(app_order), "rank_3m_rows": len(app.get("3분", []) or []), "rank_lack_15": int(insufficient.get("15분", 0)), "rank_lack_30": int(insufficient.get("30분", 0)), "rank_lack_60": int(insufficient.get("1시간", 0)), "rank_build_sec": round(time.time() - t0, 4)})
        PAPER_V279_STATS.update({"app_rows": len(app_order), "strategy_rows": len(strategy), "overlap": len(overlap), "app_only": len(app_only), "bot_only": len(bot_only), "repeat_top": len(repeated), "last_total_sec": round(time.time() - t0, 4)})
        _v280_inc("rank_build", f"v280 rows {len(rows)} / 3m {len(app.get('3분', []) or [])}")
        return data
    except Exception as e:
        try:
            append_runtime_error_log("rank_compare_v280", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {"rows": [], "row_by_ticker": {}, "app": {}, "app_counts": {}, "insufficient": {}, "strategy": [], "strategy_rows": [], "app_order": [], "overlap": [], "app_only": [], "bot_only": [], "repeated": [], "created_ts": time.time(), "build_sec": time.time() - t0}


def _v280_format_app_item(t, info=None):
    try:
        frames = "/".join((info or {}).get("frames", [])[:4]) if isinstance(info, dict) else ""
        best = safe_float((info or {}).get("best_change", 0), 0) if isinstance(info, dict) else 0
        return f"{t} {best:+.2f}%" + (f"·{frames}" if frames else "") if best > 0 else str(t)
    except Exception:
        return str(t)


def build_rank_compare_text_v279(args=None, top_n: int = 5):
    t0 = time.time()
    _v279_inc("compare")
    data = _v280_build_compare_data(force=False)
    try:
        registered, tried = _v279_maybe_register_app_watch(data)
    except Exception:
        registered, tried = (0, 0)
    app = data.get("app") or {}; counts = data.get("app_counts") or {}; lack = data.get("insufficient") or {}
    lines = [
        "📈 순위 비교 /rank_compare",
        "- 목적: 앱식 상승률 순위와 우리 봇 전략 순위를 비교해서 놓침을 찾는 용도",
        "- 바로 매수/paper 등록 아님. 앱식 반복상위는 내부감시로만 추적",
        f"- 기준: 저장 스냅샷 / 생성 {format_elapsed_text(time.time()-safe_float(data.get('created_ts',time.time()),time.time()))} 전 / 소요 {safe_float(data.get('build_sec',0),0):.3f}s",
        "",
        "[앱식 상승률 TOP]",
    ]
    for label in ["3분", "15분", "30분", "1시간"]:
        bits = []
        for val, score, money, t, row in list(app.get(label) or [])[:max(1, int(top_n))]:
            item = f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money, 0) >= 100_000_000:
                try:
                    item += f"·{format_money_compact_amount_krw(money)}"
                except Exception:
                    pass
            bits.append(item)
        lack_n = int(safe_float(lack.get(label, 0), 0))
        suffix = f" / 표본부족 {lack_n}개" if lack_n and label != "3분" else ""
        empty = "계산 가능한 상승 없음" if label == "3분" else "표본부족/상승 없음"
        lines.append(f"- {label}: " + (_v279_join(bits, limit=top_n, empty=empty) + suffix))
    strategy = data.get("strategy") or []
    overlap = data.get("overlap") or []; app_only = data.get("app_only") or []; bot_only = data.get("bot_only") or []; repeated = data.get("repeated") or []
    app_only_fmt = [_v280_format_app_item(t, counts.get(t)) for t in app_only]
    repeated_fmt = [_v280_format_app_item(t, counts.get(t)) for t in repeated]
    lines += [
        "", "[우리 봇 전략 순위 TOP]", "- " + _v279_join(strategy, limit=8, empty="없음"),
        "", "[비교 결과]",
        "- 겹침: " + _v279_join(overlap, limit=8, empty="없음"),
        "- 앱식 only 놓침후보: " + _v279_join(app_only_fmt, limit=10, empty="없음"),
        "- 봇 only 단독후보: " + _v279_join(bot_only, limit=10, empty="없음"),
        "- 앱식 반복상위: " + _v279_join(repeated_fmt, limit=8, empty="없음"),
        f"- 내부감시 등록: {registered}/{tried} / 푸시·paper 자동등록 없음",
        "", "[판단법]",
        "- 겹침 후보: 우선 검토",
        "- 앱식 only: 봇 후보소스 놓침인지, 일부러 탈락한 건지 확인",
        "- 봇 only: 앱보다 빠른 초입인지 잡음인지 확인",
    ]
    sec = time.time() - t0
    PAPER_V279_STATS["last_total_sec"] = round(sec, 4)
    _v280_time("rank_text_sec", sec)
    return "\n".join(lines).strip()


def _v279_build_compare_data(force=False):
    return _v280_build_compare_data(force=force)


def _v279_app_signal_note(ticker):
    try:
        t = _v280_key(ticker)
        if not t:
            return ""
        data = _v280_build_compare_data(force=False)
        info = (data.get("app_counts") or {}).get(t)
        if not isinstance(info, dict):
            return ""
        PAPER_V279_STATS["signal_app_hint"] = int(safe_float(PAPER_V279_STATS.get("signal_app_hint", 0), 0)) + 1
        PAPER_V280_STATS["last_signal_hint"] = int(safe_float(PAPER_V280_STATS.get("last_signal_hint", 0), 0)) + 1
        frames = "/".join(info.get("frames", [])[:4])
        best = safe_float(info.get("best_change", 0), 0)
        return f"- 앱식순위: {frames or '상위권'} / 최고 {best:+.2f}% / 비교: /rank_compare"
    except Exception:
        return ""


def _v280_ws_age(kind="ticker"):
    try:
        if kind == "trade" and "get_ws_trade_status_snapshot" in globals():
            st = get_ws_trade_status_snapshot()
        elif "get_ws_ticker_status_snapshot" in globals():
            st = get_ws_ticker_status_snapshot()
        else:
            return None
        age = st.get("last_msg_age_sec")
        return None if age is None else int(safe_float(age, 999999))
    except Exception:
        return None


def _v280_rank_age(now_ts=None):
    try:
        now_ts = safe_float(now_ts, time.time())
        ts = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS", 0), 0)
        if ts <= 0:
            try:
                with COMMAND_DISPLAY_CACHE_LOCK:
                    ts = safe_float((COMMAND_DISPLAY_CACHE.get("rank_short") or {}).get("created_ts", 0), 0)
            except Exception:
                ts = 0
        return int(max(0, now_ts - ts)) if ts > 0 else None
    except Exception:
        return None


def _v280_market_cache_diagnosis(now_ts=None, base_info=None):
    now_ts = safe_float(now_ts, time.time())
    try:
        info = dict(base_info or (_V280_BASE_SCAN_HEALTH(now_ts) if "_V280_BASE_SCAN_HEALTH" in globals() else {}))
    except Exception:
        info = {}
    try:
        fast = get_fast_scan_state(now_ts) if "get_fast_scan_state" in globals() else {}
    except Exception:
        fast = {}
    try:
        refresh = get_market_refresh_status(now_ts) if "get_market_refresh_status" in globals() else {}
    except Exception:
        refresh = {}
    cache_age = info.get("cache_age")
    snap_age = info.get("snapshot_age")
    fast_age = fast.get("age_sec")
    fast_cache_age = fast.get("cache_age")
    rank_age = _v280_rank_age(now_ts)
    ws_ticker_age = _v280_ws_age("ticker")
    ws_trade_age = _v280_ws_age("trade")
    stage = str(info.get("stage", "") or "")
    ws_ok = (ws_ticker_age is not None and ws_ticker_age <= 10) or (ws_trade_age is not None and ws_trade_age <= 10)
    rank_ok = rank_age is not None and rank_age <= 20
    fast_ok = fast_age is not None and safe_float(fast_age, 999999) <= 30
    snap_ok = snap_age is not None and safe_float(snap_age, 999999) <= 30
    refresh_stuck = bool(refresh.get("in_progress")) and safe_float(refresh.get("age_sec", 0), 0) >= 90
    cache_old = cache_age is not None and safe_float(cache_age, 0) >= SCAN_CACHE_HARD_RESET_SEC
    apparent = bool(cache_old and (ws_ok or rank_ok or fast_ok or snap_ok) and not refresh_stuck)
    true_stale = bool(cache_old and not (ws_ok or rank_ok or fast_ok or snap_ok) and (refresh_stuck or safe_float(cache_age, 0) >= max(SCAN_CACHE_HARD_RESET_SEC * 2, 120)))
    if apparent:
        state = "표시상 정체"; reason = "시장 캐시 시간만 오래됨 / WS·순위·후보 스냅샷 중 하나는 최신"
    elif true_stale:
        state = "진짜 정체"; reason = "시장 캐시·스냅샷·WS/순위가 함께 늦음"
    elif cache_old:
        state = "확인 필요"; reason = "시장 캐시 오래됨 / 복합 상태 확인 중"
    else:
        state = "정상권"; reason = "시장 캐시 정체 아님"
    diag = {"state": state, "reason": reason, "apparent": apparent, "true_stale": true_stale, "cache_age": cache_age, "snapshot_age": snap_age, "fast_age": fast_age, "fast_cache_age": fast_cache_age, "rank_age": rank_age, "ws_ticker_age": ws_ticker_age, "ws_trade_age": ws_trade_age, "refresh_age": refresh.get("age_sec"), "refresh_in_progress": bool(refresh.get("in_progress")), "stage": stage}
    PAPER_V280_STATS["last_market_state"] = state
    PAPER_V280_STATS["last_market_reason"] = reason
    _v280_inc("market_diag")
    if apparent:
        _v280_inc("apparent_stale")
    if true_stale:
        _v280_inc("true_stale")
    return diag

