# ============================================================
# v2.5.282 - 전체 코인 기반 앱식 랭크 재구성
# - 기존 /rank_compare가 이미 필터링된 전략 후보 row 안에서만 앱식 순위를 계산하던 문제 보정
# - LIGHT_SNAPSHOT_HISTORY 전체 티커를 직접 훑어 1분/3분/15분/30분/1시간 앱식 상승률을 계산
# - 앱식 순위는 매수/paper 신호가 아니라 탐색 놓침 검증용
# ============================================================
PAPER_V282_START_TS = time.time()
PAPER_V282_STATS = {
    "build": 0,
    "compare": 0,
    "cache_hit": 0,
    "full_history_tickers": 0,
    "fresh_tickers": 0,
    "app_1m": 0,
    "app_3m": 0,
    "app_15m": 0,
    "app_30m": 0,
    "app_60m": 0,
    "lack_1m": 0,
    "lack_3m": 0,
    "lack_15m": 0,
    "lack_30m": 0,
    "lack_60m": 0,
    "strategy_rows": 0,
    "overlap": 0,
    "app_only": 0,
    "bot_only": 0,
    "early_both": 0,
    "one_min_only": 0,
    "repeat_top": 0,
    "internal_watch_try": 0,
    "internal_watch_registered": 0,
    "signal_hint": 0,
    "last_build_sec": 0.0,
    "last_text_sec": 0.0,
    "last_total_sec": 0.0,
    "last_note": "",
}
_RANK_COMPARE_V282_CACHE = {"ts": 0.0, "gen": 0, "rank_ts": 0.0, "history_count": 0, "data": None}


def _v282_inc(k, note=""):
    try:
        PAPER_V282_STATS[k] = int(safe_float(PAPER_V282_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V282_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v282_key(ticker):
    try:
        raw = str(ticker or "").upper().strip()
        if raw.startswith("KRW-"):
            raw = raw.split("-", 1)[1]
        if raw.endswith("_KRW"):
            raw = raw[:-4]
        if raw.endswith("-KRW"):
            raw = raw.split("-", 1)[0]
        return raw
    except Exception:
        return str(ticker or "").upper().strip()


def _v282_money(row):
    try:
        if not isinstance(row, dict):
            return 0.0
        vals = [
            row.get("turnover_5m"), row.get("turnover"), row.get("turnover_recent_3m"),
            row.get("turnover_recent_1m"), row.get("snapshot_turnover_hint"), row.get("money"),
        ]
        vals.append((row.get("pre_alert_snapshot") or {}).get("turnover_5m") if isinstance(row.get("pre_alert_snapshot"), dict) else 0)
        return max([safe_float(v, 0) for v in vals] or [0.0])
    except Exception:
        return 0.0


def _v282_strategy_score(row):
    try:
        if not isinstance(row, dict):
            return 0.0
        return max(
            safe_float(row.get("snapshot_rank_score", 0), 0),
            safe_float(row.get("score", 0), 0),
            safe_float(row.get("leader_score", 0), 0),
            safe_float(row.get("total_score", 0), 0),
        )
    except Exception:
        return 0.0


def _v282_snapshot_change_info_from_rows(rows, seconds, current_price, now_ts=None):
    """전체 앱식 랭크용. 실제 해당 시간대 표본이 있을 때만 ready=True."""
    try:
        now_ts = safe_float(now_ts, time.time())
        current_price = safe_float(current_price, 0)
        out = {"value": 0.0, "ready": False, "base_age_sec": 0.0, "base_price": 0.0}
        if not rows or current_price <= 0:
            return out
        rows2 = [r for r in list(rows or []) if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
        if not rows2:
            return out
        rows2.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
        target_ts = now_ts - int(seconds)
        candidate = None
        for r in rows2:
            if safe_float(r.get("ts", 0), 0) <= target_ts:
                candidate = r
            else:
                break
        if candidate is None:
            # 아직 해당 시간대까지 과거 표본이 없음. 1분/3분 값을 장기 구간에 복사하지 않는다.
            first = rows2[0]
            base_age = max(0.0, now_ts - safe_float(first.get("ts", 0), 0))
            return {"value": 0.0, "ready": False, "base_age_sec": round(base_age, 1), "base_price": safe_float(first.get("price", 0), 0)}
        base = safe_float(candidate.get("price", 0), 0)
        base_ts = safe_float(candidate.get("ts", 0), 0)
        if base <= 0 or base_ts <= 0:
            return out
        age = max(0.0, now_ts - base_ts)
        # 앱식 비교용은 1분/3분은 충분히 빠르게 열고, 장기 구간은 80% 이상 채워졌을 때만 인정.
        min_age = max(20.0, int(seconds) * (0.70 if int(seconds) <= 180 else 0.80))
        ready = bool(age >= min_age)
        val = ((current_price - base) / base) * 100.0
        return {"value": round(val, 2), "ready": ready, "base_age_sec": round(age, 1), "base_price": base}
    except Exception:
        return {"value": 0.0, "ready": False, "base_age_sec": 0.0, "base_price": 0.0}


def _v282_full_history_rows(now_ts=None, max_tickers=None):
    """LIGHT_SNAPSHOT_HISTORY 전체 티커를 앱식 랭크용 row로 변환한다.

    핵심: 전략 후보 row가 아니라 전체 현재가 스냅샷 히스토리를 직접 사용한다.
    """
    now_ts = safe_float(now_ts, time.time())
    max_tickers = int(safe_float(max_tickers if max_tickers is not None else globals().get("RANK_COMPARE_FULL_HISTORY_MAX_TICKERS", 1000), 1000))
    out = []
    full_count = 0
    fresh_count = 0
    try:
        ttl = safe_float(globals().get("LIGHT_SNAPSHOT_TTL_SEC", 900), 900)
        with LIGHT_SNAPSHOT_LOCK:
            items = list(LIGHT_SNAPSHOT_HISTORY.items()) if isinstance(LIGHT_SNAPSHOT_HISTORY, dict) else []
        full_count = len(items)
        for tk, rows in items[:max(1, max_tickers)]:
            ticker = _v282_key(tk)
            if not ticker or ticker == "BTC" or is_watch_excluded_ticker(ticker):
                continue
            if not isinstance(rows, list) or not rows:
                continue
            valid = [r for r in rows if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
            if not valid:
                continue
            valid.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
            last = valid[-1]
            last_ts = safe_float(last.get("ts", 0), 0)
            price = safe_float(last.get("price", 0), 0)
            if price <= 0 or last_ts <= 0 or now_ts - last_ts > ttl:
                continue
            fresh_count += 1
            info_1 = _v282_snapshot_change_info_from_rows(valid, 60, price, now_ts)
            info_3 = _v282_snapshot_change_info_from_rows(valid, 180, price, now_ts)
            info_15 = _v282_snapshot_change_info_from_rows(valid, 900, price, now_ts)
            info_30 = _v282_snapshot_change_info_from_rows(valid, 1800, price, now_ts)
            info_60 = _v282_snapshot_change_info_from_rows(valid, 3600, price, now_ts)
            money = 0.0
            try:
                # 최근 5분 안에 기록된 turnover_hint 최대값. 없으면 0으로 둔다.
                recent = [safe_float(r.get("turnover_hint", 0), 0) for r in valid if now_ts - safe_float(r.get("ts", 0), 0) <= 300]
                money = max(recent or [0.0])
            except Exception:
                money = 0.0
            row = {
                "ticker": ticker,
                "price": price,
                "current_price": price,
                "change_1": safe_float(info_1.get("value", 0), 0),
                "change_3": safe_float(info_3.get("value", 0), 0),
                "change_15": safe_float(info_15.get("value", 0), 0),
                "change_30": safe_float(info_30.get("value", 0), 0),
                "change_60": safe_float(info_60.get("value", 0), 0),
                "change_1_ready": bool(info_1.get("ready", False)),
                "change_3_ready": bool(info_3.get("ready", False)),
                "change_15_ready": bool(info_15.get("ready", False)),
                "change_30_ready": bool(info_30.get("ready", False)),
                "change_60_ready": bool(info_60.get("ready", False)),
                "change_1_base_age_sec": safe_float(info_1.get("base_age_sec", 0), 0),
                "change_3_base_age_sec": safe_float(info_3.get("base_age_sec", 0), 0),
                "change_15_base_age_sec": safe_float(info_15.get("base_age_sec", 0), 0),
                "change_30_base_age_sec": safe_float(info_30.get("base_age_sec", 0), 0),
                "change_60_base_age_sec": safe_float(info_60.get("base_age_sec", 0), 0),
                "turnover_5m": money,
                "turnover": money,
                "snapshot_rows": len(valid),
                "snapshot_span_sec": round(max(0.0, safe_float(valid[-1].get("ts", 0), 0) - safe_float(valid[0].get("ts", 0), 0)), 1),
                "snapshot_rank_score": max(safe_float(info_1.get("value", 0), 0), safe_float(info_3.get("value", 0), 0), 0) * 2.0 + min(max(money / 100_000_000, 0), 5.0),
                "source": "full_light_snapshot_app_rank",
                "cache_source": "full_light_snapshot_history",
            }
            out.append(row)
        PAPER_V282_STATS["full_history_tickers"] = full_count
        PAPER_V282_STATS["fresh_tickers"] = fresh_count
        return out
    except Exception as e:
        try:
            append_runtime_error_log("rank_compare_v282_full_history", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        PAPER_V282_STATS["full_history_tickers"] = full_count
        PAPER_V282_STATS["fresh_tickers"] = fresh_count
        return out


def _v282_get_strategy_rows():
    try:
        rows = list(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", []) or [])
        rows = [r for r in rows if isinstance(r, dict) and _v282_key(r.get("ticker", ""))]
        if rows:
            return rows[:8]
    except Exception:
        pass
    try:
        data = _v278_get_signal_index() if '_v278_get_signal_index' in globals() else ({}, {})
        idx = data[0] if isinstance(data, tuple) else data
        if isinstance(idx, dict) and idx:
            rows = [dict(v) for v in idx.values() if isinstance(v, dict)]
            rows.sort(key=lambda r: _v282_strategy_score(r), reverse=True)
            return rows[:8]
    except Exception:
        pass
    return []


def _v282_build_compare_data(force=False):
    t0 = time.time()
    try:
        gen = int(safe_float(globals().get("COMMAND_DISPLAY_CACHE_GEN", 0), 0))
        rank_ts = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_TS", 0), 0)
        with LIGHT_SNAPSHOT_LOCK:
            hist_count = len(LIGHT_SNAPSHOT_HISTORY) if isinstance(LIGHT_SNAPSHOT_HISTORY, dict) else 0
        c = _RANK_COMPARE_V282_CACHE
        if (not force) and isinstance(c.get("data"), dict):
            if c.get("gen") == gen and c.get("history_count") == hist_count and time.time() - safe_float(c.get("ts", 0), 0) <= 3.0:
                _v282_inc("cache_hit", "v282 full app rank cache hit")
                return c.get("data")
        _v282_inc("build", "v282 full app rank build")
        rows = _v282_full_history_rows(now_ts=time.time())
        row_by = {_v282_key(r.get("ticker")): r for r in rows if isinstance(r, dict) and _v282_key(r.get("ticker"))}
        specs = [
            ("1분", "change_1", "change_1_ready"),
            ("3분", "change_3", "change_3_ready"),
            ("15분", "change_15", "change_15_ready"),
            ("30분", "change_30", "change_30_ready"),
            ("1시간", "change_60", "change_60_ready"),
        ]
        app = {}
        insufficient = {}
        app_counts = {}
        for label, key, ready_key in specs:
            picked = []
            lack = 0
            for r in rows:
                if not bool(r.get(ready_key, False)):
                    lack += 1
                    continue
                val = safe_float(r.get(key, 0), 0)
                if val <= 0:
                    continue
                t = _v282_key(r.get("ticker"))
                if not t:
                    continue
                money = _v282_money(r)
                picked.append((val, _v282_strategy_score(r), money, t, r))
            picked.sort(key=lambda x: (x[0], x[2], x[1]), reverse=True)
            app[label] = picked[:10]
            insufficient[label] = lack
            for rank, item in enumerate(picked[:10], start=1):
                val, _score, _money, t, _row = item
                info = app_counts.setdefault(t, {"count": 0, "frames": [], "best_rank": 99, "best_change": -999.0})
                info["count"] += 1
                info["frames"].append(label)
                info["best_rank"] = min(int(info.get("best_rank", 99)), rank)
                info["best_change"] = max(safe_float(info.get("best_change", -999), -999), safe_float(val, 0))
        strategy_rows = _v282_get_strategy_rows()
        strategy = [_v282_key(r.get("ticker")) for r in strategy_rows if _v282_key(r.get("ticker"))]
        app_order = []
        for label, _key, _ready in specs:
            for item in app.get(label, [])[:8]:
                t = item[3]
                if t and t not in app_order:
                    app_order.append(t)
        overlap = [t for t in strategy if t in app_order]
        app_only = [t for t in app_order if t not in strategy]
        bot_only = [t for t in strategy if t not in app_order]
        set1 = {item[3] for item in app.get("1분", [])[:10]}
        set3 = {item[3] for item in app.get("3분", [])[:10]}
        early_both = [t for t in app_order if t in set1 and t in set3]
        one_min_only = [t for t in app_order if t in set1 and t not in set3]
        repeated = [t for t, info in sorted(app_counts.items(), key=lambda kv: (kv[1].get("count", 0), -kv[1].get("best_rank", 99), kv[1].get("best_change", 0)), reverse=True) if int(info.get("count", 0)) >= 2]
        sample_excluded = sum(int(safe_float(insufficient.get(k, 0), 0)) for k in ["15분", "30분", "1시간"])
        data = {
            "rows": rows,
            "row_by_ticker": row_by,
            "app": app,
            "app_counts": app_counts,
            "insufficient": insufficient,
            "strategy": strategy,
            "strategy_rows": strategy_rows,
            "app_order": app_order,
            "overlap": overlap,
            "app_only": app_only,
            "bot_only": bot_only,
            "repeated": repeated,
            "early_both": early_both,
            "one_min_only": one_min_only,
            "sample_excluded": sample_excluded,
            "created_ts": time.time(),
            "build_sec": time.time() - t0,
            "source": "full_light_snapshot_history_v282",
        }
        _RANK_COMPARE_V282_CACHE.update({"ts": time.time(), "gen": gen, "rank_ts": rank_ts, "history_count": hist_count, "data": data})
        PAPER_V282_STATS.update({
            "app_1m": len(app.get("1분", []) or []),
            "app_3m": len(app.get("3분", []) or []),
            "app_15m": len(app.get("15분", []) or []),
            "app_30m": len(app.get("30분", []) or []),
            "app_60m": len(app.get("1시간", []) or []),
            "lack_1m": int(insufficient.get("1분", 0)),
            "lack_3m": int(insufficient.get("3분", 0)),
            "lack_15m": int(insufficient.get("15분", 0)),
            "lack_30m": int(insufficient.get("30분", 0)),
            "lack_60m": int(insufficient.get("1시간", 0)),
            "strategy_rows": len(strategy),
            "overlap": len(overlap),
            "app_only": len(app_only),
            "bot_only": len(bot_only),
            "early_both": len(early_both),
            "one_min_only": len(one_min_only),
            "repeat_top": len(repeated),
            "last_build_sec": round(time.time() - t0, 4),
            "last_total_sec": round(time.time() - t0, 4),
        })
        # 이전 v279~v281 카운터도 /cache_status 호환용으로 최신화
        try:
            PAPER_V279_STATS.update({"app_rows": len(app_order), "strategy_rows": len(strategy), "overlap": len(overlap), "app_only": len(app_only), "bot_only": len(bot_only), "repeat_top": len(repeated), "last_total_sec": round(time.time() - t0, 4)})
            PAPER_V281_STATS.update({"rows": len(rows), "rank_1m_rows": len(app.get("1분", []) or []), "rank_3m_rows": len(app.get("3분", []) or []), "lack_15": int(insufficient.get("15분", 0)), "lack_30": int(insufficient.get("30분", 0)), "lack_60": int(insufficient.get("1시간", 0)), "early_both": len(early_both), "one_min_only": len(one_min_only), "repeat_top": len(repeated), "sample_excluded": sample_excluded, "last_build_sec": round(time.time() - t0, 4)})
        except Exception:
            pass
        return data
    except Exception as e:
        try:
            append_runtime_error_log("rank_compare_v282", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {"rows": [], "row_by_ticker": {}, "app": {}, "app_counts": {}, "insufficient": {}, "strategy": [], "strategy_rows": [], "app_order": [], "overlap": [], "app_only": [], "bot_only": [], "repeated": [], "early_both": [], "one_min_only": [], "sample_excluded": 0, "created_ts": time.time(), "build_sec": time.time() - t0, "source": "error"}


def _v282_join(items, limit=8, empty="없음"):
    try:
        arr = [str(x) for x in list(items or []) if str(x).strip()]
        if not arr:
            return empty
        more = len(arr) - int(limit)
        s = ", ".join(arr[:int(limit)])
        if more > 0:
            s += f" 외 {more}개"
        return s
    except Exception:
        return empty


def _v282_format_app_item(t, info=None):
    try:
        frames = "/".join((info or {}).get("frames", [])[:5]) if isinstance(info, dict) else ""
        best = safe_float((info or {}).get("best_change", 0), 0) if isinstance(info, dict) else 0
        return f"{t} {best:+.2f}%" + (f"·{frames}" if frames else "") if best > 0 else str(t)
    except Exception:
        return str(t)


def _v282_maybe_register_full_app_watch(data):
    try:
        repeated = list((data or {}).get("repeated") or [])
        strategy = set((data or {}).get("strategy") or [])
        row_by = (data or {}).get("row_by_ticker") or {}
        registered = 0
        tried = 0
        for t in repeated[:6]:
            if t in strategy:
                continue
            row = dict(row_by.get(t) or {})
            if not row:
                continue
            row["rank_precision_watch"] = True
            row["rank_watch_action"] = "전체 앱식 반복상위 감시"
            row["primary_reason"] = "전체 앱식 상승률 반복 상위 / 봇 전략순위 미노출"
            row["label_text"] = "전체 앱식 반복상위"
            row["one_liner"] = "전체 코인 상승률에는 반복으로 보이지만 전략 순위에는 약한 후보. 바로 매수 금지, 내부감시로 결과만 확인."
            row["alert_bucket"] = "internal_watch"
            row["bucket"] = "internal_watch"
            tried += 1
            PAPER_V282_STATS["internal_watch_try"] = int(safe_float(PAPER_V282_STATS.get("internal_watch_try", 0), 0)) + 1
            ok = False
            try:
                ok = bool(register_rank_precision_internal_watch(row, now_ts=time.time(), reason="full_app_rank_compare_v282"))
            except Exception:
                ok = False
            if ok:
                registered += 1
                PAPER_V282_STATS["internal_watch_registered"] = int(safe_float(PAPER_V282_STATS.get("internal_watch_registered", 0), 0)) + 1
        if tried:
            PAPER_V282_STATS["last_note"] = f"전체 앱식 반복상위 내부감시 {registered}/{tried}"
        return registered, tried
    except Exception:
        return 0, 0


def build_rank_compare_text_v279(args=None, top_n: int = 10):
    t0 = time.time()
    _v282_inc("compare")
    data = _v282_build_compare_data(force=False)
    try:
        registered, tried = _v282_maybe_register_full_app_watch(data)
    except Exception:
        registered, tried = (0, 0)
    app = data.get("app") or {}
    counts = data.get("app_counts") or {}
    lack = data.get("insufficient") or {}
    lines = [
        "📈 순위 비교 /rank_compare",
        "- 목적: 전체 코인 앱식 상승률 순위와 우리 봇 전략 순위를 비교해서 놓침을 찾는 용도",
        "- 1분은 초입 감지용. 바로 매수/paper 등록 아님",
        f"- 기준: 전체 light snapshot 히스토리 / 생성 {format_elapsed_text(time.time()-safe_float(data.get('created_ts', time.time()), time.time()))} 전 / 소요 {safe_float(data.get('build_sec',0),0):.3f}s",
        "",
        "[전체 앱식 상승률 TOP]",
    ]
    for label in ["1분", "3분", "15분", "30분", "1시간"]:
        bits = []
        for val, _score, money, t, row in list(app.get(label) or [])[:max(1, int(top_n))]:
            item = f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money, 0) >= 100_000_000:
                try:
                    item += f"·{format_money_compact_amount_krw(money)}"
                except Exception:
                    pass
            bits.append(item)
        lack_n = int(safe_float(lack.get(label, 0), 0))
        if label in {"15분", "30분", "1시간"} and not bits and lack_n:
            lines.append(f"- {label}: 표본부족 / 계산 대기 ({lack_n}개)")
            continue
        suffix = f" / 표본부족 {lack_n}개" if lack_n and label in {"15분", "30분", "1시간"} else ""
        lines.append(f"- {label}: " + (_v282_join(bits, limit=top_n, empty="계산 가능한 상승 없음") + suffix))
    strategy = data.get("strategy") or []
    overlap = data.get("overlap") or []
    app_only = data.get("app_only") or []
    bot_only = data.get("bot_only") or []
    repeated = data.get("repeated") or []
    early_both = data.get("early_both") or []
    one_min_only = data.get("one_min_only") or []
    app_only_fmt = [_v282_format_app_item(t, counts.get(t)) for t in app_only]
    repeated_fmt = [_v282_format_app_item(t, counts.get(t)) for t in repeated]
    early_fmt = [_v282_format_app_item(t, counts.get(t)) for t in early_both]
    one_min_fmt = [_v282_format_app_item(t, counts.get(t)) for t in one_min_only]
    lines += [
        "",
        "[초입 후보]",
        "- 1분+3분 동시: " + _v282_join(early_fmt, limit=10, empty="없음"),
        "- 1분만 급등: " + _v282_join(one_min_fmt, limit=10, empty="없음") + (" / 3분 유지 확인 필요" if one_min_only else ""),
        "",
        "[우리 봇 전략 순위 TOP]",
        "- " + _v282_join(strategy, limit=8, empty="없음"),
        "",
        "[비교 결과]",
        "- 겹침: " + _v282_join(overlap, limit=8, empty="없음"),
        "- 앱식 only 놓침후보: " + _v282_join(app_only_fmt, limit=12, empty="없음"),
        "- 봇 only 단독후보: " + _v282_join(bot_only, limit=10, empty="없음"),
        "- 앱식 반복상위: " + _v282_join(repeated_fmt, limit=10, empty="없음"),
        f"- 전체 히스토리: {PAPER_V282_STATS.get('fresh_tickers',0)}/{PAPER_V282_STATS.get('full_history_tickers',0)}개 / 내부감시 등록: {registered}/{tried}",
        "",
        "[판단법]",
        "- 앱식 only는 전체 시장에서는 튀는데 전략 후보에는 약한 놓침 검증 후보",
        "- 바로 매수 아님. /signal 또는 /review_trace_detail로 체결·현재봉·고점거리 확인",
    ]
    sec = time.time() - t0
    PAPER_V282_STATS["last_text_sec"] = round(sec, 4)
    PAPER_V282_STATS["last_total_sec"] = round(sec, 4)
    return "\n".join(lines).strip()


