def _v283_inc(k, note=""):
    try:
        PAPER_V283_STATS[k] = int(safe_float(PAPER_V283_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V283_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v283_key(value):
    try:
        raw = str(value or "").strip()
        if not raw:
            return ""
        try:
            t, note = resolve_user_ticker_query(raw)
            t = str(t or "").upper().strip()
            if note:
                _v283_inc("alias_match", note)
            if t:
                return _v282_key(t) if '_v282_key' in globals() else t
        except Exception:
            pass
        return _v282_key(raw) if '_v282_key' in globals() else raw.upper().replace("KRW-", "").strip()
    except Exception:
        return str(value or "").upper().strip()


def _v283_copy_history_items(now_ts=None):
    try:
        hist = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        if not isinstance(hist, dict):
            return []
        lock = globals().get("LIGHT_SNAPSHOT_LOCK")
        try:
            acquired = bool(lock.acquire(False)) if lock is not None else False
        except Exception:
            acquired = False
        if acquired:
            try:
                return list(hist.items())
            finally:
                try: lock.release()
                except Exception: pass
        # lock이 바쁘면 최근 compare 캐시를 쓰도록 빈 list를 반환한다.
        return []
    except Exception:
        return []


def _v283_latest_trade_price(ticker, now_ts=None):
    try:
        now_ts = safe_float(now_ts, time.time())
        t = _v283_key(ticker)
        with WS_TRADE_LOCK:
            rows = list((globals().get("WS_TRADE_CACHE", {}) or {}).get(t) or [])
        rows = [r for r in rows if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
        if not rows:
            return 0.0, 0.0, 0.0, 0
        rows.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
        last = rows[-1]
        recent = [r for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 60]
        amt = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in recent)
        return safe_float(last.get("price", 0), 0), safe_float(last.get("ts", 0), 0), amt, len(recent)
    except Exception:
        return 0.0, 0.0, 0.0, 0


def _v283_latest_price(ticker, history_rows=None, now_ts=None):
    now_ts = safe_float(now_ts, time.time())
    t = _v283_key(ticker)
    try:
        with WS_TICKER_LOCK:
            row = dict((globals().get("WS_TICKER_CACHE", {}) or {}).get(t) or {})
        p = safe_float(row.get("price", 0), 0); ts = safe_float(row.get("ts", 0), 0)
        if p > 0 and ts > 0 and now_ts - ts <= safe_float(globals().get("WS_TICKER_CACHE_TTL_SEC", 20), 20):
            return {"price": p, "ts": ts, "source": "ws_ticker", "turnover": safe_float(row.get("turnover", 0), 0), "trade_amount_60s": 0.0, "trade_count_60s": 0}
    except Exception:
        pass
    try:
        p, ts, amt, cnt = _v283_latest_trade_price(t, now_ts=now_ts)
        if p > 0 and ts > 0 and now_ts - ts <= safe_float(globals().get("WS_TRADE_CACHE_TTL_SEC", 120), 120):
            PAPER_V283_STATS["trade_price_boost"] = int(safe_float(PAPER_V283_STATS.get("trade_price_boost", 0), 0)) + 1
            return {"price": p, "ts": ts, "source": "ws_trade", "turnover": amt, "trade_amount_60s": amt, "trade_count_60s": cnt}
    except Exception:
        pass
    try:
        cache = globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {}) if isinstance(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {}), dict) else {}
        p = safe_float(cache.get(t, 0), 0); ts = safe_float(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_TS", 0), 0)
        if p > 0 and ts > 0 and now_ts - ts <= safe_float(globals().get("LIGHT_SNAPSHOT_BULK_STALE_KEEP_SEC", 30), 30):
            return {"price": p, "ts": ts, "source": "bulk_ticker", "turnover": 0.0, "trade_amount_60s": 0.0, "trade_count_60s": 0}
    except Exception:
        pass
    try:
        rows = [r for r in list(history_rows or []) if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
        if rows:
            rows.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
            last = rows[-1]
            return {"price": safe_float(last.get("price", 0), 0), "ts": safe_float(last.get("ts", 0), 0), "source": "light_history", "turnover": safe_float(last.get("turnover_hint", 0), 0), "trade_amount_60s": 0.0, "trade_count_60s": 0}
    except Exception:
        pass
    return {"price": 0.0, "ts": 0.0, "source": "missing", "turnover": 0.0, "trade_amount_60s": 0.0, "trade_count_60s": 0}


def _v283_nearest_base_info(rows, seconds, current_price, now_ts=None):
    now_ts = safe_float(now_ts, time.time())
    out = {"value": 0.0, "ready": False, "base_age_sec": 0.0, "base_price": 0.0, "base_gap_sec": 0.0}
    try:
        current_price = safe_float(current_price, 0)
        if current_price <= 0:
            return out
        valid = [r for r in list(rows or []) if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
        cands = []
        for r in valid:
            age = now_ts - safe_float(r.get("ts", 0), 0)
            if age <= 3:
                continue
            gap = abs(age - float(seconds))
            cands.append((gap, age, r))
        if not cands:
            return out
        cands.sort(key=lambda x: (x[0], -x[1]))
        gap, age, base_row = cands[0]
        if seconds <= 60:
            ready = (42 <= age <= 95)
        elif seconds <= 180:
            ready = (125 <= age <= 230)
        else:
            ready = age >= seconds * 0.80
        base = safe_float(base_row.get("price", 0), 0)
        if base <= 0:
            return out
        val = ((current_price - base) / base) * 100.0
        return {"value": round(val, 2), "ready": bool(ready), "base_age_sec": round(age, 1), "base_price": base, "base_gap_sec": round(gap, 1)}
    except Exception:
        return out


def _v283_money_and_liquidity(ticker, latest, valid_rows, now_ts=None):
    now_ts = safe_float(now_ts, time.time())
    vals = []
    try:
        vals.append(safe_float((latest or {}).get("turnover", 0), 0))
        vals.append(safe_float((latest or {}).get("trade_amount_60s", 0), 0))
        for r in list(valid_rows or []):
            if isinstance(r, dict) and now_ts - safe_float(r.get("ts", 0), 0) <= 300:
                vals.append(safe_float(r.get("turnover_hint", 0), 0))
    except Exception:
        pass
    money = max(vals or [0.0])
    trade_count = int(safe_float((latest or {}).get("trade_count_60s", 0), 0))
    low = bool(money > 0 and money < APP_RANK_V283_LOW_MONEY_KRW) or bool(trade_count > 0 and trade_count <= APP_RANK_V283_LOW_TRADE_COUNT)
    return money, trade_count, low


def _v283_full_history_rows(now_ts=None, max_tickers=None):
    now_ts = safe_float(now_ts, time.time())
    items = _v283_copy_history_items(now_ts=now_ts)
    # lock이 바쁘고 v283 캐시가 있으면 호출자가 캐시를 사용하게 빈 row를 둔다.
    PAPER_V283_STATS["history_total"] = len(items)
    max_tickers = int(safe_float(max_tickers if max_tickers is not None else globals().get("RANK_COMPARE_FULL_HISTORY_MAX_TICKERS", 1000), 1000))
    out = []; fresh = 0
    for tk, rows in items[:max(1, max_tickers)]:
        try:
            ticker = _v283_key(tk)
            if not ticker or ticker == "BTC" or is_watch_excluded_ticker(ticker):
                continue
            valid = [r for r in list(rows or []) if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
            if not valid:
                continue
            valid.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
            latest = _v283_latest_price(ticker, valid, now_ts=now_ts)
            price = safe_float(latest.get("price", 0), 0); latest_ts = safe_float(latest.get("ts", 0), 0)
            if price <= 0 or latest_ts <= 0 or now_ts - latest_ts > 180:
                PAPER_V283_STATS["latest_missing"] = int(safe_float(PAPER_V283_STATS.get("latest_missing", 0), 0)) + 1
                continue
            fresh += 1
            src = str(latest.get("source", ""))
            stat_key = {"ws_ticker":"latest_ws_ticker", "ws_trade":"latest_ws_trade", "bulk_ticker":"latest_bulk", "light_history":"latest_history"}.get(src)
            if stat_key:
                PAPER_V283_STATS[stat_key] = int(safe_float(PAPER_V283_STATS.get(stat_key, 0), 0)) + 1
            info_1 = _v283_nearest_base_info(valid, 60, price, now_ts)
            info_3 = _v283_nearest_base_info(valid, 180, price, now_ts)
            info_15 = _v283_nearest_base_info(valid, 900, price, now_ts)
            info_30 = _v283_nearest_base_info(valid, 1800, price, now_ts)
            info_60 = _v283_nearest_base_info(valid, 3600, price, now_ts)
            money, trade_count, low = _v283_money_and_liquidity(ticker, latest, valid, now_ts)
            if low:
                PAPER_V283_STATS["low_liquidity"] = int(safe_float(PAPER_V283_STATS.get("low_liquidity", 0), 0)) + 1
            row = {
                "ticker": ticker, "price": price, "current_price": price,
                "latest_price_ts": latest_ts, "latest_price_age_sec": round(max(0, now_ts-latest_ts), 1), "latest_price_source": src,
                "change_1": safe_float(info_1.get("value", 0), 0), "change_3": safe_float(info_3.get("value", 0), 0), "change_15": safe_float(info_15.get("value", 0), 0), "change_30": safe_float(info_30.get("value", 0), 0), "change_60": safe_float(info_60.get("value", 0), 0),
                "change_1_ready": bool(info_1.get("ready", False)), "change_3_ready": bool(info_3.get("ready", False)), "change_15_ready": bool(info_15.get("ready", False)), "change_30_ready": bool(info_30.get("ready", False)), "change_60_ready": bool(info_60.get("ready", False)),
                "change_1_base_age_sec": safe_float(info_1.get("base_age_sec", 0), 0), "change_3_base_age_sec": safe_float(info_3.get("base_age_sec", 0), 0), "change_15_base_age_sec": safe_float(info_15.get("base_age_sec", 0), 0), "change_30_base_age_sec": safe_float(info_30.get("base_age_sec", 0), 0), "change_60_base_age_sec": safe_float(info_60.get("base_age_sec", 0), 0),
                "turnover_5m": money, "turnover": money, "trade_count_60s": trade_count, "low_liquidity_app_rank": low,
                "snapshot_rows": len(valid), "snapshot_span_sec": round(max(0.0, safe_float(valid[-1].get("ts", 0), 0) - safe_float(valid[0].get("ts", 0), 0)), 1),
                "snapshot_rank_score": max(safe_float(info_1.get("value", 0), 0), safe_float(info_3.get("value", 0), 0), 0)*2.0 + min(max(money/100_000_000,0),5.0),
                "source": "bot_calc_app_rank_v283", "cache_source": "official_quote_trade_like_rank",
            }
            out.append(row)
        except Exception:
            continue
    PAPER_V283_STATS["history_fresh"] = fresh
    return out


def _v283_build_compare_data(force=False):
    t0 = time.time()
    try:
        c = _RANK_COMPARE_V283_CACHE
        if (not force) and isinstance(c.get("data"), dict) and time.time() - safe_float(c.get("ts", 0), 0) <= RANK_COMPARE_V283_CACHE_TTL_SEC:
            _v283_inc("cache_hit", "v283 rank_compare cache hit")
            return c.get("data")
        _v283_inc("build", "v283 bot calc app rank build")
        rows = _v283_full_history_rows(now_ts=time.time())
        if not rows and isinstance(c.get("data"), dict):
            _v283_inc("cache_hit", "v283 lock busy cache")
            return c.get("data")
        row_by = {_v283_key(r.get("ticker")): r for r in rows if isinstance(r, dict) and _v283_key(r.get("ticker"))}
        specs = [("1분", "change_1", "change_1_ready"), ("3분", "change_3", "change_3_ready"), ("15분", "change_15", "change_15_ready"), ("30분", "change_30", "change_30_ready"), ("1시간", "change_60", "change_60_ready")]
        app = {}; insufficient = {}; app_counts = {}; low_rows = []
        for label, key, ready_key in specs:
            picked = []; lack = 0
            for r in rows:
                if not bool(r.get(ready_key, False)):
                    lack += 1; continue
                val = safe_float(r.get(key, 0), 0)
                if val <= 0: continue
                t = _v283_key(r.get("ticker")); money = _v282_money(r) if '_v282_money' in globals() else safe_float(r.get("turnover",0),0)
                item = (val, _v282_strategy_score(r) if '_v282_strategy_score' in globals() else safe_float(r.get("snapshot_rank_score",0),0), money, t, r)
                picked.append(item)
                if label in {"1분", "3분"} and bool(r.get("low_liquidity_app_rank", False)):
                    low_rows.append(item)
            picked.sort(key=lambda x: (x[0], x[2], x[1]), reverse=True)
            app[label] = picked[:10]; insufficient[label] = lack
            for rank, item in enumerate(picked[:10], start=1):
                val, _score, _money, t, row = item
                info = app_counts.setdefault(t, {"count": 0, "frames": [], "best_rank": 99, "best_change": -999.0, "row": row})
                info["count"] += 1; info["frames"].append(label); info["best_rank"] = min(int(info.get("best_rank",99)), rank); info["best_change"] = max(safe_float(info.get("best_change",-999),-999), safe_float(val,0)); info["row"] = row
        strategy_rows = _v282_get_strategy_rows() if '_v282_get_strategy_rows' in globals() else []
        strategy = [_v283_key(r.get("ticker")) for r in strategy_rows if _v283_key(r.get("ticker"))]
        app_order=[]
        for label, _k, _r in specs:
            for item in app.get(label, [])[:8]:
                t=item[3]
                if t and t not in app_order: app_order.append(t)
        overlap=[t for t in strategy if t in app_order]
        app_only=[t for t in app_order if t not in strategy]
        bot_only=[t for t in strategy if t not in app_order]
        set1={item[3] for item in app.get("1분", [])[:10]}; set3={item[3] for item in app.get("3분", [])[:10]}
        early_both=[t for t in app_order if t in set1 and t in set3]
        one_min_only=[t for t in app_order if t in set1 and t not in set3]
        repeated=[t for t, info in sorted(app_counts.items(), key=lambda kv:(kv[1].get("count",0), -kv[1].get("best_rank",99), kv[1].get("best_change",0)), reverse=True) if int(info.get("count",0)) >= 2]
        low_rows = sorted(low_rows, key=lambda x:(x[0], x[2]), reverse=True)[:8]
        data={"rows": rows, "row_by_ticker": row_by, "app": app, "app_counts": app_counts, "insufficient": insufficient, "strategy": strategy, "strategy_rows": strategy_rows, "app_order": app_order, "overlap": overlap, "app_only": app_only, "bot_only": bot_only, "repeated": repeated, "early_both": early_both, "one_min_only": one_min_only, "low_liquidity_rows": low_rows, "created_ts": time.time(), "build_sec": time.time()-t0, "source": "bot_calc_app_rank_v283"}
        _RANK_COMPARE_V283_CACHE.update({"ts": time.time(), "data": data, "history_count": PAPER_V283_STATS.get("history_total",0)})
        PAPER_V283_STATS.update({"app_1m": len(app.get("1분",[]) or []), "app_3m": len(app.get("3분",[]) or []), "app_15m": len(app.get("15분",[]) or []), "app_30m": len(app.get("30분",[]) or []), "app_60m": len(app.get("1시간",[]) or []), "base_lack_1m": int(insufficient.get("1분",0)), "base_lack_3m": int(insufficient.get("3분",0)), "base_ready_1m": len(app.get("1분",[]) or []), "base_ready_3m": len(app.get("3분",[]) or []), "overlap": len(overlap), "app_only": len(app_only), "bot_only": len(bot_only), "repeat_top": len(repeated), "last_build_sec": round(time.time()-t0,4), "last_total_sec": round(time.time()-t0,4)})
        try:
            PAPER_V282_STATS.update({"fresh_tickers": PAPER_V283_STATS.get("history_fresh",0), "full_history_tickers": PAPER_V283_STATS.get("history_total",0), "app_1m": len(app.get("1분",[]) or []), "app_3m": len(app.get("3분",[]) or []), "overlap": len(overlap), "app_only": len(app_only), "bot_only": len(bot_only), "repeat_top": len(repeated), "last_build_sec": round(time.time()-t0,4), "last_total_sec": round(time.time()-t0,4)})
        except Exception: pass
        return data
    except Exception as e:
        try: append_runtime_error_log("rank_compare_v283", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {"rows": [], "row_by_ticker": {}, "app": {}, "app_counts": {}, "insufficient": {}, "strategy": [], "strategy_rows": [], "app_order": [], "overlap": [], "app_only": [], "bot_only": [], "repeated": [], "early_both": [], "one_min_only": [], "low_liquidity_rows": [], "created_ts": time.time(), "build_sec": time.time()-t0, "source": "error"}


def _v283_format_app_item(t, info=None):
    try:
        frames = "/".join((info or {}).get("frames", [])[:5]) if isinstance(info, dict) else ""
        best = safe_float((info or {}).get("best_change", 0), 0) if isinstance(info, dict) else 0
        row = (info or {}).get("row", {}) if isinstance(info, dict) else {}
        src_txt = "·체결보완" if str(row.get("latest_price_source", "")) == "ws_trade" else ""
        return f"{t} {best:+.2f}%" + (f"·{frames}" if frames else "") + src_txt if best > 0 else str(t)
    except Exception:
        return str(t)


def _v283_join(items, limit=8, empty="없음"):
    return _v282_join(items, limit=limit, empty=empty) if '_v282_join' in globals() else (", ".join(list(items or [])[:limit]) if items else empty)


def build_rank_compare_text_v279(args=None, top_n: int = 10):
    t0=time.time(); _v283_inc("compare")
    data=_v283_build_compare_data(force=False)
    app=data.get("app") or {}; counts=data.get("app_counts") or {}; lack=data.get("insufficient") or {}
    lines=["📈 순위 비교 /rank_compare", "- 소스: 봇 계산 앱식 상승률 순위", "- 빗썸 앱 원본 랭킹 아님. 공식 현재가/체결/스냅샷으로 최대한 비슷하게 만든 유사 순위", "- 1분은 초입 감지용. 바로 매수/paper 등록 아님", f"- 기준: 전체 light snapshot + WS 현재가/체결 보완 / 생성 {format_elapsed_text(time.time()-safe_float(data.get('created_ts', time.time()), time.time()))} 전 / 소요 {safe_float(data.get('build_sec',0),0):.3f}s", "", "[봇 계산 상승률 TOP]"]
    for label in ["1분","3분","15분","30분","1시간"]:
        bits=[]
        for val, _score, money, t, row in list(app.get(label) or [])[:max(1,int(top_n))]:
            item=f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money,0) >= 100_000_000:
                try: item += f"·{format_money_compact_amount_krw(money)}"
                except Exception: pass
            if str(row.get("latest_price_source", "")) == "ws_trade": item += "·체결가보완"
            if label in {"1분","3분"}:
                age=safe_float(row.get(f"change_{'1' if label=='1분' else '3'}_base_age_sec",0),0)
                if age>0: item += f"·기준{age:.0f}s"
            bits.append(item)
        lack_n=int(safe_float(lack.get(label,0),0))
        if label in {"15분","30분","1시간"} and not bits and lack_n:
            lines.append(f"- {label}: 표본부족 / 계산 대기 ({lack_n}개)"); continue
        suffix=f" / 기준가부족 {lack_n}개" if lack_n and label in {"1분","3분"} else (f" / 표본부족 {lack_n}개" if lack_n and label in {"15분","30분","1시간"} else "")
        lines.append(f"- {label}: " + (_v283_join(bits, limit=top_n, empty="계산 가능한 상승 없음") + suffix))
    low_bits=[]
    for val, _score, money, t, row in list(data.get("low_liquidity_rows") or [])[:6]:
        low_bits.append(f"{t} {safe_float(val,0):+.2f}%·돈/체결약함")
    if low_bits:
        lines += ["", "[저유동성/체결약함 급등]", "- " + _v283_join(low_bits, limit=6)]
    strategy=data.get("strategy") or []; overlap=data.get("overlap") or []; app_only=data.get("app_only") or []; bot_only=data.get("bot_only") or []; repeated=data.get("repeated") or []; early_both=data.get("early_both") or []; one_min_only=data.get("one_min_only") or []
    lines += ["", "[초입 후보]", "- 1분+3분 동시: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in early_both], limit=10, empty="없음"), "- 1분만 급등: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in one_min_only], limit=10, empty="없음") + (" / 3분 유지 확인 필요" if one_min_only else ""), "", "[우리 봇 전략 순위 TOP]", "- " + _v283_join(strategy, limit=8, empty="없음"), "", "[비교 결과]", "- 겹침: " + _v283_join(overlap, limit=8, empty="없음"), "- 앱식 only 놓침후보: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in app_only], limit=12, empty="없음"), "- 봇 only 단독후보: " + _v283_join(bot_only, limit=10, empty="없음"), "- 반복상위: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in repeated], limit=10, empty="없음"), f"- 전체 히스토리: {PAPER_V283_STATS.get('history_fresh',0)}/{PAPER_V283_STATS.get('history_total',0)}개 / 체결가보완 {PAPER_V283_STATS.get('trade_price_boost',0)} / 저유동성분리 {PAPER_V283_STATS.get('low_liquidity',0)}", "", "[판단법]", "- 앱식 only는 전체 시장에서는 튀는데 전략 후보에는 약한 놓침 검증 후보", "- 빗썸 앱 원본이 아니라 봇 계산 유사 순위야. 앱 스샷과 차이가 나면 기준가/최신가/티커명을 같이 본다."]
    PAPER_V283_STATS["last_text_sec"]=round(time.time()-t0,4); PAPER_V283_STATS["last_total_sec"]=round(time.time()-t0,4)
    return "\n".join(lines).strip()


