def _v285_app_signal_note(ticker):
    try:
        t=_v285_norm(ticker)
        data=_v285_build_compare_data(force=False)
        row=(data.get('row_by_ticker') or {}).get(t)
        info=(data.get('app_counts') or {}).get(t)
        if isinstance(info,dict):
            PAPER_V285_STATS['signal_hint']=int(safe_float(PAPER_V285_STATS.get('signal_hint',0),0))+1
            return '- 전체 앱식 히스토리에는 있음: '+_v285_format_app_item(t, info)+' / 매수신호 아님'
        if isinstance(row,dict):
            c1=safe_float(row.get('change_1',0),0); c3=safe_float(row.get('change_3',0),0)
            r1='가능' if row.get('change_1_ready') else '기준가부족'; r3='가능' if row.get('change_3_ready') else '기준가부족'
            src=str(row.get('latest_price_source','') or row.get('cache_source','') or '-')
            return f"- 전체 앱식 히스토리에는 있음: 1분 {c1:+.2f}%({r1}) / 3분 {c3:+.2f}%({r3}) / 최신가 {src} / 매수신호 아님"
        return '- 전체 앱식 히스토리에도 최근 표본 없음 / 티커명 또는 상장명 확인 필요'
    except Exception:
        return ''


def _v279_app_signal_note(ticker): return _v285_app_signal_note(ticker)

try:
    _V285_BASE_BUILD_SIGNAL_TEXT = build_signal_text_v256
    def build_signal_text_v256(args=None, limit:int=None):
        args_list=list(args or []) if args is not None else []
        raw=str(args_list[0]) if args_list else ''
        resolved=_v285_norm(raw) if raw else raw
        text=str(_V285_BASE_BUILD_SIGNAL_TEXT(args=[resolved] if raw else args, limit=limit))
        if raw:
            note=_v285_app_signal_note(raw)
            if note and note not in text:
                lines=text.splitlines(); insert_at=len(lines)
                for i,l in enumerate(lines):
                    if '상세:' in l or '후보 확인' in l:
                        insert_at=i; break
                lines.insert(insert_at,note); text='\n'.join(lines).strip()
            if '현재 0.000000' in text:
                try:
                    row=(_v285_build_compare_data(force=False).get('row_by_ticker') or {}).get(resolved)
                    p=safe_float((row or {}).get('current_price',(row or {}).get('price',0)),0)
                    src=str((row or {}).get('latest_price_source',(row or {}).get('cache_source','')) or '')
                    if p>0 and f'가격보완 현재가 {p:g}' not in text:
                        PAPER_V285_STATS['signal_price_fix']=int(safe_float(PAPER_V285_STATS.get('signal_price_fix',0),0))+1
                        text=text.replace('현재 0.000000', f'현재 0.000000 / 가격보완 현재가 {p:g}({src})')
                except Exception: pass
        return text
except Exception:
    pass

