# ============================================================
# v2.5.290 - v289 rank_compare worker 실제 적용
# 원인: v288은 /rank_compare 직접계산은 끊었지만 rows=0일 때도 _v286_make_compare_data() fallback을 타서 20초 이상 걸릴 수 있었다.
# 또한 history를 list(rows)[-80:]로 통째 복사해 데이터생성이 길어질 수 있었다.
# 조치: tail80 수집, rows 부족 시 정상 캐시 보존, rows=0이면 빠른 rank snapshot fallback만 사용.
# ============================================================
PAPER_V289_STATS={'build':0,'skip':0,'busy':0,'error':0,'hit':0,'miss':0,'fallback_fast':0,'preserve':0,'items':0,'rows':0,'fresh':0,'no_valid':0,'no_latest':0,'stale':0,'cut':0,'copy_sec':0.0,'collect_sec':0.0,'text_sec':0.0,'total_sec':0.0,'cmd_sec':0.0,'source':'대기','note':'대기'}
RANK_COMPARE_V289_MIN_GOOD_ROWS=120
RANK_COMPARE_V289_BUILD_BUDGET_SEC=3.5
RANK_COMPARE_V289_MIN_INTERVAL_SEC=18.0
RANK_COMPARE_V289_STALE_OK_SEC=180.0
try:
    _V289_BASE_CACHE_STATUS=build_cache_status_text
except Exception:
    _V289_BASE_CACHE_STATUS=None

def _v289_inc(k,note=''):
    try:
        PAPER_V289_STATS[k]=int(safe_float(PAPER_V289_STATS.get(k,0),0))+1
        if note: PAPER_V289_STATS['note']=str(note)[:160]
    except Exception: pass

def _v289_norm(t):
    try: return _v288_norm(t) if '_v288_norm' in globals() else str(t or '').upper().strip().replace('KRW-','').replace('_KRW','')
    except Exception: return str(t or '').upper().strip()

def _v289_good_cache():
    try:
        d=RANK_COMPARE_V288_TEXT_CACHE.get('data') if isinstance(RANK_COMPARE_V288_TEXT_CACHE.get('data'),dict) else None
        txt=str(RANK_COMPARE_V288_TEXT_CACHE.get('text','') or '')
        ts=safe_float(RANK_COMPARE_V288_TEXT_CACHE.get('ts',0),0); age=time.time()-ts if ts else 9999
        if d and txt and len(d.get('rows') or [])>=RANK_COMPARE_V289_MIN_GOOD_ROWS and age<=240:
            return d,txt,age
    except Exception: pass
    return None,'',9999

def _v289_tail(seq,n=80):
    try:
        if seq is None: return []
        if isinstance(seq,list): return seq[-n:]
        try:
            out=[]
            for x in reversed(seq):
                out.append(x)
                if len(out)>=n: break
            out.reverse(); return out
        except Exception:
            tmp=[]
            for x in seq:
                tmp.append(x)
                if len(tmp)>n: tmp=tmp[-n:]
            return tmp
    except Exception: return []

def _v289_copy_items():
    t0=time.time()
    try:
        h=globals().get('LIGHT_SNAPSHOT_HISTORY',{})
        if not isinstance(h,dict) or not h:
            PAPER_V289_STATS['copy_sec']=round(time.time()-t0,4); return [],'empty'
        lock=globals().get('LIGHT_SNAPSHOT_LOCK')
        if lock is not None:
            try: ok=bool(lock.acquire(False))
            except Exception: ok=False
            if not ok:
                PAPER_V289_STATS['copy_sec']=round(time.time()-t0,4); return None,'lock_busy'
            try: items=list(h.items())
            finally:
                try: lock.release()
                except Exception: pass
        else: items=list(h.items())
        PAPER_V289_STATS['copy_sec']=round(time.time()-t0,4); return items,'ok'
    except Exception as e:
        _v289_inc('error',f'copy {e}'); PAPER_V289_STATS['copy_sec']=round(time.time()-t0,4); return None,'error'

def _v289_collect_rows():
    t0=time.time(); now=time.time(); items,reason=_v289_copy_items(); rank=_v288_rank_rows() if '_v288_rank_rows' in globals() else []
    rmap=_v288_rank_map(rank) if '_v288_rank_map' in globals() else {}; rows=[]; fresh=0; no_valid=0; no_latest=0; stale=0; cut=False
    if items is None:
        PAPER_V289_STATS.update({'items':0,'rows':0,'fresh':0,'collect_sec':round(time.time()-t0,4)}); return [],rank,False,reason
    PAPER_V289_STATS['items']=len(items)
    for tk,hist in list(items)[:520]:
        if time.time()-t0>RANK_COMPARE_V289_BUILD_BUDGET_SEC: cut=True; break
        try:
            t=_v289_norm(tk)
            if not t or t=='BTC': continue
            try:
                if 'is_watch_excluded_ticker' in globals() and is_watch_excluded_ticker(t): continue
            except Exception: pass
            valid=[r for r in _v289_tail(hist,80) if isinstance(r,dict) and safe_float(r.get('price',0),0)>0 and safe_float(r.get('ts',0),0)>0]
            if not valid: no_valid+=1; continue
            latest=_v288_latest_price_fast(t,valid,now_ts=now) if '_v288_latest_price_fast' in globals() else {}
            price=safe_float((latest or {}).get('price',0),0); ts=safe_float((latest or {}).get('ts',0),0)
            if price<=0 or ts<=0:
                best=max(valid,key=lambda r:safe_float(r.get('ts',0),0)); price=safe_float(best.get('price',0),0); ts=safe_float(best.get('ts',0),0); latest={'source':'history_last','turnover':safe_float(best.get('turnover_hint',0),0)}
            if price<=0 or ts<=0: no_latest+=1; continue
            if now-ts>180: stale+=1; continue
            fresh+=1
            c1=_v288_base_change_fast(valid,60,price,now) if '_v288_base_change_fast' in globals() else {'value':0,'ready':False,'base_age_sec':0}
            c3=_v288_base_change_fast(valid,180,price,now) if '_v288_base_change_fast' in globals() else {'value':0,'ready':False,'base_age_sec':0}
            row={'ticker':t,'price':price,'current_price':price,'latest_ts':ts,'latest_price_source':(latest or {}).get('source',''),'cache_source':'v289_tail80','turnover':safe_float((latest or {}).get('turnover',0),0),'change_1':c1.get('value',0),'change_1_ready':c1.get('ready',False),'change_1_base_age_sec':c1.get('base_age_sec',0),'change_3':c3.get('value',0),'change_3_ready':c3.get('ready',False),'change_3_base_age_sec':c3.get('base_age_sec',0),'change_15':0,'change_15_ready':False,'change_30':0,'change_30_ready':False,'change_60':0,'change_60_ready':False}
            try: row=_v288_enrich_with_rank(row,rmap.get(t)) if '_v288_enrich_with_rank' in globals() else row
            except Exception: pass
            rows.append(row)
        except Exception: continue
    if cut: _v289_inc('cut','budget cut')
    PAPER_V289_STATS.update({'items':len(items),'rows':len(rows),'fresh':fresh,'no_valid':no_valid,'no_latest':no_latest,'stale':stale,'collect_sec':round(time.time()-t0,4)})
    return rows,rank,cut,reason

def _v289_money(r):
    try: return _v286_money(r) if '_v286_money' in globals() else safe_float((r or {}).get('turnover',0),0)
    except Exception: return 0

def _v289_score(r):
    try: return _v286_score(r) if '_v286_score' in globals() else safe_float((r or {}).get('score',0),0)
    except Exception: return 0

def _v289_prepare(r):
    try:
        x=dict(r or {}); x['ticker']=_v289_norm(x.get('ticker'))
        if not x.get('exclude_reason_v286'): x['exclude_reason_v286']=_v286_exclude_reason(x) if '_v286_exclude_reason' in globals() else '전략 점수/근거 부족'
        if not x.get('candle_summary_v286'): x['candle_summary_v286']=_v286_candle_summary(x) if '_v286_candle_summary' in globals() else ''
        if 'low_liquidity_app_rank' not in x: x['low_liquidity_app_rank']=bool(_v286_is_low_liquidity(x)) if '_v286_is_low_liquidity' in globals() else False
        return x
    except Exception: return r

def _v289_item(r0,val):
    r=_v289_prepare(r0); return (safe_float(val,0),_v289_score(r),_v289_money(r),_v289_norm(r.get('ticker')),r)

def _v289_rank_fb(rank,frame='3분'):
    key='change_1' if frame=='1분' else 'change_3'; out=[]
    for r in list(rank or [])[:30]:
        try:
            val=safe_float(r.get(key,0),0)
            if frame=='1분' and val<=0: val=safe_float(r.get('change_1m',r.get('rise_1m',0)),0)
            if frame=='3분' and val<=0: val=safe_float(r.get('change_3m',r.get('rise_3m',0)),0)
            if val<=0: continue
            rr=dict(r); rr['cache_source']='v289_rank_snapshot_fast'; out.append(_v289_item(rr,val))
        except Exception: continue
    out.sort(key=lambda x:(x[0],x[2],x[1]),reverse=True); return out[:10]

def _v289_pick(rows,label,key,ready):
    arr=[]; miss=0; low=[]
    for r in rows or []:
        try:
            if ready and not bool(r.get(ready,False)): miss+=1; continue
            val=safe_float(r.get(key,0),0)
            if val<=0: continue
            it=_v289_item(r,val)
            if it[4].get('low_liquidity_app_rank') and label in {'1분','3분'}: low.append(it)
            else: arr.append(it)
        except Exception: continue
    arr.sort(key=lambda x:(x[0],x[2],x[1]),reverse=True); low.sort(key=lambda x:(x[0],x[2],x[1]),reverse=True)
    return arr[:10],miss,low[:8]

def _v289_data(rows=None,rank=None,source='v289'):
    t0=time.time(); rows=[r for r in list(rows or []) if isinstance(r,dict) and _v289_norm(r.get('ticker'))]; rank=[r for r in list(rank or []) if isinstance(r,dict) and _v289_norm(r.get('ticker'))]
    app={}; lack={}; counts={}; lows=[]
    for label,key,ready in [('1분','change_1','change_1_ready'),('3분','change_3','change_3_ready')]:
        picked,miss,low=_v289_pick(rows,label,key,ready)
        if not picked:
            fb=_v289_rank_fb(rank,label)
            if fb: picked=fb; source+='+rankfast'
        app[label]=picked; lack[label]=miss; lows+=low
        for i,it in enumerate(picked,1):
            val,sc,money,t,row=it; info=counts.setdefault(t,{'count':0,'frames':[],'best_rank':99,'best_change':-999,'row':row})
            if label not in info['frames']: info['count']+=1; info['frames'].append(label)
            info['best_rank']=min(info['best_rank'],i); info['best_change']=max(info['best_change'],val); info['row']=row
    for label in ['15분','30분','1시간']: app[label]=[]; lack[label]=len(rows)
    strategy=[]
    for r in rank[:8]:
        t=_v289_norm(r.get('ticker'))
        if t and t not in strategy: strategy.append(t)
    order=[]
    for label in ['1분','3분']:
        for it in app.get(label,[])[:8]:
            if it[3] not in order: order.append(it[3])
    overlap=[t for t in strategy if t in order]; app_only=[t for t in order if t not in strategy]; bot_only=[t for t in strategy if t not in order]
    s1={i[3] for i in app.get('1분',[])}; s3={i[3] for i in app.get('3분',[])}
    early=[t for t in order if t in s1 and t in s3]; one=[t for t in order if t in s1 and t not in s3]; repeated=[t for t,info in counts.items() if info.get('count',0)>=2]
    return {'rows':rows,'rank_rows':rank,'app':app,'app_counts':counts,'insufficient':lack,'strategy':strategy,'app_order':order,'overlap':overlap,'app_only':app_only,'bot_only':bot_only,'early_both':early,'one_min_only':one,'repeated':repeated,'low_liquidity_rows':lows[:8],'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':source,'rank_snapshot_only':not bool(rows),'full_rank_ready':bool(rows)}

def _v289_fmt(it,reason=False):
    try:
        val,sc,money,t,row=it; extra=[]
        if money>=100000000:
            extra.append(format_money_compact_amount_krw(money) if 'format_money_compact_amount_krw' in globals() else f'{money/100000000:.2f}억')
        elif money>0: extra.append('돈얇음')
        cs=str((row or {}).get('candle_summary_v286','') or '')
        if cs: extra.append(cs)
        out=f'{_v289_norm(t)} {safe_float(val,0):+.2f}%'+(('·'+'·'.join(extra[:2])) if extra else '')
        if reason: out+=f" / 제외이유 {str((row or {}).get('exclude_reason_v286','전략 점수/근거 부족'))}"
        return out
    except Exception: return str(it)

def _v289_info(t,counts):
    info=counts.get(t,{}) if isinstance(counts,dict) else {}; row=info.get('row') if isinstance(info.get('row'),dict) else {}; return (safe_float(info.get('best_change',0),0),0,_v289_money(row),t,row)

def _v289_text(data):
    t0=time.time(); data=data if isinstance(data,dict) else {}; app=data.get('app') or {}; counts=data.get('app_counts') or {}; lack=data.get('insufficient') or {}; rows_n=len(data.get('rows') or [])
    age=max(0,time.time()-safe_float(data.get('created_ts',time.time()),time.time())); age_txt=format_elapsed_text(age) if 'format_elapsed_text' in globals() else f'{age:.0f}초'; stale=' / ⚠️ 전체랭크 준비중' if data.get('rank_snapshot_only') else ''
    lines=['📈 순위 비교 /rank_compare','- 소스: 봇 계산 앱식 상승률 순위','- 빗썸 앱 원본 랭킹 아님. 공식 현재가/체결/스냅샷 기반 유사 순위','- v289: 명령어 직접계산 없음 / rows 0이면 무거운 fallback 금지',f"- 기준: 최종출력 캐시 / 생성 {age_txt} 전 / 데이터생성 {safe_float(data.get('build_sec',0),0):.3f}s / rows {rows_n}{stale}",'','[봇 계산 상승률 TOP]']
    for label in ['1분','3분','15분','30분','1시간']:
        a=list(app.get(label) or [])[:10]
        lines.append(f"- {label}: "+(', '.join(_v289_fmt(x) for x in a) if a else ('계산 가능한 상승 없음'+(f" / 기준가부족 {int(safe_float(lack.get(label,0),0))}개" if safe_float(lack.get(label,0),0) else ''))))
    low=list(data.get('low_liquidity_rows') or [])[:8]
    if low: lines+=['','[저유동성/체결약함 급등]','- '+', '.join(_v289_fmt(x) for x in low)]
    early=list(data.get('early_both') or [])[:8]; one=list(data.get('one_min_only') or [])[:8]
    lines+=['','[초입 후보]','- 1분+3분 동시: '+(', '.join(_v289_fmt(_v289_info(t,counts)) for t in early) if early else '없음'),'- 1분만 급등: '+((', '.join(_v289_fmt(_v289_info(t,counts)) for t in one)+' / 3분 유지 확인 필요') if one else '없음')]
    strategy=list(data.get('strategy') or [])[:8]; overlap=list(data.get('overlap') or [])[:10]; app_only=list(data.get('app_only') or [])[:10]; bot_only=list(data.get('bot_only') or [])[:8]; repeated=list(data.get('repeated') or [])[:8]
    lines+=['','[우리 봇 전략 순위 TOP]','- '+(', '.join(strategy) if strategy else '없음'),'','[비교 결과]','- 겹침: '+(', '.join(overlap) if overlap else '없음'),'- 앱식 only 놓침후보: '+(', '.join(_v289_fmt(_v289_info(t,counts),True) for t in app_only) if app_only else '없음'),'- 봇 only 단독후보: '+(', '.join(bot_only) if bot_only else '없음'),'- 반복상위: '+(', '.join(repeated) if repeated else '없음'),f"- 전체 앱식 rows {rows_n} / 소스 {data.get('source','-')} / 내부감시 자동등록 없음",'','[판단법]','- 앱식 only는 전체 시장에서는 튀는데 전략 후보에는 약한 놓침 검증 후보','- rows가 부족하면 전체랭크가 아니라 rank snapshot 임시 비교로 본다.']
    PAPER_V289_STATS['text_sec']=round(time.time()-t0,4); return '\n'.join(lines)

def _v289_store(data,text,source):
    now=time.time(); gen=int(safe_float(RANK_COMPARE_V288_TEXT_CACHE.get('generation',0),0))+1
    RANK_COMPARE_V288_TEXT_CACHE.update({'ts':now,'text':str(text or ''),'data':data if isinstance(data,dict) else {},'source':str(source or '')[:80],'generation':gen})
    try:
        if '_RANK_COMPARE_V286_BG_CACHE' in globals():
            _RANK_COMPARE_V286_BG_CACHE.update({'ts':now,'data':data,'build_sec':safe_float((data or {}).get('build_sec',0),0),'note':source})
    except Exception: pass

def _v289_fast_fallback(rank=None,source='v289_rank_snapshot_fast'):
    _v289_inc('fallback_fast',source)
    data=_v289_data([], rank if rank is not None else (_v288_rank_rows() if '_v288_rank_rows' in globals() else []), source)
    data['rank_snapshot_only']=True; data['app_rank_preparing']=True
    return data

def _v289_refresh(reason='worker',force=False):
    now=time.time(); ts=safe_float(RANK_COMPARE_V288_TEXT_CACHE.get('ts',0),0); age=now-ts if ts else 9999
    if (not force) and age<RANK_COMPARE_V289_MIN_INTERVAL_SEC:
        _v289_inc('skip',f'skip fresh {age:.1f}s'); return RANK_COMPARE_V288_TEXT_CACHE.get('data')
    if not RANK_COMPARE_V288_REFRESH_LOCK.acquire(False):
        _v289_inc('busy','busy'); return RANK_COMPARE_V288_TEXT_CACHE.get('data')
    try:
        t0=time.time(); _v289_inc('build',reason)
        rows,rank,cut,why=_v289_collect_rows(); source='v289_tail80_cut' if cut else 'v289_tail80'
        old,oldtxt,oldage=_v289_good_cache()
        if len(rows)<RANK_COMPARE_V289_MIN_GOOD_ROWS and old and oldtxt:
            _v289_inc('preserve',f'preserve {len(rows)}')
            PAPER_V289_STATS.update({'total_sec':round(time.time()-t0,4),'source':'preserve_good_cache','note':f'rows 부족 {len(rows)} / {why}'})
            return old
        data=_v289_fast_fallback(rank,'v289_rank_snapshot_fast') if not rows else _v289_data(rows,rank,source)
        data['created_ts']=time.time(); data['build_sec']=round(time.time()-t0,4)
        text=_v289_text(data); _v289_store(data,text,data.get('source',source))
        PAPER_V289_STATS.update({'total_sec':round(time.time()-t0,4),'app1':len(((data.get('app') or {}).get('1분') or [])),'app3':len(((data.get('app') or {}).get('3분') or [])),'overlap':len(data.get('overlap') or []),'app_only':len(data.get('app_only') or []),'bot_only':len(data.get('bot_only') or []),'source':data.get('source',source),'note':f'{reason} / rows {len(rows)} / {why}'})
        return data
    except Exception as e:
        _v289_inc('error',str(e))
        try: append_runtime_error_log('rank_compare_v289_refresh',str(e),exc=e,include_traceback=False)
        except Exception: pass
        return RANK_COMPARE_V288_TEXT_CACHE.get('data')
    finally:
        try: RANK_COMPARE_V288_REFRESH_LOCK.release()
        except Exception: pass

def _v289_get_text():
    t0=time.time(); txt=str(RANK_COMPARE_V288_TEXT_CACHE.get('text','') or ''); ts=safe_float(RANK_COMPARE_V288_TEXT_CACHE.get('ts',0),0); age=time.time()-ts if ts else 9999
    if txt and age<=RANK_COMPARE_V289_STALE_OK_SEC:
        _v289_inc('hit','text hit'); PAPER_V289_STATS['cmd_sec']=round(time.time()-t0,4)
        return _v288_patch_text_age(txt) if '_v288_patch_text_age' in globals() else txt
    _v289_inc('miss','text miss')
    data=_v289_fast_fallback(source='v289_command_fast_fallback'); text=_v289_text(data); _v289_store(data,text,'v289_command_fast_fallback')
    PAPER_V289_STATS['cmd_sec']=round(time.time()-t0,4); return text

