BTC_V291_CFG = {'minute10':(120,120,900),'minute30':(150,150,900),'minute60':(180,180,1200),'day':(900,600,7200)}
RANK_STALE_V291_STATS = {'penalty':0,'hide':0,'review':0,'note':'대기'}

def _v291_inc(k, note=''):
    try:
        BTC_V291_STATS[k] = int(safe_float(BTC_V291_STATS.get(k,0),0)) + 1
        if note: BTC_V291_STATS['last'] = str(note)[:160]
    except Exception: pass

def _v291_ok_df(df, n=20):
    try: return df is not None and len(df) >= int(n) and safe_float(df['close'].iloc[-1],0) > 0
    except Exception: return False

def _v291_btc_row(interval):
    return BTC_V291_CACHE.setdefault(str(interval), {'df':None,'ok_ts':0.0,'cool_until':0.0,'fail':0,'status':'대기','err':''})

def _v291_get_btc_df_cached(interval, min_len=20):
    now = time.time(); interval = str(interval)
    refresh, cool, max_reuse = BTC_V291_CFG.get(interval, (180,180,900))
    row = _v291_btc_row(interval); df = row.get('df'); age = now - safe_float(row.get('ok_ts',0),0) if safe_float(row.get('ok_ts',0),0)>0 else 999999
    if _v291_ok_df(df, min_len) and age <= refresh:
        row['status'] = 'cache_hit'; _v291_inc('hit', f'{interval} cache {int(age)}s'); return df, 'cache_hit', age
    if safe_float(row.get('cool_until',0),0) > now:
        remain = safe_float(row.get('cool_until',0),0) - now; row['status'] = 'cooldown'; _v291_inc('cooldown', f'{interval} cooldown {int(remain)}s')
        if _v291_ok_df(df, min_len) and age <= max_reuse:
            _v291_inc('reuse', f'{interval} reuse {int(age)}s'); return df, 'cooldown_reuse', age
        return None, 'cooldown_no_data', age
    try:
        nd = get_ohlcv('BTC', interval)
        if _v291_ok_df(nd, min_len):
            row.update({'df':nd,'ok_ts':time.time(),'cool_until':0.0,'fail':0,'status':'fetch_ok','err':''})
            _v291_inc('fetch', f'{interval} fetch_ok'); return nd, 'fetch_ok', 0.0
        raise RuntimeError('empty_or_short')
    except Exception as e:
        row['fail'] = int(safe_float(row.get('fail',0),0)) + 1
        row['cool_until'] = time.time() + min(cool * max(1, row['fail']), cool * 3)
        row['status'] = 'fetch_fail'; row['err'] = str(e)[:80]
        _v291_inc('fail', f'{interval} fail -> cooldown {int(row["cool_until"]-time.time())}s')
        if _v291_ok_df(df, min_len) and age <= max_reuse:
            _v291_inc('reuse', f'{interval} fail_reuse {int(age)}s'); return df, 'fail_reuse', age
        return None, 'fetch_fail_no_cache', age

def get_btc_multi_tf_snapshot():
    out = {}
    for name, interval, bars in [('short','minute10',6),('mid','minute60',6),('day','day',3)]:
        try:
            df, st, age = _v291_get_btc_df_cached(interval, max(20,bars+1))
            if not _v291_ok_df(df, max(20,bars+1)): continue
            price = safe_float(df['close'].iloc[-1],0); ma20v = ma(df,20)
            out[name] = {'interval':interval,'price':price,'change_pct':get_recent_change_pct(df,bars),'ma20':ma20v,'above_ma20':ma20v>0 and price>=ma20v,'v291_status':st,'v291_age':age}
        except Exception: pass
    return out

def get_btc_df():
    for interval in ['minute60','minute30','minute10','day']:
        df, st, age = _v291_get_btc_df_cached(interval, 20)
        if _v291_ok_df(df,20): return df, interval
    return None, None

def get_btc_market_state():
    try:
        df, interval = get_btc_df()
        if df is None: return True, 'BTC 데이터 부족 / 쿨다운 보호 중', 0.0
        price = safe_float(df['close'].iloc[-1],0); recent = get_recent_change_pct(df,4); ma20v = ma(df,20)
        if recent <= BTC_STRONG_BLOCK_PCT: return False, f'BTC가 크게 빠지는 중이야 ({recent:.2f}%)', recent
        if recent <= BTC_CRASH_BLOCK_PCT: return False, f'BTC가 약해서 신규 진입을 쉬고 있어 ({recent:.2f}%)', recent
        if BTC_MA_FILTER and ma20v > 0 and price < ma20v * 0.992: return False, 'BTC가 약한 자리라 신규 진입을 쉬고 있어', recent
        return True, f'시장 분위기 무난 / BTC {interval} 캐시 기준', recent
    except Exception: return True, 'BTC 판단 예외 / 보호모드', 0.0

