    return {'name':'UNKNOWN','message':'BTC 데이터 부족 / 시장판단 보류','watch_message':'BTC 확인 부족 · 보수적으로 보기','short_change_pct':None,'mid_change_pct':None,'day_change_pct':None,'allow_auto_buy':True,'allow_breakout':True,'watch_entry_allowed':True,'watch_recovery_allowed':True}

