def _v291_btc_lines():
    now = time.time(); parts=[]
    try:
        for k,row in BTC_V291_CACHE.items():
            age = now-safe_float(row.get('ok_ts',0),0) if safe_float(row.get('ok_ts',0),0)>0 else -1
            rem = max(0, safe_float(row.get('cool_until',0),0)-now)
            s = f'{k}:{row.get("status","-")}'
            if age >= 0: s += f'/정상{int(age)}초전'
            if rem > 0: s += f'/쿨다운{int(rem)}초'
            parts.append(s)
    except Exception: pass
    return parts

def analyze_btc_flow():
    r = get_market_regime(); name = r.get('name','UNKNOWN') if isinstance(r,dict) else 'UNKNOWN'
    state = {'BLOCK':'🚨 강한 하락','WEAK':'⚠️ 약한 장','SIDEWAYS':'😐 횡보','STRONG_UP':'🔥 강한 상승','UNKNOWN':'❔ 데이터 부족'}.get(name,'👍 보통')
    extra = '\n데이터 상태:\n- ' + ' / '.join(_v291_btc_lines()[:4]) if _v291_btc_lines() else ''
    return f"""
📊 BTC 리포트 (다중 시간대 기준)
📌 상태: {state}
- 단기: {_v291_pct(r.get('short_change_pct') if isinstance(r,dict) else None)}
- 중기: {_v291_pct(r.get('mid_change_pct') if isinstance(r,dict) else None)}
- 일봉: {_v291_pct(r.get('day_change_pct') if isinstance(r,dict) else None)}
한줄 해석:
{r.get('message','시장 상태 확인 중') if isinstance(r,dict) else '시장 상태 확인 중'}
후보 해석:
{r.get('watch_message','기본 기준대로 보면 돼') if isinstance(r,dict) else '기본 기준대로 보면 돼'}{extra}
"""

def _v291_row_age(row, now=None):
    now = time.time() if now is None else now
    vals=[]
    for k in ['snapshot_rank_detected_ts','rank_state_updated_ts','updated_ts','snapshot_ts','last_ts','created_ts','ts']:
        v = safe_float((row or {}).get(k,0),0)
        if v>0: vals.append(v)
    return now - max(vals) if vals else 0.0

def _v291_stale_row(row, now=None):
    try:
        r = dict(row or {}); age = _v291_row_age(r, now)
        if age <= 0: return r
        r['snapshot_age_v291'] = age; score = safe_float(r.get('snapshot_rank_score', r.get('score',0)),0)
        if age >= 600:
            RANK_STALE_V291_STATS['review'] += 1; r['snapshot_stale_review_v291']=True; r['rank_watch_action']='복기 기록 대기'; r['snapshot_rank_score']=min(score,0.25); r['stale_reason_v291']=f'스냅샷 {format_elapsed_text(age)} 전이라 복기용'
        elif age >= 300:
            RANK_STALE_V291_STATS['hide'] += 1; r['snapshot_stale_hide_v291']=True; r['rank_watch_action']='복기 기록 대기'; r['snapshot_rank_score']=min(score*0.2,0.6); r['stale_reason_v291']=f'스냅샷 {format_elapsed_text(age)} 전이라 상위노출 제한'
        elif age >= 180:
            RANK_STALE_V291_STATS['penalty'] += 1; r['snapshot_stale_penalty_v291']=True; r['snapshot_rank_score']=score*0.45; r['stale_reason_v291']=f'스냅샷 {format_elapsed_text(age)} 전이라 감점'
        return r
    except Exception: return row

def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    try:
        rows = _V291_OLD_RANK_ROWS(limit=limit, min_move_pct=min_move_pct) if callable(_V291_OLD_RANK_ROWS) else []
        now = time.time(); fixed = [_v291_stale_row(r, now) for r in (rows or []) if isinstance(r,dict)]
        active = [r for r in fixed if not r.get('snapshot_stale_hide_v291') and not r.get('snapshot_stale_review_v291')]
        out = active if active else fixed
        out.sort(key=lambda x:(safe_float(x.get('snapshot_rank_score',x.get('score',0)),0),safe_float(x.get('change_3',0),0)), reverse=True)
        for i,r in enumerate(out,1): r['snapshot_rank']=i
        RANK_STALE_V291_STATS['note'] = f'원본 {len(rows or [])} / 최신상위 {len(out)}'
        return out[:max(1,int(limit))]
    except Exception:
        return _V291_OLD_RANK_ROWS(limit=limit, min_move_pct=min_move_pct) if callable(_V291_OLD_RANK_ROWS) else []

def _v291_protecting():
    now=time.time(); out=[]
    for k,r in BTC_V291_CACHE.items():
        rem=safe_float(r.get('cool_until',0),0)-now
        if rem>0: out.append(f'{k} {int(rem)}초')
    return out

def build_scan_health_summary_line(display: dict = None, cache_age=None, api: dict = None, now_ts: float = None) -> str:
    base = _V291_OLD_SCAN_SUMMARY(display=display, cache_age=cache_age, api=api, now_ts=now_ts) if callable(_V291_OLD_SCAN_SUMMARY) else '상태 확인중'
    p = _v291_protecting()
    if p and ('API 병목' in str(base) or 'timeout' in str(base).lower()): return '보호 중: BTC OHLCV 쿨다운 적용 / ' + ', '.join(p[:3])
    if p: return str(base) + ' / BTC OHLCV 보호 ' + ', '.join(p[:2])
    return base

def build_scan_health_cached_text() -> str:
    base = str(_V291_OLD_SCAN_CACHED()) if callable(_V291_OLD_SCAN_CACHED) else '🩺 스캔 상태 진단 /scan_health'
    lines = _v291_btc_lines()
    if not lines: return base
    add = ['', '🧯 BTC OHLCV 보호(v2.5.291)', '- ' + ' / '.join(lines[:4]), '- 실패 직후 같은 BTC minute10/minute60/day를 반복 호출하지 않고 마지막 정상값을 재사용']
    return base.replace('\n[원칙]', '\n'+'\n'.join(add)+'\n[원칙]', 1) if '\n[원칙]' in base else base.rstrip()+'\n'+'\n'.join(add)

def build_cache_status_text():
    base = str(_V291_OLD_CACHE_STATUS()) if callable(_V291_OLD_CACHE_STATUS) else ''
    extra = ['', '🧯 v2.5.291 BTC OHLCV/오래된 후보 보호', f"- BTC캐시: hit {BTC_V291_STATS.get('hit',0)} / fetch {BTC_V291_STATS.get('fetch',0)} / fail {BTC_V291_STATS.get('fail',0)} / reuse {BTC_V291_STATS.get('reuse',0)} / cooldown {BTC_V291_STATS.get('cooldown',0)}", f"- BTC상태: {(' / '.join(_v291_btc_lines()[:4]) if _v291_btc_lines() else BTC_V291_STATS.get('last','대기'))}", f"- 스냅샷 오래됨 차단: 감점 {RANK_STALE_V291_STATS.get('penalty',0)} / 상위제한 {RANK_STALE_V291_STATS.get('hide',0)} / 복기전용 {RANK_STALE_V291_STATS.get('review',0)} / {RANK_STALE_V291_STATS.get('note','-')}", '- 쉬운 뜻: BTC 시장판단용 OHLCV 실패는 쿨다운+마지막 정상값으로 버티고, 오래된 후보는 상위에서 밀어낸다.']
    return base.rstrip() + '\n' + '\n'.join(extra)

def send_startup_message():
    lines=['✅ 봇 시작 완료',f'현재 버전: {BOT_VERSION}','',f"자동매수: {'켜짐' if AUTO_BUY else '꺼짐'}",f'운영시간: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00',f'주문 최대금액: {MAX_ENTRY_KRW:,}원','','이번 핵심 변경','- BTC minute10/minute60/day OHLCV 실패 반복 시 즉시 재호출하지 않고 쿨다운 적용','- BTC 리포트가 조회 실패를 +0.00%처럼 오해하지 않게 데이터 부족/마지막 정상값 재사용 표시','- 오래된 스냅샷 후보는 감점·상위노출 제한·복기전용으로 분리','- /scan_health와 /cache_status에 BTC OHLCV 보호 상태와 오래된 후보 차단 수치 표시','','자세한 설명은 /info']
    try: send('\n'.join(lines))
    except Exception: pass


# ============================================================
# v2.5.292 - batch /btc 허용 + BTC 시간대별 표시 + rank_compare rows 보호
# ============================================================
# 원인:
# 1) /btc는 단독 명령에는 등록되어 있었지만 /batch 실행 허용 목록에는 빠져 있었다.
# 2) BTC OHLCV cooldown 중 마지막 정상 시장판단을 재사용하면서, minute60/day가 없는 상태도
#    단기/중기/일봉이 같은 숫자처럼 보일 수 있었다.
# 3) /rank_compare가 rows 0 또는 소수 rows의 rank snapshot fallback을 정상 전체 앱식랭크처럼
#    표시하거나 정상 캐시를 덮는 흐름이 남아 있었다.
# 조치:
# - /batch 안 /btc 허용
# - BTC 단기/minute10, 중기/minute60, 일봉/day 표시를 각 interval 상태 기준으로 분리
# - rows 부족 결과는 정상 전체랭크가 아니라 임시 rank snapshot 비교로 표시
# - 직전 정상 전체랭크가 있으면 rows 0/소수 rows 결과로 덮지 않고 보존

try:
    import re as _V292_RE
except Exception:
    _V292_RE = None

V292_RANK_COMPARE_MIN_FULL_ROWS = 200
V292_RANK_COMPARE_KEEP_GOOD_SEC = 240.0
V292_STATS = {
    "rank_guard": 0,
    "rank_good_store": 0,
    "rank_rows0": 0,
    "rank_low_rows": 0,
    "rank_preserve_good": 0,
    "rank_fallback_mark": 0,
    "source_clean": 0,
    "batch_btc": 0,
    "btc_line_fix": 0,
    "last_rank_rows": 0,
    "last_rank_mode": "대기",
    "last_rank_note": "대기",
}
V292_LAST_GOOD_RANK_COMPARE = {"data": None, "text": "", "ts": 0.0, "rows": 0}


def _v292_inc(key, note=""):
    try:
        V292_STATS[key] = int(safe_float(V292_STATS.get(key, 0), 0)) + 1
        if note:
            V292_STATS["last_rank_note"] = str(note)[:180]
    except Exception:
        pass


def _v292_rank_rows_from_data(data) -> int:
    try:
        if not isinstance(data, dict):
            return 0
        rows = data.get("rows")
        if isinstance(rows, list):
            return len(rows)
        return int(safe_float(data.get("rows_count", data.get("row_count", 0)), 0))
    except Exception:
        return 0


def _v292_is_full_rank_data(data) -> bool:
    try:
        if not isinstance(data, dict):
            return False
        rows = _v292_rank_rows_from_data(data)
        source = str(data.get("source", "") or "").lower()
        if rows < int(V292_RANK_COMPARE_MIN_FULL_ROWS):
            return False
        if bool(data.get("rank_snapshot_only")) or bool(data.get("app_rank_preparing")):
            return False
        if "rank_snapshot" in source or "fallback" in source:
            return False
        return True
    except Exception:
        return False


def _v292_clean_source_text(value: str) -> str:
    try:
        s = str(value or "")
        if _V292_RE is None:
            return s
        before = s
        s = _V292_RE.sub(r"(rankfast)(?:\+rankfast)+", r"\1", s)
        s = _V292_RE.sub(r"(v289_rank_snapshot_fast)(?:\+rankfast)+", r"\1+rankfast", s)
        s = _V292_RE.sub(r"(v288_rank_snapshot_fallback)(?:\+rankfast)+", r"\1+rankfast", s)
        if s != before:
            _v292_inc("source_clean", "rankfast 중복 소스명 정리")
        return s
    except Exception:
        return str(value or "")


def _v292_mark_rank_text(text: str, data=None, reason: str = "") -> str:
    try:
        s = _v292_clean_source_text(text)
        rows = _v292_rank_rows_from_data(data)
        if _v292_is_full_rank_data(data):
            return s

        _v292_inc("rank_fallback_mark", f"fallback 표시 rows {rows}")

        # 먼저 기존 본문에서 정상 전체랭크처럼 보이는 표현을 완화한다.
        if rows < V292_RANK_COMPARE_MIN_FULL_ROWS:
            s = s.replace("전체 앱식 rows 0", "임시 rows 0")
            s = s.replace("전체 앱식캐시 rows 0", "임시 rows 0")
            s = s.replace("전체 앱식 rows ", "임시 앱식 rows ")
            s = s.replace("전체 앱식캐시 rows ", "임시 앱식캐시 rows ")
            s = s.replace("전체 앱식랭크", "임시 rank snapshot 비교")

        # 그 다음 v292 판정 문구를 넣어야 문구 자체가 replace에 훼손되지 않는다.
        if "v2.5.292 판정:" not in s:
            lines = s.splitlines()
            marker = (
                f"- v2.5.292 판정: 정상 전체 앱식랭크 아님 / rows {rows} / "
                f"임시 rank snapshot 비교"
                + (f" / 원인 {reason}" if reason else "")
            )
            insert_at = 1
            for i, line in enumerate(lines[:8]):
                if line.startswith("- 소스:") or line.startswith("- 기준:") or "명령어 직접계산" in line:
                    insert_at = i + 1
            lines.insert(insert_at, marker)
            s = "\n".join(lines)
        return s
    except Exception:
        return str(text or "")

def _v292_store_good_rank(data, text):
    try:
        rows = _v292_rank_rows_from_data(data)
        if _v292_is_full_rank_data(data) and text:
            V292_LAST_GOOD_RANK_COMPARE.update({
                "data": dict(data),
                "text": str(text),
                "ts": time.time(),
                "rows": rows,
            })
            _v292_inc("rank_good_store", f"정상 전체랭크 저장 rows {rows}")
    except Exception:
        pass


def _v292_get_good_rank():
    try:
        ts = safe_float(V292_LAST_GOOD_RANK_COMPARE.get("ts", 0), 0)
        age = time.time() - ts if ts > 0 else 999999
        if V292_LAST_GOOD_RANK_COMPARE.get("text") and age <= V292_RANK_COMPARE_KEEP_GOOD_SEC:
            return V292_LAST_GOOD_RANK_COMPARE.get("data"), V292_LAST_GOOD_RANK_COMPARE.get("text"), age
        cache = globals().get("RANK_COMPARE_V288_TEXT_CACHE", {})
        if isinstance(cache, dict):
            data = cache.get("data") if isinstance(cache.get("data"), dict) else None
            text = str(cache.get("text", "") or "")
            cts = safe_float(cache.get("ts", 0), 0)
            cage = time.time() - cts if cts > 0 else 999999
            if data and text and _v292_is_full_rank_data(data) and cage <= V292_RANK_COMPARE_KEEP_GOOD_SEC:
                V292_LAST_GOOD_RANK_COMPARE.update({"data": dict(data), "text": text, "ts": cts, "rows": _v292_rank_rows_from_data(data)})
                return data, text, cage
    except Exception:
        pass
    return None, "", 999999


try:
    _V292_OLD_V289_TEXT = _v289_text
except Exception:
    _V292_OLD_V289_TEXT = None

def _v289_text(data):
    raw = _V292_OLD_V289_TEXT(data) if callable(_V292_OLD_V289_TEXT) else "📈 순위 비교 /rank_compare\n- rank_compare 텍스트 생성 대기"
    rows = _v292_rank_rows_from_data(data)
    V292_STATS["last_rank_rows"] = rows
    if _v292_is_full_rank_data(data):
        V292_STATS["last_rank_mode"] = "full_rank"
        return _v292_clean_source_text(raw)
    if rows <= 0:
        _v292_inc("rank_rows0", "rows 0 fallback")
        V292_STATS["last_rank_mode"] = "rows0_fallback_text"
        return _v292_mark_rank_text(raw, data, "rows0")
    _v292_inc("rank_low_rows", f"low rows {rows}")
    V292_STATS["last_rank_mode"] = "low_rows_fallback_text"
    return _v292_mark_rank_text(raw, data, f"rows<{V292_RANK_COMPARE_MIN_FULL_ROWS}")


try:
    _V292_OLD_V289_STORE = _v289_store
except Exception:
    _V292_OLD_V289_STORE = None

def _v289_store(data, text, source):
    try:
        data = data if isinstance(data, dict) else {}
        source_clean = _v292_clean_source_text(source)
        if isinstance(data, dict):
            data = dict(data)
            data["source"] = _v292_clean_source_text(data.get("source", source_clean))
        text = _v292_clean_source_text(text)
        rows = _v292_rank_rows_from_data(data)
        V292_STATS["last_rank_rows"] = rows
        if _v292_is_full_rank_data(data):
            V292_STATS["last_rank_mode"] = "store_full_rank"
            _v292_store_good_rank(data, text)
            return _V292_OLD_V289_STORE(data, text, source_clean) if callable(_V292_OLD_V289_STORE) else None

        good_data, good_text, good_age = _v292_get_good_rank()
        if good_data and good_text:
            _v292_inc("rank_preserve_good", f"rows {rows} → 정상본 보존 {int(good_age)}초")
            V292_STATS["last_rank_mode"] = "preserve_good_rank"
            V292_STATS["last_rank_note"] = f"rows {rows} 결과가 정상 rows {_v292_rank_rows_from_data(good_data)} 캐시를 덮지 않음"
            try:
                gen = int(safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("generation", 0), 0)) + 1
                RANK_COMPARE_V288_TEXT_CACHE.update({
                    "ts": time.time(),
                    "text": good_text,
                    "data": good_data,
                    "source": "v292_preserve_good_rank",
                    "generation": gen,
                })
            except Exception:
                pass
            return None

        V292_STATS["last_rank_mode"] = "store_marked_fallback"
        marked = _v292_mark_rank_text(text, data, "no_good_full_rank")
        return _V292_OLD_V289_STORE(data, marked, source_clean) if callable(_V292_OLD_V289_STORE) else None
    except Exception as e:
        try:
            append_runtime_error_log("v292_rank_store_guard", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return _V292_OLD_V289_STORE(data, text, source) if callable(_V292_OLD_V289_STORE) else None


try:
    _V292_OLD_V289_GET_TEXT = _v289_get_text
except Exception:
    _V292_OLD_V289_GET_TEXT = None

def _v289_get_text():
    try:
        raw = _V292_OLD_V289_GET_TEXT() if callable(_V292_OLD_V289_GET_TEXT) else ""
        data = None
        try:
            cache = globals().get("RANK_COMPARE_V288_TEXT_CACHE", {})
            data = cache.get("data") if isinstance(cache, dict) and isinstance(cache.get("data"), dict) else None
        except Exception:
            data = None
        rows = _v292_rank_rows_from_data(data)
        V292_STATS["last_rank_rows"] = rows
        if _v292_is_full_rank_data(data):
            V292_STATS["last_rank_mode"] = "get_full_rank"
            _v292_store_good_rank(data, raw)
            return _v292_clean_source_text(raw)

        good_data, good_text, good_age = _v292_get_good_rank()
        if rows <= 0 and good_data and good_text:
            _v292_inc("rank_preserve_good", f"get rows0 → 정상본 {int(good_age)}초")
            V292_STATS["last_rank_mode"] = "get_preserve_good"
            return (
                "⚠️ /rank_compare 보호\n"
                f"- 이번 수집 rows 0이라 정상 전체랭크 캐시를 덮지 않았어.\n"
                f"- 아래는 {int(good_age)}초 전 정상 전체랭크 rows {_v292_rank_rows_from_data(good_data)} 보존본.\n\n"
                + _v292_clean_source_text(good_text)
            )

        if rows <= 0:
            _v292_inc("rank_rows0", "get rows 0")
            V292_STATS["last_rank_mode"] = "get_rows0_fallback"
            return _v292_mark_rank_text(raw, data, "rows0")
        if rows < V292_RANK_COMPARE_MIN_FULL_ROWS:
            _v292_inc("rank_low_rows", f"get low rows {rows}")
            V292_STATS["last_rank_mode"] = "get_low_rows_fallback"
            return _v292_mark_rank_text(raw, data, f"rows<{V292_RANK_COMPARE_MIN_FULL_ROWS}")
        return _v292_clean_source_text(raw)
    except Exception as e:
        try:
            append_runtime_error_log("v292_rank_get_text_guard", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return _V292_OLD_V289_GET_TEXT() if callable(_V292_OLD_V289_GET_TEXT) else "📈 순위 비교 /rank_compare\n- 출력 오류"


try:
    _V292_OLD_BUILD_RANK_COMPARE_TEXT = build_rank_compare_text_v279
except Exception:
    _V292_OLD_BUILD_RANK_COMPARE_TEXT = None

def build_rank_compare_text_v279(args=None, top_n:int=10):
    _v292_inc("rank_guard", "rank_compare wrapper")
