def _v292_btc_row_status(interval: str) -> dict:
    try:
        row = BTC_V291_CACHE.get(str(interval), {}) if isinstance(BTC_V291_CACHE, dict) else {}
        now = time.time()
        ok_ts = safe_float(row.get("ok_ts", 0), 0)
        age = now - ok_ts if ok_ts > 0 else -1
        rem = max(0.0, safe_float(row.get("cool_until", 0), 0) - now)
        df = row.get("df")
        has_df = _v291_ok_df(df, 20) if "_v291_ok_df" in globals() else False
        return {"row": row, "df": df, "has_df": has_df, "age": age, "rem": rem, "status": str(row.get("status", "대기") or "대기")}
    except Exception:
        return {"row": {}, "df": None, "has_df": False, "age": -1, "rem": 0, "status": "대기"}


def _v292_btc_change_from_df(df, bars: int):
    try:
        if df is None or len(df) <= bars:
            return None
        return get_recent_change_pct(df, bars)
    except Exception:
        return None


def _v292_format_btc_tf(label: str, interval: str, regime_value, bars: int) -> str:
    try:
        st = _v292_btc_row_status(interval)
        rem = safe_float(st.get("rem", 0), 0)
        age = safe_float(st.get("age", -1), -1)
        has_df = bool(st.get("has_df", False))
        status = str(st.get("status", "") or "")
        if rem > 0 and not has_df:
            _v292_inc("btc_line_fix", f"{interval} cooldown no data")
            return f"- {label}: 데이터 부족 / 쿨다운 {format_elapsed_text(rem)}"
        if has_df:
            val = _v292_btc_change_from_df(st.get("df"), bars)
            if val is None:
                val = regime_value
            if val is None:
                return f"- {label}: 데이터 부족"
            suffix = ""
            if rem > 0 or "reuse" in status or "cooldown" in status or "fail" in status:
                suffix = f" / 마지막 정상값 {format_elapsed_text(age)} 전 재사용" if age >= 0 else " / 마지막 정상값 재사용"
            return f"- {label}: {safe_float(val,0):+.2f}%{suffix}"
        if regime_value is None:
            return f"- {label}: 데이터 부족"
        if rem > 0 or status in {"cooldown", "fetch_fail", "cooldown_no_data", "fetch_fail_no_cache"}:
            _v292_inc("btc_line_fix", f"{interval} no df but regime value exists")
            return f"- {label}: 데이터 부족 / 쿨다운 중"
        return f"- {label}: {safe_float(regime_value,0):+.2f}%"
    except Exception:
        return f"- {label}: 데이터 부족"


