def analyze_btc_flow():
    try:
        r = get_market_regime()
        if not isinstance(r, dict):
            r = {}
        name = r.get("name", "UNKNOWN")
        state = {
            "BLOCK": "🚨 강한 하락",
            "WEAK": "⚠️ 약한 장",
            "SIDEWAYS": "😐 횡보",
            "STRONG_UP": "🔥 강한 상승",
            "UNKNOWN": "❔ 데이터 부족",
        }.get(name, "👍 보통")

        protecting = _v291_protecting() if "_v291_protecting" in globals() else []
        extra = "\n데이터 상태:\n- " + " / ".join(_v291_btc_lines()[:4]) if "_v291_btc_lines" in globals() and _v291_btc_lines() else ""
        status_line = ""
        if protecting:
            status_line = "\n- 데이터판단: BTC OHLCV 시간대별 보호 중 / 없는 시간대는 부족으로 표시"

        short_line = _v292_format_btc_tf("단기", "minute10", r.get("short_change_pct"), 6)
        mid_line = _v292_format_btc_tf("중기", "minute60", r.get("mid_change_pct"), 6)
        day_line = _v292_format_btc_tf("일봉", "day", r.get("day_change_pct"), 3)

        msg = str(r.get("message", "시장 상태 확인 중") or "시장 상태 확인 중")
        watch = str(r.get("watch_message", "기본 기준대로 보면 돼") or "기본 기준대로 보면 돼")
        if protecting and "마지막 정상" not in msg and "데이터 부족" not in msg:
            msg = "BTC OHLCV 일부 시간대 일시 불안정 / 시간대별 표시 분리"
        if protecting and "보호" not in watch:
            watch = "시장판단 보호중 · 진입은 보수 확인"

        return f"""
📊 BTC 리포트 (다중 시간대 기준)
📌 상태: {state}{status_line}
{short_line}
{mid_line}
{day_line}
한줄 해석:
{msg}
후보 해석:
{watch}{extra}
"""
    except Exception as e:
        try:
            append_runtime_error_log("v292_btc_report", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return _V292_OLD_ANALYZE_BTC_FLOW() if callable(_V292_OLD_ANALYZE_BTC_FLOW) else "📊 BTC 리포트\n- BTC 상태 출력 오류"


