def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    try:
        args = list(args or [])
        arg_preview = " ".join([str(x) for x in args]).strip()
        shown_cmd = f"/{cmd}" + (f" {arg_preview}" if arg_preview else "")
        label = f"▶️ 묶음 {idx}/{total} {shown_cmd}" if total > 1 else f"▶️ {shown_cmd}"
        c = str(cmd or "").lower().strip()
        if c in {"btc", "bitcoin"}:
            _v292_inc("batch_btc", "batch btc 허용")
            send_text_chunks(analyze_btc_flow(), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
            return
        if callable(_V292_OLD_EXECUTE_SINGLE_BATCH_COMMAND):
            return _V292_OLD_EXECUTE_SINGLE_BATCH_COMMAND(cmd, args, idx, total)
    except Exception as e:
        try:
            send(f"⚠️ 묶음 {idx}/{total} /{cmd} 처리 에러: {e}")
        except Exception:
            pass


