def _v293_inc_dict(d: dict, key: str, amount: int = 1):
    try:
        d[key] = int(safe_float(d.get(key, 0), 0)) + int(amount)
    except Exception:
        pass


def _v293_guess_caller(skip=None, max_depth: int = 18) -> str:
    try:
        skip = set(skip or [])
        skip.update({
            "_v293_guess_caller", "_v293_inc_dict", "_v293_record_ticker_caller",
            "_v293_record_btc_caller", "_record_api_call_caller",
        })
        frame = sys._getframe(2)
        depth = 0
        while frame is not None and depth < int(max_depth):
            name = str(frame.f_code.co_name or "")
            if name and name not in skip:
                return name[:90]
            frame = frame.f_back
            depth += 1
    except Exception:
        pass
    return "unknown"


def _v293_stack_names(max_depth: int = 22) -> list:
    names = []
    try:
        frame = sys._getframe(2)
        depth = 0
        while frame is not None and depth < int(max_depth):
            name = str(frame.f_code.co_name or "")
            if name:
                names.append(name)
            frame = frame.f_back
            depth += 1
    except Exception:
        pass
    return names


def _v293_record_ticker_caller(caller: str, result: str, count: int = 0):
    try:
        caller = str(caller or "unknown")[:90]
        result = str(result or "call")[:40]
        row = V293_TICKER_CALLER_STATS.setdefault(caller, {"count": 0, "fetch": 0, "blocked": 0, "cache": 0, "fallback": 0, "last": "", "last_ts": 0.0, "last_count": 0})
        row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
        row["last"] = result
        row["last_ts"] = time.time()
        row["last_count"] = int(safe_float(count, 0))
        if result in {"fetch", "fetch_allowed"}:
            row["fetch"] = int(safe_float(row.get("fetch", 0), 0)) + 1
        elif result in {"blocked", "fetch_blocked"}:
            row["blocked"] = int(safe_float(row.get("blocked", 0), 0)) + 1
        elif result in {"cache", "cache_read"}:
            row["cache"] = int(safe_float(row.get("cache", 0), 0)) + 1
        elif result in {"fallback", "fallback_read"}:
            row["fallback"] = int(safe_float(row.get("fallback", 0), 0)) + 1
        if len(V293_TICKER_CALLER_STATS) > 80:
            old = sorted(V293_TICKER_CALLER_STATS.items(), key=lambda kv: safe_float((kv[1] or {}).get("last_ts", 0), 0))[:10]
            for k, _v in old:
                V293_TICKER_CALLER_STATS.pop(k, None)
    except Exception:
        pass


def _v293_ticker_fetch_allowed(caller: str) -> bool:
    try:
        caller_l = str(caller or "").lower()
        names_l = [str(n or "").lower() for n in _v293_stack_names()]
        if caller in V293_TICKER_ALLOWED_FETCH_CALLERS:
            return True
        if any(n in V293_TICKER_ALLOWED_FETCH_CALLERS for n in names_l):
            return True
        if any(h in caller_l for h in V293_TICKER_FORBIDDEN_HINTS):
            return False
        if any(any(h in n for h in V293_TICKER_FORBIDDEN_HINTS) for n in names_l):
            return False
        # 애매한 호출은 fetch 금지. 티커 목록은 중앙 유니버스/시장 갱신만 새로 받는다.
        return False
    except Exception:
        return False


def _v293_get_cached_ticker_list():
    try:
        cached = [str(t or "").upper().strip() for t in list(globals().get("market_all_tickers", []) or []) if str(t or "").strip()]
        if cached:
            return cached
    except Exception:
        pass
    try:
        return [str(t or "").upper().strip() for t in list(DEFAULT_MARKET_TICKERS or []) if str(t or "").strip()]
    except Exception:
        return []


