def _v289_fast_fallback(rank=None, source="v293_rank_snapshot_fast"):
    data = _ORIG_V293_V289_FAST_FALLBACK(rank=rank, source=source) if callable(_ORIG_V293_V289_FAST_FALLBACK) else {}
    try:
        if isinstance(data, dict):
            diag = dict(data.get("rank_compare_diag_v293") or RANK_COMPARE_V293_DIAG)
            diag["fallback_used"] = True
            diag["final_rows"] = int(safe_float(diag.get("final_rows", 0), 0))
            diag["mode"] = "임시 rank snapshot 비교"
            diag["primary_reason"] = _v293_rank_primary_reason(diag)
            data["rank_compare_diag_v293"] = diag
            data["rank_snapshot_only"] = True
            data["app_rank_preparing"] = True
    except Exception:
        pass
    return data


def _v293_rank_diag_lines(data=None) -> list:
    try:
        d = {}
        if isinstance(data, dict) and isinstance(data.get("rank_compare_diag_v293"), dict):
            d = dict(data.get("rank_compare_diag_v293"))
        else:
            d = dict(RANK_COMPARE_V293_DIAG)
        final_rows = int(safe_float(d.get("final_rows", 0), 0))
        fallback = bool(d.get("fallback_used", False))
        mode = str(d.get("mode", "") or ("정상 전체 앱식랭크" if final_rows >= V293_RANK_COMPARE_MIN_FULL_ROWS and not fallback else "임시 rank snapshot 비교"))
        reason = str(d.get("primary_reason", "") or _v293_rank_primary_reason(d))
        lines = [
            "🧪 v2.5.293 rows 원인분해",
            f"- 전체 티커 {int(safe_float(d.get('total_tickers',0),0))} / 히스토리 {int(safe_float(d.get('history_items',0),0))} / 최신가 있음 {int(safe_float(d.get('latest_price',0),0))}",
            f"- 1분 기준가 있음 {int(safe_float(d.get('base_1m',0),0))} / 3분 기준가 있음 {int(safe_float(d.get('base_3m',0),0))} / 거래대금 있음 {int(safe_float(d.get('turnover',0),0))}",
            f"- 제외: stale {int(safe_float(d.get('stale_excluded',0),0))} / tail·cut {int(safe_float(d.get('tail_cut_excluded',0),0))} / lock busy {int(safe_float(d.get('lock_busy_excluded',0),0))}",
            f"- 최종 rows {final_rows} / fallback {'사용' if fallback else '미사용'} / 판정: {mode}",
            f"- 원인: {reason}",
        ]
        if final_rows < V293_RANK_COMPARE_MIN_FULL_ROWS or fallback:
            lines.append("- 주의: 정상 전체 앱식랭크 아님. 빗썸 앱식 전체랭크처럼 보면 안 되고 임시 rank snapshot 비교로만 본다.")
        return lines
    except Exception:
        return ["🧪 v2.5.293 rows 원인분해", "- 원인분해 표시 오류"]


try:
    _ORIG_V293_V289_TEXT = _v289_text
except Exception:
    _ORIG_V293_V289_TEXT = None


def _v289_text(data):
    raw = _ORIG_V293_V289_TEXT(data) if callable(_ORIG_V293_V289_TEXT) else "📈 순위 비교 /rank_compare\n- 출력 생성 대기"
    try:
        s = str(raw or "")
        if "🧪 v2.5.293 rows 원인분해" in s:
            return s
        add = _v293_rank_diag_lines(data)
        lines = s.splitlines()
        insert_at = 1
        for idx, line in enumerate(lines[:12]):
            if line.startswith("- 기준:") or "v2.5.292 판정:" in line:
                insert_at = idx + 1
        lines[insert_at:insert_at] = add
        return "\n".join(lines)
    except Exception:
        return raw


def _v293_record_btc_caller(kind: str, caller: str, result: str):
    try:
        key = f"{str(caller or 'unknown')[:70]}:{str(kind or '')[:20]}"
        row = BTC_V293_CALLER_STATS.setdefault(key, {"count": 0, "readonly_hit": 0, "readonly_miss": 0, "fetch_pass": 0, "last": "", "last_ts": 0.0})
        row["count"] = int(safe_float(row.get("count", 0), 0)) + 1
        row["last"] = str(result or "")[:80]
        row["last_ts"] = time.time()
        if result == "readonly_hit":
            row["readonly_hit"] = int(safe_float(row.get("readonly_hit", 0), 0)) + 1
        elif result == "readonly_miss":
            row["readonly_miss"] = int(safe_float(row.get("readonly_miss", 0), 0)) + 1
        elif result == "fetch_pass":
            row["fetch_pass"] = int(safe_float(row.get("fetch_pass", 0), 0)) + 1
        if len(BTC_V293_CALLER_STATS) > 80:
            old = sorted(BTC_V293_CALLER_STATS.items(), key=lambda kv: safe_float((kv[1] or {}).get("last_ts", 0), 0))[:10]
            for k, _v in old:
                BTC_V293_CALLER_STATS.pop(k, None)
    except Exception:
        pass


def _v293_btc_readonly_context() -> bool:
    try:
        if BTC_V293_READONLY_MODE:
            return True
        names = [str(n or "").lower() for n in _v293_stack_names()]
        readonly_hints = ("btc_command", "_execute_single_batch_command", "build_cache_status", "build_scan_health", "rank_compare", "command_cache", "review_dump", "review_pack")
        return any(any(h in n for h in readonly_hints) for n in names)
    except Exception:
        return False


try:
    _ORIG_V293_V291_GET_BTC_DF_CACHED = _v291_get_btc_df_cached
except Exception:
    _ORIG_V293_V291_GET_BTC_DF_CACHED = None


def _v291_get_btc_df_cached(interval, min_len=20):
    """v2.5.293: BTC OHLCV도 명령어/출력에서는 캐시만 읽고, 실제 fetch는 시장판단 경로에서만 허용한다."""
    caller = _v293_guess_caller(skip={"_v291_get_btc_df_cached"})
    interval = str(interval)
    BTC_V293_STATS["cached_calls"] = int(safe_float(BTC_V293_STATS.get("cached_calls", 0), 0)) + 1
    readonly = _v293_btc_readonly_context()
    if readonly:
        try:
            row = _v291_btc_row(interval)
            df = row.get("df")
            ok_ts = safe_float(row.get("ok_ts", 0), 0)
            age = time.time() - ok_ts if ok_ts > 0 else 999999.0
            if _v291_ok_df(df, min_len):
                BTC_V293_STATS["readonly_hit"] = int(safe_float(BTC_V293_STATS.get("readonly_hit", 0), 0)) + 1
                BTC_V293_STATS["fetch_block"] = int(safe_float(BTC_V293_STATS.get("fetch_block", 0), 0)) + 1
                BTC_V293_STATS["last"] = f"{caller}:{interval} 캐시읽기 {int(age)}초"
                _v293_record_btc_caller("df_cached", caller, "readonly_hit")
                return df, "v293_readonly_cache", age
            BTC_V293_STATS["readonly_miss"] = int(safe_float(BTC_V293_STATS.get("readonly_miss", 0), 0)) + 1
            BTC_V293_STATS["fetch_block"] = int(safe_float(BTC_V293_STATS.get("fetch_block", 0), 0)) + 1
            BTC_V293_STATS["last"] = f"{caller}:{interval} 캐시없음/판단보류"
            _v293_record_btc_caller("df_cached", caller, "readonly_miss")
            return None, "v293_readonly_no_cache", age
        except Exception:
            return None, "v293_readonly_error", 999999.0

    if callable(_ORIG_V293_V291_GET_BTC_DF_CACHED):
        before_fetch = int(safe_float(BTC_V291_STATS.get("fetch", 0), 0)) if isinstance(BTC_V291_STATS, dict) else 0
        df, st, age = _ORIG_V293_V291_GET_BTC_DF_CACHED(interval, min_len)
        after_fetch = int(safe_float(BTC_V291_STATS.get("fetch", 0), 0)) if isinstance(BTC_V291_STATS, dict) else before_fetch
        if after_fetch > before_fetch:
            BTC_V293_STATS["fetch_pass"] = int(safe_float(BTC_V293_STATS.get("fetch_pass", 0), 0)) + 1
            BTC_V293_STATS["last"] = f"{caller}:{interval} 중앙 fetch 허용"
            _v293_record_btc_caller("df_cached", caller, "fetch_pass")
        else:
            _v293_record_btc_caller("df_cached", caller, str(st or "cache"))
        return df, st, age
    return None, "v293_no_base", 999999.0


