def build_rank_compare_text_v279(args=None, top_n: int = 10):
    # v2.5.293: 명령어 순간 새 계산 금지. 기존 v292/v289 텍스트 캐시만 읽고 원인분해를 붙인다.
    txt = _ORIG_V293_BUILD_RANK_COMPARE_TEXT(args=args, top_n=top_n) if callable(_ORIG_V293_BUILD_RANK_COMPARE_TEXT) else _v289_get_text()
    try:
        data = None
        cache = globals().get("RANK_COMPARE_V288_TEXT_CACHE", {})
        if isinstance(cache, dict) and isinstance(cache.get("data"), dict):
            data = cache.get("data")
        if "🧪 v2.5.293 rows 원인분해" not in str(txt or ""):
            txt = _v289_text(data)
    except Exception:
        pass
    return txt


