def _v294_all_factory_tickers(hist: dict, ws_cache: dict, trade_cache: dict, bulk: dict, rank_state: dict) -> list:
    out = []
    seen = set()
    def add(x):
        t = _v294_norm_ticker(x)
        if not t or t in seen:
            return
        try:
            if "is_watch_excluded_ticker" in globals() and is_watch_excluded_ticker(t):
                return
        except Exception:
            pass
        seen.add(t)
        out.append(t)
    for source in (
        globals().get("market_all_tickers", []) or [],
        globals().get("market_universe", []) or [],
        hist.keys() if isinstance(hist, dict) else [],
        ws_cache.keys() if isinstance(ws_cache, dict) else [],
        trade_cache.keys() if isinstance(trade_cache, dict) else [],
        bulk.keys() if isinstance(bulk, dict) else [],
        rank_state.keys() if isinstance(rank_state, dict) else [],
        globals().get("DEFAULT_MARKET_TICKERS", []) or [],
    ):
        try:
            for x in list(source):
                add(x)
        except Exception:
            continue
    return out


def _v294_valid_price_rows(rows: list) -> list:
    try:
        valid = []
        for r0 in rows or []:
            if not isinstance(r0, dict):
                continue
            p = safe_float(r0.get("price", 0), 0)
            ts = safe_float(r0.get("ts", 0), 0)
            if p > 0 and ts > 0:
                valid.append({"price": p, "ts": ts, "turnover_hint": safe_float(r0.get("turnover_hint", 0), 0), "source": str(r0.get("source", "") or "")})
        valid.sort(key=lambda r: safe_float(r.get("ts", 0), 0))
        return valid[-180:]
    except Exception:
        return []


def _v294_price_at_or_before(rows: list, target_ts: float):
    try:
        if not rows:
            return 0.0, False, 0.0
        cand = None
        for r0 in rows:
            ts = safe_float(r0.get("ts", 0), 0)
            if ts <= target_ts:
                cand = r0
            else:
                break
        covered = cand is not None
        if cand is None:
            cand = rows[0]
        return safe_float(cand.get("price", 0), 0), bool(covered), safe_float(cand.get("ts", 0), 0)
    except Exception:
        return 0.0, False, 0.0


def _v294_change_info(rows: list, sec: int, price: float, now_ts: float) -> dict:
    out = {"value": 0.0, "ready": False, "base_age_sec": 0.0}
    try:
        price = safe_float(price, 0)
        if price <= 0 or not rows:
            return out
        base, covered, base_ts = _v294_price_at_or_before(rows, now_ts - int(sec))
        if base <= 0:
            return out
        age = max(0.0, now_ts - base_ts)
        ready = bool(covered and age >= max(30.0, int(sec) * 0.80))
        out.update({"value": round(((price - base) / base) * 100.0, 3), "ready": ready, "base_age_sec": round(age, 1)})
    except Exception:
        pass
    return out


def _v294_trade_summary_from_rows(rows: list, now_ts: float, window_sec: float = 60.0) -> dict:
    try:
        recent = [r for r in rows or [] if isinstance(r, dict) and now_ts - safe_float(r.get("ts", 0), 0) <= window_sec]
        if not recent:
            return {"count": 0, "amount": 0.0, "buy_count": 0, "sell_count": 0, "buy_ratio": 0.0, "label": "체결없음"}
        buy = [r for r in recent if str(r.get("side", "")) == "buy"]
        sell = [r for r in recent if str(r.get("side", "")) == "sell"]
        amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in recent)
        buy_amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in buy)
        sell_amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in sell)
        known_amount = buy_amount + sell_amount
        buy_ratio = (buy_amount / known_amount * 100.0) if known_amount > 0 else ((len(buy) / max(1, len(buy) + len(sell))) * 100.0 if (buy or sell) else 0.0)
        if len(recent) >= 8 and buy_ratio >= 62:
            label = "매수체결 우세"
        elif len(recent) >= 8 and buy_ratio <= 38 and (buy or sell):
            label = "매도체결 우세"
        elif len(recent) >= 5:
            label = "체결 활발"
        else:
            label = "체결 적음"
        return {"count": len(recent), "amount": amount, "buy_count": len(buy), "sell_count": len(sell), "buy_amount": buy_amount, "sell_amount": sell_amount, "buy_ratio": buy_ratio, "label": label, "window_sec": window_sec}
    except Exception:
        return {"count": 0, "amount": 0.0, "buy_ratio": 0.0, "label": "체결확인실패"}


def _v294_factory_row(ticker: str, hist_rows: list, ws_row: dict, trade_rows: list, bulk_price: float, rank_row: dict, now_ts: float) -> dict:
    ticker = _v294_norm_ticker(ticker)
    rows = _v294_valid_price_rows(hist_rows)
    price = 0.0
    price_source = ""
    price_ts = 0.0
    try:
        if isinstance(ws_row, dict) and now_ts - safe_float(ws_row.get("ts", 0), 0) <= max(20.0, safe_float(globals().get("WS_TICKER_CACHE_TTL_SEC", 20), 20) * 3):
            price = safe_float(ws_row.get("price", 0), 0)
            price_ts = safe_float(ws_row.get("ts", 0), 0)
            price_source = "ws_ticker"
    except Exception:
        pass
    if price <= 0 and safe_float(bulk_price, 0) > 0 and now_ts - safe_float(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_TS", 0), 0) <= max(60.0, safe_float(globals().get("LIGHT_SNAPSHOT_BULK_STALE_KEEP_SEC", 30), 30) * 4):
        price = safe_float(bulk_price, 0)
        price_ts = safe_float(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_TS", now_ts), now_ts)
        price_source = "bulk_cache"
    if price <= 0 and rows:
        price = safe_float(rows[-1].get("price", 0), 0)
        price_ts = safe_float(rows[-1].get("ts", 0), 0)
        price_source = str(rows[-1].get("source", "history") or "history")
    if price <= 0 and isinstance(rank_row, dict):
        price = safe_float(rank_row.get("price", rank_row.get("current_price", 0)), 0)
        price_ts = safe_float(rank_row.get("snapshot_rank_detected_ts", rank_row.get("updated_ts", 0)), 0)
        price_source = "rank_state"
    if price > 0 and (not rows or abs(safe_float(rows[-1].get("price", 0), 0) - price) > max(price * 0.000001, 1e-12) or now_ts - safe_float(rows[-1].get("ts", 0), 0) > 1.0):
        rows = rows + [{"ts": price_ts or now_ts, "price": price, "turnover_hint": safe_float((ws_row or {}).get("turnover", 0), 0), "source": price_source or "factory"}]
        rows = _v294_valid_price_rows(rows)
    ch1 = _v294_change_info(rows, 60, price, now_ts)
    ch3 = _v294_change_info(rows, 180, price, now_ts)
    ch5 = _v294_change_info(rows, 300, price, now_ts)
    ch10 = _v294_change_info(rows, 600, price, now_ts)
    ch15 = _v294_change_info(rows, 900, price, now_ts)
    prices_30 = [safe_float(r.get("price", 0), 0) for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 30 * 60 and safe_float(r.get("price", 0), 0) > 0]
    low30 = min(prices_30) if prices_30 else 0.0
    high30 = max(prices_30) if prices_30 else 0.0
    from_low = ((price - low30) / low30 * 100.0) if price > 0 and low30 > 0 else 0.0
    below_high = ((high30 - price) / high30 * 100.0) if price > 0 and high30 > 0 else 999.0
    turn_hints = [safe_float(r.get("turnover_hint", 0), 0) for r in rows if now_ts - safe_float(r.get("ts", 0), 0) <= 5 * 60 and safe_float(r.get("turnover_hint", 0), 0) > 0]
    turnover_hint = max(turn_hints) if turn_hints else safe_float((ws_row or {}).get("turnover", 0), 0)
    trade60 = _v294_trade_summary_from_rows(trade_rows, now_ts, 60.0)
    trade180 = _v294_trade_summary_from_rows(trade_rows, now_ts, 180.0)
    span = max(0.0, safe_float(rows[-1].get("ts", 0), 0) - safe_float(rows[0].get("ts", 0), 0)) if rows else 0.0
    row = {
        "ticker": ticker,
        "price": price,
        "current_price": price,
        "latest_ts": price_ts,
        "latest_price_source": price_source or "없음",
        "cache_source": "v294_data_factory",
        "factory_v294": True,
        "factory_stage": "1차기록",
        "snapshot_rows": len(rows),
        "snapshot_span_sec": round(span, 1),
        "snapshot_rank_detected_ts": price_ts or now_ts,
        "updated_ts": price_ts or now_ts,
        "change_1": ch1.get("value", 0), "change_1_ready": bool(ch1.get("ready", False)), "change_1_base_age_sec": ch1.get("base_age_sec", 0),
        "change_3": ch3.get("value", 0), "change_3_ready": bool(ch3.get("ready", False)), "change_3_base_age_sec": ch3.get("base_age_sec", 0),
        "change_5": ch5.get("value", 0), "change_5_ready": bool(ch5.get("ready", False)), "change_5_base_age_sec": ch5.get("base_age_sec", 0),
        "change_10": ch10.get("value", 0), "change_10_ready": bool(ch10.get("ready", False)),
        "change_15": ch15.get("value", 0), "change_15_ready": bool(ch15.get("ready", False)),
        "change_30": safe_float((rank_row or {}).get("change_30", 0), 0),
        "change_60": safe_float((rank_row or {}).get("change_60", 0), 0),
        "from_low": round(from_low, 2),
        "below_high": round(below_high, 2),
        "recent_30m_low_price": round(low30, 8),
        "recent_30m_high_price": round(high30, 8),
        "turnover": max(turnover_hint, safe_float(trade180.get("amount", 0), 0)),
        "turnover_hint": turnover_hint,
        "ws_trade_count_60s": int(safe_float(trade60.get("count", 0), 0)),
        "ws_trade_amount_60s": safe_float(trade60.get("amount", 0), 0),
        "ws_trade_buy_ratio_60s": safe_float(trade60.get("buy_ratio", 0), 0),
        "ws_trade_label_60s": str(trade60.get("label", "") or ""),
        "ws_trade_count_180s": int(safe_float(trade180.get("count", 0), 0)),
        "ws_trade_amount_180s": safe_float(trade180.get("amount", 0), 0),
        "ws_trade_buy_ratio_180s": safe_float(trade180.get("buy_ratio", 0), 0),
        "pre_alert_snapshot": {
            "chg_5m": safe_float(ch5.get("value", 0), 0),
            "chg_30m": safe_float((rank_row or {}).get("change_30", 0), 0),
            "from_30m_low_pct": round(from_low, 2),
            "below_30m_high_pct": round(below_high, 2),
            "recent_30m_low_price": round(low30, 8),
            "recent_30m_high_price": round(high30, 8),
            "snapshot_engine_used": True,
            "factory_v294": True,
        },
    }
    try:
        if isinstance(rank_row, dict):
            for k in ["snapshot_rank_score", "lite_score", "rank_watch_action", "final_candidate_action_v251", "final_candidate_state_v251", "low_structure_route_v244", "current_candle_label", "current_candle_code"]:
                if k in rank_row and k not in row:
                    row[k] = rank_row.get(k)
    except Exception:
        pass
    return row


def _v294_score_factory_row(row: dict, previous: dict = None) -> dict:
    try:
        row = row if isinstance(row, dict) else {}
        previous = previous if isinstance(previous, dict) else {}
        reasons = []
        worker_scores = {}
        ch1 = safe_float(row.get("change_1", 0), 0)
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch10 = safe_float(row.get("change_10", 0), 0)
        from_low = safe_float(row.get("from_low", 0), 0)
        below_high = safe_float(row.get("below_high", 999), 999)
        turnover = safe_float(row.get("turnover", 0), 0)
        tcnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        tamt = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        tcnt3 = int(safe_float(row.get("ws_trade_count_180s", 0), 0))
        tamt3 = safe_float(row.get("ws_trade_amount_180s", 0), 0)
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        span = safe_float(row.get("snapshot_span_sec", 0), 0)
        hist_n = int(safe_float(row.get("snapshot_rows", 0), 0))
        price = safe_float(row.get("price", 0), 0)
        latest_age = time.time() - safe_float(row.get("latest_ts", 0), 0) if safe_float(row.get("latest_ts", 0), 0) > 0 else 999999

        surge_score = 0.0
        if ch1 >= 0.25: surge_score += 0.8
        if ch3 >= 0.45: surge_score += 1.0
        if ch5 >= 0.75: surge_score += 0.8
        if ch1 >= 0.12 and ch3 >= 0.15: surge_score += 0.4
        if surge_score > 0:
            _v294_stage_reason_add(reasons, "급등형")
        worker_scores["급등형"] = round(surge_score, 2)

        money_score = 0.0
        if turnover >= 50_000_000: money_score += 1.2
        elif turnover >= 10_000_000: money_score += 0.7
        elif turnover >= 1_000_000: money_score += 0.35
        if tamt >= 5_000_000 or tamt3 >= 12_000_000: money_score += 0.8
        elif tamt >= 800_000 or tamt3 >= 2_000_000: money_score += 0.45
        if money_score > 0.3:
            _v294_stage_reason_add(reasons, "돈붙음")
        worker_scores["돈붙음"] = round(money_score, 2)

        trade_score = 0.0
        if tcnt >= 8: trade_score += 0.8
        elif tcnt >= 4: trade_score += 0.45
        if tcnt3 >= 12: trade_score += 0.4
        if buy >= 62 and tcnt >= 4: trade_score += 0.45
        if 0 < buy <= 38 and tcnt >= 6: trade_score -= 0.35
        if trade_score > 0.25:
            _v294_stage_reason_add(reasons, "체결증가")
        worker_scores["체결증가"] = round(trade_score, 2)

        low_score = 0.0
        if 0.05 <= from_low <= 2.8 and below_high >= 0.75 and span >= 180:
            low_score += 0.6
        if ch1 >= -0.05 and ch3 >= -0.10 and from_low <= 2.2 and below_high >= 1.0:
            low_score += 0.45
        if hist_n >= 8 and span >= 300 and abs(ch1) <= 0.20 and abs(ch3) <= 0.35 and tamt3 > 0:
            low_score += 0.25
        if low_score >= 0.6:
            _v294_stage_reason_add(reasons, "저점방어의심")
        worker_scores["저점방어의심"] = round(low_score, 2)

        restart_score = 0.0
        if 0.05 <= ch1 <= 0.55 and -0.05 <= ch3 <= 1.05 and below_high >= 0.80 and from_low <= 3.2:
            restart_score += 0.6
        if ch5 >= 0.15 and ch10 >= 0.05 and below_high >= 0.9:
            restart_score += 0.45
        if money_score > 0.6 and trade_score >= 0 and ch3 >= -0.05:
            restart_score += 0.25
        if restart_score >= 0.55:
            _v294_stage_reason_add(reasons, "재출발의심")
        worker_scores["재출발의심"] = round(restart_score, 2)

        repeat_score = 0.0
        prev_seen = int(safe_float(previous.get("factory_seen_count", 0), 0))
        if prev_seen >= 2:
            repeat_score += 0.35
        if bool(previous.get("stage2_candidate_v294", False)) and (ch1 >= -0.05 or ch3 >= -0.10):
            repeat_score += 0.35
        if repeat_score > 0:
            _v294_stage_reason_add(reasons, "반복감지")
        worker_scores["반복감지"] = round(repeat_score, 2)

        existing_score = 0.0
        if row.get("ticker") in (globals().get("RANK_STATE_BY_TICKER", {}) or {}):
            existing_score += 0.35
        try:
            if row.get("ticker") in (globals().get("INTERNAL_WATCH_TRACK_STATE", {}) or {}):
                existing_score += 0.45
        except Exception:
            pass
        if existing_score > 0:
            _v294_stage_reason_add(reasons, "기존감시")
        worker_scores["기존감시"] = round(existing_score, 2)

        recheck_score = 0.0
        if latest_age < DATA_FACTORY_V294_PRICE_FRESH_SEC and price > 0 and hist_n >= 2 and not reasons:
            recheck_score += 0.10
        if row.get("ticker") in DATA_FACTORY_V294_RECHECK:
            recheck_score += 0.25
        if recheck_score >= 0.25:
            _v294_stage_reason_add(reasons, "순환재검사")
        worker_scores["순환재검사"] = round(recheck_score, 2)

        total_score = surge_score + money_score + trade_score + low_score + restart_score + repeat_score + existing_score + recheck_score
        if price <= 0:
            miss_stage = "가격창고 부족"
        elif hist_n < 2 or span < 35:
            miss_stage = "가격히스토리 부족"
        elif not reasons:
            miss_stage = "1차 기록만 있음"
        elif total_score < 1.15:
            miss_stage = "2차 승격 약함"
        elif total_score < 2.40:
            miss_stage = "3차 정밀 대기"
        else:
            miss_stage = "3차 후보"
        stage2 = bool(reasons and total_score >= 0.65 and price > 0)
        stage3 = bool(stage2 and (
            total_score >= 2.40
            or (surge_score >= 1.2 and (money_score >= 0.7 or trade_score >= 0.6))
            or (restart_score >= 0.85 and money_score >= 0.7)
            or existing_score >= 0.45
        ))
        if stage2:
            row["factory_stage"] = "2차후보"
        if stage3:
            row["factory_stage"] = "3차정밀대상"
        row["factory_seen_count"] = prev_seen + 1
        row["factory_score_v294"] = round(total_score, 3)
        row["factory_worker_scores_v294"] = worker_scores
        row["factory_stage2_reasons_v294"] = reasons
        row["factory_stage2_reason_text_v294"] = "·".join(reasons)
        row["stage2_candidate_v294"] = stage2
        row["stage3_candidate_v294"] = stage3
        row["factory_miss_stage_v294"] = miss_stage
        row["factory_updated_ts_v294"] = time.time()
        base_score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", 0)), 0)
        row["snapshot_rank_score"] = round(max(base_score, total_score), 3)
        row["lite_score"] = round(max(safe_float(row.get("lite_score", 0), 0), total_score), 3)
        if reasons:
            row["primary_reason"] = row.get("primary_reason") or ("공장 " + "·".join(reasons[:3]))
        return row
    except Exception:
        return row


def _v294_refresh_stats(stage1: dict, stage2: dict, stage3: dict, all_tickers: list):
    try:
        DATA_FACTORY_V294_WORKER_COUNTS.clear()
        DATA_FACTORY_V294_WORKER_COUNTS.update({k: 0 for k in DATA_FACTORY_V294_WORKER_REASON_KEYS})
        miss_counts = {"가격창고 부족": 0, "가격히스토리 부족": 0, "1차 기록만 있음": 0, "2차 승격 약함": 0, "3차 정밀 대기": 0, "3차 후보": 0}
        for row in stage1.values():
            if not isinstance(row, dict):
                continue
            for r0 in row.get("factory_stage2_reasons_v294", []) or []:
                if r0 in DATA_FACTORY_V294_WORKER_COUNTS:
                    DATA_FACTORY_V294_WORKER_COUNTS[r0] += 1
            ms = str(row.get("factory_miss_stage_v294", "") or "")
            if ms:
                miss_counts[ms] = miss_counts.get(ms, 0) + 1
        DATA_FACTORY_V294_STATS.update({
            "total_tickers": len(all_tickers),
            "stage1_total": len(stage1),
            "price_warehouse": sum(1 for r in stage1.values() if safe_float((r or {}).get("price", 0), 0) > 0),
            "history_warehouse": sum(1 for r in stage1.values() if int(safe_float((r or {}).get("snapshot_rows", 0), 0)) >= 2),
            "base_1m": sum(1 for r in stage1.values() if bool((r or {}).get("change_1_ready", False))),
            "base_3m": sum(1 for r in stage1.values() if bool((r or {}).get("change_3_ready", False))),
            "base_5m": sum(1 for r in stage1.values() if bool((r or {}).get("change_5_ready", False))),
            "trade_warehouse": sum(1 for r in stage1.values() if int(safe_float((r or {}).get("ws_trade_count_60s", 0), 0)) > 0),
            "money_warehouse": sum(1 for r in stage1.values() if safe_float((r or {}).get("turnover", 0), 0) > 0),
            "state_warehouse": len(globals().get("RANK_STATE_BY_TICKER", {}) or {}),
            "recheck_warehouse": len(DATA_FACTORY_V294_RECHECK),
            "stage2_total": len(stage2),
            "stage3_total": len(stage3),
            "miss_price": miss_counts.get("가격창고 부족", 0),
            "miss_history": miss_counts.get("가격히스토리 부족", 0),
            "miss_trade": max(0, len(stage1) - sum(1 for r in stage1.values() if int(safe_float((r or {}).get("ws_trade_count_60s", 0), 0)) > 0)),
            "miss_stage2": miss_counts.get("2차 승격 약함", 0),
            "miss_stage3": miss_counts.get("3차 정밀 대기", 0),
            "miss_precision": len(stage3),
            "last_ts": time.time(),
        })
    except Exception:
        pass


def build_central_data_factory_v294(force: bool = False) -> dict:
    global DATA_FACTORY_V294_STAGE1, DATA_FACTORY_V294_STAGE2, DATA_FACTORY_V294_STAGE3
    global DATA_FACTORY_V294_LAST_BUILD_TS, DATA_FACTORY_V294_LAST_BUILD_SEC, DATA_FACTORY_V294_LAST_NOTE, DATA_FACTORY_V294_BUILD_COUNT, DATA_FACTORY_V294_ERROR_COUNT, DATA_FACTORY_V294_LAST_ERROR
    if not bool(globals().get("DATA_FACTORY_V294_ON", True)):
        return {}
    now_ts = time.time()
    try:
        with DATA_FACTORY_V294_LOCK:
            if (not force) and DATA_FACTORY_V294_STAGE1 and now_ts - safe_float(DATA_FACTORY_V294_LAST_BUILD_TS, 0) < DATA_FACTORY_V294_FULL_REBUILD_MIN_SEC:
                return dict(DATA_FACTORY_V294_STAGE1)
    except Exception:
        pass
    t0 = time.time()
    try:
        hist = _v294_copy_light_history()
        ws_cache = _v294_copy_ws_ticker_cache()
        trade_cache = _v294_copy_ws_trade_cache()
        bulk = _v294_copy_bulk_price_cache()
        rank_state = _v294_copy_rank_state()
        all_tickers = _v294_all_factory_tickers(hist, ws_cache, trade_cache, bulk, rank_state)
        old_stage1 = dict(DATA_FACTORY_V294_STAGE1) if isinstance(DATA_FACTORY_V294_STAGE1, dict) else {}
        stage1 = {}
        stage2 = {}
        stage3 = {}
        recheck_new = {}
        for t in all_tickers:
            row = _v294_factory_row(t, hist.get(t, []), ws_cache.get(t, {}), trade_cache.get(t, []), bulk.get(t, 0), rank_state.get(t, {}), now_ts)
            row = _v294_score_factory_row(row, previous=old_stage1.get(t, {}))
            stage1[t] = row
            if bool(row.get("stage2_candidate_v294", False)):
                stage2[t] = row
                recheck_new[t] = {"ticker": t, "ts": now_ts, "reason": row.get("factory_stage2_reason_text_v294", ""), "score": row.get("factory_score_v294", 0)}
            if bool(row.get("stage3_candidate_v294", False)):
                stage3[t] = row
        try:
            for tk, old in list(DATA_FACTORY_V294_RECHECK.items()):
                if isinstance(old, dict) and now_ts - safe_float(old.get("ts", 0), 0) <= DATA_FACTORY_V294_RECHECK_TTL_SEC and tk not in recheck_new:
                    recheck_new[tk] = old
        except Exception:
            pass
        try:
            stage3_sorted = sorted(stage3.items(), key=lambda kv: safe_float((kv[1] or {}).get("factory_score_v294", 0), 0), reverse=True)
            stage3 = dict(stage3_sorted[:max(1, int(DATA_FACTORY_V294_TARGET_STAGE3_MAX))])
        except Exception:
            pass
        _v294_refresh_stats(stage1, stage2, stage3, all_tickers)
        with DATA_FACTORY_V294_LOCK:
            DATA_FACTORY_V294_STAGE1 = stage1
            DATA_FACTORY_V294_STAGE2 = stage2
            DATA_FACTORY_V294_STAGE3 = stage3
            DATA_FACTORY_V294_RECHECK.clear()
            DATA_FACTORY_V294_RECHECK.update(recheck_new)
            DATA_FACTORY_V294_LAST_BUILD_TS = now_ts
            DATA_FACTORY_V294_LAST_BUILD_SEC = round(time.time() - t0, 4)
            DATA_FACTORY_V294_BUILD_COUNT += 1
            DATA_FACTORY_V294_LAST_NOTE = f"전체 {len(stage1)}개 / 2차 {len(stage2)}개 / 3차 {len(stage3)}개 / {DATA_FACTORY_V294_LAST_BUILD_SEC:.2f}s"
            DATA_FACTORY_V294_STATS["last_build_sec"] = DATA_FACTORY_V294_LAST_BUILD_SEC
        return dict(stage1)
    except Exception as e:
        DATA_FACTORY_V294_ERROR_COUNT += 1
        DATA_FACTORY_V294_LAST_ERROR = str(e)[:160]
        try:
            append_runtime_error_log("data_factory_v294", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return dict(DATA_FACTORY_V294_STAGE1) if isinstance(DATA_FACTORY_V294_STAGE1, dict) else {}


def _v294_factory_rows_for_rank_compare() -> list:
    try:
        build_central_data_factory_v294(force=False)
        with DATA_FACTORY_V294_LOCK:
            rows = [dict(v) for v in DATA_FACTORY_V294_STAGE1.values() if isinstance(v, dict)]
        return [r for r in rows if safe_float(r.get("price", 0), 0) > 0]
    except Exception:
        return []


def _v294_factory_rows_for_rank_source(limit: int = 70, min_move_pct: float = 0.25) -> list:
    try:
        build_central_data_factory_v294(force=False)
        with DATA_FACTORY_V294_LOCK:
            stage2 = [dict(v) for v in DATA_FACTORY_V294_STAGE2.values() if isinstance(v, dict)]
            stage1 = [dict(v) for v in DATA_FACTORY_V294_STAGE1.values() if isinstance(v, dict)]
        base = stage2 if stage2 else stage1
        rows = []
        for row in base:
            if safe_float(row.get("price", 0), 0) <= 0:
                continue
            strongest = max(
                safe_float(row.get("change_1", 0), 0), safe_float(row.get("change_3", 0), 0),
                safe_float(row.get("change_5", 0), 0), safe_float(row.get("change_10", 0), 0),
                safe_float(row.get("factory_score_v294", 0), 0) * 0.20,
            )
            if bool(row.get("stage2_candidate_v294", False)) or strongest >= safe_float(min_move_pct, 0.25):
                rows.append(row)
        rows.sort(key=lambda x: (
            safe_float(x.get("factory_score_v294", 0), 0),
            bool(x.get("stage3_candidate_v294", False)),
            safe_float(x.get("change_3", 0), 0),
            safe_float(x.get("change_1", 0), 0),
            safe_float(x.get("turnover", 0), 0),
        ), reverse=True)
        rows = rows[:max(1, int(limit))]
        for idx, row in enumerate(rows, start=1):
            row["snapshot_rank"] = idx
            row["factory_rank_v294"] = idx
            try:
                row = apply_precision_minute1_state_to_row(row) if 'apply_precision_minute1_state_to_row' in globals() else row
                row = apply_low_defense_quality_v248(row) if 'apply_low_defense_quality_v248' in globals() else row
                row = apply_high_rebreakout_hold_v248(row) if 'apply_high_rebreakout_hold_v248' in globals() else row
                row = apply_money_sustain_context(row) if 'apply_money_sustain_context' in globals() else row
                row = apply_rank_watch_chart_state(row) if 'apply_rank_watch_chart_state' in globals() else row
                row = apply_final_candidate_display_context_v251(row) if 'apply_final_candidate_display_context_v251' in globals() else row
                row["rank_watch_action"] = str(row.get("final_candidate_action_v251", "") or (realtime_rank_watch_action_label(row) if 'realtime_rank_watch_action_label' in globals() else row.get("factory_stage", "확인중")))
                if bool(row.get("stage3_candidate_v294", False)):
                    try:
                        queue_precision_minute1_chart_verify(row, reason="data_factory_v294_stage3")
                    except Exception:
                        pass
            except Exception:
                pass
            rows[idx - 1] = row
        return rows
    except Exception as e:
        try:
            append_runtime_error_log("data_factory_v294_rank_source", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return []


try:
    _ORIG_V294_GET_LIGHT_SNAPSHOT_RANK_ROWS = get_light_snapshot_rank_rows
except Exception:
    _ORIG_V294_GET_LIGHT_SNAPSHOT_RANK_ROWS = None


def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    global RANK_STATE_LAST_REUSE_COUNT, RANK_STATE_LAST_RECALC_COUNT, RANK_STATE_LAST_TOTAL_COUNT, RANK_STATE_LAST_BUILD_TS, RANK_STATE_LAST_NOTE
    t0 = time.time()
    try:
        rows = _v294_factory_rows_for_rank_source(limit=limit, min_move_pct=min_move_pct)
        RANK_STATE_LAST_REUSE_COUNT = len(rows)
        RANK_STATE_LAST_RECALC_COUNT = 0
        RANK_STATE_LAST_TOTAL_COUNT = int(DATA_FACTORY_V294_STATS.get("stage1_total", 0))
        RANK_STATE_LAST_BUILD_TS = time.time()
        RANK_STATE_LAST_NOTE = f"v294 공장기준 / 전체 {DATA_FACTORY_V294_STATS.get('stage1_total',0)} / 2차 {DATA_FACTORY_V294_STATS.get('stage2_total',0)} / 3차 {DATA_FACTORY_V294_STATS.get('stage3_total',0)} / 저장 {len(rows)}"
        globals()["RANK_SOURCE_LIGHT_CREATE_COUNT"] = len(rows)
        globals()["RANK_SOURCE_SKIPPED_COUNT"] = max(0, int(DATA_FACTORY_V294_STATS.get("stage1_total", 0)) - len(rows))
        globals()["RANK_SOURCE_PRECISION_MERGE_COUNT"] = int(DATA_FACTORY_V294_STATS.get("stage3_total", 0))
        globals()["RANK_SOURCE_STEP_LAST_TIMINGS"] = {"data_factory_v294": round(time.time() - t0, 3), "total": round(time.time() - t0, 3)}
        globals()["RANK_SOURCE_STEP_LAST_NOTE"] = f"data_factory_v294 {time.time() - t0:.2f}s"
        return rows
    except Exception as e:
        try:
            append_runtime_error_log("get_light_snapshot_rank_rows_v294", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        if callable(_ORIG_V294_GET_LIGHT_SNAPSHOT_RANK_ROWS):
            return _ORIG_V294_GET_LIGHT_SNAPSHOT_RANK_ROWS(limit=limit, min_move_pct=min_move_pct)
        return []


try:
    _ORIG_V294_V289_COLLECT_ROWS = _v289_collect_rows
except Exception:
    _ORIG_V294_V289_COLLECT_ROWS = None


def _v289_collect_rows():
    t0 = time.time()
    try:
        rows = _v294_factory_rows_for_rank_compare()
        rank = _v288_rank_rows() if "_v288_rank_rows" in globals() else []
        final_rows = len(rows)
        total = int(DATA_FACTORY_V294_STATS.get("total_tickers", 0))
        base1 = int(DATA_FACTORY_V294_STATS.get("base_1m", 0))
        base3 = int(DATA_FACTORY_V294_STATS.get("base_3m", 0))
        turnover = int(DATA_FACTORY_V294_STATS.get("money_warehouse", 0))
        try:
            _v293_update_rank_diag(
                total_tickers=total,
                history_items=int(DATA_FACTORY_V294_STATS.get("history_warehouse", 0)),
                latest_price=int(DATA_FACTORY_V294_STATS.get("price_warehouse", 0)),
                base_1m=base1,
                base_3m=base3,
                turnover=turnover,
                stale_excluded=0,
                tail_cut_excluded=0,
                lock_busy_excluded=0,
                final_rows=final_rows,
                fallback_used=False,
                copy_reason="v294_data_factory",
                cut=False,
            )
        except Exception:
            pass
        try:
            PAPER_V289_STATS.update({
                "items": total,
                "rows": final_rows,
                "fresh": final_rows,
                "no_valid": int(DATA_FACTORY_V294_STATS.get("miss_price", 0)),
                "no_latest": int(DATA_FACTORY_V294_STATS.get("miss_price", 0)),
                "stale": 0,
                "base_1m": base1,
                "base_3m": base3,
                "turnover_rows": turnover,
                "collect_sec": round(time.time() - t0, 4),
            })
        except Exception:
            pass
        return rows, rank, False, "v294_data_factory"
    except Exception as e:
        try:
            append_runtime_error_log("rank_compare_v294_collect", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        if callable(_ORIG_V294_V289_COLLECT_ROWS):
            return _ORIG_V294_V289_COLLECT_ROWS()
        return [], [], False, "v294_error"


