def _v295_norm_interval(interval: str) -> str:
    key = str(interval or "").lower().strip()
    aliases = {"1m": "minute1", "3m": "minute3", "5m": "minute5", "10m": "minute10", "15m": "minute15", "30m": "minute30", "60m": "minute60", "1h": "minute60", "4h": "minute240", "240m": "minute240", "1d": "day"}
    return aliases.get(key, key)


def _v295_interval_sec(interval: str) -> int:
    key = _v295_norm_interval(interval)
    for name, sec in FACTORY_V295_SELF_INTERVALS:
        if name == key:
            return int(sec)
    return 60


def _v295_connect_db():
    import sqlite3
    conn = sqlite3.connect(FACTORY_V295_DB_FILE, timeout=0.35)
    try:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA temp_store=MEMORY")
    except Exception:
        pass
    return conn


def _v295_init_db() -> bool:
    try:
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db()
            cur = conn.cursor()
            cur.execute("CREATE TABLE IF NOT EXISTS factory_meta (key TEXT PRIMARY KEY, value TEXT, updated_ts REAL)")
            cur.execute("""
                CREATE TABLE IF NOT EXISTS self_ohlcv (
                    ticker TEXT NOT NULL,
                    interval TEXT NOT NULL,
                    candle_start_ts INTEGER NOT NULL,
                    candle_end_ts INTEGER NOT NULL,
                    open REAL, high REAL, low REAL, close REAL,
                    volume REAL DEFAULT 0,
                    amount REAL DEFAULT 0,
                    buy_amount REAL DEFAULT 0,
                    sell_amount REAL DEFAULT 0,
                    sample_count INTEGER DEFAULT 0,
                    source TEXT,
                    confidence REAL DEFAULT 0,
                    closed INTEGER DEFAULT 0,
                    created_at REAL,
                    updated_at REAL,
                    PRIMARY KEY (ticker, interval, candle_start_ts)
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS ohlcv_verify (
                    ticker TEXT NOT NULL,
                    interval TEXT NOT NULL,
                    candle_start_ts INTEGER NOT NULL,
                    self_open REAL, self_high REAL, self_low REAL, self_close REAL,
                    rest_open REAL, rest_high REAL, rest_low REAL, rest_close REAL,
                    close_diff_pct REAL,
                    high_diff_pct REAL,
                    low_diff_pct REAL,
                    result TEXT,
                    note TEXT,
                    verified_at REAL,
                    PRIMARY KEY (ticker, interval, candle_start_ts)
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS factory_state_snapshot (
                    ticker TEXT PRIMARY KEY,
                    updated_ts REAL,
                    price REAL,
                    change_1 REAL,
                    change_3 REAL,
                    change_5 REAL,
                    change_10 REAL,
                    change_15 REAL,
                    from_low REAL,
                    below_high REAL,
                    turnover REAL,
                    trade_count_60 INTEGER,
                    trade_count_180 INTEGER,
                    factory_score REAL,
                    factory_stage TEXT,
                    stage2_reason TEXT,
                    data_confidence TEXT,
                    missing_info TEXT
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS miss_cause_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    ticker TEXT,
                    detected_ts REAL,
                    miss_stage TEXT,
                    reason TEXT,
                    action_taken TEXT,
                    raw_json TEXT
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS cleanup_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    cleaned_at REAL,
                    table_name TEXT,
                    interval TEXT,
                    deleted_rows INTEGER,
                    note TEXT
                )
            """)
            cur.execute("INSERT OR REPLACE INTO factory_meta(key,value,updated_ts) VALUES(?,?,?)", ("schema_version", str(FACTORY_V295_SCHEMA_VERSION), time.time()))
            cur.execute("INSERT OR REPLACE INTO factory_meta(key,value,updated_ts) VALUES(?,?,?)", ("bot_version", str(BOT_VERSION), time.time()))
            conn.commit()
            conn.close()
        FACTORY_V295_STATS["db_ok"] = True
        FACTORY_V295_STATS["schema_version"] = FACTORY_V295_SCHEMA_VERSION
        return True
    except Exception as e:
        FACTORY_V295_STATS["db_ok"] = False
        globals()["FACTORY_V295_LAST_ERROR"] = str(e)[:160]
        try:
            append_runtime_error_log("factory_v295_db_init", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return False


