# =========================================================
# v2.5.297 중앙창고 백그라운드 worker + 출력 가독성 정리
# =========================================================
# 목표
# - v295 자체봉/영구창고 방향은 유지한다.
# - 단, 자체봉 생성/DB저장/검증은 명령어 캐시 경로가 아니라 별도 worker에서 소량씩 처리한다.
# - /cache_status, /scan_health는 운영 중 읽기 쉽게 문단/들여쓰기 기준으로 정리한다.
# - BTC는 알트 후보 순위에서는 제외하고, /btc 시장판단 전용으로 둔다.

FACTORY_V297_BG_WORKER_ON = True
FACTORY_V297_BG_WORKER_STARTED = False
FACTORY_V297_BG_WORKER_THREAD = None
FACTORY_V297_BG_INTERVAL_SEC = 7.0
FACTORY_V297_BG_BATCH_SIZE = 24
FACTORY_V297_BG_TIME_BUDGET_SEC = 0.75
FACTORY_V297_VERIFY_PER_CYCLE = 2
FACTORY_V297_LAST_RUN_TS = 0.0
FACTORY_V297_LAST_RUN_SEC = 0.0
FACTORY_V297_LAST_NOTE = "대기"
FACTORY_V297_TOTAL_BATCHES = 0
FACTORY_V297_TOTAL_TICKERS = 0
FACTORY_V297_TOTAL_CANDLES = 0
FACTORY_V297_TOTAL_VERIFY = 0
FACTORY_V297_TOTAL_DB_ROWS = 0
FACTORY_V297_ERROR_COUNT = 0
FACTORY_V297_LAST_ERROR = ""
FACTORY_V297_CURSOR = 0
FACTORY_V297_BTC_ALT_FILTER_COUNT = 0
FACTORY_V297_PRETTY_OUTPUT_ON = True
FACTORY_V297_RANKFAST_BASE_FIX_ON = True
FACTORY_V297_DB_QUERY_CACHE = {"ts": 0.0, "counts": {}}

FACTORY_V297_EXCLUDE_ALT_RANK_TICKERS = {"BTC"}


def _v297_norm_ticker(ticker: str) -> str:
    try:
        if '_v294_norm_ticker' in globals():
            return _v294_norm_ticker(ticker)
        t = str(ticker or "").upper().strip()
        return t.replace("KRW-", "").replace("_KRW", "")
    except Exception:
        return str(ticker or "").upper().strip()


def _v297_is_btc(ticker: str) -> bool:
    return _v297_norm_ticker(ticker) in FACTORY_V297_EXCLUDE_ALT_RANK_TICKERS


def _v297_row_ticker(row) -> str:
    try:
        if isinstance(row, dict):
            return _v297_norm_ticker(row.get("ticker") or row.get("symbol") or row.get("market") or row.get("name"))
        return _v297_norm_ticker(row)
    except Exception:
        return ""


def _v297_get_stage1_tickers() -> list:
    """worker가 처리할 코인 풀. 명령어 경로에서는 호출되지 않는다."""
    try:
        seen = set(); out = []
        def add(x):
            t = _v297_norm_ticker(x)
            if not t or t in seen:
                return
            try:
                if 'is_watch_excluded_ticker' in globals() and is_watch_excluded_ticker(t):
                    return
            except Exception:
                pass
            seen.add(t); out.append(t)
        # 1순위: 최근 공장 기록판
        st1 = globals().get("DATA_FACTORY_V294_STAGE1", {})
        if isinstance(st1, dict):
            for k in st1.keys(): add(k)
        # 2순위: 가격 히스토리
        hist = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        if isinstance(hist, dict):
            for k in hist.keys(): add(k)
        # 3순위: 실시간 순위 상태
        rank_state = globals().get("RANK_STATE_BY_TICKER", {})
        if isinstance(rank_state, dict):
            for k in rank_state.keys(): add(k)
        # 4순위: 시장 목록
        for src in (globals().get("market_all_tickers", []) or [], globals().get("market_universe", []) or [], globals().get("DEFAULT_MARKET_TICKERS", []) or []):
            try:
                for k in list(src): add(k)
            except Exception:
                pass
        return out
    except Exception:
        return []


def _v297_pick_batch_tickers(pool: list, size: int) -> list:
    global FACTORY_V297_CURSOR
    try:
        arr = list(pool or [])
        if not arr:
            return []
        n = max(1, int(size))
        start = FACTORY_V297_CURSOR % len(arr)
        batch = []
        for i in range(min(n, len(arr))):
            batch.append(arr[(start + i) % len(arr)])
        FACTORY_V297_CURSOR = (start + len(batch)) % max(1, len(arr))
        return batch
    except Exception:
        return []


def _v297_get_price_history(ticker: str, max_rows: int = 240) -> list:
    try:
        t = _v297_norm_ticker(ticker)
        hist = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        lock = globals().get("LIGHT_SNAPSHOT_LOCK")
        aliases = [t, f"KRW-{t}", f"{t}_KRW"]
        if not isinstance(hist, dict):
            return []
        if lock is not None:
            with lock:
                for a in aliases:
                    rows = hist.get(a)
                    if isinstance(rows, list) and rows:
                        return list(rows[-max_rows:])
        else:
            for a in aliases:
                rows = hist.get(a)
                if isinstance(rows, list) and rows:
                    return list(rows[-max_rows:])
    except Exception:
        pass
    return []


def _v297_get_trade_history(ticker: str, max_rows: int = 240) -> list:
    try:
        t = _v297_norm_ticker(ticker)
        cache = globals().get("WS_TRADE_CACHE", {})
        lock = globals().get("WS_TRADE_LOCK")
        aliases = [t, f"KRW-{t}", f"{t}_KRW"]
        if not isinstance(cache, dict):
            return []
        if lock is not None:
            with lock:
                for a in aliases:
                    rows = cache.get(a)
                    if isinstance(rows, list) and rows:
                        return list(rows[-max_rows:])
        else:
            for a in aliases:
                rows = cache.get(a)
                if isinstance(rows, list) and rows:
                    return list(rows[-max_rows:])
    except Exception:
        pass
    return []


def _v297_insert_self_candles(ticker: str, candles: dict) -> int:
    """worker 전용. 자체봉을 DB에 소량 저장한다."""
    try:
        if not candles or '_v295_init_db' not in globals() or not _v295_init_db():
            return 0
        rows = []
        now_ts = time.time()
        for interval, c in (candles or {}).items():
            if not isinstance(c, dict):
                continue
            start = int(safe_float(c.get("candle_start_ts", 0), 0))
            if start <= 0:
                continue
            rows.append((
                _v297_norm_ticker(ticker), _v295_norm_interval(interval) if '_v295_norm_interval' in globals() else str(interval), start,
                int(safe_float(c.get("candle_end_ts", 0), 0)),
                safe_float(c.get("open", 0), 0), safe_float(c.get("high", 0), 0), safe_float(c.get("low", 0), 0), safe_float(c.get("close", 0), 0),
                safe_float(c.get("volume", 0), 0), safe_float(c.get("amount", 0), 0), safe_float(c.get("buy_amount", 0), 0), safe_float(c.get("sell_amount", 0), 0),
                int(safe_float(c.get("sample_count", 0), 0)), "self_v297_bg", safe_float(c.get("confidence", 0), 0), int(safe_float(c.get("closed", 0), 0)), now_ts, now_ts,
            ))
        if not rows:
            return 0
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db(); cur = conn.cursor()
            cur.executemany("""
                INSERT OR REPLACE INTO self_ohlcv(
                    ticker, interval, candle_start_ts, candle_end_ts, open, high, low, close, volume, amount, buy_amount, sell_amount,
                    sample_count, source, confidence, closed, created_at, updated_at
                ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, rows)
            conn.commit(); conn.close()
        return len(rows)
    except Exception as e:
        globals()["FACTORY_V297_LAST_ERROR"] = str(e)[:160]
        return 0


def _v297_try_verify_candles(ticker: str, candles: dict, max_verify: int = 1) -> int:
    try:
        checked = 0
        if '_v295_verify_self_candle_against_cached_rest' not in globals():
            return 0
        for interval, c in (candles or {}).items():
            if checked >= max(0, int(max_verify)):
                break
            if not isinstance(c, dict) or int(safe_float(c.get("closed", 0), 0)) != 1:
                continue
            cmp_row = _v295_verify_self_candle_against_cached_rest(_v297_norm_ticker(ticker), c)
            if isinstance(cmp_row, dict) and str(cmp_row.get("result", "")) not in {"no_cached_rest", ""}:
                try:
                    _v295_store_verify_result(_v297_norm_ticker(ticker), str(c.get("interval", interval)), int(safe_float(c.get("candle_start_ts", 0), 0)), c, cmp_row.get("rest", {}) if isinstance(cmp_row.get("rest"), dict) else {}, cmp_row)
                except Exception:
                    pass
                checked += 1
        return checked
    except Exception:
        return 0


def _v297_process_background_batch(force: bool = False) -> dict:
    global FACTORY_V297_LAST_RUN_TS, FACTORY_V297_LAST_RUN_SEC, FACTORY_V297_LAST_NOTE
    global FACTORY_V297_TOTAL_BATCHES, FACTORY_V297_TOTAL_TICKERS, FACTORY_V297_TOTAL_CANDLES, FACTORY_V297_TOTAL_VERIFY, FACTORY_V297_TOTAL_DB_ROWS, FACTORY_V297_ERROR_COUNT, FACTORY_V297_LAST_ERROR
    t0 = time.time()
    processed = 0; candles_n = 0; db_rows = 0; verifies = 0
    try:
        if not bool(globals().get("FACTORY_V297_BG_WORKER_ON", True)):
            FACTORY_V297_LAST_NOTE = "worker 꺼짐"
            return {"processed": 0}
        pool = _v297_get_stage1_tickers()
        batch = _v297_pick_batch_tickers(pool, FACTORY_V297_BG_BATCH_SIZE)
        for idx, ticker in enumerate(batch):
            if time.time() - t0 > FACTORY_V297_BG_TIME_BUDGET_SEC:
                FACTORY_V297_LAST_NOTE = "시간예산 도달 후 다음 사이클로 넘김"
                break
            hist_rows = _v297_get_price_history(ticker)
            if not hist_rows:
                continue
            trade_rows = _v297_get_trade_history(ticker)
            candles = _v295_build_self_candles_from_rows(_v297_norm_ticker(ticker), hist_rows, trade_rows=trade_rows, now_ts=time.time()) if '_v295_build_self_candles_from_rows' in globals() else {}
            if not candles:
                continue
            processed += 1
            candles_n += len(candles)
            db_rows += _v297_insert_self_candles(ticker, candles)
            # 검증은 아주 소량만. REST 캐시가 없으면 비용 없이 pass.
            if verifies < FACTORY_V297_VERIFY_PER_CYCLE and (idx % 7 == 0 or processed <= 2):
                verifies += _v297_try_verify_candles(ticker, candles, max_verify=max(0, FACTORY_V297_VERIFY_PER_CYCLE - verifies))
        FACTORY_V297_LAST_RUN_TS = time.time()
        FACTORY_V297_LAST_RUN_SEC = round(time.time() - t0, 3)
        FACTORY_V297_TOTAL_BATCHES += 1
        FACTORY_V297_TOTAL_TICKERS += processed
        FACTORY_V297_TOTAL_CANDLES += candles_n
        FACTORY_V297_TOTAL_DB_ROWS += db_rows
        FACTORY_V297_TOTAL_VERIFY += verifies
        if not FACTORY_V297_LAST_NOTE or "시간예산" not in FACTORY_V297_LAST_NOTE:
            FACTORY_V297_LAST_NOTE = f"{processed}개 처리 / 자체봉 {candles_n} / DB {db_rows} / 검증 {verifies}"
        try:
            FACTORY_V295_STATS["db_size_mb"] = _v295_db_size_mb() if '_v295_db_size_mb' in globals() else 0.0
            FACTORY_V295_STATS["persist_candles"] = int(FACTORY_V295_STATS.get("persist_candles", 0)) + db_rows
            FACTORY_V295_STATS["last_persist_ts"] = time.time() if db_rows else safe_float(FACTORY_V295_STATS.get("last_persist_ts", 0), 0)
        except Exception:
            pass
        return {"processed": processed, "candles": candles_n, "db_rows": db_rows, "verify": verifies}
    except Exception as e:
        FACTORY_V297_ERROR_COUNT += 1
        FACTORY_V297_LAST_ERROR = str(e)[:160]
        FACTORY_V297_LAST_NOTE = f"오류: {FACTORY_V297_LAST_ERROR}"
        try:
            append_runtime_error_log("factory_v297_bg_worker", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {"error": str(e)[:120]}


def _v297_background_loop():
    while True:
        try:
            time.sleep(max(1.0, safe_float(globals().get("FACTORY_V297_BG_INTERVAL_SEC", 7.0), 7.0)))
            _v297_process_background_batch(force=False)
        except Exception as e:
            globals()["FACTORY_V297_ERROR_COUNT"] = int(globals().get("FACTORY_V297_ERROR_COUNT", 0)) + 1
            globals()["FACTORY_V297_LAST_ERROR"] = str(e)[:160]
            time.sleep(3.0)


def _v297_start_background_worker_once():
    global FACTORY_V297_BG_WORKER_STARTED, FACTORY_V297_BG_WORKER_THREAD
    try:
        if FACTORY_V297_BG_WORKER_STARTED or not bool(globals().get("FACTORY_V297_BG_WORKER_ON", True)):
            return
        th = threading.Thread(target=_v297_background_loop, name="factory_v297_bg_worker", daemon=True)
        th.start()
        FACTORY_V297_BG_WORKER_THREAD = th
        FACTORY_V297_BG_WORKER_STARTED = True
    except Exception as e:
        globals()["FACTORY_V297_LAST_ERROR"] = str(e)[:160]


def _v297_db_interval_counts_cached() -> dict:
    try:
        now_ts = time.time()
        cache = globals().get("FACTORY_V297_DB_QUERY_CACHE", {})
        if isinstance(cache, dict) and now_ts - safe_float(cache.get("ts", 0), 0) < 20:
            return dict(cache.get("counts", {}) or {})
        if not os.path.exists(FACTORY_V295_DB_FILE):
            return {}
        out = {}
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db(); cur = conn.cursor()
            cur.execute("SELECT interval, COUNT(*) FROM self_ohlcv GROUP BY interval")
            for interval, cnt in cur.fetchall():
                out[str(interval)] = int(cnt or 0)
            conn.close()
        FACTORY_V297_DB_QUERY_CACHE = {"ts": now_ts, "counts": out}
        globals()["FACTORY_V297_DB_QUERY_CACHE"] = FACTORY_V297_DB_QUERY_CACHE
        return out
    except Exception:
        return {}


def _v297_status_lines(compact: bool = False) -> list:
    try:
        age = time.time() - safe_float(FACTORY_V297_LAST_RUN_TS, 0) if safe_float(FACTORY_V297_LAST_RUN_TS, 0) else 0
        counts = _v297_db_interval_counts_cached()
        db_mb = _v295_db_size_mb() if '_v295_db_size_mb' in globals() else 0.0
        lines = [
            "🧱 v2.5.297 중앙창고 worker / 출력정리",
            f"- worker: {'가동' if FACTORY_V297_BG_WORKER_STARTED else '대기'} / 최근 {format_elapsed_text(age) if age else '대기'} 전 / 최근 {FACTORY_V297_LAST_RUN_SEC:.2f}s / 배치 {FACTORY_V297_TOTAL_BATCHES}회",
            f"- 처리누적: 코인 {FACTORY_V297_TOTAL_TICKERS}개 / 자체봉 {FACTORY_V297_TOTAL_CANDLES}개 / DB저장 {FACTORY_V297_TOTAL_DB_ROWS}개 / 검증 {FACTORY_V297_TOTAL_VERIFY}개",
            f"- DB봉: 1m {counts.get('minute1',0)} / 3m {counts.get('minute3',0)} / 5m {counts.get('minute5',0)} / 15m {counts.get('minute15',0)} / 60m {counts.get('minute60',0)} / 4h {counts.get('minute240',0)} / day {counts.get('day',0)} / DB {db_mb:.2f}MB",
            f"- 최근 메모: {FACTORY_V297_LAST_NOTE}",
            "- 원칙: 명령어는 읽기 전용, 자체봉·DB·검증은 백그라운드에서 소량 처리",
        ]
        if FACTORY_V297_LAST_ERROR:
            lines.append(f"- 최근 오류: {FACTORY_V297_LAST_ERROR}")
        if not compact:
            lines.append("- BTC는 알트 후보 순위에서 제외하고 /btc 시장판단 전용으로 분리")
        return lines
    except Exception as e:
        return ["🧱 v2.5.297 중앙창고 worker / 출력정리", f"- 표시 오류: {e}"]


def _v297_filter_alt_rank_rows(rows: list) -> list:
    global FACTORY_V297_BTC_ALT_FILTER_COUNT
    try:
        out = []
        removed = 0
        for r in list(rows or []):
            t = _v297_row_ticker(r)
            if t in FACTORY_V297_EXCLUDE_ALT_RANK_TICKERS:
                removed += 1
                continue
            out.append(r)
        FACTORY_V297_BTC_ALT_FILTER_COUNT += removed
        return out
    except Exception:
        return rows or []

try:
    _ORIG_V297_GET_LIGHT_SNAPSHOT_RANK_ROWS = get_light_snapshot_rank_rows
except Exception:
    _ORIG_V297_GET_LIGHT_SNAPSHOT_RANK_ROWS = None

def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    rows = _ORIG_V297_GET_LIGHT_SNAPSHOT_RANK_ROWS(limit=limit + 2, min_move_pct=min_move_pct) if callable(_ORIG_V297_GET_LIGHT_SNAPSHOT_RANK_ROWS) else []
    rows = _v297_filter_alt_rank_rows(rows)
    return list(rows or [])[:max(1, int(limit))]

try:
    _ORIG_V297_V288_RANK_ROWS = _v288_rank_rows
except Exception:
    _ORIG_V297_V288_RANK_ROWS = None

def _v288_rank_rows():
    rows = _ORIG_V297_V288_RANK_ROWS() if callable(_ORIG_V297_V288_RANK_ROWS) else []
    return _v297_filter_alt_rank_rows(rows)


def _v297_pretty_line_expand(line: str) -> list:
    """운영 출력에서 긴 한 줄을 몇 줄로 쪼갠다."""
    try:
        s = str(line or "")
        if s.startswith("- 최근 캐시 단계별 소요:"):
            rest = s.split(":", 1)[1].strip()
            parts = [p.strip() for p in rest.split(",") if p.strip()]
            out = ["- 최근 캐시 단계별 소요"]
            for p in parts[:8]:
                out.append(f"  · {p}")
            return out
        if s.startswith("- WebSocket 현재가:") or s.startswith("- WebSocket 체결:"):
            title, rest = s.split(":", 1)
            parts = [p.strip() for p in rest.split("/") if p.strip()]
            out = [title + ":"]
            for p in parts[:7]:
                out.append(f"  · {p}")
            if len(parts) > 7:
                out.append("  · " + " / ".join(parts[7:]))
            return out
        if s.startswith("- rank 상태표:"):
            return ["- rank 상태표", "  · " + s.split(":",1)[1].strip()]
        if s.startswith("- rank 생성 카운터:"):
            return ["- rank 생성 카운터", "  · " + s.split(":",1)[1].strip()]
    except Exception:
        pass
    return [line]


def _v297_pretty_operational_text(text: str) -> str:
    if not bool(globals().get("FACTORY_V297_PRETTY_OUTPUT_ON", True)):
        return str(text or "")
    try:
        raw_lines = str(text or "").splitlines()
        section_heads = ("🌐 ", "📌 ", "운영 기준", "🗂 ", "🪶 ", "🧱 ", "🏭 ", "🗄 ", "🧪 ", "🧯 ", "[봇 계산", "[초입", "[우리 봇", "[비교", "[판단법]")
        out = []
        prev_blank = True
        for line in raw_lines:
            is_head = any(str(line).startswith(h) for h in section_heads)
            if is_head and out and out[-1] != "":
                out.append("")
            expanded = _v297_pretty_line_expand(line)
            for e in expanded:
                if e == "":
                    if out and out[-1] != "":
                        out.append("")
                else:
                    out.append(e)
        # 과한 연속 공백 제거
        compact = []
        for x in out:
            if x == "" and compact and compact[-1] == "":
                continue
            compact.append(x)
        return "\n".join(compact).strip()
    except Exception:
        return str(text or "")

