# =========================================================
# 목표
# - v297 worker 구조는 유지한다.
# - 운영 출력에서 헷갈리는 0 표시/기준가 표시/웹소켓 줄바꿈을 정리한다.
# - /batch 안에서 /today, /today_strategy를 지원해 오늘 승률을 바로 확인한다.
# - 과거 watchdog_hard_stale 로그는 현재 새 오류와 분리해서 표시한다.
# - 전략 조건, 자동매수, 손절/TP, rescue 조건은 건드리지 않는다.

FACTORY_V298_PRETTY_OUTPUT_ON = True
FACTORY_V298_TODAY_BATCH_ON = True
FACTORY_V298_ERRORLOG_CLEANUP_ON = True
FACTORY_V298_LABEL = "v2.5.298 오류/문구 정리"


def _v298_split_ws_line(line: str) -> list:
    """v297에서 '/' 기준으로 너무 잘게 쪼개지던 WebSocket 줄을 보기 좋게 다시 묶는다."""
    try:
        s = str(line or "")
        title, rest = s.split(":", 1)
        parts = [p.strip() for p in rest.split(" / ") if p.strip()]
        if not parts:
            return [line]
        out = [title + ":"]
        head = []
        for key in ("수신중", "중단", "연결", "끊김"):
            for p in parts:
                if p == key and p not in head:
                    head.append(p)
        mode = [p for p in parts if p.startswith("모드 ")]
        if mode:
            head.extend(mode[:1])
        if head:
            out.append("  · 상태 " + " / ".join(head))
        sub = [p for p in parts if p.startswith("구독 ")]
        active = [p for p in parts if p.startswith("활성 ")]
        recent = [p for p in parts if p.startswith("최근 ") and "건" not in p]
        line2 = []
        if sub: line2.append(sub[0])
        if active: line2.append(active[0])
        if recent: line2.append(recent[0])
        if line2:
            out.append("  · " + " / ".join(line2))
        metrics = []
        for p in parts:
            if p.startswith(("수신 ", "체결 ", "raw ", "미파싱 ")):
                metrics.append(p)
        if metrics:
            out.append("  · " + " / ".join(metrics[:4]))
        tail = []
        for p in parts:
            if p.startswith("최근 ") and "건" not in p and p not in recent[:1]:
                tail.append(p)
            elif p.startswith("60초 "):
                tail.append(p)
        if tail:
            out.append("  · " + " / ".join(tail))
        return out
    except Exception:
        return [line]


def _v297_pretty_line_expand(line: str) -> list:
    """v298: v297 가독성 함수 재정의. WebSocket slash 오분리 방지."""
    try:
        s = str(line or "")
        if s.startswith("- 최근 캐시 단계별 소요:"):
            rest = s.split(":", 1)[1].strip()
            parts = [p.strip() for p in rest.split(",") if p.strip()]
            out = ["- 최근 캐시 단계별 소요"]
            for p in parts[:8]:
                out.append(f"  · {p}")
            return out
        if s.startswith("- WebSocket 현재가:") or s.startswith("- WebSocket 체결:"):
            return _v298_split_ws_line(s)
        if s.startswith("- rank 상태표:"):
            return ["- rank 상태표", "  · " + s.split(":",1)[1].strip()]
        if s.startswith("- rank 생성 카운터:"):
            return ["- rank 생성 카운터", "  · " + s.split(":",1)[1].strip()]
    except Exception:
        pass
    return [line]


def _v298_clean_misleading_text(text: str) -> str:
    """라이트모드/worker 분리 이후 헷갈리는 구버전 카운터 문구를 보정한다."""
    try:
        s = str(text or "")
        s = re.sub(
            r"- rank_compare rows: 최종 0 / 최신가 0 / 1분기준 0 / 3분기준 0 / 원인 [^\n]+",
            "- rank_compare: 실제 순위 출력은 /rank_compare 기준 / 구카운터는 라이트모드에서 0 가능",
            s,
        )
        s = s.replace(
            "- 1분 기준가 있음 0 / 3분 기준가 있음 0 / 거래대금 있음",
            "- 자체봉 기준가: 대기 / 실제계산 rankfast·스냅샷 보조 / 거래대금 있음",
        )
        s = s.replace(
            "- 원인: 기준가 부족",
            "- 원인표시: 자체봉 창고 기준가 대기 / 실제 순위계산은 rankfast·스냅샷 보조값 사용",
        )
        s = s.replace(
            "🗄 v2.5.295 중앙 데이터 영구창고/자체봉",
            "🗄 v2.5.295 창고정책(명령어경로 제외)",
        )
        s = re.sub(
            r"- 자체봉 생성: 1m 0 / 3m 0 / 5m 0 / 10m 0 / 15m 0 / 30m 0 / 60m 0 / 4h 0 / day 0",
            "- 자체봉 생성: 명령어경로 0개 정상 / 실제 누적은 v297·v298 worker DB봉 확인",
            s,
        )
        s = re.sub(
            r"- 저장: 상태 0개 / 자체봉 ([0-9,]+)개 / 마지막 ([^\n]+)",
            r"- 저장: 명령어경로 상태 0개 / worker 저장 자체봉 \1개 / 마지막 \2",
            s,
        )
        s = s.replace(
            "- 검증: 같은 ticker+interval+candle_start_ts 닫힌 봉만 비교 / 누적 checked 0 / 통과 0 / 경고 0 / 불일치 0 / REST캐시없음 0",
            "- 검증: 명령어경로 0개 정상 / worker 검증 누적은 v297·v298 섹션 확인",
        )
        if "[watchdog_hard_stale]" in s and "현재 부팅 이후 새 오류 없음" in s and "과거 watchdog" not in s:
            s = s.replace(
                "- 과거 오류 tail은 요약만 표시함",
                "- 과거 오류 tail은 요약만 표시함\n- 과거 watchdog 기록은 현재 새 오류가 아니라 이전 병목 기록일 수 있음",
            )
        return s
    except Exception:
        return str(text or "")

