def build_cache_status_text():
    base = str(_ORIG_V298_BUILD_CACHE_STATUS_TEXT()) if callable(_ORIG_V298_BUILD_CACHE_STATUS_TEXT) else "🧊 명령어 캐시 상태 /cache_status"
