def _v299_fast_light_factory_row(ticker: str, hist_rows: list, ws_row: dict, trade_rows: list, bulk_price: float, rank_row: dict, now_ts: float) -> dict:
    t0 = time.time()
    try:
        if callable(_ORIG_V299_TRUE_BASE_FACTORY_ROW):
            row = _ORIG_V299_TRUE_BASE_FACTORY_ROW(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts)
        elif callable(_ORIG_V299_PREV_FACTORY_ROW):
            row = _ORIG_V299_PREV_FACTORY_ROW(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts)
            FACTORY_V299_STATS["fallback_row"] += 1
        else:
            row = {}
        if isinstance(row, dict):
            try:
                row = _v296_mark_light_row(row) if '_v296_mark_light_row' in globals() else row
            except Exception:
                pass
            row["factory_v299_fast_row"] = True
            row["self_ohlcv_source_v295"] = "v299_worker_only"
            row["self_ohlcv_confidence_text_v295"] = "자체봉은 뒤 작업자가 창고에 저장 중 / 순위 공장은 가벼운 정보만 사용"
            row["data_confidence_v295"] = "창고 worker 분리"
        FACTORY_V299_STATS["fast_row"] += 1
        FACTORY_V299_STATS["row_sec"] += max(0.0, time.time() - t0)
        return row if isinstance(row, dict) else {}
    except Exception as e:
        FACTORY_V299_STATS["fallback_row"] += 1
        try:
            append_runtime_error_log("factory_v299_fast_row", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {}

def _v294_factory_row(ticker: str, hist_rows: list, ws_row: dict, trade_rows: list, bulk_price: float, rank_row: dict, now_ts: float) -> dict:
    if bool(globals().get("FACTORY_V299_FAST_ROW_ON", True)):
        return _v299_fast_light_factory_row(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts)
    return _ORIG_V299_PREV_FACTORY_ROW(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts) if callable(_ORIG_V299_PREV_FACTORY_ROW) else {}

try:
    _ORIG_V299_BUILD_FACTORY = build_central_data_factory_v294
except Exception:
    _ORIG_V299_BUILD_FACTORY = None

def build_central_data_factory_v294(force: bool = False) -> dict:
    t0 = time.time()
    try:
        now_ts = t0
        cached = globals().get("DATA_FACTORY_V294_STAGE1", {})
        last_ts = safe_float(globals().get("DATA_FACTORY_V294_LAST_BUILD_TS", 0), 0)
        reuse_sec = safe_float(globals().get("FACTORY_V296_FACTORY_REUSE_SEC", 45.0), 45.0)
        if (not force) and isinstance(cached, dict) and cached and last_ts > 0 and now_ts - last_ts < reuse_sec:
            FACTORY_V299_STATS["factory_reuse"] += 1
            FACTORY_V299_STATS["last_factory_sec"] = 0.0
            FACTORY_V299_STATS["last_factory_note"] = f"완성본 재사용({format_elapsed_text(now_ts-last_ts)} 전)"
            return dict(cached)
        got = False
        if bool(globals().get("FACTORY_V299_DEDUP_FACTORY_BUILD_ON", True)):
            got = FACTORY_V299_BUILD_LOCK.acquire(False)
            if not got:
                FACTORY_V299_STATS["factory_busy_reuse"] += 1
                FACTORY_V299_STATS["last_factory_note"] = "다른 공장 생성 중이라 마지막 완성본 사용"
                return dict(cached) if isinstance(cached, dict) else {}
        try:
            out = _ORIG_V299_BUILD_FACTORY(force=force) if callable(_ORIG_V299_BUILD_FACTORY) else (dict(cached) if isinstance(cached, dict) else {})
            sec = max(0.0, time.time() - t0)
            FACTORY_V299_STATS["factory_build"] += 1
            FACTORY_V299_STATS["last_factory_sec"] = round(sec, 3)
            avg_row_ms = (FACTORY_V299_STATS["row_sec"] / max(1, FACTORY_V299_STATS["fast_row"])) * 1000.0
            FACTORY_V299_STATS["last_factory_note"] = f"빠른 row 공장 생성 {sec:.2f}s / row평균 {avg_row_ms:.2f}ms"
            FACTORY_V299_STATS["last_root_fix"] = "v295 자체봉 row 생성 우회 적용"
            return out if isinstance(out, dict) else {}
        finally:
            if got:
                try: FACTORY_V299_BUILD_LOCK.release()
                except Exception: pass
    except Exception as e:
        FACTORY_V299_STATS["last_factory_note"] = f"오류: {str(e)[:80]}"
        try:
            append_runtime_error_log("factory_v299_build", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        cached = globals().get("DATA_FACTORY_V294_STAGE1", {})
        return dict(cached) if isinstance(cached, dict) else {}

def _v299_easy_terms_text(text: str) -> str:
    if not bool(globals().get("FACTORY_V299_EASY_LABEL_ON", True)):
        return str(text or "")
    try:
        s = str(text or "")
        repl = {
            "PF": "수익/손실 균형",
            "strict_signal": "실전급 후보",
            "loose_threshold_test": "문턱 낮춘 실험 후보",
            "v274_preview_bridge_prepare": "관심 후보→진입 대기",
            "v275_order_flow_prepare": "체결흐름 진입 대기",
            "preheat_preview_test": "예열 관심 후보",
            "now_recheck_exit_v267": "바로 진입 후 힘 부족 정리",
            "open_recheck_exit_v267": "보유 중 신호악화 정리",
            "protect_recheck_exit_v267": "수익 후 약해져서 보호청산",
            "early_pending_cancel_v267": "대기 중 신호악화 취소",
            "entry_precheck_cancel_v266": "진입 직전 힘빠짐 취소",
            "pending_timeout": "대기 시간초과",
            "BUY_OK": "바로 사는 후보",
            "PULLBACK_WAIT": "눌림 대기 후보",
            "BREAKOUT_WAIT": "돌파 대기 후보",
            "now": "바로 진입형",
            "pullback": "눌림형",
            "breakout": "돌파형",
        }
        for a,b in repl.items():
            s = s.replace(a, b)
        return s
    except Exception:
        return str(text or "")

