def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    args = list(args or [])
    cmd_l = str(cmd or '').lower().strip()
    arg_preview = ' '.join([str(x) for x in args]).strip()
    shown_cmd = f"/{cmd_l}" + (f" {arg_preview}" if arg_preview else "")
    label = f"▶️ 묶음 {idx}/{total} {shown_cmd}" if total > 1 else f"▶️ {shown_cmd}"
    if cmd_l in {'paper_stats_full', 'paper_full'}:
        FACTORY_V299_STATS["batch_full_supported"] += 1
        send_text_chunks(build_paper_stats_full_text_v277(), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if cmd_l in {'paper_recent_full', 'paper_log_full'}:
        FACTORY_V299_STATS["batch_full_supported"] += 1
        send_text_chunks(build_paper_recent_full_text_v277(limit=20), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_ORIG_V299_EXECUTE_SINGLE_BATCH_COMMAND):
        return _ORIG_V299_EXECUTE_SINGLE_BATCH_COMMAND(cmd, args, idx, total)
    send(f"{label}\n- batch 처리 원본 함수를 찾지 못했어")

