    sec = max(0.0, time.time() - t0)
    try:
        FACTORY_V300_STATS["rank_compare_calls"] += 1
        FACTORY_V300_STATS["rank_compare_total_sec"] += sec
        FACTORY_V300_STATS["rank_compare_last_sec"] = round(sec, 3)
        FACTORY_V300_STATS["rank_compare_last_rows"] = _v300_extract_rows_from_rank_compare_text(str(txt or ""))
    except Exception:
        pass
    return _v297_pretty_operational_text(txt) if '_v297_pretty_operational_text' in globals() else txt


