def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    args = list(args or [])
    cmd_l = str(cmd or '').lower().strip()
    arg_preview = ' '.join([str(x) for x in args]).strip()
    shown_cmd = f"/{cmd_l}" + (f" {arg_preview}" if arg_preview else "")
    label = f"▶️ 묶음 {idx}/{total} {shown_cmd}" if total > 1 else f"▶️ {shown_cmd}"
    if cmd_l in {'cache_status_full', 'cache_full', 'cache_detail', 'cache_status_detail'}:
        FACTORY_V300_STATS["cache_full_batch"] += 1
        send_text_chunks(build_cache_status_full_text(), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_ORIG_V300_EXECUTE_SINGLE_BATCH_COMMAND):
        return _ORIG_V300_EXECUTE_SINGLE_BATCH_COMMAND(cmd, args, idx, total)
    send(f"{label}\n- batch 처리 원본 함수를 찾지 못했어")


