# =========================================================
# v2.5.302: 취소 후 놓침 추적 + PENDLE류 강제감시 + 바로진입 문턱 재분리
# =========================================================
# 원칙:
# - 전체 조건을 조이는 수정이 아니다.
# - 잘 버린 취소는 기본 출력에서 숨기고, 취소 뒤 실제로 간 후보만 따로 보여준다.
# - 앱/스크린샷에서 보인 코인이 유니버스 밖에 있으면 detail 조회만으로 감시풀에 강제 등록한다.
# - 바로진입형은 너무 강한 조건 하나로만 보지 않고, 강한 직행/준비확인/구경으로 다시 나눈다.
PAPER_CANCEL_WATCH_FILE_V302 = data_file("paper_cancel_watch_v302.json")
PAPER_CANCEL_WATCH_TTL_SEC_V302 = 60 * 60
PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302 = 0.70
PAPER_CANCEL_WATCH_STRONG_UP_PCT_V302 = 1.50
PAPER_CANCEL_WATCH_MAX_ITEMS_V302 = 260
PAPER_CANCEL_WATCH_DEFAULT_LIMIT_V302 = 4
PAPER_CANCEL_WATCH_FULL_LIMIT_V302 = 20
PAPER_CANCEL_WATCH_LOCK_V302 = threading.RLock()
PAPER_CANCEL_WATCH_STATE_V302 = {}
PAPER_CANCEL_WATCH_LOADED_V302 = False
DETAIL_FORCE_RANK_TRACK_TTL_SEC_V302 = 60 * 60
PAPER_V302_STATS = {
    "cancel_watch_added": 0,
    "cancel_watch_updated": 0,
    "cancel_watch_important": 0,
    "cancel_watch_hidden_good_drop": 0,
    "detail_force_track": 0,
    "detail_force_cache": 0,
    "detail_force_trace": 0,
    "now_direct_relaxed": 0,
    "now_prepare_relaxed": 0,
    "recent_compact": 0,
    "last_note": "대기",
}


def _v302_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V302_STATS:
            PAPER_V302_STATS[key] = int(safe_float(PAPER_V302_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V302_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v302_load_cancel_watch_state(force: bool = False) -> dict:
    global PAPER_CANCEL_WATCH_LOADED_V302, PAPER_CANCEL_WATCH_STATE_V302
    try:
        with PAPER_CANCEL_WATCH_LOCK_V302:
            if PAPER_CANCEL_WATCH_LOADED_V302 and not force:
                return PAPER_CANCEL_WATCH_STATE_V302
            raw = load_json_file(PAPER_CANCEL_WATCH_FILE_V302, {})
            if not isinstance(raw, dict):
                raw = {}
            rows = raw.get("rows", raw)
            if isinstance(rows, list):
                rows = {str(x.get("key", i)): dict(x) for i, x in enumerate(rows) if isinstance(x, dict)}
            if not isinstance(rows, dict):
                rows = {}
            PAPER_CANCEL_WATCH_STATE_V302 = {str(k): dict(v) for k, v in rows.items() if isinstance(v, dict)}
            PAPER_CANCEL_WATCH_LOADED_V302 = True
            return PAPER_CANCEL_WATCH_STATE_V302
    except Exception as e:
        try: append_runtime_error_log("v302_cancel_watch_load", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {}


def _v302_save_cancel_watch_state():
    global PAPER_CANCEL_WATCH_STATE_V302
    try:
        with PAPER_CANCEL_WATCH_LOCK_V302:
            rows = dict(PAPER_CANCEL_WATCH_STATE_V302 or {})
        now_ts = time.time()
        # 오래된 행과 의미 없는 행은 파일에서 정리한다. 단, 크게 간 놓침 표본은 조금 더 남긴다.
        cleaned = {}
        for k, r in rows.items():
            if not isinstance(r, dict):
                continue
            cancel_ts = safe_float(r.get("cancel_ts", 0), 0)
            max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
            keep_sec = PAPER_CANCEL_WATCH_TTL_SEC_V302 * (3 if max_up >= PAPER_CANCEL_WATCH_STRONG_UP_PCT_V302 else 1)
            if cancel_ts > 0 and now_ts - cancel_ts > keep_sec:
                continue
            cleaned[str(k)] = dict(r)
        if len(cleaned) > PAPER_CANCEL_WATCH_MAX_ITEMS_V302:
            ordered = sorted(cleaned.items(), key=lambda kv: (safe_float(kv[1].get("max_up_after_cancel_pct", 0), 0), safe_float(kv[1].get("cancel_ts", 0), 0)), reverse=True)
            cleaned = dict(ordered[:PAPER_CANCEL_WATCH_MAX_ITEMS_V302])
        with PAPER_CANCEL_WATCH_LOCK_V302:
            PAPER_CANCEL_WATCH_STATE_V302 = cleaned
        save_json_file(PAPER_CANCEL_WATCH_FILE_V302, {"schema": "paper_cancel_watch_v302", "updated_ts": now_ts, "rows": cleaned})
    except Exception as e:
        try: append_runtime_error_log("v302_cancel_watch_save", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v302_cancel_watch_key(pos_id: str, pos: dict, now_ts: float) -> str:
    ticker = str((pos or {}).get("ticker", "") or "").upper().strip()
    pid = str(pos_id or (pos or {}).get("id", "") or "")
    created = int(safe_float((pos or {}).get("created_ts", now_ts), now_ts))
    return f"{ticker}:{pid}:{created}"


def _v302_track_cancelled_candidate(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    try:
        now_ts = safe_float(now_ts, time.time())
        pos = dict(pos or {})
        ticker = str(pos.get("ticker", "") or "").upper().strip()
        if not ticker:
            return
        cancel_price = safe_float(pos.get("last_price", 0), 0)
        if cancel_price <= 0:
            cancel_price = safe_float(pos.get("planned_entry_high", pos.get("planned_entry_low", 0)), 0)
        if cancel_price <= 0:
            return
        key = _v302_cancel_watch_key(pos_id, pos, now_ts)
        row = {
            "key": key,
            "ticker": ticker,
            "id": str(pos.get("id", pos_id) or pos_id),
            "cancel_ts": now_ts,
            "created_ts": safe_float(pos.get("created_ts", now_ts), now_ts),
            "cancel_price": cancel_price,
            "last_price": cancel_price,
            "max_price_after_cancel": cancel_price,
            "min_price_after_cancel": cancel_price,
            "max_up_after_cancel_pct": 0.0,
            "min_after_cancel_pct": 0.0,
            "seconds_to_high": 0,
            "close_reason": str(reason or pos.get("close_reason", "cancel")),
            "lane": str(pos.get("lane", "") or ""),
            "entry_rule": str(pos.get("entry_rule", "") or ""),
            "score": safe_float(pos.get("score", 0), 0),
            "money_amount": safe_float(pos.get("money_amount", 0), 0),
            "trade_count": int(safe_float(pos.get("trade_count", 0), 0)),
            "buy_ratio": safe_float(pos.get("buy_ratio", 0), 0),
            "active": True,
            "important": False,
        }
        _v302_load_cancel_watch_state()
        with PAPER_CANCEL_WATCH_LOCK_V302:
            PAPER_CANCEL_WATCH_STATE_V302[key] = row
        _v302_inc("cancel_watch_added", f"취소후추적 등록 {ticker}")
        _v302_save_cancel_watch_state()
    except Exception as e:
        try: append_runtime_error_log("v302_track_cancelled", str(e), exc=e, include_traceback=False)
        except Exception: pass


try:
    _BASE_PAPER_CANCEL_PENDING_V302 = _paper_cancel_pending_v258
except Exception:
    _BASE_PAPER_CANCEL_PENDING_V302 = None


def _paper_cancel_pending_v258(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    try:
        _v302_track_cancelled_candidate(pos_id, pos, reason, now_ts=now_ts)
    except Exception:
        pass
    if callable(_BASE_PAPER_CANCEL_PENDING_V302):
        return _BASE_PAPER_CANCEL_PENDING_V302(pos_id, pos, reason, now_ts)
    return None


def update_paper_cancel_watch_v302(max_items: int = 35) -> int:
    """진입취소 후보가 이후 갔는지 추적한다. 새 API 호출 없이 기존 가격추적/WS 값만 사용한다."""
    updated = 0
    try:
        _v302_load_cancel_watch_state()
        now_ts = time.time()
        with PAPER_CANCEL_WATCH_LOCK_V302:
            items = [(k, dict(v)) for k, v in (PAPER_CANCEL_WATCH_STATE_V302 or {}).items() if isinstance(v, dict)]
        # 최근 취소와 이미 많이 간 후보를 우선 갱신한다.
        items.sort(key=lambda kv: (safe_float(kv[1].get("cancel_ts", 0), 0), safe_float(kv[1].get("max_up_after_cancel_pct", 0), 0)), reverse=True)
        changed = False
        for k, row in items[:max(1, int(max_items))]:
            cancel_ts = safe_float(row.get("cancel_ts", 0), 0)
            if cancel_ts <= 0 or now_ts - cancel_ts > PAPER_CANCEL_WATCH_TTL_SEC_V302:
                row["active"] = False
                with PAPER_CANCEL_WATCH_LOCK_V302:
                    if k in PAPER_CANCEL_WATCH_STATE_V302:
                        PAPER_CANCEL_WATCH_STATE_V302[k].update(row)
                changed = True
                continue
            ticker = str(row.get("ticker", "") or "").upper().strip()
            cancel_price = safe_float(row.get("cancel_price", 0), 0)
            if not ticker or cancel_price <= 0:
                continue
            price, src, age = _paper_price_v258(ticker, fallback=safe_float(row.get("last_price", cancel_price), cancel_price))
            if safe_float(price, 0) <= 0:
                continue
            price = safe_float(price, 0)
            max_price = max(safe_float(row.get("max_price_after_cancel", cancel_price), cancel_price), price)
            min_price = min(safe_float(row.get("min_price_after_cancel", cancel_price), cancel_price), price)
            max_up = ((max_price - cancel_price) / cancel_price) * 100.0 if cancel_price > 0 else 0.0
            min_pct = ((min_price - cancel_price) / cancel_price) * 100.0 if cancel_price > 0 else 0.0
            cur_pct = ((price - cancel_price) / cancel_price) * 100.0 if cancel_price > 0 else 0.0
            if max_price > safe_float(row.get("max_price_after_cancel", cancel_price), cancel_price):
                row["seconds_to_high"] = int(max(0, now_ts - cancel_ts))
            row.update({
                "last_price": price,
                "last_price_source": src,
                "last_price_age": safe_float(age, 0),
                "last_check_ts": now_ts,
                "max_price_after_cancel": max_price,
                "min_price_after_cancel": min_price,
                "max_up_after_cancel_pct": round(max_up, 4),
                "min_after_cancel_pct": round(min_pct, 4),
                "current_after_cancel_pct": round(cur_pct, 4),
                "important": bool(max_up >= PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302),
                "active": True,
            })
            if row["important"]:
                _v302_inc("cancel_watch_important", f"취소후상승 {ticker}/{max_up:+.2f}%")
            else:
                _v302_inc("cancel_watch_hidden_good_drop")
            with PAPER_CANCEL_WATCH_LOCK_V302:
                if k in PAPER_CANCEL_WATCH_STATE_V302:
                    PAPER_CANCEL_WATCH_STATE_V302[k].update(row)
            updated += 1
            changed = True
        if changed:
            _v302_save_cancel_watch_state()
        if updated:
            _v302_inc("cancel_watch_updated", f"취소후추적 갱신 {updated}개")
    except Exception as e:
        try: append_runtime_error_log("v302_update_cancel_watch", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return updated


def _v302_important_cancel_rows(limit: int = None, include_weak: bool = False) -> list:
    try:
        update_paper_cancel_watch_v302()
        _v302_load_cancel_watch_state()
        with PAPER_CANCEL_WATCH_LOCK_V302:
            rows = [dict(v) for v in (PAPER_CANCEL_WATCH_STATE_V302 or {}).values() if isinstance(v, dict)]
        if not include_weak:
            rows = [r for r in rows if safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302]
        rows.sort(key=lambda r: (safe_float(r.get("max_up_after_cancel_pct", 0), 0), safe_float(r.get("cancel_ts", 0), 0)), reverse=True)
        if limit is not None:
            rows = rows[:max(1, int(limit))]
        return rows
    except Exception:
        return []


def _v302_format_cancel_watch_row(row: dict, idx: int = 1, full: bool = False) -> str:
    ticker = str(row.get("ticker", "?") or "?").upper().strip()
    max_up = safe_float(row.get("max_up_after_cancel_pct", 0), 0)
    cur_up = safe_float(row.get("current_after_cancel_pct", 0), 0)
    sec_hi = int(max(0, safe_float(row.get("seconds_to_high", 0), 0)))
    reason = _paper_v301_easy_reason(row.get("close_reason", "")) if '_paper_v301_easy_reason' in globals() else str(row.get("close_reason", ""))
    lane = _paper_v301_easy_lane(row.get("lane", "")) if '_paper_v301_easy_lane' in globals() else str(row.get("lane", ""))
    rule = _paper_v301_easy_rule(row.get("entry_rule", "")) if '_paper_v301_easy_rule' in globals() else str(row.get("entry_rule", ""))
    head = f"{idx}. {ticker} / 취소 후 최고 {max_up:+.2f}% / 현재 {cur_up:+.2f}% / 최고까지 {format_elapsed_text(sec_hi)}"
    if not full:
        return f"{head} / {reason}"
    return "\n".join([
        head,
        f"- 취소가 {fmt_price_detail(row.get('cancel_price',0))} → 최고 {fmt_price_detail(row.get('max_price_after_cancel',0))} / 현재 {fmt_price_detail(row.get('last_price',0))}",
        f"- 유형: {lane} / {rule} / 사유: {reason}",
        f"- 당시 점수/돈/체결: {safe_float(row.get('score',0),0):.2f} / {safe_float(row.get('money_amount',0),0)/100000000:.2f}억 / {int(safe_float(row.get('trade_count',0),0))}건·매수 {safe_float(row.get('buy_ratio',0),0):.0f}%",
    ])


def build_paper_cancel_watch_section_v302(full: bool = False, limit: int = None) -> str:
    limit = limit if limit is not None else (PAPER_CANCEL_WATCH_FULL_LIMIT_V302 if full else PAPER_CANCEL_WATCH_DEFAULT_LIMIT_V302)
    rows = _v302_important_cancel_rows(limit=limit, include_weak=bool(full))
    strong = [r for r in rows if safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302]
    title = "🚨 취소 후 놓침 의심" if not full else "🚨 취소 후 추적 상세"
    lines = [title]
    if not full:
        lines.append(f"- 기준: 취소 뒤 최고 +{PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302:.1f}% 이상만 표시. 잘 버린 취소는 숨김.")
    else:
        lines.append(f"- 기준: 최근 {int(PAPER_CANCEL_WATCH_TTL_SEC_V302//60)}분 추적. 기본 화면은 +{PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302:.1f}% 이상만 보여줌.")
    if not strong and not full:
        lines.append("- 지금은 취소 후 크게 간 후보 없음. 잘 버린 취소는 기본 화면에서 안 보여줌.")
        return "\n".join(lines)
    shown_rows = rows if full else strong
    if not shown_rows:
        lines.append("- 추적 중인 취소 후보 없음")
        return "\n".join(lines)
    for i, r in enumerate(shown_rows[:max(1, int(limit))], start=1):
        # full에서도 너무 의미 없는 행만 길게 늘어지는 건 막는다.
        if full and safe_float(r.get("max_up_after_cancel_pct", 0), 0) < 0.25:
            continue
        lines.append(_v302_format_cancel_watch_row(r, idx=i, full=full))
    return "\n".join(lines).strip()


