def _v302_recent_closed_lines(limit: int = 4) -> list:
    try:
        rows = _paper_closed_logs_v258(include_cancelled=False)
        rows.sort(key=lambda r: safe_float(r.get("close_ts", 0), 0), reverse=True)
        out = []
        for i, r in enumerate(rows[:max(1, int(limit))], start=1):
            ticker = str(r.get("ticker", "?") or "?").upper()
            pnl = safe_float(r.get("pnl_pct", 0), 0)
            reason = _paper_v301_easy_reason(r.get("close_reason", "")) if '_paper_v301_easy_reason' in globals() else str(r.get("close_reason", ""))
            lane = _paper_v301_easy_lane(r.get("lane", "")) if '_paper_v301_easy_lane' in globals() else str(r.get("lane", ""))
            out.append(f"{i}. {ticker} / {pnl:+.2f}% / {reason} / {lane} / 최고 {safe_float(r.get('max_up_pct',0),0):+.2f}%·최저 {safe_float(r.get('min_down_pct',0),0):+.2f}%")
        return out
    except Exception:
        return []


def build_paper_recent_text_v258(limit: int = 6) -> str:
    """v302 기본 recent: 잘 버린 취소는 숨기고, 취소 후 간 후보와 실제 청산만 짧게 본다."""
    _v302_inc("recent_compact")
    try:
        update_paper_cancel_watch_v302()
        lines = [
            "🧾 최근 모의매매 /paper_recent",
            "- 실제 주문 아님",
            "- 기본 화면은 중요 후보만: 취소 후 간 애 + 실제 청산 결과",
            "",
            build_paper_cancel_watch_section_v302(full=False, limit=PAPER_CANCEL_WATCH_DEFAULT_LIMIT_V302),
            "",
            "✅ 최근 모의청산",
        ]
        closed_lines = _v302_recent_closed_lines(limit=4)
        if closed_lines:
            lines.extend(closed_lines)
        else:
            lines.append("- 최근 청산 없음")
        lines += [
            "",
            "- 전체 취소/청산 원본: /paper_recent_full",
            "- 흐름 요약: /paper_flow",
        ]
        return "\n".join(lines).strip()
    except Exception as e:
        if callable(_BASE_BUILD_PAPER_RECENT_TEXT_V302):
            return str(_BASE_BUILD_PAPER_RECENT_TEXT_V302(limit=limit))
        return f"🧾 최근 모의매매 /paper_recent\n- 생성 오류: {e.__class__.__name__}: {str(e)[:120]}"


try:
    _BASE_BUILD_PAPER_RECENT_FULL_TEXT_V302 = build_paper_recent_full_text_v277
except Exception:
    _BASE_BUILD_PAPER_RECENT_FULL_TEXT_V302 = None


def build_paper_recent_full_text_v277(limit: int = 20):
    try:
        update_paper_cancel_watch_v302(max_items=80)
        base = str(_BASE_BUILD_PAPER_RECENT_FULL_TEXT_V302(limit=limit)) if callable(_BASE_BUILD_PAPER_RECENT_FULL_TEXT_V302) else (str(_BASE_BUILD_PAPER_RECENT_TEXT_V302(limit=limit)) if callable(_BASE_BUILD_PAPER_RECENT_TEXT_V302) else "")
        section = build_paper_cancel_watch_section_v302(full=True, limit=PAPER_CANCEL_WATCH_FULL_LIMIT_V302)
        if section and section not in base:
            base = base.rstrip() + "\n\n" + section
        return base.strip()
    except Exception as e:
        return f"🧾 최근 모의매매 상세 /paper_recent_full\n- 생성 오류: {e.__class__.__name__}: {str(e)[:120]}"


try:
    _BASE_BUILD_PAPER_FLOW_TEXT_V302 = build_paper_flow_text_v301
except Exception:
    _BASE_BUILD_PAPER_FLOW_TEXT_V302 = None


def build_paper_flow_text_v301(minutes: int = PAPER_FLOW_DEFAULT_MINUTES_V301) -> str:
    base = str(_BASE_BUILD_PAPER_FLOW_TEXT_V302(minutes=minutes)) if callable(_BASE_BUILD_PAPER_FLOW_TEXT_V302) else "🧪 모의매매 흐름 /paper_flow"
    try:
        section = build_paper_cancel_watch_section_v302(full=False, limit=3)
        if "🚨 취소 후 놓침 의심" not in base:
            base = base.rstrip() + "\n\n" + section
        if "잘 버린 취소" not in base:
            base += "\n- 잘 버린 취소는 /paper_recent 기본 화면에서 숨김. 전체 원본은 /paper_recent_full"
    except Exception:
        pass
    return base


# ---- v302: 바로진입형 문턱 재분리 ----
PAPER_V302_NOW_DIRECT_MONEY_MIN = 80_000_000
PAPER_V302_NOW_DIRECT_TRADE_MIN = 3
PAPER_V302_NOW_DIRECT_BUY_RATIO_MIN = 52.0
PAPER_V302_NOW_PREPARE_MONEY_MIN = 20_000_000
