def build_review_trace_detail_text(ticker: str, limit: int = REVIEW_TRACE_DETAIL_RECENT_LIMIT) -> str:
    raw_query = str(ticker or '').strip()
    resolved, _note = resolve_user_ticker_query(raw_query)
    resolved = str(resolved or raw_query).upper().strip()
    if resolved:
        force_detail_ticker_into_rank_pool_v302(resolved, reason="review_trace_detail")
    text = str(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V302(ticker, limit=limit)) if callable(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V302) else ""
    try:
        if resolved and "v302" not in text and ("역추적 기록이 아직 없어" in text or "누락 진단" in text):
            text += "\n- v302 보정: 상세조회한 코인은 감시풀/현재가 스냅샷에 강제 등록했어. 몇 분 뒤 /rank_compare, /review_trace_detail에서 다시 확인."
    except Exception:
        pass
    return text


