# =========================================================
# v2.5.303: v302 오류수정 + 취소후 재감시 문턱 + POLA형 후보 보강
# =========================================================
# 원칙:
# - 전체 조건을 조이는 수정이 아니다.
# - 잘 버린 취소는 계속 숨기고, 취소 뒤 실제로 간 후보만 더 선명하게 보여준다.
# - POLA/WIKEN처럼 돈·거래량·현재봉이 살아 있는데 반짝형으로 낮아진 후보는 내부 재감시로 올린다.
# - v302에서 확인된 전역 저장 오류와 turnover_score 누락 오류를 방어한다.
PAPER_CANCEL_WATCH_REWATCH_UP_PCT_V303 = 1.50
PAPER_CANCEL_WATCH_MISSED_STRONG_UP_PCT_V303 = 3.00
V303_REWATCH_MIN_SCORE = 7.20
V303_REWATCH_MIN_MONEY = 300_000_000
V303_REWATCH_STRONG_MONEY = 3_000_000_000
V303_REWATCH_MIN_VOL_RATIO = 2.40
V303_REWATCH_MIN_MTF_MOVE = 0.75
V303_REWATCH_HIGH_GAP_MAX = 1.20
V303_REWATCH_FROM_LOW_MIN = 0.80
V303_REWATCH_FROM_LOW_MAX = 4.80
V303_STATS = {
    "cancel_save_fixed": 0,
    "turnover_default_filled": 0,
    "reentry_watch_promoted": 0,
    "precision_rewatch_allowed": 0,
    "last_note": "대기",
}


def _v303_inc(key: str, note: str = ""):
    try:
        if key in V303_STATS:
            V303_STATS[key] = int(safe_float(V303_STATS.get(key, 0), 0)) + 1
        if note:
            V303_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v303_money(row: dict) -> float:
    try:
        if '_row_turnover_value' in globals():
            return safe_float(_row_turnover_value(row), 0)
    except Exception:
        pass
    for k in ("turnover_5m", "turnover_recent", "turnover", "money_amount", "ws_trade_amount_60s", "trade_amount_60s", "snapshot_turnover_hint"):
        v = safe_float((row or {}).get(k, 0), 0)
        if v > 0:
            return v
    return 0.0


def _v303_strongest_move(row: dict) -> float:
    try:
        if '_row_strongest_rank_move' in globals():
            return safe_float(_row_strongest_rank_move(row), 0)
    except Exception:
        pass
    vals = []
    for k in ("change_1", "change_3", "change_5", "change_15", "change_30", "change_60", "chg1", "chg3", "chg5", "chg15", "chg30"):
        vals.append(safe_float((row or {}).get(k, 0), 0))
    return max(vals) if vals else 0.0


def _v303_high_gap(row: dict) -> float:
    for k in ("below_30m_high_pct", "recent_30m_high_gap_pct", "high_gap_pct", "reference_high_gap_pct"):
        v = safe_float((row or {}).get(k, 999), 999)
        if 0 <= v < 900:
            return v
    try:
        if 'get_recent_30m_high_gap_pct' in globals():
            return safe_float(get_recent_30m_high_gap_pct(row), 999)
    except Exception:
        pass
    return 999.0


def _v303_from_low(row: dict) -> float:
    for k in ("from_30m_low_pct", "from_low_pct", "range_pct", "reference_low_rise_pct"):
        v = safe_float((row or {}).get(k, 0), 0)
        if v > 0:
            return v
    try:
        if 'get_reference_low_rise_pct' in globals():
            return safe_float(get_reference_low_rise_pct(row), 0)
    except Exception:
        pass
    return 0.0


def _v303_candle_alive(row: dict) -> bool:
    txt = " ".join(str((row or {}).get(k, "") or "") for k in ("current_candle_label", "current_candle_status", "now_candle_status", "rank_watch_chart_state", "final_candidate_state_v251"))
    live_score = safe_float((row or {}).get("current_candle_live_score", (row or {}).get("candle_live_score", 0)), 0)
    pressure = safe_float((row or {}).get("current_candle_pressure_score", (row or {}).get("candle_pressure_score", 0)), 0)
    if any(x in txt for x in ("강밀림", "위꼬리강밀림", "막판강밀림")):
        return False
    if "확실" in txt and "살아" in txt:
        return True
    if "아랫꼬리강회복" in txt or "고점 재돌파 유지" in txt:
        return True
    if live_score >= 2.0 and pressure < 1.4:
        return True
    return False


def _v303_money_or_flow_ok(row: dict) -> bool:
    money = _v303_money(row)
    score = safe_float((row or {}).get("snapshot_rank_score", (row or {}).get("lite_score", 0)), 0)
    vol = max(
        safe_float((row or {}).get("vol_ratio", 0), 0),
        safe_float((row or {}).get("volume_ratio", 0), 0),
        safe_float((row or {}).get("vol_ratio_snapshot", 0), 0),
    )
    trade_cnt = max(
        int(safe_float((row or {}).get("ws_trade_count_60s", 0), 0)),
        int(safe_float((row or {}).get("trade_count_60s", 0), 0)),
        int(safe_float((row or {}).get("trade_count", 0), 0)),
    )
    buy_ratio = max(
        safe_float((row or {}).get("ws_trade_buy_ratio_60s", 0), 0),
        safe_float((row or {}).get("buy_ratio_60s", 0), 0),
        safe_float((row or {}).get("buy_ratio", 0), 0),
    )
    # POLA류: 돈이 매우 크면 매수비율이 완벽하지 않아도 재감시 가치가 있다.
    if money >= V303_REWATCH_STRONG_MONEY and score >= 6.8:
        return True
    if money >= V303_REWATCH_MIN_MONEY and (vol >= V303_REWATCH_MIN_VOL_RATIO or trade_cnt >= 6 or buy_ratio >= 55):
        return True
    return False


def is_v303_reentry_rewatch_candidate(row: dict) -> bool:
    """반짝형으로만 버리기 아까운 POLA/WIKEN식 재감시 후보."""
    try:
        row = row if isinstance(row, dict) else {}
        if bool(row.get("rank_tick_noise_block", False)) or ('is_watch_excluded_ticker' in globals() and is_watch_excluded_ticker(str(row.get('ticker','')))):
            return False
        score = safe_float(row.get("snapshot_rank_score", row.get("lite_score", row.get("score", 0))), 0)
        strongest = _v303_strongest_move(row)
        high_gap = _v303_high_gap(row)
        from_low = _v303_from_low(row)
        money = _v303_money(row)
        if score < V303_REWATCH_MIN_SCORE and not (money >= V303_REWATCH_STRONG_MONEY and strongest >= 0.45):
            return False
        if strongest < V303_REWATCH_MIN_MTF_MOVE and not (money >= V303_REWATCH_STRONG_MONEY and strongest >= 0.35):
            return False
        if not _v303_money_or_flow_ok(row):
            return False
        if not (0 <= high_gap <= V303_REWATCH_HIGH_GAP_MAX):
            return False
        if not (V303_REWATCH_FROM_LOW_MIN <= from_low <= V303_REWATCH_FROM_LOW_MAX) and not money >= V303_REWATCH_STRONG_MONEY:
            return False
        # 현재봉이 아주 강하면 통과. 다만 강한 돈+흐름이 있으면 미검증 row도 재감시까지는 허용.
        if _v303_candle_alive(row):
            return True
        txt = " ".join(str(row.get(k, "") or "") for k in ("current_candle_label", "current_candle_status", "rank_watch_chart_state", "final_candidate_state_v251"))
        if any(x in txt for x in ("강밀림", "막판강밀림", "위꼬리강밀림")):
            return False
        return money >= V303_REWATCH_STRONG_MONEY and score >= V303_REWATCH_MIN_SCORE + 1.0
    except Exception:
        return False


# v302 저장 오류 재정의: 함수 안에서 전역 dict를 다시 대입하므로 global이 필요하다.
def _v302_save_cancel_watch_state():
    global PAPER_CANCEL_WATCH_STATE_V302
    try:
        with PAPER_CANCEL_WATCH_LOCK_V302:
            rows = dict(PAPER_CANCEL_WATCH_STATE_V302 or {})
        now_ts = time.time()
        cleaned = {}
        for k, r in rows.items():
            if not isinstance(r, dict):
                continue
            cancel_ts = safe_float(r.get("cancel_ts", 0), 0)
            max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
            keep_sec = PAPER_CANCEL_WATCH_TTL_SEC_V302 * (3 if max_up >= PAPER_CANCEL_WATCH_STRONG_UP_PCT_V302 else 1)
            if cancel_ts > 0 and now_ts - cancel_ts > keep_sec:
                continue
            cleaned[str(k)] = dict(r)
        if len(cleaned) > PAPER_CANCEL_WATCH_MAX_ITEMS_V302:
            ordered = sorted(cleaned.items(), key=lambda kv: (safe_float(kv[1].get("max_up_after_cancel_pct", 0), 0), safe_float(kv[1].get("cancel_ts", 0), 0)), reverse=True)
            cleaned = dict(ordered[:PAPER_CANCEL_WATCH_MAX_ITEMS_V302])
        with PAPER_CANCEL_WATCH_LOCK_V302:
            PAPER_CANCEL_WATCH_STATE_V302 = cleaned
        save_json_file(PAPER_CANCEL_WATCH_FILE_V302, {"schema": "paper_cancel_watch_v303", "updated_ts": now_ts, "rows": cleaned})
        _v303_inc("cancel_save_fixed", "취소후추적 저장 정상")
    except Exception as e:
        try: append_runtime_error_log("v303_cancel_watch_save", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v303_cancel_watch_grade(row: dict) -> str:
    max_up = safe_float((row or {}).get("max_up_after_cancel_pct", 0), 0)
    cur_up = safe_float((row or {}).get("current_after_cancel_pct", 0), 0)
    if max_up >= PAPER_CANCEL_WATCH_MISSED_STRONG_UP_PCT_V303:
        return "강한 놓침"
    if max_up >= PAPER_CANCEL_WATCH_REWATCH_UP_PCT_V303:
        return "재감시 강함"
    if max_up >= PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302:
        return "놓침 의심"
    if cur_up <= 0:
        return "잘 버림"
    return "약한 재확인"


# v302 출력 보강: 기본 화면에는 중요한 취소만, full에는 등급과 재확인 의미를 더 쉽게 표시.
def _v302_format_cancel_watch_row(row: dict, idx: int = 1, full: bool = False) -> str:
    ticker = str((row or {}).get("ticker", "?") or "?").upper().strip()
    max_up = safe_float((row or {}).get("max_up_after_cancel_pct", 0), 0)
    cur_up = safe_float((row or {}).get("current_after_cancel_pct", 0), 0)
    sec_hi = int(max(0, safe_float((row or {}).get("seconds_to_high", 0), 0)))
    reason = _paper_v301_easy_reason((row or {}).get("close_reason", "")) if '_paper_v301_easy_reason' in globals() else str((row or {}).get("close_reason", ""))
    lane = _paper_v301_easy_lane((row or {}).get("lane", "")) if '_paper_v301_easy_lane' in globals() else str((row or {}).get("lane", ""))
    rule = _paper_v301_easy_rule((row or {}).get("entry_rule", "")) if '_paper_v301_easy_rule' in globals() else str((row or {}).get("entry_rule", ""))
    grade = _v303_cancel_watch_grade(row)
    head = f"{idx}. {ticker} / {grade} / 취소 후 최고 {max_up:+.2f}% / 현재 {cur_up:+.2f}% / 최고까지 {format_elapsed_text(sec_hi)}"
    if not full:
        return f"{head} / {reason}"
    action = ""
    if max_up >= PAPER_CANCEL_WATCH_MISSED_STRONG_UP_PCT_V303:
        action = "다음 비슷한 패턴은 취소 직후 10~30분 재감시 강화"
    elif max_up >= PAPER_CANCEL_WATCH_REWATCH_UP_PCT_V303:
        action = "다음 비슷한 패턴은 바로 버리지 말고 재감시 유지"
    elif max_up >= PAPER_CANCEL_WATCH_MIN_SHOW_UP_PCT_V302:
        action = "소폭 놓침. 재감시 표본으로만 참고"
    else:
        action = "잘 버린 쪽. 기본 화면 숨김"
    return "\n".join([
        head,
        f"- 취소가 {fmt_price_detail(row.get('cancel_price',0))} → 최고 {fmt_price_detail(row.get('max_price_after_cancel',0))} / 현재 {fmt_price_detail(row.get('last_price',0))}",
        f"- 유형: {lane} / {rule} / 사유: {reason}",
        f"- 당시 점수/돈/체결: {safe_float(row.get('score',0),0):.2f} / {safe_float(row.get('money_amount',0),0)/100000000:.2f}억 / {int(safe_float(row.get('trade_count',0),0))}건·매수 {safe_float(row.get('buy_ratio',0),0):.0f}%",
        f"- 다음 판단: {action}",
    ])


# v303: 강제주입/스냅샷 row 기본값 보강. turnover_score 누락이 다시 나도 정렬/워커가 죽지 않게 한다.
def ensure_v303_rank_row_defaults(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        price = safe_float(row.get("price", row.get("current_price", row.get("last_price", 0))), 0)
        turn = _v303_money(row)
        if "turnover_recent" not in row:
            row["turnover_recent"] = turn
        if "turnover_score" not in row:
            row["turnover_score"] = math.log10(max(turn, 1)) if turn > 0 else 0.0
            _v303_inc("turnover_default_filled")
        row.setdefault("surge_score", safe_float(row.get("snapshot_rank_score", row.get("score", 0)), 0))
        row.setdefault("leader_score", safe_float(row.get("snapshot_rank_score", row.get("score", 0)), 0))
        row.setdefault("last_price", price)
        row.setdefault("current_price", price)
        row.setdefault("price", price)
        return row
    except Exception:
        return row


try:
    _BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V303 = force_detail_ticker_into_rank_pool_v302
except Exception:
    _BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V303 = None


def force_detail_ticker_into_rank_pool_v302(ticker: str, reason: str = "detail_v303") -> bool:
    global shared_market_cache, market_universe
    ok = False
    try:
        ok = bool(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V303(ticker, reason=reason)) if callable(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V303) else False
    except Exception as e:
        try: append_runtime_error_log("v303_detail_force_base", str(e), exc=e, include_traceback=False)
        except Exception: pass
    try:
        t = str(ticker or "").upper().strip()
        if not t:
            return ok
        if isinstance(shared_market_cache, dict) and isinstance(shared_market_cache.get(t), dict):
            shared_market_cache[t] = ensure_v303_rank_row_defaults(dict(shared_market_cache.get(t)))
        if isinstance(market_universe, list):
            fixed = []
            changed = False
            for x in market_universe:
                if isinstance(x, dict) and str(x.get("ticker", "")).upper().strip() == t:
                    fixed.append(ensure_v303_rank_row_defaults(dict(x)))
                    changed = True
                else:
                    fixed.append(x)
            if changed:
                market_universe = fixed
        return ok
    except Exception as e:
        try: append_runtime_error_log("v303_detail_force_defaults", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ok


