def _paper_classify_for_register_v258(row: dict):
    if not callable(_BASE_PAPER_CLASSIFY_V306):
        return False, "", "분류함수없음", {}
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V306(row)
    try:
        if ok and isinstance(cls, dict):
            risk = _v306_direct_entry_risk_reason(row if isinstance(row, dict) else {}, cls)
            if risk and str(cls.get("grade", "") or "").upper().strip() == "BUY_OK":
                original_grade = str(cls.get("grade", "") or "BUY_OK")
                cls = dict(cls)
                cls["paper_original_grade"] = str(cls.get("paper_original_grade", original_grade) or original_grade)
                cls["paper_v306_direct_block_reason"] = risk
                cls["paper_v306_flow_position"] = "2차 후보 → 3차 진입 전 준비 → paper 검증"
                cls["grade"] = "PULLBACK_WAIT"
                cls["decision"] = "바로진입 보류 / 진입 전 준비"
                lane = str(lane or "strict_signal") + "_prepare_v306"
                reason = (str(reason or "신호층") + " / v306 바로진입 보류: " + risk)[:240]
                _v306_inc("paper_direct_to_prepare", f"바로진입→준비 {str((row or {}).get('ticker', cls.get('ticker','?')))} / {risk}")
        return ok, lane, reason, cls
    except Exception as e:
        try:
            append_runtime_error_log("v306_paper_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return ok, lane, reason, cls


try:
    _BASE_PAPER_CLOSE_V306 = _paper_close_position_v258
except Exception:
    _BASE_PAPER_CLOSE_V306 = None


def _paper_close_position_v258(pos_id: str, pos: dict, price: float, reason: str, now_ts: float = None):
    """청산 알림의 최고/최저에 청산가 변동도 포함한다.

    APE/DOGE 표본처럼 30~40초 만에 손실 청산됐는데 최고/최저가 0.00/0.00으로 보이면
    사용자가 원인을 오해한다. paper/trace 표시 보정이며 매매 조건 변경이 아니다.
    """
    try:
        patched = dict(pos or {})
        entry = safe_float(patched.get("entry_price", 0), 0)
        close_price = safe_float(price, 0)
        if entry > 0 and close_price > 0:
            pnl_now = _paper_pct_v258(entry, close_price)
            patched["max_up_pct"] = max(safe_float(patched.get("max_up_pct", pnl_now), pnl_now), pnl_now)
            patched["min_down_pct"] = min(safe_float(patched.get("min_down_pct", pnl_now), pnl_now), pnl_now)
            patched["v306_range_includes_close_price"] = True
            _v306_inc("paper_range_fix_on_close", f"청산범위보정 {patched.get('ticker','?')}/{pnl_now:+.2f}%")
        if callable(_BASE_PAPER_CLOSE_V306):
            return _BASE_PAPER_CLOSE_V306(pos_id, patched, price, reason, now_ts)
    except Exception as e:
        try:
            append_runtime_error_log("v306_paper_close_range_fix", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    if callable(_BASE_PAPER_CLOSE_V306):
        return _BASE_PAPER_CLOSE_V306(pos_id, pos, price, reason, now_ts)
    return None


