# =========================================================
# v2.5.308: /review_sample 검증 표본 저장 + 차트 데이터 일치 검증
# 위치: 3차 표본선정 + 창고 + 출력 + paper/trace
# 핵심:
# - 내가 즉석으로 추천하는 방식이 아니라, 봇이 당일 검증 표본을 저장한다.
# - 표본은 하루 동안 유지하고, 과거 표본은 history에 남긴다.
# - 각 표본에 “봇이 가진 차트 데이터”와 “빗썸 차트에서 비교할 시간대”를 같이 표시한다.
# - 순위는 다를 수 있어도, 같은 시각의 차트 데이터는 빗썸 실제 차트와 맞아야 한다.
# =========================================================
V308_SCHEMA_VERSION = "review_sample_v308"
V308_MODULE_LOAD_TS = time.time()
REVIEW_SAMPLE_TODAY_FILE_V308 = data_file("review_sample_today_v308.json")
REVIEW_SAMPLE_HISTORY_FILE_V308 = data_file("review_sample_history_v308.json")
REVIEW_SAMPLE_HISTORY_KEEP_DAYS_V308 = 90
REVIEW_SAMPLE_DAILY_TARGETS_V308 = 5
V308_STATS = {
    "sample_generated": 0,
    "sample_reused": 0,
    "history_saved": 0,
    "chart_snapshot_saved": 0,
    "entry_alert_patched": 0,
    "exit_alert_patched": 0,
    "batch_review_sample": 0,
    "last_note": "대기",
}


def _v308_inc(key: str, note: str = ""):
    try:
        if key in V308_STATS:
            V308_STATS[key] = int(safe_float(V308_STATS.get(key, 0), 0)) + 1
        if note:
            V308_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v308_today_key() -> str:
    try:
        return now_kst().strftime("%Y-%m-%d")
    except Exception:
        return time.strftime("%Y-%m-%d", time.localtime(time.time() + 9 * 3600))


def _v308_ts_text(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "시각없음"
        return datetime.fromtimestamp(ts, KST).strftime("%m-%d %H:%M") if 'KST' in globals() else time.strftime("%m-%d %H:%M", time.localtime(ts))
    except Exception:
        return "시각오류"


def _v308_time_window_text(ts: float, minute_before: int = 10, minute_after: int = 10) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "기준시각 없음"
        a = _v308_ts_text(ts - minute_before * 60)
        b = _v308_ts_text(ts + minute_after * 60)
        return f"{a} ~ {b}"
    except Exception:
        return "시간대 계산 오류"


def _v308_num(v, default=0.0):
    return safe_float(v, default)


def _v308_pick_first(d: dict, keys: list, default=None):
    try:
        d = d if isinstance(d, dict) else {}
        for k in keys:
            if k in d and d.get(k) not in (None, ""):
                return d.get(k)
    except Exception:
        pass
    return default


def _v308_money_text(v) -> str:
    try:
        x = safe_float(v, 0)
        if x <= 0:
            return "-"
        if x >= 100000000:
            return f"{x/100000000:.2f}억"
        if x >= 10000:
            return f"{x/10000:.0f}만"
        return f"{x:.0f}"
    except Exception:
        return "-"


def _v308_cached_rank_rows(limit: int = 100) -> list:
    try:
        rows, _meta = get_cached_rank_rows_for_instant(limit=max(20, int(limit or 100)), max_age_sec=3600) if 'get_cached_rank_rows_for_instant' in globals() else ([], {})
        if rows:
            return [dict(r) for r in rows if isinstance(r, dict)]
    except Exception:
        pass
    try:
        rows = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
        if isinstance(rows, list):
            return [dict(r) for r in rows[:limit] if isinstance(r, dict)]
    except Exception:
        pass
    return []


def _v308_find_rank_row(ticker: str, rank_rows: list = None) -> dict:
    t = str(ticker or "").upper().strip()
    if not t:
        return {}
    for r in list(rank_rows or _v308_cached_rank_rows(120) or []):
        if isinstance(r, dict) and str(r.get("ticker", "")).upper().strip() == t:
            return dict(r)
    return {}


def _v308_chart_snapshot(ticker: str, primary: dict = None, rank_row: dict = None, event_ts: float = None, source: str = "") -> dict:
    """봇이 가진 차트 데이터를 검증용으로 고정 저장한다.

    여기서 새 OHLCV/API를 호출하지 않는다. 이미 창고/공장/paper/trace에 저장된 값만 요약한다.
    """
    try:
        primary = primary if isinstance(primary, dict) else {}
        rank_row = rank_row if isinstance(rank_row, dict) else {}
        merged = {}
        for src in (rank_row, primary):
            if isinstance(src, dict):
                merged.update(src)
        ts = safe_float(event_ts, 0) or safe_float(_v308_pick_first(merged, ["snapshot_ts", "updated_ts", "last_check_ts", "close_ts", "cancel_ts", "created_ts", "entered_ts"], 0), 0)
        price = _v308_pick_first(merged, ["price", "current_price", "last_price", "close_price", "entry_price", "cancel_price"], 0)
        high = _v308_pick_first(merged, ["high", "current_high", "candle_high", "high_price", "max_price_after_cancel"], 0)
        low = _v308_pick_first(merged, ["low", "current_low", "candle_low", "low_price", "min_price_after_cancel"], 0)
        open_p = _v308_pick_first(merged, ["open", "current_open", "candle_open"], 0)
        close_p = _v308_pick_first(merged, ["close", "current_close", "candle_close", "last_price", "price"], 0)
        money = _v308_pick_first(merged, ["money_amount", "turnover_krw", "turnover_recent", "turnover", "recent_turnover", "volume_krw"], 0)
        trade_count = _v308_pick_first(merged, ["trade_count", "trade_count_60s", "ws_trade_count_60s", "count_60s"], 0)
        buy_ratio = _v308_pick_first(merged, ["buy_ratio", "buy_ratio_60s", "ws_buy_ratio_60s"], 0)
        chg1 = _v308_pick_first(merged, ["change_1m", "chg_1m", "change_1", "change_rate_1m", "pct_1m", "rank_chg_1m"], None)
        chg3 = _v308_pick_first(merged, ["change_3m", "chg_3m", "change_3", "change_rate_3m", "pct_3m", "rank_chg_3m"], None)
        chg5 = _v308_pick_first(merged, ["change_5m", "chg_5m", "change_5", "change_rate_5m", "pct_5m", "rank_chg_5m"], None)
        chg15 = _v308_pick_first(merged, ["change_15m", "chg_15m", "change_15", "pct_15m"], None)
        candle = _v308_pick_first(merged, ["current_candle_label", "current_candle_code", "candle_label", "candle_status", "rank_watch_action"], "-")
        pressure = _v308_pick_first(merged, ["current_candle_pressure_score", "candle_pressure_score", "pressure_score"], None)
        live = _v308_pick_first(merged, ["current_candle_live_score", "candle_live_score", "alive_score"], None)
        tail = _v308_pick_first(merged, ["upper_tail_pct", "current_upper_tail_pct", "wick_up_pct"], None)
        lower = _v308_pick_first(merged, ["lower_tail_pct", "current_lower_tail_pct", "wick_down_pct"], None)
        reason = _v308_pick_first(merged, ["rank_reason", "watch_route", "trace_reason", "signal_decision", "decision", "register_reason"], "-")
        out = {
            "ticker": str(ticker or _v308_pick_first(merged, ["ticker"], "")).upper().strip(),
            "basis_ts": ts,
            "basis_time_text": _v308_ts_text(ts),
            "price": safe_float(price, 0),
            "open": safe_float(open_p, 0),
            "high": safe_float(high, 0),
            "low": safe_float(low, 0),
            "close": safe_float(close_p, 0),
            "change_1m": None if chg1 is None else safe_float(chg1, 0),
            "change_3m": None if chg3 is None else safe_float(chg3, 0),
            "change_5m": None if chg5 is None else safe_float(chg5, 0),
            "change_15m": None if chg15 is None else safe_float(chg15, 0),
            "money": safe_float(money, 0),
            "trade_count": int(safe_float(trade_count, 0)),
            "buy_ratio": safe_float(buy_ratio, 0),
            "current_candle": str(candle or "-"),
            "pressure": None if pressure is None else safe_float(pressure, 0),
            "live_score": None if live is None else safe_float(live, 0),
            "upper_tail_pct": None if tail is None else safe_float(tail, 0),
            "lower_tail_pct": None if lower is None else safe_float(lower, 0),
            "bot_reason": str(reason or "-"),
            "source": str(source or _v308_pick_first(merged, ["source", "rank_source"], "stored")),
        }
        _v308_inc("chart_snapshot_saved", f"차트데이터 {out.get('ticker','?')}")
        return out
    except Exception as e:
        try: append_runtime_error_log("v308_chart_snapshot", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {"ticker": str(ticker or "").upper().strip(), "basis_ts": safe_float(event_ts, 0), "basis_time_text": _v308_ts_text(event_ts), "source": "error"}


def _v308_snapshot_lines(snap: dict) -> list:
    try:
        s = snap if isinstance(snap, dict) else {}
        def pct(v):
            return "-" if v is None else f"{safe_float(v,0):+.2f}%"
        price = safe_float(s.get("price", 0), 0)
        o = safe_float(s.get("open", 0), 0); h = safe_float(s.get("high", 0), 0); l = safe_float(s.get("low", 0), 0); c = safe_float(s.get("close", 0), 0)
        ohlc = []
        if o > 0: ohlc.append(f"시 {fmt_price_detail(o)}")
        if h > 0: ohlc.append(f"고 {fmt_price_detail(h)}")
        if l > 0: ohlc.append(f"저 {fmt_price_detail(l)}")
        if c > 0: ohlc.append(f"종 {fmt_price_detail(c)}")
        lines = [
            f"- 기준시각: {s.get('basis_time_text','-')} / 가격 {fmt_price_detail(price) if price > 0 else '-'}",
            f"- 변화율: 1m {pct(s.get('change_1m'))} / 3m {pct(s.get('change_3m'))} / 5m {pct(s.get('change_5m'))} / 15m {pct(s.get('change_15m'))}",
            f"- 돈/체결: {_v308_money_text(s.get('money'))} / {int(safe_float(s.get('trade_count',0),0))}건·매수 {safe_float(s.get('buy_ratio',0),0):.0f}%",
            f"- 현재봉: {s.get('current_candle','-')} / 압력 {s.get('pressure','-')} / 생존 {s.get('live_score','-')}",
            f"- 봇판단: {str(s.get('bot_reason','-'))[:120]}",
        ]
        if ohlc:
            lines.insert(1, "- 봇 OHLC: " + " / ".join(ohlc))
        return lines
    except Exception as e:
        return [f"- 차트 데이터 표시 오류: {e}"]


def _v308_sample_key(kind: str, ticker: str) -> str:
    return f"{str(kind or '').strip()}:{str(ticker or '').upper().strip()}"


def _v308_make_sample(kind: str, ticker: str, reason: str, source_row: dict = None, rank_rows: list = None, event_ts: float = None, priority: float = 0.0, check_hint: str = "") -> dict:
    source_row = source_row if isinstance(source_row, dict) else {}
    t = str(ticker or source_row.get("ticker", "")).upper().strip()
    rr = _v308_find_rank_row(t, rank_rows or [])
    ts = safe_float(event_ts, 0) or safe_float(_v308_pick_first(source_row, ["close_ts", "cancel_ts", "entered_ts", "created_ts", "last_check_ts", "updated_ts"], 0), 0) or time.time()
    snap = _v308_chart_snapshot(t, source_row, rr, event_ts=ts, source=kind)
    return {
        "kind": str(kind or "검증"),
        "ticker": t,
        "reason": str(reason or "")[:240],
        "priority": safe_float(priority, 0),
        "event_ts": ts,
        "event_time_text": _v308_ts_text(ts),
        "compare_1m_window": _v308_time_window_text(ts, 10, 10),
        "compare_5m_window": _v308_time_window_text(ts, 30, 30),
        "chart_snapshot": snap,
        "source_row_brief": {
            "status": str(source_row.get("status", ""))[:40],
            "close_reason": str(source_row.get("close_reason", ""))[:80],
            "pnl_pct": safe_float(source_row.get("pnl_pct", 0), 0),
            "max_up_after_cancel_pct": safe_float(source_row.get("max_up_after_cancel_pct", 0), 0),
            "current_after_cancel_pct": safe_float(source_row.get("current_after_cancel_pct", 0), 0),
        },
        "check_hint": str(check_hint or "빗썸 1분봉에서 기준시각 전후를 밀어서 봐. 봇 OHLC/현재봉/거래량이 실제 차트와 맞는지 먼저 확인."),
    }


def _v308_cancel_watch_rows() -> list:
    try:
        if '_v302_load_cancel_watch_state' in globals():
            _v302_load_cancel_watch_state(force=True)
        state = globals().get("PAPER_CANCEL_WATCH_STATE_V302", {})
        rows = [dict(v) for v in (state or {}).values() if isinstance(v, dict)] if isinstance(state, dict) else []
        rows.sort(key=lambda r: (safe_float(r.get("max_up_after_cancel_pct", 0), 0), safe_float(r.get("last_check_ts", r.get("cancel_ts", 0)), 0)), reverse=True)
        return rows
    except Exception as e:
        try: append_runtime_error_log("v308_cancel_watch_rows", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return []


def _v308_select_review_samples() -> list:
    rank_rows = _v308_cached_rank_rows(120)
    samples = []
    used = set()
    now_ts = time.time()
    try:
        closed_all = _paper_closed_logs_v258(include_cancelled=True) if '_paper_closed_logs_v258' in globals() else []
    except Exception:
        closed_all = []
    closed = [r for r in closed_all if isinstance(r, dict) and str(r.get("status", "")).upper() == "CLOSED"]
    recent_closed = [r for r in closed if safe_float(r.get("close_ts", 0), 0) >= now_ts - 24 * 3600]
    losses = [r for r in recent_closed if safe_float(r.get("pnl_pct", 0), 0) < 0]
    losses.sort(key=lambda r: (safe_float(r.get("pnl_pct", 0), 0), -safe_float(r.get("close_ts", 0), 0)))
    if losses:
        r = losses[0]
        t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v308_make_sample("손실 표본", t, f"모의청산 {safe_float(r.get('pnl_pct',0),0):+.2f}% / 손실 진입문 검증", r, rank_rows, event_ts=safe_float(r.get("entered_ts", r.get("close_ts", 0)), 0), priority=90, check_hint="진입 시각 1분봉에서 이미 고점/위꼬리/밀림이었는지 먼저 봐."))
        used.add(_v308_sample_key("손실", t))
        used.add(t)
    cw_rows = _v308_cancel_watch_rows()
    strong = [r for r in cw_rows if safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= 3.0]
    if strong:
        r = strong[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v308_make_sample("취소 후 강한 놓침", t, f"취소 후 최고 {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / 현재 {safe_float(r.get('current_after_cancel_pct',0),0):+.2f}%", r, rank_rows, event_ts=safe_float(r.get("cancel_ts", 0), 0), priority=88, check_hint="취소 이후 1분/5분봉에서 다시 살아난 신호가 있었는지, 현재 추격금지인지 같이 봐."))
        used.add(t)
    rewatch = [r for r in cw_rows if str(r.get("ticker", "")).upper().strip() not in used and safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= 1.5]
    if rewatch:
        r = rewatch[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v308_make_sample("재감시 강함", t, f"취소 후 {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / 재감시 복귀 후보", r, rank_rows, event_ts=safe_float(r.get("cancel_ts", 0), 0), priority=82, check_hint="취소 후 다시 고점/저점을 높였는지, 재감시→진입대기 복귀가 맞았는지 봐."))
        used.add(t)
    # rank_short 상위 보류/반짝/내부감시 표본
    for r in rank_rows[:20]:
        t = str(r.get("ticker", "")).upper().strip()
        if not t or t in used:
            continue
        txt = " ".join(str(r.get(k, "")) for k in ["rank_watch_action", "rank_watch_explain", "final_candidate_state_v251", "money_flow_text", "rank_reason", "watch_route", "trace_reason"])
        if any(x in txt for x in ["반짝형", "밀림", "매도우세", "내부감시", "복기 기록", "순위권 움직임"]):
            samples.append(_v308_make_sample("상위 보류/차트판단", t, "rank_short 상위지만 즉시진입이 아닌 후보. 차트 해석이 실제와 맞는지 확인", r, rank_rows, event_ts=safe_float(r.get("snapshot_ts", r.get("updated_ts", now_ts)), now_ts), priority=70, check_hint="봇의 현재봉/위꼬리/매도우세/반짝형 판단이 실제 빗썸 차트와 맞는지 봐."))
            used.add(t)
            break
    # 앱식/rank_compare only 표본: rank row 필드가 있으면 우선 사용, 없으면 초입 후보 중 전략근거 약한 것 대체
    app_candidates = []
    for r in rank_rows[:50]:
        t = str(r.get("ticker", "")).upper().strip()
        if not t or t in used:
            continue
        txt = " ".join(str(r.get(k, "")) for k in ["app_compare_candidate", "app_only", "exclude_reason", "rank_compare_reason", "rank_reason", "watch_route"])
        if bool(r.get("app_compare_candidate", False)) or bool(r.get("app_only", False)) or "앱식" in txt or "전략 점수" in txt or "체결적음" in txt:
            app_candidates.append(r)
    if not app_candidates:
        for r in rank_rows[:30]:
            t = str(r.get("ticker", "")).upper().strip()
            if t and t not in used:
                app_candidates.append(r); break
    if app_candidates:
        r = app_candidates[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v308_make_sample("앱식/rank_compare only", t, "시장에서는 움직였지만 봇 전략 후보에는 약하거나 보류된 후보", r, rank_rows, event_ts=safe_float(r.get("snapshot_ts", r.get("updated_ts", now_ts)), now_ts), priority=60, check_hint="순위는 다를 수 있음. 다만 같은 시각 차트 데이터와 현재봉 해석이 맞는지 먼저 확인."))
        used.add(t)
    # 부족하면 최근 수익/대표 표본으로 채움
    wins = [r for r in recent_closed if safe_float(r.get("pnl_pct", 0), 0) > 0 and str(r.get("ticker", "")).upper().strip() not in used]
    wins.sort(key=lambda r: safe_float(r.get("pnl_pct", 0), 0), reverse=True)
    if len(samples) < REVIEW_SAMPLE_DAILY_TARGETS_V308 and wins:
        r = wins[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v308_make_sample("잘 잡은 표본", t, f"모의청산 {safe_float(r.get('pnl_pct',0),0):+.2f}% / 좋은 구조 확인", r, rank_rows, event_ts=safe_float(r.get("entered_ts", r.get("close_ts",0)),0), priority=50, check_hint="봇이 좋게 본 차트가 실제로도 초입/재출발 구조였는지 확인."))
    return samples[:REVIEW_SAMPLE_DAILY_TARGETS_V308]


def _v308_load_today_sample(force_new: bool = False) -> dict:
    today = _v308_today_key()
    if not force_new:
        obj = load_json_file(REVIEW_SAMPLE_TODAY_FILE_V308, {})
        if isinstance(obj, dict) and obj.get("date") == today and isinstance(obj.get("samples"), list) and obj.get("samples"):
            _v308_inc("sample_reused", "당일 표본 재사용")
            return obj
    # 기존 today는 history로 이동
    try:
        old = load_json_file(REVIEW_SAMPLE_TODAY_FILE_V308, {})
        if isinstance(old, dict) and old.get("date") and old.get("date") != today and old.get("samples"):
            hist = load_json_file(REVIEW_SAMPLE_HISTORY_FILE_V308, [])
            if not isinstance(hist, list): hist = []
            if not any(isinstance(x, dict) and x.get("date") == old.get("date") for x in hist):
                hist.append(old)
                hist = hist[-REVIEW_SAMPLE_HISTORY_KEEP_DAYS_V308:]
                save_json_file(REVIEW_SAMPLE_HISTORY_FILE_V308, hist)
                _v308_inc("history_saved", f"history 저장 {old.get('date')}")
    except Exception:
        pass
    samples = _v308_select_review_samples()
    obj = {"schema": V308_SCHEMA_VERSION, "date": today, "created_ts": time.time(), "created_time_text": _v308_ts_text(time.time()), "samples": samples}
    save_json_file(REVIEW_SAMPLE_TODAY_FILE_V308, obj)
    _v308_inc("sample_generated", f"오늘 표본 생성 {len(samples)}개")
    return obj


def _v308_sample_summary_line(sample: dict, idx: int) -> list:
    s = sample if isinstance(sample, dict) else {}
    snap = s.get("chart_snapshot", {}) if isinstance(s.get("chart_snapshot", {}), dict) else {}
    lines = [
        f"{idx}. {s.get('ticker','?')} / {s.get('kind','검증 표본')}",
        f"- 이유: {s.get('reason','-')}",
        f"- 기준시각: {s.get('event_time_text','-')} / 1분봉 비교 {s.get('compare_1m_window','-')}",
        f"- 봇차트: 현재가 {fmt_price_detail(safe_float(snap.get('price',0),0)) if safe_float(snap.get('price',0),0)>0 else '-'} / 1m {snap.get('change_1m','-')} / 3m {snap.get('change_3m','-')} / 5m {snap.get('change_5m','-')}",
        f"- 봇해석: {str(snap.get('current_candle','-'))[:40]} / {str(snap.get('bot_reason','-'))[:90]}",
        f"- 실제차트 체크: {s.get('check_hint','빗썸 차트와 데이터 일치 확인')}",
    ]
    return lines


def build_review_sample_text_v308(full: bool = False, force_new: bool = False) -> str:
    try:
        obj = _v308_load_today_sample(force_new=force_new)
        samples = list(obj.get("samples") or []) if isinstance(obj, dict) else []
        lines = [
            "🧪 오늘 검증 표본 /review_sample",
            f"- 날짜: {obj.get('date','-')} / 생성 {obj.get('created_time_text','-')}",
            "- 목적: 봇이 저장한 차트 데이터가 빗썸 실제 차트와 같은지 먼저 확인",
            "- 순위는 빗썸 앱과 다를 수 있음. 하지만 같은 시각의 차트 데이터가 다르면 안 됨.",
            "- 같은 날 다시 눌러도 같은 표본 유지. 과거 표본은 history로 보관.",
            "",
            "[오늘 볼 표본]",
        ]
        if not samples:
            lines.append("- 아직 저장할 표본이 부족함. paper/rank 기록이 더 쌓이면 생성됨.")
        for i, smp in enumerate(samples, start=1):
            lines.extend(_v308_sample_summary_line(smp, i))
            if full:
                lines.append("  [봇 차트 데이터]")
                lines.extend(["  " + x for x in _v308_snapshot_lines(smp.get("chart_snapshot", {}))])
                lines.append(f"  - 5분봉 비교 구간: {smp.get('compare_5m_window','-')}")
                br = smp.get("source_row_brief", {}) if isinstance(smp.get("source_row_brief", {}), dict) else {}
                lines.append(f"  - 원본요약: 상태 {br.get('status','-')} / 사유 {br.get('close_reason','-')} / 손익 {safe_float(br.get('pnl_pct',0),0):+.2f}% / 취소후최고 {safe_float(br.get('max_up_after_cancel_pct',0),0):+.2f}%")
            lines.append("")
        lines += [
            "[차트 비교 순서]",
            "1. 빗썸 1분봉에서 기준시각 전후 10분을 먼저 맞춘다.",
            "2. 봇 OHLC/현재가/거래량/현재봉 판단이 실제 차트와 같은지 본다.",
            "3. 데이터가 맞으면 그다음에 초입·재출발·밀림·추격금지 판단을 본다.",
            "4. 데이터가 다르면 전략 문제가 아니라 허브/공장/창고 데이터 문제로 본다.",
        ]
        if full:
            try:
                hist = load_json_file(REVIEW_SAMPLE_HISTORY_FILE_V308, [])
                if isinstance(hist, list) and hist:
                    lines += ["", "[history 최근]", "- " + ", ".join(str(x.get("date","?")) for x in hist[-7:] if isinstance(x, dict))]
            except Exception:
                pass
        return "\n".join(lines).strip()
    except Exception as e:
        try: append_runtime_error_log("build_review_sample_v308", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return f"⚠️ /review_sample 생성 오류: {e.__class__.__name__}: {str(e)[:160]}"


def review_sample_command(update, context: CallbackContext):
    try:
        args = list(getattr(context, "args", []) or [])
        force = bool(args and str(args[0]).lower() in {"reset", "new", "force"})
        send_text_chunks(build_review_sample_text_v308(full=False, force_new=force), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        send(f"⚠️ /review_sample 오류: {e}")


def review_sample_full_command(update, context: CallbackContext):
    try:
        send_text_chunks(build_review_sample_text_v308(full=True, force_new=False), limit=TG_MESSAGE_SOFT_LIMIT)
    except Exception as e:
        send(f"⚠️ /review_sample_full 오류: {e}")


try:
    _BASE_EXECUTE_SINGLE_BATCH_V308 = _execute_single_batch_command
except Exception:
    _BASE_EXECUTE_SINGLE_BATCH_V308 = None


def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    cmd_l = str(cmd or "").lower().strip()
    shown_cmd = f"/{cmd_l}" + (" " + " ".join(args or []) if args else "")
    label = f"▶️ 묶음 {idx}/{total} {shown_cmd}" if total > 1 else f"▶️ {shown_cmd}"
    if cmd_l in {"review_sample", "sample_review", "sample"}:
        _v308_inc("batch_review_sample", "batch review_sample")
        send_text_chunks(build_review_sample_text_v308(full=False), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if cmd_l in {"review_sample_full", "sample_full"}:
        send_text_chunks(build_review_sample_text_v308(full=True), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_BASE_EXECUTE_SINGLE_BATCH_V308):
        return _BASE_EXECUTE_SINGLE_BATCH_V308(cmd, args, idx, total)
    send(f"{label}\n- batch 처리 원본 함수를 찾지 못했어")


