def _v308_status_lines() -> list:
    return [
        "🧪 v2.5.308 review_sample/차트 데이터 검증",
        "- 위치: 3차 표본선정 + 창고 저장 + 출력 + paper/trace / 조건 전체 강화 아님",
        "- /review_sample: 손실·놓침·재감시·보류·앱식 only 표본을 봇이 직접 저장",
        "- 당일 표본 하루 유지 / history 저장 / 빗썸 차트 비교 기준시각 포함",
        f"- 표본생성 {V308_STATS.get('sample_generated',0)} / 재사용 {V308_STATS.get('sample_reused',0)} / 차트데이터저장 {V308_STATS.get('chart_snapshot_saved',0)} / 알림보정 {V308_STATS.get('entry_alert_patched',0)}·{V308_STATS.get('exit_alert_patched',0)}",
        f"- 최근: {V308_STATS.get('last_note','대기')}",
    ]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_V308()) if callable(_BASE_CACHE_STATUS_V308) else "🧊 명령어 캐시 상태 /cache_status"
    try:
        if "🧪 v2.5.308 review_sample/차트 데이터 검증" not in base:
            base += "\n" + "\n".join(_v308_status_lines())
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    return build_cache_status_text()


