try:
    _BASE_CHART_SNAPSHOT_V310 = _v308_chart_snapshot
except Exception:
    _BASE_CHART_SNAPSHOT_V310 = None


def _v310_chart_quality(s: dict) -> tuple[str, str]:
    try:
        s = s if isinstance(s, dict) else {}
        price = safe_float(s.get("price", 0), 0)
        o = safe_float(s.get("open", 0), 0); h = safe_float(s.get("high", 0), 0); l = safe_float(s.get("low", 0), 0); c = safe_float(s.get("close", 0), 0)
        basis_ts = safe_float(s.get("basis_ts", 0), 0)
        candle_ts = safe_float(s.get("candle_ts", 0), 0)
        diff = abs(candle_ts - basis_ts) if basis_ts > 0 and candle_ts > 0 else 0
        has_full_ohlc = all(x > 0 for x in (o, h, l, c))
        has_some_ohlc = any(x > 0 for x in (o, h, l, c))
        has_change = any(s.get(k) is not None for k in ("change_1m", "change_3m", "change_5m"))
        if diff > 180:
            return "봉시각 불일치 의심", f"기준시각과 봉시각 차이 {int(diff)}초. 기준시각 기준으로 빗썸 차트 확인"
        if has_full_ohlc and price > 0:
            return "충분", "현재가+OHLC 저장값 있음"
        if price > 0 and has_some_ohlc and has_change:
            return "부분충분", "일부 OHLC/변화율 있음"
        if price > 0:
            return "현재가 중심", "OHLC 부족. 현재가·변화율 중심으로만 검증"
        return "부족", "가격/OHLC 저장값 부족"
    except Exception:
        return "확인필요", "차트데이터 품질 계산 오류"


def _v308_chart_snapshot(ticker: str, primary: dict = None, rank_row: dict = None, event_ts: float = None, source: str = "") -> dict:
    try:
        base = _BASE_CHART_SNAPSHOT_V310(ticker, primary, rank_row, event_ts, source) if callable(_BASE_CHART_SNAPSHOT_V310) else {}
        if not isinstance(base, dict):
            base = {}
        basis_ts = safe_float(base.get("basis_ts", event_ts or 0), 0)
        candle_ts = safe_float(base.get("candle_ts", 0), 0)
        if basis_ts > 0 and candle_ts > 0 and abs(candle_ts - basis_ts) > 180:
            base["original_candle_ts"] = candle_ts
            base["original_candle_time_text"] = base.get("candle_time_text", "")
            base["candle_ts"] = basis_ts
            base["candle_time_text"] = _v308_ts_text(basis_ts)
            base["candle_ts_fixed_v310"] = True
            _v310_inc("chart_time_mismatch_fixed", f"봉시각 보정 {base.get('ticker', ticker)}")
        quality, note = _v310_chart_quality(base)
        base["chart_data_quality"] = quality
        base["chart_data_quality_note"] = note
        if quality == "충분": _v310_inc("chart_quality_full")
        elif quality in {"부분충분"}: _v310_inc("chart_quality_partial")
        elif quality == "현재가 중심": _v310_inc("chart_quality_price_only")
        return base
    except Exception as e:
        try: append_runtime_error_log("v310_chart_snapshot", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return _BASE_CHART_SNAPSHOT_V310(ticker, primary, rank_row, event_ts, source) if callable(_BASE_CHART_SNAPSHOT_V310) else {}


try:
    _BASE_V309_SNAPSHOT_LINES_V310 = _v309_snapshot_lines
except Exception:
    _BASE_V309_SNAPSHOT_LINES_V310 = None


def _v309_snapshot_lines(snap: dict) -> list:
    try:
        lines = list(_BASE_V309_SNAPSHOT_LINES_V310(snap)) if callable(_BASE_V309_SNAPSHOT_LINES_V310) else []
        s = snap if isinstance(snap, dict) else {}
        quality = s.get("chart_data_quality") or _v310_chart_quality(s)[0]
        note = s.get("chart_data_quality_note") or _v310_chart_quality(s)[1]
        insert = [
            "[차트 데이터 품질 - v310]",
            f"- 품질: {quality} / {note}",
            "- 품질이 '현재가 중심' 또는 '부족'이면 OHLC 해석보다 현재가·성과·비교구간 검증을 우선",
        ]
        # [검증구간 참고] 앞에 넣는다.
        out = []
        inserted = False
        for line in lines:
            if (not inserted) and str(line).startswith("[검증구간 참고]"):
                out.extend(insert)
                inserted = True
            out.append(line)
        if not inserted:
            out.extend(insert)
        return out
    except Exception as e:
        return [f"- 차트 데이터 표시 오류(v310): {e}"]


try:
    _BASE_V309_SAMPLE_SUMMARY_V310 = _v309_sample_summary_line
except Exception:
    _BASE_V309_SAMPLE_SUMMARY_V310 = None


def _v309_sample_summary_line(sample: dict, idx: int) -> list:
    lines = list(_BASE_V309_SAMPLE_SUMMARY_V310(sample, idx)) if callable(_BASE_V309_SAMPLE_SUMMARY_V310) else []
    try:
        snap = (sample or {}).get("chart_snapshot", {}) if isinstance((sample or {}).get("chart_snapshot", {}), dict) else {}
        quality = snap.get("chart_data_quality") or _v310_chart_quality(snap)[0]
        # 봇차트 줄 바로 뒤에 품질을 붙인다.
        out = []
        done = False
        for line in lines:
            out.append(line)
            if (not done) and str(line).startswith("- 봇차트:"):
                out.append(f"- 차트데이터 품질: {quality}")
                done = True
        return out
    except Exception:
        return lines


