def _v311_status_lines() -> list:
    return [
        "🔥 v2.5.311 강한놓침 복귀/공통 추세확인",
        "- 위치: 2차 후보분류 + 3차 재감시복귀 + paper/trace 성과 + 출력 / 조건 전체 강화 아님",
        "- 참고조건: 일반 매매 프로그램식 1m·3m·5m 유지, 체결표본, 매수비율, 거래대금, 현재봉 밀림 여부를 같이 봄",
        f"- 바로진입: 공통확인통과 {V311_STATS.get('common_confirm_pass',0)} / 준비대기전환 {V311_STATS.get('weak_direct_to_prepare',0)}",
        f"- 강한놓침: 복귀감시 {V311_STATS.get('strong_miss_reentry_watch',0)} / 눌림감시 {V311_STATS.get('strong_miss_pullback_watch',0)} / 추격→눌림 {V311_STATS.get('chase_to_pullback_watch',0)}",
        f"- 성과표출력 {V311_STATS.get('paper_stats_rendered',0)} / 최근: {V311_STATS.get('last_note','대기')}",
    ]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_V311()) if callable(_BASE_CACHE_STATUS_V311) else "🧊 명령어 캐시 상태 /cache_status"
    try:
        if "🔥 v2.5.311 강한놓침 복귀/공통 추세확인" not in base:
            base += "\n" + "\n".join(_v311_status_lines())
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    return build_cache_status_text()


