def _v312_cancel_watch_hint(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        max_up = safe_float(row.get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float(row.get("current_after_cancel_pct", 0), 0)
        keep = (cur_up / max_up) if max_up > 0 else 0
        reason = str(row.get("cancel_reason", "") or "")
        if max_up >= V312_BIG_MISS_UP and cur_up >= V312_REENTRY_CUR_UP and keep >= V312_MIN_KEEP_RATIO:
            return "v312판단: 복귀감시 연결 대상"
        if "추격" in reason or "chase" in reason:
            return "v312판단: 추격금지 → 눌림 재진입 감시"
        if "힘빠짐" in reason or "신호악화" in reason:
            return "v312판단: 취소 후 3~15분 재확인 대상"
        if max_up >= V312_BIG_MISS_UP:
            return "v312판단: 강한 놓침 / 눌림감시 대상"
        return ""
    except Exception:
        return ""


def _v302_format_cancel_watch_row(row: dict, idx: int = 1, full: bool = False) -> str:
    base = str(_BASE_FORMAT_CANCEL_WATCH_ROW_V312(row, idx=idx, full=full)) if callable(_BASE_FORMAT_CANCEL_WATCH_ROW_V312) else ""
    hint = _v312_cancel_watch_hint(row)
    if hint and hint not in base:
        sep = "\n  - " if full else " / "
        base += sep + hint
    return base


