def _v313_active_queue_rows(limit: int = 6) -> list:
    try:
        _v313_load_state()
        now_ts = time.time()
        with V313_STATE_LOCK:
            rows = [dict(v) for v in (V313_REENTRY_STATE or {}).values() if isinstance(v, dict)]
        rows.sort(key=lambda r: safe_float(r.get("registered_ts", 0), 0), reverse=True)
        out = []
        for r in rows:
            ts = safe_float(r.get("registered_ts", 0), 0)
            if ts > 0 and now_ts - ts <= V313_FORCE_WATCH_TTL_SEC * 3:
                out.append(r)
        return out[:max(1, int(limit))]
    except Exception:
        return []


def _v313_queue_section(full: bool = False) -> str:
    rows = _v313_active_queue_rows(limit=8 if full else 4)
    lines = ["🧲 v313 강한놓침 강제감시"]
    lines.append("- 강한 놓침은 기록으로 끝내지 않고, 바로매수 없이 눌림/복귀 PENDING으로 강제 연결")
    if not rows:
        lines.append("- 현재 강제감시 등록 없음")
        return "\n".join(lines)
    for i, r in enumerate(rows, start=1):
        t = str(r.get("ticker", "?") or "?").upper()
        mode = "눌림감시" if str(r.get("mode", "")) == "pullback" else "복귀감시"
        age = format_elapsed_text(max(0, time.time() - safe_float(r.get("registered_ts", 0), 0))) if callable(globals().get("format_elapsed_text")) else f"{int(max(0, time.time()-safe_float(r.get('registered_ts',0),0)))}초"
        lines.append(f"{i}. {t} / {mode} / 최고 {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / 현재 {safe_float(r.get('current_after_cancel_pct',0),0):+.2f}% / 등록 {age} 전")
        if full:
            lines.append(f"   - 사유: {str(r.get('why',''))[:180]}")
    return "\n".join(lines)


