def _v315_read_json_quick(path: str) -> tuple[bool, str, object]:
    try:
        if not path:
            return False, "경로 없음", None
        if not os.path.exists(path):
            return True, "파일 없음(초기상태 가능)", None
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            return True, f"dict {len(data)}개", data
        if isinstance(data, list):
            return True, f"list {len(data)}개", data
        return True, type(data).__name__, data
    except Exception as e:
        return False, f"JSON 읽기 실패: {e.__class__.__name__}: {str(e)[:100]}", None


def _v315_compile_self_check() -> tuple[bool, str]:
    try:
        path = os.path.abspath(__file__)
        with open(path, "r", encoding="utf-8") as f:
            body = f.read()
        compile(body, path, "exec")
        return True, "현재 실행 파일 문법 통과"
    except Exception as e:
        return False, f"문법 확인 실패: {e.__class__.__name__}: {str(e)[:120]}"


def _v315_source_contains(pattern: str) -> bool:
    try:
        with open(os.path.abspath(__file__), "r", encoding="utf-8") as f:
            return str(pattern) in f.read()
    except Exception:
        return False


