def _v315_cache_status_lines() -> list:
    state = _v315_load_guard_state()
    checked_ts = safe_float(state.get("checked_ts", 0), 0)
    age_text = "아직 없음" if checked_ts <= 0 else format_elapsed_text(time.time() - checked_ts) + " 전"
    summary = str(state.get("summary", "대기") or "대기")
    checks = state.get("checks", []) if isinstance(state.get("checks", []), list) else []
    def _one(name):
        for c in checks:
            if str(c.get("name", "")) == name:
                return _v315_status_word(bool(c.get("ok")), bool(c.get("warn")))
        return "대기"
    rem = _v315_new_entry_pause_remaining_sec()
    pause_text = "가능 / 현재 꺼짐" if rem <= 0 else f"작동중 {format_elapsed_text(rem)} 남음"
    return [
        "🛡 v315 업데이트 안전장치",
        f"- 최근 route_doctor: {summary} / {age_text}",
        f"- 상태저장: {_one('상태저장 테스트')}",
        f"- 부팅복구: 파일 {_one('부팅복구 파일 읽기')} / 함수 {_one('부팅복구 함수')}",
        f"- 잔고대조: {_one('거래소 잔고 대조')}",
        f"- 기존보유 보호관리: {_one('기존 보유 보호관리')}",
        f"- 신규진입 일시정지: {pause_text}",
        f"- 차단횟수: 신규진입 {V315_STATS.get('new_entry_blocked',0)} / 최근: {V315_STATS.get('last_note','대기')}",
    ]


