# =========================================================
# v2.5.316: route_doctor 실연결 + 후보품질 진단
# 위치: 출력 + batch 라우팅 + 명령 핸들러 + paper/trace 품질 진단
# 핵심:
# - v315 안전장치가 내부 자가검사만 통과하고 실제 텔레그램 명령이 무응답인 상황을 잡는다.
# - /batch 안에서도 /route_doctor를 실행할 수 있게 한다.
# - 후보품질을 보지 못하는 문제를 줄이기 위해 새 API/OHLCV 없이 paper 로그 기준 품질 진단을 만든다.
# - 전략 조건 전체 강화가 아니라, 손실/취소/강한놓침/복귀강함 미전환 원인을 먼저 보이게 한다.
# =========================================================
V316_SCHEMA_VERSION = "route_quality_guard_v316"
V316_MODULE_LOAD_TS = time.time()
V316_STATS = {
    "manual_route_command": 0,
    "manual_route_fallback": 0,
    "batch_route_doctor": 0,
    "quality_command": 0,
    "quality_batch": 0,
    "cache_status_rendered": 0,
    "paper_stats_quality_rendered": 0,
    "last_route_ts": 0.0,
    "last_quality_ts": 0.0,
    "last_note": "대기",
}


def _v316_inc(key: str, note: str = ""):
    try:
        if key in V316_STATS:
            V316_STATS[key] = int(safe_float(V316_STATS.get(key, 0), 0)) + 1
        if key == "manual_route_command":
            V316_STATS["last_route_ts"] = time.time()
        if key in {"quality_command", "quality_batch"}:
            V316_STATS["last_quality_ts"] = time.time()
        if note:
            V316_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v316_status_age(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "아직 없음"
        return format_elapsed_text(max(0, time.time() - ts)) + " 전"
    except Exception:
        return "확인 안 됨"


def _v316_rows_recent(hours: float = 6.0, include_cancelled: bool = True) -> list:
    try:
        rows = _paper_closed_logs_v258(include_cancelled=include_cancelled) if '_paper_closed_logs_v258' in globals() else []
        start = time.time() - max(0.5, float(hours)) * 3600.0
        out = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            ts = safe_float(r.get("close_ts", r.get("cancel_ts", r.get("created_ts", 0))), 0)
            if ts >= start:
                out.append(dict(r))
        return out
    except Exception:
        return []


def _v316_easy_lane(row: dict) -> str:
    try:
        raw = str((row or {}).get("lane", (row or {}).get("trigger", (row or {}).get("entry_rule", ""))) or "")
        if '_paper_v301_easy_lane' in globals():
            txt = str(_paper_v301_easy_lane(raw))
            if txt and txt != raw:
                return txt
        if "strong_return_v314" in raw or str((row or {}).get("v314_route", "")) == "strong_return_breakout":
            return "v314 복귀강함"
        if "cancel_reentry_forced_v313_breakout" in raw:
            return "강한놓침 복귀감시"
        if "cancel_reentry_forced_v313_pullback" in raw:
            return "강한놓침 눌림감시"
        if str((row or {}).get("entry_rule", "")) == "breakout":
            return "돌파대기"
        if str((row or {}).get("entry_rule", "")) == "pullback":
            return "눌림/준비대기"
        if str((row or {}).get("entry_rule", "")) == "now":
            return "바로진입형"
        return raw or "분류없음"
    except Exception:
        return "분류오류"


def _v316_quality_stats(hours: float = 6.0) -> dict:
    rows = _v316_rows_recent(hours=hours, include_cancelled=True)
    closed = [r for r in rows if str(r.get("status", "")).upper() == "CLOSED"]
    cancelled = [r for r in rows if str(r.get("status", "")).upper() == "CANCELLED"]
    wins = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) > 0]
    losses = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) < 0]
    total = sum(safe_float(r.get("pnl_pct", 0), 0) for r in closed)
    pf = (sum(wins) / abs(sum(losses))) if losses and abs(sum(losses)) > 0 else (999.0 if wins else 0.0)
    cancel_reason = {}
    for r in cancelled:
        reason = str(r.get("close_reason", r.get("cancel_reason", "취소사유 없음")) or "취소사유 없음")
        cancel_reason[reason] = cancel_reason.get(reason, 0) + 1
    lane_stats = {}
    for r in closed:
        lane = _v316_easy_lane(r)
        st = lane_stats.setdefault(lane, {"n": 0, "wins": 0, "losses": 0, "pnl": 0.0})
        pnl = safe_float(r.get("pnl_pct", 0), 0)
        st["n"] += 1
        st["pnl"] += pnl
        if pnl > 0:
            st["wins"] += 1
        elif pnl < 0:
            st["losses"] += 1
    missed = []
    for r in cancelled:
        best = safe_float(r.get("max_up_after_cancel_pct", r.get("cancel_watch_max_up_pct", r.get("max_up_pct", 0))), 0)
        cur = safe_float(r.get("current_after_cancel_pct", r.get("last_up_pct", 0)), 0)
        if best >= 0.70:
            missed.append((best, cur, str(r.get("ticker", "?")), str(r.get("close_reason", ""))))
    missed.sort(reverse=True, key=lambda x: x[0])
    active_pending = []
    strong_mismatch = []
    try:
        with PAPER_STATE_LOCK:
            pos_rows = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict)]
        for p in pos_rows:
            status = str(p.get("status", "")).upper()
            if status == "PENDING":
                active_pending.append(p)
                lane = str(p.get("lane", "") or "")
                route = str(p.get("v314_route", "") or "")
                if ("strong_return" in lane or route == "strong_return_breakout") and str(p.get("entry_rule", "")) != "breakout":
                    strong_mismatch.append(p)
    except Exception:
        pass
    return {
        "hours": hours,
        "rows": rows,
        "closed": closed,
        "cancelled": cancelled,
        "wins": wins,
        "losses": losses,
        "total": total,
        "pf": pf,
        "cancel_reason": cancel_reason,
        "lane_stats": lane_stats,
        "missed": missed,
        "active_pending": active_pending,
        "strong_mismatch": strong_mismatch,
    }


def build_quality_check_text_v316(full: bool = False, hours: float = 6.0) -> str:
    try:
        q = _v316_quality_stats(hours=hours)
        closed = q.get("closed", [])
        cancelled = q.get("cancelled", [])
        wins = q.get("wins", [])
        losses = q.get("losses", [])
        n = len(closed)
        win_rate = (len(wins) / n * 100.0) if n else 0.0
        pf = safe_float(q.get("pf", 0), 0)
        total = safe_float(q.get("total", 0), 0)
        lines = [
            "🧪 후보품질 진단 /quality_check",
            f"- 기준: 최근 {hours:g}시간 / 새 API·OHLCV 호출 없음 / paper 저장값만 사용",
            f"- 모의청산: {n}전 {len(wins)}승 {len(losses)}패 / 승률 {win_rate:.1f}% / 누적 {total:+.2f}% / PF {pf:.2f}",
            f"- 진입취소: {len(cancelled)}개 / 현재대기 {len(q.get('active_pending', []))}개",
        ]
        if n == 0 and not cancelled:
            lines.append("- 아직 판단할 paper 표본이 없음")
        # 후보품질 결론
        if n >= 3 and (total < 0 or pf < 1.0):
            lines.append("- 결론: 후보품질 수정 필요. 지금은 좋은 후보를 고르는 단계보다 진입 전 취소/문턱 분리가 먼저 문제로 보임")
        elif n >= 3 and pf >= 1.3:
            lines.append("- 결론: 최근 표본은 나쁘지 않음. 조건을 더 조이기보다 놓친 후보/취소 후 상승을 우선 확인")
        else:
            lines.append("- 결론: 표본이 적어서 단정 금지. 그래도 취소 후 강한 놓침과 대기 중 신호악화는 계속 봐야 함")
        # 취소 원인 TOP
        cr = sorted(q.get("cancel_reason", {}).items(), key=lambda x: x[1], reverse=True)[:5]
        lines.append("")
        lines.append("🧯 취소 원인 TOP")
        if cr:
            for i, (reason, cnt) in enumerate(cr, 1):
                lines.append(f"{i}. {reason[:90]}: {cnt}회")
        else:
            lines.append("- 최근 취소 없음")
        # lane stats
        lane_stats = sorted(q.get("lane_stats", {}).items(), key=lambda kv: abs(safe_float(kv[1].get('pnl',0),0)), reverse=True)[:6]
        lines.append("")
        lines.append("📊 문턱별 후보품질")
        if lane_stats:
            for lane, st in lane_stats:
                n2 = int(st.get("n", 0)); w = int(st.get("wins", 0)); l = int(st.get("losses", 0)); pnl = safe_float(st.get("pnl", 0), 0)
                wr = (w / n2 * 100.0) if n2 else 0.0
                lines.append(f"- {lane}: {n2}전 {w}승 {l}패 / 승률 {wr:.0f}% / 누적 {pnl:+.2f}%")
        else:
            lines.append("- 최근 청산 표본 없음")
        # missed suspects
        missed = q.get("missed", [])[:5 if full else 3]
        lines.append("")
        lines.append("🚨 취소 후 놓침 의심")
        if missed:
            for i, (best, cur, ticker, reason) in enumerate(missed, 1):
                lines.append(f"{i}. {ticker} / 취소 후 최고 {best:+.2f}% / 현재 {cur:+.2f}% / 원인 {reason[:70]}")
        else:
            lines.append("- 최근 강한 놓침 의심 없음")
        # v314 mismatch / active pending
        mismatch = q.get("strong_mismatch", [])
        lines.append("")
        lines.append("🧲 v314 복귀강함 연결 확인")
        if mismatch:
            lines.append(f"- 주의: 복귀강함 표시인데 entry_rule이 breakout이 아닌 대기 {len(mismatch)}개")
            for p in mismatch[:3]:
                lines.append(f"  · {str(p.get('ticker','?')).upper()} / rule {p.get('entry_rule','?')} / lane {str(p.get('lane',''))[:70]}")
        else:
            lines.append("- 복귀강함 표시와 breakout 대기 불일치 없음")
        if full:
            lines.append("")
            lines.append("⏳ 현재 진입대기")
            active = q.get("active_pending", [])[:10]
            if active:
                for p in active:
                    age = format_elapsed_text(max(0, time.time() - safe_float(p.get('created_ts', 0), 0))) if safe_float(p.get('created_ts', 0), 0) > 0 else "나이 확인불가"
                    lines.append(f"- {str(p.get('ticker','?')).upper()} / {_v316_easy_lane(p)} / rule {p.get('entry_rule','?')} / {age} 전 / 사유 {str(p.get('register_reason',''))[:80]}")
            else:
                lines.append("- 현재 진입대기 없음")
        lines.append("")
        lines.append("다음 판단: /paper_flow_full 또는 /review_trace_detail 코인명으로 원인 확인")
        return "\n".join(lines)
    except Exception as e:
        return f"🧪 후보품질 진단 오류: {e.__class__.__name__}: {str(e)[:160]}"


