# =========================================================
# v2.5.317: early_pending_cancel 원인분해 + 좋은 후보 재감시 유지
# 위치: 2차 후보분류 + 3차 진입 전 취소 + paper/trace + 출력/성과집계
# 핵심:
# - early_pending_cancel_v267이 좋은 후보까지 삭제하는지 보이게 원인을 분해한다.
# - 좋은 후보는 취소=삭제가 아니라 재감시/눌림/복귀 대기로 한 번만 전환한다.
# - KNC처럼 같은 놓침이 여러 줄 반복되는 출력은 묶어서 본다.
# - v314 이후 성과가 거래 없음으로 보이는 문제를 보완하기 위해 v317부터 paper row에 version tag를 남긴다.
# - 조건 전체 강화가 아니라 취소 문턱의 오작동 경로를 좁게 고친다.
# =========================================================
V317_SCHEMA_VERSION = "early_cancel_quality_rewatch_v317"
V317_MODULE_LOAD_TS = time.time()
V317_STATS = {
    "cancel_checked": 0,
    "early_detail_logged": 0,
    "reroute_to_pullback": 0,
    "reroute_to_breakout": 0,
    "reroute_blocked_dead": 0,
    "reroute_blocked_weak": 0,
    "reroute_blocked_repeat": 0,
    "version_tag_close": 0,
    "version_tag_cancel": 0,
    "quality_rendered": 0,
    "cache_status_rendered": 0,
    "paper_stats_rendered": 0,
    "last_note": "대기",
}


def _v317_inc(key: str, note: str = ""):
    try:
        if key in V317_STATS:
            V317_STATS[key] = int(safe_float(V317_STATS.get(key, 0), 0)) + 1
        if note:
            V317_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v317_target_cancel_reason(reason: str) -> bool:
    r = str(reason or "").lower()
    return r in {"early_pending_cancel_v267", "entry_precheck_cancel_v266", "chase_over_before_entry"}


def _v317_cancel_detail(pos_or_row: dict, reason: str = "") -> str:
    try:
        row = pos_or_row if isinstance(pos_or_row, dict) else {}
        raw = str(row.get("v317_cancel_detail", "") or row.get("v267_cancel_reason", "") or row.get("v266_cancel_reason", "") or row.get("close_reason", "") or reason or "")
        txt = raw.lower()
        if "실제돈" in raw or "체결 사라" in raw:
            return "돈/체결 사라짐"
        if "60초 체결" in raw or "체결 없음" in raw:
            return "체결표본 없음"
        if "현재봉/돈흐름" in raw:
            return "현재봉+돈흐름 식음"
        if "고점 앞 체결 부족" in raw:
            return "고점 앞 체결 부족"
        if "즉시진입" in raw or "now" in txt:
            return "즉시진입 힘 부족"
        if "chase_over" in txt or "추격" in raw:
            return "추격금지 초과"
        if "entry_precheck" in txt or "진입직전" in raw or "힘빠짐" in raw:
            return "진입직전 힘빠짐"
        if "early_pending_cancel" in txt or "신호악화" in raw:
            return "대기 중 신호악화"
        if raw:
            return raw[:60]
    except Exception:
        pass
    return "취소세부 미확인"


def _v317_pos_force_or_watch_text(pos: dict) -> str:
    try:
        p = pos if isinstance(pos, dict) else {}
        return " ".join([
            str(p.get("lane", "") or ""),
            str(p.get("trigger", "") or ""),
            str(p.get("register_reason", "") or ""),
            str(p.get("signal_decision", "") or ""),
            str(p.get("v312_decision", "") or ""),
            str(p.get("v314_route", "") or ""),
        ]).lower()
    except Exception:
        return ""


def _v317_get_live_cls_for_pos(ticker: str, pos: dict) -> dict:
    try:
        if callable(globals().get("_v267_current_cls_for_pos")):
            cls = _v267_current_cls_for_pos(ticker, pos)
            return cls if isinstance(cls, dict) else {}
    except Exception:
        pass
    return {}


def _v317_strength_bits(cls: dict, pos: dict) -> dict:
    try:
        if callable(globals().get("_v266_strength_bits")):
            bits = _v266_strength_bits(cls if isinstance(cls, dict) else {}, cls if isinstance(cls, dict) else {})
            if isinstance(bits, dict):
                return bits
    except Exception:
        pass
    return {}


def _v317_assess_cancel_to_rewatch(pos: dict, reason: str, price: float, now_ts: float) -> dict:
    """취소 직전 후보를 삭제할지, 한 번만 재감시로 돌릴지 판단한다. 새 API/OHLCV 호출 없음."""
    out = {"keep": False, "mode": "", "detail": _v317_cancel_detail(pos, reason), "why": ""}
    try:
        pos = pos if isinstance(pos, dict) else {}
        ticker = str(pos.get("ticker", "") or "").upper().strip()
        if not ticker or not _v317_target_cancel_reason(reason):
            out["why"] = "대상 취소사유 아님"
            return out
        _v317_inc("cancel_checked")
        reroutes = int(safe_float(pos.get("v317_reroute_count", 0), 0))
        if reroutes >= 1:
            out["why"] = "이미 v317 재감시 1회 사용"
            _v317_inc("reroute_blocked_repeat", f"재감시 반복차단 {ticker}")
            return out
        price = safe_float(price if price > 0 else pos.get("last_price", 0), 0)
        if price <= 0:
            out["why"] = "현재가 없음"
            _v317_inc("reroute_blocked_dead", f"가격없음 {ticker}")
            return out
        low = safe_float(pos.get("planned_entry_low", 0), 0)
        high = safe_float(pos.get("planned_entry_high", 0), 0)
        chase = safe_float(pos.get("chase_stop", 0), 0)
        stop = safe_float(pos.get("stop", 0), 0)
        score = safe_float(pos.get("score", 0), 0)
        money = safe_float(pos.get("money_amount", 0), 0)
        trade_count = int(safe_float(pos.get("trade_count", 0), 0))
        buy_ratio = safe_float(pos.get("buy_ratio", 0), 0)
        age_sec = max(0.0, now_ts - safe_float(pos.get("created_ts", now_ts), now_ts))
        text = _v317_pos_force_or_watch_text(pos)
        force_lane = any(k in text for k in ["cancel_reentry", "강한놓침", "복귀감시", "눌림감시", "strong_return", "v314"])
        cls = _v317_get_live_cls_for_pos(ticker, pos)
        bits = _v317_strength_bits(cls, pos)
        grade = str(cls.get("grade", pos.get("signal_grade", "")) or "")
        live_score = safe_float(cls.get("score", score), score)
        bit_money = safe_float(bits.get("money", money), money)
        bit_trade = int(safe_float(bits.get("trade_count", trade_count), trade_count))
        bit_buy = safe_float(bits.get("buy_ratio", buy_ratio), buy_ratio)
        candle_weak = bool(bits.get("candle_weak", False))
        money_weak = bool(bits.get("money_weak", False))
        # 진짜 무너진 후보는 재감시로 살리지 않는다.
        if stop > 0 and price <= stop * 1.003 and not force_lane:
            out["why"] = "손절선 근처라 재감시 금지"
            _v317_inc("reroute_blocked_dead", f"손절근처 {ticker}")
            return out
        if low > 0 and price < low * 0.985 and not force_lane:
            out["why"] = "계획가 아래로 이미 무너짐"
            _v317_inc("reroute_blocked_dead", f"계획가이탈 {ticker}")
            return out
        if age_sec >= 22 * 60 and not force_lane and live_score < 4.2:
            out["why"] = "대기 오래됐고 강한 근거 부족"
            _v317_inc("reroute_blocked_weak", f"오래된약함 {ticker}")
            return out
        has_flow = (bit_trade >= 1 or bit_buy >= 42 or bit_money >= 500_000 or money >= 1_000_000)
        price_hold = bool((low <= 0 or price >= low * 0.995) and (stop <= 0 or price > stop * 1.006))
        good_evidence = bool(
            force_lane
            or (score >= 4.2 and price_hold and has_flow)
            or (live_score >= 4.4 and price_hold and has_flow)
            or (grade not in {"", "DISCARD"} and score >= 3.8 and price_hold and has_flow)
            or (str(reason) == "chase_over_before_entry" and price_hold and (score >= 3.8 or force_lane))
        )
        if not good_evidence:
            out["why"] = "재감시할 만큼의 가격유지/돈흐름 근거 부족"
            _v317_inc("reroute_blocked_weak", f"근거부족 {ticker}")
            return out
        # 현재봉+돈이 둘 다 죽었고 강제감시도 아니면 살리지 않는다.
        if candle_weak and money_weak and not force_lane and score < 5.0:
            out["why"] = "현재봉과 돈흐름이 같이 죽음"
            _v317_inc("reroute_blocked_weak", f"현재봉돈약함 {ticker}")
            return out
        r = str(reason or "")
        # 너무 위로 달아난 경우는 추격하지 않고 눌림 재감시로만 남긴다.
        if r == "chase_over_before_entry" or (chase > 0 and price > chase) or (high > 0 and price > high * 1.006):
            out.update({"keep": True, "mode": "pullback", "why": "추격 취소 대신 눌림 재감시"})
        elif force_lane or grade == "BREAKOUT_WAIT" or price_hold:
            out.update({"keep": True, "mode": "breakout", "why": "신호악화 취소 대신 짧은 재상승 확인"})
        else:
            out.update({"keep": True, "mode": "pullback", "why": "삭제 대신 눌림 재확인"})
        return out
    except Exception as e:
        out["why"] = f"평가오류 {e.__class__.__name__}"
        return out


def _v317_apply_rewatch(pos_id: str, pos: dict, price: float, reason: str, assess: dict, now_ts: float) -> bool:
    try:
        ticker = str((pos or {}).get("ticker", "") or "").upper().strip()
        if not ticker or not assess.get("keep"):
            return False
        mode = str(assess.get("mode", "pullback") or "pullback")
        detail = str(assess.get("detail", "") or _v317_cancel_detail(pos, reason))
        why = str(assess.get("why", "") or "취소 대신 재감시")
        price = safe_float(price if price > 0 else (pos or {}).get("last_price", 0), 0)
        if price <= 0:
            return False
        with PAPER_STATE_LOCK:
            cur = paper_positions.get(pos_id)
            if not isinstance(cur, dict) or str(cur.get("status", "")).upper() != "PENDING":
                return False
            reroutes = int(safe_float(cur.get("v317_reroute_count", 0), 0)) + 1
            cur.setdefault("v317_original_created_ts", safe_float(cur.get("created_ts", now_ts), now_ts))
            cur.setdefault("v317_original_entry_rule", str(cur.get("entry_rule", "") or ""))
            cur["v317_reroute_count"] = reroutes
            cur["v317_last_reroute_ts"] = now_ts
            cur["v317_cancel_reason"] = str(reason or "")
            cur["v317_cancel_detail"] = detail
            cur["v317_reroute_why"] = why
            cur["last_price"] = price
            cur["last_price_source"] = "v317_rewatch_guard"
            cur["updated_ts"] = now_ts
            cur["created_ts"] = now_ts
            lane = str(cur.get("lane", "") or "")
            if mode == "breakout":
                cur["entry_rule"] = "breakout"
                cur["planned_entry_low"] = round(price * 1.0015, 8)
                cur["planned_entry_high"] = round(price * 1.0015, 8)
                cur["chase_stop"] = round(price * 1.018, 8)
                suffix = "_v317_breakout_rewatch"
                cur["signal_decision"] = "v317 취소 대신 복귀/재상승 확인대기"
            else:
                cur["entry_rule"] = "pullback"
                cur["planned_entry_low"] = round(price * 0.982, 8)
                cur["planned_entry_high"] = round(price * 0.997, 8)
                cur["chase_stop"] = round(price * 1.020, 8)
                suffix = "_v317_pullback_rewatch"
                cur["signal_decision"] = "v317 취소 대신 눌림 재감시"
            if suffix not in lane:
                cur["lane"] = (lane + suffix)[:200]
            cur["register_reason"] = (str(cur.get("register_reason", "") or "") + f" / v317 {why}: {detail}")[:520]
            # stop/TP가 비어 있거나 너무 낡았을 때 최소 안전값만 보정. 실주문 아님.
            if safe_float(cur.get("stop", 0), 0) <= 0:
                cur["stop"] = round(price * 0.982, 8)
            if safe_float(cur.get("tp1", 0), 0) <= 0:
                cur["tp1"] = round(price * 1.010, 8)
            if safe_float(cur.get("tp2", 0), 0) <= 0:
                cur["tp2"] = round(price * 1.020, 8)
            if safe_float(cur.get("tp3", 0), 0) <= 0:
                cur["tp3"] = round(price * 1.035, 8)
        save_paper_state_v258()
        if mode == "breakout":
            _v317_inc("reroute_to_breakout", f"취소대신 복귀감시 {ticker}/{detail}")
        else:
            _v317_inc("reroute_to_pullback", f"취소대신 눌림감시 {ticker}/{detail}")
        return True
    except Exception as e:
        try: append_runtime_error_log("v317_apply_rewatch", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False


try:
    _BASE_PAPER_CANCEL_PENDING_V317 = _paper_cancel_pending_v258
except Exception:
    _BASE_PAPER_CANCEL_PENDING_V317 = None


def _paper_cancel_pending_v258(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    now_ts = safe_float(now_ts, time.time())
    try:
        if isinstance(pos, dict):
            pos["v317_cancel_detail"] = _v317_cancel_detail(pos, reason)
            pos["bot_version_at_cancel"] = BOT_VERSION
            pos["version_tag"] = BOT_VERSION
        if _v317_target_cancel_reason(reason):
            ticker = str((pos or {}).get("ticker", "") or "").upper().strip()
            fallback = safe_float((pos or {}).get("last_price", (pos or {}).get("planned_entry_high", (pos or {}).get("planned_entry_low", 0))), 0)
            try:
                price, src, age = _paper_price_v258(ticker, fallback=fallback) if ticker else (fallback, "fallback", 0)
            except Exception:
                price, src, age = fallback, "fallback", 0
            assess = _v317_assess_cancel_to_rewatch(pos if isinstance(pos, dict) else {}, reason, safe_float(price, 0), now_ts)
            if assess.get("keep") and _v317_apply_rewatch(pos_id, pos, safe_float(price, 0), reason, assess, now_ts):
                return None
        if callable(_BASE_PAPER_CANCEL_PENDING_V317):
            _v317_inc("version_tag_cancel")
            return _BASE_PAPER_CANCEL_PENDING_V317(pos_id, pos, reason, now_ts)
    except Exception as e:
        try: append_runtime_error_log("paper_cancel_v317", str(e), exc=e, include_traceback=False)
        except Exception: pass
        if callable(_BASE_PAPER_CANCEL_PENDING_V317):
            return _BASE_PAPER_CANCEL_PENDING_V317(pos_id, pos, reason, now_ts)
    return None


try:
    _BASE_PAPER_CLOSE_POSITION_V317 = _paper_close_position_v258
except Exception:
    _BASE_PAPER_CLOSE_POSITION_V317 = None


def _paper_close_position_v258(pos_id: str, pos: dict, price: float, reason: str, now_ts: float = None):
    try:
        if isinstance(pos, dict):
            pos["bot_version_at_close"] = BOT_VERSION
            pos["version_tag"] = BOT_VERSION
            pos.setdefault("route_label_at_close", _v316_easy_lane(pos) if callable(globals().get("_v316_easy_lane")) else str(pos.get("lane", "")))
        _v317_inc("version_tag_close")
    except Exception:
        pass
    if callable(_BASE_PAPER_CLOSE_POSITION_V317):
        return _BASE_PAPER_CLOSE_POSITION_V317(pos_id, pos, price, reason, now_ts)
    return None


def _v317_rows_recent(hours: float = 6.0, include_cancelled: bool = True) -> list:
    try:
        return _v316_rows_recent(hours=hours, include_cancelled=include_cancelled) if callable(globals().get("_v316_rows_recent")) else []
    except Exception:
        return []


def _v317_quality_stats(hours: float = 6.0) -> dict:
    try:
        q = _v316_quality_stats(hours=hours) if callable(globals().get("_v316_quality_stats")) else {}
        rows = q.get("rows", []) if isinstance(q, dict) else []
        cancelled = q.get("cancelled", []) if isinstance(q, dict) else []
        early_details = {}
        for r in cancelled:
            reason = str(r.get("close_reason", "") or "")
            if reason in {"early_pending_cancel_v267", "entry_precheck_cancel_v266", "chase_over_before_entry"}:
                d = _v317_cancel_detail(r, reason)
                early_details[d] = early_details.get(d, 0) + 1
        # 같은 티커/비슷한 최고수익률/같은 취소사유는 한 줄로 묶는다.
        dedup = {}
        for r in cancelled:
            best = safe_float(r.get("max_up_after_cancel_pct", r.get("cancel_watch_max_up_pct", r.get("max_up_pct", 0))), 0)
            cur = safe_float(r.get("current_after_cancel_pct", r.get("last_up_pct", 0)), 0)
            if best < 0.70:
                continue
            ticker = str(r.get("ticker", "?") or "?").upper()
            reason = str(r.get("close_reason", "") or "")
            key = (ticker, reason, round(best, 1))
            prev = dedup.get(key)
            if prev is None or best > safe_float(prev.get("best", 0), 0):
                dedup[key] = {"ticker": ticker, "reason": reason, "best": best, "cur": cur, "count": 1, "detail": _v317_cancel_detail(r, reason)}
            else:
                prev["count"] = int(prev.get("count", 1)) + 1
                prev["cur"] = max(safe_float(prev.get("cur", 0), 0), cur)
        missed_grouped = sorted(dedup.values(), key=lambda x: safe_float(x.get("best", 0), 0), reverse=True)
        rerouted_active = []
        try:
            with PAPER_STATE_LOCK:
                rerouted_active = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict) and int(safe_float(p.get("v317_reroute_count", 0), 0)) > 0]
        except Exception:
            pass
        q["early_details_v317"] = early_details
        q["missed_grouped_v317"] = missed_grouped
        q["rerouted_active_v317"] = rerouted_active
        return q
    except Exception as e:
        try: append_runtime_error_log("v317_quality_stats", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {}


try:
    _BASE_BUILD_QUALITY_CHECK_TEXT_V317 = build_quality_check_text_v316
except Exception:
    _BASE_BUILD_QUALITY_CHECK_TEXT_V317 = None


def build_quality_check_text_v316(full: bool = False, hours: float = 6.0) -> str:
    try:
        q = _v317_quality_stats(hours=hours)
        closed = q.get("closed", [])
        cancelled = q.get("cancelled", [])
        wins = q.get("wins", [])
        losses = q.get("losses", [])
        n = len(closed)
        win_rate = (len(wins) / n * 100.0) if n else 0.0
        pf = safe_float(q.get("pf", 0), 0)
        total = safe_float(q.get("total", 0), 0)
        lines = [
            "🧪 후보품질 진단 /quality_check",
            f"- 기준: 최근 {hours:g}시간 / 새 API·OHLCV 호출 없음 / paper 저장값만 사용",
            f"- 모의청산: {n}전 {len(wins)}승 {len(losses)}패 / 승률 {win_rate:.1f}% / 누적 {total:+.2f}% / PF {pf:.2f}",
            f"- 진입취소: {len(cancelled)}개 / 현재대기 {len(q.get('active_pending', []))}개 / v317 재감시대기 {len(q.get('rerouted_active_v317', []))}개",
        ]
        if n >= 3 and (total < 0 or pf < 1.0):
            lines.append("- 결론: 후보품질 수정 필요. 특히 취소=삭제 문턱이 좋은 후보까지 죽이는지 봐야 함")
        elif n >= 3 and pf >= 1.3:
            lines.append("- 결론: 최근 표본은 나쁘지 않음. 조건을 더 조이기보다 놓친 후보/취소 후 상승을 우선 확인")
        else:
            lines.append("- 결론: 표본이 적어서 단정 금지. 취소 후 강한 놓침과 재감시 전환을 계속 봐야 함")
        cr = sorted(q.get("cancel_reason", {}).items(), key=lambda x: x[1], reverse=True)[:5]
        lines.append("")
        lines.append("🧯 취소 원인 TOP")
        if cr:
            for i, (reason, cnt) in enumerate(cr, 1):
                lines.append(f"{i}. {reason[:90]}: {cnt}회")
        else:
            lines.append("- 최근 취소 없음")
        lines.append("")
        lines.append("🔎 early/진입전 취소 세부")
        details = sorted(q.get("early_details_v317", {}).items(), key=lambda x: x[1], reverse=True)[:7]
        if details:
            for i, (d, cnt) in enumerate(details, 1):
                lines.append(f"{i}. {d}: {cnt}회")
        else:
            lines.append("- 최근 early/진입전 취소 세부 없음")
        lane_stats = sorted(q.get("lane_stats", {}).items(), key=lambda kv: abs(safe_float(kv[1].get('pnl',0),0)), reverse=True)[:6]
        lines.append("")
        lines.append("📊 문턱별 후보품질")
        if lane_stats:
            for lane, st in lane_stats:
                n2 = int(st.get("n", 0)); w = int(st.get("wins", 0)); l = int(st.get("losses", 0)); pnl = safe_float(st.get("pnl", 0), 0)
                wr = (w / n2 * 100.0) if n2 else 0.0
                lines.append(f"- {lane}: {n2}전 {w}승 {l}패 / 승률 {wr:.0f}% / 누적 {pnl:+.2f}%")
        else:
            lines.append("- 최근 청산 표본 없음")
        lines.append("")
        lines.append("🚨 취소 후 놓침 의심(중복 묶음)")
        missed = q.get("missed_grouped_v317", [])[:7 if full else 4]
        if missed:
            for i, m in enumerate(missed, 1):
                cnt = int(m.get("count", 1))
                more = f" / 중복 {cnt}건" if cnt > 1 else ""
                lines.append(f"{i}. {m.get('ticker','?')} / 최고 {safe_float(m.get('best',0),0):+.2f}% / 현재 {safe_float(m.get('cur',0),0):+.2f}% / {m.get('detail','')} / 원인 {str(m.get('reason',''))[:55]}{more}")
        else:
            lines.append("- 최근 강한 놓침 의심 없음")
        lines.append("")
        lines.append("🧭 v317 취소대신 재감시")
        lines.append(f"- 눌림재감시 {V317_STATS.get('reroute_to_pullback',0)} / 복귀재감시 {V317_STATS.get('reroute_to_breakout',0)}")
        lines.append(f"- 차단: 무너짐 {V317_STATS.get('reroute_blocked_dead',0)} / 약함 {V317_STATS.get('reroute_blocked_weak',0)} / 반복 {V317_STATS.get('reroute_blocked_repeat',0)}")
        active = q.get("rerouted_active_v317", [])[:5]
        if active:
            for p in active:
                age = format_elapsed_text(max(0, time.time() - safe_float(p.get('v317_last_reroute_ts', p.get('created_ts', 0)), 0))) if safe_float(p.get('v317_last_reroute_ts', p.get('created_ts', 0)), 0) > 0 else "나이확인불가"
                lines.append(f"  · {str(p.get('ticker','?')).upper()} / {p.get('entry_rule','?')} / {age} 전 / {str(p.get('v317_cancel_detail',''))[:50]}")
        if full:
            lines.append("")
            lines.append("⏳ 현재 진입대기")
            active2 = q.get("active_pending", [])[:12]
            if active2:
                for p in active2:
                    age = format_elapsed_text(max(0, time.time() - safe_float(p.get('created_ts', 0), 0))) if safe_float(p.get('created_ts', 0), 0) > 0 else "나이 확인불가"
                    lines.append(f"- {str(p.get('ticker','?')).upper()} / {_v316_easy_lane(p)} / rule {p.get('entry_rule','?')} / {age} 전 / {str(p.get('register_reason',''))[:80]}")
            else:
                lines.append("- 현재 진입대기 없음")
        _v317_inc("quality_rendered", "quality_check v317 표시")
        lines.append("")
        lines.append("다음 판단: /paper_flow_full 또는 /review_trace_detail 코인명으로 원인 확인")
        return "\n".join(lines)
    except Exception as e:
        if callable(_BASE_BUILD_QUALITY_CHECK_TEXT_V317):
            try:
                return _BASE_BUILD_QUALITY_CHECK_TEXT_V317(full=full, hours=hours) + f"\n\n[v317 후보품질 표시 오류] {e.__class__.__name__}: {str(e)[:120]}"
            except Exception:
                pass
        return f"🧪 후보품질 진단 오류: {e.__class__.__name__}: {str(e)[:160]}"


