def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V317()) if callable(_BASE_BUILD_PAPER_STATS_V317) else "📊 모의매매 성과 /paper_stats"
    try:
        rows = _paper_closed_logs_v258(include_cancelled=False) if callable(globals().get("_paper_closed_logs_v258")) else []
        since = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            # v317부터는 version_tag가 있으면 그것을 우선 사용하고, 없으면 현재 재시작 이후 표본만 보조로 본다.
            tag = str(r.get("version_tag", r.get("bot_version_at_close", "")) or "")
            ts = safe_float(r.get("close_ts", 0), 0)
            if "v2.5.317" in tag or ts >= V317_MODULE_LOAD_TS:
                since.append(r)
        sec = ["", "[v317 적용 이후 성과 - early 취소 재감시/후보품질]"]
        sec.append("- 목표: 좋은 후보를 early_pending_cancel에서 바로 죽이지 않고 한 번은 눌림/복귀 재감시로 남기는지 확인")
        if since:
            sec.append(_paper_stats_line_v258("v317 이후", since))
            try:
                sec.extend(_v307_route_stats_section(since, title="v317 이후 문턱별"))
            except Exception:
                pass
        else:
            sec.append("- 거래: 없음 / v317 적용 후 새 청산이 쌓이면 표시")
        sec.append(f"- 재감시 전환: 눌림 {V317_STATS.get('reroute_to_pullback',0)} / 복귀 {V317_STATS.get('reroute_to_breakout',0)}")
        sec.append(f"- 세부원인/중복놓침은 /quality_check full에서 확인")
        if "[v317 적용 이후 성과" not in base:
            base += "\n" + "\n".join(sec)
        _v317_inc("paper_stats_rendered", "paper_stats v317 표시")
    except Exception as e:
        base += f"\n\n[v317 성과표] 표시 오류: {e.__class__.__name__}: {str(e)[:120]}"
    return base


