# =========================================================
# v2.5.318: route_doctor 판정오류/부팅표시 안정화
# 위치: 출력 + 안전검사 + 부팅 추적 + 신규진입 보호
# 핵심:
# - v317에서 문법 통과인데 v2.5.315/316만 허용해 route_doctor가 실패로 뜨던 false fail 수정.
# - 실제 치명 실패와 단순 주의/표시 문제를 분리한다.
# - 같은 프로세스 안에서 시작 알림이 중복 발송되지 않게 막고, 짧은 재부팅은 기록으로 남긴다.
# - v317 후보품질 로직은 유지한다. 후보 조건 전체 강화/자동매수/손절TP 변경 없음.
# =========================================================
V318_SCHEMA_VERSION = "route_doctor_boot_guard_v318"
V318_BOOT_GUARD_FILE = data_file("update_guard_v318_boot.json")
V318_MODULE_LOAD_TS = time.time()
V318_STARTUP_READY_SENT = False
V318_STARTUP_DONE_SENT = False
V318_STATS = {
    "route_doctor_fixed": 0,
    "critical_pause_set": 0,
    "ready_sent": 0,
    "ready_duplicate_blocked": 0,
    "startup_sent": 0,
    "startup_duplicate_blocked": 0,
    "last_note": "대기",
}


def _v318_inc(key: str, note: str = ""):
    try:
        if key in V318_STATS:
            V318_STATS[key] = int(safe_float(V318_STATS.get(key, 0), 0)) + 1
        if note:
            V318_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v318_load_boot_file() -> dict:
    try:
        data = load_json_file(V318_BOOT_GUARD_FILE, {}) if callable(globals().get("load_json_file")) else {}
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def _v318_save_boot_file(data: dict):
    try:
        save_json_file(V318_BOOT_GUARD_FILE, data if isinstance(data, dict) else {})
    except Exception as e:
        try: append_runtime_error_log("v318_save_boot_file", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v318_record_boot_marker() -> dict:
    try:
        now_ts = time.time()
        prev = _v318_load_boot_file()
        prev_ts = safe_float(prev.get("last_boot_ts", 0), 0)
        prev_version = str(prev.get("last_version", "") or "")
        count = int(safe_float(prev.get("boot_count", 0), 0)) + 1
        short_restart = bool(prev_ts > 0 and now_ts - prev_ts <= 10 * 60)
        same_version_short = bool(short_restart and prev_version == BOT_VERSION)
        info = {
            "schema": V318_SCHEMA_VERSION,
            "boot_count": count,
            "last_boot_ts": now_ts,
            "last_boot_text": format_ts_mdhm(now_ts),
            "last_version": BOT_VERSION,
            "previous_boot_ts": prev_ts,
            "previous_boot_text": format_ts_mdhm(prev_ts) if prev_ts > 0 else "없음",
            "previous_version": prev_version,
            "seconds_since_previous_boot": int(now_ts - prev_ts) if prev_ts > 0 else -1,
            "short_restart": short_restart,
            "same_version_short_restart": same_version_short,
        }
        _v318_save_boot_file(info)
        if same_version_short:
            _v318_inc("route_doctor_fixed", "같은 버전 짧은 재부팅 감지")
        return info
    except Exception as e:
        try: append_runtime_error_log("v318_record_boot_marker", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {"schema": V318_SCHEMA_VERSION, "boot_error": str(e)[:120]}


V318_BOOT_INFO = _v318_record_boot_marker()


def _v318_boot_line() -> str:
    try:
        prev_sec = int(safe_float(V318_BOOT_INFO.get("seconds_since_previous_boot", -1), -1)) if isinstance(V318_BOOT_INFO, dict) else -1
        count = int(safe_float(V318_BOOT_INFO.get("boot_count", 0), 0)) if isinstance(V318_BOOT_INFO, dict) else 0
        if prev_sec >= 0:
            return f"부팅기록 #{count} / 이전 부팅 {format_elapsed_text(prev_sec)} 전"
        return f"부팅기록 #{count} / 이전 부팅 없음"
    except Exception:
        return "부팅기록 확인중"


try:
    _BASE_V315_RUN_ROUTE_DOCTOR_V318 = _v315_run_route_doctor
except Exception:
    _BASE_V315_RUN_ROUTE_DOCTOR_V318 = None


def _v318_is_version_ok() -> bool:
    try:
        v = str(BOT_VERSION or "")
        return v.startswith("수익형 v2.5.") or "v2.5." in v
    except Exception:
        return False


def _v318_fix_route_result(result: dict, full_balance: bool = False, auto: bool = False) -> dict:
    try:
        result = result if isinstance(result, dict) else {}
        checks = list(result.get("checks", []) if isinstance(result.get("checks", []), list) else [])
        compile_ok, compile_msg = _v315_compile_self_check() if callable(globals().get("_v315_compile_self_check")) else (True, "문법 확인 함수 없음")
        version_ok = _v318_is_version_ok()
        fixed = False
        for c in checks:
            if isinstance(c, dict) and str(c.get("name", "")) == "코드 문법/버전":
                c["ok"] = bool(compile_ok and version_ok)
                c["warn"] = bool(compile_ok and not version_ok)
                c["detail"] = f"{BOT_VERSION} / {compile_msg}" if version_ok else f"버전명 확인 필요: {BOT_VERSION} / {compile_msg}"
                fixed = True
                break
        if not fixed:
            checks.insert(0, _v315_check_item("코드 문법/버전", bool(compile_ok and version_ok), f"{BOT_VERSION} / {compile_msg}", warn=bool(compile_ok and not version_ok)))
        boot_warn = bool(isinstance(V318_BOOT_INFO, dict) and V318_BOOT_INFO.get("same_version_short_restart"))
        boot_detail = _v318_boot_line()
        if boot_warn:
            boot_detail += " / 같은 버전 짧은 재부팅 감지: journalctl로 원인 확인 권장"
        # 기존 결과에 같은 항목이 없을 때만 추가한다.
        if not any(isinstance(c, dict) and str(c.get("name", "")) == "부팅/재시작 추적" for c in checks):
            checks.append(_v315_check_item("부팅/재시작 추적", True, boot_detail, warn=boot_warn))

        critical_names = {"부팅복구 파일 읽기", "부팅복구 함수", "기존 보유 보호관리", "paper worker 연결", "강한놓침 복귀 경로"}
        critical_fail = any((isinstance(c, dict) and str(c.get("name", "")) in critical_names and not bool(c.get("ok"))) for c in checks)
        any_fail = any((isinstance(c, dict) and not bool(c.get("ok"))) for c in checks)
        any_warn = any((isinstance(c, dict) and bool(c.get("warn"))) for c in checks)
        current_boot_error_fail = any((isinstance(c, dict) and str(c.get("name", "")) == "현재부팅 오류로그" and not bool(c.get("ok"))) for c in checks)
        # 현재부팅 오류는 바로 치명으로 단정하지 않고 주의로 올린다. 포지션/worker 경로가 끊긴 경우만 위험.
        if current_boot_error_fail:
            any_warn = True
        summary = "통과"
        ok_flag = True
        warn_flag = False
        severity = "pass"
        if critical_fail:
            summary = "위험"
            ok_flag = False
            warn_flag = True
            severity = "critical"
        elif any_fail or any_warn:
            summary = "주의"
            ok_flag = True
            warn_flag = True
            severity = "warn"
        result.update({
            "schema": "update_guard_v318",
            "bot_version": BOT_VERSION,
            "checked_ts": result.get("checked_ts", time.time()),
            "checked_text": result.get("checked_text", format_ts_mdhm(time.time())),
            "auto": bool(auto),
            "full_balance": bool(full_balance),
            "checks": checks,
            "ok": ok_flag,
            "warn": warn_flag,
            "summary": summary,
            "severity": severity,
            "v318_fixed_false_fail": True,
        })
        try:
            _v315_save_guard_state(result)
        except Exception:
            pass
        if critical_fail and not v315_new_entry_paused():
            try:
                set_v315_new_entry_pause(True, minutes=30, reason="route_doctor_critical_v318")
                _v318_inc("critical_pause_set", "route_doctor 치명 실패로 신규진입 자동정지")
            except Exception:
                pass
        _v318_inc("route_doctor_fixed", f"route_doctor {summary}")
        return result
    except Exception as e:
        try: append_runtime_error_log("v318_fix_route_result", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return result if isinstance(result, dict) else {}


def _v315_run_route_doctor(full_balance: bool = False, auto: bool = False) -> dict:
    try:
        if callable(_BASE_V315_RUN_ROUTE_DOCTOR_V318):
            base = _BASE_V315_RUN_ROUTE_DOCTOR_V318(full_balance=full_balance, auto=auto)
        else:
            base = {"checks": [], "summary": "주의", "ok": True, "warn": True, "bot_version": BOT_VERSION, "checked_ts": time.time(), "checked_text": format_ts_mdhm(time.time())}
        return _v318_fix_route_result(base, full_balance=full_balance, auto=auto)
    except Exception as e:
        try: append_runtime_error_log("route_doctor_v318", str(e), exc=e, include_traceback=True)
        except Exception: pass
        result = {"schema": "update_guard_v318", "bot_version": BOT_VERSION, "checked_ts": time.time(), "checked_text": format_ts_mdhm(time.time()), "ok": False, "warn": True, "summary": "위험", "severity": "critical", "checks": [_v315_check_item("route_doctor 자체", False, f"v318 자가검사 오류: {e.__class__.__name__}: {str(e)[:160]}")]}
        try: _v315_save_guard_state(result)
        except Exception: pass
        return result


try:
    _BASE_V315_FORMAT_ROUTE_DOCTOR_V318 = _v315_format_route_doctor_result
except Exception:
    _BASE_V315_FORMAT_ROUTE_DOCTOR_V318 = None


def _v315_format_route_doctor_result(result: dict) -> str:
    try:
        txt = _BASE_V315_FORMAT_ROUTE_DOCTOR_V318(result) if callable(_BASE_V315_FORMAT_ROUTE_DOCTOR_V318) else "🧪 경로 자가검사 /route_doctor"
        result = result if isinstance(result, dict) else {}
        severity = str(result.get("severity", "") or "")
        txt = str(txt).replace("결론: 실패 항목 있음. 신규진입은 막고 원인부터 확인", "결론: 위험 항목이면 신규진입을 자동 보호하고, 단순 주의는 원인만 확인")
        txt = txt.replace("결론: 큰 실패는 없지만 주의 항목이 있음. 세부 항목 먼저 확인", "결론: 치명 실패는 아님. 주의 항목만 확인하면 됨")
        if severity == "critical":
            txt += "\n- v318 보호: 치명 실패라 신규진입 일시정지를 자동 적용했거나 적용 대상이야."
        elif severity == "warn":
            txt += "\n- v318 판정: 포지션/worker 치명 실패가 아니면 전체 실패로 보지 않음."
        else:
            txt += "\n- v318 판정: 문법/버전 false fail 보정 적용됨."
        return txt
    except Exception as e:
        return f"🧪 경로 자가검사 /route_doctor\n- 표시 오류: {e.__class__.__name__}: {str(e)[:160]}"


try:
    _BASE_V315_AUTO_ROUTE_WORKER_V318 = v315_auto_route_doctor_worker
except Exception:
    _BASE_V315_AUTO_ROUTE_WORKER_V318 = None


def v315_auto_route_doctor_worker():
    try:
        time.sleep(V315_ROUTE_DOCTOR_AUTO_DELAY_SEC)
        result = _v315_run_route_doctor(full_balance=False, auto=True)
        if (not result.get("ok")) or result.get("warn"):
            txt = _v315_format_route_doctor_result(result)
            send_text_chunks("🛡 v318 업데이트 안전검사 주의\n\n" + txt, limit=3200)
    except Exception as e:
        try: append_runtime_error_log("v318_auto_route_doctor_worker", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v315_cache_status_lines() -> list:
    state = _v315_load_guard_state() if callable(globals().get("_v315_load_guard_state")) else {}
    checked_ts = safe_float(state.get("checked_ts", 0), 0) if isinstance(state, dict) else 0
    age_text = format_elapsed_text(time.time() - checked_ts) + " 전" if checked_ts > 0 else "아직 없음"
    summary = str(state.get("summary", "대기") or "대기") if isinstance(state, dict) else "대기"
    checks = state.get("checks", []) if isinstance(state, dict) and isinstance(state.get("checks", []), list) else []
    def _find_status(name):
        for c in checks:
            if isinstance(c, dict) and str(c.get("name", "")) == name:
                return _v315_status_word(bool(c.get("ok")), bool(c.get("warn")))
        return "미확인"
    rem = _v315_new_entry_pause_remaining_sec() if callable(globals().get("_v315_new_entry_pause_remaining_sec")) else 0
    return [
        "🛡 v318 업데이트 안전장치",
        f"- 최근 route_doctor: {summary} / {age_text}",
        f"- 상태저장: {_find_status('상태저장 테스트')}",
        f"- 부팅복구: 파일 {_find_status('부팅복구 파일 읽기')} / 함수 {_find_status('부팅복구 함수')}",
        f"- 잔고대조: {_find_status('거래소 잔고 대조')}",
        f"- 기존보유 보호관리: {_find_status('기존 보유 보호관리')}",
        f"- 부팅추적: {_find_status('부팅/재시작 추적')} / {_v318_boot_line()}",
        f"- 신규진입 일시정지: {'켜짐 ' + format_elapsed_text(rem) + ' 남음' if rem > 0 else '가능 / 현재 꺼짐'}",
        f"- 차단횟수: 신규진입 {V315_STATS.get('new_entry_blocked',0)} / 최근: {V318_STATS.get('last_note','대기')}",
    ]


