def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    cmd_l = str(cmd or "").lower().strip().lstrip("/")
    args = list(args or [])
    shown_cmd = f"/{cmd_l}" + (" " + " ".join([str(a) for a in args]) if args else "")
    label = f"▶️ 묶음 {idx}/{total} {shown_cmd}" if total > 1 else f"▶️ {shown_cmd}"
    if cmd_l in {"route_doctor", "doctor"}:
        _v319_inc("batch_quick", "batch route_doctor quick")
        full = any(str(x).lower().strip() in {"full", "balance", "잔고", "전체"} for x in args)
        result = _v319_build_quick_route_result(full_balance=full, auto=False, source="batch")
        send_text_chunks(_v315_format_route_doctor_result(result), prefix=label, limit=3000)
        _v319_store_last_route_result(result)
        return
    if callable(_BASE_EXECUTE_SINGLE_BATCH_V319):
        return _BASE_EXECUTE_SINGLE_BATCH_V319(cmd, args, idx, total)
    send(f"{label}\n- batch 처리 원본 함수를 찾지 못했어")

