def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_TEXT_V319()) if callable(_BASE_CACHE_STATUS_TEXT_V319) else "🧊 명령어 캐시 상태 /cache_status"
    try:
        # 이전 v315/v318 fail 문구가 남아도 새 v319 섹션을 아래에 명확히 붙인다.
        base = base.replace("🛡 v315 업데이트 안전장치", "🛡 업데이트 안전장치")
        base = base.replace("🛡 v318 업데이트 안전장치", "🛡 업데이트 안전장치")
        if "🧯 v319 route_doctor 무응답 방지" not in base:
            base += "\n" + "\n".join(_v319_cache_status_lines())
        _v319_inc("cache_status_rendered", "cache_status v319 표시")
    except Exception:
        pass
    return base

def build_cache_status_full_text():
    return build_cache_status_text()

