# =========================================================
# v2.5.320: route_doctor 원인수리 + 후보품질 연결강화
# =========================================================
# 수정 위치:
# - 출력/명령 라우팅: route_doctor는 명령어가 직접 무거운 검사하지 않고 snapshot만 읽는다.
# - worker: main이 이미 띄우는 v315_auto_route_doctor_worker를 v320 snapshot worker로 바꾼다.
# - 2차/3차/paper: 관심후보·실전급 후보가 약하면 바로/쉬운 진입 금지, 공통확인/눌림확인으로 강제 연결한다.
# - paper/trace: early_pending_cancel·entry_precheck·chase_over에서 좋은 후보를 삭제하지 않고 최대 2회 재감시로 강하게 연결한다.
# 원칙:
# - route_doctor 삭제 아님. 원인은 “명령어 직접검사/구버전 핸들러/파일락 가능성”으로 보고 snapshot 구조로 수리.
# - 조건 전체 강화 아님. 손실이 난 관심/실전급 경로만 강등하고, 성과가 좋은 강한놓침 눌림/복귀 경로는 살린다.

V320_SCHEMA_VERSION = "route_snapshot_quality_force_v320"
V320_ROUTE_SNAPSHOT_LOCK = threading.RLock()
V320_ROUTE_SNAPSHOT = {}
V320_ROUTE_WORKER_STARTED = False
V320_ROUTE_WORKER_INTERVAL_SEC = 45.0
V320_ROUTE_BUILDING = False
V320_STATS = {
    "route_snapshot_build": 0,
    "route_snapshot_error": 0,
    "route_manual": 0,
    "route_batch": 0,
    "route_worker_tick": 0,
    "register_guard_checked": 0,
    "interest_to_pullback": 0,
    "real_grade_to_common_wait": 0,
    "real_grade_to_pullback": 0,
    "force_watch_blocked_register": 0,
    "early_cancel_checked": 0,
    "early_to_breakout_rewatch": 0,
    "early_to_pullback_rewatch": 0,
    "early_rewatch_repeat2": 0,
    "strong_miss_force_connected": 0,
    "pending_force_connected": 0,
    "last_note": "대기",
}

def _v320_inc(key: str, note: str = ""):
    try:
        if key in V320_STATS:
            V320_STATS[key] = int(safe_float(V320_STATS.get(key, 0), 0)) + 1
        if note:
            V320_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass

def _v320_text_has_any(text: str, words: list) -> bool:
    s = str(text or "").lower()
    return any(str(w).lower() in s for w in (words or []))

def _v320_join_text(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        keys = [
            "ticker", "lane", "entry_rule", "register_reason", "signal_decision", "decision", "grade",
            "v266_reason", "v270_reason", "v274_bridge_reason", "v275_bridge_reason",
            "v312_route", "v313_route", "v314_route", "v317_cancel_detail", "close_reason",
        ]
        return " / ".join(str(row.get(k, "") or "") for k in keys)
    except Exception:
        return ""

def _v320_price_from_pos(pos: dict) -> float:
    try:
        p = safe_float((pos or {}).get("last_price", 0), 0)
        if p <= 0:
            p = safe_float((pos or {}).get("current_price", 0), 0)
        if p <= 0:
            p = safe_float((pos or {}).get("planned_entry_high", 0), 0)
        if p <= 0:
            p = safe_float((pos or {}).get("planned_entry_low", 0), 0)
        return p
    except Exception:
        return 0.0

def _v320_strength_snapshot(row: dict) -> dict:
    """저장된 row/pos 값만 사용한다. 새 API/OHLCV 호출 금지."""
    row = row if isinstance(row, dict) else {}
    try:
        text = _v320_join_text(row)
        price = _v320_price_from_pos(row)
        trade_count = int(safe_float(row.get("trade_count", row.get("ws_trade_count_60s", row.get("cnt60", 0))), 0))
        buy_ratio = safe_float(row.get("buy_ratio", row.get("ws_trade_buy_ratio_60s", row.get("br60", 0))), 0)
        money = safe_float(row.get("money_amount", row.get("turnover_5m", row.get("turnover_recent_5m", row.get("ws_trade_amount_60s", 0)))), 0)
        score = safe_float(row.get("score", row.get("expected_score", row.get("edge_score", 0))), 0)
        chg1 = safe_float(row.get("change_1", row.get("chg_1m", row.get("current_candle_change_pct", 0))), 0)
        chg3 = safe_float(row.get("change_3", row.get("chg_3m", row.get("chg_3", 0))), 0)
        chg5 = safe_float(row.get("change_5", row.get("chg_5m", row.get("chg_5", 0))), 0)
        high_gap = safe_float(row.get("below_30m_high_pct", row.get("high_gap_pct", row.get("below_high", 999))), 999)
        from_low = safe_float(row.get("from_low", row.get("from_30m_low_pct", row.get("chart_lifecycle_from_low_pct", 0))), 0)
        live_score = safe_float(row.get("current_candle_live_score", 0), 0)
        pressure = safe_float(row.get("current_candle_pressure_score", 0), 0)
        follow = safe_float(row.get("current_candle_follow_score", 0), 0)
        current_label = str(row.get("current_candle_label", "") or "")
        money_label = str(row.get("money_sustain_label", row.get("money_status", "")) or "")
        strong_miss = _v320_text_has_any(text, ["강한놓침", "강한 놓침", "복귀감시", "눌림감시", "reentry", "v313", "v314"])
        interest = _v320_text_has_any(text, ["관심 후보", "관심후보", "관심 후보→진입 대기"])
        real_grade = _v320_text_has_any(text, ["실전급 후보", "실전급"])
        candle_bad = (pressure >= 1.25) or _v320_text_has_any(current_label, ["밀림", "위꼬리", "약함"])
        money_bad = _v320_text_has_any(money_label, ["식음", "매도우세", "얇", "없음", "약함"])
        live_ok = (live_score >= 1.25 or follow >= 0.55 or chg1 >= 0.05 or chg3 >= 0.08 or chg5 >= 0.12)
        money_ok = (money >= 750000 or trade_count >= 3 or buy_ratio >= 50)
        distance_ok = (high_gap >= 0.55 or high_gap >= 900) and from_low <= 4.2
        common_ok = bool(live_ok and money_ok and distance_ok and not (candle_bad and money_bad))
        strong_ok = bool(common_ok and (score >= 4.0 or strong_miss or buy_ratio >= 52 or trade_count >= 5) and not candle_bad)
        return {
            "price": price,
            "trade_count": trade_count,
            "buy_ratio": buy_ratio,
            "money": money,
            "score": score,
            "chg1": chg1,
            "chg3": chg3,
            "chg5": chg5,
            "high_gap": high_gap,
            "from_low": from_low,
            "live_score": live_score,
            "pressure": pressure,
            "follow": follow,
            "strong_miss": strong_miss,
            "interest": interest,
            "real_grade": real_grade,
            "candle_bad": candle_bad,
            "money_bad": money_bad,
            "live_ok": live_ok,
            "money_ok": money_ok,
            "distance_ok": distance_ok,
            "common_ok": common_ok,
            "strong_ok": strong_ok,
            "text": text,
        }
    except Exception as e:
        return {"error": str(e)[:120], "price": 0.0, "common_ok": False, "strong_ok": False}

def _v320_set_pullback_window(pos: dict, price: float, tight: bool = False):
    try:
        if price <= 0:
            return
        low_mul = 0.988 if tight else 0.982
        high_mul = 0.998 if tight else 0.996
        pos["planned_entry_low"] = round(price * low_mul, 8)
        pos["planned_entry_high"] = round(price * high_mul, 8)
        pos["chase_stop"] = round(price * 1.006, 8)
    except Exception:
        pass

def _v320_set_breakout_window(pos: dict, price: float, soft: bool = False):
    try:
        if price <= 0:
            return
        low_mul = 1.0006 if soft else 1.0012
        high_mul = 1.0045 if soft else 1.0070
        pos["planned_entry_low"] = round(price * low_mul, 8)
        pos["planned_entry_high"] = round(price * high_mul, 8)
        pos["chase_stop"] = round(price * (1.011 if soft else 1.016), 8)
    except Exception:
        pass

def _v320_apply_register_guard_to_pos(pos_id: str, pos: dict) -> bool:
    """등록 직후 관심/실전급 약한 경로를 강제로 공통확인/눌림확인에 연결한다."""
    try:
        if not isinstance(pos, dict):
            return False
        snap = _v320_strength_snapshot(pos)
        price = snap.get("price", 0.0)
        changed = False
        # 관심 후보는 성과가 나쁘므로 무조건 바로/쉬운 돌파 진입 금지. 강하면 눌림확인, 약하면 더 깊은 눌림확인.
        if snap.get("interest"):
            if str(pos.get("entry_rule", "") or "") != "pullback" or str(pos.get("status", "") or "").upper() == "OPEN":
                pos["status"] = "PENDING"
                pos["entry_rule"] = "pullback"
                pos["lane"] = str(pos.get("lane", "관심 후보→진입 대기") or "관심 후보→진입 대기")
                pos["signal_decision"] = "v320 관심후보는 바로진입 금지 → 눌림 확인 후 진입"
                pos["v320_quality_guard"] = "interest_to_pullback"
                _v320_set_pullback_window(pos, price, tight=bool(snap.get("common_ok")))
                _v320_inc("interest_to_pullback", f"관심후보 눌림확인 {pos.get('ticker','?')}")
                changed = True
        # 실전급 후보가 실제로 현재봉/돈/거리 공통확인을 못 통과하면 이름값을 낮춰서 대기시킨다.
        if snap.get("real_grade"):
            if snap.get("strong_ok"):
                # 강한 실전급도 바로 OPEN은 피하고 now_prepare 성격으로 1회 확인을 둔다.
                if str(pos.get("entry_rule", "") or "") == "now" or str(pos.get("status", "") or "").upper() == "OPEN":
                    pos["status"] = "PENDING"
                    pos["entry_rule"] = "now_prepare"
                    pos["signal_decision"] = "v320 실전급도 현재봉/돈흐름 1회 공통확인 후 진입"
                    pos["v320_quality_guard"] = "real_grade_common_wait"
                    _v320_set_breakout_window(pos, price, soft=True)
                    _v320_inc("real_grade_to_common_wait", f"실전급 공통확인 {pos.get('ticker','?')}")
                    changed = True
            else:
                pos["status"] = "PENDING"
                pos["entry_rule"] = "pullback"
                pos["signal_decision"] = "v320 실전급 이름값 부족 → 바로진입 금지, 눌림 재확인"
                pos["v320_quality_guard"] = "real_grade_to_pullback"
                _v320_set_pullback_window(pos, price, tight=False)
                _v320_inc("real_grade_to_pullback", f"실전급 눌림강등 {pos.get('ticker','?')}")
                changed = True
        if changed:
            pos["v320_guard_ts"] = time.time()
            pos["v320_guard_snapshot"] = {k: snap.get(k) for k in ["trade_count", "buy_ratio", "money", "score", "chg1", "chg3", "chg5", "high_gap", "from_low", "live_score", "pressure", "common_ok", "strong_ok"]}
            with PAPER_STATE_LOCK:
                if pos_id in paper_positions and isinstance(paper_positions.get(pos_id), dict):
                    paper_positions[pos_id].update(pos)
            try:
                save_paper_state_v258()
            except Exception:
                pass
        return changed
    except Exception as e:
        try: append_runtime_error_log("v320_register_guard", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False

def _v320_force_connect_pending_positions(reason: str = "worker") -> int:
    """기존 PENDING 중 끊긴 연결을 강제로 정렬한다. 새 조회 없이 paper 저장값만 사용."""
    changed = 0
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            if str(pos.get("status", "") or "").upper() != "PENDING":
                continue
            snap = _v320_strength_snapshot(pos)
            text = snap.get("text", "")
            price = snap.get("price", 0.0)
            ch = False
            # 강한놓침 복귀감시는 눌림만 기다리다 놓치는 일이 많으므로 복귀/재상승 확인으로 강제 연결.
            if snap.get("strong_miss") and _v320_text_has_any(text, ["복귀감시", "복귀강함", "breakout", "v314"]):
                if str(pos.get("entry_rule", "") or "") not in {"breakout", "now_prepare"}:
                    pos["entry_rule"] = "breakout"
                    pos["signal_decision"] = "v320 강한놓침 복귀감시 → 재상승 확인대기 강제연결"
                    pos["v320_force_connected"] = "strong_miss_breakout"
                    _v320_set_breakout_window(pos, price, soft=True)
                    _v320_inc("strong_miss_force_connected", f"강한놓침 복귀강제 {pos.get('ticker','?')}")
                    ch = True
            # 강한놓침 눌림감시는 성과가 좋으므로 pullback 연결을 유지/강제.
            if snap.get("strong_miss") and _v320_text_has_any(text, ["눌림감시", "pullback"]):
                if str(pos.get("entry_rule", "") or "") != "pullback":
                    pos["entry_rule"] = "pullback"
                    pos["signal_decision"] = "v320 강한놓침 눌림감시 → 눌림확인 강제연결"
                    pos["v320_force_connected"] = "strong_miss_pullback"
                    _v320_set_pullback_window(pos, price, tight=True)
                    _v320_inc("strong_miss_force_connected", f"강한놓침 눌림강제 {pos.get('ticker','?')}")
                    ch = True
            if snap.get("interest") or snap.get("real_grade"):
                if _v320_apply_register_guard_to_pos(pid, pos):
                    ch = True
            if ch:
                changed += 1
                with PAPER_STATE_LOCK:
                    if pid in paper_positions and isinstance(paper_positions.get(pid), dict):
                        paper_positions[pid].update(pos)
        if changed:
            _v320_inc("pending_force_connected", f"대기연결 정렬 {changed}개/{reason}")
            try: save_paper_state_v258()
            except Exception: pass
    except Exception as e:
        try: append_runtime_error_log("v320_force_connect_pending", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return changed

try:
    _BASE_PAPER_REGISTER_V320 = paper_register_candidate_v258
except Exception:
    _BASE_PAPER_REGISTER_V320 = None

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    """후보 등록 후 약한 관심/실전급 경로를 강제로 공통확인/눌림확인으로 연결."""
    try:
        _v320_inc("register_guard_checked")
        before_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
        ok = _BASE_PAPER_REGISTER_V320(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V320) else False
        if ok:
            after_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
            new_ids = list(after_ids - before_ids)
            # 중복등록 제한 때문에 새 id가 없을 수도 있으므로 같은 ticker 최근 pending도 같이 본다.
            ticker = str((row or {}).get("ticker", "") or "").upper().strip()
            if not new_ids and ticker:
                with PAPER_STATE_LOCK:
                    new_ids = [pid for pid, p in (paper_positions or {}).items() if isinstance(p, dict) and str(p.get("ticker", "")).upper() == ticker]
            for pid in new_ids[-3:]:
                try:
                    with PAPER_STATE_LOCK:
                        pos = dict(paper_positions.get(pid, {})) if isinstance(paper_positions.get(pid, {}), dict) else {}
                    _v320_apply_register_guard_to_pos(pid, pos)
                except Exception:
                    pass
            _v320_force_connect_pending_positions(reason="register")
        return ok
    except Exception as e:
        try: append_runtime_error_log("paper_register_v320", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return _BASE_PAPER_REGISTER_V320(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V320) else False

def _v320_apply_cancel_rewatch(pos_id: str, pos: dict, reason: str, mode: str, why: str, now_ts: float) -> bool:
    try:
        if not isinstance(pos, dict):
            return False
        ticker = str(pos.get("ticker", "") or "").upper().strip()
        if not ticker:
            return False
        with PAPER_STATE_LOCK:
            cur = dict(paper_positions.get(pos_id, pos) or pos)
            if not isinstance(cur, dict):
                return False
            price = _v320_price_from_pos(cur)
            reroutes = int(safe_float(cur.get("v320_reroute_count", cur.get("v317_reroute_count", 0)), 0)) + 1
            cur["status"] = "PENDING"
            cur["entry_rule"] = "breakout" if mode == "breakout" else "pullback"
            cur["v320_reroute_count"] = reroutes
            cur["v320_last_reroute_ts"] = now_ts
            cur["v320_cancel_reason"] = str(reason or "")
            cur["v320_reroute_why"] = why
            cur["version_tag"] = BOT_VERSION
            cur["bot_version_at_cancel_guard"] = BOT_VERSION
            cur["signal_decision"] = "v320 취소 삭제 금지 → " + ("복귀/재상승 확인대기" if mode == "breakout" else "눌림 재감시")
            cur["register_reason"] = (str(cur.get("register_reason", "") or "") + f" / v320 {why}")[:700]
            if mode == "breakout":
                _v320_set_breakout_window(cur, price, soft=True)
                _v320_inc("early_to_breakout_rewatch", f"취소대신 복귀 {ticker}")
            else:
                _v320_set_pullback_window(cur, price, tight=True)
                _v320_inc("early_to_pullback_rewatch", f"취소대신 눌림 {ticker}")
            if reroutes >= 2:
                _v320_inc("early_rewatch_repeat2", f"2회재감시 {ticker}")
            paper_positions[pos_id] = cur
        try: save_paper_state_v258()
        except Exception: pass
        return True
    except Exception as e:
        try: append_runtime_error_log("v320_apply_cancel_rewatch", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False

try:
    _BASE_PAPER_CANCEL_PENDING_V320 = _paper_cancel_pending_v258
except Exception:
    _BASE_PAPER_CANCEL_PENDING_V320 = None

def _paper_cancel_pending_v258(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    """좋은 후보를 early/precheck/chase 취소에서 바로 삭제하지 않고 강제로 재감시 연결."""
    now_ts = safe_float(now_ts, time.time())
    try:
        r = str(reason or "")
        if r in {"early_pending_cancel_v267", "entry_precheck_cancel_v266", "chase_over_before_entry"}:
            _v320_inc("early_cancel_checked")
            p = dict(pos or {})
            with PAPER_STATE_LOCK:
                if pos_id in paper_positions and isinstance(paper_positions.get(pos_id), dict):
                    p.update(dict(paper_positions.get(pos_id, {})))
            snap = _v320_strength_snapshot(p)
            reroutes = int(safe_float(p.get("v320_reroute_count", p.get("v317_reroute_count", 0)), 0))
            price = snap.get("price", 0.0)
            stop = safe_float(p.get("stop_price", p.get("stop", 0)), 0)
            dead = bool((stop > 0 and price > 0 and price <= stop * 1.003) or (snap.get("candle_bad") and snap.get("money_bad") and not snap.get("strong_miss")))
            # v320은 한 번으로 끝내지 않고 강한 후보는 최대 2회까지 연결한다.
            if (not dead) and reroutes < 2:
                if snap.get("strong_miss"):
                    mode = "breakout" if (snap.get("common_ok") or r != "chase_over_before_entry") else "pullback"
                    if _v320_apply_cancel_rewatch(pos_id, p, r, mode, "강한놓침/복귀후보 취소삭제 차단", now_ts):
                        return None
                elif r == "chase_over_before_entry" and price > 0:
                    if _v320_apply_cancel_rewatch(pos_id, p, r, "pullback", "추격초과는 삭제 대신 눌림확인", now_ts):
                        return None
                elif snap.get("common_ok") and (snap.get("live_ok") or snap.get("money_ok")):
                    mode = "breakout" if snap.get("live_ok") and not snap.get("candle_bad") else "pullback"
                    if _v320_apply_cancel_rewatch(pos_id, p, r, mode, "공통확인 일부 생존", now_ts):
                        return None
    except Exception as e:
        try: append_runtime_error_log("paper_cancel_v320_guard", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_PAPER_CANCEL_PENDING_V320):
        return _BASE_PAPER_CANCEL_PENDING_V320(pos_id, pos, reason, now_ts)
    return None

