def _v320_build_route_snapshot(source: str = "worker") -> dict:
    """route_doctor 원인수리: 새 API/py_compile/대형 JSON 파싱 없이 메모리와 파일 크기만 확인."""
    global V320_ROUTE_BUILDING
    t0 = time.time()
    if V320_ROUTE_BUILDING:
        with V320_ROUTE_SNAPSHOT_LOCK:
            cached = dict(V320_ROUTE_SNAPSHOT or {})
        if cached:
            cached["note"] = "이전 snapshot 반환 / 새 snapshot 생성 중"
            return cached
    V320_ROUTE_BUILDING = True
    try:
        checks = []
        def add(name, ok=True, detail="", warn=False):
            checks.append({"name": str(name), "ok": bool(ok), "warn": bool(warn), "detail": str(detail or "")[:240]})
        add("버전/실행상태", str(BOT_VERSION).startswith("수익형 v2.5."), f"{BOT_VERSION} / py_compile 직접 실행 안 함")
        add("명령 연결", callable(globals().get("route_doctor_command")) and callable(globals().get("_execute_single_batch_command")), "direct/batch 핸들러는 snapshot만 읽음")
        try:
            files = []
            for label, path in [("positions", POSITIONS_FILE), ("pending_sells", PENDING_SELLS_FILE), ("pending_buys", PENDING_BUYS_FILE), ("settings", RUNTIME_SETTINGS_FILE)]:
                if os.path.exists(path):
                    files.append(f"{label}:{os.path.getsize(path)}B")
                else:
                    files.append(f"{label}:없음")
            add("상태파일 존재/크기", True, " / ".join(files))
        except Exception as e:
            add("상태파일 존재/크기", False, f"확인 오류 {e.__class__.__name__}", warn=True)
        apos = active_positions if isinstance(active_positions, dict) else {}
        psells = pending_sells if isinstance(pending_sells, dict) else {}
        add("기존 보유 보호관리", True, f"active {len(apos)} / pending_sell {len(psells)}")
        try:
            with PAPER_STATE_LOCK:
                paper_n = len(paper_positions or {}) if isinstance(paper_positions, dict) else 0
                pending_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "PENDING")
                open_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "OPEN")
            add("paper worker/상태", True, f"paper {paper_n} / PENDING {pending_n} / OPEN {open_n}")
        except Exception as e:
            add("paper worker/상태", False, f"확인 오류 {e.__class__.__name__}", warn=True)
        add("강한놓침 연결", callable(globals().get("_v320_force_connect_pending_positions")) and callable(globals().get("_v320_apply_cancel_rewatch")), "v313/v314/v317/v320 강제연결 함수 확인")
        try:
            body = read_runtime_error_log_current_boot(max_lines=12)
            if body:
                add("현재부팅 오류로그", False, "현재부팅 오류 있음 / /errorlog 확인", warn=True)
            else:
                add("현재부팅 오류로그", True, "현재 부팅 이후 새 오류 없음")
        except Exception:
            add("현재부팅 오류로그", True, "quick 오류로그 확인 생략", warn=True)
        bad = [c for c in checks if (not c.get("ok")) and not c.get("warn")]
        warn = [c for c in checks if c.get("warn") or not c.get("ok")]
        summary = "통과" if not bad and not warn else ("주의" if not bad else "위험")
        result = {"schema": V320_SCHEMA_VERSION, "source": source, "bot_version": BOT_VERSION, "checked_ts": time.time(), "elapsed_sec": round(time.time()-t0, 3), "summary": summary, "ok": not bad, "warn": bool(warn), "checks": checks}
        with V320_ROUTE_SNAPSHOT_LOCK:
            V320_ROUTE_SNAPSHOT.clear(); V320_ROUTE_SNAPSHOT.update(result)
        _v320_inc("route_snapshot_build", f"route snapshot {summary}")
        return result
    except Exception as e:
        _v320_inc("route_snapshot_error", f"route snapshot 오류 {e.__class__.__name__}")
        return {"schema": V320_SCHEMA_VERSION, "source": source, "bot_version": BOT_VERSION, "checked_ts": time.time(), "elapsed_sec": round(time.time()-t0, 3), "summary": "주의", "ok": True, "warn": True, "checks": [{"name": "route snapshot", "ok": True, "warn": True, "detail": f"생성 오류 {e.__class__.__name__}: {str(e)[:120]}"}]}
    finally:
        V320_ROUTE_BUILDING = False

def _v320_format_route_snapshot(result: dict) -> str:
    try:
        r = result if isinstance(result, dict) else {}
        ts = safe_float(r.get("checked_ts", 0), 0)
        age = format_elapsed_text(time.time() - ts) + " 전" if ts > 0 else "없음"
        lines = [
            "🧪 경로 자가검사 /route_doctor",
            "",
            f"- 버전: {BOT_VERSION}",
            f"- 방식: v320 snapshot quick / 명령어 직접검사 없음",
            f"- 최근 검사: {age} / 소요 {safe_float(r.get('elapsed_sec',0),0):.2f}s",
            f"- 종합: {r.get('summary','확인중')}",
            "",
        ]
        for i, c in enumerate(list(r.get("checks", []) or []), start=1):
            icon = "✅" if c.get("ok") and not c.get("warn") else ("⚠️" if c.get("warn") or c.get("ok") else "❌")
            lines.append(f"{i}. {icon} {c.get('name','?')}: {'통과' if c.get('ok') else '확인필요'}")
            d = str(c.get("detail", "") or "").strip()
            if d:
                lines.append(f"   - {d}")
        lines.append("")
        lines.append("원칙: route_doctor는 삭제하지 않고, worker snapshot만 읽어서 멈춤 원인을 제거함")
        lines.append("후보품질 확인은 /quality_check, 흐름 확인은 /paper_flow")
        return "\n".join(lines).strip()
    except Exception as e:
        return f"🧪 경로 자가검사 /route_doctor\n- 표시 오류: {e.__class__.__name__}: {str(e)[:120]}"

def _v320_get_route_snapshot_or_build(source: str = "manual") -> dict:
    with V320_ROUTE_SNAPSHOT_LOCK:
        cached = dict(V320_ROUTE_SNAPSHOT or {})
    age = time.time() - safe_float(cached.get("checked_ts", 0), 0) if cached else 999999
    if cached and age <= 180:
        return cached
    return _v320_build_route_snapshot(source=source)

def route_doctor_command(update, context: CallbackContext):
    try:
        _v320_inc("route_manual", "route_doctor snapshot 수동")
        result = _v320_get_route_snapshot_or_build(source="manual")
        send_text_chunks(_v320_format_route_snapshot(result), limit=2600)
    except Exception as e:
        try: append_runtime_error_log("route_doctor_v320", str(e), exc=e, include_traceback=False)
        except Exception: pass
        send(f"🧪 /route_doctor snapshot 오류: {e.__class__.__name__}: {str(e)[:120]}")

def route_doctor_text_fallback_v316(update, context: CallbackContext):
    return route_doctor_command(update, context)

def v320_route_snapshot_worker_loop():
    while True:
        try:
            _v320_inc("route_worker_tick")
            _v320_build_route_snapshot(source="worker")
        except Exception as e:
            try: append_runtime_error_log("v320_route_snapshot_worker", str(e), exc=e, include_traceback=False)
            except Exception: pass
        time.sleep(max(15.0, safe_float(V320_ROUTE_WORKER_INTERVAL_SEC, 45.0)))

def v315_auto_route_doctor_worker():
    """main이 기존 이름으로 thread를 띄우므로, 그 경로를 v320 snapshot worker로 강제 연결한다."""
    global V320_ROUTE_WORKER_STARTED
    try:
        if V320_ROUTE_WORKER_STARTED:
            return
        V320_ROUTE_WORKER_STARTED = True
        _v320_build_route_snapshot(source="startup")
        v320_route_snapshot_worker_loop()
    except Exception as e:
        try: append_runtime_error_log("v315_auto_route_doctor_worker_v320", str(e), exc=e, include_traceback=False)
        except Exception: pass

