def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    cmd_l = str(cmd or "").lower().strip()
    label = f"▶️ 묶음 {idx}/{total} /{cmd_l}" if total > 1 else f"▶️ /{cmd_l}"
    if cmd_l in {"route_doctor", "doctor"}:
        _v320_inc("route_batch", "batch route_doctor snapshot")
        result = _v320_get_route_snapshot_or_build(source="batch")
        send_text_chunks(_v320_format_route_snapshot(result), prefix=label, limit=2600)
        return
    if callable(_BASE_EXECUTE_SINGLE_BATCH_V320):
        return _BASE_EXECUTE_SINGLE_BATCH_V320(cmd, args, idx, total)
    send(f"{label}\n- batch 처리 원본 함수를 찾지 못했어")

