def build_paper_stats_text_v258(full: bool = False) -> str:
    base = _BASE_PAPER_STATS_COMMAND_TEXT_V320(full=full) if callable(_BASE_PAPER_STATS_COMMAND_TEXT_V320) else "📊 모의매매 성과 /paper_stats"
    try:
        if "[v320 연결강화 이후 확인]" not in base:
            base = str(base).rstrip() + "\n\n" + "\n".join([
                "[v320 연결강화 이후 확인]",
                "- 목표: 실전급/관심후보 약한 진입을 줄이고, 강한놓침 눌림/복귀 경로를 강제로 이어 수익률을 올리는지 확인",
                f"- 관심→눌림 {V320_STATS.get('interest_to_pullback',0)} / 실전급대기 {V320_STATS.get('real_grade_to_common_wait',0)} / 실전급눌림 {V320_STATS.get('real_grade_to_pullback',0)}",
                f"- 취소대신복귀 {V320_STATS.get('early_to_breakout_rewatch',0)} / 취소대신눌림 {V320_STATS.get('early_to_pullback_rewatch',0)} / 강한놓침연결 {V320_STATS.get('strong_miss_force_connected',0)}",
                "- 성과 판단은 /quality_check의 문턱별 후보품질과 함께 본다",
            ])
    except Exception:
        pass
    return base

try:
    _BASE_SEND_STARTUP_V320 = send_startup_message
except Exception:
    _BASE_SEND_STARTUP_V320 = None

def send_startup_message():
    lines = [
        "✅ 봇 시작 완료",
        f"현재 버전: {BOT_VERSION}",
        "",
        f"자동매수: {'켜짐' if AUTO_BUY else '꺼짐'}",
        f"운영시간: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00",
        f"주문 최대금액: {MAX_ENTRY_KRW:,}원",
        "",
        "이번 핵심 변경",
        "- v320: route_doctor 무응답 원인을 명령어 직접검사/구버전 연결/파일락 가능성으로 보고 snapshot worker 구조로 수리",
        "- route_doctor는 삭제하지 않고, 명령어는 마지막 진단 snapshot만 즉시 출력",
        "- 관심 후보→진입 대기 약한 라인은 바로/쉬운 진입 금지, 눌림확인으로 강제 연결",
        "- 실전급 후보도 현재봉/돈/거리 공통확인을 못 통과하면 공통확인/눌림확인으로 강등",
        "- early/precheck/chase 취소에서 좋은 후보는 삭제하지 않고 최대 2회 복귀/눌림 재감시",
        "- 강한놓침 눌림/복귀감시 성과 라인은 유지·강화",
        "- 자동매수, 손절/TP 기본값 변경 없음",
        "",
        "확인: /cache_status /quality_check /paper_flow /paper_stats /errorlog",
        "자세한 설명은 /info",
    ]
    try:
        send("\n".join(lines))
    except Exception:
        pass

