# =========================================================
# v2.5.321: 후보품질 본선 2차 - 실전급/관심 약한 진입 강제강등 + 강한놓침 연결 보정
# =========================================================
# 수정 위치:
# - 2차/3차 후보분류 + paper 등록/취소 경로 + 출력
# - route_doctor/timing 계측은 다음 수정으로 넘기고, 이번에는 후보품질을 우선 수정한다.
# 핵심:
# - v320에서 카운터가 0으로 남은 원인: paper row의 lane/grade 원문(strict_signal, v274_preview_bridge_prepare 등)을
#   한국어 표시명과 같이 보지 못해 연결강화가 일부 후보에 안 걸릴 수 있었다.
# - 관심 후보/실전급 후보 손실 라인은 강제로 바로진입을 막고 pullback/now_prepare로 보낸다.
# - 강한놓침 복귀감시는 무조건 breakout이 아니라, 현재봉/돈/거리 공통확인이 부족하면 pullback으로 낮춘다.
# - paper_stats full 인자 오류를 같이 고친다. 기능 추가가 아니라 깨진 출력 경로 복구다.

V321_STATS = {
    "strength_enhanced": 0,
    "interest_to_pullback": 0,
    "loose_to_pullback": 0,
    "real_to_common": 0,
    "real_to_pullback": 0,
    "strong_return_to_breakout": 0,
    "strong_return_to_pullback": 0,
    "strong_pullback_keep": 0,
    "cancel_to_breakout": 0,
    "cancel_to_pullback": 0,
    "paper_stats_full_fixed": 0,
    "last_note": "대기",
}

def _v321_inc(key: str, note: str = ""):
    try:
        if key in V321_STATS:
            V321_STATS[key] = int(safe_float(V321_STATS.get(key, 0), 0)) + 1
        if note:
            V321_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass

try:
    _BASE_V320_STRENGTH_FOR_V321 = _v320_strength_snapshot
except Exception:
    _BASE_V320_STRENGTH_FOR_V321 = None

def _v321_lane_raw(row: dict) -> str:
    try:
        return str((row or {}).get("lane", "") or "").strip()
    except Exception:
        return ""

def _v321_lane_easy(row: dict) -> str:
    try:
        raw = _v321_lane_raw(row)
        return str(_paper_v301_easy_lane(raw)) if '_paper_v301_easy_lane' in globals() else raw
    except Exception:
        return _v321_lane_raw(row)

def _v321_text_blob(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        keys = [
            "ticker", "lane", "entry_rule", "signal_grade", "original_grade", "register_reason", "signal_decision",
            "decision", "grade", "reasons", "close_reason", "v312_route", "v313_route", "v314_route",
            "v317_cancel_detail", "v320_quality_guard", "v320_force_connected",
        ]
        parts = [_v321_lane_easy(row)]
        for k in keys:
            v = row.get(k, "")
            if isinstance(v, (list, tuple)):
                parts += [str(x) for x in v]
            else:
                parts.append(str(v or ""))
        return " / ".join(parts)
    except Exception:
        return ""

def _v320_strength_snapshot(row: dict) -> dict:
    """v321: v320 snapshot을 유지하되 paper 원문 lane/grade까지 같이 본다. 새 API/OHLCV 호출 없음."""
    try:
        base = dict(_BASE_V320_STRENGTH_FOR_V321(row) if callable(_BASE_V320_STRENGTH_FOR_V321) else {})
    except Exception:
        base = {}
    try:
        row = row if isinstance(row, dict) else {}
        raw_lane = _v321_lane_raw(row)
        easy_lane = _v321_lane_easy(row)
        text = (str(base.get("text", "") or "") + " / " + _v321_text_blob(row)).lower()
        signal_grade = str(row.get("signal_grade", row.get("grade", "")) or "").upper().strip()
        original_grade = str(row.get("original_grade", row.get("paper_original_grade", "")) or "").upper().strip()
        entry_rule = str(row.get("entry_rule", "") or "").lower().strip()
        interest = bool(base.get("interest")) or raw_lane in {"v274_preview_bridge_prepare", "preheat_preview_test"} or "관심 후보" in easy_lane or "관심" in text
        loose = raw_lane == "loose_threshold_test" or "문턱 낮춘" in easy_lane or "loose_threshold_test" in text
        real_grade = bool(base.get("real_grade")) or raw_lane == "strict_signal" or "실전급" in easy_lane or signal_grade == "BUY_OK" or original_grade == "BUY_OK"
        strong_miss = bool(base.get("strong_miss")) or raw_lane.startswith("cancel_reentry_forced_v313") or "강한놓침" in text or "강한 놓침" in text or "복귀감시" in text or "눌림감시" in text or "v314" in text
        trade_count = int(safe_float(base.get("trade_count", row.get("trade_count", row.get("ws_trade_count_60s", 0))), 0))
        buy_ratio = safe_float(base.get("buy_ratio", row.get("buy_ratio", row.get("ws_trade_buy_ratio_60s", 0))), 0)
        money = safe_float(base.get("money", row.get("money_amount", row.get("turnover_5m", row.get("ws_trade_amount_60s", 0)))), 0)
        score = safe_float(base.get("score", row.get("score", row.get("edge_score", 0))), 0)
        chg1 = safe_float(base.get("chg1", row.get("change_1", row.get("chg_1m", 0))), 0)
        chg3 = safe_float(base.get("chg3", row.get("change_3", row.get("chg_3m", 0))), 0)
        chg5 = safe_float(base.get("chg5", row.get("change_5", row.get("chg_5m", 0))), 0)
        high_gap = safe_float(base.get("high_gap", row.get("below_30m_high_pct", row.get("high_gap_pct", 999))), 999)
        from_low = safe_float(base.get("from_low", row.get("from_low", row.get("from_30m_low_pct", 0))), 0)
        live_score = safe_float(base.get("live_score", row.get("current_candle_live_score", 0)), 0)
        pressure = safe_float(base.get("pressure", row.get("current_candle_pressure_score", 0)), 0)
        follow = safe_float(base.get("follow", row.get("current_candle_follow_score", 0)), 0)
        current_label = str(row.get("current_candle_label", "") or "")
        money_label = str(row.get("money_sustain_label", row.get("money_status", "")) or "")
        candle_bad = bool(base.get("candle_bad")) or pressure >= 1.10 or _v320_text_has_any(current_label, ["밀림", "위꼬리", "약함"])
        money_bad = bool(base.get("money_bad")) or _v320_text_has_any(money_label, ["식음", "매도우세", "얇", "없음", "약함"])
        live_ok = bool(base.get("live_ok")) or live_score >= 1.25 or follow >= 0.55 or chg1 >= 0.05 or chg3 >= 0.08 or chg5 >= 0.12
        money_ok = bool(base.get("money_ok")) or money >= 750000 or trade_count >= 3 or buy_ratio >= 50
        distance_ok = bool(base.get("distance_ok")) or ((high_gap >= 0.55 or high_gap >= 900) and from_low <= 4.20)
        # 실전급 후보는 이름값을 더 빡세게 본다. 강한놓침은 별도 경로로 살린다.
        common_ok = bool(live_ok and money_ok and distance_ok and not (candle_bad and money_bad))
        strong_ok = bool(common_ok and not candle_bad and (score >= 4.3 or buy_ratio >= 55 or trade_count >= 5 or money >= 20_000_000 or (strong_miss and buy_ratio >= 48)))
        base.update({
            "raw_lane": raw_lane,
            "easy_lane": easy_lane,
            "entry_rule": entry_rule,
            "interest": interest,
            "loose": loose,
            "real_grade": real_grade,
            "strong_miss": strong_miss,
            "trade_count": trade_count,
            "buy_ratio": buy_ratio,
            "money": money,
            "score": score,
            "chg1": chg1,
            "chg3": chg3,
            "chg5": chg5,
            "high_gap": high_gap,
            "from_low": from_low,
            "live_score": live_score,
            "pressure": pressure,
            "follow": follow,
            "candle_bad": candle_bad,
            "money_bad": money_bad,
            "live_ok": live_ok,
            "money_ok": money_ok,
            "distance_ok": distance_ok,
            "common_ok": common_ok,
            "strong_ok": strong_ok,
            "text": text,
        })
        _v321_inc("strength_enhanced")
        return base
    except Exception as e:
        base.update({"error_v321": str(e)[:120]})
        return base

def _v321_zero_entry_if_pending(pos: dict):
    try:
        if str(pos.get("status", "")).upper() == "PENDING":
            pos["entry_price"] = 0.0
            pos["entered_ts"] = 0.0
            pos["remaining_ratio"] = 1.0
            pos["realized_pct"] = 0.0
    except Exception:
        pass

def _v320_apply_register_guard_to_pos(pos_id: str, pos: dict) -> bool:
    """v321: 관심/실전급/loose 약한 진입을 강제로 대기 라인에 연결한다."""
    try:
        if not isinstance(pos, dict):
            return False
        snap = _v320_strength_snapshot(pos)
        price = safe_float(snap.get("price", _v320_price_from_pos(pos)), 0)
        changed = False
        ticker = str(pos.get("ticker", "?") or "?")
        # 강한놓침은 아래 force 연결에서 따로 처리. 실전급/관심 규칙으로 죽이지 않는다.
        if not snap.get("strong_miss"):
            if snap.get("interest") or snap.get("loose"):
                # 관심/loose 라인은 성과가 약하므로 무조건 직접/쉬운 진입 금지.
                if str(pos.get("entry_rule", "") or "") != "pullback" or str(pos.get("status", "") or "").upper() == "OPEN":
                    pos["status"] = "PENDING"
                    pos["entry_rule"] = "pullback"
                    pos["signal_decision"] = "v321 관심/loose 후보는 바로진입 금지 → 눌림 확인 후 진입"
                    pos["v321_quality_guard"] = "interest_or_loose_to_pullback"
                    _v320_set_pullback_window(pos, price, tight=bool(snap.get("common_ok")))
                    _v321_zero_entry_if_pending(pos)
                    _v321_inc("loose_to_pullback" if snap.get("loose") else "interest_to_pullback", f"관심/loose 눌림강등 {ticker}")
                    changed = True
            elif snap.get("real_grade"):
                if snap.get("strong_ok"):
                    if str(pos.get("entry_rule", "") or "") != "now_prepare" or str(pos.get("status", "") or "").upper() == "OPEN":
                        pos["status"] = "PENDING"
                        pos["entry_rule"] = "now_prepare"
                        pos["signal_decision"] = "v321 실전급도 공통확인 1회 통과 후 진입"
                        pos["v321_quality_guard"] = "real_to_common"
                        _v320_set_breakout_window(pos, price, soft=True)
                        _v321_zero_entry_if_pending(pos)
                        _v321_inc("real_to_common", f"실전급 공통확인 {ticker}")
                        changed = True
                else:
                    pos["status"] = "PENDING"
                    pos["entry_rule"] = "pullback"
                    pos["signal_decision"] = "v321 실전급 이름값 부족 → 눌림 확인으로 강등"
                    pos["v321_quality_guard"] = "real_to_pullback"
                    _v320_set_pullback_window(pos, price, tight=False)
                    _v321_zero_entry_if_pending(pos)
                    _v321_inc("real_to_pullback", f"실전급 눌림강등 {ticker}")
                    changed = True
        if changed:
            pos["v321_guard_ts"] = time.time()
            pos["version_tag"] = BOT_VERSION
            pos["v321_guard_snapshot"] = {k: snap.get(k) for k in ["raw_lane", "easy_lane", "trade_count", "buy_ratio", "money", "score", "chg1", "chg3", "chg5", "high_gap", "from_low", "live_score", "pressure", "common_ok", "strong_ok"]}
            with PAPER_STATE_LOCK:
                if pos_id in paper_positions and isinstance(paper_positions.get(pos_id), dict):
                    paper_positions[pos_id].update(pos)
            try: save_paper_state_v258()
            except Exception: pass
        return changed
    except Exception as e:
        try: append_runtime_error_log("v321_register_guard", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False

def _v320_force_connect_pending_positions(reason: str = "worker") -> int:
    """v321: 강한놓침 복귀는 공통확인 부족 시 pullback으로 낮추고, 관심/실전급 강등을 강제한다."""
    changed = 0
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            if str(pos.get("status", "") or "").upper() != "PENDING":
                continue
            snap = _v320_strength_snapshot(pos)
            text = str(snap.get("text", "") or "")
            price = safe_float(snap.get("price", _v320_price_from_pos(pos)), 0)
            ch = False
            if snap.get("strong_miss"):
                is_pullback_watch = _v320_text_has_any(text, ["눌림감시", "pullback"])
                is_return_watch = _v320_text_has_any(text, ["복귀감시", "복귀강함", "breakout", "strong_return", "v314"])
                if is_pullback_watch:
                    if str(pos.get("entry_rule", "") or "") != "pullback":
                        pos["entry_rule"] = "pullback"
                        pos["signal_decision"] = "v321 강한놓침 눌림감시 → pullback 유지"
                        pos["v321_force_connected"] = "strong_pullback_keep"
                        _v320_set_pullback_window(pos, price, tight=True)
                        _v321_inc("strong_pullback_keep", f"강한놓침 눌림유지 {pos.get('ticker','?')}")
                        ch = True
                elif is_return_watch:
                    if snap.get("common_ok") and not snap.get("candle_bad"):
                        if str(pos.get("entry_rule", "") or "") not in {"breakout", "now_prepare"}:
                            pos["entry_rule"] = "breakout"
                            pos["signal_decision"] = "v321 강한놓침 복귀감시 → 재상승 확인대기"
                            pos["v321_force_connected"] = "strong_return_breakout"
                            _v320_set_breakout_window(pos, price, soft=True)
                            _v321_inc("strong_return_to_breakout", f"강한놓침 복귀대기 {pos.get('ticker','?')}")
                            ch = True
                    else:
                        if str(pos.get("entry_rule", "") or "") != "pullback":
                            pos["entry_rule"] = "pullback"
                            pos["signal_decision"] = "v321 복귀감시지만 공통확인 부족 → 눌림확인으로 낮춤"
                            pos["v321_force_connected"] = "strong_return_to_pullback"
                            _v320_set_pullback_window(pos, price, tight=True)
                            _v321_inc("strong_return_to_pullback", f"복귀감시 눌림전환 {pos.get('ticker','?')}")
                            ch = True
            if snap.get("interest") or snap.get("loose") or snap.get("real_grade"):
                if _v320_apply_register_guard_to_pos(pid, pos):
                    ch = True
            if ch:
                changed += 1
                pos["v321_force_ts"] = time.time()
                pos["version_tag"] = BOT_VERSION
                with PAPER_STATE_LOCK:
                    if pid in paper_positions and isinstance(paper_positions.get(pid), dict):
                        paper_positions[pid].update(pos)
        if changed:
            try: save_paper_state_v258()
            except Exception: pass
            _v320_inc("pending_force_connected", f"v321 대기연결 {changed}개/{reason}")
    except Exception as e:
        try: append_runtime_error_log("v321_force_connect_pending", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return changed

try:
    _BASE_PAPER_REGISTER_V321 = paper_register_candidate_v258
except Exception:
    _BASE_PAPER_REGISTER_V321 = None

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    try:
        before_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
        ok = _BASE_PAPER_REGISTER_V321(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V321) else False
        if ok:
            after_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
            new_ids = list(after_ids - before_ids)
            ticker = str((row or {}).get("ticker", "") or "").upper().strip()
            if not new_ids and ticker:
                with PAPER_STATE_LOCK:
                    new_ids = [pid for pid, p in (paper_positions or {}).items() if isinstance(p, dict) and str(p.get("ticker", "")).upper() == ticker]
            for pid in new_ids[-5:]:
                with PAPER_STATE_LOCK:
                    pos = dict(paper_positions.get(pid, {})) if isinstance(paper_positions.get(pid, {}), dict) else {}
                # 원본 row의 lane/판단값을 pos에 일부 주입해 guard가 한국어 표시명/원문을 같이 보게 한다.
                try:
                    for k in ["lane", "signal_grade", "original_grade", "register_reason", "signal_decision", "decision", "grade", "reasons"]:
                        if k in row and k not in pos:
                            pos[k] = row.get(k)
                except Exception:
                    pass
                _v320_apply_register_guard_to_pos(pid, pos)
            _v320_force_connect_pending_positions(reason="register_v321")
        return ok
    except Exception as e:
        try: append_runtime_error_log("paper_register_v321", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return _BASE_PAPER_REGISTER_V321(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V321) else False

try:
    _BASE_PAPER_CANCEL_PENDING_V321_ORIGINAL = _BASE_PAPER_CANCEL_PENDING_V320
except Exception:
    _BASE_PAPER_CANCEL_PENDING_V321_ORIGINAL = None

def _paper_cancel_pending_v258(pos_id: str, pos: dict, reason: str, now_ts: float = None):
    """v321: 좋은 후보 삭제 방지. 강한놓침/관심/실전급 생존 후보를 더 강하게 재감시로 연결."""
    now_ts = safe_float(now_ts, time.time())
    try:
        r = str(reason or "")
        if r in {"early_pending_cancel_v267", "entry_precheck_cancel_v266", "chase_over_before_entry", "pending_timeout"}:
            p = dict(pos or {})
            with PAPER_STATE_LOCK:
                if pos_id in paper_positions and isinstance(paper_positions.get(pos_id), dict):
                    p.update(dict(paper_positions.get(pos_id, {})))
            snap = _v320_strength_snapshot(p)
            reroutes = int(safe_float(p.get("v320_reroute_count", p.get("v317_reroute_count", 0)), 0))
            price = safe_float(snap.get("price", _v320_price_from_pos(p)), 0)
            stop = safe_float(p.get("stop_price", p.get("stop", 0)), 0)
            dead = bool((stop > 0 and price > 0 and price <= stop * 1.002) or (snap.get("candle_bad") and snap.get("money_bad") and not snap.get("strong_miss")))
            if (not dead) and reroutes < 2:
                mode = ""
                why = ""
                if snap.get("strong_miss"):
                    mode = "breakout" if (snap.get("common_ok") and not snap.get("candle_bad") and r != "chase_over_before_entry") else "pullback"
                    why = "강한놓침 취소삭제 차단"
                elif snap.get("real_grade") and (snap.get("money_ok") or snap.get("live_ok")):
                    mode = "pullback"
                    why = "실전급 약화 취소 대신 눌림 재확인"
                elif (snap.get("interest") or snap.get("loose")) and (snap.get("money_ok") or snap.get("live_ok")):
                    mode = "pullback"
                    why = "관심/loose 취소 대신 눌림 재확인"
                elif r == "chase_over_before_entry" and price > 0:
                    mode = "pullback"
                    why = "추격초과 삭제 대신 눌림확인"
                if mode:
                    if _v320_apply_cancel_rewatch(pos_id, p, r, mode, "v321 " + why, now_ts):
                        _v321_inc("cancel_to_breakout" if mode == "breakout" else "cancel_to_pullback", f"취소대신 {mode} {p.get('ticker','?')}")
                        return None
    except Exception as e:
        try: append_runtime_error_log("paper_cancel_v321_guard", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_PAPER_CANCEL_PENDING_V321_ORIGINAL):
        return _BASE_PAPER_CANCEL_PENDING_V321_ORIGINAL(pos_id, pos, reason, now_ts)
    return None

