def build_scan_health_cached_text() -> str:
    """v322: scan_health도 누적 로그를 매번 훑지 않게 느린 직후에는 이전 완성본을 재사용한다."""
    now_ts = _v322_now()
    try:
        cached_text = str(V322_SCAN_HEALTH_CACHE.get("text", "") or "")
        cached_ts = safe_float(V322_SCAN_HEALTH_CACHE.get("ts", 0), 0)
        cached_sec = safe_float(V322_SCAN_HEALTH_CACHE.get("sec", 0), 0)
        age = now_ts - cached_ts if cached_ts > 0 else 999999
        if cached_text and age <= V322_SCAN_HEALTH_REUSE_SEC and cached_sec >= V322_SCAN_HEALTH_SLOW_SEC:
            _v322_inc("scan_health_reuse", f"scan_health 이전 완성본 재사용 {age:.0f}s")
            return cached_text + f"\n\n🧯 v322 scan_health 재사용\n- 이전 완성본: {format_elapsed_text(age)} 전 / 직전 생성 {cached_sec:.2f}s"
        if cached_text and age <= 10.0:
            _v322_inc("scan_health_reuse", f"scan_health 짧은간격 재사용 {age:.0f}s")
            return cached_text
    except Exception:
        pass
    t0 = _v322_now()
    try:
        txt = str(_BASE_BUILD_SCAN_HEALTH_CACHED_TEXT_V322()) if callable(_BASE_BUILD_SCAN_HEALTH_CACHED_TEXT_V322) else "🩺 스캔 상태 진단 /scan_health"
        sec = max(0.0, _v322_now() - t0)
        V322_SCAN_HEALTH_CACHE.update({"ts": _v322_now(), "text": txt, "sec": sec, "note": f"원본 {sec:.2f}s"})
        _v322_inc("scan_health_refresh", f"scan_health 원본갱신 {sec:.2f}s")
        if sec >= V322_SCAN_HEALTH_SLOW_SEC:
            _v322_inc("scan_health_slow", f"scan_health 느림 {sec:.2f}s")
        return txt
    except Exception as e:
        try: append_runtime_error_log("v322_scan_health", str(e), exc=e, include_traceback=False)
        except Exception: pass
        cached_text = str(V322_SCAN_HEALTH_CACHE.get("text", "") or "") if isinstance(V322_SCAN_HEALTH_CACHE, dict) else ""
        if cached_text:
            return cached_text + f"\n\n🧯 v322 scan_health 오류 → 이전 완성본 재사용: {e.__class__.__name__}"
        return f"🩺 스캔 상태 진단 /scan_health\n- 생성 오류: {e.__class__.__name__}: {str(e)[:120]}"

# --- 전량청산 손익비 보정 유틸 ---
def _v322_pos_blob(pos: dict) -> str:
    try:
        p = pos if isinstance(pos, dict) else {}
        keys = ["lane", "source", "route", "watch_route", "mode", "paper_type", "signal_decision", "v321_quality_guard", "v321_force_connected", "v320_rewatch_reason", "entry_note", "reason"]
        return " / ".join([str(p.get(k, "") or "") for k in keys]).lower()
    except Exception:
        return ""

def _v322_is_common_wait(pos: dict) -> bool:
    b = _v322_pos_blob(pos)
    return ("공통확인" in b) or ("common" in b and "wait" in b) or ("common" in b and "보류" in b)

def _v322_is_weak_line(pos: dict) -> bool:
    b = _v322_pos_blob(pos)
    return ("관심" in b) or ("interest" in b) or ("실전급" in b) or ("strict_signal" in b) or ("real_to_pullback" in b) or ("loose" in b)

def _v322_is_strong_line(pos: dict) -> bool:
    b = _v322_pos_blob(pos)
    return ("강한놓침" in b) or ("strong" in b and "miss" in b) or ("눌림감시" in b) or ("복귀감시" in b)

def _v322_entry_price(pos: dict) -> float:
    try:
        return safe_float(pos.get("entry_price", pos.get("planned_entry", pos.get("price", 0))), 0)
    except Exception:
        return 0.0

def _v322_open_ts(pos: dict) -> float:
    try:
        return safe_float(pos.get("opened_ts", pos.get("entry_ts", pos.get("created_ts", pos.get("registered_ts", 0)))), 0)
    except Exception:
        return 0.0

def _v322_current_pnl(pos: dict, price: float) -> float:
    entry = _v322_entry_price(pos)
    if entry > 0 and price > 0:
        return ((price - entry) / entry) * 100.0
    return safe_float(pos.get("pnl_pct", 0), 0)

def _v322_max_profit(pos: dict, pnl: float = 0.0) -> float:
    vals = []
    for k in ["max_up_pct", "max_profit_pct", "high_pnl_pct", "best_pnl_pct", "peak_pnl_pct"]:
        try: vals.append(safe_float(pos.get(k, 0), 0))
        except Exception: pass
    vals.append(safe_float(pnl, 0))
    return max(vals) if vals else safe_float(pnl, 0)

def _v322_close_position(pos_id: str, pos: dict, price: float, reason: str, now_ts: float):
    try:
        p = dict(pos or {})
        p["v322_close_reason"] = reason
        p["v322_exit_guard"] = True
        return _paper_close_position_v258(pos_id, p, price, reason, now_ts)
    except Exception as e:
        try: append_runtime_error_log("v322_close_position", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return None

def _v322_preclose_positions_once():
    """약한 후보 손실은 짧게, 강한 후보는 본전/트레일링으로 관리. 새 API 없이 가격 캐시만 사용."""
    now_ts = _v322_now()
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict) and str(pos.get("status", "")).upper() == "OPEN"]
    except Exception:
        items = []
    for pid, pos in items:
        try:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            price = get_price_for_tracking(ticker, caller="paper_v322_exit", allow_api_fallback=False) if callable(globals().get("get_price_for_tracking")) else 0
            price = safe_float(price, 0)
            if price <= 0:
                price = safe_float(pos.get("last_price", pos.get("current_price", 0)), 0)
            if price <= 0:
                continue
            pnl = _v322_current_pnl(pos, price)
            best = _v322_max_profit(pos, pnl)
            opened = _v322_open_ts(pos)
            hold = max(0.0, now_ts - opened) if opened > 0 else 0.0
            common = _v322_is_common_wait(pos)
            weak = _v322_is_weak_line(pos)
            strong = _v322_is_strong_line(pos)
            # POLA형: 공통확인/바로진입 보류가 힘 없이 밀리면 -1%대까지 방치 금지.
            if common:
                if pnl <= V322_FAST_CUT_COMMON_LOSS:
                    _v322_inc("common_wait_fast_cut", f"공통확인 빠른손절 {ticker}/{pnl:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_common_wait_fast_cut", now_ts)
                    continue
                if hold >= V322_FAST_CUT_COMMON_NO_PROGRESS_SEC and best < V322_FAST_CUT_COMMON_NO_PROGRESS_MAX and pnl <= V322_FAST_CUT_COMMON_NO_PROGRESS_LOSS:
                    _v322_inc("common_wait_fast_cut", f"공통확인 무진행정리 {ticker}/{pnl:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_common_wait_no_progress_cut", now_ts)
                    continue
            # 관심/실전급 강등 라인은 약하면 손실을 짧게 자른다.
            if weak and not strong:
                if pnl <= V322_FAST_CUT_WEAK_LOSS:
                    _v322_inc("weak_fast_cut", f"약한라인 빠른손절 {ticker}/{pnl:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_weak_line_fast_cut", now_ts)
                    continue
                if hold >= V322_FAST_CUT_WEAK_NO_PROGRESS_SEC and best < V322_FAST_CUT_WEAK_NO_PROGRESS_MAX and pnl <= V322_FAST_CUT_WEAK_NO_PROGRESS_LOSS:
                    _v322_inc("weak_fast_cut", f"약한라인 무진행정리 {ticker}/{pnl:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_weak_line_no_progress_cut", now_ts)
                    continue
            # 강한 라인은 조금 더 먹되, 본전/소익 보호와 트레일링은 반드시 둔다.
            if strong:
                if best >= V322_STRONG_TRAIL_AFTER and pnl <= max(V322_STRONG_BREAKEVEN_FLOOR, best * V322_STRONG_TRAIL_KEEP_RATIO):
                    _v322_inc("strong_trailing_exit", f"강한라인 트레일링 {ticker}/{pnl:+.2f}% 최고{best:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_strong_trailing_full_exit", now_ts)
                    continue
                if best >= V322_STRONG_BREAKEVEN_AFTER and pnl <= V322_STRONG_BREAKEVEN_FLOOR:
                    _v322_inc("strong_breakeven_guard", f"강한라인 본전보호 {ticker}/{pnl:+.2f}% 최고{best:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_strong_breakeven_guard", now_ts)
                    continue
                if hold >= V322_STRONG_MAX_HOLD_SEC and pnl > 0:
                    _v322_inc("strong_trailing_exit", f"강한라인 시간익절 {ticker}/{pnl:+.2f}%")
                    _v322_close_position(pid, pos, price, "v322_strong_time_profit_exit", now_ts)
                    continue
        except Exception as e:
            try: append_runtime_error_log("v322_preclose", str(e), exc=e, include_traceback=False)
            except Exception: pass

