# ============================================================
# v2.5.324: v324 출력/추적 블록 실행위치 수리 + 압축 출력 실제 연결
# ============================================================
# 위치: 출력 / cache_status / quality_check / batch 계측표시 / paper 진입 기록
# 원칙:
# - 후보 선별 조건, v321 후보 연결, v322 청산 수치는 이번 버전에서 건드리지 않는다.
# - 기본 화면은 짧게, 자세한 원본은 *_full 명령으로 보낸다.
# - POLA처럼 trace에서는 반짝형/C/미검증인데 paper 진입까지 올라간 후보의 진입 직전 row를 저장한다.
# - 캐시 병목은 이번에 숨기지 않고 원인 추적에 필요한 크기/단계 정보를 기본 화면에 짧게 노출한다.

V323_SCHEMA_VERSION = "v324_compact_trace_v2"
V323_ENTRY_TRACE_FILE = data_file("paper_entry_trace_v324.jsonl") if callable(globals().get("data_file")) else "paper_entry_trace_v324.jsonl"
V323_STATS = globals().get("V323_STATS", {
    "entry_trace_saved": 0,
    "entry_trace_pola_like": 0,
    "cache_compact": 0,
    "quality_compact": 0,
    "batch_timing_compact": 0,
    "last_note": "대기",
})


def _v324_now() -> float:
    try:
        return time.time()
    except Exception:
        return 0.0


def _v324_inc(key: str, note: str = ""):
    try:
        V323_STATS[key] = int(safe_float(V323_STATS.get(key, 0), 0)) + 1
        if note:
            V323_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v324_len(obj) -> int:
    try:
        return len(obj) if obj is not None else 0
    except Exception:
        return 0


def _v324_elapsed(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "아직 없음"
        return format_elapsed_text(max(0, _v324_now() - ts)) + " 전" if callable(globals().get("format_elapsed_text")) else f"{int(max(0, _v324_now()-ts))}초 전"
    except Exception:
        return "확인불가"


def _v324_simple_reason(reason: str) -> str:
    r = str(reason or "")
    table = [
        ("early_pending_cancel_v267", "진입 전 약화/늦은 자리"),
        ("entry_precheck_cancel_v266", "진입 직전 힘 빠짐"),
        ("chase_over_before_entry", "너무 오른 자리라 대기"),
        ("now_prepare_timeout_v268", "준비대기 시간초과"),
        ("now_prepare_cancel_v268", "준비대기 중 약화"),
        ("v314_force_watch_dead", "강제감시 무너짐"),
        ("대기 중 신호악화", "대기 중 신호 약화"),
        ("진입 직전 힘빠짐", "진입 직전 힘 빠짐"),
        ("추격금지", "너무 오른 자리라 대기"),
        ("수익 후 신호약화", "수익 후 힘 약해져 정리"),
        ("보유 중 신호악화", "보유 중 힘 빠져 정리"),
        ("시간 대비 힘 부족", "시간 대비 힘 부족"),
    ]
    for k, v in table:
        if k in r:
            return v
    r = r.replace("_", " ").strip()
    return r[:40] if r else "사유 없음"


def _v324_row_blob(row: dict) -> str:
    try:
        if not isinstance(row, dict):
            return ""
        keys = [
            "ticker", "lane", "source", "route", "watch_route", "entry_rule", "register_reason", "reason",
            "signal_decision", "decision", "final_decision", "final_class", "final_type", "grade", "signal_grade",
            "rank_reason", "trace_reason", "pattern_tag", "record_type", "minute1_status", "chart_status",
            "v321_quality_guard", "v321_force_connected", "v320_reroute_why", "v317_reroute_reason",
        ]
        vals = []
        for k in keys:
            v = row.get(k)
            if v not in {None, "", []}:
                vals.append(f"{k}={str(v)[:120]}")
        return " | ".join(vals)[:1200]
    except Exception:
        return ""


def _v324_is_pola_like_entry(row: dict, pos: dict = None) -> bool:
    try:
        blob = (_v324_row_blob(row) + " | " + _v324_row_blob(pos or {})).lower()
        weak_words = ["반짝", "c", "등급 c", "복기", "미검증", "minute1_central_wait", "정밀미검증", "정밀차트 미검증"]
        paper_words = ["common", "공통확인", "바로진입 보류", "strict_signal", "now_prepare"]
        weak_hit = any(w.lower() in blob for w in weak_words)
        paper_hit = any(w.lower() in blob for w in paper_words)
        return bool(weak_hit and paper_hit)
    except Exception:
        return False


def _v324_entry_trace_from_row(row: dict, trigger: str = "", pos: dict = None) -> dict:
    row = dict(row or {}) if isinstance(row, dict) else {}
    pos = dict(pos or {}) if isinstance(pos, dict) else {}
    try:
        easy = _v316_easy_lane(pos or row) if callable(globals().get("_v316_easy_lane")) else str((pos or row).get("lane", ""))
    except Exception:
        easy = str((pos or row).get("lane", ""))
    trace = {
        "schema": V323_SCHEMA_VERSION,
        "ts": _v324_now(),
        "version": BOT_VERSION,
        "ticker": str(row.get("ticker", pos.get("ticker", "")) or "").upper().strip(),
        "trigger": str(trigger or "")[:80],
        "pos_id": str(pos.get("id", pos.get("pos_id", "")) or "")[:80],
        "easy_lane": str(easy or "")[:120],
        "entry_rule": str(pos.get("entry_rule", row.get("entry_rule", "")) or "")[:80],
        "status": str(pos.get("status", "") or "")[:40],
        "row_lane": str(row.get("lane", "") or "")[:120],
        "pos_lane": str(pos.get("lane", "") or "")[:120],
        "grade": str(row.get("grade", row.get("signal_grade", row.get("original_grade", ""))) or "")[:80],
        "final_class": str(row.get("final_class", row.get("final_type", row.get("decision", ""))) or "")[:120],
        "trace_reason": str(row.get("trace_reason", "") or "")[:220],
        "rank_reason": str(row.get("rank_reason", "") or "")[:220],
        "watch_route": str(row.get("watch_route", pos.get("watch_route", "")) or "")[:160],
        "register_reason": str(pos.get("register_reason", row.get("register_reason", "")) or "")[:260],
        "signal_decision": str(pos.get("signal_decision", row.get("signal_decision", "")) or "")[:220],
        "minute1_status": str(row.get("minute1_status", row.get("minute1_central_status", "")) or "")[:100],
        "chart_status": str(row.get("chart_status", row.get("precision_chart_status", "")) or "")[:100],
        "chg1": safe_float(row.get("chg1", row.get("change_1m", 0)), 0),
        "chg3": safe_float(row.get("chg3", row.get("change_3m", 0)), 0),
        "chg5": safe_float(row.get("chg5", row.get("change_5m", 0)), 0),
        "money": safe_float(row.get("money", row.get("turnover", row.get("amount_5m", 0))), 0),
        "high_gap": safe_float(row.get("high_gap", row.get("high_gap_pct", 0)), 0),
        "from_low": safe_float(row.get("from_low", row.get("from_low_pct", 0)), 0),
    }
    trace["pola_like_risk"] = _v324_is_pola_like_entry(row, pos)
    trace["raw_hint"] = _v324_row_blob(row)[:800]
    return trace


def _v324_append_entry_trace(trace: dict):
    try:
        if not isinstance(trace, dict):
            return
        # jsonl은 원인 추적용으로만 쓴다. 커지는 것을 막기 위해 지나치게 큰 필드는 위에서 자른다.
        with open(V323_ENTRY_TRACE_FILE, "a", encoding="utf-8") as f:
            f.write(json.dumps(trace, ensure_ascii=False, default=str) + "\n")
        _v324_inc("entry_trace_saved", f"entry trace 저장 {trace.get('ticker','?')}")
        if trace.get("pola_like_risk"):
            _v324_inc("entry_trace_pola_like", f"POLA형 경로추적 {trace.get('ticker','?')}")
    except Exception as e:
        try: append_runtime_error_log("v324_entry_trace", str(e), exc=e, include_traceback=False)
        except Exception: pass


try:
    _BASE_PAPER_REGISTER_V323 = paper_register_candidate_v258
except Exception:
    _BASE_PAPER_REGISTER_V323 = None


def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    """v324: 후보 조건은 바꾸지 않고, paper 진입 직전 경로만 저장한다."""
    before_ids = set()
    try:
        with PAPER_STATE_LOCK:
            before_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
    except Exception:
        pass
    ok = False
    try:
        ok = _BASE_PAPER_REGISTER_V323(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V323) else False
    except Exception as e:
        try: append_runtime_error_log("paper_register_v324_base", str(e), exc=e, include_traceback=False)
        except Exception: pass
        ok = False
    if ok:
        try:
            with PAPER_STATE_LOCK:
                after_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
                new_ids = list(after_ids - before_ids)
                ticker = str((row or {}).get("ticker", "") or "").upper().strip()
                if not new_ids and ticker:
                    new_ids = [pid for pid, p in (paper_positions or {}).items() if isinstance(p, dict) and str(p.get("ticker", "")).upper().strip() == ticker]
                for pid in new_ids[-6:]:
                    pos = paper_positions.get(pid) if isinstance(paper_positions.get(pid), dict) else {}
                    trace = _v324_entry_trace_from_row(row or {}, trigger=trigger, pos=dict(pos or {}))
                    trace["pos_id"] = str(pid)
                    if isinstance(pos, dict):
                        pos["v324_entry_trace"] = {k: v for k, v in trace.items() if k not in {"raw_hint"}}
                        pos["v324_entry_raw_hint"] = trace.get("raw_hint", "")[:500]
                        pos["v324_pola_like_risk"] = bool(trace.get("pola_like_risk"))
                        paper_positions[pid] = pos
                    _v324_append_entry_trace(trace)
            try: save_paper_state_v258()
            except Exception: pass
        except Exception as e:
            try: append_runtime_error_log("paper_register_v324_trace", str(e), exc=e, include_traceback=False)
            except Exception: pass
    return ok


