        building = bool(globals().get("COMMAND_DISPLAY_CACHE_WORKER_BUILDING", False))
        stage = str(globals().get("COMMAND_DISPLAY_CACHE_BUILD_STAGE", "대기") or "대기")
        done = int(safe_float(globals().get("COMMAND_DISPLAY_CACHE_DONE", 0), 0))
        fail = int(safe_float(globals().get("COMMAND_DISPLAY_CACHE_FAIL", 0), 0))
