# ---------- quality_check compact ----------
try:
    _BASE_QUALITY_TEXT_V323 = build_quality_check_text_v316
except Exception:
    _BASE_QUALITY_TEXT_V323 = None


def _v324_lane_sort_key(item):
    lane, st = item
    return abs(safe_float(st.get("pnl", 0), 0))


def _v324_quality_compact(hours: float = 6.0) -> str:
    _v324_inc("quality_compact", "quality_check compact")
    q = _v316_quality_stats(hours=hours) if callable(globals().get("_v316_quality_stats")) else {}
    closed = q.get("closed", []) if isinstance(q, dict) else []
    cancelled = q.get("cancelled", []) if isinstance(q, dict) else []
    wins = q.get("wins", []) if isinstance(q, dict) else []
    losses = q.get("losses", []) if isinstance(q, dict) else []
    n = len(closed)
    win_rate = (len(wins) / n * 100.0) if n else 0.0
    total = safe_float(q.get("total", 0) if isinstance(q, dict) else 0, 0)
    pf = safe_float(q.get("pf", 0) if isinstance(q, dict) else 0, 0)
    active_n = len(q.get("active_pending", []) if isinstance(q, dict) else [])
    lane_items = sorted((q.get("lane_stats", {}) if isinstance(q, dict) else {}).items(), key=_v324_lane_sort_key, reverse=True)
    good = []
    weak = []
    for lane, st in lane_items:
        n2 = int(st.get("n", 0)); w = int(st.get("wins", 0)); l = int(st.get("losses", 0)); pnl = safe_float(st.get("pnl", 0), 0)
        if n2 <= 0:
            continue
        line = f"- {lane}: {n2}전 {w}승 {l}패 / {pnl:+.2f}%"
        if pnl >= 0.25:
            good.append(line)
        elif pnl < 0:
            weak.append(line)
    missed = q.get("missed", []) if isinstance(q, dict) else []
    lines = [
        "🧪 후보 품질 /quality_check",
        f"- 최근 {hours:g}시간: {n}전 {len(wins)}승 {len(losses)}패 / {total:+.2f}% / PF {pf:.2f}",
        f"- 취소: {len(cancelled)}개 / 현재대기 {active_n}개",
    ]
    if n >= 5 and pf >= 1.2 and total > 0:
        lines.append("- 판단: 후보 조건은 지금 유지. 놓친 후보와 이상한 진입 경로만 추적")
    elif n >= 5 and pf < 1.0:
        lines.append("- 판단: 아직 약함. 다만 전체 조이기보다 손실 라인/진입 경로만 좁게 확인")
    else:
        lines.append("- 판단: 표본 적음. 30~60분 더 확인")
    lines.append("")
    lines.append("✅ 좋은 흐름")
    lines += (good[:3] if good else ["- 아직 뚜렷한 좋은 라인 없음"])
    lines.append("")
    lines.append("⚠️ 아쉬운 흐름")
    lines += (weak[:3] if weak else ["- 큰 손실 라인 없음"])
    lines.append("")
    lines.append("🚨 놓친 후보")
    if missed:
        for best, cur, ticker, reason in missed[:4]:
            lines.append(f"- {ticker}: 취소 후 최고 {best:+.2f}% / 현재 {cur:+.2f}% / {_v324_simple_reason(reason)}")
    else:
        lines.append("- 최근 큰 놓침 없음")
    lines.append("")
    lines.append("🔎 원인 추적")
    lines.append(f"- POLA형 진입경로 저장: {V323_STATS.get('entry_trace_saved',0)}건 / 의심 {V323_STATS.get('entry_trace_pola_like',0)}건")
    lines.append(f"- v321 연결: 관심→눌림 {V321_STATS.get('interest_to_pullback',0) if 'V321_STATS' in globals() else 0} / 실전급→눌림 {V321_STATS.get('real_to_pullback',0) if 'V321_STATS' in globals() else 0} / 강한눌림 유지 {V321_STATS.get('strong_pullback_keep',0) if 'V321_STATS' in globals() else 0}")
    lines.append(f"- v322 청산: 공통확인 빠른손절 {V322_STATS.get('common_wait_fast_cut',0) if 'V322_STATS' in globals() else 0} / 본전보호 {V322_STATS.get('strong_breakeven_guard',0) if 'V322_STATS' in globals() else 0} / 트레일링 {V322_STATS.get('strong_trailing_exit',0) if 'V322_STATS' in globals() else 0}")
    lines.append("")
    lines.append("📌 자세히: /quality_check full")
    return "\n".join(lines)


def build_quality_check_text_v316(full: bool = False, hours: float = 6.0) -> str:
    if full:
        try:
            return _BASE_QUALITY_TEXT_V323(full=True, hours=hours) if callable(_BASE_QUALITY_TEXT_V323) else _v324_quality_compact(hours=hours)
        except Exception as e:
            return f"🧪 후보품질 상세 오류: {e.__class__.__name__}: {str(e)[:160]}"
    try:
        return _v324_quality_compact(hours=hours)
    except Exception as e:
        return f"🧪 후보 품질 /quality_check\n- compact 표시 오류: {e.__class__.__name__}: {str(e)[:160]}\n- 자세히: /quality_check full"


# ---------- batch timing compact ----------
def _v322_batch_timing_summary() -> str:
    try:
        rows = list(V322_BATCH_TIMING_LAST or [])
        if not rows:
            return ""
        total_proc = sum(safe_float(r.get("proc", 0), 0) for r in rows)
        slow = max(rows, key=lambda r: safe_float(r.get("proc", 0), 0))
        lines = [
            "⏱ 묶음 응답시간",
            f"- 전체 처리시간 합계: {total_proc:.2f}s",
            f"- 가장 느린 명령: {slow.get('cmd','?')} / 처리 {safe_float(slow.get('proc',0),0):.2f}s",
            "- 명령별",
        ]
        for r in rows:
            cmd = str(r.get("cmd", "?"))
            proc = safe_float(r.get("proc", 0), 0)
            input_after = safe_float(r.get("input_after", 0), 0)
            cache_age = str(r.get("cache_age", ""))
            reason = ""
            if proc >= 2.5:
                reason = " / 긴 출력·파일읽기 의심"
            elif proc >= 1.0:
                reason = " / 약간 느림"
            lines.append(f"  · {cmd}: 입력후 {input_after:.1f}s / 처리 {proc:.2f}s / 캐시 {cache_age}{reason}")
        _v324_inc("batch_timing_compact", "batch timing compact")
        return "\n".join(lines)
    except Exception as e:
        return f"⏱ 묶음 응답시간\n- 표시 오류: {e.__class__.__name__}: {str(e)[:120]}"


