# ============================================================
# v2.5.325: paper_flow 병목 경량화 + 청산보정 연결추적 + 약한데 진입한 후보 표시 개선
# ============================================================
# 위치: 출력 / paper_flow / paper_stats / quality_check / paper close 진단
# 원칙:
# - 후보 선별 조건, v321 후보 연결 조건, v322 청산 수치는 이번 버전에서 바꾸지 않는다.
# - /paper_flow는 명령어가 무거운 계산/강제 주입을 직접 하지 않고 최신 저장값만 빠르게 요약한다.
# - v322 청산보정이 실제로 왜 발동/미발동했는지 기록한다.
# - "POLA형"이라는 표현은 "약한데 진입한 후보"로 바꿔 사용한다.

V325_SCHEMA_VERSION = "v325_flow_exit_trace_v1"
V325_PAPER_FLOW_LOG_LIMIT = 520
V325_ENTRY_TRACE_SHOW_LIMIT = 3
V325_STATS = globals().get("V325_STATS", {
    "paper_flow_fast": 0,
    "paper_flow_full_passthrough": 0,
    "paper_flow_slow": 0,
    "paper_flow_rows_scanned": 0,
    "paper_flow_cache_reuse": 0,
    "exit_trace_seen": 0,
    "exit_trace_strong": 0,
    "exit_trace_common": 0,
    "exit_trace_weak": 0,
    "exit_trace_should_breakeven": 0,
    "exit_trace_should_trailing": 0,
    "exit_trace_recovery_fail": 0,
    "weak_entry_trace_rendered": 0,
    "cancel_reentry_speed_rendered": 0,
    "last_note": "대기",
})
V325_PAPER_FLOW_CACHE = {"ts": 0.0, "text": "", "sec": 0.0, "minutes": 0}
V325_CLOSE_TRACE_RECENT = []
V325_CLOSE_TRACE_LOCK = threading.RLock()


def _v325_inc(key: str, note: str = ""):
    try:
        V325_STATS[key] = int(safe_float(V325_STATS.get(key, 0), 0)) + 1
        if note:
            V325_STATS["last_note"] = str(note)[:220]
    except Exception:
        pass


def _v325_ts() -> float:
    try:
        return time.time()
    except Exception:
        return 0.0


def _v325_get_recent_paper_rows(limit: int = V325_PAPER_FLOW_LOG_LIMIT):
    """paper_flow용: 전체 paper_log를 매번 깊게 훑지 않고 뒤쪽 N개만 복사한다."""
    try:
        lim = max(80, min(int(limit or V325_PAPER_FLOW_LOG_LIMIT), 900))
    except Exception:
        lim = V325_PAPER_FLOW_LOG_LIMIT
    try:
        with PAPER_STATE_LOCK:
            pos_rows = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict)]
            raw_logs = list(paper_trade_log or [])
            log_rows = [dict(r) for r in raw_logs[-lim:] if isinstance(r, dict)]
        V325_STATS["paper_flow_rows_scanned"] = len(log_rows)
        return pos_rows, log_rows
    except Exception as e:
        try: append_runtime_error_log("v325_recent_paper_rows", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return [], []


def _v325_status(row: dict) -> str:
    try:
        return str((row or {}).get("status", "") or "").upper()
    except Exception:
        return ""


def _v325_recent_ts(row: dict, keys) -> float:
    try:
        for k in keys:
            v = safe_float((row or {}).get(k, 0), 0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _v325_easy_lane(row_or_lane) -> str:
    try:
        if isinstance(row_or_lane, dict):
            lane = row_or_lane.get("lane", row_or_lane.get("paper_type", ""))
        else:
            lane = row_or_lane
        if callable(globals().get("_paper_v301_easy_lane")):
            return _paper_v301_easy_lane(lane)
        return str(lane or "-")[:80]
    except Exception:
        return "-"


def _v325_easy_reason(reason: str) -> str:
    try:
        if callable(globals().get("_paper_v301_easy_reason")):
            return _paper_v301_easy_reason(reason)
        if callable(globals().get("_v324_simple_reason")):
            return _v324_simple_reason(reason)
        return str(reason or "-")[:80]
    except Exception:
        return str(reason or "-")[:80]


def _v325_easy_rule(rule: str) -> str:
    try:
        if callable(globals().get("_paper_v301_easy_rule")):
            return _paper_v301_easy_rule(rule)
        r = str(rule or "").lower()
        if "pull" in r or "눌" in r:
            return "눌림 대기"
        if "break" in r or "돌파" in r:
            return "돌파 대기"
        return str(rule or "대기")[:40]
    except Exception:
        return "대기"


def _v325_stats_for_closed(rows: list) -> dict:
    try:
        if callable(globals().get("_paper_stats_for_rows_v258")):
            return _paper_stats_for_rows_v258(rows)
    except Exception:
        pass
    n = len(rows or [])
    wins = sum(1 for r in rows or [] if safe_float(r.get("pnl_pct", 0), 0) > 0)
    losses = n - wins
    total = sum(safe_float(r.get("pnl_pct", 0), 0) for r in rows or [])
    profit = sum(safe_float(r.get("pnl_pct", 0), 0) for r in rows or [] if safe_float(r.get("pnl_pct", 0), 0) > 0)
    loss = abs(sum(safe_float(r.get("pnl_pct", 0), 0) for r in rows or [] if safe_float(r.get("pnl_pct", 0), 0) < 0))
    pf = 999 if profit > 0 and loss == 0 else (profit / loss if loss > 0 else 0)
    return {"n": n, "wins": wins, "losses": losses, "total_pct": total, "profit_factor": pf}


def _v325_cancel_watch_rows_fast(limit: int = 4) -> list:
    """출력용: cancel_watch 상태를 새로 갱신하지 않고 메모리에 있는 것만 빠르게 본다."""
    try:
        state = globals().get("PAPER_CANCEL_WATCH_STATE_V302", {})
        rows = [dict(v) for v in (state or {}).values() if isinstance(v, dict)] if isinstance(state, dict) else []
        out = []
        for r in rows:
            max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
            cur_up = safe_float(r.get("current_after_cancel_pct", 0), 0)
            if max_up >= 0.70:
                out.append(r)
        out.sort(key=lambda r: (safe_float(r.get("max_up_after_cancel_pct", 0), 0), safe_float(r.get("current_after_cancel_pct", 0), 0), safe_float(r.get("cancel_ts", 0), 0)), reverse=True)
        return out[:max(1, int(limit or 4))]
    except Exception:
        return []


def _v325_reentry_rows_fast(limit: int = 4) -> list:
    try:
        if callable(globals().get("_v313_active_queue_rows")):
            return list(_v313_active_queue_rows(limit=max(1, int(limit or 4))) or [])[:limit]
    except Exception:
        pass
    return []


def _v325_minutes_to_reentry(row: dict) -> str:
    try:
        cancel_ts = safe_float(row.get("cancel_ts", row.get("created_ts", 0)), 0)
        t = str(row.get("ticker", "") or "").upper()
        if not t or cancel_ts <= 0:
            return "재감시시간 확인불가"
        best_dt = None
        for rr in _v325_reentry_rows_fast(limit=20):
            if str(rr.get("ticker", "")).upper() != t:
                continue
            rts = safe_float(rr.get("registered_ts", rr.get("created_ts", 0)), 0)
            if rts > 0 and rts >= cancel_ts:
                dt = (rts - cancel_ts) / 60.0
                if best_dt is None or dt < best_dt:
                    best_dt = dt
        if best_dt is None:
            return "재감시 연결 아직 없음"
        return f"재감시까지 {best_dt:.1f}분"
    except Exception:
        return "재감시시간 오류"


try:
    _BASE_BUILD_PAPER_FLOW_TEXT_V325 = build_paper_flow_text_v301
except Exception:
    _BASE_BUILD_PAPER_FLOW_TEXT_V325 = None


def build_paper_flow_text_v301(minutes: int = PAPER_FLOW_DEFAULT_MINUTES_V301) -> str:
    """v325: 기본 /paper_flow는 빠른 요약. full은 기존 긴 원본을 사용."""
    try:
        minutes_i = int(minutes or PAPER_FLOW_DEFAULT_MINUTES_V301)
    except Exception:
        minutes_i = PAPER_FLOW_DEFAULT_MINUTES_V301
    if minutes_i > PAPER_FLOW_DEFAULT_MINUTES_V301:
        _v325_inc("paper_flow_full_passthrough", "paper_flow_full 원본 사용")
        return _BASE_BUILD_PAPER_FLOW_TEXT_V325(minutes=minutes) if callable(_BASE_BUILD_PAPER_FLOW_TEXT_V325) else "🧪 모의매매 흐름 상세 /paper_flow_full"
    now_ts = _v325_ts()
    try:
        cached = V325_PAPER_FLOW_CACHE.get("text", "") if isinstance(V325_PAPER_FLOW_CACHE, dict) else ""
        cts = safe_float(V325_PAPER_FLOW_CACHE.get("ts", 0), 0) if isinstance(V325_PAPER_FLOW_CACHE, dict) else 0
        if cached and now_ts - cts <= 12:
            _v325_inc("paper_flow_cache_reuse", "paper_flow 짧은간격 캐시 재사용")
            return str(cached)
    except Exception:
        pass
    t0 = _v325_ts()
    try:
        start = now_ts - max(1, minutes_i) * 60
        pos_rows, log_rows = _v325_get_recent_paper_rows()
        current_pending = [p for p in pos_rows if _v325_status(p) == "PENDING"]
        current_open = [p for p in pos_rows if _v325_status(p) == "OPEN"]
        registered = []
        for p in pos_rows:
            if _v325_recent_ts(p, ["created_ts", "registered_ts"]) >= start:
                registered.append(p)
        for r in log_rows:
            if _v325_recent_ts(r, ["created_ts", "registered_ts"]) >= start:
                registered.append(r)
        entered = []
        for p in current_open:
            if _v325_recent_ts(p, ["entered_ts", "entry_ts", "created_ts"]) >= start:
                entered.append(p)
        for r in log_rows:
            if _v325_status(r) == "CLOSED" and _v325_recent_ts(r, ["entered_ts", "entry_ts"]) >= start:
                entered.append(r)
        closed = [r for r in log_rows if _v325_status(r) == "CLOSED" and _v325_recent_ts(r, ["close_ts"]) >= start]
        cancels = [r for r in log_rows if _v325_status(r) == "CANCELLED" and _v325_recent_ts(r, ["close_ts", "cancel_ts"]) >= start]
        reason_counts = {}
        lane_counts = {}
        for r in cancels:
            k = _v325_easy_reason(r.get("close_reason", r.get("cancel_reason", "-")))
            reason_counts[k] = reason_counts.get(k, 0) + 1
        for r in registered:
            k = _v325_easy_lane(r)
            lane_counts[k] = lane_counts.get(k, 0) + 1
        top_cancel = sorted(reason_counts.items(), key=lambda x: (-x[1], x[0]))[:5]
        top_lane = sorted(lane_counts.items(), key=lambda x: (-x[1], x[0]))[:5]
        lines = [
            "🧪 모의매매 흐름 /paper_flow",
            f"- 기준: 최근 {minutes_i}분 / 빠른요약 v325 / 원본행 {len(log_rows)}개만 사용",
            "- 실제 주문 아님. 후보가 어디서 죽는지 보는 표야.",
            "",
            "📌 흐름 요약",
            f"- 등록: {len(registered)}개 / 모의매수: {len(entered)}개 / 청산: {len(closed)}개 / 취소: {len(cancels)}개",
            f"- 현재 진행: 보유가정 {len(current_open)}개 / 진입대기 {len(current_pending)}개",
        ]
        if top_lane:
            lines += ["", "🧱 등록 유형"]
            for k, v in top_lane:
                lines.append(f"- {k}: {v}개")
        lines += ["", "🧯 취소 원인 TOP"]
        if top_cancel:
            for i, (k, v) in enumerate(top_cancel, 1):
                lines.append(f"{i}. {k}: {v}개")
        else:
            lines.append("- 최근 취소 없음")
        if current_open:
            lines += ["", "✅ 현재 모의보유"]
            for p in current_open[:4]:
                entry = safe_float(p.get("entry_price", 0), 0)
                price = safe_float(p.get("last_price", p.get("current_price", 0)), 0)
                pnl = _paper_pct_v258(entry, price) if callable(globals().get("_paper_pct_v258")) and entry > 0 and price > 0 else safe_float(p.get("pnl_pct", 0), 0)
                lines.append(f"- {str(p.get('ticker','?')).upper()} / {pnl:+.2f}% / {_v325_easy_lane(p)}")
        if current_pending:
            lines += ["", "⏳ 현재 진입대기"]
            for p in current_pending[:4]:
                lines.append(f"- {str(p.get('ticker','?')).upper()} / {_v325_easy_rule(p.get('entry_rule',''))} / {_v325_easy_lane(p)}")
        lines += ["", "🧭 판단"]
        if closed:
            st = _v325_stats_for_closed(closed)
            pf = safe_float(st.get("profit_factor", 0), 0)
            pf_text = "∞" if pf >= 900 else f"{pf:.2f}"
            lines.append(f"- 청산 결과: {st.get('n',0)}전 {st.get('wins',0)}승 {st.get('losses',0)}패 / 누적 {safe_float(st.get('total_pct',0),0):+.2f}% / 수익/손실 균형 {pf_text}")
        elif entered:
            lines.append("- 모의매수는 들어갔고, 아직 결과를 기다리는 중.")
        elif registered and cancels:
            lines.append("- 후보는 잡히지만 진입 전 취소가 많은 상태. 전체 조이기보다 취소 후 강한 움직임 연결을 봐야 함.")
        else:
            lines.append("- 최근 표본 부족. 조금 더 확인.")
        missed = _v325_cancel_watch_rows_fast(limit=4)
        lines += ["", "🚨 취소 후 놓침 의심"]
        if missed:
            for i, r in enumerate(missed, 1):
                t = str(r.get("ticker", "?")).upper()
                max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
                cur_up = safe_float(r.get("current_after_cancel_pct", 0), 0)
                reason = _v325_easy_reason(r.get("close_reason", r.get("cancel_reason", "")))
                lines.append(f"{i}. {t} / 최고 {max_up:+.2f}% / 현재 {cur_up:+.2f}% / {reason} / {_v325_minutes_to_reentry(r)}")
        else:
            lines.append("- 최근 큰 놓침 없음")
        rq = _v325_reentry_rows_fast(limit=4)
        lines += ["", "🧲 강한놓침 재감시"]
        if rq:
            for i, r in enumerate(rq, 1):
                t = str(r.get("ticker", "?")).upper()
                mode = "눌림감시" if str(r.get("mode", "")) == "pullback" else "복귀감시"
                age = format_elapsed_text(max(0, now_ts - safe_float(r.get("registered_ts", 0), 0))) if callable(globals().get("format_elapsed_text")) else f"{int(max(0, now_ts-safe_float(r.get('registered_ts',0),0)))}초"
                lines.append(f"{i}. {t} / {mode} / 최고 {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / 현재 {safe_float(r.get('current_after_cancel_pct',0),0):+.2f}% / 등록 {age} 전")
        else:
            lines.append("- 현재 강제감시 등록 없음")
        sec = max(0.0, _v325_ts() - t0)
        if sec >= 2.5:
            _v325_inc("paper_flow_slow", f"paper_flow 느림 {sec:.2f}s")
        _v325_inc("paper_flow_fast", f"paper_flow fast {sec:.2f}s/{len(log_rows)}행")
        lines.append("")
        lines.append(f"📌 길게 보기: /paper_flow_full / 생성 {sec:.2f}s")
        txt = "\n".join(lines).strip()
        try:
            V325_PAPER_FLOW_CACHE.update({"ts": _v325_ts(), "text": txt, "sec": sec, "minutes": minutes_i})
        except Exception:
            pass
        return txt
    except Exception as e:
        try: append_runtime_error_log("v325_paper_flow_fast", str(e), exc=e, include_traceback=True)
        except Exception: pass
        if callable(_BASE_BUILD_PAPER_FLOW_TEXT_V325):
            return _BASE_BUILD_PAPER_FLOW_TEXT_V325(minutes=minutes)
        return f"🧪 모의매매 흐름 /paper_flow\n- v325 빠른요약 오류: {e.__class__.__name__}: {str(e)[:120]}"


# ---- v322 청산보정 실제 연결 추적 ----
def _v325_exit_blob(pos: dict) -> str:
    try:
        return _v322_pos_blob(pos) if callable(globals().get("_v322_pos_blob")) else " / ".join(str((pos or {}).get(k, "")) for k in ["lane", "route", "trigger", "register_reason", "signal_decision"]).lower()
    except Exception:
        return ""


def _v325_exit_diag(pos: dict, price: float, reason: str = "") -> dict:
    try:
        p = dict(pos or {})
        pnl = _v322_current_pnl(p, safe_float(price, 0)) if callable(globals().get("_v322_current_pnl")) else safe_float(p.get("pnl_pct", 0), 0)
        best = _v322_max_profit(p, pnl) if callable(globals().get("_v322_max_profit")) else max(pnl, safe_float(p.get("max_up_pct", 0), 0))
        common = _v322_is_common_wait(p) if callable(globals().get("_v322_is_common_wait")) else ("common" in _v325_exit_blob(p) or "공통확인" in _v325_exit_blob(p))
        weak = _v322_is_weak_line(p) if callable(globals().get("_v322_is_weak_line")) else ("관심" in _v325_exit_blob(p) or "strict" in _v325_exit_blob(p))
        strong = _v322_is_strong_line(p) if callable(globals().get("_v322_is_strong_line")) else ("강한" in _v325_exit_blob(p) or "cancel_reentry" in _v325_exit_blob(p))
        opened = _v322_open_ts(p) if callable(globals().get("_v322_open_ts")) else safe_float(p.get("opened_ts", p.get("entered_ts", 0)), 0)
        hold = max(0.0, _v325_ts() - opened) if opened > 0 else 0.0
        should_common = bool(common and pnl <= safe_float(globals().get("V322_FAST_CUT_COMMON_LOSS", -0.62), -0.62))
        should_weak = bool((weak and not strong) and pnl <= safe_float(globals().get("V322_FAST_CUT_WEAK_LOSS", -0.75), -0.75))
        should_be = bool(strong and best >= safe_float(globals().get("V322_STRONG_BREAKEVEN_AFTER", 0.5), 0.5) and pnl <= safe_float(globals().get("V322_STRONG_BREAKEVEN_FLOOR", 0.08), 0.08))
        trail_floor = max(safe_float(globals().get("V322_STRONG_BREAKEVEN_FLOOR", 0.08), 0.08), best * safe_float(globals().get("V322_STRONG_TRAIL_KEEP_RATIO", 0.55), 0.55))
        should_trail = bool(strong and best >= safe_float(globals().get("V322_STRONG_TRAIL_AFTER", 0.95), 0.95) and pnl <= trail_floor)
        return {
            "ts": _v325_ts(), "ticker": str(p.get("ticker", "?")).upper(), "lane": str(p.get("lane", ""))[:90],
            "reason": str(reason or "")[:120], "pnl": round(pnl, 3), "best": round(best, 3), "hold_sec": round(hold, 1),
            "common": common, "weak": weak, "strong": strong,
            "should_common": should_common, "should_weak": should_weak, "should_breakeven": should_be, "should_trailing": should_trail,
            "trail_floor": round(trail_floor, 3), "route_hint": _v325_exit_blob(p)[:220],
        }
    except Exception as e:
        return {"ts": _v325_ts(), "ticker": str((pos or {}).get("ticker", "?")), "error": f"{e.__class__.__name__}: {str(e)[:100]}"}


def _v325_store_close_diag(diag: dict):
    try:
        if not isinstance(diag, dict):
            return
        with V325_CLOSE_TRACE_LOCK:
            V325_CLOSE_TRACE_RECENT.append(dict(diag))
            del V325_CLOSE_TRACE_RECENT[:-12]
        _v325_inc("exit_trace_seen", f"청산진단 {diag.get('ticker','?')}/{diag.get('pnl',0):+}")
        if diag.get("strong"):
            _v325_inc("exit_trace_strong")
        if diag.get("common"):
            _v325_inc("exit_trace_common")
        if diag.get("weak"):
            _v325_inc("exit_trace_weak")
        if diag.get("should_breakeven"):
            _v325_inc("exit_trace_should_breakeven", f"본전보호 대상 {diag.get('ticker')}")
        if diag.get("should_trailing"):
            _v325_inc("exit_trace_should_trailing", f"트레일링 대상 {diag.get('ticker')}")
        if safe_float(diag.get("best", 0), 0) >= 0.5 and safe_float(diag.get("pnl", 0), 0) <= 0:
            _v325_inc("exit_trace_recovery_fail", f"회수실패 {diag.get('ticker')}")
    except Exception:
        pass


try:
    _BASE_PAPER_CLOSE_POSITION_V325 = _paper_close_position_v258
except Exception:
    _BASE_PAPER_CLOSE_POSITION_V325 = None


def _paper_close_position_v258(pos_id: str, pos: dict, price: float, reason: str, now_ts: float = None):
    """v325: 실제 청산 시점에 v322 보정이 왜 발동/미발동했는지 추적만 한다. 청산 조건은 변경하지 않는다."""
    try:
        diag = _v325_exit_diag(pos or {}, price, reason)
        if isinstance(pos, dict):
            pos["v325_exit_diag"] = {k: v for k, v in diag.items() if k != "route_hint"}
            pos["v325_exit_route_hint"] = str(diag.get("route_hint", ""))[:220]
        _v325_store_close_diag(diag)
    except Exception as e:
        try: append_runtime_error_log("v325_close_diag", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_PAPER_CLOSE_POSITION_V325):
        return _BASE_PAPER_CLOSE_POSITION_V325(pos_id, pos, price, reason, now_ts)
    return None


try:
    _BASE_V322_PRECLOSE_V325 = _v322_preclose_positions_once
except Exception:
    _BASE_V322_PRECLOSE_V325 = None


def _v322_preclose_positions_once():
    """v325: v322 preclose 전에 열린 포지션을 진단해, 왜 카운터가 0인지 추적한다. 조건 변경 없음."""
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict) and str(pos.get("status", "")).upper() == "OPEN"]
        for pid, pos in items[:20]:
            ticker = str(pos.get("ticker", "") or "").upper()
            price = safe_float(pos.get("last_price", pos.get("current_price", 0)), 0)
            try:
                if callable(globals().get("get_price_for_tracking")):
                    p2 = get_price_for_tracking(ticker, caller="v325_preclose_diag", allow_api_fallback=False)
                    if safe_float(p2, 0) > 0:
                        price = safe_float(p2, 0)
            except Exception:
                pass
            if price > 0:
                diag = _v325_exit_diag(pos, price, "preclose_check")
                if diag.get("should_breakeven") or diag.get("should_trailing") or diag.get("should_common") or diag.get("should_weak"):
                    _v325_store_close_diag(diag)
    except Exception as e:
        try: append_runtime_error_log("v325_preclose_diag", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_V322_PRECLOSE_V325):
        return _BASE_V322_PRECLOSE_V325()
    return None


def _v325_exit_trace_lines(limit: int = 4) -> list:
    try:
        with V325_CLOSE_TRACE_LOCK:
            rows = list(V325_CLOSE_TRACE_RECENT)[-max(1, int(limit)):]
        rows = list(reversed(rows))
        out = []
        for d in rows:
            t = str(d.get("ticker", "?"))
            flags = []
            if d.get("strong"): flags.append("강한라인")
            if d.get("common"): flags.append("공통확인")
            if d.get("weak"): flags.append("약한라인")
            target = []
            if d.get("should_breakeven"): target.append("본전보호 대상")
            if d.get("should_trailing"): target.append("트레일링 대상")
            if d.get("should_common") or d.get("should_weak"): target.append("빠른손절 대상")
            flag_txt = "/".join(flags) if flags else "일반"
            target_txt = ", ".join(target) if target else "보정대상 아님"
            out.append(f"- {t}: 최고 {safe_float(d.get('best',0),0):+.2f}% / 현재·청산 {safe_float(d.get('pnl',0),0):+.2f}% / {flag_txt} / {target_txt}")
        return out
    except Exception:
        return []


def _v325_recent_entry_trace_lines(limit: int = V325_ENTRY_TRACE_SHOW_LIMIT) -> list:
    try:
        path = globals().get("V323_ENTRY_TRACE_FILE", "")
        if not path:
            return []
        import os
        if not os.path.exists(path):
            return []
        with open(path, "r", encoding="utf-8") as f:
            raw = f.readlines()[-max(10, int(limit)*4):]
        rows = []
        for line in raw:
            try:
                obj = json.loads(line)
                if isinstance(obj, dict):
                    rows.append(obj)
            except Exception:
                continue
        rows = rows[-max(1, int(limit)):]
        out = []
        for r in reversed(rows):
            t = str(r.get("ticker", "?")).upper()
            lane = str(r.get("easy_lane", r.get("pos_lane", "")))[:36]
            grade = str(r.get("grade", ""))[:16] or "등급?"
            chart = str(r.get("chart_status", r.get("minute1_status", "")))[:24] or "차트확인?"
            risk = "의심" if r.get("pola_like_risk") else "일반"
            out.append(f"- {t}: {lane} / {grade} / {chart} / {risk}")
        return out
    except Exception:
        return []


