def build_quality_check_text_v316(full: bool = False, hours: float = 6.0) -> str:
    if full:
        return _BASE_QUALITY_TEXT_V325(full=True, hours=hours) if callable(_BASE_QUALITY_TEXT_V325) else "🧪 후보품질 상세"
    base = _BASE_QUALITY_TEXT_V325(full=False, hours=hours) if callable(_BASE_QUALITY_TEXT_V325) else "🧪 후보 품질 /quality_check"
    try:
        base = str(base).replace("POLA형 진입경로 저장", "약한데 진입한 후보 추적")
        if "최근 진입경로" not in base:
            trace_lines = _v325_recent_entry_trace_lines(limit=3)
            if trace_lines:
                _v325_inc("weak_entry_trace_rendered", "약한데 진입한 후보 최근경로 표시")
                extra = ["", "최근 진입경로"] + trace_lines
                base = base.rstrip() + "\n" + "\n".join(extra)
        if "v325 청산 연결 추적" not in base:
            close_lines = _v325_exit_trace_lines(limit=3)
            if close_lines:
                extra = ["", "v325 청산 연결 추적"] + close_lines
                base = base.rstrip() + "\n" + "\n".join(extra)
    except Exception:
        pass
    return base


