def build_paper_stats_text_v258(*args, **kwargs) -> str:
    base = _BASE_PAPER_STATS_TEXT_V325(*args, **kwargs) if callable(_BASE_PAPER_STATS_TEXT_V325) else "📊 모의매매 성과 /paper_stats"
    try:
        lines = [
            "",
            "[v325 청산보정 연결 추적]",
            f"- 청산진단 {V325_STATS.get('exit_trace_seen',0)} / 강한라인 {V325_STATS.get('exit_trace_strong',0)} / 공통확인 {V325_STATS.get('exit_trace_common',0)} / 약한라인 {V325_STATS.get('exit_trace_weak',0)}",
            f"- 발동대상 감지: 본전보호 {V325_STATS.get('exit_trace_should_breakeven',0)} / 트레일링 {V325_STATS.get('exit_trace_should_trailing',0)} / 회수실패 {V325_STATS.get('exit_trace_recovery_fail',0)}",
        ]
        close_lines = _v325_exit_trace_lines(limit=4)
        if close_lines:
            lines += close_lines
        else:
            lines.append("- 아직 새 청산 진단 없음")
        lines += [
            "",
            "[v325 paper_flow 경량화]",
            f"- 빠른요약 {V325_STATS.get('paper_flow_fast',0)} / 캐시재사용 {V325_STATS.get('paper_flow_cache_reuse',0)} / 느림감지 {V325_STATS.get('paper_flow_slow',0)} / 최근스캔행 {V325_STATS.get('paper_flow_rows_scanned',0)}",
        ]
        if "[v325 청산보정 연결 추적]" not in str(base):
            base = str(base).rstrip() + "\n" + "\n".join(lines)
    except Exception:
        pass
    return base


