# =============================================================================
# v2.5.328: 허브/차트재료 신뢰도 강제 보정 + 오래된 강한놓침 차단 + 진입직후 급락 방지
# 위치: 허브 row 품질판정 / v313 강제재감시 / paper 등록·진입·청산 / review_trace_detail / 시작알림
# 원칙: 후보 조건 전체 강화가 아님. 차트값이 실제 차트와 안 맞거나 오래된 재감시가 paper로 넘어가는 경로만 강하게 차단한다.
# =============================================================================
V328_SCHEMA_VERSION = "v328_hub_chart_truth_gate_v1"
V328_STATS = globals().get("V328_STATS", {
    "chart_good": 0, "chart_partial": 0, "chart_flat_suspect": 0, "chart_missing": 0, "chart_ws_only": 0,
    "register_block_chart": 0, "pending_chart_hold": 0, "old_reentry_block": 0, "old_reentry_review_only": 0,
    "immediate_dump_cut": 0, "stale_reentry_queue_skip": 0, "stale_reentry_force_review": 0,
    "trace_detail_chart_section": 0, "startup_fixed": 0,
    "last_note": "대기",
})

def _v328_inc(key: str, note: str = ""):
    try:
        if key in V328_STATS:
            V328_STATS[key] = int(safe_float(V328_STATS.get(key, 0), 0)) + 1
        if note:
            V328_STATS["last_note"] = str(note)[:220]
    except Exception:
        pass

def _v328_blob(obj) -> str:
    try:
        if not isinstance(obj, dict):
            return str(obj or "").lower()
        keys = [
            "ticker", "lane", "trigger", "source", "route", "watch_route", "route_class", "v326_route_class",
            "v327_route_class", "entry_rule", "signal_grade", "signal_decision", "final_class", "final_type",
            "rank_watch_action", "register_reason", "close_reason", "reason", "reasons", "note", "current_candle_label",
            "minute1_status", "minute1_central_status", "chart_status", "precision_chart_status", "last_price_source",
        ]
        vals = []
        for k in keys:
            v = obj.get(k, "")
            if isinstance(v, (list, tuple, set)):
                v = " / ".join(map(str, list(v)[:8]))
            vals.append(str(v or ""))
        tr = obj.get("v324_entry_trace") if isinstance(obj.get("v324_entry_trace"), dict) else {}
        if tr:
            vals += [str(tr.get(k, "") or "") for k in ["easy_lane", "final_class", "trace_reason", "rank_reason", "watch_route", "chart_status", "minute1_status"]]
        return " / ".join(vals).lower()
    except Exception:
        return ""

def _v328_price(obj) -> float:
    obj = obj if isinstance(obj, dict) else {}
    for k in ["current_price", "price", "last_price", "snapshot_price", "close", "entry_price", "planned_entry_high", "planned_entry_low"]:
        try:
            v = safe_float(obj.get(k, 0), 0)
            if v > 0:
                return v
        except Exception:
            pass
    return 0.0

def _v328_first_float(obj: dict, keys: list, default: float = 0.0) -> float:
    obj = obj if isinstance(obj, dict) else {}
    for k in keys:
        try:
            if k in obj:
                v = safe_float(obj.get(k, default), default)
                if v != default or default == 0.0:
                    return v
        except Exception:
            pass
    tr = obj.get("v324_entry_trace") if isinstance(obj.get("v324_entry_trace"), dict) else {}
    for k in keys:
        try:
            if k in tr:
                return safe_float(tr.get(k, default), default)
        except Exception:
            pass
    return default

def _v328_max_abs_changes(obj: dict) -> float:
    vals = []
    for keys in [
        ["chg1", "change_1", "change_1m", "chg_1m", "current_candle_change_pct"],
        ["chg3", "change_3", "change_3m", "chg_3m", "chg_3"],
        ["chg5", "change_5", "change_5m", "chg_5m", "chg_5"],
        ["chg15", "change_15", "change_15m", "chg_15m"],
        ["chg30", "change_30", "change_30m", "chg_30m"],
    ]:
        vals.append(abs(_v328_first_float(obj, keys, 0.0)))
    return max(vals) if vals else 0.0

def _v328_route_class(obj) -> str:
    try:
        if callable(globals().get("_v327_route_class")):
            return str(_v327_route_class(obj) or "unknown")
    except Exception:
        pass
    b = _v328_blob(obj)
    if any(x in b for x in ["눌림감시", "pullback", "v313_p"]):
        return "strong_reentry_pullback"
    if any(x in b for x in ["복귀감시", "breakout", "strong_return", "v313_b"]):
        return "strong_reentry_breakout"
    if any(x in b for x in ["공통확인", "common"]):
        return "strict_common"
    if any(x in b for x in ["관심 후보", "interest", "preview_bridge"]):
        return "interest_prepare"
    if any(x in b for x in ["실전급", "strict_signal"]):
        return "strict_signal"
    return "unknown"

def _v328_is_strong(obj) -> bool:
    cls = _v328_route_class(obj)
    b = _v328_blob(obj)
    return cls in {"strong_reentry_pullback", "strong_reentry_breakout"} or any(x in b for x in ["강한놓침", "강한 놓침", "복귀감시", "눌림감시", "cancel_reentry"])

def _v328_is_common_or_precision(obj) -> bool:
    cls = _v328_route_class(obj)
    b = _v328_blob(obj)
    return cls == "strict_common" or any(x in b for x in ["정밀검토", "공통확인", "바로진입 보류"])

def _v328_is_weak(obj) -> bool:
    cls = _v328_route_class(obj)
    b = _v328_blob(obj)
    return cls in {"interest_prepare", "strict_signal", "order_flow_prepare"} or any(x in b for x in ["관심 후보", "실전급", "체결흐름"])

def _v328_chart_quality(obj: dict) -> dict:
    """허브/row/pos 차트 재료가 실제 1분봉 판단에 쓸 만한지 판정한다. 새 API 호출 없음."""
    obj = obj if isinstance(obj, dict) else {}
    try:
        price = _v328_price(obj)
        high30 = _v328_first_float(obj, ["recent_30m_high_price", "high_30m", "recent30_high", "chart_high", "high_price_30m", "max_price_after_cancel"], 0.0)
        low30 = _v328_first_float(obj, ["recent_30m_low_price", "low_30m", "recent30_low", "chart_low", "low_price_30m", "min_price_after_cancel"], 0.0)
        high10 = _v328_first_float(obj, ["recent_10m_high_price", "high_10m", "recent10_high"], 0.0)
        low10 = _v328_first_float(obj, ["recent_10m_low_price", "low_10m", "recent10_low"], 0.0)
        maxchg = _v328_max_abs_changes(obj)
        money = _v328_first_float(obj, ["money_amount", "turnover", "turnover_5m", "turnover_recent", "amount_5m", "snapshot_turnover_hint"], 0.0)
        score = _v328_first_float(obj, ["score", "expected_score", "rank_score", "edge_score"], 0.0)
        prep = _v328_first_float(obj, ["prepare_score", "preparation_score", "restart_prepare_score", "v244_prepare_score"], 0.0)
        b = _v328_blob(obj)
        src_text = ""
        try:
            src_text = " / ".join([str(obj.get(k, "") or "") for k in ["minute1_status", "minute1_central_status", "chart_status", "precision_chart_status", "last_price_source"]])
        except Exception:
            src_text = ""
        ws_only = ("ws" in src_text.lower() or "유사" in src_text) and not any(x in src_text.lower() for x in ["rest", "확정"])
        flat = False
        swing30 = 0.0
        if price > 0 and high30 > 0 and low30 > 0:
            swing30 = abs(high30 - low30) / max(price, 1e-12) * 100.0
            sameish = abs(high30 - low30) <= max(price * 0.0007, 1e-12) and abs(high30 - price) <= max(price * 0.0007, 1e-12) and abs(low30 - price) <= max(price * 0.0007, 1e-12)
            flat = bool(sameish and maxchg <= 0.12 and (money > 0 or score > 0 or "정밀" in b or "재감시" in b))
        # 차트 수치가 전부 0인데 돈/점수/정밀검토가 있으면 허브가 현재가 하나로 메운 흔적일 수 있다.
        zero_chart_words = any(x in b for x in ["몸통", "윗꼬리", "아랫꼬리", "고점 다시도전 힘 0", "돈이 계속 붙는 힘 0"])
        if (high30 <= 0 or low30 <= 0) and (_v328_is_strong(obj) or _v328_is_common_or_precision(obj)):
            code = "MISSING"
            reason = "최근 10/30분 고저점 없음"
        elif flat or (zero_chart_words and maxchg <= 0.08 and (_v328_is_strong(obj) or _v328_is_common_or_precision(obj))):
            code = "FLAT_SUSPECT"
            reason = "고점·저점·현재가가 비슷하거나 차트수치가 0으로 평평함"
        elif ws_only:
            code = "WS_ONLY"
            reason = "REST 확정봉 전 WS 유사봉 중심"
        elif (high30 > 0 and low30 > 0) or (high10 > 0 and low10 > 0):
            code = "GOOD" if not ws_only else "WS_ONLY"
            reason = "최근 고저점 확인"
        else:
            code = "PARTIAL"
            reason = "일부 차트값만 확인"
        if code == "GOOD": _v328_inc("chart_good")
        elif code == "PARTIAL": _v328_inc("chart_partial")
        elif code == "FLAT_SUSPECT": _v328_inc("chart_flat_suspect")
        elif code == "WS_ONLY": _v328_inc("chart_ws_only")
        else: _v328_inc("chart_missing")
        return {
            "code": code, "reason": reason, "price": price, "high30": high30, "low30": low30,
            "high10": high10, "low10": low10, "swing30": round(swing30, 4), "maxchg": round(maxchg, 4),
            "money": money, "score": score, "prepare": prep, "source": src_text[:180],
        }
    except Exception as e:
        try: append_runtime_error_log("v328_chart_quality", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {"code": "MISSING", "reason": "품질판정 오류", "price": 0.0, "high30": 0.0, "low30": 0.0, "maxchg": 0.0, "source": "error"}

def _v328_should_block_paper_entry(obj: dict) -> tuple[bool, str, dict]:
    q = _v328_chart_quality(obj)
    code = str(q.get("code", ""))
    b = _v328_blob(obj)
    prep = safe_float(q.get("prepare", 0), 0)
    maxchg = safe_float(q.get("maxchg", 0), 0)
    strong = _v328_is_strong(obj)
    precision = _v328_is_common_or_precision(obj)
    # 허브/차트가 평평하거나 미확정인데 정밀검토/재감시 후보가 paper로 넘어가는 경로만 막는다.
    if code in {"FLAT_SUSPECT", "MISSING"} and (strong or precision):
        return True, f"차트재료 {code}: {q.get('reason')} → paper 진입 금지", q
    if code == "WS_ONLY" and precision and prep <= 2.2 and maxchg <= 0.12:
        return True, "WS 유사봉만 있고 준비점수/변화율 약함 → 다음 확정봉 대기", q
    if ("정밀검토" in b or "바로 매수 신호 아님" in b) and prep <= 1.8 and maxchg <= 0.12:
        return True, "정밀검토 대기인데 준비점수·변화율 약함 → 복기/내부감시만", q
    return False, "", q

def _v328_reentry_age(pos: dict) -> float:
    now_ts = time.time()
    vals = []
    for k in ["cancel_ts", "v320_last_reroute_ts", "v317_reroute_ts", "created_ts", "registered_ts"]:
        try:
            v = safe_float((pos or {}).get(k, 0), 0)
            if v > 0:
                vals.append(v)
        except Exception:
            pass
    if not vals:
        return 0.0
    # 강한놓침 유효시간은 원 취소시각이 있으면 그 기준, 없으면 가장 오래된 생성 기준으로 본다.
    return max(0.0, now_ts - min(vals))

def _v328_fresh_reconfirm(pos: dict) -> bool:
    try:
        snap = _v320_strength_snapshot(pos) if callable(globals().get("_v320_strength_snapshot")) else {}
        price = safe_float(snap.get("price", _v328_price(pos)), 0)
        chg1 = safe_float(snap.get("chg1", _v328_first_float(pos, ["chg1", "change_1m"], 0)), 0)
        chg3 = safe_float(snap.get("chg3", _v328_first_float(pos, ["chg3", "change_3m"], 0)), 0)
        money_ok = bool(snap.get("money_ok")) or safe_float(snap.get("money", 0), 0) >= 100000000
        live_ok = bool(snap.get("live_ok")) or max(chg1, chg3) >= 0.20
        common_ok = bool(snap.get("common_ok"))
        if price <= 0:
            return False
        return bool(common_ok or (money_ok and live_ok))
    except Exception:
        return False

try:
    _BASE_V313_REGISTER_FORCED_PENDING_V328 = _v313_register_forced_pending
except Exception:
    _BASE_V313_REGISTER_FORCED_PENDING_V328 = None

def _v313_register_forced_pending(row: dict, mode: str, why: str) -> bool:
    """v328: 오래된 강한놓침은 현재 후보처럼 강제주입하지 않는다. 새 확인이 없으면 복기용으로 남긴다."""
    try:
        now_ts = time.time()
        cancel_ts = safe_float((row or {}).get("cancel_ts", (row or {}).get("close_ts", (row or {}).get("ts", 0))), 0)
        age = max(0.0, now_ts - cancel_ts) if cancel_ts > 0 else 0.0
        max_up = safe_float((row or {}).get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float((row or {}).get("current_after_cancel_pct", 0), 0)
        keep = (cur_up / max_up) if max_up > 0 else 0.0
        # 30분 넘은 강한놓침은 새 힘이 유지되는 경우만 허용. 60분 이상은 강제주입 금지.
        if age >= 60 * 60:
            _v328_inc("stale_reentry_queue_skip", f"60분 초과 강한놓침 주입차단 {str((row or {}).get('ticker','?')).upper()}/{age/60:.0f}분")
            return False
        if age >= 30 * 60 and not (cur_up >= 1.20 and keep >= 0.45):
            _v328_inc("stale_reentry_queue_skip", f"30분 초과 새확인부족 {str((row or {}).get('ticker','?')).upper()}/{age/60:.0f}분")
            return False
        # 오래됐지만 현재 힘이 살아있으면 돌파추격 대신 눌림으로 강등한다.
        if age >= 30 * 60 and (cur_up >= 1.20 and keep >= 0.45):
            mode = "pullback"
            why = str(why or "") + f" / v328 오래된 강한놓침: 바로추격 금지, 눌림만 허용({age/60:.0f}분)"
            _v328_inc("stale_reentry_force_review", f"오래된 강한놓침 눌림만 {str((row or {}).get('ticker','?')).upper()}")
    except Exception as e:
        try: append_runtime_error_log("v328_v313_age_guard", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_V313_REGISTER_FORCED_PENDING_V328):
        return _BASE_V313_REGISTER_FORCED_PENDING_V328(row, mode, why)
    return False

try:
    _BASE_PAPER_REGISTER_V328 = paper_register_candidate_v258
except Exception:
    _BASE_PAPER_REGISTER_V328 = None

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    """v328: 허브/차트재료가 실제 1분봉과 안 맞을 가능성이 크면 paper 진입 자체를 막는다."""
    try:
        block, why, q = _v328_should_block_paper_entry(row if isinstance(row, dict) else {})
        if block:
            _v328_inc("register_block_chart", f"차트품질 등록차단 {str((row or {}).get('ticker','?')).upper()} / {q.get('code')}")
            try:
                append_runtime_event_log("v328_chart_entry_block", "차트재료 미확정 후보 paper 진입 차단", extra={"ticker": str((row or {}).get("ticker", "?")), "why": why, "quality": q})
            except Exception:
                pass
            return False
    except Exception as e:
        try: append_runtime_error_log("v328_register_gate", str(e), exc=e, include_traceback=False)
        except Exception: pass
    before_ids = set()
    try:
        with PAPER_STATE_LOCK:
            before_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
    except Exception:
        pass
    ok = _BASE_PAPER_REGISTER_V328(row, trigger=trigger) if callable(_BASE_PAPER_REGISTER_V328) else False
    if ok:
        try:
            after_ids = set((paper_positions or {}).keys()) if isinstance(paper_positions, dict) else set()
            new_ids = list(after_ids - before_ids)
            ticker = str((row or {}).get("ticker", "") or "").upper().strip()
            if not new_ids and ticker:
                with PAPER_STATE_LOCK:
                    new_ids = [pid for pid, p in (paper_positions or {}).items() if isinstance(p, dict) and str(p.get("ticker", "")).upper() == ticker]
            q = _v328_chart_quality(row if isinstance(row, dict) else {})
            for pid in new_ids[-5:]:
                with PAPER_STATE_LOCK:
                    pos = dict(paper_positions.get(pid, {})) if isinstance(paper_positions.get(pid, {}), dict) else {}
                    if pos:
                        pos["v328_chart_quality"] = dict(q)
                        pos["v328_chart_quality_code"] = q.get("code")
                        pos["v328_chart_basis_ts"] = time.time()
                        block, why, q2 = _v328_should_block_paper_entry({**dict(row or {}), **pos})
                        if block:
                            pos["status"] = "PENDING"
                            pos["entry_rule"] = "chart_verify"
                            pos["signal_decision"] = "v328 차트 미확정 → paper 진입 보류"
                            pos["v328_chart_hold_reason"] = why
                            pos["entry_price"] = 0.0
                            _v328_inc("pending_chart_hold", f"등록 후 차트확인대기 {pos.get('ticker','?')}/{q2.get('code')}")
                        paper_positions[pid].update(pos)
            try: save_paper_state_v258()
            except Exception: pass
        except Exception as e:
            try: append_runtime_error_log("v328_register_mark", str(e), exc=e, include_traceback=False)
            except Exception: pass
    return ok

def _v328_price_for_pos(ticker: str, pos: dict) -> float:
    price = 0.0
    try:
        if callable(globals().get("get_price_for_tracking")):
            price = safe_float(get_price_for_tracking(ticker, caller="v328_guard", allow_api_fallback=False), 0)
    except Exception:
        price = 0.0
    if price <= 0:
        price = _v328_price(pos)
    return safe_float(price, 0)

def _v328_pre_guard_positions_once(reason: str = "worker") -> int:
    changed = 0
    now_ts = time.time()
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
    except Exception:
        items = []
    for pid, pos in items:
        try:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            status = str(pos.get("status", "") or "").upper()
            if not ticker:
                continue
            route = _v328_route_class(pos)
            strong = _v328_is_strong(pos)
            weak = _v328_is_weak(pos)
            price = _v328_price_for_pos(ticker, pos)
            if status == "PENDING":
                block, why, q = _v328_should_block_paper_entry(pos)
                age = _v328_reentry_age(pos)
                stale = bool(strong and age >= 30 * 60 and not _v328_fresh_reconfirm(pos))
                if block or stale:
                    pos["entry_rule"] = "review_only" if stale else "chart_verify"
                    pos["signal_decision"] = "v328 오래된 강한놓침/차트미확정 → paper 진입 금지, 복기/내부감시만"
                    pos["v328_entry_hold"] = "old_reentry" if stale else "chart_quality"
                    pos["v328_entry_hold_reason"] = (f"오래된 재감시 {age/60:.1f}분" if stale else why)[:260]
                    pos["entry_price"] = 0.0
                    if stale:
                        _v328_inc("old_reentry_review_only", f"오래된 강한놓침 paper진입금지 {ticker}/{age/60:.0f}분")
                    else:
                        _v328_inc("pending_chart_hold", f"차트확인 전 paper진입금지 {ticker}/{q.get('code')}")
                    with PAPER_STATE_LOCK:
                        if pid in paper_positions and isinstance(paper_positions.get(pid), dict):
                            paper_positions[pid].update(pos)
                    changed += 1
                    continue
            elif status == "OPEN":
                if price <= 0:
                    continue
                pnl = _v322_current_pnl(pos, price) if callable(globals().get("_v322_current_pnl")) else 0.0
                best = _v322_max_profit(pos, pnl) if callable(globals().get("_v322_max_profit")) else max(pnl, safe_float(pos.get("max_up_pct", 0), 0))
                opened = _v322_open_ts(pos) if callable(globals().get("_v322_open_ts")) else safe_float(pos.get("entered_ts", pos.get("created_ts", 0)), 0)
                open_age = max(0.0, now_ts - opened) if opened > 0 else 0.0
                q = _v328_chart_quality(pos)
                # RSR/TDROP형: 진입 직후 최고수익 없이 바로 밀리면 -1%대까지 방치 금지.
                cut = False
                cut_reason = ""
                if open_age <= 4 * 60 and best <= 0.10 and pnl <= -0.65:
                    cut = True; cut_reason = "v328_entry_immediate_dump_cut"
                elif open_age <= 7 * 60 and best <= 0.20 and pnl <= -0.85:
                    cut = True; cut_reason = "v328_fast_no_profit_dump_cut"
                elif str(q.get("code")) in {"FLAT_SUSPECT", "MISSING"} and best <= 0.10 and pnl <= -0.45:
                    cut = True; cut_reason = "v328_bad_chart_open_cut"
                if cut:
                    _v328_inc("immediate_dump_cut", f"진입직후 급밀림 정리 {ticker}/{pnl:+.2f}%/{route}")
                    if callable(globals().get("_v322_close_position")):
                        _v322_close_position(pid, pos, price, cut_reason, now_ts)
                        changed += 1
                        continue
        except Exception as e:
            try: append_runtime_error_log("v328_pre_guard_pos", str(e), exc=e, include_traceback=False)
            except Exception: pass
    if changed:
        try: save_paper_state_v258()
        except Exception: pass
    return changed

