def _v328_chart_compare_section(ticker: str, row: dict = None) -> str:
    try:
        t = str(ticker or "").upper().strip()
        row = dict(row or {}) if isinstance(row, dict) else _v328_latest_trace_row(t)
        # 현재 active paper가 있으면 pos의 실제 경로도 같이 본다.
        try:
            with PAPER_STATE_LOCK:
                for p in (paper_positions or {}).values():
                    if isinstance(p, dict) and str(p.get("ticker", "")).upper().strip() == t:
                        merged = dict(row); merged.update({k: v for k, v in p.items() if v not in (None, "")}); row = merged; break
        except Exception:
            pass
        q = _v328_chart_quality(row)
        ts = safe_float(row.get("ts", row.get("created_ts", row.get("updated_ts", 0))), 0)
        ts_txt = format_reverse_trace_ts(ts) if callable(globals().get("format_reverse_trace_ts")) and ts > 0 else "미확인"
        src = str(q.get("source", "") or "미확인")
        lines = [
            "",
            "📊 v328 차트 비교용",
            f"- 기준시각: {ts_txt}",
            f"- 데이터상태: {q.get('code')} / {q.get('reason')}",
            f"- 현재가: {fmt_price(q.get('price')) if callable(globals().get('fmt_price')) else q.get('price')}",
            f"- 최근30분: 고점 {fmt_price(q.get('high30')) if callable(globals().get('fmt_price')) else q.get('high30')} / 저점 {fmt_price(q.get('low30')) if callable(globals().get('fmt_price')) else q.get('low30')} / 변동폭 {q.get('swing30')}%",
            f"- 변화율 최대값: {q.get('maxchg')}% / 돈 {q.get('money', 0):,.0f} / 점수 {q.get('score', 0):.2f}",
            f"- 출처: {src[:120] if src else '미확인'}",
        ]
        if str(q.get("code")) in {"FLAT_SUSPECT", "MISSING", "WS_ONLY"}:
            lines.append("- 판단: 이 상태면 실제 빗썸 1분봉과 불일치 가능성이 있어 paper 진입보다 다음 봉/REST 확정 확인이 우선")
        else:
            lines.append("- 판단: 스샷과 비교 가능한 기본 차트값은 있음")
        _v328_inc("trace_detail_chart_section")
        return "\n".join(lines)
    except Exception as e:
        try: append_runtime_error_log("v328_chart_compare_section", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return "\n\n📊 v328 차트 비교용\n- 생성 실패"

def build_review_trace_detail_text(ticker: str, limit: int = REVIEW_TRACE_DETAIL_RECENT_LIMIT) -> str:
    base = str(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V328(ticker, limit=limit)) if callable(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V328) else ""
    try:
        raw_query = str(ticker or "").strip()
        resolved, _note = resolve_user_ticker_query(raw_query) if callable(globals().get("resolve_user_ticker_query")) else (raw_query, "")
        resolved = str(resolved or raw_query).upper().strip()
        if resolved and "📊 v328 차트 비교용" not in base:
            base = base.rstrip() + _v328_chart_compare_section(resolved)
    except Exception:
        pass
    return base

