def _v313_register_forced_pending(row: dict, mode: str, why: str) -> bool:
    """v329: 강한놓침 강제주입도 실제 1분봉 복구 후 판단한다."""
    row = row if isinstance(row, dict) else {}
    try:
        q0 = _BASE_V328_CHART_QUALITY_V329(row) if callable(_BASE_V328_CHART_QUALITY_V329) else _v328_chart_quality(row)
        if _v329_need_repair(row, q0):
            q = _v329_repair_chart_quality(row, q0, reason="forced_pending")
            if q.get("ok"):
                _v329_apply_repair_to_row(row, q)
                _v329_inc("forced_pending_repair", f"강제주입 전 차트복구 {str(row.get('ticker','?')).upper()}")
            else:
                _v329_inc("repair_blocked_fail", f"강제주입 복구실패 {str(row.get('ticker','?')).upper()}")
                return False
        block, why2, q2 = _v328_should_block_paper_entry(row)
        if block:
            _v329_inc("repair_blocked_fail", f"강제주입 차단 {str(row.get('ticker','?')).upper()}/{q2.get('code')}")
            return False
    except Exception as e:
        try: append_runtime_error_log("v329_forced_pending_repair", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_V313_REGISTER_FORCED_PENDING_V329(row, mode, why) if callable(_BASE_V313_REGISTER_FORCED_PENDING_V329) else False

try:
    _BASE_CHART_COMPARE_SECTION_V329 = _v328_chart_compare_section
except Exception:
    _BASE_CHART_COMPARE_SECTION_V329 = None

def _v329_chart_repair_section(ticker: str, row: dict = None) -> str:
    try:
        t = str(ticker or "").upper().strip()
        row = dict(row or {}) if isinstance(row, dict) else (_v328_latest_trace_row(t) if callable(globals().get("_v328_latest_trace_row")) else {})
        q0 = _BASE_V328_CHART_QUALITY_V329(row) if callable(_BASE_V328_CHART_QUALITY_V329) else _v328_chart_quality(row)
        q = _v329_repair_chart_quality(row, q0, reason="trace_detail") if _v329_need_repair(row, q0) else _v328_chart_quality(row)
        code = str(q.get("code", ""))
        price = q.get("price", 0)
        lines = [
            "",
            "🛠 v329 차트 복구/재수집",
            f"- 복구상태: {code} / {q.get('reason','')}",
            f"- 기준봉: {q.get('basis_ts','미확인')} / 출처 {q.get('source','미확인')}",
            f"- 현재가: {fmt_price(price) if callable(globals().get('fmt_price')) else price}",
            f"- 최근10분: 고점 {fmt_price(q.get('high10')) if callable(globals().get('fmt_price')) else q.get('high10')} / 저점 {fmt_price(q.get('low10')) if callable(globals().get('fmt_price')) else q.get('low10')} / 변동폭 {q.get('swing10','?')}%",
            f"- 최근30분: 고점 {fmt_price(q.get('high30')) if callable(globals().get('fmt_price')) else q.get('high30')} / 저점 {fmt_price(q.get('low30')) if callable(globals().get('fmt_price')) else q.get('low30')} / 변동폭 {q.get('swing30','?')}%",
            f"- 변화율: 1m {q.get('chg1','?')}% / 3m {q.get('chg3','?')}% / 5m {q.get('chg5','?')}% / 15m {q.get('chg15','?')}% / 30m {q.get('chg30','?')}%",
            f"- 현재봉: 몸통 {q.get('body_pct','?')}% / 윗꼬리 {q.get('upper_wick_pct','?')}% / 아랫꼬리 {q.get('lower_wick_pct','?')}% / 봉변화 {q.get('last_candle_change_pct','?')}%",
        ]
        if code in {"REPAIR_FAILED", "REPAIR_RATE_LIMITED", "REST_FLAT_CONFIRMED"}:
            lines.append("- 판단: 복구 실패/진짜 평평함이면 paper 진입보다 보류·복기 우선")
        else:
            lines.append("- 판단: 이 값과 빗썸 1분봉 스샷을 우선 대조")
        _v329_inc("trace_repair_section")
        return "\n".join(lines)
    except Exception as e:
        try: append_runtime_error_log("v329_chart_repair_section", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return "\n\n🛠 v329 차트 복구/재수집\n- 생성 실패"

try:
    _BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V329 = build_review_trace_detail_text
except Exception:
    _BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V329 = None

def build_review_trace_detail_text(ticker: str, limit: int = REVIEW_TRACE_DETAIL_RECENT_LIMIT) -> str:
    base = str(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V329(ticker, limit=limit)) if callable(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V329) else ""
    try:
        raw_query = str(ticker or "").strip()
        resolved, _note = resolve_user_ticker_query(raw_query) if callable(globals().get("resolve_user_ticker_query")) else (raw_query, "")
        resolved = str(resolved or raw_query).upper().strip()
        if resolved and "🛠 v329 차트 복구/재수집" not in base:
            base = base.rstrip() + _v329_chart_repair_section(resolved)
    except Exception:
        pass
    return base

