def send_startup_message():
    lines = [
        "✅ 봇 시작 완료",
        f"현재 버전: {BOT_VERSION}",
        "",
        f"자동매수: {'켜짐' if AUTO_BUY else '꺼짐'}",
        f"운영시간: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00",
        f"주문 최대금액: {MAX_ENTRY_KRW:,}원",
        "",
        "이번 핵심 변경",
        "- v329: 차트값이 이상하면 해당 코인만 1분봉 REST/캐시로 재수집",
        "- 복구 성공 시 최근 10/30분 고점·저점·현재봉·변화율을 허브 row에 다시 반영",
        "- paper 진입 직전과 강한놓침 강제주입 직전에 차트복구 후 재판단",
        "- 복구 실패/REST 확인해도 평평한 후보는 paper 진입 금지",
        "- /review_trace_detail에 v329 차트 복구/재수집 섹션 추가",
        "- 전체 450개 재조회 아님: 의심 후보만 선별 복구",
        "- 후보 조건 전체 강화, 자동매수, 기본 손절/TP 대규모 변경 없음",
        "",
        "확인: /cache_status /quality_check /paper_flow /paper_recent /paper_stats /errorlog",
    ]
    try: send("\n".join(lines))
    except Exception: pass

def send_startup_notice():
    try:
        return send_startup_message()
    except Exception:
        pass

